		public MarchingCubesPro()
		{
			Implicit = new ImplicitSphere3d();
			Bounds = new AxisAlignedBox3d(Vector3d.Zero, 8.0);
			CubeSize = 0.25;
		}

		public void Generate()
		{
			Mesh = new DMesh3();
			int num = (int)(Bounds.Width / CubeSize) + 1;
			int num2 = (int)(Bounds.Height / CubeSize) + 1;
			int num3 = (int)(Bounds.Depth / CubeSize) + 1;
			CellDimensions = new Vector3i(num, num2, num3);
			GridBounds = new AxisAlignedBox3i(Vector3i.Zero, CellDimensions);
			corner_values_grid = new DenseGrid3f(num + 1, num2 + 1, num3 + 1, float.MaxValue);
			edge_vertices = new Dictionary<long, int>();
			corner_values = new Dictionary<long, double>();
			if (ParallelCompute)
			{
				generate_parallel();
			}
			else
			{
				generate_basic();
			}
		}

		public void GenerateContinuation(IEnumerable<Vector3d> seeds)
		{
			Mesh = new DMesh3();
			int num = (int)(Bounds.Width / CubeSize) + 1;
			int num2 = (int)(Bounds.Height / CubeSize) + 1;
			int num3 = (int)(Bounds.Depth / CubeSize) + 1;
			CellDimensions = new Vector3i(num, num2, num3);
			GridBounds = new AxisAlignedBox3i(Vector3i.Zero, CellDimensions);
			if (LastGridBounds != GridBounds)
			{
				corner_values_grid = new DenseGrid3f(num + 1, num2 + 1, num3 + 1, float.MaxValue);
				edge_vertices = new Dictionary<long, int>();
				corner_values = new Dictionary<long, double>();
				if (ParallelCompute)
				{
					done_cells = new DenseGrid3i(CellDimensions.x, CellDimensions.y, CellDimensions.z, 0);
				}
			}
			else
			{
				edge_vertices.Clear();
				corner_values.Clear();
				corner_values_grid.assign(float.MaxValue);
				if (ParallelCompute)
				{
					done_cells.assign(0);
				}
			}
			if (ParallelCompute)
			{
				generate_continuation_parallel(seeds);
			}
			else
			{
				generate_continuation(seeds);
			}
			LastGridBounds = GridBounds;
		}

		private void corner_pos(ref Vector3i ijk, ref Vector3d p)
		{
			p.x = Bounds.Min.x + CubeSize * (double)ijk.x;
			p.y = Bounds.Min.y + CubeSize * (double)ijk.y;
			p.z = Bounds.Min.z + CubeSize * (double)ijk.z;
		}

		private Vector3d corner_pos(ref Vector3i ijk)
		{
			return new Vector3d(Bounds.Min.x + CubeSize * (double)ijk.x, Bounds.Min.y + CubeSize * (double)ijk.y, Bounds.Min.z + CubeSize * (double)ijk.z);
		}

		private Vector3i cell_index(Vector3d pos)
		{
			return new Vector3i((int)((pos.x - Bounds.Min.x) / CubeSize), (int)((pos.y - Bounds.Min.y) / CubeSize), (int)((pos.z - Bounds.Min.z) / CubeSize));
		}

		private long corner_hash(ref Vector3i idx)
		{
			return (long)(((ulong)idx.x & 0xFFFFuL) | (((ulong)idx.y & 0xFFFFuL) << 16) | (((ulong)idx.z & 0xFFFFuL) << 32));
		}

		private long corner_hash(int x, int y, int z)
		{
			return (long)(((ulong)x & 0xFFFFuL) | (((ulong)y & 0xFFFFuL) << 16) | (((ulong)z & 0xFFFFuL) << 32));
		}

		private long edge_hash(ref Vector3i idx1, ref Vector3i idx2)
		{
			if (idx1.x != idx2.x)
			{
				int x = Math.Min(idx1.x, idx2.x);
				return corner_hash(x, idx1.y, idx1.z) | 0x10000000;
			}
			if (idx1.y != idx2.y)
			{
				int y = Math.Min(idx1.y, idx2.y);
				return corner_hash(idx1.x, y, idx1.z) | 0x20000000;
			}
			int z = Math.Min(idx1.z, idx2.z);
			return corner_hash(idx1.x, idx1.y, z) | 0x40000000;
		}

		private int edge_vertex_id(ref Vector3i idx1, ref Vector3i idx2, double f1, double f2)
		{
			long key = edge_hash(ref idx1, ref idx2);
			int value = -1;
			bool lockTaken = false;
			edge_vertices_lock.Enter(ref lockTaken);
			bool num = edge_vertices.TryGetValue(key, out value);
			edge_vertices_lock.Exit();
			if (num)
			{
				return value;
			}
			Vector3d p = Vector3d.Zero;
			Vector3d p2 = Vector3d.Zero;
			corner_pos(ref idx1, ref p);
			corner_pos(ref idx2, ref p2);
			Vector3d pIso = Vector3d.Zero;
			find_iso(ref p, ref p2, f1, f2, ref pIso);
			lockTaken = false;
			edge_vertices_lock.Enter(ref lockTaken);
			if (!edge_vertices.TryGetValue(key, out value))
			{
				value = append_vertex(pIso);
				edge_vertices[key] = value;
			}
			edge_vertices_lock.Exit();
			return value;
		}

		private double corner_value(ref Vector3i idx)
		{
			long key = corner_hash(ref idx);
			double value = 0.0;
			if (!corner_values.TryGetValue(key, out value))
			{
				Vector3d pt = corner_pos(ref idx);
				value = Implicit.Value(ref pt);
				corner_values[key] = value;
			}
			return value;
		}

		private void initialize_cell_values(GridCell cell, bool shift)
		{
			bool lockTaken = false;
			corner_values_lock.Enter(ref lockTaken);
			if (shift)
			{
				cell.f[1] = corner_value(ref cell.i[1]);
				cell.f[2] = corner_value(ref cell.i[2]);
				cell.f[5] = corner_value(ref cell.i[5]);
				cell.f[6] = corner_value(ref cell.i[6]);
			}
			else
			{
				for (int i = 0; i < 8; i++)
				{
					cell.f[i] = corner_value(ref cell.i[i]);
				}
			}
			corner_values_lock.Exit();
		}

		private double corner_value_grid(ref Vector3i idx)
		{
			double num = corner_values_grid[idx];
			if (num != 3.4028234663852886E+38)
			{
				return num;
			}
			Vector3d pt = corner_pos(ref idx);
			num = Implicit.Value(ref pt);
			corner_values_grid[idx] = (float)num;
			return num;
		}

		private void initialize_cell_values_grid(GridCell cell, bool shift)
		{
			if (shift)
			{
				cell.f[1] = corner_value_grid(ref cell.i[1]);
				cell.f[2] = corner_value_grid(ref cell.i[2]);
				cell.f[5] = corner_value_grid(ref cell.i[5]);
				cell.f[6] = corner_value_grid(ref cell.i[6]);
			}
			else
			{
				for (int i = 0; i < 8; i++)
				{
					cell.f[i] = corner_value_grid(ref cell.i[i]);
				}
			}
		}

		private double corner_value_nohash(ref Vector3i idx)
		{
			Vector3d pt = corner_pos(ref idx);
			return Implicit.Value(ref pt);
		}

		private void initialize_cell_values_nohash(GridCell cell, bool shift)
		{
			if (shift)
			{
				cell.f[1] = corner_value_nohash(ref cell.i[1]);
				cell.f[2] = corner_value_nohash(ref cell.i[2]);
				cell.f[5] = corner_value_nohash(ref cell.i[5]);
				cell.f[6] = corner_value_nohash(ref cell.i[6]);
			}
			else
			{
				for (int i = 0; i < 8; i++)
				{
					cell.f[i] = corner_value_nohash(ref cell.i[i]);
				}
			}
		}

		private void initialize_cell(GridCell cell, ref Vector3i idx)
		{
			cell.i[0] = new Vector3i(idx.x, idx.y, idx.z);
			cell.i[1] = new Vector3i(idx.x + 1, idx.y, idx.z);
			cell.i[2] = new Vector3i(idx.x + 1, idx.y, idx.z + 1);
			cell.i[3] = new Vector3i(idx.x, idx.y, idx.z + 1);
			cell.i[4] = new Vector3i(idx.x, idx.y + 1, idx.z);
			cell.i[5] = new Vector3i(idx.x + 1, idx.y + 1, idx.z);
			cell.i[6] = new Vector3i(idx.x + 1, idx.y + 1, idx.z + 1);
			cell.i[7] = new Vector3i(idx.x, idx.y + 1, idx.z + 1);
			initialize_cell_values_grid(cell, shift: false);
		}

		private void shift_cell_x(GridCell cell, int xi)
		{
			cell.f[0] = cell.f[1];
			cell.f[3] = cell.f[2];
			cell.f[4] = cell.f[5];
			cell.f[7] = cell.f[6];
			cell.i[0].x = xi;
			cell.i[1].x = xi + 1;
			cell.i[2].x = xi + 1;
			cell.i[3].x = xi;
			cell.i[4].x = xi;
			cell.i[5].x = xi + 1;
			cell.i[6].x = xi + 1;
			cell.i[7].x = xi;
			initialize_cell_values_grid(cell, shift: true);
		}

		private void generate_parallel()
		{
			mesh_lock = default(SpinLock);
			parallel_mesh_access = true;
			gParallel.ForEach(Interval1i.Range(CellDimensions.z), delegate(int zi)
			{
				GridCell cell = new GridCell();
				int[] vertIndexList = new int[12];
				for (int i = 0; i < CellDimensions.y; i++)
				{
					if (CancelF())
					{
						break;
					}
					Vector3i idx = new Vector3i(0, i, zi);
					initialize_cell(cell, ref idx);
					polygonize_cell(cell, vertIndexList);
					for (int j = 1; j < CellDimensions.x; j++)
					{
						shift_cell_x(cell, j);
						polygonize_cell(cell, vertIndexList);
					}
				}
			});
			parallel_mesh_access = false;
		}

		private void generate_basic()
		{
			GridCell cell = new GridCell();
			int[] vertIndexList = new int[12];
			for (int i = 0; i < CellDimensions.z; i++)
			{
				for (int j = 0; j < CellDimensions.y; j++)
				{
					if (CancelF())
					{
						return;
					}
					Vector3i idx = new Vector3i(0, j, i);
					initialize_cell(cell, ref idx);
					polygonize_cell(cell, vertIndexList);
					for (int k = 1; k < CellDimensions.x; k++)
					{
						shift_cell_x(cell, k);
						polygonize_cell(cell, vertIndexList);
					}
				}
			}
		}

		private void generate_continuation(IEnumerable<Vector3d> seeds)
		{
			GridCell cell = new GridCell();
			int[] vertIndexList = new int[12];
			done_cells = new DenseGrid3i(CellDimensions.x, CellDimensions.y, CellDimensions.z, 0);
			List<Vector3i> list = new List<Vector3i>();
			foreach (Vector3d seed in seeds)
			{
				Vector3i vector3i = cell_index(seed);
				if (done_cells[vector3i] == 1)
				{
					continue;
				}
				list.Add(vector3i);
				done_cells[vector3i] = 1;
				while (list.Count > 0)
				{
					Vector3i idx = list[list.Count - 1];
					list.RemoveAt(list.Count - 1);
					if (CancelF())
					{
						return;
					}
					initialize_cell(cell, ref idx);
					if (!polygonize_cell(cell, vertIndexList))
					{
						continue;
					}
					Vector3i[] gridOffsets = gIndices.GridOffsets6;
					foreach (Vector3i vector3i2 in gridOffsets)
					{
						Vector3i vector3i3 = idx + vector3i2;
						if (GridBounds.Contains(vector3i3) && done_cells[vector3i3] == 0)
						{
							list.Add(vector3i3);
							done_cells[vector3i3] = 1;
						}
					}
				}
			}
		}

		private void generate_continuation_parallel(IEnumerable<Vector3d> seeds)
		{
			mesh_lock = default(SpinLock);
			parallel_mesh_access = true;
			gParallel.ForEach(seeds, delegate(Vector3d seed)
			{
				Vector3i idx = cell_index(seed);
				if (set_cell_if_not_done(ref idx))
				{
					GridCell cell = new GridCell();
					int[] vertIndexList = new int[12];
					List<Vector3i> list = new List<Vector3i> { idx };
					while (list.Count > 0)
					{
						Vector3i idx2 = list[list.Count - 1];
						list.RemoveAt(list.Count - 1);
						if (CancelF())
						{
							break;
						}
						initialize_cell(cell, ref idx2);
						if (polygonize_cell(cell, vertIndexList))
						{
							Vector3i[] gridOffsets = gIndices.GridOffsets6;
							foreach (Vector3i vector3i in gridOffsets)
							{
								Vector3i idx3 = idx2 + vector3i;
								if (GridBounds.Contains(idx3) && set_cell_if_not_done(ref idx3))
								{
									list.Add(idx3);
								}
							}
						}
					}
				}
			});
			parallel_mesh_access = false;
		}

		private bool set_cell_if_not_done(ref Vector3i idx)
		{
			bool result = false;
			bool lockTaken = false;
			done_cells_lock.Enter(ref lockTaken);
			if (done_cells[idx] == 0)
			{
				done_cells[idx] = 1;
				result = true;
			}
			done_cells_lock.Exit();
			return result;
		}

		private bool polygonize_cell(GridCell cell, int[] vertIndexList)
		{
			int num = 0;
			int num2 = 1;
			for (int i = 0; i < 8; i++)
			{
				if (cell.f[i] < IsoValue)
				{
					num |= num2;
				}
				num2 <<= 1;
			}
			if (edgeTable[num] == 0)
			{
				return false;
			}
			num2 = 1;
			_ = Vector3d.Zero;
			_ = Vector3d.Zero;
			for (int j = 0; j <= 11; j++)
			{
				if ((edgeTable[num] & num2) != 0)
				{
					int num3 = edge_indices[j, 0];
					int num4 = edge_indices[j, 1];
					vertIndexList[j] = edge_vertex_id(ref cell.i[num3], ref cell.i[num4], cell.f[num3], cell.f[num4]);
				}
				num2 <<= 1;
			}
			int num5 = 0;
			for (int k = 0; triTable[num, k] != -1; k += 3)
			{
				int num6 = triTable[num, k];
				int num7 = triTable[num, k + 1];
				int num8 = triTable[num, k + 2];
				int num9 = vertIndexList[num6];
				int num10 = vertIndexList[num7];
				int num11 = vertIndexList[num8];
				if (num9 != num10 && num9 != num11 && num10 != num11)
				{
					append_triangle(num9, num10, num11);
					num5++;
				}
			}
			return num5 > 0;
		}

		private int append_vertex(Vector3d v)
		{
			bool lockTaken = false;
			if (parallel_mesh_access)
			{
				mesh_lock.Enter(ref lockTaken);
			}
			int result = Mesh.AppendVertex(v);
			if (lockTaken)
			{
				mesh_lock.Exit();
			}
			return result;
		}

		private int append_triangle(int a, int b, int c)
		{
			bool lockTaken = false;
			if (parallel_mesh_access)
			{
				mesh_lock.Enter(ref lockTaken);
			}
			int result = Mesh.AppendTriangle(a, b, c);
			if (lockTaken)
			{
				mesh_lock.Exit();
			}
			return result;
		}

		private void find_iso(ref Vector3d p1, ref Vector3d p2, double valp1, double valp2, ref Vector3d pIso)
		{
			if (Math.Abs(valp1 - valp2) < 1E-05)
			{
				pIso = (p1 + p2) * 0.5;
				return;
			}
			if (Math.Abs(IsoValue - valp1) < 1E-05)
			{
				pIso = 0.999999 * p1 + 1.0000000000287557E-06 * p2;
				return;
			}
			if (Math.Abs(IsoValue - valp2) < 1E-05)
			{
				pIso = 0.999999 * p2 + 1.0000000000287557E-06 * p1;
				return;
			}
			Vector3d a = p1;
			Vector3d b = p2;
			double num = valp1;
			double num2 = valp2;
			if (valp2 < valp1)
			{
				a = p2;
				b = p1;
				num2 = valp1;
				num = valp2;
			}
			if (RootMode == RootfindingModes.Bisection)
			{
				for (int i = 0; i < RootModeSteps; i++)
				{
					pIso.x = (a.x + b.x) * 0.5;
					pIso.y = (a.y + b.y) * 0.5;
					pIso.z = (a.z + b.z) * 0.5;
					double num3 = Implicit.Value(ref pIso);
					if (num3 < IsoValue)
					{
						a = pIso;
						num = num3;
					}
					else
					{
						b = pIso;
						num2 = num3;
					}
				}
				pIso = Vector3d.Lerp(a, b, 0.5);
				return;
			}
			double num4 = 0.0;
			if (RootMode == RootfindingModes.LerpSteps)
			{
				for (int j = 0; j < RootModeSteps; j++)
				{
					num4 = (IsoValue - num) / (num2 - num);
					pIso.x = a.x + num4 * (b.x - a.x);
					pIso.y = a.y + num4 * (b.y - a.y);
					pIso.z = a.z + num4 * (b.z - a.z);
					double num5 = Implicit.Value(ref pIso);
					if (num5 < IsoValue)
					{
						a = pIso;
						num = num5;
					}
					else
					{
						b = pIso;
						num2 = num5;
					}
				}
			}
			num4 = (IsoValue - num) / (num2 - num);
			pIso.x = a.x + num4 * (b.x - a.x);
			pIso.y = a.y + num4 * (b.y - a.y);
			pIso.z = a.z + num4 * (b.z - a.z);
		}
	}
	public class AutoHoleFill
	{
		private enum UseFillType
		{
			PlanarFill,
			MinimalFill,
			PlanarSpansFill,
			SmoothFill
		}

		public DMesh3 Mesh;

		public double TargetEdgeLength = 2.5;

		public EdgeLoop FillLoop;

		public int[] FillTriangles;

		public AutoHoleFill(DMesh3 mesh, EdgeLoop fillLoop)
		{
			Mesh = mesh;
			FillLoop = fillLoop;
		}

		public bool Apply()
		{
			UseFillType useFillType = classify_hole();
			bool flag = false;
			bool flag2 = false;
			flag = ((useFillType == UseFillType.PlanarFill && !flag2) ? fill_planar() : (useFillType switch
			{
				UseFillType.MinimalFill => fill_minimal(), 
				UseFillType.PlanarSpansFill => fill_planar_spans(), 
				_ => fill_smooth(), 
			}));
			if (!flag && useFillType != UseFillType.SmoothFill)
			{
				flag = fill_smooth();
			}
			return flag;
		}

		private UseFillType classify_hole()
		{
			return UseFillType.MinimalFill;
		}

		private bool fill_smooth()
		{
			return new SmoothedHoleFill(Mesh, FillLoop)
			{
				TargetEdgeLength = TargetEdgeLength,
				SmoothAlpha = 1.0,
				ConstrainToHoleInterior = true
			}.Apply();
		}

		private bool fill_planar()
		{
			Vector3d zero = Vector3d.Zero;
			Vector3d zero2 = Vector3d.Zero;
			int edgeCount = FillLoop.EdgeCount;
			for (int i = 0; i < edgeCount; i++)
			{
				int eID = FillLoop.Edges[i];
				zero += Mesh.GetTriNormal(Mesh.GetEdgeT(eID).a);
				zero2 += Mesh.GetEdgePoint(eID, 0.5);
			}
			zero.Normalize();
			zero2 /= (double)edgeCount;
			PlanarHoleFiller planarHoleFiller = new PlanarHoleFiller(Mesh);
			planarHoleFiller.FillTargetEdgeLen = TargetEdgeLength;
			planarHoleFiller.AddFillLoop(FillLoop);
			planarHoleFiller.SetPlane(zero2, zero);
			return planarHoleFiller.Fill();
		}

		private bool fill_minimal()
		{
			return new MinimalHoleFill(Mesh, FillLoop).Apply();
		}

		private bool fill_planar_spans()
		{
			foreach (KeyValuePair<Vector3d, List<EdgeSpan>> item in find_coplanar_span_sets(Mesh, FillLoop))
			{
				Vector3d key = item.Key;
				List<EdgeSpan> value = item.Value;
				Vector3d vertex = value[0].GetVertex(0);
				if (value.Count > 1)
				{
					foreach (List<EdgeSpan> item2 in sort_planar_spans(value, key))
					{
						if (item2.Count == 1)
						{
							PlanarSpansFiller planarSpansFiller = new PlanarSpansFiller(Mesh, item2);
							planarSpansFiller.FillTargetEdgeLen = TargetEdgeLength;
							planarSpansFiller.SetPlane(vertex, key);
							planarSpansFiller.Fill();
						}
					}
				}
				else
				{
					PlanarSpansFiller planarSpansFiller2 = new PlanarSpansFiller(Mesh, value);
					planarSpansFiller2.FillTargetEdgeLen = TargetEdgeLength;
					planarSpansFiller2.SetPlane(vertex, key);
					planarSpansFiller2.Fill();
				}
			}
			return true;
		}

		private List<List<EdgeSpan>> sort_planar_spans(List<EdgeSpan> allspans, Vector3d normal)
		{
			List<List<EdgeSpan>> list = new List<List<EdgeSpan>>();
			Frame3f polyFrame = new Frame3f(Vector3d.Zero, normal);
			int count = allspans.Count;
			List<PolyLine2d> list2 = new List<PolyLine2d>();
			foreach (EdgeSpan allspan in allspans)
			{
				list2.Add(to_polyline(allspan, polyFrame));
			}
			bool[] array = new bool[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = false;
			}
			bool[] array2 = new bool[count];
			for (int j = 0; j < count; j++)
			{
				if (array2[j])
				{
					continue;
				}
				bool flag = array[j];
				AxisAlignedBox2d bounds = list2[j].Bounds;
				array2[j] = true;
				List<int> list3 = new List<int> { j };
				for (int k = j + 1; k < count; k++)
				{
					if (!array2[k])
					{
						AxisAlignedBox2d bounds2 = list2[k].Bounds;
						if (bounds.Intersects(bounds2))
						{
							array2[k] = true;
							flag = flag || array[k];
							bounds.Contain(bounds2);
							list3.Add(k);
						}
					}
				}
				if (flag)
				{
					continue;
				}
				List<EdgeSpan> list4 = new List<EdgeSpan>();
				foreach (int item in list3)
				{
					list4.Add(allspans[item]);
				}
				list.Add(list4);
			}
			return list;
		}

		private PolyLine2d to_polyline(EdgeSpan span, Frame3f polyFrame)
		{
			int vertexCount = span.VertexCount;
			PolyLine2d polyLine2d = new PolyLine2d();
			for (int i = 0; i < vertexCount; i++)
			{
				polyLine2d.AppendVertex(polyFrame.ToPlaneUV((Vector3f)span.GetVertex(i), 2));
			}
			return polyLine2d;
		}

		private Polygon2d to_polygon(EdgeSpan span, Frame3f polyFrame)
		{
			int vertexCount = span.VertexCount;
			Polygon2d polygon2d = new Polygon2d();
			for (int i = 0; i < vertexCount; i++)
			{
				polygon2d.AppendVertex(polyFrame.ToPlaneUV((Vector3f)span.GetVertex(i), 2));
			}
			return polygon2d;
		}

		private bool self_intersects(PolyLine2d poly)
		{
			Segment2d seg = new Segment2d(poly.Start, poly.End);
			int num = poly.VertexCount - 2;
			for (int i = 1; i < num; i++)
			{
				if (poly.Segment(i).Intersects(ref seg))
				{
					return true;
				}
			}
			return false;
		}

		private Dictionary<Vector3d, List<EdgeSpan>> find_coplanar_span_sets(DMesh3 mesh, EdgeLoop loop)
		{
			double num = 0.999;
			Dictionary<Vector3d, List<EdgeSpan>> dictionary = new Dictionary<Vector3d, List<EdgeSpan>>();
			int num2 = loop.Vertices.Length;
			int num3 = loop.Edges.Length;
			Vector3d[] array = new Vector3d[num3];
			for (int i = 0; i < num3; i++)
			{
				array[i] = mesh.GetTriNormal(mesh.GetEdgeT(loop.Edges[i]).a);
			}
			bool[] array2 = new bool[num2];
			int num4 = 0;
			for (int j = 0; j < num2; j++)
			{
				int num5 = ((j == 0) ? (num2 - 1) : (j - 1));
				if (array[j].Dot(ref array[num5]) > num)
				{
					array2[j] = true;
					num4++;
				}
			}
			if (num4 < 2)
			{
				return null;
			}
			int k;
			for (k = 0; array2[k]; k++)
			{
			}
			int num6 = k;
			int num7 = k + 1;
			while (num7 != k)
			{
				if (!array2[num7])
				{
					num6 = num7;
					num7 = (num7 + 1) % num2;
					continue;
				}
				List<int> list = new List<int> { loop.Edges[num6] };
				int num8 = num7;
				while (array2[num7])
				{
					list.Add(loop.Edges[num7]);
					num7 = (num7 + 1) % num2;
				}
				if (list.Count <= 1)
				{
					continue;
				}
				Vector3d v = array[num8];
				EdgeSpan edgeSpan = EdgeSpan.FromEdges(mesh, list);
				edgeSpan.CheckValidity();
				foreach (KeyValuePair<Vector3d, List<EdgeSpan>> item in dictionary)
				{
					if (item.Key.Dot(ref v) > num)
					{
						v = item.Key;
						break;
					}
				}
				if (!dictionary.TryGetValue(v, out var value))
				{
					dictionary[v] = new List<EdgeSpan> { edgeSpan };
				}
				else
				{
					value.Add(edgeSpan);
				}
			}
			return dictionary;
		}
	}
	public class MergeCoincidentEdges
	{
		private class DuplicateEdge : DynamicPriorityQueueNode
		{
			public int eid;
		}

		public DMesh3 Mesh;

		public double MergeDistance = 9.999999974752427E-07;

		public bool OnlyUniquePairs;

		private double merge_r2;

		public MergeCoincidentEdges(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public virtual bool Apply()
		{
			merge_r2 = MergeDistance * MergeDistance;
			PointSetHashtable pointSetHashtable = new PointSetHashtable(new MeshBoundaryEdgeMidpoints(Mesh));
			int maxAxisSubdivs = 64;
			if (Mesh.TriangleCount > 100000)
			{
				maxAxisSubdivs = 128;
			}
			if (Mesh.TriangleCount > 1000000)
			{
				maxAxisSubdivs = 256;
			}
			pointSetHashtable.Build(maxAxisSubdivs);
			Vector3d a = Vector3d.Zero;
			Vector3d b = Vector3d.Zero;
			Vector3d a2 = Vector3d.Zero;
			Vector3d b2 = Vector3d.Zero;
			int[] array = new int[1024];
			List<int>[] array2 = new List<int>[Mesh.MaxEdgeID];
			HashSet<int> hashSet = new HashSet<int>();
			foreach (int item in Mesh.BoundaryEdgeIndices())
			{
				Vector3d edgePoint = Mesh.GetEdgePoint(item, 0.5);
				int buffer_count;
				while (!pointSetHashtable.FindInBall(edgePoint, MergeDistance, array, out buffer_count))
				{
					array = new int[array.Length];
				}
				if (buffer_count == 1 && array[0] != item)
				{
					throw new Exception("MergeCoincidentEdges.Apply: how could this happen?!");
				}
				if (buffer_count <= 1)
				{
					continue;
				}
				Mesh.GetEdgeV(item, ref a, ref b);
				List<int> list = new List<int>(buffer_count - 1);
				for (int i = 0; i < buffer_count; i++)
				{
					if (array[i] != item)
					{
						Mesh.GetEdgeV(array[i], ref a2, ref b2);
						if (is_same_edge(ref a, ref b, ref a2, ref b2))
						{
							list.Add(array[i]);
						}
					}
				}
				if (list.Count > 0)
				{
					array2[item] = list;
					hashSet.Add(item);
				}
			}
			DynamicPriorityQueue<DuplicateEdge> dynamicPriorityQueue = new DynamicPriorityQueue<DuplicateEdge>();
			foreach (int item2 in hashSet)
			{
				if (OnlyUniquePairs)
				{
					if (array2[item2].Count != 1)
					{
						continue;
					}
					foreach (int item3 in array2[item2])
					{
						if (array2[item3].Count == 1)
						{
							_ = array2[item3][0];
						}
					}
				}
				dynamicPriorityQueue.Enqueue(new DuplicateEdge
				{
					eid = item2
				}, array2[item2].Count);
			}
			while (dynamicPriorityQueue.Count > 0)
			{
				DuplicateEdge duplicateEdge = dynamicPriorityQueue.Dequeue();
				if (!Mesh.IsEdge(duplicateEdge.eid) || array2[duplicateEdge.eid] == null || !hashSet.Contains(duplicateEdge.eid) || !Mesh.IsBoundaryEdge(duplicateEdge.eid))
				{
					continue;
				}
				List<int> list2 = array2[duplicateEdge.eid];
				bool flag = false;
				int num = 0;
				for (int j = 0; j < list2.Count; j++)
				{
					if (flag)
					{
						break;
					}
					int num2 = list2[j];
					if (Mesh.IsEdge(num2) && Mesh.IsBoundaryEdge(num2))
					{
						if (Mesh.MergeEdges(duplicateEdge.eid, num2, out var _) != MeshResult.Ok)
						{
							list2.RemoveAt(j);
							j--;
							array2[num2].Remove(duplicateEdge.eid);
							num++;
						}
						else
						{
							flag = true;
							array2[num2] = null;
							hashSet.Remove(num2);
						}
					}
				}
				if (flag)
				{
					array2[duplicateEdge.eid] = null;
					hashSet.Remove(duplicateEdge.eid);
				}
				else
				{
					array2[duplicateEdge.eid] = null;
					hashSet.Remove(duplicateEdge.eid);
				}
			}
			return true;
		}

		private bool is_same_edge(ref Vector3d a, ref Vector3d b, ref Vector3d c, ref Vector3d d)
		{
			if (!(a.DistanceSquared(c) < merge_r2) || !(b.DistanceSquared(d) < merge_r2))
			{
				if (a.DistanceSquared(d) < merge_r2)
				{
					return b.DistanceSquared(c) < merge_r2;
				}
				return false;
			}
			return true;
		}
	}
	public class MeshAssembly
	{
		public DMesh3 SourceMesh;

		public bool HasNoVoids;

		public List<DMesh3> ClosedSolids;

		public List<DMesh3> OpenMeshes;

		public MeshAssembly(DMesh3 sourceMesh)
		{
			SourceMesh = sourceMesh;
			ClosedSolids = new List<DMesh3>();
			OpenMeshes = new List<DMesh3>();
		}

		public void Decompose()
		{
			process();
		}

		private void process()
		{
			DMesh3 dMesh = SourceMesh;
			if (!dMesh.CachedIsClosed)
			{
				dMesh = new DMesh3(SourceMesh);
				new RemoveDuplicateTriangles(dMesh).Apply();
				new MergeCoincidentEdges(dMesh).Apply();
			}
			DMesh3[] array = MeshConnectedComponents.Separate(dMesh);
			List<DMesh3> list = new List<DMesh3>();
			DMesh3[] array2 = array;
			foreach (DMesh3 dMesh2 in array2)
			{
				if (!dMesh2.CachedIsClosed)
				{
					OpenMeshes.Add(dMesh2);
				}
				else
				{
					list.Add(dMesh2);
				}
			}
			if (list.Count != 0)
			{
				if (list.Count == 1)
				{
					ClosedSolids = new List<DMesh3> { list[0] };
				}
				if (HasNoVoids)
				{
					ClosedSolids = process_solids_novoid(list);
				}
				else
				{
					ClosedSolids = process_solids(list);
				}
			}
		}

		private List<DMesh3> process_solids(List<DMesh3> solid_components)
		{
			DMesh3 dMesh = new DMesh3(SourceMesh.Components | MeshComponents.FaceGroups);
			MeshEditor meshEditor = new MeshEditor(dMesh);
			foreach (DMesh3 solid_component in solid_components)
			{
				meshEditor.AppendMesh(solid_component, dMesh.AllocateTriangleGroup());
			}
			return new List<DMesh3> { dMesh };
		}

		private List<DMesh3> process_solids_novoid(List<DMesh3> solid_components)
		{
			return solid_components;
		}
	}
	public class MeshAutoRepair
	{
		public enum RemoveModes
		{
			None,
			Interior,
			Occluded
		}

		public double RepairTolerance = 9.999999974752427E-07;

		public double MinEdgeLengthTol = 0.0001;

		public int ErosionIterations = 5;

		public RemoveModes RemoveMode;

		public ProgressCancel Progress;

		public DMesh3 Mesh;

		protected virtual bool Cancelled()
		{
			if (Progress != null)
			{
				return Progress.Cancelled();
			}
			return false;
		}

		public MeshAutoRepair(DMesh3 mesh3)
		{
			Mesh = mesh3;
		}

		public bool Apply()
		{
			bool flag = false;
			if (flag)
			{
				Mesh.CheckValidity();
			}
			do_remove_inside();
			if (Cancelled())
			{
				return false;
			}
			int num = 0;
			while (true)
			{
				repair_orientation(bGlobal: false);
				if (Cancelled())
				{
					return false;
				}
				repair_cracks(bUniqueOnly: true, RepairTolerance);
				if (Mesh.IsClosed())
				{
					break;
				}
				if (Cancelled())
				{
					return false;
				}
				collapse_all_degenerate_edges(RepairTolerance * 0.5, bBoundaryOnly: true);
				if (Cancelled())
				{
					return false;
				}
				repair_cracks(bUniqueOnly: true, 2.0 * RepairTolerance);
				if (Cancelled())
				{
					return false;
				}
				repair_cracks(bUniqueOnly: false, 2.0 * RepairTolerance);
				if (Cancelled())
				{
					return false;
				}
				if (Mesh.IsClosed())
				{
					break;
				}
				repair_orientation(bGlobal: false);
				if (Cancelled())
				{
					return false;
				}
				if (flag)
				{
					Mesh.CheckValidity();
				}
				remove_loners();
				int nRemaining = 0;
				fill_trivial_holes(out var nRemaining2, out var saw_spans);
				if (Cancelled())
				{
					return false;
				}
				if (Mesh.IsClosed())
				{
					break;
				}
				fill_any_holes(out nRemaining2, out saw_spans);
				if (Cancelled())
				{
					return false;
				}
				if (saw_spans)
				{
					disconnect_bowties(out nRemaining);
					fill_any_holes(out nRemaining2, out saw_spans);
				}
				if (Cancelled())
				{
					return false;
				}
				if (Mesh.IsClosed())
				{
					break;
				}
				disconnect_bowties(out nRemaining);
				if (Cancelled())
				{
					return false;
				}
				if (num == 0 && !Mesh.IsClosed())
				{
					num++;
					continue;
				}
				if (num > ErosionIterations || Mesh.IsClosed())
				{
					break;
				}
				num++;
				MeshFaceSelection meshFaceSelection = new MeshFaceSelection(Mesh);
				foreach (int item in MeshIterators.BoundaryEdges(Mesh))
				{
					meshFaceSelection.SelectEdgeTris(item);
				}
				MeshEditor.RemoveTriangles(Mesh, meshFaceSelection);
			}
			if (MinEdgeLengthTol > 0.0)
			{
				collapse_all_degenerate_edges(MinEdgeLengthTol, bBoundaryOnly: false);
			}
			if (Cancelled())
			{
				return false;
			}
			repair_orientation(bGlobal: true);
			if (Cancelled())
			{
				return false;
			}
			if (flag)
			{
				Mesh.CheckValidity();
			}
			Mesh = new DMesh3(Mesh, bCompact: true);
			MeshNormals.QuickCompute(Mesh);
			return true;
		}

		private void fill_trivial_holes(out int nRemaining, out bool saw_spans)
		{
			MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh);
			nRemaining = 0;
			saw_spans = meshBoundaryLoops.SawOpenSpans;
			foreach (EdgeLoop item in meshBoundaryLoops)
			{
				if (Cancelled())
				{
					break;
				}
				bool flag = false;
				if (item.VertexCount == 3)
				{
					flag = new SimpleHoleFiller(Mesh, item).Fill();
				}
				else if (item.VertexCount == 4)
				{
					flag = new MinimalHoleFill(Mesh, item).Apply();
					if (!flag)
					{
						flag = new SimpleHoleFiller(Mesh, item).Fill();
					}
				}
				if (!flag)
				{
					nRemaining++;
				}
			}
		}

		private void fill_any_holes(out int nRemaining, out bool saw_spans)
		{
			MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh);
			nRemaining = 0;
			saw_spans = meshBoundaryLoops.SawOpenSpans;
			foreach (EdgeLoop item in meshBoundaryLoops)
			{
				if (Cancelled())
				{
					break;
				}
				if (!new MinimalHoleFill(Mesh, item).Apply())
				{
					if (Cancelled())
					{
						break;
					}
					new SimpleHoleFiller(Mesh, item).Fill();
				}
			}
		}

		private bool repair_cracks(bool bUniqueOnly, double mergeDist)
		{
			try
			{
				return new MergeCoincidentEdges(Mesh)
				{
					OnlyUniquePairs = bUniqueOnly,
					MergeDistance = mergeDist
				}.Apply();
			}
			catch (Exception)
			{
				return false;
			}
		}

		private bool remove_duplicate_faces(double vtxTolerance, out int nRemoved)
		{
			nRemoved = 0;
			try
			{
				RemoveDuplicateTriangles removeDuplicateTriangles = new RemoveDuplicateTriangles(Mesh);
				removeDuplicateTriangles.VertexTolerance = vtxTolerance;
				bool result = removeDuplicateTriangles.Apply();
				nRemoved = removeDuplicateTriangles.Removed;
				return result;
			}
			catch (Exception)
			{
				return false;
			}
		}

		private bool collapse_degenerate_edges(double minLength, bool bBoundaryOnly, out int collapseCount)
		{
			collapseCount = 0;
			foreach (int item in MathUtil.ModuloIteration(Mesh.MaxEdgeID))
			{
				if (Cancelled())
				{
					break;
				}
				if (!Mesh.IsEdge(item))
				{
					continue;
				}
				bool flag = Mesh.IsBoundaryEdge(item);
				if (bBoundaryOnly && !flag)
				{
					continue;
				}
				Index2i edgeV = Mesh.GetEdgeV(item);
				Vector3d vertex = Mesh.GetVertex(edgeV.a);
				Vector3d vertex2 = Mesh.GetVertex(edgeV.b);
				if (!(vertex.Distance(vertex2) < minLength))
				{
					continue;
				}
				int num = (Mesh.IsBoundaryVertex(edgeV.a) ? edgeV.a : edgeV.b);
				int vRemove = ((num == edgeV.a) ? edgeV.b : edgeV.a);
				if (Mesh.CollapseEdge(num, vRemove, out var _) == MeshResult.Ok)
				{
					collapseCount++;
					if (!Mesh.IsBoundaryVertex(num) || flag)
					{
						Mesh.SetVertex(num, (vertex + vertex2) * 0.5);
					}
				}
			}
			return true;
		}

		private bool collapse_all_degenerate_edges(double minLength, bool bBoundaryOnly)
		{
			bool flag = true;
			while (flag && !Cancelled())
			{
				collapse_degenerate_edges(minLength, bBoundaryOnly, out var collapseCount);
				if (collapseCount == 0)
				{
					flag = false;
				}
			}
			return true;
		}

		private bool disconnect_bowties(out int nRemaining)
		{
			MeshEditor meshEditor = new MeshEditor(Mesh);
			nRemaining = meshEditor.DisconnectAllBowties();
			return true;
		}

		private void repair_orientation(bool bGlobal)
		{
			MeshRepairOrientation meshRepairOrientation = new MeshRepairOrientation(Mesh);
			meshRepairOrientation.OrientComponents();
			if (!Cancelled() && bGlobal)
			{
				meshRepairOrientation.SolveGlobalOrientation();
			}
		}

		private bool remove_interior(out int nRemoved)
		{
			RemoveOccludedTriangles removeOccludedTriangles = new RemoveOccludedTriangles(Mesh);
			removeOccludedTriangles.PerVertex = true;
			removeOccludedTriangles.InsideMode = RemoveOccludedTriangles.CalculationMode.FastWindingNumber;
			removeOccludedTriangles.Apply();
			nRemoved = removeOccludedTriangles.RemovedT.Count();
			return true;
		}

		private bool remove_occluded(out int nRemoved)
		{
			RemoveOccludedTriangles removeOccludedTriangles = new RemoveOccludedTriangles(Mesh);
			removeOccludedTriangles.PerVertex = true;
			removeOccludedTriangles.InsideMode = RemoveOccludedTriangles.CalculationMode.SimpleOcclusionTest;
			removeOccludedTriangles.Apply();
			nRemoved = removeOccludedTriangles.RemovedT.Count();
			return true;
		}

		private bool do_remove_inside()
		{
			int nRemoved = 0;
			if (RemoveMode == RemoveModes.Interior)
			{
				return remove_interior(out nRemoved);
			}
			if (RemoveMode == RemoveModes.Occluded)
			{
				return remove_occluded(out nRemoved);
			}
			return true;
		}

		private bool remove_loners()
		{
			MeshEditor.RemoveIsolatedTriangles(Mesh);
			return true;
		}
	}
	public class MeshInsertProjectedPolygon
	{
		public DMesh3 Mesh;

		public int SeedTriangle = -1;

		public Frame3f ProjectFrame;

		public bool SimplifyInsertion = true;

		public bool RemovePolygonInterior = true;

		public RegionOperator ModifiedRegion;

		public int[] InsertedPolygonVerts;

		public EdgeLoop InsertedLoop;

		public int[] InteriorTriangles;

		public Polygon2d Polygon;

		public MeshInsertProjectedPolygon(DMesh3 mesh, Polygon2d poly, Frame3f frame, int seedTri)
		{
			Mesh = mesh;
			Polygon = new Polygon2d(poly);
			ProjectFrame = frame;
			SeedTriangle = seedTri;
		}

		public MeshInsertProjectedPolygon(DMesh3 mesh, DCurve3 polygon3, Frame3f frame, int seedTri)
		{
			if (!polygon3.Closed)
			{
				throw new Exception("MeshInsertPolyCurve(): only closed polygon3 supported for now");
			}
			Mesh = mesh;
			ProjectFrame = frame;
			SeedTriangle = seedTri;
			Polygon = new Polygon2d();
			foreach (Vector3d vertex in polygon3.Vertices)
			{
				Vector2f vector2f = frame.ToPlaneUV((Vector3f)vertex, 2);
				Polygon.AppendVertex(vector2f);
			}
		}

		public virtual ValidationStatus Validate()
		{
			if (!Mesh.IsTriangle(SeedTriangle))
			{
				return ValidationStatus.NotATriangle;
			}
			return ValidationStatus.Ok;
		}

		public bool Insert()
		{
			Func<int, bool> func = delegate(int vid)
			{
				Vector3d vertex = Mesh.GetVertex(vid);
				Vector2f vector2f = ProjectFrame.ToPlaneUV((Vector3f)vertex, 2);
				return Polygon.Contains(vector2f);
			};
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(Mesh);
			Index3i triangle = Mesh.GetTriangle(SeedTriangle);
			List<int> list = new List<int>();
			for (int num = 0; num < 3; num++)
			{
				if (func(triangle[num]))
				{
					list.Add(triangle[num]);
				}
			}
			if (list.Count == 0)
			{
				list.Add(triangle.a);
				list.Add(triangle.b);
				list.Add(triangle.c);
			}
			meshVertexSelection.FloodFill(list.ToArray(), func);
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(Mesh, meshVertexSelection, 1);
			meshFaceSelection.ExpandToOneRingNeighbours();
			meshFaceSelection.FillEars(bFillTinyHoles: true);
			RegionOperator regionOperator = new RegionOperator(Mesh, meshFaceSelection);
			DMesh3 subMesh = regionOperator.Region.SubMesh;
			Vector3d[] initialPositions = new Vector3d[subMesh.MaxVertexID];
			MeshTransforms.PerVertexTransform(subMesh, subMesh.VertexIndices(), delegate(Vector3d vector3d2, int vid)
			{
				Vector2f vector2f = ProjectFrame.ToPlaneUV((Vector3f)vector3d2, 2);
				initialPositions[vid] = vector3d2;
				return new Vector3d(vector2f.x, vector2f.y, 0.0);
			});
			DMesh3 dMesh = new DMesh3(subMesh);
			DMeshAABBTree3 dMeshAABBTree = new DMeshAABBTree3(dMesh, autoBuild: true);
			MeshInsertUVPolyCurve meshInsertUVPolyCurve = new MeshInsertUVPolyCurve(subMesh, Polygon);
			if (!meshInsertUVPolyCurve.Apply())
			{
				throw new Exception("insertUV.Apply() failed");
			}
			if (SimplifyInsertion)
			{
				meshInsertUVPolyCurve.Simplify();
			}
			int[] curveVertices = meshInsertUVPolyCurve.CurveVertices;
			EdgeLoop insertedLoop = null;
			if (meshInsertUVPolyCurve.Loops.Count == 1)
			{
				insertedLoop = meshInsertUVPolyCurve.Loops[0];
			}
			List<int> list2 = new List<int>();
			foreach (int item in subMesh.TriangleIndices())
			{
				Vector3d triCentroid = subMesh.GetTriCentroid(item);
				if (Polygon.Contains(triCentroid.xy))
				{
					list2.Add(item);
				}
			}
			if (RemovePolygonInterior)
			{
				new MeshEditor(subMesh).RemoveTriangles(list2, bRemoveIsolatedVerts: true);
				InteriorTriangles = null;
			}
			else
			{
				InteriorTriangles = list2.ToArray();
			}
			Vector3d v = Vector3d.Zero;
			Vector3d v2 = Vector3d.Zero;
			Vector3d v3 = Vector3d.Zero;
			foreach (int item2 in subMesh.VertexIndices())
			{
				Vector3d vPoint = subMesh.GetVertex(item2);
				int tID = dMeshAABBTree.FindNearestTriangle(vPoint);
				Index3i triangle2 = dMesh.GetTriangle(tID);
				dMesh.GetTriVertices(tID, ref v, ref v2, ref v3);
				Vector3d vector3d = MathUtil.BarycentricCoords(ref vPoint, ref v, ref v2, ref v3);
				Vector3d vNewPos = vector3d.x * initialPositions[triangle2.a] + vector3d.y * initialPositions[triangle2.b] + vector3d.z * initialPositions[triangle2.c];
				subMesh.SetVertex(item2, vNewPos);
			}
			return BackPropagate(regionOperator, curveVertices, insertedLoop);
		}

		protected virtual bool BackPropagate(RegionOperator regionOp, int[] insertedPolyVerts, EdgeLoop insertedLoop)
		{
			bool num = regionOp.BackPropropagate();
			if (num)
			{
				ModifiedRegion = regionOp;
				IndexUtil.Apply(insertedPolyVerts, regionOp.ReinsertSubToBaseMapV);
				InsertedPolygonVerts = insertedPolyVerts;
				if (insertedLoop != null)
				{
					InsertedLoop = MeshIndexUtil.MapLoopViaVertexMap(regionOp.ReinsertSubToBaseMapV, regionOp.Region.SubMesh, regionOp.Region.BaseMesh, insertedLoop);
					if (RemovePolygonInterior)
					{
						InsertedLoop.CorrectOrientation();
					}
				}
			}
			return num;
		}
	}
	public class MeshRepairOrientation
	{
		private class Component
		{
			public List<int> triangles;

			public double outFacing;

			public double inFacing;
		}

		public DMesh3 Mesh;

		private DMeshAABBTree3 spatial;

		private List<Component> Components = new List<Component>();

		protected DMeshAABBTree3 Spatial
		{
			get
			{
				if (spatial == null)
				{
					spatial = new DMeshAABBTree3(Mesh, autoBuild: true);
				}
				return spatial;
			}
		}

		public MeshRepairOrientation(DMesh3 mesh3, DMeshAABBTree3 spatial = null)
		{
			Mesh = mesh3;
			this.spatial = spatial;
		}

		public void OrientComponents()
		{
			Components = new List<Component>();
			HashSet<int> hashSet = new HashSet<int>(Mesh.TriangleIndices());
			List<int> list = new List<int>();
			while (hashSet.Count > 0)
			{
				Component component = new Component();
				component.triangles = new List<int>();
				list.Clear();
				int item = hashSet.First();
				hashSet.Remove(item);
				component.triangles.Add(item);
				list.Add(item);
				while (list.Count > 0)
				{
					int tID = list[list.Count - 1];
					list.RemoveAt(list.Count - 1);
					Index3i triangle = Mesh.GetTriangle(tID);
					Index3i triNeighbourTris = Mesh.GetTriNeighbourTris(tID);
					for (int i = 0; i < 3; i++)
					{
						int num = triNeighbourTris[i];
						if (hashSet.Contains(num))
						{
							int b = triangle[i];
							int a = triangle[(i + 1) % 3];
							Index3i tri_verts = Mesh.GetTriangle(num);
							if (IndexUtil.find_tri_ordered_edge(a, b, ref tri_verts) == -1)
							{
								Mesh.ReverseTriOrientation(num);
							}
							list.Add(num);
							hashSet.Remove(num);
							component.triangles.Add(num);
						}
					}
				}
				Components.Add(component);
			}
		}

		public void ComputeStatistics()
		{
			_ = Spatial;
			foreach (Component component in Components)
			{
				compute_statistics(component);
			}
		}

		private void compute_statistics(Component c)
		{
			int count = c.triangles.Count;
			c.inFacing = (c.outFacing = 0.0);
			double dist = 2.0 * Mesh.CachedBounds.DiagonalLength;
			HashSet<int> hashSet = new HashSet<int>(c.triangles);
			spatial.TriangleFilterF = hashSet.Contains;
			SpinLock count_lock = default(SpinLock);
			gParallel.BlockStartEnd(0, count - 1, delegate(int a, int b)
			{
				for (int i = a; i <= b; i++)
				{
					int num = c.triangles[i];
					Mesh.GetTriInfo(num, out var normal, out var fArea, out var vCentroid);
					if (!(fArea < 9.999999974752427E-07))
					{
						Vector3d origin = vCentroid + dist * normal;
						Vector3d origin2 = vCentroid - dist * normal;
						int num2 = spatial.FindNearestHitTriangle(new Ray3d(origin, -normal));
						int num3 = spatial.FindNearestHitTriangle(new Ray3d(origin2, normal));
						if ((num2 == num || num3 == num) && (num2 != num || num3 != num))
						{
							bool lockTaken = false;
							count_lock.Enter(ref lockTaken);
							if (num3 == num)
							{
								c.inFacing += fArea;
							}
							else if (num2 == num)
							{
								c.outFacing += fArea;
							}
							count_lock.Exit();
						}
					}
				}
			});
			spatial.TriangleFilterF = null;
		}

		public void SolveGlobalOrientation()
		{
			ComputeStatistics();
			MeshEditor meshEditor = new MeshEditor(Mesh);
			foreach (Component component in Components)
			{
				if (component.inFacing > component.outFacing)
				{
					meshEditor.ReverseTriangles(component.triangles);
				}
			}
		}
	}
	public class MeshSpatialSort
	{
		public class ComponentMesh
		{
			public object Identifier;

			public DMesh3 Mesh;

			public bool IsClosed;

			public DMeshAABBTree3 Spatial;

			public AxisAlignedBox3d Bounds;

			public List<ComponentMesh> InsideOf = new List<ComponentMesh>();

			public List<ComponentMesh> InsideSet = new List<ComponentMesh>();

			public ComponentMesh(DMesh3 mesh, object identifier, DMeshAABBTree3 spatial)
			{
				Mesh = mesh;
				Identifier = identifier;
				IsClosed = mesh.IsClosed();
				Spatial = spatial;
				Bounds = mesh.CachedBounds;
			}

			public bool Contains(ComponentMesh mesh2, double fIso = 0.5)
			{
				if (Spatial == null)
				{
					return false;
				}
				Spatial.FastWindingNumber(Vector3d.Zero);
				int vertexCount = mesh2.Mesh.VertexCount;
				bool contained = true;
				gParallel.BlockStartEnd(0, vertexCount - 1, delegate(int a, int b)
				{
					if (contained)
					{
						for (int i = a; i <= b && contained; i++)
						{
							Vector3d vertex = mesh2.Mesh.GetVertex(i);
							if (Math.Abs(Spatial.FastWindingNumber(vertex)) < fIso)
							{
								contained = false;
								break;
							}
						}
					}
				}, 100);
				return contained;
			}
		}

		public class MeshSolid
		{
			public ComponentMesh Outer;

			public List<ComponentMesh> Cavities = new List<ComponentMesh>();
		}

		public List<ComponentMesh> Components;

		public List<MeshSolid> Solids;

		public bool AllowOpenContainers;

		public double FastWindingIso = 0.5;

		public MeshSpatialSort()
		{
			Components = new List<ComponentMesh>();
		}

		public void AddMesh(DMesh3 mesh, object identifier, DMeshAABBTree3 spatial = null)
		{
			ComponentMesh componentMesh = new ComponentMesh(mesh, identifier, spatial);
			if (spatial == null && (componentMesh.IsClosed || AllowOpenContainers))
			{
				componentMesh.Spatial = new DMeshAABBTree3(mesh, autoBuild: true);
			}
			Components.Add(componentMesh);
		}

		public void Sort()
		{
			int N = Components.Count;
			ComponentMesh[] comps = Components.ToArray();
			Array.Sort(comps, (ComponentMesh i, ComponentMesh j) => (!i.Bounds.Contains(j.Bounds)) ? 1 : (-1));
			bool[] bIsContained = new bool[N];
			Dictionary<int, List<int>> ContainSets = new Dictionary<int, List<int>>();
			Dictionary<int, List<int>> ContainedParents = new Dictionary<int, List<int>>();
			SpinLock dataLock = default(SpinLock);
			gParallel.ForEach(Interval1i.Range(N), delegate(int i)
			{
				ComponentMesh componentMesh4 = comps[i];
				if (componentMesh4.IsClosed || AllowOpenContainers)
				{
					for (int j = 0; j < N; j++)
					{
						if (i != j)
						{
							ComponentMesh componentMesh5 = comps[j];
							if (componentMesh4.Bounds.Contains(componentMesh5.Bounds) && componentMesh4.Contains(componentMesh5))
							{
								bool lockTaken = false;
								dataLock.Enter(ref lockTaken);
								componentMesh5.InsideOf.Add(componentMesh4);
								componentMesh4.InsideSet.Add(componentMesh5);
								if (!ContainSets.ContainsKey(i))
								{
									ContainSets.Add(i, new List<int>());
								}
								ContainSets[i].Add(j);
								bIsContained[j] = true;
								if (!ContainedParents.ContainsKey(j))
								{
									ContainedParents.Add(j, new List<int>());
								}
								ContainedParents[j].Add(i);
								dataLock.Exit();
							}
						}
					}
				}
			});
			List<MeshSolid> list = new List<MeshSolid>();
			HashSet<ComponentMesh> hashSet = new HashSet<ComponentMesh>();
			Dictionary<ComponentMesh, int> dictionary = new Dictionary<ComponentMesh, int>();
			List<int> list2 = new List<int>();
			for (int num = 0; num < N; num++)
			{
				ComponentMesh componentMesh = comps[num];
				if (!bIsContained[num])
				{
					MeshSolid item = new MeshSolid
					{
						Outer = componentMesh
					};
					int count = list.Count;
					dictionary[componentMesh] = count;
					hashSet.Add(componentMesh);
					if (ContainSets.ContainsKey(num))
					{
						list2.Add(num);
					}
					list.Add(item);
				}
			}
			while (list2.Count > 0)
			{
				List<int> list3 = new List<int>();
				foreach (int item5 in list2)
				{
					ComponentMesh key = comps[item5];
					int index = dictionary[key];
					foreach (int item6 in ContainSets[item5])
					{
						ComponentMesh item2 = comps[item6];
						if (ContainedParents[item6].Count <= 1)
						{
							list[index].Cavities.Add(item2);
							hashSet.Add(item2);
							if (ContainSets.ContainsKey(item6))
							{
								list3.Add(item6);
							}
						}
					}
					list3.Add(item5);
				}
				foreach (int item7 in list3)
				{
					ContainSets.Remove(item7);
					foreach (int item8 in new List<int>(ContainedParents.Keys))
					{
						if (ContainedParents[item8].Contains(item7))
						{
							ContainedParents[item8].Remove(item7);
						}
					}
				}
				list2.Clear();
				for (int num2 = 0; num2 < N; num2++)
				{
					ComponentMesh componentMesh2 = comps[num2];
					if (!hashSet.Contains(componentMesh2) && ContainSets.ContainsKey(num2) && ContainedParents[num2].Count <= 0)
					{
						MeshSolid item3 = new MeshSolid
						{
							Outer = componentMesh2
						};
						int count2 = list.Count;
						dictionary[componentMesh2] = count2;
						hashSet.Add(componentMesh2);
						if (ContainSets.ContainsKey(num2))
						{
							list2.Add(num2);
						}
						list.Add(item3);
					}
				}
			}
			for (int num3 = 0; num3 < N; num3++)
			{
				ComponentMesh componentMesh3 = comps[num3];
				if (!hashSet.Contains(componentMesh3))
				{
					MeshSolid item4 = new MeshSolid
					{
						Outer = componentMesh3
					};
					list.Add(item4);
				}
			}
			Solids = list;
		}
	}
	public class MeshStitchLoops
	{
		private struct span
		{
			public Interval1i span0;

			public Interval1i span1;
		}

		public DMesh3 Mesh;

		public EdgeLoop Loop0;

		public EdgeLoop Loop1;

		public bool TrustLoopOrientations = true;

		public SetGroupBehavior Group = SetGroupBehavior.AutoGenerate;

		private List<span> spans = new List<span>();

		public MeshStitchLoops(DMesh3 mesh, EdgeLoop l0, EdgeLoop l1)
		{
			Mesh = mesh;
			Loop0 = new EdgeLoop(l0);
			Loop1 = new EdgeLoop(l1);
			span item = new span
			{
				span0 = new Interval1i(0, 0),
				span1 = new Interval1i(0, 0)
			};
			spans.Add(item);
		}

		public void AddKnownCorrespondences(int[] verts0, int[] verts1)
		{
			int num = verts0.Length;
			if (num != verts1.Length)
			{
				throw new Exception("MeshStitchLoops.AddKnownCorrespondence: lengths not the same!");
			}
			List<Index2i> list = new List<Index2i>();
			for (int i = 0; i < num; i++)
			{
				int ii = Loop0.FindVertexIndex(verts0[i]);
				int jj = Loop1.FindVertexIndex(verts1[i]);
				list.Add(new Index2i(ii, jj));
			}
			list.Sort((Index2i pair1, Index2i pair2) => pair1.a.CompareTo(pair2.a));
			List<span> list2 = new List<span>();
			for (int num2 = 0; num2 < list.Count; num2++)
			{
				Index2i index2i = list[num2];
				Index2i index2i2 = list[(num2 + 1) % list.Count];
				span item = new span
				{
					span0 = new Interval1i(index2i.a, index2i2.a),
					span1 = new Interval1i(index2i.b, index2i2.b)
				};
				list2.Add(item);
			}
			spans = list2;
		}

		public bool Stitch()
		{
			if (spans.Count == 1)
			{
				throw new Exception("MeshStitchLoops.Stitch: blind stitching not supported yet...");
			}
			int groupID = Group.GetGroupID(Mesh);
			bool result = true;
			int count = spans.Count;
			for (int i = 0; i < count; i++)
			{
				span s = spans[i];
				if (!stitch_span_simple(s, groupID))
				{
					result = false;
				}
			}
			return result;
		}

		private bool stitch_span_simple(span s, int gid)
		{
			bool result = true;
			int num = Loop0.Vertices.Length;
			int num2 = Loop1.Vertices.Length;
			int num3 = s.span0.a;
			int b = s.span0.b;
			int num4 = s.span1.a;
			int b2 = s.span1.b;
			while (num3 != b && num4 != b2)
			{
				int num5 = (num3 + 1) % num;
				int num6 = (num4 + 1) % num2;
				int b3 = Loop0.Vertices[num3];
				int num7 = Loop0.Vertices[num5];
				int num8 = Loop1.Vertices[num4];
				int b4 = Loop1.Vertices[num6];
				if (!add_triangle(num7, b3, num8, gid))
				{
					result = false;
				}
				if (!add_triangle(num8, b4, num7, gid))
				{
					result = false;
				}
				num3 = num5;
				num4 = num6;
			}
			int c = Loop1.Vertices[num4];
			while (num3 != b)
			{
				int num9 = (num3 + 1) % num;
				int b5 = Loop0.Vertices[num3];
				int a = Loop0.Vertices[num9];
				if (!add_triangle(a, b5, c, gid))
				{
					result = false;
				}
				num3 = num9;
			}
			int c2 = Loop0.Vertices[num3];
			while (num4 != b2)
			{
				int num10 = (num4 + 1) % num2;
				int a2 = Loop1.Vertices[num4];
				int b6 = Loop1.Vertices[num10];
				if (!add_triangle(a2, b6, c2, gid))
				{
					result = false;
				}
				num4 = num10;
			}
			return result;
		}

		private bool add_triangle(int a, int b, int c, int gid)
		{
			int num = -1;
			if (!TrustLoopOrientations)
			{
				int eID = Mesh.FindEdge(a, b);
				Index2i orientedBoundaryEdgeV = Mesh.GetOrientedBoundaryEdgeV(eID);
				num = Mesh.AppendTriangle(orientedBoundaryEdgeV.b, orientedBoundaryEdgeV.a, c, gid);
			}
			else
			{
				num = Mesh.AppendTriangle(a, b, c, gid);
			}
			return num >= 0;
		}
	}
	public class MeshTopology
	{
		public DMesh3 Mesh;

		private double crease_angle = 30.0;

		public HashSet<int> BoundaryEdges;

		public HashSet<int> CreaseEdges;

		public HashSet<int> AllEdges;

		public HashSet<int> AllVertices;

		public HashSet<int> JunctionVertices;

		public EdgeLoop[] Loops;

		public EdgeSpan[] Spans;

		private int topo_timestamp = -1;

		public bool IgnoreTimestamp;

		public double CreaseAngle
		{
			get
			{
				return crease_angle;
			}
			set
			{
				crease_angle = value;
				invalidate_topology();
			}
		}

		public MeshTopology(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public void Compute()
		{
			validate_topology();
		}

		public void AddRemeshConstraints(MeshConstraints constraints)
		{
			validate_topology();
			int num = 10;
			EdgeSpan[] spans = Spans;
			foreach (EdgeSpan edgeSpan in spans)
			{
				DCurveProjectionTarget target = new DCurveProjectionTarget(edgeSpan.ToCurve());
				MeshConstraintUtil.ConstrainVtxSpanTo(constraints, Mesh, edgeSpan.Vertices, target, num++);
			}
			EdgeLoop[] loops = Loops;
			foreach (EdgeLoop edgeLoop in loops)
			{
				DCurveProjectionTarget target2 = new DCurveProjectionTarget(edgeLoop.ToCurve());
				MeshConstraintUtil.ConstrainVtxLoopTo(constraints, Mesh, edgeLoop.Vertices, target2, num++);
			}
			VertexConstraint pinned = VertexConstraint.Pinned;
			pinned.FixedSetID = -1;
			foreach (int junctionVertex in JunctionVertices)
			{
				if (constraints.HasVertexConstraint(junctionVertex))
				{
					VertexConstraint vertexConstraint = constraints.GetVertexConstraint(junctionVertex);
					vertexConstraint.Target = null;
					vertexConstraint.Fixed = true;
					vertexConstraint.FixedSetID = -1;
					constraints.SetOrUpdateVertexConstraint(junctionVertex, vertexConstraint);
				}
				else
				{
					constraints.SetOrUpdateVertexConstraint(junctionVertex, pinned);
				}
			}
		}

		private void invalidate_topology()
		{
			topo_timestamp = -1;
		}

		private void validate_topology()
		{
			if ((!IgnoreTimestamp || AllEdges == null) && Mesh.ShapeTimestamp != topo_timestamp)
			{
				find_crease_edges(CreaseAngle);
				extract_topology();
				topo_timestamp = Mesh.ShapeTimestamp;
			}
		}

		private void find_crease_edges(double angle_tol)
		{
			CreaseEdges = new HashSet<int>();
			BoundaryEdges = new HashSet<int>();
			double num = Math.Cos(angle_tol * (Math.PI / 180.0));
			foreach (int item in Mesh.EdgeIndices())
			{
				Index2i edgeT = Mesh.GetEdgeT(item);
				if (edgeT.b == -1)
				{
					BoundaryEdges.Add(item);
					continue;
				}
				Vector3d triNormal = Mesh.GetTriNormal(edgeT.a);
				Vector3d triNormal2 = Mesh.GetTriNormal(edgeT.b);
				if (Math.Abs(triNormal.Dot(triNormal2)) < num)
				{
					CreaseEdges.Add(item);
				}
			}
			AllEdges = new HashSet<int>(CreaseEdges);
			foreach (int boundaryEdge in BoundaryEdges)
			{
				AllEdges.Add(boundaryEdge);
			}
			AllVertices = new HashSet<int>();
			IndexUtil.EdgesToVertices(Mesh, AllEdges, AllVertices);
		}

		private void extract_topology()
		{
			DGraph3 dGraph = new DGraph3();
			int[] array = new int[Mesh.MaxVertexID];
			int[] array2 = new int[AllVertices.Count];
			foreach (int allVertex in AllVertices)
			{
				array2[array[allVertex] = dGraph.AppendVertex(Mesh.GetVertex(allVertex))] = allVertex;
			}
			int[] array3 = new int[Mesh.MaxEdgeID];
			foreach (int allEdge in AllEdges)
			{
				Index2i edgeV = Mesh.GetEdgeV(allEdge);
				int v = array[edgeV.a];
				int v2 = array[edgeV.b];
				int num = dGraph.AppendEdge(v, v2, allEdge);
				array3[allEdge] = num;
			}
			DGraph3Util.Curves curves = DGraph3Util.ExtractCurves(dGraph, bWantLoopIndices: true);
			int count = curves.PathEdges.Count;
			Spans = new EdgeSpan[count];
			for (int i = 0; i < count; i++)
			{
				List<int> list = curves.PathEdges[i];
				for (int j = 0; j < list.Count; j++)
				{
					list[j] = dGraph.GetEdgeGroup(list[j]);
				}
				Spans[i] = EdgeSpan.FromEdges(Mesh, list);
			}
			int count2 = curves.LoopEdges.Count;
			Loops = new EdgeLoop[count2];
			for (int k = 0; k < count2; k++)
			{
				List<int> list2 = curves.LoopEdges[k];
				for (int l = 0; l < list2.Count; l++)
				{
					list2[l] = dGraph.GetEdgeGroup(list2[l]);
				}
				Loops[k] = EdgeLoop.FromEdges(Mesh, list2);
			}
			JunctionVertices = new HashSet<int>();
			foreach (int item in curves.JunctionV)
			{
				JunctionVertices.Add(array2[item]);
			}
		}

		public DMesh3 MakeElementsMesh(Polygon2d spanProfile, Polygon2d loopProfile)
		{
			DMesh3 dMesh = new DMesh3();
			validate_topology();
			EdgeSpan[] spans = Spans;
			for (int i = 0; i < spans.Length; i++)
			{
				TubeGenerator tubeGenerator = new TubeGenerator(spans[i].ToCurve(Mesh), spanProfile);
				MeshEditor.Append(dMesh, tubeGenerator.Generate().MakeDMesh());
			}
			EdgeLoop[] loops = Loops;
			for (int i = 0; i < loops.Length; i++)
			{
				TubeGenerator tubeGenerator2 = new TubeGenerator(loops[i].ToCurve(Mesh), loopProfile);
				MeshEditor.Append(dMesh, tubeGenerator2.Generate().MakeDMesh());
			}
			return dMesh;
		}
	}
	public class MinimalHoleFill
	{
		public DMesh3 Mesh;

		public EdgeLoop FillLoop;

		public bool IgnoreBoundaryTriangles;

		public bool OptimizeDevelopability = true;

		public bool OptimizeTriangles = true;

		public double DevelopabilityTolerance = 0.0001;

		public int[] FillVertices;

		public int[] FillTriangles;

		private RegionOperator regionop;

		private DMesh3 fillmesh;

		private HashSet<int> boundaryv;

		private Dictionary<int, double> exterior_angle_sums;

		private double[] curvatures;

		public MinimalHoleFill(DMesh3 mesh, EdgeLoop fillLoop)
		{
			Mesh = mesh;
			FillLoop = fillLoop;
		}

		public bool Apply()
		{
			SimpleHoleFiller simpleHoleFiller = new SimpleHoleFiller(Mesh, FillLoop);
			int group_id = Mesh.AllocateTriangleGroup();
			if (!simpleHoleFiller.Fill(group_id))
			{
				return false;
			}
			if (FillLoop.Vertices.Length <= 3)
			{
				FillTriangles = simpleHoleFiller.NewTriangles;
				FillVertices = new int[0];
				return true;
			}
			HashSet<int> hashSet = new HashSet<int>(simpleHoleFiller.NewTriangles);
			regionop = new RegionOperator(Mesh, simpleHoleFiller.NewTriangles, delegate(DSubmesh3 submesh)
			{
				submesh.ComputeTriMaps = true;
			});
			fillmesh = regionop.Region.SubMesh;
			boundaryv = new HashSet<int>(MeshIterators.BoundaryEdgeVertices(fillmesh));
			exterior_angle_sums = new Dictionary<int, double>();
			if (!IgnoreBoundaryTriangles)
			{
				foreach (int item in boundaryv)
				{
					double num = 0.0;
					int num2 = regionop.Region.MapVertexToBaseMesh(item);
					foreach (int item2 in regionop.BaseMesh.VtxTrianglesItr(num2))
					{
						if (!hashSet.Contains(item2))
						{
							Index3i tri_verts = regionop.BaseMesh.GetTriangle(item2);
							int i = IndexUtil.find_tri_index(num2, ref tri_verts);
							num += regionop.BaseMesh.GetTriInternalAngleR(item2, i);
						}
					}
					exterior_angle_sums[item] = num;
				}
			}
			MeshQueries.EdgeLengthStatsFromEdges(Mesh, FillLoop.Edges, out var _, out var _, out var avgEdgeLen);
			MeshQueries.EdgeLengthStats(fillmesh, out var _, out var maxEdgeLen2, out var _);
			double num3 = avgEdgeLen;
			if (maxEdgeLen2 / num3 > 10.0)
			{
				num3 = maxEdgeLen2 / 10.0;
			}
			RemesherPro obj = new RemesherPro(fillmesh)
			{
				SmoothSpeedT = 1.0
			};
			MeshConstraintUtil.FixAllBoundaryEdges(obj);
			obj.SetTargetEdgeLength(num3);
			obj.FastestRemesh();
			int num4 = 0;
			int num5 = 0;
			while (num5++ < 20 && num4 < 2)
			{
				int maxEdgeID = fillmesh.MaxEdgeID;
				int num6 = 0;
				for (int num7 = 0; num7 < maxEdgeID; num7++)
				{
					if (!fillmesh.IsEdge(num7) || fillmesh.IsBoundaryEdge(num7))
					{
						continue;
					}
					Index2i edgeV = fillmesh.GetEdgeV(num7);
					bool flag = boundaryv.Contains(edgeV.a);
					bool flag2 = boundaryv.Contains(edgeV.b);
					if (!(flag && flag2))
					{
						int num8 = (flag ? edgeV.a : edgeV.b);
						int vRemove = ((num8 == edgeV.a) ? edgeV.b : edgeV.a);
						Vector3d vertex = fillmesh.GetVertex(num8);
						if (!MeshUtil.CheckIfCollapseCreatesFlip(fillmesh, num7, vertex) && fillmesh.CollapseEdge(num8, vRemove, out var _) == MeshResult.Ok)
						{
							num6++;
						}
					}
				}
				num4 = ((num6 == 0) ? (num4 + 1) : 0);
				maxEdgeID = fillmesh.MaxEdgeID;
				for (int num9 = 0; num9 < maxEdgeID; num9++)
				{
					if (!fillmesh.IsEdge(num9) || fillmesh.IsBoundaryEdge(num9))
					{
						continue;
					}
					bool flag3 = false;
					Index2i edgeV2 = fillmesh.GetEdgeV(num9);
					MeshUtil.GetEdgeFlipNormals(fillmesh, num9, out var n, out var n2, out var on, out var on2);
					double num10 = n.Dot(n2);
					double num11 = on.Dot(on2);
					if (n.Dot(n2) < 0.1 || num11 > num10 + 1.1920928955078125E-07)
					{
						flag3 = true;
					}
					if (!flag3)
					{
						Index2i edgeOpposingV = fillmesh.GetEdgeOpposingV(num9);
						double num12 = fillmesh.GetVertex(edgeV2.a).Distance(fillmesh.GetVertex(edgeV2.b));
						if (fillmesh.GetVertex(edgeOpposingV.a).Distance(fillmesh.GetVertex(edgeOpposingV.b)) < num12 && !MeshUtil.CheckIfEdgeFlipCreatesFlip(fillmesh, num9))
						{
							flag3 = true;
						}
					}
					if (flag3)
					{
						fillmesh.FlipEdge(num9, out var _);
					}
				}
			}
			remove_remaining_interior_verts();
			bool flag4 = true;
			bool optimizeDevelopability = OptimizeDevelopability;
			bool flag5 = OptimizeDevelopability && OptimizeTriangles;
			HashSet<int> hashSet2 = new HashSet<int>(fillmesh.EdgeIndices());
			HashSet<int> hashSet3 = new HashSet<int>();
			int num13 = 0;
			int num14 = 0;
			while (num13++ < 40 && num14 < 2 && hashSet2.Count() > 0 && flag4)
			{
				num14++;
				foreach (int item3 in hashSet2)
				{
					if (!fillmesh.IsBoundaryEdge(item3))
					{
						bool flag6 = false;
						fillmesh.GetEdgeV(item3);
						MeshUtil.GetEdgeFlipNormals(fillmesh, item3, out var n3, out var n4, out var on3, out var on4);
						double num15 = n3.Dot(n4);
						double num16 = on3.Dot(on4);
						if (num13 < 20 && num15 < 0.1)
						{
							flag6 = true;
						}
						if (num16 > num15 + 1.1920928955078125E-07)
						{
							flag6 = true;
						}
						if (flag6 && fillmesh.FlipEdge(item3, out var _) == MeshResult.Ok)
						{
							num14 = 0;
							add_all_edges(item3, hashSet3);
						}
					}
				}
				HashSet<int> hashSet4 = hashSet2;
				hashSet2 = hashSet3;
				hashSet3 = hashSet4;
				hashSet3.Clear();
			}
			int num17 = 0;
			if (optimizeDevelopability)
			{
				curvatures = new double[fillmesh.MaxVertexID];
				foreach (int item4 in fillmesh.VertexIndices())
				{
					update_curvature(item4);
				}
				hashSet2 = new HashSet<int>(fillmesh.EdgeIndices());
				hashSet3 = new HashSet<int>();
				while (num17++ < 40 && hashSet2.Count() > 0 && optimizeDevelopability)
				{
					foreach (int item5 in hashSet2)
					{
						if (fillmesh.IsBoundaryEdge(item5))
						{
							continue;
						}
						Index2i edgeV3 = fillmesh.GetEdgeV(item5);
						Index2i edgeOpposingV2 = fillmesh.GetEdgeOpposingV(item5);
						if (fillmesh.FindEdge(edgeOpposingV2.a, edgeOpposingV2.b) != -1)
						{
							continue;
						}
						double num18 = curvature_metric_cached(edgeV3.a, edgeV3.b, edgeOpposingV2.a, edgeOpposingV2.b);
						if (!(num18 < 9.999999974752427E-07) && fillmesh.FlipEdge(item5, out var flip3) == MeshResult.Ok)
						{
							if (!(curvature_metric_eval(edgeV3.a, edgeV3.b, edgeOpposingV2.a, edgeOpposingV2.b) < num18 - 9.999999974752427E-07))
							{
								fillmesh.FlipEdge(item5, out flip3);
								continue;
							}
							update_curvature(edgeV3.a);
							update_curvature(edgeV3.b);
							update_curvature(edgeOpposingV2.a);
							update_curvature(edgeOpposingV2.b);
							add_all_edges(item5, hashSet3);
						}
					}
					HashSet<int> hashSet5 = hashSet2;
					hashSet2 = hashSet3;
					hashSet3 = hashSet5;
					hashSet3.Clear();
				}
			}
			if (flag5)
			{
				hashSet2 = new HashSet<int>(fillmesh.EdgeIndices());
				hashSet3 = new HashSet<int>();
				int num19 = 0;
				while (hashSet2.Count() > 0 && num19 < 20)
				{
					num19++;
					foreach (int item6 in hashSet2)
					{
						if (fillmesh.IsBoundaryEdge(item6))
						{
							continue;
						}
						Index2i edgeV4 = fillmesh.GetEdgeV(item6);
						Index2i edgeOpposingV3 = fillmesh.GetEdgeOpposingV(item6);
						if (fillmesh.FindEdge(edgeOpposingV3.a, edgeOpposingV3.b) != -1)
						{
							continue;
						}
						double num20 = curvature_metric_cached(edgeV4.a, edgeV4.b, edgeOpposingV3.a, edgeOpposingV3.b);
						if (!(aspect_metric(item6) > 1.0) && fillmesh.FlipEdge(item6, out var flip4) == MeshResult.Ok)
						{
							double num21 = curvature_metric_eval(edgeV4.a, edgeV4.b, edgeOpposingV3.a, edgeOpposingV3.b);
							if (!(Math.Abs(num20 - num21) < DevelopabilityTolerance))
							{
								fillmesh.FlipEdge(item6, out flip4);
								continue;
							}
							update_curvature(edgeV4.a);
							update_curvature(edgeV4.b);
							update_curvature(edgeOpposingV3.a);
							update_curvature(edgeOpposingV3.b);
							add_all_edges(item6, hashSet3);
						}
					}
					HashSet<int> hashSet6 = hashSet2;
					hashSet2 = hashSet3;
					hashSet3 = hashSet6;
					hashSet3.Clear();
				}
			}
			regionop.BackPropropagate();
			FillTriangles = regionop.CurrentBaseTriangles;
			FillVertices = regionop.CurrentBaseInteriorVertices().ToArray();
			return true;
		}

		private void remove_remaining_interior_verts()
		{
			HashSet<int> hashSet = new HashSet<int>(MeshIterators.InteriorVertices(fillmesh));
			int num = 0;
			while (hashSet.Count > 0 && hashSet.Count != num)
			{
				num = hashSet.Count;
				int[] array = hashSet.ToArray();
				foreach (int num2 in array)
				{
					foreach (int item in fillmesh.VtxEdgesItr(num2))
					{
						Index2i edgeV = fillmesh.GetEdgeV(item);
						int vKeep = ((edgeV.a == num2) ? edgeV.b : edgeV.a);
						if (fillmesh.CollapseEdge(vKeep, num2, out var _) == MeshResult.Ok)
						{
							break;
						}
					}
					if (!fillmesh.IsVertex(num2))
					{
						hashSet.Remove(num2);
					}
				}
			}
			if (hashSet.Count > 0)
			{
				Util.gBreakToDebugger();
			}
		}

		private void add_all_edges(int ei, HashSet<int> edge_set)
		{
			Index2i edgeT = fillmesh.GetEdgeT(ei);
			Index3i triEdges = fillmesh.GetTriEdges(edgeT.a);
			edge_set.Add(triEdges.a);
			edge_set.Add(triEdges.b);
			edge_set.Add(triEdges.c);
			triEdges = fillmesh.GetTriEdges(edgeT.b);
			edge_set.Add(triEdges.a);
			edge_set.Add(triEdges.b);
			edge_set.Add(triEdges.c);
		}

		private double area_metric(int eid)
		{
			MeshUtil.GetEdgeFlipTris(fillmesh, eid, out var orig_t, out var orig_t2, out var flip_t, out var flip_t2);
			double num = get_tri_area(fillmesh, ref orig_t);
			double num2 = get_tri_area(fillmesh, ref orig_t2);
			double num3 = get_tri_area(fillmesh, ref flip_t);
			double num4 = get_tri_area(fillmesh, ref flip_t2);
			double num5 = (num + num2) * 0.5;
			double num6 = (num3 + num4) * 0.5;
			double num7 = Math.Abs(num - num5) + Math.Abs(num2 - num5);
			return (Math.Abs(num3 - num6) + Math.Abs(num4 - num6)) / num7;
		}

		private double aspect_metric(int eid)
		{
			MeshUtil.GetEdgeFlipTris(fillmesh, eid, out var orig_t, out var orig_t2, out var flip_t, out var flip_t2);
			double num = get_tri_aspect(fillmesh, ref orig_t);
			double num2 = get_tri_aspect(fillmesh, ref orig_t2);
			double num3 = get_tri_aspect(fillmesh, ref flip_t);
			double num4 = get_tri_aspect(fillmesh, ref flip_t2);
			double num5 = Math.Abs(num - 1.0) + Math.Abs(num2 - 1.0);
			return (Math.Abs(num3 - 1.0) + Math.Abs(num4 - 1.0)) / num5;
		}

		private void update_curvature(int vid)
		{
			double value = 0.0;
			exterior_angle_sums.TryGetValue(vid, out value);
			foreach (int item in fillmesh.VtxTrianglesItr(vid))
			{
				Index3i tri_verts = fillmesh.GetTriangle(item);
				int i = IndexUtil.find_tri_index(vid, ref tri_verts);
				value += fillmesh.GetTriInternalAngleR(item, i);
			}
			curvatures[vid] = value - Math.PI * 2.0;
		}

		private double curvature_metric_cached(int a, int b, int c, int d)
		{
			double value = curvatures[a];
			double value2 = curvatures[b];
			double value3 = curvatures[c];
			double value4 = curvatures[d];
			return Math.Abs(value) + Math.Abs(value2) + Math.Abs(value3) + Math.Abs(value4);
		}

		private double curvature_metric_eval(int a, int b, int c, int d)
		{
			double value = compute_gauss_curvature(a);
			double value2 = compute_gauss_curvature(b);
			double value3 = compute_gauss_curvature(c);
			double value4 = compute_gauss_curvature(d);
			return Math.Abs(value) + Math.Abs(value2) + Math.Abs(value3) + Math.Abs(value4);
		}

		private double compute_gauss_curvature(int vid)
		{
			double value = 0.0;
			exterior_angle_sums.TryGetValue(vid, out value);
			foreach (int item in fillmesh.VtxTrianglesItr(vid))
			{
				Index3i tri_verts = fillmesh.GetTriangle(item);
				int i = IndexUtil.find_tri_index(vid, ref tri_verts);
				value += fillmesh.GetTriInternalAngleR(item, i);
			}
			return value - Math.PI * 2.0;
		}

		private Vector3d get_tri_normal(DMesh3 mesh, Index3i tri)
		{
			return MathUtil.Normal(mesh.GetVertex(tri.a), mesh.GetVertex(tri.b), mesh.GetVertex(tri.c));
		}

		private double get_tri_area(DMesh3 mesh, ref Index3i tri)
		{
			return MathUtil.Area(mesh.GetVertex(tri.a), mesh.GetVertex(tri.b), mesh.GetVertex(tri.c));
		}

		private double get_tri_aspect(DMesh3 mesh, ref Index3i tri)
		{
			return MathUtil.AspectRatio(mesh.GetVertex(tri.a), mesh.GetVertex(tri.b), mesh.GetVertex(tri.c));
		}
	}
	public class RemoveDuplicateTriangles
	{
		private class TriCentroids : IPointSet
		{
			public DMesh3 Mesh;

			public int VertexCount => Mesh.TriangleCount;

			public int MaxVertexID => Mesh.MaxTriangleID;

			public bool HasVertexNormals => false;

			public bool HasVertexColors => false;

			public int Timestamp => Mesh.Timestamp;

			public Vector3d GetVertex(int i)
			{
				return Mesh.GetTriCentroid(i);
			}

			public Vector3f GetVertexNormal(int i)
			{
				return Vector3f.AxisY;
			}

			public Vector3f GetVertexColor(int i)
			{
				return Vector3f.One;
			}

			public bool IsVertex(int tID)
			{
				return Mesh.IsTriangle(tID);
			}

			public IEnumerable<int> VertexIndices()
			{
				return Mesh.TriangleIndices();
			}
		}

		public DMesh3 Mesh;

		public double VertexTolerance = 9.999999974752427E-07;

		public bool CheckOrientation = true;

		public int Removed;

		public RemoveDuplicateTriangles(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public virtual bool Apply()
		{
			Removed = 0;
			double tolSqr = VertexTolerance * VertexTolerance;
			PointSetHashtable pointSetHashtable = new PointSetHashtable(new TriCentroids
			{
				Mesh = Mesh
			});
			int maxAxisSubdivs = ((Mesh.TriangleCount > 100000) ? 128 : 64);
			pointSetHashtable.Build(maxAxisSubdivs);
			Vector3d v = Vector3d.Zero;
			Vector3d v2 = Vector3d.Zero;
			Vector3d v3 = Vector3d.Zero;
			Vector3d v4 = Vector3d.Zero;
			Vector3d v5 = Vector3d.Zero;
			Vector3d v6 = Vector3d.Zero;
			int maxTriangleID = Mesh.MaxTriangleID;
			int[] array = new int[1024];
			for (int i = 0; i < maxTriangleID; i++)
			{
				if (!Mesh.IsTriangle(i))
				{
					continue;
				}
				Vector3d triCentroid = Mesh.GetTriCentroid(i);
				int buffer_count;
				while (!pointSetHashtable.FindInBall(triCentroid, VertexTolerance, array, out buffer_count))
				{
					array = new int[array.Length];
				}
				if (buffer_count == 1 && array[0] != i)
				{
					throw new Exception("RemoveDuplicateTriangles.Apply: how could this happen?!");
				}
				if (buffer_count <= 1)
				{
					continue;
				}
				Mesh.GetTriVertices(i, ref v, ref v2, ref v3);
				Vector3d vector3d = MathUtil.Normal(v, v2, v3);
				for (int j = 0; j < buffer_count; j++)
				{
					if (array[j] == i)
					{
						continue;
					}
					Mesh.GetTriVertices(array[j], ref v4, ref v5, ref v6);
					if (!is_same_triangle(ref v, ref v2, ref v3, ref v4, ref v5, ref v6, tolSqr))
					{
						continue;
					}
					if (CheckOrientation)
					{
						Vector3d v7 = MathUtil.Normal(v4, v5, v6);
						if (vector3d.Dot(v7) < 0.99)
						{
							continue;
						}
					}
					if (Mesh.RemoveTriangle(array[j]) == MeshResult.Ok)
					{
						Removed++;
					}
				}
			}
			return true;
		}

		private bool is_same_triangle(ref Vector3d a, ref Vector3d b, ref Vector3d c, ref Vector3d x, ref Vector3d y, ref Vector3d z, double tolSqr)
		{
			if (a.DistanceSquared(x) < tolSqr)
			{
				if (b.DistanceSquared(y) < tolSqr && c.DistanceSquared(z) < tolSqr)
				{
					return true;
				}
				if (b.DistanceSquared(z) < tolSqr && c.DistanceSquared(y) < tolSqr)
				{
					return true;
				}
			}
			else if (a.DistanceSquared(y) < tolSqr)
			{
				if (b.DistanceSquared(x) < tolSqr && c.DistanceSquared(z) < tolSqr)
				{
					return true;
				}
				if (b.DistanceSquared(z) < tolSqr && c.DistanceSquared(x) < tolSqr)
				{
					return true;
				}
			}
			else if (a.DistanceSquared(z) < tolSqr)
			{
				if (b.DistanceSquared(x) < tolSqr && c.DistanceSquared(y) < tolSqr)
				{
					return true;
				}
				if (b.DistanceSquared(y) < tolSqr && c.DistanceSquared(x) < tolSqr)
				{
					return true;
				}
			}
			return false;
		}
	}
	public class RemoveOccludedTriangles
	{
		public enum CalculationMode
		{
			RayParity,
			AnalyticWindingNumber,
			FastWindingNumber,
			SimpleOcclusionTest
		}

		public DMesh3 Mesh;

		public DMeshAABBTree3 Spatial;

		public List<int> RemovedT;

		public bool RemoveFailed;

		public bool PerVertex;

		public double NormalOffset = 1E-08;

		public double WindingIsoValue = 0.5;

		public CalculationMode InsideMode;

		public ProgressCancel Progress;

		protected virtual bool Cancelled()
		{
			if (Progress != null)
			{
				return Progress.Cancelled();
			}
			return false;
		}

		public RemoveOccludedTriangles(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public RemoveOccludedTriangles(DMesh3 mesh, DMeshAABBTree3 spatial)
		{
			Mesh = mesh;
			Spatial = spatial;
		}

		public virtual bool Apply()
		{
			DMesh3 dMesh = Mesh;
			if (InsideMode == CalculationMode.RayParity)
			{
				MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(dMesh);
				if (meshBoundaryLoops.Count > 0)
				{
					dMesh = new DMesh3(Mesh);
					foreach (EdgeLoop item in meshBoundaryLoops)
					{
						if (Cancelled())
						{
							return false;
						}
						new SimpleHoleFiller(dMesh, item).Fill();
					}
				}
			}
			DMeshAABBTree3 spatial = ((Spatial != null && dMesh == Mesh) ? Spatial : new DMeshAABBTree3(dMesh, autoBuild: true));
			if (InsideMode == CalculationMode.AnalyticWindingNumber)
			{
				spatial.WindingNumber(Vector3d.Zero);
			}
			else if (InsideMode == CalculationMode.FastWindingNumber)
			{
				spatial.FastWindingNumber(Vector3d.Zero);
			}
			if (Cancelled())
			{
				return false;
			}
			List<Vector3d> ray_dirs = null;
			int NR = 0;
			if (InsideMode == CalculationMode.SimpleOcclusionTest)
			{
				ray_dirs = new List<Vector3d>();
				ray_dirs.Add(Vector3d.AxisX);
				ray_dirs.Add(-Vector3d.AxisX);
				ray_dirs.Add(Vector3d.AxisY);
				ray_dirs.Add(-Vector3d.AxisY);
				ray_dirs.Add(Vector3d.AxisZ);
				ray_dirs.Add(-Vector3d.AxisZ);
				NR = ray_dirs.Count;
			}
			Func<Vector3d, bool> isOccludedF = delegate(Vector3d pt)
			{
				if (InsideMode == CalculationMode.RayParity)
				{
					return spatial.IsInside(pt);
				}
				if (InsideMode == CalculationMode.AnalyticWindingNumber)
				{
					return spatial.WindingNumber(pt) > WindingIsoValue;
				}
				if (InsideMode == CalculationMode.FastWindingNumber)
				{
					return spatial.FastWindingNumber(pt) > WindingIsoValue;
				}
				for (int i = 0; i < NR; i++)
				{
					if (spatial.FindNearestHitTriangle(new Ray3d(pt, ray_dirs[i])) == -1)
					{
						return false;
					}
				}
				return true;
			};
			bool cancel = false;
			BitArray vertices = null;
			if (PerVertex)
			{
				vertices = new BitArray(Mesh.MaxVertexID);
				MeshNormals normals = null;
				if (!Mesh.HasVertexNormals)
				{
					normals = new MeshNormals(Mesh);
					normals.Compute();
				}
				gParallel.ForEach(Mesh.VertexIndices(), delegate(int vid)
				{
					if (!cancel)
					{
						if (vid % 10 == 0)
						{
							cancel = Cancelled();
						}
						Vector3d vertex = Mesh.GetVertex(vid);
						Vector3d vector3d = ((normals == null) ? ((Vector3d)Mesh.GetVertexNormal(vid)) : normals[vid]);
						vertex += vector3d * NormalOffset;
						vertices[vid] = isOccludedF(vertex);
					}
				});
			}
			if (Cancelled())
			{
				return false;
			}
			RemovedT = new List<int>();
			SpinLock removeLock = default(SpinLock);
			gParallel.ForEach(Mesh.TriangleIndices(), delegate(int tid)
			{
				if (!cancel)
				{
					if (tid % 10 == 0)
					{
						cancel = Cancelled();
					}
					bool flag2 = false;
					if (PerVertex)
					{
						Index3i triangle = Mesh.GetTriangle(tid);
						flag2 = vertices[triangle.a] || vertices[triangle.b] || vertices[triangle.c];
					}
					else
					{
						Vector3d triCentroid = Mesh.GetTriCentroid(tid);
						Vector3d triNormal = Mesh.GetTriNormal(tid);
						triCentroid += triNormal * NormalOffset;
						flag2 = isOccludedF(triCentroid);
					}
					if (flag2)
					{
						bool lockTaken = false;
						removeLock.Enter(ref lockTaken);
						RemovedT.Add(tid);
						removeLock.Exit();
					}
				}
			});
			if (Cancelled())
			{
				return false;
			}
			if (RemovedT.Count > 0)
			{
				bool flag = new MeshEditor(Mesh).RemoveTriangles(RemovedT, bRemoveIsolatedVerts: true);
				RemoveFailed = !flag;
			}
			return true;
		}
	}
	public class SmoothedHoleFill
	{
		public DMesh3 Mesh;

		public Vector3d OffsetDirection = Vector3d.Zero;

		public double OffsetDistance;

		public double TargetEdgeLength = 2.5;

		public double SmoothAlpha = 1.0;

		public int InitialRemeshPasses = 20;

		public bool RemeshBeforeSmooth = true;

		public bool RemeshAfterSmooth = true;

		public Action<Remesher, bool> ConfigureRemesherF;

		public bool EnableLaplacianSmooth = true;

		public int SmoothSolveIterations = 1;

		public bool ConstrainToHoleInterior;

		public EdgeLoop FillLoop;

		public List<int> BorderHintTris;

		public int[] FillTriangles;

		public int[] FillVertices;

		public SmoothedHoleFill(DMesh3 mesh, EdgeLoop fillLoop = null)
		{
			Mesh = mesh;
			FillLoop = fillLoop;
		}

		public bool Apply()
		{
			EdgeLoop edgeLoop = null;
			if (FillLoop == null)
			{
				MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh);
				if (meshBoundaryLoops.Count == 0)
				{
					return false;
				}
				if (BorderHintTris != null)
				{
					edgeLoop = select_loop_tris_hint(meshBoundaryLoops);
				}
				if (edgeLoop == null && meshBoundaryLoops.MaxVerticesLoopIndex >= 0)
				{
					edgeLoop = meshBoundaryLoops[meshBoundaryLoops.MaxVerticesLoopIndex];
				}
			}
			else
			{
				edgeLoop = FillLoop;
			}
			if (edgeLoop == null)
			{
				return false;
			}
			SimpleHoleFiller simpleHoleFiller = new SimpleHoleFiller(Mesh, edgeLoop);
			if (!simpleHoleFiller.Fill())
			{
				return false;
			}
			if (edgeLoop.Vertices.Length <= 3)
			{
				FillTriangles = simpleHoleFiller.NewTriangles;
				FillVertices = new int[0];
				return true;
			}
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(Mesh);
			meshFaceSelection.Select(simpleHoleFiller.NewTriangles);
			if (OffsetDistance > 0.0)
			{
				MeshExtrudeFaces meshExtrudeFaces = new MeshExtrudeFaces(Mesh, meshFaceSelection);
				meshExtrudeFaces.ExtrudedPositionF = (Vector3d v, Vector3f n, int vid) => v + OffsetDistance * OffsetDirection;
				if (!meshExtrudeFaces.Extrude())
				{
					return false;
				}
				meshFaceSelection.Select(meshExtrudeFaces.JoinTriangles);
			}
			if (!ConstrainToHoleInterior)
			{
				meshFaceSelection.ExpandToOneRingNeighbours(2);
				meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			}
			if (RemeshBeforeSmooth)
			{
				RegionRemesher regionRemesher = new RegionRemesher(Mesh, meshFaceSelection);
				regionRemesher.SetTargetEdgeLength(TargetEdgeLength);
				regionRemesher.EnableSmoothing = SmoothAlpha > 0.0;
				regionRemesher.SmoothSpeedT = SmoothAlpha;
				if (ConfigureRemesherF != null)
				{
					ConfigureRemesherF(regionRemesher, arg2: true);
				}
				for (int num = 0; num < InitialRemeshPasses; num++)
				{
					regionRemesher.BasicRemeshPass();
				}
				regionRemesher.BackPropropagate();
				meshFaceSelection = new MeshFaceSelection(Mesh);
				meshFaceSelection.Select(regionRemesher.CurrentBaseTriangles);
				if (!ConstrainToHoleInterior)
				{
					meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
				}
			}
			if (ConstrainToHoleInterior)
			{
				for (int num2 = 0; num2 < SmoothSolveIterations; num2++)
				{
					smooth_and_remesh_preserve(meshFaceSelection, num2 == SmoothSolveIterations - 1);
					meshFaceSelection = new MeshFaceSelection(Mesh);
					meshFaceSelection.Select(FillTriangles);
				}
			}
			else
			{
				smooth_and_remesh(meshFaceSelection);
				meshFaceSelection = new MeshFaceSelection(Mesh);
				meshFaceSelection.Select(FillTriangles);
			}
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(Mesh);
			meshVertexSelection.SelectInteriorVertices(meshFaceSelection);
			FillVertices = meshVertexSelection.ToArray();
			return true;
		}

		private void smooth_and_remesh_preserve(MeshFaceSelection tris, bool bFinal)
		{
			if (EnableLaplacianSmooth)
			{
				LaplacianMeshSmoother.RegionSmooth(Mesh, tris, 2, 2, bPreserveExteriorRings: true);
			}
			if (RemeshAfterSmooth)
			{
				MeshProjectionTarget projectionTarget = (bFinal ? MeshProjectionTarget.Auto(Mesh, tris) : null);
				RegionRemesher regionRemesher = new RegionRemesher(Mesh, tris);
				regionRemesher.SetTargetEdgeLength(TargetEdgeLength);
				regionRemesher.SmoothSpeedT = 1.0;
				regionRemesher.SetProjectionTarget(projectionTarget);
				if (ConfigureRemesherF != null)
				{
					ConfigureRemesherF(regionRemesher, arg2: false);
				}
				for (int i = 0; i < 10; i++)
				{
					regionRemesher.BasicRemeshPass();
				}
				regionRemesher.BackPropropagate();
				FillTriangles = regionRemesher.CurrentBaseTriangles;
			}
			else
			{
				FillTriangles = tris.ToArray();
			}
		}

		private void smooth_and_remesh(MeshFaceSelection tris)
		{
			if (EnableLaplacianSmooth)
			{
				LaplacianMeshSmoother.RegionSmooth(Mesh, tris, 2, 2, bPreserveExteriorRings: false);
			}
			if (RemeshAfterSmooth)
			{
				tris.ExpandToOneRingNeighbours(2);
				tris.LocalOptimize(bClipFins: true, bFillEars: true);
				MeshProjectionTarget projectionTarget = MeshProjectionTarget.Auto(Mesh, tris);
				RegionRemesher regionRemesher = new RegionRemesher(Mesh, tris);
				regionRemesher.SetTargetEdgeLength(TargetEdgeLength);
				regionRemesher.SmoothSpeedT = 1.0;
				regionRemesher.SetProjectionTarget(projectionTarget);
				if (ConfigureRemesherF != null)
				{
					ConfigureRemesherF(regionRemesher, arg2: false);
				}
				for (int i = 0; i < 10; i++)
				{
					regionRemesher.BasicRemeshPass();
				}
				regionRemesher.BackPropropagate();
				FillTriangles = regionRemesher.CurrentBaseTriangles;
			}
			else
			{
				FillTriangles = tris.ToArray();
			}
		}

		private EdgeLoop select_loop_tris_hint(MeshBoundaryLoops loops)
		{
			HashSet<int> hashSet = new HashSet<int>();
			foreach (int borderHintTri in BorderHintTris)
			{
				if (!Mesh.IsTriangle(borderHintTri))
				{
					continue;
				}
				Index3i triEdges = Mesh.GetTriEdges(borderHintTri);
				for (int i = 0; i < 3; i++)
				{
					if (Mesh.IsBoundaryEdge(triEdges[i]))
					{
						hashSet.Add(triEdges[i]);
					}
				}
			}
			int count = loops.Count;
			int num = -1;
			int num2 = 0;
			for (int j = 0; j < count; j++)
			{
				int num3 = 0;
				int[] edges = loops[j].Edges;
				foreach (int item in edges)
				{
					if (hashSet.Contains(item))
					{
						num3++;
					}
				}
				if (num3 > num2)
				{
					num = j;
					num2 = num3;
				}
			}
			if (num == -1)
			{
				return null;
			}
			return loops[num];
		}
	}
	public class EditMeshSpatial : ISpatial
	{
		public DMesh3 SourceMesh;

		public DMeshAABBTree3 SourceSpatial;

		public DMesh3 EditMesh;

		private HashSet<int> RemovedT = new HashSet<int>();

		private HashSet<int> AddedT = new HashSet<int>();

		public bool SupportsNearestTriangle => false;

		public bool SupportsPointContainment => false;

		public bool SupportsTriangleRayIntersection => true;

		public void RemoveTriangle(int tid)
		{
			if (AddedT.Contains(tid))
			{
				AddedT.Remove(tid);
			}
			else
			{
				RemovedT.Add(tid);
			}
		}

		public void AddTriangle(int tid)
		{
			AddedT.Add(tid);
		}

		public int FindNearestTriangle(Vector3d p, double fMaxDist = double.MaxValue)
		{
			return -1;
		}

		public bool IsInside(Vector3d p)
		{
			return false;
		}

		public int FindNearestHitTriangle(Ray3d ray, double fMaxDist = double.MaxValue)
		{
			Func<int, bool> triangleFilterF = SourceSpatial.TriangleFilterF;
			SourceSpatial.TriangleFilterF = source_filter;
			int num = SourceSpatial.FindNearestHitTriangle(ray);
			SourceSpatial.TriangleFilterF = triangleFilterF;
			int hit_tid;
			IntrRay3Triangle3 intrRay3Triangle = find_added_hit(ref ray, out hit_tid);
			if (num == -1 && hit_tid == -1)
			{
				return -1;
			}
			if (num == -1)
			{
				return hit_tid;
			}
			if (hit_tid == -1)
			{
				return num;
			}
			IntrRay3Triangle3 intrRay3Triangle2 = ((num != -1) ? MeshQueries.TriangleIntersection(SourceMesh, num, ray) : null);
			if (!(intrRay3Triangle.RayParameter < intrRay3Triangle2.RayParameter))
			{
				return num;
			}
			return hit_tid;
		}

		private bool source_filter(int tid)
		{
			return !RemovedT.Contains(tid);
		}

		private IntrRay3Triangle3 find_added_hit(ref Ray3d ray, out int hit_tid)
		{
			hit_tid = -1;
			IntrRay3Triangle3 result = null;
			double num = double.MaxValue;
			Triangle3d t = default(Triangle3d);
			foreach (int item in AddedT)
			{
				Index3i triangle = EditMesh.GetTriangle(item);
				t.V0 = EditMesh.GetVertex(triangle.a);
				t.V1 = EditMesh.GetVertex(triangle.b);
				t.V2 = EditMesh.GetVertex(triangle.c);
				IntrRay3Triangle3 intrRay3Triangle = new IntrRay3Triangle3(ray, t);
				if (intrRay3Triangle.Find() && intrRay3Triangle.RayParameter < num)
				{
					num = intrRay3Triangle.RayParameter;
					hit_tid = item;
					result = intrRay3Triangle;
				}
			}
			return result;
		}
	}
	public class MeshScalarSamplingGrid
	{
		public enum ComputeModes
		{
			FullGrid,
			NarrowBand
		}

		public DMesh3 Mesh;

		public Func<Vector3d, double> ScalarF;

		public double CellSize;

		public int BufferCells = 1;

		public ComputeModes ComputeMode = ComputeModes.NarrowBand;

		public float IsoValue = 0.5f;

		public bool WantMeshSDFGrid = true;

		public Func<bool> CancelF = () => false;

		public bool DebugPrint;

		private Vector3f grid_origin;

		private DenseGrid3f scalar_grid;

		private MeshSignedDistanceGrid mesh_sdf;

		public Vector3i Dimensions => new Vector3i(scalar_grid.ni, scalar_grid.nj, scalar_grid.nk);

		public DenseGrid3f Grid => scalar_grid;

		public Vector3f GridOrigin => grid_origin;

		public MeshSignedDistanceGrid SDFGrid => mesh_sdf;

		public float this[int i, int j, int k] => scalar_grid[i, j, k];

		public MeshScalarSamplingGrid(DMesh3 mesh, double cellSize, Func<Vector3d, double> scalarF)
		{
			Mesh = mesh;
			ScalarF = scalarF;
			CellSize = cellSize;
		}

		public void Compute()
		{
			AxisAlignedBox3d cachedBounds = Mesh.CachedBounds;
			float num = (float)(2 * BufferCells) * (float)CellSize;
			grid_origin = (Vector3f)cachedBounds.Min - num * Vector3f.One;
			Vector3f vector3f = (Vector3f)cachedBounds.Max + num * Vector3f.One;
			int ni = (int)((vector3f.x - grid_origin.x) / (float)CellSize) + 1;
			int nj = (int)((vector3f.y - grid_origin.y) / (float)CellSize) + 1;
			int nk = (int)((vector3f.z - grid_origin.z) / (float)CellSize) + 1;
			scalar_grid = new DenseGrid3f();
			if (ComputeMode == ComputeModes.FullGrid)
			{
				make_grid_dense(grid_origin, (float)CellSize, ni, nj, nk, scalar_grid);
			}
			else
			{
				make_grid(grid_origin, (float)CellSize, ni, nj, nk, scalar_grid);
			}
		}

		public Vector3f CellCenter(int i, int j, int k)
		{
			return new Vector3f((double)(float)i * CellSize + (double)grid_origin.x, (double)(float)j * CellSize + (double)grid_origin.y, (double)(float)k * CellSize + (double)grid_origin.z);
		}

		private void make_grid(Vector3f origin, float dx, int ni, int nj, int nk, DenseGrid3f scalars)
		{
			scalars.resize(ni, nj, nk);
			scalars.assign(float.MaxValue);
			if (DebugPrint)
			{
				Console.WriteLine("start");
			}
			MeshSignedDistanceGrid meshSignedDistanceGrid = new MeshSignedDistanceGrid(Mesh, CellSize)
			{
				ComputeSigns = false
			};
			meshSignedDistanceGrid.CancelF = CancelF;
			meshSignedDistanceGrid.Compute();
			if (CancelF())
			{
				return;
			}
			DenseGrid3f distances = meshSignedDistanceGrid.Grid;
			if (WantMeshSDFGrid)
			{
				mesh_sdf = meshSignedDistanceGrid;
			}
			if (DebugPrint)
			{
				Console.WriteLine("done initial sdf");
			}
			_ = origin[0];
			_ = origin[1];
			_ = origin[2];
			gParallel.ForEach(gIndices.Grid3IndicesYZ(nj, nk), delegate(Vector3i jk)
			{
				if (!CancelF())
				{
					for (int i = 0; i < ni; i++)
					{
						Vector3i ijk = new Vector3i(i, jk.y, jk.z);
						if ((double)distances[ijk] < CellSize)
						{
							Vector3d arg = new Vector3d((float)ijk.x * dx + origin[0], (float)ijk.y * dx + origin[1], (float)ijk.z * dx + origin[2]);
							scalars[ijk] = (float)ScalarF(arg);
						}
					}
				}
			});
			if (CancelF())
			{
				return;
			}
			if (DebugPrint)
			{
				Console.WriteLine("done narrow-band");
			}
			AxisAlignedBox3i bounds = scalars.Bounds;
			bounds.Max -= Vector3i.One;
			Bitmap3 bits = new Bitmap3(new Vector3i(ni, nj, nk));
			List<Vector3i> list = new List<Vector3i>();
			foreach (Vector3i item in scalars.Indices())
			{
				if (scalars[item] != float.MaxValue)
				{
					list.Add(item);
					bits[item] = true;
				}
			}
			if (CancelF())
			{
				return;
			}
			HashSet<Vector3i> queue = new HashSet<Vector3i>();
			SpinLock queue_lock = default(SpinLock);
			while (true)
			{
				if (CancelF())
				{
					return;
				}
				bool abort = false;
				int iter_count = 0;
				gParallel.ForEach(list, delegate(Vector3i ijk)
				{
					Interlocked.Increment(ref iter_count);
					if (iter_count % 100 == 0)
					{
						abort = CancelF();
					}
					if (!abort)
					{
						float num2 = scalars[ijk];
						for (int i = 0; i < 26; i++)
						{
							Vector3i vector3i = ijk + gIndices.GridOffsets26[i];
							if (bounds.Contains(vector3i))
							{
								float num3 = scalars[vector3i];
								if (num3 == float.MaxValue)
								{
									Vector3d arg = new Vector3d((float)vector3i.x * dx + origin[0], (float)vector3i.y * dx + origin[1], (float)vector3i.z * dx + origin[2]);
									num3 = (float)ScalarF(arg);
									scalars[vector3i] = num3;
								}
								if (!bits[vector3i] && ((num2 < IsoValue && num3 > IsoValue) || (num2 > IsoValue && num3 < IsoValue)))
								{
									bool lockTaken = false;
									queue_lock.Enter(ref lockTaken);
									queue.Add(vector3i);
									queue_lock.Exit();
								}
							}
						}
					}
				});
				if (DebugPrint)
				{
					Console.WriteLine("front has {0} voxels", queue.Count);
				}
				if (queue.Count == 0)
				{
					break;
				}
				foreach (Vector3i item2 in queue)
				{
					bits[item2] = true;
				}
				list.Clear();
				list.AddRange(queue);
				queue.Clear();
			}
			if (DebugPrint)
			{
				Console.WriteLine("done front-prop");
			}
			if (DebugPrint)
			{
				int num = 0;
				foreach (Vector3i item3 in scalars.Indices())
				{
					if (scalars[item3] != float.MaxValue)
					{
						num++;
					}
				}
				Console.WriteLine("filled: {0} / {1}  -  {2}%", num, ni * nj * nk, (double)num / (double)(ni * nj * nk) * 100.0);
			}
			if (!CancelF())
			{
				fill_spans(ni, nj, nk, scalars);
				if (DebugPrint)
				{
					Console.WriteLine("done sweep");
				}
			}
		}

		private void make_grid_dense(Vector3f origin, float dx, int ni, int nj, int nk, DenseGrid3f scalars)
		{
			scalars.resize(ni, nj, nk);
			bool abort = false;
			int count = 0;
			gParallel.ForEach(scalars.Indices(), delegate(Vector3i ijk)
			{
				Interlocked.Increment(ref count);
				if (count % 100 == 0)
				{
					abort = CancelF();
				}
				if (!abort)
				{
					Vector3d arg = new Vector3d((float)ijk.x * dx + origin[0], (float)ijk.y * dx + origin[1], (float)ijk.z * dx + origin[2]);
					scalars[ijk] = (float)ScalarF(arg);
				}
			});
		}

		private void fill_spans(int ni, int nj, int nk, DenseGrid3f scalars)
		{
			gParallel.ForEach(gIndices.Grid3IndicesYZ(nj, nk), delegate(Vector3i idx)
			{
				int y = idx.y;
				int z = idx.z;
				float num = scalars[0, y, z];
				if (num == float.MaxValue)
				{
					num = 0f;
				}
				for (int i = 0; i < ni; i++)
				{
					if (scalars[i, y, z] == float.MaxValue)
					{
						scalars[i, y, z] = num;
					}
					else
					{
						num = scalars[i, y, z];
						if (num < IsoValue)
						{
							num = 0f;
						}
					}
				}
			});
		}
	}
