		private void fill_spans(int ni, int nj, int nk, DenseGrid3f winding)
		{
			gParallel.ForEach(gIndices.Grid3IndicesYZ(nj, nk), delegate(Vector3i idx)
			{
				int y = idx.y;
				int z = idx.z;
