namespace g3
{
	public class BiArcFit2
	{
		private struct Arc
		{
			public Vector2d Center;

			public double Radius;

			public double AngleStartR;

			public double AngleEndR;

			public bool PositiveRotation;

			public bool IsSegment;

			public Vector2d P0;

			public Vector2d P1;

			public Arc(Vector2d c, double r, double startR, double endR, bool posRotation)
			{
				Center = c;
				Radius = r;
				AngleStartR = startR;
				AngleEndR = endR;
				PositiveRotation = posRotation;
				IsSegment = false;
				P0 = (P1 = Vector2d.Zero);
			}

			public Arc(Vector2d p0, Vector2d p1)
			{
				Center = Vector2d.Zero;
				Radius = (AngleStartR = (AngleEndR = 0.0));
				PositiveRotation = false;
				IsSegment = true;
				P0 = p0;
				P1 = p1;
			}
		}

		public Vector2d Point1;

		public Vector2d Point2;

		public Vector2d Tangent1;

		public Vector2d Tangent2;

		public double Epsilon = 1E-08;

		public Arc2d Arc1;

		public Arc2d Arc2;

		public bool Arc1IsSegment;

		public bool Arc2IsSegment;

		public Segment2d Segment1;

		public Segment2d Segment2;

		public double FitD1;

		public double FitD2;

		private Arc arc1;

		private Arc arc2;

		public List<IParametricCurve2d> Curves
		{
			get
			{
				IParametricCurve2d parametricCurve2d2;
				if (!Arc1IsSegment)
				{
					IParametricCurve2d parametricCurve2d = Arc1;
					parametricCurve2d2 = parametricCurve2d;
				}
				else
				{
					IParametricCurve2d parametricCurve2d = Segment1;
					parametricCurve2d2 = parametricCurve2d;
				}
				IParametricCurve2d item = parametricCurve2d2;
				IParametricCurve2d parametricCurve2d3;
				if (!Arc2IsSegment)
				{
					IParametricCurve2d parametricCurve2d = Arc2;
					parametricCurve2d3 = parametricCurve2d;
				}
				else
				{
					IParametricCurve2d parametricCurve2d = Segment2;
					parametricCurve2d3 = parametricCurve2d;
				}
				IParametricCurve2d item2 = parametricCurve2d3;
				return new List<IParametricCurve2d> { item, item2 };
			}
		}

		public IParametricCurve2d Curve1
		{
			get
			{
				if (!Arc1IsSegment)
				{
					return Arc1;
				}
				return Segment1;
			}
		}

		public IParametricCurve2d Curve2
		{
			get
			{
				if (!Arc2IsSegment)
				{
					return Arc2;
				}
				return Segment2;
			}
		}

		public BiArcFit2(Vector2d point1, Vector2d tangent1, Vector2d point2, Vector2d tangent2)
		{
			Point1 = point1;
			Tangent1 = tangent1;
			Point2 = point2;
			Tangent2 = tangent2;
			Fit();
			set_output();
		}

		public BiArcFit2(Vector2d point1, Vector2d tangent1, Vector2d point2, Vector2d tangent2, double d1)
		{
			Point1 = point1;
			Tangent1 = tangent1;
			Point2 = point2;
			Tangent2 = tangent2;
			Fit(d1);
			set_output();
		}

		private void set_output()
		{
			if (arc1.IsSegment)
			{
				Arc1IsSegment = true;
				Segment1 = new Segment2d(arc1.P0, arc1.P1);
			}
			else
			{
				Arc1IsSegment = false;
				Arc1 = get_arc(0);
			}
			if (arc2.IsSegment)
			{
				Arc2IsSegment = true;
				Segment2 = new Segment2d(arc2.P1, arc2.P0);
			}
			else
			{
				Arc2IsSegment = false;
				Arc2 = get_arc(1);
			}
		}

		public double Distance(Vector2d point)
		{
			double val = (Arc1IsSegment ? Math.Sqrt(Segment1.DistanceSquared(point)) : Arc1.Distance(point));
			double val2 = (Arc2IsSegment ? Math.Sqrt(Segment2.DistanceSquared(point)) : Arc2.Distance(point));
			return Math.Min(val, val2);
		}

		public Vector2d NearestPoint(Vector2d point)
		{
			Vector2d result = (Arc1IsSegment ? Segment1.NearestPoint(point) : Arc1.NearestPoint(point));
			Vector2d result2 = (Arc2IsSegment ? Segment2.NearestPoint(point) : Arc2.NearestPoint(point));
			if (!(result.DistanceSquared(point) < result2.DistanceSquared(point)))
			{
				return result2;
			}
			return result;
		}

		private void set_arc(int i, Arc a)
		{
			if (i == 0)
			{
				arc1 = a;
			}
			else
			{
				arc2 = a;
			}
		}

		private Arc2d get_arc(int i)
		{
			Arc arc = ((i == 0) ? arc1 : arc2);
			double num = arc.AngleStartR * (180.0 / Math.PI);
			double num2 = arc.AngleEndR * (180.0 / Math.PI);
			if (arc.PositiveRotation)
			{
				double num3 = num;
				num = num2;
				num2 = num3;
			}
			Arc2d arc2d = new Arc2d(arc.Center, arc.Radius, num, num2);
			if (i == 0 && arc2d.SampleT(0.0).DistanceSquared(Point1) > 1E-08)
			{
				arc2d.Reverse();
			}
			if (i == 1 && arc2d.SampleT(1.0).DistanceSquared(Point2) > 1E-08)
			{
				arc2d.Reverse();
			}
			return arc2d;
		}

		private void Fit()
		{
			Vector2d point = Point1;
			Vector2d point2 = Point2;
			Vector2d tangent = Tangent1;
			Vector2d tangent2 = Tangent2;
			Vector2d vector2d = point2 - point;
			double lengthSquared = vector2d.LengthSquared;
			Vector2d v = tangent + tangent2;
			bool flag = MathUtil.EpsilonEqual(v.LengthSquared, 4.0, Epsilon);
			double num = vector2d.Dot(tangent);
			bool flag2 = MathUtil.EpsilonEqual(num, 0.0, Epsilon);
			if (flag && flag2)
			{
				FitD1 = (FitD2 = double.PositiveInfinity);
				double num2 = Math.Atan2(vector2d.y, vector2d.x);
				Vector2d c = point + 0.25 * vector2d;
				Vector2d c2 = point + 0.75 * vector2d;
				double r = Math.Sqrt(lengthSquared) * 0.25;
				double num3 = vector2d.x * tangent.y - vector2d.y * tangent.x;
				arc1 = new Arc(c, r, num2, num2 + Math.PI, num3 < 0.0);
				arc1 = new Arc(c2, r, num2, num2 + Math.PI, num3 > 0.0);
				return;
			}
			double num4 = vector2d.Dot(v);
			double num5 = 0.0;
			if (flag)
			{
				num5 = lengthSquared / (4.0 * num);
			}
			else
			{
				double num6 = 2.0 - 2.0 * tangent.Dot(tangent2);
				num5 = (Math.Sqrt(num4 * num4 + num6 * lengthSquared) - num4) / num6;
			}
			FitD1 = (FitD2 = num5);
			Vector2d p = point + point2 + num5 * (tangent - tangent2);
			p *= 0.5;
			SetArcFromEdge(0, point, tangent, p, fromP1: true);
			SetArcFromEdge(1, point2, tangent2, p, fromP1: false);
		}

		private void Fit(double d1)
		{
			Vector2d point = Point1;
			Vector2d point2 = Point2;
			Vector2d tangent = Tangent1;
			Vector2d tangent2 = Tangent2;
			Vector2d vector2d = point2 - point;
			double lengthSquared = vector2d.LengthSquared;
			_ = (tangent + tangent2).LengthSquared;
			double num = vector2d.Dot(tangent);
			double num2 = vector2d.Dot(tangent2);
			double num3 = tangent.Dot(tangent2);
			double num4 = num2 - d1 * (num3 - 1.0);
			if (MathUtil.EpsilonEqual(num4, 0.0, 9.999999974752427E-07))
			{
				FitD1 = d1;
				FitD2 = double.PositiveInfinity;
				Vector2d p = point + d1 * tangent;
				p += (num2 - d1 * num3) * tangent2;
				SetArcFromEdge(0, point, tangent, p, fromP1: true);
				SetArcFromEdge(1, point2, tangent2, p, fromP1: false);
			}
			else
			{
				double num5 = (0.5 * lengthSquared - d1 * num) / num4;
				double num6 = 1.0 / (d1 + num5);
				Vector2d p2 = d1 * num5 * (tangent - tangent2);
				p2 += d1 * point2;
				p2 += num5 * point;
				p2 *= num6;
				FitD1 = d1;
				FitD2 = num5;
				SetArcFromEdge(0, point, tangent, p2, fromP1: true);
				SetArcFromEdge(1, point2, tangent2, p2, fromP1: false);
			}
		}

		private void SetArcFromEdge(int i, Vector2d p1, Vector2d t1, Vector2d p2, bool fromP1)
		{
			Vector2d vector2d = p2 - p1;
			Vector2d vector2d2 = new Vector2d(0.0 - t1.y, t1.x);
			double num = vector2d.Dot(vector2d2);
			if (MathUtil.EpsilonEqual(num, 0.0, Epsilon))
			{
				set_arc(i, new Arc(p1, p2));
				return;
			}
			double num2 = vector2d.LengthSquared / (2.0 * num);
			Vector2d vector2d3 = p1 + num2 * vector2d2;
			Vector2d vector2d4 = p1 - vector2d3;
			Vector2d vector2d5 = p2 - vector2d3;
			double startR = Math.Atan2(vector2d4.y, vector2d4.x);
			double endR = Math.Atan2(vector2d5.y, vector2d5.x);
			if (vector2d4.x * t1.y - vector2d4.y * t1.x > 0.0)
			{
				set_arc(i, new Arc(vector2d3, Math.Abs(num2), startR, endR, !fromP1));
			}
			else
			{
				set_arc(i, new Arc(vector2d3, Math.Abs(num2), startR, endR, fromP1));
			}
		}

		public void DebugPrint()
		{
			Console.WriteLine("biarc fit Pt0 {0} Pt1 {1}  Tan0 {2} Tan1 {3}", Point1, Point2, Tangent1, Tangent2);
			Console.WriteLine("  First: Start {0} End {1}  {2}", Arc1IsSegment ? Segment1.P0 : Arc1.SampleT(0.0), Arc1IsSegment ? Segment1.P1 : Arc1.SampleT(1.0), Arc1IsSegment ? "segment" : "arc");
			Console.WriteLine("  Second: Start {0} End {1}  {2}", Arc2IsSegment ? Segment2.P0 : Arc2.SampleT(0.0), Arc2IsSegment ? Segment2.P1 : Arc2.SampleT(1.0), Arc2IsSegment ? "segment" : "arc");
		}
	}
	public class GaussPointsFit3
	{
		public Box3d Box;

		public bool ResultValid;

		public GaussPointsFit3(IEnumerable<Vector3d> points)
		{
			Box = new Box3d(Vector3d.Zero, Vector3d.One);
			int num = 0;
			foreach (Vector3d point in points)
			{
				Box.Center += point;
				num++;
			}
			double num2 = 1.0 / (double)num;
			Box.Center *= num2;
			double num3 = 0.0;
			double num4 = 0.0;
			double num5 = 0.0;
			double num6 = 0.0;
			double num7 = 0.0;
			double num8 = 0.0;
			foreach (Vector3d point2 in points)
			{
				Vector3d vector3d = point2 - Box.Center;
				num3 += vector3d[0] * vector3d[0];
				num4 += vector3d[0] * vector3d[1];
				num5 += vector3d[0] * vector3d[2];
				num6 += vector3d[1] * vector3d[1];
				num7 += vector3d[1] * vector3d[2];
				num8 += vector3d[2] * vector3d[2];
			}
			do_solve(num3, num4, num5, num6, num7, num8, num2);
		}

		public GaussPointsFit3(IEnumerable<Vector3d> points, IEnumerable<double> weights)
		{
			Box = new Box3d(Vector3d.Zero, Vector3d.One);
			int num = 0;
			double num2 = 0.0;
			IEnumerator<double> enumerator = weights.GetEnumerator();
			foreach (Vector3d point in points)
			{
				enumerator.MoveNext();
				double current2 = enumerator.Current;
				Box.Center += current2 * point;
				num2 += current2;
				num++;
			}
			double num3 = 1.0 / num2;
			Box.Center *= num3;
			double num4 = 0.0;
			double num5 = 0.0;
			double num6 = 0.0;
			double num7 = 0.0;
			double num8 = 0.0;
			double num9 = 0.0;
			enumerator = weights.GetEnumerator();
			foreach (Vector3d point2 in points)
			{
				enumerator.MoveNext();
				double current4 = enumerator.Current;
				current4 *= current4;
				Vector3d vector3d = point2 - Box.Center;
				num4 += current4 * vector3d[0] * vector3d[0];
				num5 += current4 * vector3d[0] * vector3d[1];
				num6 += current4 * vector3d[0] * vector3d[2];
				num7 += current4 * vector3d[1] * vector3d[1];
				num8 += current4 * vector3d[1] * vector3d[2];
				num9 += current4 * vector3d[2] * vector3d[2];
			}
			do_solve(num4, num5, num6, num7, num8, num9, num3 * num3);
		}

		private void do_solve(double sumXX, double sumXY, double sumXZ, double sumYY, double sumYZ, double sumZZ, double invSumMultiplier)
		{
			sumXX *= invSumMultiplier;
			sumXY *= invSumMultiplier;
			sumXZ *= invSumMultiplier;
			sumYY *= invSumMultiplier;
			sumYZ *= invSumMultiplier;
			sumZZ *= invSumMultiplier;
			double[] input = new double[9] { sumXX, sumXY, sumXZ, sumXY, sumYY, sumYZ, sumXZ, sumYZ, sumZZ };
			SymmetricEigenSolver symmetricEigenSolver = new SymmetricEigenSolver(3, 4096);
			int num = symmetricEigenSolver.Solve(input, SymmetricEigenSolver.SortType.Increasing);
			ResultValid = num > 0 && num < int.MaxValue;
			if (ResultValid)
			{
				Box.Extent = new Vector3d(symmetricEigenSolver.GetEigenvalues());
				double[] eigenvectors = symmetricEigenSolver.GetEigenvectors();
				Box.AxisX = new Vector3d(eigenvectors[0], eigenvectors[1], eigenvectors[2]);
				Box.AxisY = new Vector3d(eigenvectors[3], eigenvectors[4], eigenvectors[5]);
				Box.AxisZ = new Vector3d(eigenvectors[6], eigenvectors[7], eigenvectors[8]);
			}
		}
	}
	public class OrthogonalPlaneFit3
	{
		public Vector3d Origin;

		public Vector3d Normal;

		public bool ResultValid;

		public OrthogonalPlaneFit3(IEnumerable<Vector3d> points)
		{
			Origin = Vector3d.Zero;
			int num = 0;
			foreach (Vector3d point in points)
			{
				Origin += point;
				num++;
			}
			double num2 = 1.0 / (double)num;
			Origin *= num2;
			double num3 = 0.0;
			double num4 = 0.0;
			double num5 = 0.0;
			double num6 = 0.0;
			double num7 = 0.0;
			double num8 = 0.0;
			foreach (Vector3d point2 in points)
			{
				Vector3d vector3d = point2 - Origin;
				num3 += vector3d[0] * vector3d[0];
				num4 += vector3d[0] * vector3d[1];
				num5 += vector3d[0] * vector3d[2];
				num6 += vector3d[1] * vector3d[1];
				num7 += vector3d[1] * vector3d[2];
				num8 += vector3d[2] * vector3d[2];
			}
			num3 *= num2;
			num4 *= num2;
			num5 *= num2;
			num6 *= num2;
			num7 *= num2;
			num8 *= num2;
			double[] input = new double[9] { num3, num4, num5, num4, num6, num7, num5, num7, num8 };
			SymmetricEigenSolver symmetricEigenSolver = new SymmetricEigenSolver(3, 4096);
			int num9 = symmetricEigenSolver.Solve(input, SymmetricEigenSolver.SortType.Decreasing);
			ResultValid = num9 > 0 && num9 < int.MaxValue;
			Normal = new Vector3d(symmetricEigenSolver.GetEigenvector(2));
		}
	}
	public static class QuadraticFit2
	{
		public static double Fit(Vector2d[] points, double[] coefficients)
		{
			DenseMatrix denseMatrix = new DenseMatrix(6, 6);
			int num = points.Length;
			for (int i = 0; i < num; i++)
			{
				double x = points[i].x;
				double y = points[i].y;
				double num2 = x * x;
				double num3 = y * y;
				double num4 = x * y;
				double num5 = x * num2;
				double num6 = x * num3;
				double num7 = x * num4;
				double num8 = y * num3;
				double num9 = x * num5;
				double num10 = x * num6;
				double num11 = x * num7;
				double num12 = y * num8;
				double num13 = x * num8;
				denseMatrix[0, 1] += x;
				denseMatrix[0, 2] += y;
				denseMatrix[0, 3] += num2;
				denseMatrix[0, 4] += num3;
				denseMatrix[0, 5] += num4;
				denseMatrix[1, 3] += num5;
				denseMatrix[1, 4] += num6;
				denseMatrix[1, 5] += num7;
				denseMatrix[2, 4] += num8;
				denseMatrix[3, 3] += num9;
				denseMatrix[3, 4] += num10;
				denseMatrix[3, 5] += num11;
				denseMatrix[4, 4] += num12;
				denseMatrix[4, 5] += num13;
			}
			denseMatrix[0, 0] = num;
			denseMatrix[1, 1] = denseMatrix[0, 3];
			denseMatrix[1, 2] = denseMatrix[0, 5];
			denseMatrix[2, 2] = denseMatrix[0, 4];
			denseMatrix[2, 3] = denseMatrix[1, 5];
			denseMatrix[2, 5] = denseMatrix[1, 4];
			denseMatrix[5, 5] = denseMatrix[3, 4];
			for (int j = 0; j < 6; j++)
			{
				for (int k = 0; k < j; k++)
				{
					denseMatrix[j, k] = denseMatrix[k, j];
				}
			}
			double num14 = 1.0 / (double)num;
			for (int l = 0; l < 6; l++)
			{
				for (int m = 0; m < 6; m++)
				{
					denseMatrix[l, m] *= num14;
				}
			}
			SymmetricEigenSolver symmetricEigenSolver = new SymmetricEigenSolver(6, 1024);
			symmetricEigenSolver.Solve(denseMatrix.Buffer, SymmetricEigenSolver.SortType.Increasing);
			symmetricEigenSolver.GetEigenvector(0, coefficients);
			return Math.Abs(symmetricEigenSolver.GetEigenvalue(0));
		}

		public static double FitCircle2(Vector2d[] points, out Circle2d circle)
		{
			DenseMatrix denseMatrix = new DenseMatrix(4, 4);
			int num = points.Length;
			for (int i = 0; i < num; i++)
			{
				double x = points[i].x;
				double y = points[i].y;
				double num2 = x * x;
				double num3 = y * y;
				double num4 = x * y;
				double num5 = num2 + num3;
				double num6 = x * num5;
				double num7 = y * num5;
				double num8 = num5 * num5;
				denseMatrix[0, 1] += x;
				denseMatrix[0, 2] += y;
				denseMatrix[0, 3] += num5;
				denseMatrix[1, 1] += num2;
				denseMatrix[1, 2] += num4;
				denseMatrix[1, 3] += num6;
				denseMatrix[2, 2] += num3;
				denseMatrix[2, 3] += num7;
				denseMatrix[3, 3] += num8;
			}
			denseMatrix[0, 0] = num;
			for (int j = 0; j < 4; j++)
			{
				for (int k = 0; k < j; k++)
				{
					denseMatrix[j, k] = denseMatrix[k, j];
				}
			}
			double num9 = 1.0 / (double)num;
			for (int l = 0; l < 4; l++)
			{
				for (int m = 0; m < 4; m++)
				{
					denseMatrix[l, m] *= num9;
				}
			}
			SymmetricEigenSolver symmetricEigenSolver = new SymmetricEigenSolver(4, 1024);
			symmetricEigenSolver.Solve(denseMatrix.Buffer, SymmetricEigenSolver.SortType.Increasing);
			double[] array = new double[4];
			symmetricEigenSolver.GetEigenvector(0, array);
			double num10 = 1.0 / array[3];
			Vector3d zero = Vector3d.Zero;
			for (int n = 0; n < 3; n++)
			{
				zero[n] = num10 * array[n];
			}
			Vector2d center = new Vector2d(-0.5 * zero[1], -0.5 * zero[2]);
			double radius = Math.Sqrt(Math.Abs(center.LengthSquared - zero[0]));
			circle = new Circle2d(center, radius);
			return Math.Abs(symmetricEigenSolver.GetEigenvalue(0));
		}
	}
	public struct Colorb
	{
		public byte r;

		public byte g;

		public byte b;

		public byte a;

		public byte this[int key]
		{
			get
			{
				return key switch
				{
					0 => r, 
					1 => g, 
					2 => b, 
					_ => a, 
				};
			}
			set
			{
				switch (key)
				{
				case 0:
					r = value;
					break;
				case 1:
					g = value;
					break;
				case 2:
					b = value;
					break;
				default:
					a = value;
					break;
				}
			}
		}

		public Colorb(byte greylevel, byte a = 1)
		{
			r = (g = (b = greylevel));
			this.a = a;
		}

		public Colorb(byte r, byte g, byte b, byte a = 1)
		{
			this.r = r;
			this.g = g;
			this.b = b;
			this.a = a;
		}

		public Colorb(float r, float g, float b, float a = 1f)
		{
			this.r = (byte)MathUtil.Clamp((int)(r * 255f), 0, 255);
			this.g = (byte)MathUtil.Clamp((int)(g * 255f), 0, 255);
			this.b = (byte)MathUtil.Clamp((int)(b * 255f), 0, 255);
			this.a = (byte)MathUtil.Clamp((int)(a * 255f), 0, 255);
		}

		public Colorb(byte[] v2)
		{
			r = v2[0];
			g = v2[1];
			b = v2[2];
			a = v2[3];
		}

		public Colorb(Colorb copy)
		{
			r = copy.r;
			g = copy.g;
			b = copy.b;
			a = copy.a;
		}

		public Colorb(Colorb copy, byte newAlpha)
		{
			r = copy.r;
			g = copy.g;
			b = copy.b;
			a = newAlpha;
		}

		public static implicit operator Colorb(Color32 c)
		{
			return new Colorb(c.r, c.g, c.b, c.a);
		}

		public static implicit operator Color32(Colorb c)
		{
			return new Color32(c.r, c.g, c.b, c.a);
		}
	}
