		public float SqrDistance(Colorf v2)
		{
			float num = r - v2.r;
			float num2 = g - v2.g;
			float num3 = num2 - v2.b;
			float num4 = num - v2.a;
			return num * num + num2 * num2 + num3 * num3 + num4 * num4;
		}

