		public static bool operator ==(Colorf a, Colorf b)
		{
			if (a.r == b.r && a.g == b.g && a.b == b.b)
			{
				return a.a == b.a;
			}
			return false;
		}

		public static bool operator !=(Colorf a, Colorf b)
		{
			if (a.r == b.r && a.g == b.g && a.b == b.b)
			{
				return a.a != b.a;
			}
			return true;
		}

