	public class ColorHSV
	{
		public float h;

		public float s;

		public float v;

		public float a;

		public Colorf RGBA
		{
			get
			{
				return ConvertToRGB();
			}
			set
			{
				ConvertFromRGB(value);
			}
		}

		public ColorHSV(float h, float s, float v, float a = 1f)
		{
			this.h = h;
			this.s = s;
			this.v = v;
			this.a = a;
		}

		public ColorHSV(Colorf rgb)
		{
			ConvertFromRGB(rgb);
		}

		public Colorf ConvertToRGB()
		{
			float num = h;
			float f = s;
			float f2 = v;
			if (num > 360f)
			{
				num -= 360f;
			}
			if (num < 0f)
			{
				num += 360f;
			}
			num = MathUtil.Clamp(num, 0f, 360f);
			f = MathUtil.Clamp(f, 0f, 1f);
			float num2 = MathUtil.Clamp(f2, 0f, 1f);
			float num3 = num2 * f;
			float num4 = num3 * (1f - Math.Abs(num / 60f % 2f - 1f));
			float num5 = num2 - num3;
			float num6;
			float num7;
			float num8;
			switch ((int)(num / 60f))
			{
			case 0:
				num6 = num3;
				num7 = num4;
				num8 = 0f;
				break;
			case 1:
				num6 = num4;
				num7 = num3;
				num8 = 0f;
				break;
			case 2:
				num6 = 0f;
				num7 = num3;
				num8 = num4;
				break;
			case 3:
				num6 = 0f;
				num7 = num4;
				num8 = num3;
				break;
			case 4:
				num6 = num4;
				num7 = 0f;
				num8 = num3;
				break;
			default:
				num6 = num3;
				num7 = 0f;
				num8 = num4;
				break;
			}
			return new Colorf(MathUtil.Clamp(num6 + num5, 0f, 1f), MathUtil.Clamp(num7 + num5, 0f, 1f), MathUtil.Clamp(num8 + num5, 0f, 1f), a);
		}

		public void ConvertFromRGB(Colorf rgb)
		{
			a = rgb.a;
			float r = rgb.r;
			float g = rgb.g;
			float b = rgb.b;
			float num = r;
			int num2 = 0;
			if (g > num)
			{
				num = g;
				num2 = 1;
			}
			if (b > num)
			{
				num = b;
				num2 = 2;
			}
			float num3 = r;
			if (g < num3)
			{
				num3 = g;
			}
			if (b < num3)
			{
				num3 = b;
			}
			float num4 = num - num3;
			if (num4 == 0f)
			{
				h = 0f;
			}
			else
			{
				switch (num2)
				{
				case 0:
					h = 60f * ((g - b) / num4 % 6f);
					break;
				case 1:
					h = 60f * ((b - r) / num4 + 2f);
					break;
				case 2:
					h = 60f * ((r - g) / num4 + 4f);
					break;
				}
				if (h < 0f)
				{
					h += 360f;
				}
			}
			v = num;
			if (num == 0f)
			{
				s = 0f;
			}
			else
			{
				s = num4 / num;
			}
		}
	}
	public class ColorMap
	{
		private struct ColorPoint
		{
			public float t;

			public Colorf c;
		}

		private List<ColorPoint> points = new List<ColorPoint>();

		private Interval1d validRange;

		public ColorMap()
		{
			validRange = Interval1d.Empty;
		}

		public ColorMap(float[] t, Colorf[] c)
		{
			validRange = Interval1d.Empty;
			for (int i = 0; i < t.Length; i++)
			{
				AddPoint(t[i], c[i]);
			}
		}

		public void AddPoint(float t, Colorf c)
		{
			ColorPoint colorPoint = new ColorPoint
			{
				t = t,
				c = c
			};
			if (points.Count == 0)
			{
				points.Add(colorPoint);
				validRange.Contain(t);
				return;
			}
			if (t < points[0].t)
			{
				points.Insert(0, colorPoint);
				validRange.Contain(t);
				return;
			}
			for (int i = 0; i < points.Count; i++)
			{
				if (points[i].t == t)
				{
					points[i] = colorPoint;
					return;
				}
				if (points[i].t > t)
				{
					points.Insert(i, colorPoint);
					return;
				}
			}
			points.Add(colorPoint);
			validRange.Contain(t);
		}

		public Colorf Linear(float t)
		{
			if (t <= points[0].t)
			{
				return points[0].c;
			}
			int count = points.Count;
			if (t >= points[count - 1].t)
			{
				return points[count - 1].c;
			}
			for (int i = 1; i < points.Count; i++)
			{
				if (points[i].t > t)
				{
					ColorPoint colorPoint = points[i - 1];
					ColorPoint colorPoint2 = points[i];
					float num = (t - colorPoint.t) / (colorPoint2.t - colorPoint.t);
					return (1f - num) * colorPoint.c + num * colorPoint2.c;
				}
			}
			return points[count - 1].c;
		}
	}
	public static class ColorMixer
	{
		public static Colorf Lighten(Colorf baseColor, float fValueMult = 1.25f)
		{
			ColorHSV colorHSV = new ColorHSV(baseColor);
			colorHSV.v = MathUtil.Clamp(colorHSV.v * fValueMult, 0f, 1f);
			return colorHSV.ConvertToRGB();
		}

		public static Colorf Darken(Colorf baseColor, float fValueMult = 0.75f)
		{
			ColorHSV colorHSV = new ColorHSV(baseColor);
			colorHSV.v *= fValueMult;
			return colorHSV.ConvertToRGB();
		}

		public static Colorf CopyHue(Colorf BaseColor, Colorf TakeHue, float fBlendAlpha)
		{
			ColorHSV colorHSV = new ColorHSV(BaseColor);
			ColorHSV colorHSV2 = new ColorHSV(TakeHue);
			colorHSV.h = colorHSV2.h;
			colorHSV.s = MathUtil.Lerp(colorHSV.s, colorHSV2.s, fBlendAlpha);
			colorHSV.v = MathUtil.Lerp(colorHSV.v, colorHSV2.v, fBlendAlpha);
			return colorHSV.ConvertToRGB();
		}
	}
	public class Arrangement2d
	{
		protected struct SegmentPoint
		{
			public double t;

			public int vid;
		}

		protected struct Intersection
		{
			public int eid;

			public int sidex;

			public int sidey;

			public IntrSegment2Segment2 intr;
		}

		public DGraph2 Graph;

		public PointHashGrid2d<int> PointHash;

		public double VertexSnapTol = 1E-05;

		public Arrangement2d(AxisAlignedBox2d boundsHint)
		{
			Graph = new DGraph2();
			double cellSize = boundsHint.MaxDim / 64.0;
			PointHash = new PointHashGrid2d<int>(cellSize, -1);
		}

		public void Insert(Vector2d a, Vector2d b, int gid = -1)
		{
			insert_segment(a, b, gid);
		}

		public void Insert(Segment2d segment, int gid = -1)
		{
			insert_segment(segment.P0, segment.P1, gid);
		}

		public void Insert(PolyLine2d pline, int gid = -1)
		{
			int num = pline.VertexCount - 1;
			for (int i = 0; i < num; i++)
			{
				Vector2d a = pline[i];
				Vector2d b = pline[i + 1];
				insert_segment(a, b, gid);
			}
		}

		public void Insert(Polygon2d poly, int gid = -1)
		{
			int vertexCount = poly.VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				Vector2d a = poly[i];
				Vector2d b = poly[(i + 1) % vertexCount];
				insert_segment(a, b, gid);
			}
		}

		public void ConnectOpenBoundaries(double distThresh)
		{
			int maxVertexID = Graph.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (Graph.IsBoundaryVertex(i))
				{
					Vector2d vertex = Graph.GetVertex(i);
					int num = find_nearest_boundary_vertex(vertex, distThresh, i);
					if (num != -1)
					{
						Vector2d vertex2 = Graph.GetVertex(num);
						Insert(vertex, vertex2);
					}
				}
			}
		}

		protected bool insert_segment(ref Vector2d a, ref Vector2d b, int gid = -1, double tol = 0.0)
		{
			int num = find_existing_vertex(a);
			int num2 = find_existing_vertex(b);
			if (num == num2 && num >= 0)
			{
				return false;
			}
			List<Intersection> list = new List<Intersection>();
			find_intersecting_edges(ref a, ref b, list, tol);
			int count = list.Count;
			List<SegmentPoint> list2 = new List<SegmentPoint>();
			Segment2d segment2d = new Segment2d(a, b);
			for (int i = 0; i < count; i++)
			{
				Intersection intersection = list[i];
				int eid = intersection.eid;
				double parameter = intersection.intr.Parameter0;
				double parameter2 = intersection.intr.Parameter1;
				int num3 = -1;
				if (intersection.intr.Type == IntersectionType.Point || intersection.intr.Type == IntersectionType.Segment)
				{
					Index2i index2i = split_segment_at_t(eid, parameter, VertexSnapTol);
					num3 = index2i.b;
					Vector2d vertex = Graph.GetVertex(index2i.a);
					list2.Add(new SegmentPoint
					{
						t = segment2d.Project(vertex),
						vid = index2i.a
					});
				}
				if (intersection.intr.Type == IntersectionType.Segment)
				{
					if (num3 == -1)
					{
						Index2i index2i2 = split_segment_at_t(eid, parameter2, VertexSnapTol);
						Vector2d vertex2 = Graph.GetVertex(index2i2.a);
						list2.Add(new SegmentPoint
						{
							t = segment2d.Project(vertex2),
							vid = index2i2.a
						});
					}
					else
					{
						Segment2d edgeSegment = Graph.GetEdgeSegment(num3);
						Vector2d p = intersection.intr.Segment1.PointAt(parameter2);
						double t = edgeSegment.Project(p);
						Index2i index2i3 = split_segment_at_t(num3, t, VertexSnapTol);
						Vector2d vertex3 = Graph.GetVertex(index2i3.a);
						list2.Add(new SegmentPoint
						{
							t = segment2d.Project(vertex3),
							vid = index2i3.a
						});
					}
				}
			}
			if (num == -1)
			{
				num = find_existing_vertex(a);
			}
			if (num == -1)
			{
				num = Graph.AppendVertex(a);
				PointHash.InsertPointUnsafe(num, a);
			}
			if (num2 == -1)
			{
				num2 = find_existing_vertex(b);
			}
			if (num2 == -1)
			{
				num2 = Graph.AppendVertex(b);
				PointHash.InsertPointUnsafe(num2, b);
			}
			list2.Add(new SegmentPoint
			{
				t = segment2d.Project(a),
				vid = num
			});
			list2.Add(new SegmentPoint
			{
				t = segment2d.Project(b),
				vid = num2
			});
			list2.Sort((SegmentPoint pa, SegmentPoint pb) => (!(pa.t < pb.t)) ? ((pa.t > pb.t) ? 1 : 0) : (-1));
			for (int num4 = 0; num4 < list2.Count - 1; num4++)
			{
				int vid = list2[num4].vid;
				int vid2 = list2[num4 + 1].vid;
				if (vid != vid2)
				{
					if (Math.Abs(list2[num4].t - list2[num4 + 1].t) < 1.1920928955078125E-07)
					{
						Console.WriteLine("insert_segment: different points with same t??");
					}
					if (Graph.FindEdge(vid, vid2) == -1)
					{
						Graph.AppendEdge(vid, vid2, gid);
					}
				}
			}
			return true;
		}

		protected bool insert_segment(Vector2d a, Vector2d b, int gid = -1, double tol = 0.0)
		{
			return insert_segment(ref a, ref b, gid, tol);
		}

		protected Index2i split_segment_at_t(int eid, double t, double tol)
		{
			Index2i edgeV = Graph.GetEdgeV(eid);
			Segment2d segment2d = new Segment2d(Graph.GetVertex(edgeV.a), Graph.GetVertex(edgeV.b));
			int num = -1;
			int jj = -1;
			if (t < 0.0 - (segment2d.Extent - tol))
			{
				num = edgeV.a;
			}
			else if (t > segment2d.Extent - tol)
			{
				num = edgeV.b;
			}
			else
			{
				if (Graph.SplitEdge(eid, out var split) != MeshResult.Ok)
				{
					throw new Exception("insert_into_segment: edge split failed?");
				}
				num = split.vNew;
				jj = split.eNewBN;
				Vector2d vector2d = segment2d.PointAt(t);
				Graph.SetVertex(num, vector2d);
				PointHash.InsertPointUnsafe(split.vNew, vector2d);
			}
			return new Index2i(num, jj);
		}

		protected int find_existing_vertex(Vector2d pt)
		{
			return find_nearest_vertex(pt, VertexSnapTol);
		}

		protected int find_nearest_vertex(Vector2d pt, double searchRadius, int ignore_vid = -1)
		{
			KeyValuePair<int, double> keyValuePair = ((ignore_vid == -1) ? PointHash.FindNearestInRadius(pt, searchRadius, (int b) => pt.DistanceSquared(Graph.GetVertex(b))) : PointHash.FindNearestInRadius(pt, searchRadius, (int b) => pt.DistanceSquared(Graph.GetVertex(b)), (int vid) => vid == ignore_vid));
			if (keyValuePair.Key == PointHash.InvalidValue)
			{
				return -1;
			}
			return keyValuePair.Key;
		}

		protected int find_nearest_boundary_vertex(Vector2d pt, double searchRadius, int ignore_vid = -1)
		{
			KeyValuePair<int, double> keyValuePair = PointHash.FindNearestInRadius(pt, searchRadius, (int b) => pt.Distance(Graph.GetVertex(b)), (int vid) => !Graph.IsBoundaryVertex(vid) || vid == ignore_vid);
			if (keyValuePair.Key == PointHash.InvalidValue)
			{
				return -1;
			}
			return keyValuePair.Key;
		}

		protected bool find_intersecting_edges(ref Vector2d a, ref Vector2d b, List<Intersection> hits, double tol = 0.0)
		{
			int num = 0;
			Vector2d a2 = Vector2d.Zero;
			Vector2d b2 = Vector2d.Zero;
			foreach (int item in Graph.EdgeIndices())
			{
				Graph.GetEdgeV(item, ref a2, ref b2);
				int num2 = Segment2d.WhichSide(ref a, ref b, ref a2, tol);
				int num3 = Segment2d.WhichSide(ref a, ref b, ref b2, tol);
				if (num2 != num3 || num2 == 0)
				{
					IntrSegment2Segment2 intrSegment2Segment = new IntrSegment2Segment2(new Segment2d(a2, b2), new Segment2d(a, b));
					if (intrSegment2Segment.Find())
					{
						hits.Add(new Intersection
						{
							eid = item,
							sidex = num2,
							sidey = num3,
							intr = intrSegment2Segment
						});
						num++;
					}
				}
			}
			return num > 0;
		}
	}
	public class ConvexHull2
	{
		protected class Edge
		{
			public Vector2i V;

			public Edge E0;

			public Edge E1;

			public int Sign;

			public int Time;

			public Edge(int v0, int v1)
			{
				Sign = 0;
				Time = -1;
				V[0] = v0;
				V[1] = v1;
				E0 = null;
				E1 = null;
			}

			public int GetSign(int i, Query2 query)
			{
				if (i != Time)
				{
					Time = i;
					Sign = query.ToLine(i, V[0], V[1]);
				}
				return Sign;
			}

			public void Insert(Edge adj0, Edge adj1)
			{
				adj0.E1 = this;
				adj1.E0 = this;
				E0 = adj0;
				E1 = adj1;
			}

			public void DeleteSelf()
			{
				if (E0 != null)
				{
					E0.E1 = null;
				}
				if (E1 != null)
				{
					E1.E0 = null;
				}
			}

			public void GetIndices(ref int numIndices, ref int[] indices)
			{
				numIndices = 0;
				Edge edge = this;
				do
				{
					numIndices++;
					edge = edge.E1;
				}
				while (edge != this);
				indices = new int[numIndices];
				numIndices = 0;
				edge = this;
				do
				{
					indices[numIndices] = edge.V[0];
					numIndices++;
					edge = edge.E1;
				}
				while (edge != this);
			}
		}

		private IList<Vector2d> mVertices;

		private int mNumVertices;

		private int mDimension;

		private int mNumSimplices;

		private double mEpsilon;

		private Vector2d[] mSVertices;

		private int[] mIndices;

		private Query2 mQuery;

		private Vector2d mLineOrigin;

		private Vector2d mLineDirection;

		public int Dimension => mDimension;

		public int NumSimplices => mNumSimplices;

		public int[] HullIndices => mIndices;

		public ConvexHull2(IList<Vector2d> vertices, double epsilon, QueryNumberType queryType)
		{
			mVertices = vertices;
			mNumVertices = vertices.Count;
			mDimension = 0;
			mNumSimplices = 0;
			mIndices = null;
			mSVertices = null;
			mEpsilon = epsilon;
			mQuery = null;
			mLineOrigin = Vector2d.Zero;
			mLineDirection = Vector2d.Zero;
			Vector2d.GetInformation(mVertices, mEpsilon, out var info);
			if (info.mDimension == 0)
			{
				mDimension = 0;
				mIndices = null;
				return;
			}
			if (info.mDimension == 1)
			{
				mDimension = 1;
				mLineOrigin = info.mOrigin;
				mLineDirection = info.mDirection0;
				return;
			}
			mDimension = 2;
			int num = info.mExtreme[0];
			int num2 = info.mExtreme[1];
			int num3 = info.mExtreme[2];
			mSVertices = new Vector2d[mNumVertices];
			if (queryType != QueryNumberType.QT_RATIONAL && queryType != QueryNumberType.QT_FILTERED)
			{
				Vector2d vector2d = new Vector2d(info.mMin[0], info.mMin[1]);
				double num4 = 1.0 / info.mMaxRange;
				for (int i = 0; i < mNumVertices; i++)
				{
					mSVertices[i] = (mVertices[i] - vector2d) * num4;
				}
				double num5;
				switch (queryType)
				{
				case QueryNumberType.QT_INT64:
					num5 = 1048576.0;
					mQuery = new Query2Int64(mSVertices);
					break;
				case QueryNumberType.QT_INTEGER:
					throw new NotImplementedException("ConvexHull2: Query type QT_INTEGER not currently supported");
				default:
					num5 = 1.0;
					mQuery = new Query2d(mSVertices);
					break;
				}
				for (int j = 0; j < mNumVertices; j++)
				{
					mSVertices[j] *= num5;
				}
				Edge edge = null;
				Edge edge2 = null;
				Edge edge3 = null;
				if (info.mExtremeCCW)
				{
					edge = new Edge(num, num2);
					edge2 = new Edge(num2, num3);
					edge3 = new Edge(num3, num);
				}
				else
				{
					edge = new Edge(num, num3);
					edge2 = new Edge(num3, num2);
					edge3 = new Edge(num2, num);
				}
				edge.Insert(edge3, edge2);
				edge2.Insert(edge, edge3);
				edge3.Insert(edge2, edge);
				Edge hull = edge;
				int num6 = 0;
				do
				{
					if (!Update(ref hull, num6))
					{
						return;
					}
					num6 = (num6 + 31337) % mNumVertices;
				}
				while (num6 != 0);
				hull.GetIndices(ref mNumSimplices, ref mIndices);
				return;
			}
			throw new NotImplementedException("ConvexHull2: Query type QT_RATIONAL/QT_FILTERED not currently supported");
		}

		public void Get1DHullInfo(out Vector2d origin, out Vector2d direction)
		{
			origin = mLineOrigin;
			direction = mLineDirection;
		}

		public Polygon2d GetHullPolygon()
		{
			if (mIndices == null)
			{
				return null;
			}
			Polygon2d polygon2d = new Polygon2d();
			for (int i = 0; i < mIndices.Length; i++)
			{
				polygon2d.AppendVertex(mVertices[mIndices[i]]);
			}
			return polygon2d;
		}

		private bool Update(ref Edge hull, int i)
		{
			Edge edge = null;
			Edge edge2 = hull;
			do
			{
				if (edge2.GetSign(i, mQuery) > 0)
				{
					edge = edge2;
					break;
				}
				edge2 = edge2.E1;
			}
			while (edge2 != hull);
			if (edge == null)
			{
				return true;
			}
			Edge e = edge.E0;
			if (e == null)
			{
				return false;
			}
			Edge e2 = edge.E1;
			if (e2 == null)
			{
				return false;
			}
			edge.DeleteSelf();
			while (e.GetSign(i, mQuery) > 0)
			{
				hull = e;
				e = e.E0;
				if (e == null)
				{
					return false;
				}
				e.E1.DeleteSelf();
			}
			while (e2.GetSign(i, mQuery) > 0)
			{
				hull = e2;
				e2 = e2.E1;
				if (e2 == null)
				{
					return false;
				}
				e2.E0.DeleteSelf();
			}
			Edge edge3 = new Edge(e.V[1], i);
			Edge edge4 = new Edge(i, e2.V[0]);
			edge3.Insert(e, edge4);
			edge4.Insert(edge3, e2);
			hull = edge3;
			return true;
		}
	}
	public class GraphCells2d
	{
		public DGraph2 Graph;

		public List<int[]> CellLoops;

		public GraphCells2d(DGraph2 graph)
		{
			Graph = graph;
		}

		public void FindCells()
		{
			Index2i[][] array = new Index2i[Graph.MaxVertexID][];
			HashSet<Index2i> hashSet = new HashSet<Index2i>();
			foreach (int item2 in Graph.VertexIndices())
			{
				int[] array2 = Graph.SortedVtxEdges(item2);
				array[item2] = new Index2i[array2.Length];
				for (int i = 0; i < array2.Length; i++)
				{
					array[item2][i] = new Index2i(array2[i], array2[(i + 1) % array2.Length]);
					hashSet.Add(new Index2i(item2, i));
				}
			}
			CellLoops = new List<int[]>();
			List<int> list = new List<int>();
			while (hashSet.Count > 0)
			{
				Index2i item = hashSet.First();
				hashSet.Remove(item);
				int a = item.a;
				int b = item.b;
				_ = array[a][b].a;
				int b2 = array[a][b].b;
				list.Clear();
				list.Add(a);
				int num = a;
				int num2 = b2;
				bool flag = false;
				while (!flag)
				{
					Index2i edgeV = Graph.GetEdgeV(num2);
					int num3 = ((edgeV.a == num) ? edgeV.b : edgeV.a);
					if (num3 == a)
					{
						flag = true;
						continue;
					}
					Index2i[] array3 = array[num3];
					int num4 = -1;
					for (int j = 0; j < array3.Length; j++)
					{
						if (array3[j].a == num2)
						{
							num4 = j;
							break;
						}
					}
					if (num4 == -1)
					{
						throw new Exception("could not find next wedge?");
					}
					hashSet.Remove(new Index2i(num3, num4));
					list.Add(num3);
					num = num3;
					num2 = array3[num4].b;
				}
				CellLoops.Add(list.ToArray());
			}
		}

		public List<Polygon2d> CellsToPolygons(Func<Polygon2d, bool> FilterF = null)
		{
			List<Polygon2d> list = new List<Polygon2d>();
			for (int i = 0; i < CellLoops.Count; i++)
			{
				int[] array = CellLoops[i];
				Polygon2d polygon2d = new Polygon2d();
				for (int j = 0; j < array.Length; j++)
				{
					polygon2d.AppendVertex(Graph.GetVertex(array[j]));
				}
				if (FilterF == null || FilterF(polygon2d))
				{
					list.Add(polygon2d);
				}
			}
			return list;
		}

		public List<Polygon2d> ContainedCells(GeneralPolygon2d container)
		{
			Func<Polygon2d, bool> filterF = delegate(Polygon2d poly)
			{
				bool isClockwise = poly.IsClockwise;
				for (int i = 0; i < poly.VertexCount; i++)
				{
					Segment2d segment2d = poly.Segment(i);
					Vector2d vector2d = segment2d.Center + 1.1920928955078125E-07 * segment2d.Direction.Perp;
					if (poly.Contains(vector2d) == isClockwise)
					{
						return container.Contains(vector2d);
					}
				}
				return false;
			};
			return CellsToPolygons(filterF);
		}
	}
	public class GraphSplitter2d
	{
		private struct edge_hit
		{
			public int hit_eid;

			public Index2i vtx_signs;

			public int hit_vid;

			public Vector2d hit_pos;

			public double line_t;
		}

		public DGraph2 Graph;

		public double OnVertexTol = 1.1920928955078125E-07;

		public int InsertedEdgesID = 1;

		public Func<Vector2d, bool> InsideTestF;

		private DVector<int> EdgeSigns = new DVector<int>();

		private List<edge_hit> hits = new List<edge_hit>();

		public GraphSplitter2d(DGraph2 graph)
		{
			Graph = graph;
		}

		public void InsertLine(Line2d line, int insert_edges_id = -1)
		{
			if (insert_edges_id == -1)
			{
				insert_edges_id = InsertedEdgesID;
			}
			do_split(line, insert_edges: true, insert_edges_id);
		}

		protected virtual void do_split(Line2d line, bool insert_edges, int insert_gid)
		{
			if (EdgeSigns.Length < Graph.MaxVertexID)
			{
				EdgeSigns.resize(Graph.MaxVertexID);
			}
			foreach (int item2 in Graph.VertexIndices())
			{
				EdgeSigns[item2] = line.WhichSide(Graph.GetVertex(item2), OnVertexTol);
			}
			hits.Clear();
			foreach (int item3 in Graph.EdgeIndices())
			{
				Index2i edgeV = Graph.GetEdgeV(item3);
				Index2i vtx_signs = new Index2i(EdgeSigns[edgeV.a], EdgeSigns[edgeV.b]);
				if (vtx_signs.a * vtx_signs.b > 0)
				{
					continue;
				}
				edge_hit item = new edge_hit
				{
					hit_eid = item3,
					vtx_signs = vtx_signs,
					hit_vid = -1
				};
				Vector2d vertex = Graph.GetVertex(edgeV.a);
				Vector2d vertex2 = Graph.GetVertex(edgeV.b);
				if (vtx_signs.a == vtx_signs.b)
				{
					if (vertex.DistanceSquared(vertex2) > 2.220446049250313E-16)
					{
						item.hit_vid = edgeV.a;
						item.line_t = line.Project(vertex);
						hits.Add(item);
						item.hit_vid = edgeV.b;
						item.line_t = line.Project(vertex2);
						hits.Add(item);
					}
					else
					{
						vtx_signs.b = 1;
					}
				}
				if (vtx_signs.a == 0)
				{
					item.hit_pos = vertex;
					item.hit_vid = edgeV.a;
					item.line_t = line.Project(vertex);
				}
				else if (vtx_signs.b == 0)
				{
					item.hit_pos = vertex2;
					item.hit_vid = edgeV.b;
					item.line_t = line.Project(vertex2);
				}
				else
				{
					IntrLine2Segment2 intrLine2Segment = new IntrLine2Segment2(line, new Segment2d(vertex, vertex2));
					if (!intrLine2Segment.Find())
					{
						throw new Exception("GraphSplitter2d.Split: signs are different but ray did not it?");
					}
					if (!intrLine2Segment.IsSimpleIntersection)
					{
						throw new Exception("GraphSplitter2d.Split: got parallel edge case!");
					}
					item.hit_pos = intrLine2Segment.Point;
					item.line_t = intrLine2Segment.Parameter;
				}
				hits.Add(item);
			}
			hits.Sort((edge_hit hit0, edge_hit hit1) => hit0.line_t.CompareTo(hit1.line_t));
			int count = hits.Count;
			for (int num = 0; num < count - 1; num++)
			{
				int index = num + 1;
				if (hits[num].line_t == hits[index].line_t || hits[num].hit_eid == hits[index].hit_eid)
				{
					continue;
				}
				int num2 = hits[num].hit_vid;
				int num3 = hits[index].hit_vid;
				if ((num2 == num3 && num2 >= 0) || (num2 >= 0 && num3 >= 0 && Graph.FindEdge(num2, num3) >= 0))
				{
					continue;
				}
				if (num2 == -1)
				{
					if (Graph.SplitEdge(hits[num].hit_eid, out var split) != MeshResult.Ok)
					{
						throw new Exception("GraphSplitter2d.Split: first edge split failed!");
					}
					num2 = split.vNew;
					Graph.SetVertex(num2, hits[num].hit_pos);
					edge_hit value = hits[num];
					value.hit_vid = num2;
					hits[num] = value;
				}
				if (num3 == -1)
				{
					if (Graph.SplitEdge(hits[index].hit_eid, out var split2) != MeshResult.Ok)
					{
						throw new Exception("GraphSplitter2d.Split: second edge split failed!");
					}
					num3 = split2.vNew;
					Graph.SetVertex(num3, hits[index].hit_pos);
					edge_hit value2 = hits[index];
					value2.hit_vid = num3;
					hits[index] = value2;
				}
				if (InsideTestF != null)
				{
					Vector2d arg = 0.5 * (Graph.GetVertex(num2) + Graph.GetVertex(num3));
					if (!InsideTestF(arg))
					{
						continue;
					}
				}
				if (insert_edges)
				{
					Graph.AppendEdge(num2, num3, insert_gid);
				}
			}
		}
	}
	public class SphericalFibonacciPointSet
	{
		public int N = 64;

		private static readonly double PHI = (Math.Sqrt(5.0) + 1.0) / 2.0;

		public int Count => N;

		public Vector3d this[int i] => Point(i);

		public SphericalFibonacciPointSet(int n = 64)
		{
			N = n;
		}

		public Vector3d Point(int i)
		{
			double num = (double)i / PHI;
			double num2 = Math.PI * 2.0 * (num - Math.Floor(num));
			double num3 = Math.Cos(num2);
			double num4 = Math.Sin(num2);
			double num5 = 1.0 - (2.0 * (double)i + 1.0) / (double)N;
			double num6 = Math.Sin(Math.Acos(num5));
			return new Vector3d(num3 * num6, num4 * num6, num5);
		}

		public int NearestPoint(Vector3d p, bool bIsNormalized = false)
		{
			if (bIsNormalized)
			{
				return inverseSF(ref p);
			}
			p.Normalize();
			return inverseSF(ref p);
		}

		private double madfrac(double a, double b)
		{
			return a * b + (0.0 - Math.Floor(a * b));
		}

		private int inverseSF(ref Vector3d p)
		{
			double x = Math.Min(Math.Atan2(p.y, p.x), Math.PI);
			double z = p.z;
			double y = Math.Max(2.0, Math.Floor(Math.Log((double)N * Math.PI * Math.Sqrt(5.0) * (1.0 - z * z)) / Math.Log(PHI * PHI)));
			double num = Math.Pow(PHI, y) / Math.Sqrt(5.0);
			double num2 = Math.Round(num);
			double num3 = Math.Round(num * PHI);
			Matrix2d matrix2d = new Matrix2d(Math.PI * 2.0 * madfrac(num2 + 1.0, PHI - 1.0) - Math.PI * 2.0 * (PHI - 1.0), Math.PI * 2.0 * madfrac(num3 + 1.0, PHI - 1.0) - Math.PI * 2.0 * (PHI - 1.0), -2.0 * num2 / (double)N, -2.0 * num3 / (double)N);
			Matrix2d matrix2d2 = matrix2d.Inverse();
			Vector2d vector2d = new Vector2d(x, z - (1.0 - 1.0 / (double)N));
			vector2d = matrix2d2 * vector2d;
			vector2d.x = Math.Floor(vector2d.x);
			vector2d.y = Math.Floor(vector2d.y);
			double num4 = double.PositiveInfinity;
			double num5 = 0.0;
			for (uint num6 = 0u; num6 < 4; num6++)
			{
				Vector2d v = new Vector2d(num6 % 2, num6 / 2) + vector2d;
				z = matrix2d.Row(1).Dot(v) + (1.0 - 1.0 / (double)N);
				z = MathUtil.Clamp(z, -1.0, 1.0) * 2.0 - z;
				double num7 = Math.Floor((double)N * 0.5 - z * (double)N * 0.5);
				x = Math.PI * 2.0 * madfrac(num7, PHI - 1.0);
				z = 1.0 - (2.0 * num7 + 1.0) * (1.0 / (double)N);
				double num8 = Math.Sqrt(1.0 - z * z);
				Vector3d vector3d = new Vector3d(Math.Cos(x) * num8, Math.Sin(x) * num8, z);
				double num9 = Vector3d.Dot(vector3d - p, vector3d - p);
				if (num9 < num4)
				{
					num4 = num9;
					num5 = num7;
				}
			}
			return (int)num5;
		}
	}
	public class ContOrientedBox3
	{
		public Box3d Box;

		public bool ResultValid;

		public ContOrientedBox3(IEnumerable<Vector3d> points)
		{
			GaussPointsFit3 gaussPointsFit = new GaussPointsFit3(points);
			if (gaussPointsFit.ResultValid)
			{
				Box = gaussPointsFit.Box;
				Box.Contain(points);
			}
		}

		public ContOrientedBox3(IEnumerable<Vector3d> points, IEnumerable<double> pointWeights)
		{
			GaussPointsFit3 gaussPointsFit = new GaussPointsFit3(points, pointWeights);
			if (gaussPointsFit.ResultValid)
			{
				Box = gaussPointsFit.Box;
				Box.Contain(points);
			}
		}
	}
	public class ContMinBox2
	{
		protected enum RCFlags
		{
			F_NONE,
			F_LEFT,
			F_RIGHT,
			F_BOTTOM,
			F_TOP
		}

		private Box2d mMinBox;

		public Box2d MinBox => mMinBox;

		public ContMinBox2(IList<Vector2d> points, double epsilon, QueryNumberType queryType, bool isConvexPolygon)
		{
			IList<Vector2d> list;
			int num;
			if (isConvexPolygon)
			{
				list = points;
				num = list.Count;
			}
			else
			{
				ConvexHull2 convexHull = new ConvexHull2(points, epsilon, queryType);
				int dimension = convexHull.Dimension;
				int numSimplices = convexHull.NumSimplices;
				int[] hullIndices = convexHull.HullIndices;
				switch (dimension)
				{
				case 0:
					mMinBox.Center = points[0];
					mMinBox.AxisX = Vector2d.AxisX;
					mMinBox.AxisY = Vector2d.AxisY;
					mMinBox.Extent[0] = 0.0;
					mMinBox.Extent[1] = 0.0;
					return;
				case 1:
					throw new NotImplementedException("ContMinBox2: Have not implemented 1d case");
				}
				num = numSimplices;
				Vector2d[] array = new Vector2d[num];
				for (int i = 0; i < num; i++)
				{
					array[i] = points[hullIndices[i]];
				}
				list = array;
			}
			int num2 = num - 1;
			Vector2d[] array2 = new Vector2d[num];
			bool[] array3 = new bool[num];
			for (int j = 0; j < num2; j++)
			{
				array2[j] = list[j + 1] - list[j];
				array2[j].Normalize();
				array3[j] = false;
			}
			array2[num2] = list[0] - list[num2];
			array2[num2].Normalize();
			array3[num2] = false;
			double x = list[0].x;
			double num3 = x;
			double y = list[0].y;
			double num4 = y;
			int num5 = 0;
			int num6 = 0;
			int num7 = 0;
			int num8 = 0;
			for (int k = 1; k < num; k++)
			{
				if (list[k].x <= x)
				{
					x = list[k].x;
					num5 = k;
				}
				if (list[k].x >= num3)
				{
					num3 = list[k].x;
					num6 = k;
				}
				if (list[k].y <= y)
				{
					y = list[k].y;
					num7 = k;
				}
				if (list[k].y >= num4)
				{
					num4 = list[k].y;
					num8 = k;
				}
			}
			if (num5 == num2 && list[0].x <= x)
			{
				x = list[0].x;
				num5 = 0;
			}
			if (num6 == num2 && list[0].x >= num3)
			{
				num3 = list[0].x;
				num6 = 0;
			}
			if (num7 == num2 && list[0].y <= y)
			{
				y = list[0].y;
				num7 = 0;
			}
			if (num8 == num2 && list[0].y >= num4)
			{
				num4 = list[0].y;
				num8 = 0;
			}
			mMinBox.Center.x = 0.5 * (x + num3);
			mMinBox.Center.y = 0.5 * (y + num4);
			mMinBox.AxisX = Vector2d.AxisX;
			mMinBox.AxisY = Vector2d.AxisY;
			mMinBox.Extent[0] = 0.5 * (num3 - x);
			mMinBox.Extent[1] = 0.5 * (num4 - y);
			double minAreaDiv = mMinBox.Extent[0] * mMinBox.Extent[1];
			Vector2d U = Vector2d.AxisX;
			Vector2d V = Vector2d.AxisY;
			bool flag = false;
			while (!flag)
			{
				RCFlags rCFlags = RCFlags.F_NONE;
				double num9 = 0.0;
				double num10 = U.Dot(array2[num7]);
				if (num10 > num9)
				{
					num9 = num10;
					rCFlags = RCFlags.F_BOTTOM;
				}
				num10 = V.Dot(array2[num6]);
				if (num10 > num9)
				{
					num9 = num10;
					rCFlags = RCFlags.F_RIGHT;
				}
				num10 = 0.0 - U.Dot(array2[num8]);
				if (num10 > num9)
				{
					num9 = num10;
					rCFlags = RCFlags.F_TOP;
				}
				num10 = 0.0 - V.Dot(array2[num5]);
				if (num10 > num9)
				{
					num9 = num10;
					rCFlags = RCFlags.F_LEFT;
				}
				switch (rCFlags)
				{
				case RCFlags.F_BOTTOM:
					if (array3[num7])
					{
						flag = true;
						break;
					}
					U = array2[num7];
					V = -U.Perp;
					UpdateBox(list[num5], list[num6], list[num7], list[num8], ref U, ref V, ref minAreaDiv);
					array3[num7] = true;
					if (++num7 == num)
					{
						num7 = 0;
					}
					break;
				case RCFlags.F_RIGHT:
					if (array3[num6])
					{
						flag = true;
						break;
					}
					V = array2[num6];
					U = V.Perp;
					UpdateBox(list[num5], list[num6], list[num7], list[num8], ref U, ref V, ref minAreaDiv);
					array3[num6] = true;
					if (++num6 == num)
					{
						num6 = 0;
					}
					break;
				case RCFlags.F_TOP:
					if (array3[num8])
					{
						flag = true;
						break;
					}
					U = -array2[num8];
					V = -U.Perp;
					UpdateBox(list[num5], list[num6], list[num7], list[num8], ref U, ref V, ref minAreaDiv);
					array3[num8] = true;
					if (++num8 == num)
					{
						num8 = 0;
					}
					break;
				case RCFlags.F_LEFT:
					if (array3[num5])
					{
						flag = true;
						break;
					}
					V = -array2[num5];
					U = V.Perp;
					UpdateBox(list[num5], list[num6], list[num7], list[num8], ref U, ref V, ref minAreaDiv);
					array3[num5] = true;
					if (++num5 == num)
					{
						num5 = 0;
					}
					break;
				case RCFlags.F_NONE:
					flag = true;
					break;
				}
			}
		}

		protected void UpdateBox(Vector2d LPoint, Vector2d RPoint, Vector2d BPoint, Vector2d TPoint, ref Vector2d U, ref Vector2d V, ref double minAreaDiv4)
		{
			Vector2d v = RPoint - LPoint;
			Vector2d v2 = TPoint - BPoint;
			double num = 0.5 * U.Dot(v);
			double num2 = 0.5 * V.Dot(v2);
			double num3 = num * num2;
			if (num3 < minAreaDiv4)
			{
				minAreaDiv4 = num3;
				mMinBox.AxisX = U;
				mMinBox.AxisY = V;
				mMinBox.Extent[0] = num;
				mMinBox.Extent[1] = num2;
				Vector2d v3 = LPoint - BPoint;
				mMinBox.Center = LPoint + U * num + V * (num2 - V.Dot(v3));
			}
		}
	}
	public class ContMinCircle2
	{
		private struct Circle(Vector2d c, double radius)
		{
			public Vector2d Center = c;

			public double Radius = radius;
		}

		protected class Support
		{
			public int Quantity;

			public Index3i Index;

			public bool Contains(int index, IList<Vector2d> Points, int[] permutation, double epsilon)
			{
				for (int i = 0; i < Quantity; i++)
				{
					if ((Points[permutation[index]] - Points[permutation[Index[i]]]).LengthSquared < epsilon)
					{
						return true;
					}
				}
				return false;
			}
		}

		private double mEpsilon;

		private Func<int, int[], Support, Circle>[] mUpdate = new Func<int, int[], Support, Circle>[4];

		private IList<Vector2d> Points;

		private Circle[] circle_buf = new Circle[6];

		public Circle2d Result;

		private static readonly int[,] type2_2 = new int[2, 2]
		{
			{ 0, 1 },
			{ 1, 0 }
		};

		private static readonly int[,] type2_3 = new int[3, 3]
		{
			{ 0, 1, 2 },
			{ 1, 0, 2 },
			{ 2, 0, 1 }
		};

		private static readonly int[,] type3_3 = new int[3, 3]
		{
			{ 0, 1, 2 },
			{ 0, 2, 1 },
			{ 1, 2, 0 }
		};

		public ContMinCircle2(IList<Vector2d> pointsIn, double epsilon = 1E-05)
		{
			mEpsilon = epsilon;
			mUpdate[0] = null;
			mUpdate[1] = UpdateSupport1;
			mUpdate[2] = UpdateSupport2;
			mUpdate[3] = UpdateSupport3;
			Support support = new Support();
			double distDiff = 0.0;
			Points = pointsIn;
			int count = pointsIn.Count;
			int[] array = null;
			System.Random random = new System.Random();
			if (count >= 1)
			{
				array = new int[count];
				for (int i = 0; i < count; i++)
				{
					array[i] = i;
				}
				for (int num = count - 1; num > 0; num--)
				{
					int num2 = random.Next() % (num + 1);
					if (num2 != num)
					{
						int num3 = array[num];
						array[num] = array[num2];
						array[num2] = num3;
					}
				}
				Circle circle = new Circle(Points[array[0]], 0.0);
				support.Quantity = 1;
				support.Index[0] = 0;
				int num4 = 1 % count;
				int num5 = 0;
				while (num4 != num5)
				{
					if (!support.Contains(num4, Points, array, mEpsilon) && !Contains(Points[array[num4]], ref circle, ref distDiff))
					{
						Circle circle2 = mUpdate[support.Quantity](num4, array, support);
						if (circle2.Radius > circle.Radius)
						{
							circle = circle2;
							num5 = num4;
						}
					}
					num4 = (num4 + 1) % count;
				}
				Result = new Circle2d(circle.Center, Math.Sqrt(circle.Radius));
				return;
			}
			throw new Exception("ContMinCircle2: Input must contain points\n");
		}

		private bool Contains(Vector2d point, ref Circle circle, ref double distDiff)
		{
			double lengthSquared = (point - circle.Center).LengthSquared;
			distDiff = lengthSquared - circle.Radius;
			return distDiff <= 0.0;
		}

		private Circle ExactCircle2(ref Vector2d P0, ref Vector2d P1)
		{
			return new Circle(0.5 * (P0 + P1), 0.25 * P1.DistanceSquared(P0));
		}

		private Circle ExactCircle2(Vector2d P0, ref Vector2d P1)
		{
			return new Circle(0.5 * (P0 + P1), 0.25 * P1.DistanceSquared(P0));
		}

		private Circle ExactCircle3(ref Vector2d P0, ref Vector2d P1, ref Vector2d P2)
		{
			Vector2d vector2d = P1 - P0;
			Vector2d vector2d2 = P2 - P0;
			Matrix2d matrix2d = new Matrix2d(vector2d.x, vector2d.y, vector2d2.x, vector2d2.y);
			Vector2d vector2d3 = new Vector2d(0.5 * vector2d.LengthSquared, 0.5 * vector2d2.LengthSquared);
			double num = matrix2d.m00 * matrix2d.m11 - matrix2d.m01 * matrix2d.m10;
			if (Math.Abs(num) > mEpsilon)
			{
				double num2 = 1.0 / num;
				Vector2d vector2d4 = default(Vector2d);
				vector2d4.x = (matrix2d.m11 * vector2d3.x - matrix2d.m01 * vector2d3.y) * num2;
				vector2d4.y = (matrix2d.m00 * vector2d3.y - matrix2d.m10 * vector2d3.x) * num2;
				return new Circle(P0 + vector2d4, vector2d4.LengthSquared);
			}
			return new Circle(Vector2d.Zero, double.MaxValue);
		}

		private Circle ExactCircle3(Vector2d P0, Vector2d P1, ref Vector2d P2)
		{
			return ExactCircle3(ref P0, ref P1, ref P2);
		}

		private Circle ExactCircle3(Vector2d P0, ref Vector2d P1, ref Vector2d P2)
		{
			return ExactCircle3(ref P0, ref P1, ref P2);
		}

		private Circle UpdateSupport1(int i, int[] permutation, Support support)
		{
			Vector2d P = Points[permutation[support.Index[0]]];
			Vector2d P2 = Points[permutation[i]];
			Circle result = ExactCircle2(ref P, ref P2);
			support.Quantity = 2;
			support.Index[1] = i;
			return result;
		}

		private Circle UpdateSupport2(int i, int[] permutation, Support support)
		{
			Vector2dTuple2 vector2dTuple = new Vector2dTuple2(Points[permutation[support.Index[0]]], Points[permutation[support.Index[1]]]);
			Vector2d P = Points[permutation[i]];
			int num = 2;
			Circle[] array = circle_buf;
			int num2 = 0;
			double num3 = double.MaxValue;
			int num4 = -1;
			double distDiff = 0.0;
			double num5 = double.MaxValue;
			int num6 = -1;
			int num7 = 0;
			while (num7 < num)
			{
				array[num2] = ExactCircle2(vector2dTuple[type2_2[num7, 0]], ref P);
				if (array[num2].Radius < num3)
				{
					if (Contains(vector2dTuple[type2_2[num7, 1]], ref array[num2], ref distDiff))
					{
						num3 = array[num2].Radius;
						num4 = num2;
					}
					else if (distDiff < num5)
					{
						num5 = distDiff;
						num6 = num2;
					}
				}
				num7++;
				num2++;
			}
			array[num2] = ExactCircle3(vector2dTuple[0], vector2dTuple[1], ref P);
			if (array[num2].Radius < num3)
			{
				num3 = array[num2].Radius;
				num4 = num2;
			}
			if (num4 == -1)
			{
				num4 = num6;
			}
			Circle result = array[num4];
			switch (num4)
			{
			case 0:
				support.Index[1] = i;
				break;
			case 1:
				support.Index[0] = i;
				break;
			case 2:
				support.Quantity = 3;
				support.Index[2] = i;
				break;
			}
			return result;
		}

		private Circle UpdateSupport3(int i, int[] permutation, Support support)
		{
			Vector2dTuple3 vector2dTuple = new Vector2dTuple3(Points[permutation[support.Index[0]]], Points[permutation[support.Index[1]]], Points[permutation[support.Index[2]]]);
			Vector2d P = Points[permutation[i]];
			int num = 3;
			int num2 = 3;
			Circle[] array = circle_buf;
			int num3 = 0;
			double num4 = double.MaxValue;
			int num5 = -1;
			double distDiff = 0.0;
			double num6 = double.MaxValue;
			int num7 = -1;
			int num8 = 0;
			while (num8 < num)
			{
				array[num3] = ExactCircle2(vector2dTuple[type2_3[num8, 0]], ref P);
				if (array[num3].Radius < num4)
				{
					if (Contains(vector2dTuple[type2_3[num8, 1]], ref array[num3], ref distDiff) && Contains(vector2dTuple[type2_3[num8, 2]], ref array[num3], ref distDiff))
					{
						num4 = array[num3].Radius;
						num5 = num3;
					}
					else if (distDiff < num6)
					{
						num6 = distDiff;
						num7 = num3;
					}
				}
				num8++;
				num3++;
			}
			num8 = 0;
			while (num8 < num2)
			{
				array[num3] = ExactCircle3(vector2dTuple[type3_3[num8, 0]], vector2dTuple[type3_3[num8, 1]], ref P);
				if (array[num3].Radius < num4)
				{
					if (Contains(vector2dTuple[type3_3[num8, 2]], ref array[num3], ref distDiff))
					{
						num4 = array[num3].Radius;
						num5 = num3;
					}
					else if (distDiff < num6)
					{
						num6 = distDiff;
						num7 = num3;
					}
				}
				num8++;
				num3++;
			}
			if (num5 == -1)
			{
				num5 = num7;
			}
			Circle result = array[num5];
			switch (num5)
			{
			case 0:
				support.Quantity = 2;
				support.Index[1] = i;
				break;
			case 1:
				support.Quantity = 2;
				support.Index[0] = i;
				break;
			case 2:
				support.Quantity = 2;
				support.Index[0] = support.Index[2];
				support.Index[1] = i;
				break;
			case 3:
				support.Index[2] = i;
				break;
			case 4:
				support.Index[1] = i;
				break;
			case 5:
				support.Index[0] = i;
				break;
			}
			return result;
		}
	}
	public static class TilingUtil
	{
		public static List<Vector2d> BoundedRegularTiling2(AxisAlignedBox2d element, AxisAlignedBox2d bounds, double spacing)
		{
			Vector2d vector2d = -element.Min;
			double width = element.Width;
			double height = element.Height;
			int num = Math.Max(1, (int)(bounds.Width / width));
			double num2 = (double)(num - 1) * spacing;
			while (num > 1 && bounds.Width - (width * (double)num + num2) < 0.0)
			{
				num--;
			}
			int num3 = Math.Max(1, (int)(bounds.Height / height));
			double num4 = (double)(num3 - 1) * spacing;
			while (num3 > 1 && bounds.Height - (height * (double)num3 + num4) < 0.0)
			{
				num3--;
			}
			List<Vector2d> list = new List<Vector2d>();
			for (int i = 0; i < num3; i++)
			{
				double y = (double)i * height + (double)i * spacing;
				for (int j = 0; j < num; j++)
				{
					double x = (double)j * width + (double)j * spacing;
					list.Add(new Vector2d(x, y) + vector2d + bounds.Min);
				}
			}
			return list;
		}

		public static List<Vector2d> BoundedCircleTiling2(AxisAlignedBox2d element, AxisAlignedBox2d bounds, double spacing)
		{
			Vector2d vector2d = -element.Min;
			double width = element.Width;
			double height = element.Height;
			if (!MathUtil.EpsilonEqual(width, height, 1.1920928955078125E-07))
			{
				throw new Exception("BoundedHexTiling2: input box is not square");
			}
			double num = width / 2.0;
			Hexagon2d obj = new Hexagon2d(element.Center, num, Hexagon2d.TopModes.Tip)
			{
				InnerRadius = num
			};
			double horzSpacing = obj.HorzSpacing;
			double vertSpacing = obj.VertSpacing;
			int num2 = Math.Max(1, (int)(bounds.Height / vertSpacing));
			double num3 = (double)(num2 - 1) * spacing;
			while (num2 > 1 && bounds.Height - (vertSpacing * (double)num2 + num3) < 0.0)
			{
				num2--;
			}
			int num4 = Math.Max(1, (int)(bounds.Width / horzSpacing));
			double num5 = (double)(num4 - 1) * spacing;
			while (num4 > 1 && bounds.Width - (horzSpacing * (double)num4 + num5) < 0.0)
			{
				num4--;
			}
			int num6 = num4;
			num5 = (double)(num6 - 1) * spacing;
			if (num2 > 0 && horzSpacing * (double)num6 + num5 + horzSpacing * 0.5 > bounds.Width)
			{
				num6--;
				num5 = (double)(num6 - 1) * spacing;
			}
			List<Vector2d> list = new List<Vector2d>();
			for (int i = 0; i < num2; i++)
			{
				double y = (double)i * vertSpacing + (double)i * spacing;
				double num7 = horzSpacing * 0.5;
				int num8 = num6;
				if (i % 2 == 0)
				{
					num7 = 0.0;
					num8 = num4;
				}
				for (int j = 0; j < num8; j++)
				{
					double x = num7 + (double)j * horzSpacing + (double)j * spacing;
					list.Add(new Vector2d(x, y) + vector2d + bounds.Min);
				}
			}
			return list;
		}
	}
	public class BufferUtil
	{
		public static void SetVertex3(double[] v, int i, double x, double y, double z)
		{
			v[3 * i] = x;
			v[3 * i + 1] = y;
			v[3 * i + 2] = z;
		}

		public static void SetVertex3(float[] v, int i, float x, float y, float z)
		{
			v[3 * i] = x;
			v[3 * i + 1] = y;
			v[3 * i + 2] = z;
		}

		public static void SetVertex2(double[] v, int i, double x, double y)
		{
			v[2 * i] = x;
			v[2 * i + 1] = y;
		}

		public static void SetVertex2(float[] v, int i, float x, float y)
		{
			v[2 * i] = x;
			v[2 * i + 1] = y;
		}

		public static void SetTriangle(int[] v, int i, int a, int b, int c)
		{
			v[3 * i] = a;
			v[3 * i + 1] = b;
			v[3 * i + 2] = c;
		}

		public static double Dot(double[] a, double[] b)
		{
			double num = 0.0;
			for (int i = 0; i < a.Length; i++)
			{
				num += a[i] * b[i];
			}
			return num;
		}

		public static void MultiplyAdd(double[] dest, double multiply, double[] add)
		{
			for (int i = 0; i < dest.Length; i++)
			{
				dest[i] += multiply * add[i];
			}
		}

		public static void MultiplyAdd(double[] dest, double[] multiply, double[] add)
		{
			for (int i = 0; i < dest.Length; i++)
			{
				dest[i] += multiply[i] * add[i];
			}
		}

		public static double MultiplyAdd_GetSqrSum(double[] dest, double multiply, double[] add)
		{
			double num = 0.0;
			for (int i = 0; i < dest.Length; i++)
			{
				dest[i] += multiply * add[i];
				num += dest[i] * dest[i];
			}
			return num;
		}

		public static double DistanceSquared(double[] a, double[] b)
		{
			double num = 0.0;
			for (int i = 0; i < a.Length; i++)
			{
				num += (a[i] - b[i]) * (a[i] - b[i]);
			}
			return num;
		}

		public static void ParallelDot(double[] a, double[][] b, double[][] result)
		{
			int num = a.Length;
			int count = b.Length;
			gParallel.BlockStartEnd(0, num - 1, delegate(int i0, int i1)
			{
				for (int j = i0; j <= i1; j++)
				{
					for (int k = 0; k < count; k++)
					{
						result[k][j] = a[j] * b[k][j];
					}
				}
			}, 1000);
		}

