		public static int CountValid<T>(T[] data, Func<T, bool> FilterF, int max_i = -1)
		{
			int num = ((max_i == -1) ? data.Length : max_i);
			int num2 = 0;
			for (int i = 0; i < num; i++)
			{
				if (FilterF(data[i]))
				{
					num2++;
				}
			}
			return num2;
		}

		public static int FilterInPlace<T>(T[] data, Func<T, bool> FilterF, int max_i = -1)
		{
