			int result = 0;
			for (int i = 0; i < num; i++)
			{
				if (FilterF(data[i]))
				{
					data[result++] = data[i];
				}
			}
			return result;
		}

		public static T[] Filter<T>(T[] data, Func<T, bool> FilterF, int max_i = -1)
		{
