			{
				num /= 3;
				array = new Vector3d[num];
				foreach (float item in values as IEnumerable<float>)
				{
					array[num2][num3++] = item;
					if (num3 == 3)
					{
						num3 = 0;
						num2++;
					}
				}
			}
			else if (typeFromHandle == typeof(double))
			{
				num /= 3;
				array = new Vector3d[num];
