	public class CommandArgumentSet
	{
		public Dictionary<string, int> Integers = new Dictionary<string, int>();

		public Dictionary<string, float> Floats = new Dictionary<string, float>();

		public Dictionary<string, string> Strings = new Dictionary<string, string>();

		public Dictionary<string, bool> Flags = new Dictionary<string, bool>();

		public HashSet<string> SawArguments = new HashSet<string>();

		public List<string> Filenames = new List<string>();

		public void Register(string argument, int defaultValue)
		{
			Integers.Add(argument, defaultValue);
		}

		public void Register(string argument, float defaultValue)
		{
			Floats.Add(argument, defaultValue);
		}

		public void Register(string argument, bool defaultValue)
		{
			Flags.Add(argument, defaultValue);
		}

		public void Register(string argument, string defaultValue)
		{
			Strings.Add(argument, defaultValue);
		}

		public bool Saw(string argument)
		{
			return SawArguments.Contains(argument);
		}

		public bool Validate(string sParam, params string[] values)
		{
			if (!Strings.ContainsKey(sParam))
			{
				throw new Exception("Argument set does not contain " + sParam);
			}
			string text = Strings[sParam];
			for (int i = 0; i < values.Length; i++)
			{
				if (text == values[i])
				{
					return true;
				}
			}
			return false;
		}

		public bool Parse(string[] arguments)
		{
			int num = arguments.Length;
			int num2 = 0;
			while (num2 < num)
			{
				string text = arguments[num2];
				num2++;
				if (Integers.ContainsKey(text))
				{
					SawArguments.Add(text);
					if (num2 == num)
					{
						error_missing_argument(text);
						return false;
					}
					string text2 = arguments[num2];
					if (!int.TryParse(text2, out var result))
					{
						error_invalid_value(text, text2);
						return false;
					}
					Integers[text] = result;
					num2++;
				}
				else if (Floats.ContainsKey(text))
				{
					SawArguments.Add(text);
					if (num2 == num)
					{
						error_missing_argument(text);
						return false;
					}
					string text3 = arguments[num2];
					if (!float.TryParse(text3, out var result2))
					{
						error_invalid_value(text, text3);
						return false;
					}
					Floats[text] = result2;
					num2++;
				}
				else if (Strings.ContainsKey(text))
				{
					SawArguments.Add(text);
					if (num2 == num)
					{
						error_missing_argument(text);
						return false;
					}
					string value = arguments[num2];
					Strings[text] = value;
					num2++;
				}
				else if (Flags.ContainsKey(text))
				{
					SawArguments.Add(text);
					Flags[text] = true;
				}
				else
				{
					Filenames.Add(text);
				}
			}
			return true;
		}

		protected virtual void error_missing_argument(string arg)
		{
			Console.WriteLine("argument {0} is missing value", arg);
		}

		protected virtual void error_invalid_value(string arg, string value)
		{
			Console.WriteLine("argument {0} has invalid value {1}", arg, value);
		}
	}
	public static class DeepCopy
	{
		public static List<T> List<T>(IEnumerable<T> Input) where T : IDuplicatable<T>
		{
			List<T> list = new List<T>();
			foreach (T item in Input)
			{
				list.Add(item.Duplicate());
			}
			return list;
		}

		public static T[] Array<T>(IEnumerable<T> Input) where T : IDuplicatable<T>
		{
			T[] array = new T[Input.Count()];
			int num = 0;
			foreach (T item in Input)
			{
				array[num++] = item.Duplicate();
			}
			return array;
		}
	}
	public class DijkstraGraphDistance
	{
		private class GraphNode : DynamicPriorityQueueNode, IEquatable<GraphNode>
		{
			public int id;

			public GraphNode parent;

			public bool frozen;

			public bool Equals(GraphNode other)
			{
				return id == other.id;
			}
		}

		private struct GraphNodeStruct(int id, int parent, float distance) : IEquatable<GraphNodeStruct>
		{
			public int id = id;

			public int parent = parent;

			public bool frozen = false;

			public float distance = distance;

			public static readonly GraphNodeStruct Zero = new GraphNodeStruct
			{
				id = -1,
				parent = -1,
				distance = float.MaxValue,
				frozen = false
			};

			public bool Equals(GraphNodeStruct other)
			{
				return id == other.id;
			}
		}

		public const float InvalidValue = float.MaxValue;

		public bool TrackOrder;

		private DynamicPriorityQueue<GraphNode> SparseQueue;

		private SparseObjectList<GraphNode> SparseNodes;

		private MemoryPool<GraphNode> SparseNodePool;

		private IndexPriorityQueue DenseQueue;

		private GraphNodeStruct[] DenseNodes;

		private Func<int, bool> NodeFilterF;

		private Func<int, int, float> NodeDistanceF;

		private Func<int, IEnumerable<int>> NeighboursF;

		private List<int> Seeds;

		private float max_value;

		private List<int> order;

		public float MaxDistance => max_value;

		public DijkstraGraphDistance(int nMaxID, bool bSparse, Func<int, bool> nodeFilterF, Func<int, int, float> nodeDistanceF, Func<int, IEnumerable<int>> neighboursF, IEnumerable<Vector2d> seeds = null)
		{
			NodeFilterF = nodeFilterF;
			NodeDistanceF = nodeDistanceF;
			NeighboursF = neighboursF;
			if (bSparse)
			{
				SparseQueue = new DynamicPriorityQueue<GraphNode>();
				SparseNodes = new SparseObjectList<GraphNode>(nMaxID, 0);
				SparseNodePool = new MemoryPool<GraphNode>();
			}
			else
			{
				DenseQueue = new IndexPriorityQueue(nMaxID);
				DenseNodes = new GraphNodeStruct[nMaxID];
			}
			Seeds = new List<int>();
			max_value = float.MinValue;
			if (seeds == null)
			{
				return;
			}
			foreach (Vector2d seed in seeds)
			{
				AddSeed((int)seed.x, (float)seed.y);
			}
		}

		public static DijkstraGraphDistance MeshVertices(DMesh3 mesh, bool bSparse = false)
		{
			if (!bSparse)
			{
				return new DijkstraGraphDistance(mesh.MaxVertexID, bSparse: false, (int id) => true, (int a, int b) => (float)mesh.GetVertex(a).Distance(mesh.GetVertex(b)), mesh.VtxVerticesItr);
			}
			return new DijkstraGraphDistance(mesh.MaxVertexID, bSparse: true, (int id) => mesh.IsVertex(id), (int a, int b) => (float)mesh.GetVertex(a).Distance(mesh.GetVertex(b)), mesh.VtxVerticesItr);
		}

		public static DijkstraGraphDistance MeshTriangles(DMesh3 mesh, bool bSparse = false)
		{
			Func<int, int, float> nodeDistanceF = (int a, int b) => (float)mesh.GetTriCentroid(a).Distance(mesh.GetTriCentroid(b));
			if (!bSparse)
			{
				return new DijkstraGraphDistance(mesh.MaxTriangleID, bSparse: false, (int id) => true, nodeDistanceF, mesh.TriTrianglesItr);
			}
			return new DijkstraGraphDistance(mesh.MaxTriangleID, bSparse: true, (int id) => mesh.IsTriangle(id), nodeDistanceF, mesh.TriTrianglesItr);
		}

		public void Reset()
		{
			if (SparseNodes != null)
			{
				SparseQueue.Clear(bFreeMemory: false);
				SparseNodes.Clear();
				SparseNodePool.ReturnAll();
			}
			else
			{
				DenseQueue.Clear(bFreeMemory: false);
				Array.Clear(DenseNodes, 0, DenseNodes.Length);
			}
			Seeds = new List<int>();
			max_value = float.MinValue;
		}

		public void AddSeed(int id, float seed_dist)
		{
			if (SparseNodes != null)
			{
				GraphNode node = get_node(id);
				SparseQueue.Enqueue(node, seed_dist);
			}
			else
			{
				enqueue_node_dense(id, seed_dist, -1);
			}
			Seeds.Add(id);
		}

		public bool IsSeed(int id)
		{
			return Seeds.Contains(id);
		}

		public void Compute()
		{
			if (TrackOrder)
			{
				order = new List<int>();
			}
			if (SparseNodes != null)
			{
				Compute_Sparse();
			}
			else
			{
				Compute_Dense();
			}
		}

		protected void Compute_Sparse()
		{
			while (SparseQueue.Count > 0)
			{
				GraphNode graphNode = SparseQueue.Dequeue();
				max_value = Math.Max(graphNode.priority, max_value);
				graphNode.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNode.id);
				}
				update_neighbours_sparse(graphNode);
			}
		}

		protected void Compute_Dense()
		{
			while (DenseQueue.Count > 0)
			{
				float firstPriority = DenseQueue.FirstPriority;
				int num = DenseQueue.Dequeue();
				GraphNodeStruct graphNodeStruct = DenseNodes[num];
				graphNodeStruct.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNodeStruct.id);
				}
				graphNodeStruct.distance = max_value;
				DenseNodes[num] = graphNodeStruct;
				max_value = Math.Max(firstPriority, max_value);
				update_neighbours_dense(graphNodeStruct.id);
			}
		}

		public void ComputeToMaxDistance(float fMaxDistance)
		{
			if (TrackOrder)
			{
				order = new List<int>();
			}
			if (SparseNodes != null)
			{
				ComputeToMaxDistance_Sparse(fMaxDistance);
			}
			else
			{
				ComputeToMaxDistance_Dense(fMaxDistance);
			}
		}

		protected void ComputeToMaxDistance_Sparse(float fMaxDistance)
		{
			while (SparseQueue.Count > 0)
			{
				GraphNode graphNode = SparseQueue.Dequeue();
				max_value = Math.Max(graphNode.priority, max_value);
				if (max_value > fMaxDistance)
				{
					break;
				}
				graphNode.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNode.id);
				}
				update_neighbours_sparse(graphNode);
			}
		}

		protected void ComputeToMaxDistance_Dense(float fMaxDistance)
		{
			while (DenseQueue.Count > 0)
			{
				float firstPriority = DenseQueue.FirstPriority;
				max_value = Math.Max(firstPriority, max_value);
				if (max_value > fMaxDistance)
				{
					break;
				}
				int num = DenseQueue.Dequeue();
				GraphNodeStruct graphNodeStruct = DenseNodes[num];
				graphNodeStruct.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNodeStruct.id);
				}
				graphNodeStruct.distance = max_value;
				DenseNodes[num] = graphNodeStruct;
				update_neighbours_dense(graphNodeStruct.id);
			}
		}

		public void ComputeToNode(int node_id, float fMaxDistance = float.MaxValue)
		{
			if (TrackOrder)
			{
				order = new List<int>();
			}
			if (SparseNodes != null)
			{
				ComputeToNode_Sparse(node_id, fMaxDistance);
			}
			else
			{
				ComputeToNode_Dense(node_id, fMaxDistance);
			}
		}

		protected void ComputeToNode_Sparse(int node_id, float fMaxDistance)
		{
			while (SparseQueue.Count > 0)
			{
				GraphNode graphNode = SparseQueue.Dequeue();
				max_value = Math.Max(graphNode.priority, max_value);
				if (max_value > fMaxDistance)
				{
					break;
				}
				graphNode.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNode.id);
				}
				if (graphNode.id == node_id)
				{
					break;
				}
				update_neighbours_sparse(graphNode);
			}
		}

		protected void ComputeToNode_Dense(int node_id, float fMaxDistance)
		{
			while (DenseQueue.Count > 0)
			{
				float firstPriority = DenseQueue.FirstPriority;
				max_value = Math.Max(firstPriority, max_value);
				if (max_value > fMaxDistance)
				{
					break;
				}
				int num = DenseQueue.Dequeue();
				GraphNodeStruct graphNodeStruct = DenseNodes[num];
				graphNodeStruct.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNodeStruct.id);
				}
				graphNodeStruct.distance = max_value;
				DenseNodes[num] = graphNodeStruct;
				if (graphNodeStruct.id == node_id)
				{
					break;
				}
				update_neighbours_dense(graphNodeStruct.id);
			}
		}

		public int ComputeToNode(Func<int, bool> terminatingNodeF, float fMaxDistance = float.MaxValue)
		{
			if (TrackOrder)
			{
				order = new List<int>();
			}
			if (SparseNodes != null)
			{
				return ComputeToNode_Sparse(terminatingNodeF, fMaxDistance);
			}
			return ComputeToNode_Dense(terminatingNodeF, fMaxDistance);
		}

		protected int ComputeToNode_Sparse(Func<int, bool> terminatingNodeF, float fMaxDistance)
		{
			while (SparseQueue.Count > 0)
			{
				GraphNode graphNode = SparseQueue.Dequeue();
				max_value = Math.Max(graphNode.priority, max_value);
				if (max_value > fMaxDistance)
				{
					return -1;
				}
				graphNode.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNode.id);
				}
				if (terminatingNodeF(graphNode.id))
				{
					return graphNode.id;
				}
				update_neighbours_sparse(graphNode);
			}
			return -1;
		}

		protected int ComputeToNode_Dense(Func<int, bool> terminatingNodeF, float fMaxDistance)
		{
			while (DenseQueue.Count > 0)
			{
				float firstPriority = DenseQueue.FirstPriority;
				max_value = Math.Max(firstPriority, max_value);
				if (max_value > fMaxDistance)
				{
					return -1;
				}
				int num = DenseQueue.Dequeue();
				GraphNodeStruct graphNodeStruct = DenseNodes[num];
				graphNodeStruct.frozen = true;
				if (TrackOrder)
				{
					order.Add(graphNodeStruct.id);
				}
				graphNodeStruct.distance = max_value;
				DenseNodes[num] = graphNodeStruct;
				if (terminatingNodeF(graphNodeStruct.id))
				{
					return graphNodeStruct.id;
				}
				update_neighbours_dense(graphNodeStruct.id);
			}
			return -1;
		}

		public float GetDistance(int id)
		{
			if (SparseNodes != null)
			{
				return SparseNodes[id]?.priority ?? float.MaxValue;
			}
			GraphNodeStruct graphNodeStruct = DenseNodes[id];
			if (!graphNodeStruct.frozen)
			{
				return float.MaxValue;
			}
			return graphNodeStruct.distance;
		}

		public List<int> GetOrder()
		{
			if (!TrackOrder)
			{
				throw new InvalidOperationException("DijkstraGraphDistance.GetOrder: Must set TrackOrder = true");
			}
			return order;
		}

		public bool GetPathToSeed(int fromv, List<int> path)
		{
			if (SparseNodes != null)
			{
				GraphNode graphNode = get_node(fromv);
				if (!graphNode.frozen)
				{
					return false;
				}
				path.Add(fromv);
				while (graphNode.parent != null)
				{
					path.Add(graphNode.parent.id);
					graphNode = graphNode.parent;
				}
				return true;
			}
			GraphNodeStruct graphNodeStruct = DenseNodes[fromv];
			if (!graphNodeStruct.frozen)
			{
				return false;
			}
			path.Add(fromv);
			while (graphNodeStruct.parent != -1)
			{
				path.Add(graphNodeStruct.parent);
				graphNodeStruct = DenseNodes[graphNodeStruct.parent];
			}
			return true;
		}

		private GraphNode get_node(int id)
		{
			GraphNode graphNode = SparseNodes[id];
			if (graphNode == null)
			{
				graphNode = SparseNodePool.Allocate();
				graphNode.id = id;
				graphNode.parent = null;
				graphNode.frozen = false;
				SparseNodes[id] = graphNode;
			}
			return graphNode;
		}

		private void update_neighbours_sparse(GraphNode parent)
		{
			float priority = parent.priority;
			foreach (int item in NeighboursF(parent.id))
			{
				if (!NodeFilterF(item))
				{
					continue;
				}
				GraphNode graphNode = get_node(item);
				if (graphNode.frozen)
				{
					continue;
				}
				float num = NodeDistanceF(parent.id, item) + priority;
				if (num == float.MaxValue)
				{
					continue;
				}
				if (SparseQueue.Contains(graphNode))
				{
					if (num < graphNode.priority)
					{
						graphNode.parent = parent;
						SparseQueue.Update(graphNode, num);
					}
				}
				else
				{
					graphNode.parent = parent;
					SparseQueue.Enqueue(graphNode, num);
				}
			}
		}

		private void enqueue_node_dense(int id, float dist, int parent_id)
		{
			GraphNodeStruct graphNodeStruct = new GraphNodeStruct(id, parent_id, dist);
			DenseNodes[id] = graphNodeStruct;
			DenseQueue.Insert(id, dist);
		}

		private void update_neighbours_dense(int parent_id)
		{
			float distance = DenseNodes[parent_id].distance;
			foreach (int item in NeighboursF(parent_id))
			{
				if (!NodeFilterF(item))
				{
					continue;
				}
				GraphNodeStruct graphNodeStruct = DenseNodes[item];
				if (graphNodeStruct.frozen)
				{
					continue;
				}
				float num = NodeDistanceF(parent_id, item) + distance;
				if (num == float.MaxValue)
				{
					continue;
				}
				if (DenseQueue.Contains(item))
				{
					if (num < graphNodeStruct.distance)
					{
						graphNodeStruct.parent = parent_id;
						DenseQueue.Update(item, num);
						DenseNodes[item] = graphNodeStruct;
					}
				}
				else
				{
					enqueue_node_dense(item, num, parent_id);
				}
			}
		}
	}
	public class DVector<T> : IEnumerable<T>, IEnumerable
	{
		public struct DBlock
		{
			public T[] data;

			public int usedCount;
		}

		private List<T[]> Blocks;

		private int iCurBlock;

		private int iCurBlockUsed;

		private int nBlockSize = 2048;

		private const int nShiftBits = 11;

		private const int nBlockIndexBitmask = 2047;

		public int Length => iCurBlock * nBlockSize + iCurBlockUsed;

		public int BlockCount => nBlockSize;

		public int size => Length;

		public bool empty
		{
			get
			{
				if (iCurBlock == 0)
				{
					return iCurBlockUsed == 0;
				}
				return false;
			}
		}

		public int MemoryUsageBytes
		{
			get
			{
				if (Blocks.Count != 0)
				{
					return Blocks.Count * nBlockSize * Marshal.SizeOf(Blocks[0][0]);
				}
				return 0;
			}
		}

		public T this[int i]
		{
			get
			{
				return Blocks[i >> 11][i & 0x7FF];
			}
			set
			{
				Blocks[i >> 11][i & 0x7FF] = value;
			}
		}

		public T back
		{
			get
			{
				return Blocks[iCurBlock][iCurBlockUsed - 1];
			}
			set
			{
				Blocks[iCurBlock][iCurBlockUsed - 1] = value;
			}
		}

		public T front
		{
			get
			{
				return Blocks[0][0];
			}
			set
			{
				Blocks[0][0] = value;
			}
		}

		public DVector()
		{
			iCurBlock = 0;
			iCurBlockUsed = 0;
			Blocks = new List<T[]>();
			Blocks.Add(new T[nBlockSize]);
		}

		public DVector(DVector<T> copy)
		{
			nBlockSize = copy.nBlockSize;
			iCurBlock = copy.iCurBlock;
			iCurBlockUsed = copy.iCurBlockUsed;
			Blocks = new List<T[]>();
			for (int i = 0; i < copy.Blocks.Count; i++)
			{
				Blocks.Add(new T[nBlockSize]);
				Array.Copy(copy.Blocks[i], Blocks[i], copy.Blocks[i].Length);
			}
		}

		public DVector(T[] data)
		{
			Initialize(data);
		}

		public DVector(IEnumerable<T> init)
		{
			iCurBlock = 0;
			iCurBlockUsed = 0;
			Blocks = new List<T[]>();
			Blocks.Add(new T[nBlockSize]);
			foreach (T item in init)
			{
				Add(item);
			}
		}

		public void Add(T value)
		{
			if (iCurBlockUsed == nBlockSize)
			{
				if (iCurBlock == Blocks.Count - 1)
				{
					Blocks.Add(new T[nBlockSize]);
				}
				iCurBlock++;
				iCurBlockUsed = 0;
			}
			Blocks[iCurBlock][iCurBlockUsed] = value;
			iCurBlockUsed++;
		}

		public void Add(T value, int nRepeat)
		{
			for (int i = 0; i < nRepeat; i++)
			{
				Add(value);
			}
		}

		public void Add(T[] values)
		{
			for (int i = 0; i < values.Length; i++)
			{
				Add(values[i]);
			}
		}

		public void Add(T[] values, int nRepeat)
		{
			for (int i = 0; i < nRepeat; i++)
			{
				for (int j = 0; j < values.Length; j++)
				{
					Add(values[j]);
				}
			}
		}

		public void push_back(T value)
		{
			Add(value);
		}

		public void pop_back()
		{
			if (iCurBlockUsed > 0)
			{
				iCurBlockUsed--;
			}
			if (iCurBlockUsed == 0 && iCurBlock > 0)
			{
				iCurBlock--;
				iCurBlockUsed = nBlockSize;
			}
		}

		public void insert(T value, int index)
		{
			insertAt(value, index);
		}

		public void insertAt(T value, int index)
		{
			int num = size;
			if (index == num)
			{
				push_back(value);
			}
			else if (index > num)
			{
				resize(index);
				push_back(value);
			}
			else
			{
				this[index] = value;
			}
		}

		public void resize(int count)
		{
			if (Length != count)
			{
				int num = 1 + count / nBlockSize;
				int count2 = Blocks.Count;
				for (int i = num; i < count2; i++)
				{
					Blocks[i] = null;
				}
				if (num >= Blocks.Count)
				{
					Blocks.Capacity = num;
				}
				else
				{
					Blocks.RemoveRange(num, Blocks.Count - num);
				}
				for (int j = count2; j < num; j++)
				{
					Blocks.Add(new T[nBlockSize]);
				}
				iCurBlockUsed = count - (num - 1) * nBlockSize;
				iCurBlock = num - 1;
			}
		}

		public void copy(DVector<T> copyIn)
		{
			if (Blocks != null && copyIn.Blocks.Count == Blocks.Count)
			{
				int count = copyIn.Blocks.Count;
				for (int i = 0; i < count; i++)
				{
					Array.Copy(copyIn.Blocks[i], Blocks[i], copyIn.Blocks[i].Length);
				}
				iCurBlock = copyIn.iCurBlock;
				iCurBlockUsed = copyIn.iCurBlockUsed;
				return;
			}
			resize(copyIn.size);
			int count2 = copyIn.Blocks.Count;
			for (int j = 0; j < count2; j++)
			{
				Array.Copy(copyIn.Blocks[j], Blocks[j], copyIn.Blocks[j].Length);
			}
			iCurBlock = copyIn.iCurBlock;
			iCurBlockUsed = copyIn.iCurBlockUsed;
		}

		public void GetBuffer(T[] data)
		{
			int length = Length;
			for (int i = 0; i < length; i++)
			{
				data[i] = this[i];
			}
		}

		public T[] GetBuffer()
		{
			T[] array = new T[Length];
			for (int i = 0; i < Length; i++)
			{
				array[i] = this[i];
			}
			return array;
		}

		public T[] ToArray()
		{
			return GetBuffer();
		}

		public T2[] GetBufferCast<T2>()
		{
			T2[] array = new T2[Length];
			for (int i = 0; i < Length; i++)
			{
				array[i] = (T2)Convert.ChangeType(this[i], typeof(T2));
			}
			return array;
		}

		public byte[] GetBytes()
		{
			int num = Marshal.SizeOf(typeof(T));
			byte[] array = new byte[Length * num];
			int num2 = 0;
			int count = Blocks.Count;
			for (int i = 0; i < count - 1; i++)
			{
				Buffer.BlockCopy(Blocks[i], 0, array, num2, nBlockSize * num);
				num2 += nBlockSize * num;
			}
			Buffer.BlockCopy(Blocks[count - 1], 0, array, num2, iCurBlockUsed * num);
			return array;
		}

		public void Initialize(T[] data)
		{
			int num = data.Length / nBlockSize;
			Blocks = new List<T[]>();
			int num2 = 0;
			for (int i = 0; i < num; i++)
			{
				T[] array = new T[nBlockSize];
				Array.Copy(data, num2, array, 0, nBlockSize);
				Blocks.Add(array);
				num2 += nBlockSize;
			}
			iCurBlockUsed = data.Length - num2;
			if (iCurBlockUsed != 0)
			{
				T[] array2 = new T[nBlockSize];
				Array.Copy(data, num2, array2, 0, iCurBlockUsed);
				Blocks.Add(array2);
			}
			else
			{
				iCurBlockUsed = nBlockSize;
			}
			iCurBlock = Blocks.Count - 1;
		}

		public void Clear()
		{
			foreach (T[] block in Blocks)
			{
				Array.Clear(block, 0, block.Length);
			}
		}

		public void Apply(Action<T, int> applyF)
		{
			for (int i = 0; i < iCurBlock; i++)
			{
				T[] array = Blocks[i];
				for (int j = 0; j < nBlockSize; j++)
				{
					applyF(array[j], j);
				}
			}
			T[] array2 = Blocks[iCurBlock];
			for (int k = 0; k < iCurBlockUsed; k++)
			{
				applyF(array2[k], k);
			}
		}

		public void ApplyReplace(Func<T, int, T> applyF)
		{
			for (int i = 0; i < iCurBlock; i++)
			{
				T[] array = Blocks[i];
				for (int j = 0; j < nBlockSize; j++)
				{
					array[j] = applyF(array[j], j);
				}
			}
			T[] array2 = Blocks[iCurBlock];
			for (int k = 0; k < iCurBlockUsed; k++)
			{
				array2[k] = applyF(array2[k], k);
			}
		}

		public unsafe static void FastGetBuffer(DVector<double> v, double* pBuffer)
		{
			IntPtr destination = new IntPtr(pBuffer);
			int count = v.Blocks.Count;
			for (int i = 0; i < count - 1; i++)
			{
				Marshal.Copy(v.Blocks[i], 0, destination, v.nBlockSize);
				destination = new IntPtr(destination.ToInt64() + v.nBlockSize * 8);
			}
			Marshal.Copy(v.Blocks[count - 1], 0, destination, v.iCurBlockUsed);
		}

		public unsafe static void FastGetBuffer(DVector<float> v, float* pBuffer)
		{
			IntPtr destination = new IntPtr(pBuffer);
			int count = v.Blocks.Count;
			for (int i = 0; i < count - 1; i++)
			{
				Marshal.Copy(v.Blocks[i], 0, destination, v.nBlockSize);
				destination = new IntPtr(destination.ToInt64() + v.nBlockSize * 4);
			}
			Marshal.Copy(v.Blocks[count - 1], 0, destination, v.iCurBlockUsed);
		}

		public unsafe static void FastGetBuffer(DVector<int> v, int* pBuffer)
		{
			IntPtr destination = new IntPtr(pBuffer);
			int count = v.Blocks.Count;
			for (int i = 0; i < count - 1; i++)
			{
				Marshal.Copy(v.Blocks[i], 0, destination, v.nBlockSize);
				destination = new IntPtr(destination.ToInt64() + v.nBlockSize * 4);
			}
			Marshal.Copy(v.Blocks[count - 1], 0, destination, v.iCurBlockUsed);
		}

		public IEnumerator<T> GetEnumerator()
		{
			int bi = 0;
			while (bi < iCurBlock)
			{
				T[] block = Blocks[bi];
				int num;
				for (int k = 0; k < nBlockSize; k = num)
				{
					yield return block[k];
					num = k + 1;
				}
				num = bi + 1;
				bi = num;
			}
			T[] lastblock = Blocks[iCurBlock];
			bi = 0;
			while (bi < iCurBlockUsed)
			{
				yield return lastblock[bi];
				int num = bi + 1;
				bi = num;
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		public IEnumerable<DBlock> BlockIterator()
		{
			int i = 0;
			while (i < iCurBlock)
			{
				yield return new DBlock
				{
					data = Blocks[i],
					usedCount = nBlockSize
				};
				int num = i + 1;
				i = num;
			}
			yield return new DBlock
			{
				data = Blocks[iCurBlock],
				usedCount = iCurBlockUsed
			};
		}
	}
	public class DVectorArray3<T> : IEnumerable<T>, IEnumerable
	{
		public DVector<T> vector;

		public int Count => vector.Length / 3;

		public DVectorArray3(int nCount = 0)
		{
			vector = new DVector<T>();
			if (nCount > 0)
			{
				vector.resize(nCount * 3);
			}
		}

		public DVectorArray3(T[] data)
		{
			vector = new DVector<T>(data);
		}

		public IEnumerator<T> GetEnumerator()
		{
			int i = 0;
			while (i < vector.Length)
			{
				yield return vector[i];
				int num = i + 1;
				i = num;
			}
		}

		public void Resize(int count)
		{
			vector.resize(3 * count);
		}

		public void Set(int i, T a, T b, T c)
		{
			vector.insert(a, 3 * i);
			vector.insert(b, 3 * i + 1);
			vector.insert(c, 3 * i + 2);
		}

		public void Append(T a, T b, T c)
		{
			vector.push_back(a);
			vector.push_back(b);
			vector.push_back(c);
		}

		public void Clear()
		{
			vector.Clear();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
