	public class gParallel
	{
		public static void ForEach_Sequential<T>(IEnumerable<T> source, Action<T> body)
		{
			foreach (T item in source)
			{
				body(item);
			}
		}

		public static void ForEach<T>(IEnumerable<T> source, Action<T> body)
		{
			Parallel.ForEach(source, body);
		}

		public static void Evaluate(params Action[] funcs)
		{
			ForEach(Interval1i.Range(funcs.Length), delegate(int i)
			{
				funcs[i]();
			});
		}

		public static void BlockStartEnd(int iStart, int iEnd, Action<int, int> blockF, int iBlockSize = -1, bool bDisableParallel = false)
		{
			if (iBlockSize == -1)
			{
				iBlockSize = 100;
			}
			int num = iEnd - iStart + 1;
			int num2 = num / iBlockSize;
			if (bDisableParallel)
			{
				ForEach_Sequential(Interval1i.Range(num2), delegate(int bi)
				{
					int num5 = iStart + iBlockSize * bi;
					blockF(num5, num5 + iBlockSize - 1);
				});
			}
			else
			{
				ForEach(Interval1i.Range(num2), delegate(int bi)
				{
					int num5 = iStart + iBlockSize * bi;
					blockF(num5, num5 + iBlockSize - 1);
				});
			}
			int num3 = num - num2 * iBlockSize;
			if (num3 > 0)
			{
				int num4 = iStart + num2 * iBlockSize;
				blockF(num4, num4 + num3 - 1);
			}
		}

		private static void for_each<T>(IEnumerable<T> source, Action<T> body)
		{
			int remainingWorkItems;
			int num = (remainingWorkItems = Environment.ProcessorCount);
			Exception last_exception = null;
			IEnumerator<T> enumerator = source.GetEnumerator();
			try
			{
				ManualResetEvent mre = new ManualResetEvent(initialState: false);
				try
				{
					for (int i = 0; i < num; i++)
					{
						ThreadPool.QueueUserWorkItem(delegate
						{
							while (true)
							{
								T current;
								lock (enumerator)
								{
									if (enumerator.MoveNext())
									{
										current = enumerator.Current;
										goto IL_0039;
									}
								}
								break;
								IL_0039:
								try
								{
									body(current);
								}
								catch (Exception ex)
								{
									last_exception = ex;
									break;
								}
							}
							if (Interlocked.Decrement(ref remainingWorkItems) == 0)
							{
								mre.Set();
							}
						});
					}
					mre.WaitOne();
				}
				finally
				{
					if (mre != null)
					{
						((IDisposable)mre).Dispose();
					}
				}
			}
			finally
			{
				if (enumerator != null)
				{
					enumerator.Dispose();
				}
			}
			if (last_exception != null)
			{
				throw last_exception;
			}
		}
	}
	public class ParallelStream<V, T>
	{
		public Func<V, T> ProducerF;

		public Action<T> ConsumerF;

		private LockingQueue<T> store0 = new LockingQueue<T>();

		private IEnumerable<V> source;

		private bool producer_done;

		private AutoResetEvent consumer_done_event;

		public void Run_NoThreads(IEnumerable<V> sourceIn)
		{
			foreach (V item in sourceIn)
			{
				T obj = ProducerF(item);
				ConsumerF(obj);
			}
		}

		public void Run(IEnumerable<V> sourceIn)
		{
			source = sourceIn;
			producer_done = false;
			consumer_done_event = new AutoResetEvent(initialState: false);
			Thread thread = new Thread(ProducerThreadFunc);
			thread.Name = "ParallelStream_producer";
			thread.Start();
			Thread thread2 = new Thread(ConsumerThreadFunc);
			thread2.Name = "ParallelStream_consumer";
			thread2.Start();
			consumer_done_event.WaitOne();
		}

		private void ProducerThreadFunc()
		{
			foreach (V item in source)
			{
				T obj = ProducerF(item);
				store0.Add(obj);
			}
			producer_done = true;
		}

		private void ConsumerThreadFunc()
		{
			T val = default(T);
			while (!producer_done || store0.Count > 0)
			{
				if (store0.Remove(ref val))
				{
					ConsumerF(val);
				}
			}
			consumer_done_event.Set();
		}
	}
	public class LockingQueue<T>
	{
		private Queue<T> queue;

		private object queue_lock;

		public int Count
		{
			get
			{
				lock (queue_lock)
				{
					return queue.Count;
				}
			}
		}

		public LockingQueue()
		{
			queue = new Queue<T>();
			queue_lock = new object();
		}

		public bool Remove(ref T val)
		{
			lock (queue_lock)
			{
				if (queue.Count > 0)
				{
					val = queue.Dequeue();
					return true;
				}
				return false;
			}
		}

		public void Add(T obj)
		{
			lock (queue_lock)
			{
				queue.Enqueue(obj);
			}
		}
	}
	public struct HashBuilder(int init = -2128831035)
	{
		public int Hash = init;

		public void Add(int i)
		{
			Hash = (Hash * 16777619) ^ i.GetHashCode();
		}

		public void Add(double d)
		{
			Hash = (Hash * 16777619) ^ d.GetHashCode();
