	public class IndexMap : IIndexMap
	{
		public readonly int InvalidIndex = int.MinValue;

		private int[] dense_map;

		private Dictionary<int, int> sparse_map;

		private int MaxIndex;

		public int this[int index]
		{
			get
			{
				if (dense_map != null)
				{
					return dense_map[index];
				}
				if (sparse_map.TryGetValue(index, out var value))
				{
					return value;
				}
				return InvalidIndex;
			}
			set
			{
				if (dense_map != null)
				{
					dense_map[index] = value;
				}
				else
				{
					sparse_map[index] = value;
				}
			}
		}

		public IndexMap(bool bForceSparse, int MaxIndex = -1)
		{
			if (bForceSparse)
			{
				sparse_map = new Dictionary<int, int>();
			}
			else
			{
				dense_map = new int[MaxIndex];
			}
			this.MaxIndex = MaxIndex;
			SetToInvalid();
		}

		public IndexMap(int[] use_dense_map, int MaxIndex = -1)
		{
			dense_map = use_dense_map;
			this.MaxIndex = MaxIndex;
		}

		public IndexMap(int MaxIndex, int SubsetCountEst)
		{
			bool num = MaxIndex < 32000;
			float num2 = (float)SubsetCountEst / (float)MaxIndex;
			float num3 = 0.1f;
			if (num || num2 > num3)
			{
				dense_map = new int[MaxIndex];
			}
			else
			{
				sparse_map = new Dictionary<int, int>();
			}
			this.MaxIndex = MaxIndex;
			SetToInvalid();
		}

		public void SetToInvalid()
		{
			if (dense_map != null)
			{
				for (int i = 0; i < dense_map.Length; i++)
				{
					dense_map[i] = InvalidIndex;
				}
			}
		}

		public bool Contains(int index)
		{
			if (MaxIndex > 0 && index >= MaxIndex)
			{
				return false;
			}
			if (dense_map != null)
			{
				return dense_map[index] != InvalidIndex;
			}
			return sparse_map.ContainsKey(index);
		}
	}
	public class IndexPriorityQueue : IEnumerable<int>, IEnumerable
	{
		private struct QueueNode
		{
			public int id;

			public float priority;

			public int index;
		}

		public bool EnableDebugChecks;

		private DVector<QueueNode> nodes;

		private int num_nodes;

		private int[] id_to_index;

		public int Count => num_nodes;

		public int First => nodes[1].id;

		public float FirstPriority => nodes[1].priority;

		public IndexPriorityQueue(int maxID)
		{
			nodes = new DVector<QueueNode>();
			id_to_index = new int[maxID];
			for (int i = 0; i < maxID; i++)
			{
				id_to_index[i] = -1;
			}
			num_nodes = 0;
		}

		public void Clear(bool bFreeMemory = true)
		{
			if (bFreeMemory)
			{
				nodes = new DVector<QueueNode>();
			}
			Array.Clear(id_to_index, 0, id_to_index.Length);
			num_nodes = 0;
		}

		public bool Contains(int id)
		{
			int num = id_to_index[id];
			if (num <= 0 || num > num_nodes)
			{
				return false;
			}
			return nodes[num].index > 0;
		}

		public void Insert(int id, float priority)
		{
			if (EnableDebugChecks && Contains(id))
			{
				throw new Exception("IndexPriorityQueue.Insert: tried to add node that is already in queue!");
			}
			QueueNode value = new QueueNode
			{
				id = id,
				priority = priority
			};
			num_nodes++;
			value.index = num_nodes;
			id_to_index[id] = value.index;
			nodes.insert(value, num_nodes);
			move_up(nodes[num_nodes].index);
		}

		public void Enqueue(int id, float priority)
		{
			Insert(id, priority);
		}

		public int Dequeue()
		{
			if (EnableDebugChecks && Count == 0)
			{
				throw new Exception("IndexPriorityQueue.Dequeue: queue is empty!");
			}
			int id = nodes[1].id;
			remove_at_index(1);
			return id;
		}

		public void Remove(int id)
		{
			if (EnableDebugChecks && !Contains(id))
			{
				throw new Exception("IndexPriorityQueue.Remove: tried to remove node that does not exist in queue!");
			}
			int iNode = id_to_index[id];
			remove_at_index(iNode);
		}

		public void Update(int id, float priority)
		{
			if (EnableDebugChecks && !Contains(id))
			{
				throw new Exception("IndexPriorityQueue.Update: tried to update node that does not exist in queue!");
			}
			int num = id_to_index[id];
			QueueNode value = nodes[num];
			value.priority = priority;
			nodes[num] = value;
			on_node_updated(num);
		}

		public float GetPriority(int id)
		{
			if (EnableDebugChecks && !Contains(id))
			{
				throw new Exception("IndexPriorityQueue.Update: tried to get priorty of node that does not exist in queue!");
			}
			int i = id_to_index[id];
			return nodes[i].priority;
		}

		public IEnumerator<int> GetEnumerator()
		{
			for (int i = 1; i <= num_nodes; i++)
			{
				yield return nodes[i].id;
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		private void remove_at_index(int iNode)
		{
			if (iNode == num_nodes)
			{
				nodes[iNode] = default(QueueNode);
				num_nodes--;
				return;
			}
			swap_nodes_at_indices(iNode, num_nodes);
			nodes[num_nodes] = default(QueueNode);
			num_nodes--;
			on_node_updated(iNode);
		}

		private void swap_nodes_at_indices(int i1, int i2)
		{
			QueueNode value = nodes[i1];
			value.index = i2;
			QueueNode value2 = nodes[i2];
			value2.index = i1;
			nodes[i1] = value2;
			nodes[i2] = value;
			id_to_index[value2.id] = i1;
			id_to_index[value.id] = i2;
		}

		private void move(int iFrom, int iTo)
		{
			QueueNode value = nodes[iFrom];
			value.index = iTo;
			nodes[iTo] = value;
			id_to_index[value.id] = iTo;
		}

		private void set(int iTo, ref QueueNode n)
		{
			n.index = iTo;
			nodes[iTo] = n;
			id_to_index[n.id] = iTo;
		}

		private void move_up(int iNode)
		{
			int num = iNode;
			QueueNode n = nodes[num];
			int num2 = iNode / 2;
			while (num2 >= 1 && !(nodes[num2].priority < n.priority))
			{
				move(num2, iNode);
				iNode = num2;
				num2 = nodes[iNode].index / 2;
			}
			if (iNode != num)
			{
				set(iNode, ref n);
			}
		}

		private void move_down(int iNode)
		{
			int num = iNode;
			QueueNode n = nodes[num];
			while (true)
			{
				int num2 = iNode;
				int num3 = 2 * iNode;
				if (num3 > num_nodes)
				{
					break;
				}
				float num4 = n.priority;
				float priority = nodes[num3].priority;
				if (priority < num4)
				{
					num2 = num3;
					num4 = priority;
				}
				int num5 = num3 + 1;
				if (num5 <= num_nodes && nodes[num5].priority < num4)
				{
					num2 = num5;
				}
				if (num2 == iNode)
				{
					break;
				}
				move(num2, iNode);
				iNode = num2;
			}
			if (iNode != num)
			{
				set(iNode, ref n);
			}
		}

		private void on_node_updated(int iNode)
		{
			int num = iNode / 2;
			if (num > 0 && has_higher_priority(iNode, num))
			{
				move_up(iNode);
			}
			else
			{
				move_down(iNode);
			}
		}

		private bool has_higher_priority(int iHigher, int iLower)
		{
			return nodes[iHigher].priority < nodes[iLower].priority;
		}

		public bool IsValidQueue()
		{
			for (int i = 1; i < num_nodes; i++)
			{
				int num = 2 * i;
				if (num < num_nodes && has_higher_priority(num, i))
				{
					return false;
				}
				int num2 = num + 1;
				if (num2 < num_nodes && has_higher_priority(num2, i))
				{
					return false;
				}
			}
			return true;
		}

		public void DebugPrint()
		{
			for (int i = 1; i <= num_nodes; i++)
			{
				Console.WriteLine("{0} : p {1}  index {2}  id {3}", i, nodes[i].priority, nodes[i].index, nodes[i].id);
			}
		}
	}
	public class MemoryPool<T> where T : class, new()
	{
		private DVector<T> Allocated;

		private DVector<T> Free;

		public MemoryPool()
		{
			Allocated = new DVector<T>();
			Free = new DVector<T>();
		}

		public T Allocate()
		{
			if (Free.size > 0)
			{
				T result = Free[Free.size - 1];
				Free.pop_back();
				return result;
			}
			T val = new T();
			Allocated.Add(val);
			return val;
		}

		public void Return(T obj)
		{
			Free.Add(obj);
		}

		public void ReturnAll()
		{
			Free = new DVector<T>(Allocated);
		}

		public void FreeAll()
		{
			Allocated = new DVector<T>();
			Free = new DVector<T>();
		}
	}
	public class BlockTimer
	{
		public Stopwatch Watch;

		public string Label;

		public TimeSpan Accumulated;

		private const string minute_format = "{0:mm}:{0:ss}.{0:fffffff}";

		private const string second_format = "{0:ss}.{0:fffffff}";

		public bool Running => Watch.IsRunning;

		public string AccumulatedString => string.Format(TimeFormatString(Accumulated), Accumulated);

		public BlockTimer(string label, bool bStart)
		{
			Label = label;
			Watch = new Stopwatch();
			if (bStart)
			{
				Watch.Start();
			}
			Accumulated = TimeSpan.Zero;
		}

		public void Start()
		{
			Watch.Start();
		}

		public void Stop()
		{
			Watch.Stop();
		}

		public void Accumulate(bool bReset = false)
		{
			Watch.Stop();
			Accumulated += Watch.Elapsed;
			if (bReset)
			{
				Watch.Reset();
			}
		}

		public void Reset()
		{
			Watch.Stop();
			Watch.Reset();
			Watch.Start();
		}

		public override string ToString()
		{
			_ = Watch.Elapsed;
			return string.Format(TimeFormatString(Accumulated), Watch.Elapsed);
		}

		public static string TimeFormatString(TimeSpan span)
		{
			if (span.Minutes > 0)
			{
				return "{0:mm}:{0:ss}.{0:fffffff}";
			}
			return "{0:ss}.{0:fffffff}";
		}
	}
	public class LocalProfiler : IDisposable
	{
		private Dictionary<string, BlockTimer> Timers = new Dictionary<string, BlockTimer>();

		private List<string> Order = new List<string>();

		public BlockTimer Start(string label)
		{
			if (Timers.ContainsKey(label))
			{
				Timers[label].Reset();
			}
			else
			{
				Timers[label] = new BlockTimer(label, bStart: true);
				Order.Add(label);
			}
			return Timers[label];
		}

		public BlockTimer StopAllAndStartNew(string label)
		{
			StopAll();
			return Start(label);
		}

		public BlockTimer Get(string label)
		{
			return Timers[label];
		}

		public void Stop(string label)
		{
			Timers[label].Stop();
		}

		public void StopAll()
		{
			foreach (BlockTimer value in Timers.Values)
			{
				if (value.Running)
				{
					value.Stop();
				}
			}
		}

		public void StopAndAccumulate(string label, bool bReset = false)
		{
			Timers[label].Accumulate(bReset);
		}

		public void Reset(string label)
		{
			Timers[label].Reset();
		}

		public void ResetAccumulated(string label)
		{
			Timers[label].Accumulated = TimeSpan.Zero;
		}

		public void ResetAllAccumulated(string label)
		{
			foreach (BlockTimer value in Timers.Values)
			{
				value.Accumulated = TimeSpan.Zero;
			}
		}

		public void DivideAllAccumulated(int div)
		{
			foreach (BlockTimer value in Timers.Values)
			{
				value.Accumulated = new TimeSpan(value.Accumulated.Ticks / div);
			}
		}

		public string Elapsed(string label)
		{
			return Timers[label].ToString();
		}

		public string Accumulated(string label)
		{
			TimeSpan accumulated = Timers[label].Accumulated;
			return string.Format(BlockTimer.TimeFormatString(accumulated), accumulated);
		}

		public string AllTicks(string prefix = "Times:")
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(prefix + " ");
			foreach (string item in Order)
			{
				stringBuilder.Append(item + ": " + Timers[item].ToString() + " ");
			}
			return stringBuilder.ToString();
		}

		public string AllAccumulatedTicks(string prefix = "Times:")
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(prefix + " ");
			foreach (string item in Order)
			{
				stringBuilder.Append(item + ": " + Accumulated(item) + " ");
			}
			return stringBuilder.ToString();
		}

		public string AllTimes(string prefix = "Times:", string separator = " ")
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(prefix + " ");
			foreach (string item in Order)
			{
				TimeSpan elapsed = Timers[item].Watch.Elapsed;
				stringBuilder.Append(item + ": " + string.Format(BlockTimer.TimeFormatString(elapsed), elapsed) + separator);
			}
			return stringBuilder.ToString();
		}

		public string AllAccumulatedTimes(string prefix = "Times:", string separator = " ")
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(prefix + " ");
			foreach (string item in Order)
			{
				TimeSpan accumulated = Timers[item].Accumulated;
				stringBuilder.Append(item + ": " + string.Format(BlockTimer.TimeFormatString(accumulated), accumulated) + separator);
			}
			return stringBuilder.ToString();
		}

		public void Dispose()
		{
			foreach (BlockTimer value in Timers.Values)
			{
				value.Stop();
			}
			Timers.Clear();
		}
	}
	public interface ICancelSource
	{
		bool Cancelled();
	}
	public class CancelFunction : ICancelSource
	{
		public Func<bool> CancelF;

		public CancelFunction(Func<bool> cancelF)
		{
			CancelF = cancelF;
		}

		public bool Cancelled()
		{
			return CancelF();
		}
	}
	public class ProgressCancel
	{
		public ICancelSource Source;

		private bool WasCancelled;

		public ProgressCancel(ICancelSource source)
		{
			Source = source;
		}

		public ProgressCancel(Func<bool> cancelF)
		{
			Source = new CancelFunction(cancelF);
		}

		public bool Cancelled()
		{
			if (WasCancelled)
			{
				return true;
			}
			WasCancelled = Source.Cancelled();
			return WasCancelled;
		}
	}
	public class RefCountVector : IEnumerable
	{
		public static readonly short invalid = -1;

		private DVector<short> ref_counts;

		private DVector<int> free_indices;

		private int used_count;

		public DVector<short> RawRefCounts => ref_counts;

		public bool empty => used_count == 0;

		public int count => used_count;

		public int max_index => ref_counts.size;

		public bool is_dense => free_indices.Length == 0;

		public string UsageStats => $"RefCountSize {ref_counts.size}  FreeSize {free_indices.size} FreeMem {free_indices.MemoryUsageBytes / 1024}kb";

		public RefCountVector()
		{
			ref_counts = new DVector<short>();
			free_indices = new DVector<int>();
			used_count = 0;
		}

		public RefCountVector(RefCountVector copy)
		{
			ref_counts = new DVector<short>(copy.ref_counts);
			free_indices = new DVector<int>(copy.free_indices);
			used_count = copy.used_count;
		}

		public RefCountVector(short[] raw_ref_counts, bool build_free_list = false)
		{
			ref_counts = new DVector<short>(raw_ref_counts);
			free_indices = new DVector<int>();
			used_count = 0;
			if (build_free_list)
			{
				rebuild_free_list();
			}
		}

		public bool isValid(int index)
		{
			if (index >= 0 && index < ref_counts.size)
			{
				return ref_counts[index] > 0;
			}
			return false;
		}

		public bool isValidUnsafe(int index)
		{
			return ref_counts[index] > 0;
		}

		public int refCount(int index)
		{
			int num = ref_counts[index];
			if (num != invalid)
			{
				return num;
			}
			return 0;
		}

		public int rawRefCount(int index)
		{
			return ref_counts[index];
		}

		public int allocate()
		{
			used_count++;
			if (free_indices.empty)
			{
				ref_counts.push_back(1);
				return ref_counts.size - 1;
			}
			int back = invalid;
			while (back == invalid && !free_indices.empty)
			{
				back = free_indices.back;
				free_indices.pop_back();
			}
			if (back != invalid)
			{
				ref_counts[back] = 1;
				return back;
			}
			ref_counts.push_back(1);
			return ref_counts.size - 1;
		}

		public int increment(int index, short increment = 1)
		{
			ref_counts[index] += increment;
			return ref_counts[index];
		}

		public void decrement(int index, short decrement = 1)
		{
			ref_counts[index] -= decrement;
			if (ref_counts[index] == 0)
			{
				free_indices.push_back(index);
				ref_counts[index] = invalid;
				used_count--;
			}
		}

		public bool allocate_at(int index)
		{
			if (index >= ref_counts.size)
			{
				for (int i = ref_counts.size; i < index; i++)
				{
					ref_counts.push_back(invalid);
					free_indices.push_back(i);
				}
				ref_counts.push_back(1);
				used_count++;
				return true;
			}
			if (ref_counts[index] > 0)
			{
				return false;
			}
			int size = free_indices.size;
			for (int j = 0; j < size; j++)
			{
				if (free_indices[j] == index)
				{
					free_indices[j] = invalid;
					ref_counts[index] = 1;
					used_count++;
					return true;
				}
			}
			return false;
		}

		public bool allocate_at_unsafe(int index)
		{
			if (index >= ref_counts.size)
			{
				for (int i = ref_counts.size; i < index; i++)
				{
					ref_counts.push_back(invalid);
				}
				ref_counts.push_back(1);
				used_count++;
				return true;
			}
			if (ref_counts[index] > 0)
			{
				return false;
			}
			ref_counts[index] = 1;
			used_count++;
			return true;
		}

		public void set_Unsafe(int index, short count)
		{
			ref_counts[index] = count;
		}

		public void rebuild_free_list()
		{
			free_indices = new DVector<int>();
			used_count = 0;
			int length = ref_counts.Length;
			for (int i = 0; i < length; i++)
			{
				if (ref_counts[i] > 0)
				{
					used_count++;
				}
				else
				{
					free_indices.Add(i);
				}
			}
		}

		public void trim(int maxIndex)
		{
			free_indices = new DVector<int>();
			ref_counts.resize(maxIndex);
			used_count = maxIndex;
		}

		public IEnumerator GetEnumerator()
		{
			int nIndex = 0;
			int nLast;
			for (nLast = max_index; nIndex != nLast && ref_counts[nIndex] <= 0; nIndex++)
			{
			}
			while (nIndex != nLast)
			{
				yield return nIndex;
				if (nIndex != nLast)
				{
					nIndex++;
				}
				for (; nIndex != nLast && ref_counts[nIndex] <= 0; nIndex++)
				{
				}
			}
		}

		public string debug_print()
		{
			string text = $"size {ref_counts.size} used {used_count} free_size {free_indices.size}\n";
			for (int i = 0; i < ref_counts.size; i++)
			{
				text += $"{i}:{ref_counts[i]} ";
			}
			text += "\nfree:\n";
			for (int j = 0; j < free_indices.size; j++)
			{
				text = text + free_indices[j] + " ";
			}
			return text;
		}
	}
	public class SafeListBuilder<T>
	{
		public List<T> List;

		public SpinLock spinlock;

		public List<T> Result => List;

		public SafeListBuilder()
		{
			List = new List<T>();
			spinlock = default(SpinLock);
		}

		public void SafeAdd(T value)
		{
			bool lockTaken = false;
			while (!lockTaken)
			{
				spinlock.Enter(ref lockTaken);
			}
			List.Add(value);
			spinlock.Exit();
		}

		public void SafeOperation(Action<List<T>> opF)
		{
			bool lockTaken = false;
			while (!lockTaken)
			{
				spinlock.Enter(ref lockTaken);
			}
			opF(List);
			spinlock.Exit();
		}
	}
	public class SmallListSet
	{
		private const int Null = -1;

		private const int BLOCKSIZE = 8;

		private const int BLOCK_LIST_OFFSET = 9;

		private DVector<int> list_heads;

		private DVector<int> block_store;

		private DVector<int> free_blocks;

		private int allocated_count;

		private DVector<int> linked_store;

		private int free_head_ptr;

		public int Size => list_heads.size;

		public string MemoryUsage => $"ListSize {list_heads.size}  Blocks Count {allocated_count} Free {free_blocks.size * 4 / 1024} Mem {block_store.size}kb  Linked Mem {linked_store.size * 4 / 1024}kb";

		public SmallListSet()
		{
			list_heads = new DVector<int>();
			linked_store = new DVector<int>();
			free_head_ptr = -1;
			block_store = new DVector<int>();
			free_blocks = new DVector<int>();
		}

		public SmallListSet(SmallListSet copy)
		{
			linked_store = new DVector<int>(copy.linked_store);
			free_head_ptr = copy.free_head_ptr;
			list_heads = new DVector<int>(copy.list_heads);
			block_store = new DVector<int>(copy.block_store);
			free_blocks = new DVector<int>(copy.free_blocks);
		}

		public void Resize(int new_size)
		{
			int size = list_heads.size;
			if (new_size > size)
			{
				list_heads.resize(new_size);
				for (int i = size; i < new_size; i++)
				{
					list_heads[i] = -1;
				}
			}
		}

		public void AllocateAt(int list_index)
		{
			if (list_index >= list_heads.size)
			{
				int i = list_heads.size;
				list_heads.insert(-1, list_index);
				for (; i < list_index; i++)
				{
					list_heads[i] = -1;
				}
			}
			else if (list_heads[list_index] != -1)
			{
				throw new Exception("SmallListSet: list at " + list_index + " is not empty!");
			}
		}

		public void Insert(int list_index, int val)
		{
			int num = list_heads[list_index];
			if (num == -1)
			{
				num = allocate_block();
				block_store[num] = 0;
				list_heads[list_index] = num;
			}
			int num2 = block_store[num];
			if (num2 < 8)
			{
				block_store[num + num2 + 1] = val;
			}
			else
			{
				int value = block_store[num + 9];
				if (free_head_ptr == -1)
				{
					int size = linked_store.size;
					linked_store.Add(val);
					linked_store.Add(value);
					block_store[num + 9] = size;
				}
				else
				{
					int num3 = free_head_ptr;
					free_head_ptr = linked_store[num3 + 1];
					linked_store[num3] = val;
					linked_store[num3 + 1] = value;
					block_store[num + 9] = num3;
				}
			}
			block_store[num]++;
		}

		public bool Remove(int list_index, int val)
		{
			int num = list_heads[list_index];
			int num2 = block_store[num];
			int num3 = num + Math.Min(num2, 8);
			for (int i = num + 1; i <= num3; i++)
			{
				if (block_store[i] == val)
				{
					for (int j = i + 1; j <= num3; j++)
					{
						block_store[j - 1] = block_store[j];
					}
					if (num2 > 8)
					{
						int num4 = block_store[num + 9];
						block_store[num + 9] = linked_store[num4 + 1];
						block_store[num3] = linked_store[num4];
						add_free_link(num4);
					}
					block_store[num]--;
					return true;
				}
			}
			if (num2 > 8 && remove_from_linked_list(num, val))
			{
				block_store[num]--;
				return true;
			}
			return false;
		}

		public void Move(int from_index, int to_index)
		{
			if (list_heads[to_index] != -1)
			{
				throw new Exception("SmallListSet.MoveTo: list at " + to_index + " is not empty!");
			}
			if (list_heads[from_index] == -1)
			{
				throw new Exception("SmallListSet.MoveTo: list at " + from_index + " is empty!");
			}
			list_heads[to_index] = list_heads[from_index];
			list_heads[from_index] = -1;
		}

		public void Clear(int list_index)
		{
			int num = list_heads[list_index];
			if (num == -1)
			{
				return;
			}
			if (block_store[num] > 8)
			{
				int num2 = block_store[num + 9];
				while (num2 != -1)
				{
					int ptr = num2;
					num2 = linked_store[num2 + 1];
					add_free_link(ptr);
				}
				block_store[num + 9] = -1;
			}
			block_store[num] = 0;
			free_blocks.push_back(num);
			list_heads[list_index] = -1;
		}

		public int Count(int list_index)
		{
			int num = list_heads[list_index];
			if (num != -1)
			{
				return block_store[num];
			}
			return 0;
		}

		public bool Contains(int list_index, int val)
		{
			int num = list_heads[list_index];
			if (num != -1)
			{
				int num2 = block_store[num];
				if (num2 < 8)
				{
					int num3 = num + num2;
					for (int i = num + 1; i <= num3; i++)
					{
						if (block_store[i] == val)
						{
							return true;
						}
					}
				}
				else
				{
					int num4 = num + 8;
					for (int j = num + 1; j <= num4; j++)
					{
						if (block_store[j] == val)
						{
							return true;
						}
					}
					for (int num5 = block_store[num + 9]; num5 != -1; num5 = linked_store[num5 + 1])
					{
						if (linked_store[num5] == val)
						{
							return true;
						}
					}
				}
			}
			return false;
		}

		public int First(int list_index)
		{
			int num = list_heads[list_index];
			return block_store[num + 1];
		}

		public IEnumerable<int> ValueItr(int list_index)
		{
			int block_ptr = list_heads[list_index];
			if (block_ptr == -1)
			{
				yield break;
			}
			int num = block_store[block_ptr];
			int iEnd;
			if (num < 8)
			{
				iEnd = block_ptr + num;
				int i = block_ptr + 1;
				while (i <= iEnd)
				{
					yield return block_store[i];
					int num2 = i + 1;
					i = num2;
				}
				yield break;
			}
			iEnd = block_ptr + 8;
			int i2 = block_ptr + 1;
			while (i2 <= iEnd)
			{
				yield return block_store[i2];
				int num2 = i2 + 1;
				i2 = num2;
			}
			for (int i = block_store[block_ptr + 9]; i != -1; i = linked_store[i + 1])
			{
				yield return linked_store[i];
			}
		}

		public int Find(int list_index, Func<int, bool> findF, int invalidValue = -1)
		{
			int num = list_heads[list_index];
			if (num != -1)
			{
				int num2 = block_store[num];
				if (num2 < 8)
				{
					int num3 = num + num2;
					for (int i = num + 1; i <= num3; i++)
					{
						int num4 = block_store[i];
						if (findF(num4))
						{
							return num4;
						}
					}
				}
				else
				{
					int num5 = num + 8;
					for (int j = num + 1; j <= num5; j++)
					{
						int num6 = block_store[j];
						if (findF(num6))
						{
							return num6;
						}
					}
					for (int num7 = block_store[num + 9]; num7 != -1; num7 = linked_store[num7 + 1])
					{
						int num8 = linked_store[num7];
						if (findF(num8))
						{
							return num8;
						}
					}
				}
			}
			return invalidValue;
		}

		public bool Replace(int list_index, Func<int, bool> findF, int new_value)
		{
			int num = list_heads[list_index];
			if (num != -1)
			{
				int num2 = block_store[num];
				if (num2 < 8)
				{
					int num3 = num + num2;
					for (int i = num + 1; i <= num3; i++)
					{
						int arg = block_store[i];
						if (findF(arg))
						{
							block_store[i] = new_value;
							return true;
						}
					}
				}
				else
				{
					int num4 = num + 8;
					for (int j = num + 1; j <= num4; j++)
					{
						int arg2 = block_store[j];
						if (findF(arg2))
						{
							block_store[j] = new_value;
							return true;
						}
					}
					for (int num5 = block_store[num + 9]; num5 != -1; num5 = linked_store[num5 + 1])
					{
						int arg3 = linked_store[num5];
						if (findF(arg3))
						{
							linked_store[num5] = new_value;
							return true;
						}
					}
				}
			}
			return false;
		}

		protected int allocate_block()
		{
			int size = free_blocks.size;
			if (size > 0)
			{
				int result = free_blocks[size - 1];
				free_blocks.pop_back();
				return result;
			}
			int size2 = block_store.size;
			block_store.insert(-1, size2 + 9);
			block_store[size2] = 0;
			allocated_count++;
			return size2;
		}

		private void add_free_link(int ptr)
		{
			linked_store[ptr + 1] = free_head_ptr;
			free_head_ptr = ptr;
		}

		private bool remove_from_linked_list(int block_ptr, int val)
		{
			int num = block_store[block_ptr + 9];
			int num2 = -1;
			while (num != -1)
			{
				if (linked_store[num] == val)
				{
					int value = linked_store[num + 1];
					if (num2 == -1)
					{
						block_store[block_ptr + 9] = value;
					}
					else
					{
						linked_store[num2 + 1] = value;
					}
					add_free_link(num);
					return true;
				}
				num2 = num;
				num = linked_store[num + 1];
			}
			return false;
		}
	}
	public class Snapping
	{
		public static double SnapToIncrement(double fValue, double fIncrement, double offset = 0.0)
		{
			if (!MathUtil.IsFinite(fValue))
			{
				return 0.0;
			}
			fValue -= offset;
			double num = Math.Sign(fValue);
			fValue = Math.Abs(fValue);
			int num2 = (int)(fValue / fIncrement);
			if (fValue % fIncrement > fIncrement / 2.0)
			{
				num2++;
			}
			return num * (double)num2 * fIncrement + offset;
		}

		public static double SnapToNearbyIncrement(double fValue, double fIncrement, double fTolerance)
		{
			double num = SnapToIncrement(fValue, fIncrement);
			if (Math.Abs(num - fValue) < fTolerance)
			{
				return num;
			}
			return fValue;
		}

		private static double SnapToIncrementSigned(double fValue, double fIncrement, bool low)
		{
			if (!MathUtil.IsFinite(fValue))
			{
				return 0.0;
			}
			double num = Math.Sign(fValue);
			fValue = Math.Abs(fValue);
			int num2 = (int)(fValue / fIncrement);
			if (low && num < 0.0)
			{
				num2++;
			}
			else if (!low && num > 0.0)
			{
				num2++;
			}
			return num * (double)num2 * fIncrement;
		}

		public static double SnapToIncrementLow(double fValue, double fIncrement, double offset = 0.0)
		{
			return SnapToIncrementSigned(fValue - offset, fIncrement, low: true) + offset;
		}

		public static double SnapToIncrementHigh(double fValue, double fIncrement, double offset = 0.0)
		{
			return SnapToIncrementSigned(fValue - offset, fIncrement, low: false) + offset;
		}
	}
	public class SparseList<T> where T : IEquatable<T>
	{
		private T[] dense;

		private Dictionary<int, T> sparse;

		private T zeroValue;

		public T this[int idx]
		{
			get
			{
				if (dense != null)
				{
					return dense[idx];
				}
				if (sparse.TryGetValue(idx, out var value))
				{
					return value;
				}
				return zeroValue;
			}
			set
			{
				if (dense != null)
				{
					dense[idx] = value;
				}
				else
				{
					sparse[idx] = value;
				}
			}
		}

		public SparseList(int MaxIndex, int SubsetCountEst, T ZeroValue)
		{
			zeroValue = ZeroValue;
			bool num = MaxIndex > 0 && MaxIndex < 1024;
			float num2 = ((MaxIndex == 0) ? 0f : ((float)SubsetCountEst / (float)MaxIndex));
			float num3 = 0.1f;
			if (num || num2 > num3)
			{
				dense = new T[MaxIndex];
				for (int i = 0; i < MaxIndex; i++)
				{
					dense[i] = ZeroValue;
				}
			}
			else
			{
				sparse = new Dictionary<int, T>();
			}
		}

		public int Count(Func<T, bool> CountF)
		{
			int num = 0;
			if (dense != null)
			{
				for (int i = 0; i < dense.Length; i++)
				{
					if (CountF(dense[i]))
					{
						num++;
					}
				}
			}
			else
			{
				foreach (KeyValuePair<int, T> item in sparse)
				{
					if (CountF(item.Value))
					{
						num++;
					}
				}
			}
			return num;
		}

		public IEnumerable<KeyValuePair<int, T>> Values()
		{
			if (dense != null)
			{
				int i = 0;
				while (i < dense.Length)
				{
					yield return new KeyValuePair<int, T>(i, dense[i]);
					int num = i + 1;
					i = num;
				}
				yield break;
			}
			foreach (KeyValuePair<int, T> item in sparse)
			{
				yield return item;
			}
		}

		public IEnumerable<KeyValuePair<int, T>> NonZeroValues()
		{
			if (dense != null)
			{
				int i = 0;
				while (i < dense.Length)
				{
					ref readonly T reference = ref dense[i];
					T other = zeroValue;
					if (!reference.Equals(other))
					{
						yield return new KeyValuePair<int, T>(i, dense[i]);
					}
					int num = i + 1;
					i = num;
				}
				yield break;
			}
			foreach (KeyValuePair<int, T> item in sparse)
			{
				yield return item;
			}
		}
	}
