	public abstract class BaseCurve2
	{
		protected double mTMin;

		protected double mTMax;

		public BaseCurve2(double tmin, double tmax)
		{
			mTMin = tmin;
			mTMax = tmax;
		}

		public double GetMinTime()
		{
			return mTMax;
		}

		public double GetMaxTime()
		{
			return mTMax;
		}

		public void SetTimeInterval(double tmin, double tmax)
		{
			if (tmin >= tmax)
			{
				throw new Exception("Curve2.SetTimeInterval: invalid min/max");
			}
			mTMin = tmin;
			mTMax = tmax;
		}

		public abstract Vector2d GetPosition(double t);

		public abstract Vector2d GetFirstDerivative(double t);

		public abstract Vector2d GetSecondDerivative(double t);

		public abstract Vector2d GetThirdDerivative(double t);

		public double GetSpeed(double t)
		{
			return GetFirstDerivative(t).Length;
		}

		private double GetSpeedWithData(double t, object data)
		{
			return (data as BaseCurve2).GetSpeed(t);
		}

		public virtual double GetLength(double t0, double t1)
		{
			if (t0 < mTMin || t0 > mTMax)
			{
				throw new Exception("BaseCurve2.GetLength: min t out of bounds: " + t0);
			}
			if (t1 < mTMin || t1 > mTMax)
			{
				throw new Exception("BaseCurve2.GetLength: max t out of bounds: " + t1);
			}
			if (t0 > t1)
			{
				throw new Exception("BaseCurve2.GetLength: inverted t-range\n " + t0 + " " + t1);
			}
			return Integrate1d.RombergIntegral(8, t0, t1, GetSpeedWithData, this);
		}

		public double GetTotalLength()
		{
			return GetLength(mTMin, mTMax);
		}

		public Vector2d GetTangent(double t)
		{
			return GetFirstDerivative(t).Normalized;
		}

		public Vector2d GetNormal(double t)
		{
			return GetFirstDerivative(t).Normalized.Perp;
		}

		public void GetFrame(double t, ref Vector2d position, ref Vector2d tangent, ref Vector2d normal)
		{
			position = GetPosition(t);
			tangent = GetFirstDerivative(t).Normalized;
			normal = tangent.Perp;
		}

		public double GetCurvature(double t)
		{
			Vector2d firstDerivative = GetFirstDerivative(t);
			Vector2d secondDerivative = GetSecondDerivative(t);
			double lengthSquared = firstDerivative.LengthSquared;
			if (lengthSquared >= 1E-08)
			{
				double num = firstDerivative.DotPerp(secondDerivative);
				double num2 = Math.Pow(lengthSquared, 1.5);
				return num / num2;
			}
			return 0.0;
		}

		public virtual double GetTime(double length, int iterations = 32, double tolerance = 1E-06)
		{
			if (length <= 0.0)
			{
				return mTMin;
			}
			if (length >= GetTotalLength())
			{
				return mTMax;
			}
			double num = length / GetTotalLength();
			double num2 = (1.0 - num) * mTMin + num * mTMax;
			double num3 = mTMin;
			double num4 = mTMax;
			for (int i = 0; i < iterations; i++)
			{
				double num5 = GetLength(mTMin, num2) - length;
				if (Math.Abs(num5) < tolerance)
				{
					return num2;
				}
				double num6 = num2 - num5 / GetSpeed(num2);
				if (num5 > 0.0)
				{
					num4 = num2;
					num2 = ((!(num6 <= num3)) ? num6 : (0.5 * (num4 + num3)));
				}
				else
				{
					num3 = num2;
					num2 = ((!(num6 >= num4)) ? num6 : (0.5 * (num4 + num3)));
				}
			}
			return num2;
		}

		private Vector2d[] SubdivideByTime(int numPoints)
		{
			if (numPoints < 2)
			{
				throw new Exception("BaseCurve2.SubdivideByTime: Subdivision requires at least two points, requested " + numPoints);
			}
			Vector2d[] array = new Vector2d[numPoints];
			double num = (mTMax - mTMin) / (double)(numPoints - 1);
			for (int i = 0; i < numPoints; i++)
			{
				double t = mTMin + num * (double)i;
				array[i] = GetPosition(t);
			}
			return array;
		}

		private Vector2d[] SubdivieByLength(int numPoints)
		{
			if (numPoints < 2)
			{
				throw new Exception("BaseCurve2.SubdivideByTime: Subdivision requires at least two points, requested " + numPoints);
			}
			Vector2d[] array = new Vector2d[numPoints];
			double num = GetTotalLength() / (double)(numPoints - 1);
			for (int i = 0; i < numPoints; i++)
			{
				double length = num * (double)i;
				double time = GetTime(length);
				array[i] = GetPosition(time);
			}
			return array;
		}
	}
	public class BezierCurve2 : BaseCurve2, IParametricCurve2d
	{
		private int mDegree;

		private int mNumCtrlPoints;

		private Vector2d[] mCtrlPoint;

		private Vector2d[] mDer1CtrlPoint;

		private Vector2d[] mDer2CtrlPoint;

		private Vector2d[] mDer3CtrlPoint;

		private DenseMatrix mChoose;

		public int Degree => mDegree;

		public Vector2d[] ControlPoints => mCtrlPoint;

		public bool IsClosed => false;

		public double ParamLength => mTMax - mTMin;

		public bool HasArcLength => true;

		public double ArcLength => GetTotalLength();

		public bool IsTransformable => true;

		public BezierCurve2(int degree, Vector2d[] ctrlPoint, bool bTakeOwnership = false)
			: base(0.0, 1.0)
		{
			if (degree < 2)
			{
				throw new Exception("BezierCurve2() The degree must be three or larger\n");
			}
			mDegree = degree;
			mNumCtrlPoints = mDegree + 1;
			if (bTakeOwnership)
			{
				mCtrlPoint = ctrlPoint;
			}
			else
			{
				mCtrlPoint = new Vector2d[ctrlPoint.Length];
				Array.Copy(ctrlPoint, mCtrlPoint, ctrlPoint.Length);
			}
			mDer1CtrlPoint = new Vector2d[mNumCtrlPoints - 1];
			for (int i = 0; i < mNumCtrlPoints - 1; i++)
			{
				mDer1CtrlPoint[i] = mCtrlPoint[i + 1] - mCtrlPoint[i];
			}
			mDer2CtrlPoint = new Vector2d[mNumCtrlPoints - 2];
			for (int i = 0; i < mNumCtrlPoints - 2; i++)
			{
				mDer2CtrlPoint[i] = mDer1CtrlPoint[i + 1] - mDer1CtrlPoint[i];
			}
			if (degree >= 3)
			{
				mDer3CtrlPoint = new Vector2d[mNumCtrlPoints - 3];
				for (int i = 0; i < mNumCtrlPoints - 3; i++)
				{
					mDer3CtrlPoint[i] = mDer2CtrlPoint[i + 1] - mDer2CtrlPoint[i];
				}
			}
			else
			{
				mDer3CtrlPoint = null;
			}
			mChoose = new DenseMatrix(mNumCtrlPoints, mNumCtrlPoints);
			mChoose[0, 0] = 1.0;
			mChoose[1, 0] = 1.0;
			mChoose[1, 1] = 1.0;
			for (int i = 2; i <= mDegree; i++)
			{
				mChoose[i, 0] = 1.0;
				mChoose[i, i] = 1.0;
				for (int j = 1; j < i; j++)
				{
					mChoose[i, j] = mChoose[i - 1, j - 1] + mChoose[i - 1, j];
				}
			}
		}

		protected BezierCurve2()
			: base(0.0, 1.0)
		{
		}

		public override Vector2d GetPosition(double t)
		{
			double num = 1.0 - t;
			double num2 = t;
			Vector2d vector2d = num * mCtrlPoint[0];
			for (int i = 1; i < mDegree; i++)
			{
				double num3 = mChoose[mDegree, i] * num2;
				vector2d = (vector2d + mCtrlPoint[i] * num3) * num;
				num2 *= t;
			}
			return vector2d + mCtrlPoint[mDegree] * num2;
		}

		public override Vector2d GetFirstDerivative(double t)
		{
			double num = 1.0 - t;
			double num2 = t;
			Vector2d vector2d = num * mDer1CtrlPoint[0];
			int num3 = mDegree - 1;
			for (int i = 1; i < num3; i++)
			{
				double num4 = mChoose[num3, i] * num2;
				vector2d = (vector2d + mDer1CtrlPoint[i] * num4) * num;
				num2 *= t;
			}
			vector2d += mDer1CtrlPoint[num3] * num2;
			return vector2d * mDegree;
		}

		public override Vector2d GetSecondDerivative(double t)
		{
			double num = 1.0 - t;
			double num2 = t;
			Vector2d vector2d = num * mDer2CtrlPoint[0];
			int num3 = mDegree - 2;
			for (int i = 1; i < num3; i++)
			{
				double num4 = mChoose[num3, i] * num2;
				vector2d = (vector2d + mDer2CtrlPoint[i] * num4) * num;
				num2 *= t;
			}
			vector2d += mDer2CtrlPoint[num3] * num2;
			return vector2d * (mDegree * (mDegree - 1));
		}

		public override Vector2d GetThirdDerivative(double t)
		{
			if (mDegree < 3)
			{
				return Vector2d.Zero;
			}
			double num = 1.0 - t;
			double num2 = t;
			Vector2d vector2d = num * mDer3CtrlPoint[0];
			int num3 = mDegree - 3;
			for (int i = 1; i < num3; i++)
			{
				double num4 = mChoose[num3, i] * num2;
				vector2d = (vector2d + mDer3CtrlPoint[i] * num4) * num;
				num2 *= t;
			}
			vector2d += mDer3CtrlPoint[num3] * num2;
			return vector2d * (mDegree * (mDegree - 1) * (mDegree - 2));
		}

		public Vector2d SampleT(double t)
		{
			return GetPosition(t);
		}

		public Vector2d TangentT(double t)
		{
			return GetFirstDerivative(t).Normalized;
		}

		public Vector2d SampleArcLength(double a)
		{
			double time = GetTime(a);
			return GetPosition(time);
		}

		public void Reverse()
		{
			throw new NotSupportedException("NURBSCurve2.Reverse: how to reverse?!?");
		}

		public IParametricCurve2d Clone()
		{
			return new BezierCurve2
			{
				mDegree = mDegree,
				mNumCtrlPoints = mNumCtrlPoints,
				mCtrlPoint = (Vector2d[])mCtrlPoint.Clone(),
				mDer1CtrlPoint = (Vector2d[])mDer1CtrlPoint.Clone(),
				mDer2CtrlPoint = (Vector2d[])mDer2CtrlPoint.Clone(),
				mDer3CtrlPoint = (Vector2d[])mDer3CtrlPoint.Clone(),
				mChoose = new DenseMatrix(mChoose)
			};
		}

		public void Transform(ITransform2 xform)
		{
			for (int i = 0; i < mCtrlPoint.Length; i++)
			{
				mCtrlPoint[i] = xform.TransformP(mCtrlPoint[i]);
			}
			for (int j = 0; j < mNumCtrlPoints - 1; j++)
			{
				mDer1CtrlPoint[j] = mCtrlPoint[j + 1] - mCtrlPoint[j];
			}
			for (int k = 0; k < mNumCtrlPoints - 2; k++)
			{
				mDer2CtrlPoint[k] = mDer1CtrlPoint[k + 1] - mDer1CtrlPoint[k];
			}
			if (mDegree >= 3)
			{
				for (int l = 0; l < mNumCtrlPoints - 3; l++)
				{
					mDer3CtrlPoint[l] = mDer2CtrlPoint[l + 1] - mDer2CtrlPoint[l];
				}
			}
		}
	}
	public class BSplineBasis
	{
		protected int mNumCtrlPoints;

		protected int mDegree;

		protected double[] mKnot;

		protected bool mOpen;

		protected bool mUniform;

		protected double[,] mBD0;

		protected double[,] mBD1;

		protected double[,] mBD2;

		protected double[,] mBD3;

		public int KnotCount => mNumCtrlPoints + mDegree + 1;

		public int InteriorKnotCount => mNumCtrlPoints - mDegree - 1;

		protected BSplineBasis()
		{
		}

		public BSplineBasis(int numCtrlPoints, int degree, bool open)
		{
			mUniform = true;
			int num = Initialize(numCtrlPoints, degree, open);
			double num2 = 1.0 / (double)(mNumCtrlPoints - mDegree);
			if (mOpen)
			{
				int i;
				for (i = 0; i <= mDegree; i++)
				{
					mKnot[i] = 0.0;
				}
				for (; i < mNumCtrlPoints; i++)
				{
					mKnot[i] = (double)(i - mDegree) * num2;
				}
				for (; i < num; i++)
				{
					mKnot[i] = 1.0;
				}
			}
			else
			{
				for (int i = 0; i < num; i++)
				{
					mKnot[i] = (double)(i - mDegree) * num2;
				}
			}
		}

		public BSplineBasis(int numCtrlPoints, int degree, double[] knots, bool bIsInteriorKnots)
		{
			mUniform = false;
			int num = Initialize(numCtrlPoints, degree, open: true);
			if (bIsInteriorKnots)
			{
				if (knots.Length != mNumCtrlPoints - mDegree - 1)
				{
					throw new Exception("BSplineBasis nonuniform constructor: invalid interior knot vector");
				}
				int i;
				for (i = 0; i <= mDegree; i++)
				{
					mKnot[i] = 0.0;
				}
				int num2 = 0;
				while (i < mNumCtrlPoints)
				{
					mKnot[i] = knots[num2];
					i++;
					num2++;
				}
				for (; i < num; i++)
				{
					mKnot[i] = 1.0;
				}
			}
			else
			{
				if (mKnot.Length != knots.Length)
				{
					throw new Exception("BSplineBasis nonuniform constructor: invalid knot vector");
				}
				Array.Copy(knots, mKnot, knots.Length);
			}
		}

		public BSplineBasis Clone()
		{
			return new BSplineBasis
			{
				mNumCtrlPoints = mNumCtrlPoints,
				mDegree = mDegree,
				mKnot = (double[])mKnot.Clone(),
				mOpen = mOpen,
				mUniform = mUniform
			};
		}

		public int GetNumCtrlPoints()
		{
			return mNumCtrlPoints;
		}

		public int GetDegree()
		{
			return mDegree;
		}

		public bool IsOpen()
		{
			return mOpen;
		}

		public bool IsUniform()
		{
			return mUniform;
		}

		public void SetInteriorKnot(int j, double value)
		{
			if (!mUniform)
			{
				int num = j + mDegree + 1;
				if (mDegree + 1 <= num && num <= mNumCtrlPoints)
				{
					mKnot[num] = value;
					return;
				}
				throw new Exception("BSplineBasis.SetKnot: index out of range: " + j);
			}
			throw new Exception("BSplineBasis.SetKnot: knots cannot be set for uniform splines");
		}

		public double GetInteriorKnot(int j)
		{
			int num = j + mDegree + 1;
			if (mDegree + 1 <= num && num <= mNumCtrlPoints)
			{
				return mKnot[num];
			}
			throw new Exception("BSplineBasis.GetKnot: index out of range: " + j);
		}

		public void SetKnot(int j, double value)
		{
			mKnot[j] = value;
		}

		public double GetKnot(int j)
		{
			return mKnot[j];
		}

		public double GetD0(int i)
		{
			return mBD0[mDegree, i];
		}

		public double GetD1(int i)
		{
			return mBD1[mDegree, i];
		}

		public double GetD2(int i)
		{
			return mBD2[mDegree, i];
		}

		public double GetD3(int i)
		{
			return mBD3[mDegree, i];
		}

		public void Compute(double t, int order, ref int minIndex, ref int maxIndex)
		{
			if (order > 3)
			{
				throw new Exception("BSplineBasis.Compute: cannot compute order " + order);
			}
			if (order >= 1)
			{
				if (mBD1 == null)
				{
					mBD1 = Allocate();
				}
				if (order >= 2)
				{
					if (mBD2 == null)
					{
						mBD2 = Allocate();
					}
					if (order >= 3 && mBD3 == null)
					{
						mBD3 = Allocate();
					}
				}
			}
			int key = GetKey(ref t);
			mBD0[0, key] = 1.0;
			if (order >= 1)
			{
				mBD1[0, key] = 0.0;
				if (order >= 2)
				{
					mBD2[0, key] = 0.0;
					if (order >= 3)
					{
						mBD3[0, key] = 0.0;
					}
				}
			}
			double num = t - mKnot[key];
			double num2 = mKnot[key + 1] - t;
			for (int i = 1; i <= mDegree; i++)
			{
				double num3 = 1.0 / (mKnot[key + i] - mKnot[key]);
				double num4 = 1.0 / (mKnot[key + 1] - mKnot[key - i + 1]);
				if (mKnot[key + i] == mKnot[key])
				{
					num3 = 0.0;
				}
				if (mKnot[key + 1] == mKnot[key - i + 1])
				{
					num4 = 0.0;
				}
				mBD0[i, key] = num * mBD0[i - 1, key] * num3;
				mBD0[i, key - i] = num2 * mBD0[i - 1, key - i + 1] * num4;
				if (order < 1)
				{
					continue;
				}
				mBD1[i, key] = (num * mBD1[i - 1, key] + mBD0[i - 1, key]) * num3;
				mBD1[i, key - i] = (num2 * mBD1[i - 1, key - i + 1] - mBD0[i - 1, key - i + 1]) * num4;
				if (order >= 2)
				{
					mBD2[i, key] = (num * mBD2[i - 1, key] + 2.0 * mBD1[i - 1, key]) * num3;
					mBD2[i, key - i] = (num2 * mBD2[i - 1, key - i + 1] - 2.0 * mBD1[i - 1, key - i + 1]) * num4;
					if (order >= 3)
					{
						mBD3[i, key] = (num * mBD3[i - 1, key] + 3.0 * mBD2[i - 1, key]) * num3;
						mBD3[i, key - i] = (num2 * mBD3[i - 1, key - i + 1] - 3.0 * mBD2[i - 1, key - i + 1]) * num4;
					}
				}
			}
			for (int i = 2; i <= mDegree; i++)
			{
				for (int j = key - i + 1; j < key; j++)
				{
					num = t - mKnot[j];
					num2 = mKnot[j + i + 1] - t;
					double num3 = 1.0 / (mKnot[j + i] - mKnot[j]);
					double num4 = 1.0 / (mKnot[j + i + 1] - mKnot[j + 1]);
					if (mKnot[j + i] == mKnot[j])
					{
						num3 = 0.0;
					}
					if (mKnot[j + i + 1] == mKnot[j + 1])
					{
						num4 = 0.0;
					}
					mBD0[i, j] = num * mBD0[i - 1, j] * num3 + num2 * mBD0[i - 1, j + 1] * num4;
					if (order < 1)
					{
						continue;
					}
					mBD1[i, j] = (num * mBD1[i - 1, j] + mBD0[i - 1, j]) * num3 + (num2 * mBD1[i - 1, j + 1] - mBD0[i - 1, j + 1]) * num4;
					if (order >= 2)
					{
						mBD2[i, j] = (num * mBD2[i - 1, j] + 2.0 * mBD1[i - 1, j]) * num3 + (num2 * mBD2[i - 1, j + 1] - 2.0 * mBD1[i - 1, j + 1]) * num4;
						if (order >= 3)
						{
							mBD3[i, j] = (num * mBD3[i - 1, j] + 3.0 * mBD2[i - 1, j]) * num3 + (num2 * mBD3[i - 1, j + 1] - 3.0 * mBD2[i - 1, j + 1]) * num4;
						}
					}
				}
			}
			minIndex = key - mDegree;
			maxIndex = key;
		}

		protected int Initialize(int numCtrlPoints, int degree, bool open)
		{
			if (numCtrlPoints < 2)
			{
				throw new Exception("BSplineBasis.Initialize: only received " + numCtrlPoints + " control points!");
			}
			if (degree < 1 || degree > numCtrlPoints - 1)
			{
				throw new Exception("BSplineBasis.Initialize: invalid degree " + degree);
			}
			mNumCtrlPoints = numCtrlPoints;
			mDegree = degree;
			mOpen = open;
			int num = mNumCtrlPoints + mDegree + 1;
			mKnot = new double[num];
			mBD0 = Allocate();
			mBD1 = null;
			mBD2 = null;
			mBD3 = null;
			return num;
		}

		protected double[,] Allocate()
		{
			int num = mDegree + 1;
			int num2 = mNumCtrlPoints + mDegree;
			double[,] array = new double[num, num2];
			for (int i = 0; i < num; i++)
			{
				for (int j = 0; j < num2; j++)
				{
					array[i, j] = 0.0;
				}
			}
			return array;
		}

		protected int GetKey(ref double t)
		{
			if (mOpen)
			{
				if (t <= 0.0)
				{
					t = 0.0;
					return mDegree;
				}
				if (t >= 1.0)
				{
					t = 1.0;
					return mNumCtrlPoints - 1;
				}
			}
			else if (t < 0.0 || t >= 1.0)
			{
				t -= Math.Floor(t);
			}
			if (mUniform)
			{
				return mDegree + (int)((double)(mNumCtrlPoints - mDegree) * t);
			}
			int i;
			for (i = mDegree + 1; i <= mNumCtrlPoints && !(t < mKnot[i]); i++)
			{
			}
			return i - 1;
		}
	}
	public class Circle2d : IParametricCurve2d
	{
		public Vector2d Center;

		public double Radius;

		public bool IsReversed;

		public double Curvature => 1.0 / Radius;

		public double SignedCurvature
		{
			get
			{
				if (!IsReversed)
				{
					return 1.0 / Radius;
				}
				return -1.0 / Radius;
			}
		}

		public bool IsClosed => true;

		public bool IsTransformable => true;

		public double ParamLength => 1.0;

		public bool HasArcLength => true;

		public double ArcLength => Math.PI * 2.0 * Radius;

		public double Circumference
		{
			get
			{
				return Math.PI * 2.0 * Radius;
			}
			set
			{
				Radius = value / (Math.PI * 2.0);
			}
		}

		public double Diameter
		{
			get
			{
				return 2.0 * Radius;
			}
			set
			{
				Radius = value / 2.0;
			}
		}

		public double Area
		{
			get
			{
				return Math.PI * Radius * Radius;
			}
			set
			{
				Radius = Math.Sqrt(value / Math.PI);
			}
		}

		public AxisAlignedBox2d Bounds => new AxisAlignedBox2d(Center, Radius, Radius);

		public Circle2d(double radius)
		{
			IsReversed = false;
			Center = Vector2d.Zero;
			Radius = radius;
		}

		public Circle2d(Vector2d center, double radius)
		{
			IsReversed = false;
			Center = center;
			Radius = radius;
		}

		public void Reverse()
		{
			IsReversed = !IsReversed;
		}

		public IParametricCurve2d Clone()
		{
			return new Circle2d(Center, Radius)
			{
				IsReversed = IsReversed
			};
		}

		public void Transform(ITransform2 xform)
		{
			Center = xform.TransformP(Center);
			Radius = xform.TransformScalar(Radius);
		}

		public Vector2d SampleDeg(double degrees)
		{
			double num = degrees * (Math.PI / 180.0);
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return new Vector2d(Center.x + Radius * num2, Center.y + Radius * num3);
		}

		public Vector2d SampleRad(double radians)
		{
			double num = Math.Cos(radians);
			double num2 = Math.Sin(radians);
			return new Vector2d(Center.x + Radius * num, Center.y + Radius * num2);
		}

		public Vector2d SampleT(double t)
		{
			double num = (IsReversed ? ((0.0 - t) * (Math.PI * 2.0)) : (t * (Math.PI * 2.0)));
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return new Vector2d(Center.x + Radius * num2, Center.y + Radius * num3);
		}

		public Vector2d TangentT(double t)
		{
			double num = (IsReversed ? ((0.0 - t) * (Math.PI * 2.0)) : (t * (Math.PI * 2.0)));
			Vector2d vector2d = new Vector2d(0.0 - Math.Sin(num), Math.Cos(num));
			if (IsReversed)
			{
				vector2d = -vector2d;
			}
			vector2d.Normalize();
			return vector2d;
		}

		public Vector2d SampleArcLength(double a)
		{
			double num = a / ArcLength;
			double num2 = (IsReversed ? ((0.0 - num) * (Math.PI * 2.0)) : (num * (Math.PI * 2.0)));
			double num3 = Math.Cos(num2);
			double num4 = Math.Sin(num2);
			return new Vector2d(Center.x + Radius * num3, Center.y + Radius * num4);
		}

		public bool Contains(Vector2d p)
		{
			return Center.DistanceSquared(p) <= Radius * Radius;
		}

		public double SignedDistance(Vector2d pt)
		{
			return Center.Distance(pt) - Radius;
		}

		public double Distance(Vector2d pt)
		{
			return Math.Abs(Center.Distance(pt) - Radius);
		}

		public static double RadiusArea(double r)
		{
			return Math.PI * r * r;
		}

		public static double RadiusCircumference(double r)
		{
			return Math.PI * 2.0 * r;
		}

		public static double BoundingPolygonRadius(double r, int n)
		{
			double d = Math.PI * 2.0 / (double)n / 2.0;
			return r / Math.Cos(d);
		}
	}
	public abstract class CurveGenerator
	{
		public VectorArray3d vertices;

		public bool closed;

		public abstract void Generate();

		public void Make(DCurve3 c)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				c.AppendVertex(vertices[i]);
			}
			c.Closed = closed;
		}
	}
	public class LineGenerator : CurveGenerator
	{
		public Vector3d Start = Vector3d.Zero;

		public Vector3d End = Vector3d.AxisX;

		public int Subdivisions = -1;

		public double StepSize;

		public override void Generate()
		{
			double length = (Start - End).Length;
			int num = 10;
			if (Subdivisions > 0)
			{
				num = Subdivisions;
			}
			else if (StepSize > 0.0)
			{
				num = MathUtil.Clamp((int)(length / StepSize), 2, 10000);
			}
			vertices = new VectorArray3d(num + 1);
			for (int i = 0; i < num; i++)
			{
				double num2 = (double)i / (double)num;
				Vector3d value = (1.0 - num2) * Start + num2 * End;
				vertices[i] = value;
			}
			vertices[num] = End;
			closed = false;
		}
	}
	public class CurveResampler
	{
		private double[] lengths;

		public List<Vector3d> SplitResample(ISampledCurve3d curve, double fMaxEdgeLen)
		{
			double num = fMaxEdgeLen * fMaxEdgeLen;
			int vertexCount = curve.VertexCount;
			int num2 = (curve.Closed ? (vertexCount + 1) : vertexCount);
			if (lengths == null || lengths.Length < num2)
			{
				lengths = new double[num2];
			}
			bool flag = false;
			for (int i = 0; i < num2; i++)
			{
				lengths[i] = curve.GetVertex(i).DistanceSquared(curve.GetVertex((i + 1) % vertexCount));
				if (lengths[i] > num)
				{
					flag = true;
				}
			}
			if (!flag)
			{
				return null;
			}
			List<Vector3d> list = new List<Vector3d>();
			Vector3d vector3d = curve.GetVertex(0);
			list.Add(vector3d);
			for (int j = 0; j < num2 - 1; j++)
			{
				Vector3d vertex = curve.GetVertex((j + 1) % vertexCount);
				if (lengths[j] > num)
				{
					int num3 = (int)(Math.Sqrt(lengths[j]) / fMaxEdgeLen) + 1;
					for (int k = 1; k < num3; k++)
					{
						double t = (double)k / (double)num3;
						Vector3d item = Vector3d.Lerp(vector3d, vertex, t);
						list.Add(item);
					}
				}
				list.Add(vertex);
				vector3d = vertex;
			}
			return list;
		}

		public List<Vector3d> SplitCollapseResample(ISampledCurve3d curve, double fMaxEdgeLen, double fMinEdgeLen)
		{
			double num = fMaxEdgeLen * fMaxEdgeLen;
			double num2 = fMinEdgeLen * fMinEdgeLen;
			int vertexCount = curve.VertexCount;
			int num3 = (curve.Closed ? (vertexCount + 1) : vertexCount);
			if (lengths == null || lengths.Length < num3)
			{
				lengths = new double[num3];
			}
			bool flag = false;
			bool flag2 = false;
			for (int i = 0; i < num3 - 1; i++)
			{
				lengths[i] = curve.GetVertex(i).DistanceSquared(curve.GetVertex((i + 1) % vertexCount));
				if (lengths[i] > num)
				{
					flag = true;
				}
				else if (lengths[i] < num2)
				{
					flag2 = true;
				}
			}
			if (!flag && !flag2)
			{
				return null;
			}
			List<Vector3d> list = new List<Vector3d>();
			Vector3d vector3d = curve.GetVertex(0);
			list.Add(vector3d);
			double num4 = 0.0;
			for (int j = 0; j < num3 - 1; j++)
			{
				Vector3d vertex = curve.GetVertex((j + 1) % vertexCount);
				if (lengths[j] < num2)
				{
					num4 += Math.Sqrt(lengths[j]);
					if (num4 > fMinEdgeLen)
					{
						num4 = 0.0;
						list.Add(vertex);
					}
					vector3d = vertex;
					continue;
				}
				if (num4 > 0.0)
				{
					list.Add(vector3d);
					num4 = 0.0;
				}
				if (lengths[j] > num)
				{
					int num5 = (int)(Math.Sqrt(lengths[j]) / fMaxEdgeLen) + 1;
					for (int k = 1; k < num5; k++)
					{
						double t = (double)k / (double)num5;
						Vector3d item = Vector3d.Lerp(vector3d, vertex, t);
						list.Add(item);
					}
				}
				list.Add(vertex);
				vector3d = vertex;
			}
			return list;
		}
	}
	public static class CurveSampler2
	{
		public static VectorArray2d AutoSample(IParametricCurve2d curve, double fSpacingLength, double fSpacingT)
		{
			if (curve is ParametricCurveSequence2)
			{
				return AutoSample(curve as ParametricCurveSequence2, fSpacingLength, fSpacingT);
			}
			if (curve.HasArcLength)
			{
				if (curve is NURBSCurve2)
				{
					return SampleNURBSHybrid(curve as NURBSCurve2, fSpacingLength);
				}
				return SampleArcLen(curve, fSpacingLength);
			}
			return SampleT(curve, fSpacingT);
		}

		public static VectorArray2d SampleT(IParametricCurve2d curve, int N)
		{
			double paramLength = curve.ParamLength;
			VectorArray2d vectorArray2d = new VectorArray2d(N);
			double num = (curve.IsClosed ? ((double)N) : ((double)(N - 1)));
			for (int i = 0; i < N; i++)
			{
				double num2 = (double)i / num;
				vectorArray2d[i] = curve.SampleT(num2 * paramLength);
			}
			return vectorArray2d;
		}

		public static VectorArray2d SampleTRange(IParametricCurve2d curve, int N, double t0, double t1)
		{
			VectorArray2d vectorArray2d = new VectorArray2d(N);
			for (int i = 0; i < N; i++)
			{
				double num = (double)i / (double)(N - 1);
				double t2 = (1.0 - num) * t0 + num * t1;
				vectorArray2d[i] = curve.SampleT(t2);
			}
			return vectorArray2d;
		}

		public static VectorArray2d SampleT(IParametricCurve2d curve, double fSpacing)
		{
			double paramLength = curve.ParamLength;
			int num = Math.Max((int)(paramLength / fSpacing) + 1, 2);
			VectorArray2d vectorArray2d = new VectorArray2d(num);
			for (int i = 0; i < num; i++)
			{
				double num2 = (double)i / (double)(num - 1);
				vectorArray2d[i] = curve.SampleT(num2 * paramLength);
			}
			return vectorArray2d;
		}

		public static VectorArray2d SampleArcLen(IParametricCurve2d curve, double fSpacing)
		{
			if (!curve.HasArcLength)
			{
				throw new InvalidOperationException("CurveSampler2.SampleArcLen: curve does not support arc length sampling!");
			}
			double arcLength = curve.ArcLength;
			if (arcLength < 1E-08)
			{
				return new VectorArray2d(2)
				{
					[0] = curve.SampleArcLength(0.0),
					[1] = curve.SampleArcLength(1.0)
				};
			}
			int num = Math.Max((int)(arcLength / fSpacing) + 1, 2);
			VectorArray2d vectorArray2d = new VectorArray2d(num);
			for (int i = 0; i < num; i++)
			{
				double num2 = (double)i / (double)(num - 1);
				vectorArray2d[i] = curve.SampleArcLength(num2 * arcLength);
			}
			return vectorArray2d;
		}

		public static VectorArray2d SampleNURBSHybrid(NURBSCurve2 curve, double fSpacing)
		{
			List<double> paramIntervals = curve.GetParamIntervals();
			int num = paramIntervals.Count - 1;
			VectorArray2d[] array = new VectorArray2d[num];
			int num2 = 0;
			for (int i = 0; i < num; i++)
			{
				double num3 = paramIntervals[i];
				double num4 = paramIntervals[i + 1];
				int num5 = Math.Max((int)(curve.GetLength(num3, num4) / fSpacing) + 1, 2);
				double num6 = 1.0 / (double)num5;
				if (!curve.IsClosed && i == num - 1)
				{
					num5++;
					num6 = 1.0 / (double)(num5 - 1);
				}
				VectorArray2d vectorArray2d = new VectorArray2d(num5);
				for (int j = 0; j < num5; j++)
				{
					double num7 = (double)j * num6;
					double t = (1.0 - num7) * num3 + num7 * num4;
					vectorArray2d[j] = curve.SampleT(t);
				}
				array[i] = vectorArray2d;
				num2 += num5;
			}
			VectorArray2d vectorArray2d2 = new VectorArray2d(num2);
			int num8 = 0;
			for (int k = 0; k < num; k++)
			{
				vectorArray2d2.Set(num8, array[k].Count, array[k]);
				num8 += array[k].Count;
			}
			return vectorArray2d2;
		}

		public static VectorArray2d AutoSample(ParametricCurveSequence2 curves, double fSpacingLength, double fSpacingT)
		{
			int count = curves.Count;
			bool isClosed = curves.IsClosed;
			VectorArray2d[] array = new VectorArray2d[count];
			int num = 0;
			int num2 = 0;
			foreach (IParametricCurve2d curf in curves.Curves)
			{
				array[num] = AutoSample(curf, fSpacingLength, fSpacingT);
				num2 += array[num].Count;
				num++;
			}
			int num3 = (isClosed ? count : (count - 1));
			num2 -= num3;
			VectorArray2d vectorArray2d = new VectorArray2d(num2);
			int num4 = 0;
			for (int i = 0; i < count; i++)
			{
				VectorArray2d vectorArray2d2 = array[i];
				int num5 = ((isClosed || i < count - 1) ? (vectorArray2d2.Count - 1) : vectorArray2d2.Count);
				vectorArray2d.Set(num4, num5, vectorArray2d2);
				num4 += num5;
			}
			return vectorArray2d;
		}
	}
	public class CurveUtils
	{
		public static Vector3d GetTangent(List<Vector3d> vertices, int i, bool bLoop = false)
		{
			if (bLoop)
			{
				int count = vertices.Count;
				if (i == 0)
				{
					return (vertices[1] - vertices[count - 1]).Normalized;
				}
				return (vertices[(i + 1) % count] - vertices[i - 1]).Normalized;
			}
			if (i == 0)
			{
				return (vertices[1] - vertices[0]).Normalized;
			}
			if (i == vertices.Count - 1)
			{
				return (vertices[vertices.Count - 1] - vertices[vertices.Count - 2]).Normalized;
			}
			return (vertices[i + 1] - vertices[i - 1]).Normalized;
		}

		public static double ArcLength(List<Vector3d> vertices, bool bLoop = false)
		{
			double num = 0.0;
			int count = vertices.Count;
			for (int i = 1; i < count; i++)
			{
				num += vertices[i].Distance(vertices[i - 1]);
			}
			if (bLoop)
			{
				num += vertices[count - 1].Distance(vertices[0]);
			}
			return num;
		}

		public static double ArcLength(Vector3d[] vertices, bool bLoop = false)
		{
			double num = 0.0;
			for (int i = 1; i < vertices.Length; i++)
			{
				num += vertices[i].Distance(vertices[i - 1]);
			}
			if (bLoop)
			{
				num += vertices[^1].Distance(vertices[0]);
			}
			return num;
		}

		public static double ArcLength(IEnumerable<Vector3d> vertices)
		{
			double num = 0.0;
			Vector3d vector3d = Vector3f.Zero;
			int num2 = 0;
			foreach (Vector3d vertex in vertices)
			{
				if (num2++ > 0)
				{
					num += (vertex - vector3d).Length;
				}
				vector3d = vertex;
			}
			return num;
		}

		public static int FindNearestIndex(ISampledCurve3d c, Vector3d v)
		{
			int result = -1;
			double num = double.MaxValue;
			int vertexCount = c.VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				double lengthSquared = (c.GetVertex(i) - v).LengthSquared;
				if (lengthSquared < num)
				{
					num = lengthSquared;
					result = i;
				}
			}
			return result;
		}

		public static bool FindClosestRayIntersection(ISampledCurve3d c, double segRadius, Ray3d ray, out double minRayT)
		{
			minRayT = double.MaxValue;
			int num = -1;
			int segmentCount = c.SegmentCount;
			for (int i = 0; i < segmentCount; i++)
			{
				Segment3d segment = c.GetSegment(i);
				if (RayIntersection.SphereSigned(ref ray.Origin, ref ray.Direction, ref segment.Center, segment.Extent + segRadius, out var _) && DistRay3Segment3.SquaredDistance(ref ray, ref segment, out var rayT, out var _) < segRadius * segRadius && rayT < minRayT)
				{
					minRayT = rayT;
					num = i;
				}
			}
			return num >= 0;
		}

		public static void InPlaceSmooth(IList<Vector3d> vertices, double alpha, int nIterations, bool bClosed)
		{
			InPlaceSmooth(vertices, 0, vertices.Count, alpha, nIterations, bClosed);
		}

		public static void InPlaceSmooth(IList<Vector3d> vertices, int iStart, int iEnd, double alpha, int nIterations, bool bClosed)
		{
			int count = vertices.Count;
			if (bClosed)
			{
				for (int i = 0; i < nIterations; i++)
				{
					for (int j = iStart; j < iEnd; j++)
					{
						int index = j % count;
						int index2 = ((j == 0) ? (count - 1) : (j - 1));
						int index3 = (j + 1) % count;
						Vector3d vector3d = vertices[index2];
						Vector3d vector3d2 = vertices[index3];
						Vector3d vector3d3 = (vector3d + vector3d2) * 0.5;
						vertices[index] = (1.0 - alpha) * vertices[index] + alpha * vector3d3;
					}
				}
				return;
			}
			for (int k = 0; k < nIterations; k++)
			{
				for (int l = iStart; l <= iEnd; l++)
				{
					if (l != 0 && l < count - 1)
					{
						Vector3d vector3d4 = vertices[l - 1];
						Vector3d vector3d5 = vertices[l + 1];
						Vector3d vector3d6 = (vector3d4 + vector3d5) * 0.5;
						vertices[l] = (1.0 - alpha) * vertices[l] + alpha * vector3d6;
					}
				}
			}
		}

		public static void IterativeSmooth(IList<Vector3d> vertices, double alpha, int nIterations, bool bClosed)
		{
			IterativeSmooth(vertices, 0, vertices.Count, alpha, nIterations, bClosed);
		}

		public static void IterativeSmooth(IList<Vector3d> vertices, int iStart, int iEnd, double alpha, int nIterations, bool bClosed, Vector3d[] buffer = null)
		{
			int count = vertices.Count;
			if (buffer == null || buffer.Length < count)
			{
				buffer = new Vector3d[count];
			}
			if (bClosed)
			{
				for (int i = 0; i < nIterations; i++)
				{
					for (int j = iStart; j < iEnd; j++)
					{
						int num = j % count;
						int index = ((j == 0) ? (count - 1) : (j - 1));
						int index2 = (j + 1) % count;
						Vector3d vector3d = vertices[index];
						Vector3d vector3d2 = vertices[index2];
						Vector3d vector3d3 = (vector3d + vector3d2) * 0.5;
						buffer[num] = (1.0 - alpha) * vertices[num] + alpha * vector3d3;
					}
					for (int k = iStart; k < iEnd; k++)
					{
						int num2 = k % count;
						vertices[num2] = buffer[num2];
					}
				}
				return;
			}
			for (int l = 0; l < nIterations; l++)
			{
				for (int m = iStart; m <= iEnd; m++)
				{
					if (m != 0 && m < count - 1)
					{
						Vector3d vector3d4 = vertices[m - 1];
						Vector3d vector3d5 = vertices[m + 1];
						Vector3d vector3d6 = (vector3d4 + vector3d5) * 0.5;
						buffer[m] = (1.0 - alpha) * vertices[m] + alpha * vector3d6;
					}
				}
				for (int n = iStart; n < iEnd; n++)
				{
					int num3 = n % count;
					vertices[num3] = buffer[num3];
				}
			}
		}
	}
	public class IWrappedCurve3d : ISampledCurve3d
	{
		public IList<Vector3d> VertexList;

		public bool Closed { get; set; }

		public int VertexCount
		{
			get
			{
				if (VertexList != null)
				{
					return VertexList.Count;
				}
				return 0;
			}
		}

		public int SegmentCount
		{
			get
			{
				if (!Closed)
				{
					return VertexCount - 1;
				}
				return VertexCount;
			}
		}

		public IEnumerable<Vector3d> Vertices => VertexList;

		public Vector3d GetVertex(int i)
		{
			return VertexList[i];
		}

		public Segment3d GetSegment(int iSegment)
		{
			if (!Closed)
			{
				return new Segment3d(VertexList[iSegment], VertexList[iSegment + 1]);
			}
			return new Segment3d(VertexList[iSegment], VertexList[(iSegment + 1) % VertexList.Count]);
		}
	}
	public static class CurveUtils2
	{
		public static IParametricCurve2d Convert(Polygon2d poly)
		{
			ParametricCurveSequence2 parametricCurveSequence = new ParametricCurveSequence2();
			int vertexCount = poly.VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				parametricCurveSequence.Append(new Segment2d(poly[i], poly[(i + 1) % vertexCount]));
			}
			parametricCurveSequence.IsClosed = true;
			return parametricCurveSequence;
		}

		public static double SampledDistance(IParametricCurve2d c, Vector2d point, int N = 100)
		{
			double paramLength = c.ParamLength;
			double num = double.MaxValue;
			for (int i = 0; i <= N; i++)
			{
				double num2 = (double)i / (double)N;
				num2 *= paramLength;
				double num3 = c.SampleT(num2).DistanceSquared(point);
				if (num3 < num)
				{
					num = num3;
				}
			}
			return Math.Sqrt(num);
		}

		public static IEnumerable<IParametricCurve2d> LeafCurvesIteration(IParametricCurve2d c)
		{
			if (c is IMultiCurve2d)
			{
				IMultiCurve2d multiCurve2d = c as IMultiCurve2d;
				foreach (IParametricCurve2d curf in multiCurve2d.Curves)
				{
					foreach (IParametricCurve2d item in LeafCurvesIteration(curf))
					{
						yield return item;
					}
				}
			}
			else
			{
				yield return c;
			}
		}

		public static List<IParametricCurve2d> Flatten(List<IParametricCurve2d> curves)
		{
			List<IParametricCurve2d> list = new List<IParametricCurve2d>();
			foreach (IParametricCurve2d curf in curves)
			{
				foreach (IParametricCurve2d item in LeafCurvesIteration(curf))
				{
					list.Add(item);
				}
			}
			return list;
		}

		public static List<IParametricCurve2d> Flatten(IParametricCurve2d curve)
		{
			return new List<IParametricCurve2d>(LeafCurvesIteration(curve));
		}

		public static Vector2d GetMaxOriginDistances(IEnumerable<Vector2d> vertices)
		{
			Vector2d zero = Vector2d.Zero;
			foreach (Vector2d vertex in vertices)
			{
				double num = Math.Abs(vertex.x);
				if (num > zero.x)
				{
					zero.x = num;
				}
				double num2 = Math.Abs(vertex.y);
				if (num2 > zero.y)
				{
					zero.y = num2;
				}
			}
			return zero;
		}

		public static int FindNearestVertex(Vector2d pt, IEnumerable<Vector2d> vertices)
		{
			int num = 0;
			int result = -1;
			double num2 = double.MaxValue;
			foreach (Vector2d vertex in vertices)
			{
				double num3 = vertex.DistanceSquared(pt);
				if (num3 < num2)
				{
					num2 = num3;
					result = num;
				}
				num++;
			}
			return result;
		}

		public static Vector2d CentroidVtx(IEnumerable<Vector2d> vertices)
		{
			Vector2d zero = Vector2d.Zero;
			int num = 0;
			foreach (Vector2d vertex in vertices)
			{
				zero += vertex;
				num++;
			}
			if (num > 1)
			{
				zero /= (double)num;
			}
			return zero;
		}

		public static void LaplacianSmooth(IList<Vector2d> vertices, double alpha, int iterations, bool is_loop, bool in_place = false)
		{
			int count = vertices.Count;
			Vector2d[] array = null;
			if (!in_place)
			{
				array = new Vector2d[count];
			}
			IList<Vector2d> list2;
			if (!in_place)
			{
				IList<Vector2d> list = array;
				list2 = list;
			}
			else
			{
				list2 = vertices;
			}
			IList<Vector2d> list3 = list2;
			double num = 1.0 - alpha;
			for (int i = 0; i < iterations; i++)
			{
				if (is_loop)
				{
					for (int j = 0; j < count; j++)
					{
						Vector2d vector2d = (vertices[(j + count - 1) % count] + vertices[(j + 1) % count]) * 0.5;
						list3[j] = num * vertices[j] + alpha * vector2d;
					}
				}
				else
				{
					list3[0] = vertices[0];
					list3[count - 1] = vertices[count - 1];
					for (int k = 1; k < count - 1; k++)
					{
						Vector2d vector2d2 = (vertices[k - 1] + vertices[k + 1]) * 0.5;
						list3[k] = num * vertices[k] + alpha * vector2d2;
					}
				}
				if (!in_place)
				{
					for (int l = 0; l < count; l++)
					{
						vertices[l] = list3[l];
					}
				}
			}
		}

		public static void LaplacianSmoothConstrained(Polygon2d poly, double alpha, int iterations, double max_dist, bool bAllowShrink, bool bAllowGrow, bool bPerVertexDistances = true)
		{
			Polygon2d polygon2d = new Polygon2d(poly);
			int vertexCount = poly.VertexCount;
			Vector2d[] array = new Vector2d[poly.VertexCount];
			double num = max_dist * max_dist;
			double num2 = 1.0 - alpha;
			for (int i = 0; i < iterations; i++)
			{
				for (int j = 0; j < vertexCount; j++)
				{
					Vector2d vector2d = poly[j];
					Vector2d vector2d2 = (poly[(j + vertexCount - 1) % vertexCount] + poly[(j + 1) % vertexCount]) * 0.5;
					bool flag = true;
					if (!bAllowShrink || !bAllowGrow)
					{
						flag = ((!polygon2d.Contains(vector2d2)) ? bAllowGrow : bAllowShrink);
					}
					if (flag)
					{
						Vector2d vector2d3 = num2 * vector2d + alpha * vector2d2;
						if (bPerVertexDistances)
						{
							while (polygon2d[j].DistanceSquared(vector2d3) > num)
							{
								vector2d3 = (vector2d3 + vector2d) * 0.5;
							}
						}
						else
						{
							while (polygon2d.DistanceSquared(vector2d3) > num)
							{
								vector2d3 = (vector2d3 + vector2d) * 0.5;
							}
						}
						array[j] = vector2d3;
					}
					else
					{
						array[j] = vector2d;
					}
				}
				for (int k = 0; k < vertexCount; k++)
				{
					poly[k] = array[k];
				}
			}
		}

		public static void LaplacianSmoothConstrained(GeneralPolygon2d solid, double alpha, int iterations, double max_dist, bool bAllowShrink, bool bAllowGrow)
		{
			LaplacianSmoothConstrained(solid.Outer, alpha, iterations, max_dist, bAllowShrink, bAllowGrow);
			foreach (Polygon2d hole in solid.Holes)
			{
				LaplacianSmoothConstrained(hole, alpha, iterations, max_dist, bAllowShrink, bAllowGrow);
			}
		}

		public static List<T> Filter<T>(List<T> objects, Func<T, bool> keepF)
		{
			List<T> list = new List<T>(objects.Count);
			foreach (T @object in objects)
			{
				if (keepF(@object))
				{
					list.Add(@object);
				}
			}
			return list;
		}

		public static void Split<T>(List<T> objects, out List<T> set1, out List<T> set2, Func<T, bool> splitF)
		{
			set1 = new List<T>();
			set2 = new List<T>();
			foreach (T @object in objects)
			{
				if (splitF(@object))
				{
					set1.Add(@object);
				}
				else
				{
					set2.Add(@object);
				}
			}
		}

		public static Polygon2d SplitToTargetLength(Polygon2d poly, double length)
		{
			Polygon2d polygon2d = new Polygon2d();
			polygon2d.AppendVertex(poly[0]);
			for (int i = 0; i < poly.VertexCount; i++)
			{
				int key = (i + 1) % poly.VertexCount;
				double num = poly[i].Distance(poly[key]);
				if (num < length)
				{
					polygon2d.AppendVertex(poly[key]);
					continue;
				}
				int num2 = (int)Math.Ceiling(num / length);
				for (int j = 1; j < num2; j++)
				{
					double num3 = (double)j / (double)num2;
					Vector2d v = (1.0 - num3) * poly[i] + num3 * poly[key];
					polygon2d.AppendVertex(v);
				}
				if (i < poly.VertexCount - 1)
				{
					polygon2d.AppendVertex(poly[key]);
				}
			}
			return polygon2d;
		}

		public static List<GeneralPolygon2d> FilterDegenerate(List<GeneralPolygon2d> polygons, double minArea)
		{
			List<GeneralPolygon2d> list = new List<GeneralPolygon2d>(polygons.Count);
			List<Polygon2d> list2 = new List<Polygon2d>();
			foreach (GeneralPolygon2d polygon in polygons)
			{
				if (polygon.Outer.Area < minArea)
				{
					continue;
				}
				if (polygon.Holes.Count == 0)
				{
					list.Add(polygon);
					continue;
				}
				list2.Clear();
				for (int i = 0; i < polygon.Holes.Count; i++)
				{
					Polygon2d polygon2d = polygon.Holes[i];
					if (polygon2d.Area > minArea)
					{
						list2.Add(polygon2d);
					}
				}
				if (list2.Count != polygon.Holes.Count)
				{
					polygon.ClearHoles();
					foreach (Polygon2d item in list2)
					{
						polygon.AddHole(item, bCheckContainment: false, bCheckOrientation: false);
					}
				}
				list.Add(polygon);
			}
			return list;
		}
	}
	public class DCurve3 : ISampledCurve3d
	{
		protected List<Vector3d> vertices;

		public int Timestamp;

		public bool Closed { get; set; }

		public int VertexCount => vertices.Count;

		public int SegmentCount
		{
			get
			{
				if (!Closed)
				{
					return vertices.Count - 1;
				}
				return vertices.Count;
			}
		}

		public Vector3d this[int key]
		{
			get
			{
				return vertices[key];
			}
			set
			{
				vertices[key] = value;
				Timestamp++;
			}
		}

		public Vector3d Start => vertices[0];

		public Vector3d End
		{
			get
			{
				if (!Closed)
				{
					return vertices.Last();
				}
				return vertices[0];
			}
		}

		public IEnumerable<Vector3d> Vertices => vertices;

		public double ArcLength => CurveUtils.ArcLength(vertices, Closed);

		public DCurve3()
		{
			vertices = new List<Vector3d>();
			Closed = false;
			Timestamp = 1;
		}

		public DCurve3(List<Vector3d> verticesIn, bool bClosed, bool bTakeOwnership = false)
		{
			if (bTakeOwnership)
			{
				vertices = verticesIn;
			}
			else
			{
				vertices = new List<Vector3d>(verticesIn);
			}
			Closed = bClosed;
			Timestamp = 1;
		}

		public DCurve3(IEnumerable<Vector3d> verticesIn, bool bClosed)
		{
			vertices = new List<Vector3d>(verticesIn);
			Closed = bClosed;
			Timestamp = 1;
		}

		public DCurve3(DCurve3 copy)
		{
			vertices = new List<Vector3d>(copy.vertices);
			Closed = copy.Closed;
			Timestamp = 1;
		}

		public DCurve3(ISampledCurve3d icurve)
		{
			vertices = new List<Vector3d>(icurve.Vertices);
			Closed = icurve.Closed;
			Timestamp = 1;
		}

		public DCurve3(Polygon2d poly, int ix = 0, int iy = 1)
		{
			int vertexCount = poly.VertexCount;
			vertices = new List<Vector3d>(vertexCount);
			for (int i = 0; i < vertexCount; i++)
			{
				Vector3d zero = Vector3d.Zero;
				zero[ix] = poly[i].x;
				zero[iy] = poly[i].y;
				vertices.Add(zero);
			}
			Closed = true;
			Timestamp = 1;
		}

		public DCurve3(Vector3[] v_in, bool bClosed)
		{
			Closed = bClosed;
			vertices = ((IEnumerable<Vector3>)v_in.ToList()).Select((Func<Vector3, Vector3d>)((Vector3 vertex) => vertex)).ToList();
			Timestamp = 1;
		}

		public void AppendVertex(Vector3d v)
		{
			vertices.Add(v);
			Timestamp++;
		}

		public Vector3d GetVertex(int i)
		{
			return vertices[i];
		}

		public IEnumerable<Vector3d> VertexItr()
		{
			return vertices;
		}

		public void SetVertex(int i, Vector3d v)
		{
			vertices[i] = v;
			Timestamp++;
		}

		public void SetVertices(VectorArray3d v)
		{
			vertices = new List<Vector3d>();
			for (int i = 0; i < v.Count; i++)
			{
				vertices.Add(v[i]);
			}
			Timestamp++;
		}

		public void SetVertices(IEnumerable<Vector3d> v)
		{
			vertices = new List<Vector3d>(v);
			Timestamp++;
		}

		public void SetVertices(List<Vector3d> vertices, bool bTakeOwnership)
		{
			if (bTakeOwnership)
			{
				this.vertices = vertices;
			}
			else
			{
				this.vertices = new List<Vector3d>(vertices);
			}
			Timestamp++;
		}

		public void ClearVertices()
		{
			vertices = new List<Vector3d>();
			Closed = false;
			Timestamp++;
		}

		public void RemoveVertex(int idx)
		{
			vertices.RemoveAt(idx);
			Timestamp++;
		}

		public void Reverse()
		{
			vertices.Reverse();
			Timestamp++;
		}

		public Segment3d GetSegment(int iSegment)
		{
			if (!Closed)
			{
				return new Segment3d(vertices[iSegment], vertices[iSegment + 1]);
			}
			return new Segment3d(vertices[iSegment], vertices[(iSegment + 1) % vertices.Count]);
		}

		public IEnumerable<Segment3d> SegmentItr()
		{
			if (Closed)
			{
				int NV = vertices.Count;
				int i = 0;
				while (i < NV)
				{
					yield return new Segment3d(vertices[i], vertices[(i + 1) % NV]);
					int num = i + 1;
					i = num;
				}
			}
			else
			{
				int NV = vertices.Count - 1;
				int i = 0;
				while (i < NV)
				{
					yield return new Segment3d(vertices[i], vertices[i + 1]);
					int num = i + 1;
					i = num;
				}
			}
		}

		public Vector3d PointAt(int iSegment, double fSegT)
		{
			return new Segment3d(vertices[iSegment], vertices[(iSegment + 1) % vertices.Count]).PointAt(fSegT);
		}

		public AxisAlignedBox3d GetBoundingBox()
		{
			AxisAlignedBox3d empty = AxisAlignedBox3d.Empty;
			foreach (Vector3d vertex in vertices)
			{
				empty.Contain(vertex);
			}
			return empty;
		}

		public Vector3d Tangent(int i)
		{
			return CurveUtils.GetTangent(vertices, i, Closed);
		}

		public Vector3d Centroid(int i)
		{
			if (Closed)
			{
				int count = vertices.Count;
				if (i == 0)
				{
					return 0.5 * (vertices[1] + vertices[count - 1]);
				}
				return 0.5 * (vertices[(i + 1) % count] + vertices[i - 1]);
			}
			if (i == 0 || i == vertices.Count - 1)
			{
				return vertices[i];
			}
			return 0.5 * (vertices[i + 1] + vertices[i - 1]);
		}

		public Index2i Neighbours(int i)
		{
			int count = vertices.Count;
			if (Closed)
			{
				if (i == 0)
				{
					return new Index2i(count - 1, 1);
				}
				return new Index2i(i - 1, (i + 1) % count);
			}
			if (i == 0)
			{
				return new Index2i(-1, 1);
			}
			if (i == count - 1)
			{
				return new Index2i(count - 2, -1);
			}
			return new Index2i(i - 1, i + 1);
		}

		public double OpeningAngleDeg(int i)
		{
			int num = i - 1;
			int num2 = i + 1;
			if (Closed)
			{
				int count = vertices.Count;
				num = ((i == 0) ? (count - 1) : num);
				num2 %= count;
			}
			else if (i == 0 || i == vertices.Count - 1)
			{
				return 180.0;
			}
			Vector3d v = vertices[num] - vertices[i];
			Vector3d v2 = vertices[num2] - vertices[i];
			v.Normalize();
			v2.Normalize();
			return Vector3d.AngleD(v, v2);
		}

		public int NearestVertex(Vector3d p)
		{
			double num = double.MaxValue;
			int result = -1;
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				double num2 = vertices[i].DistanceSquared(ref p);
				if (num2 < num)
				{
					num = num2;
					result = i;
				}
			}
			return result;
		}

		public double DistanceSquared(Vector3d p, out int iNearSeg, out double fNearSegT)
		{
			iNearSeg = -1;
			fNearSegT = double.MaxValue;
			double num = double.MaxValue;
			int num2 = (Closed ? vertices.Count : (vertices.Count - 1));
			for (int i = 0; i < num2; i++)
			{
				int index = i;
				int index2 = (i + 1) % vertices.Count;
				Segment3d segment3d = new Segment3d(vertices[index], vertices[index2]);
				double num3 = (p - segment3d.Center).Dot(segment3d.Direction);
				double num4 = double.MaxValue;
				num4 = ((num3 >= segment3d.Extent) ? segment3d.P1.DistanceSquared(p) : ((!(num3 <= 0.0 - segment3d.Extent)) ? (segment3d.PointAt(num3) - p).LengthSquared : segment3d.P0.DistanceSquared(p)));
				if (num4 < num)
				{
					num = num4;
					iNearSeg = i;
					fNearSegT = num3;
				}
			}
			return num;
		}

		public double DistanceSquared(Vector3d p)
		{
			int iNearSeg;
			double fNearSegT;
			return DistanceSquared(p, out iNearSeg, out fNearSegT);
		}

		public DCurve3 ResampleSharpTurns(double sharp_thresh = 90.0, double flat_thresh = 189.0, double corner_t = 0.01)
		{
			int count = vertices.Count;
			DCurve3 dCurve = new DCurve3
			{
				Closed = Closed
			};
			double t = 1.0 - corner_t;
			for (int i = 0; i < count; i++)
			{
				double num = Math.Abs(OpeningAngleDeg(i));
				if (!(num > flat_thresh) || i <= 0)
				{
					if (num > sharp_thresh)
					{
						dCurve.AppendVertex(vertices[i]);
						continue;
					}
					Vector3d b = vertices[(i + 1) % count];
					Vector3d a = vertices[(i == 0) ? (count - 1) : (i - 1)];
					dCurve.AppendVertex(Vector3d.Lerp(a, vertices[i], t));
					dCurve.AppendVertex(vertices[i]);
					dCurve.AppendVertex(Vector3d.Lerp(vertices[i], b, corner_t));
				}
			}
			return dCurve;
		}

		public Vector3d Center()
		{
			Vector3d zero = Vector3d.Zero;
			int num = SegmentCount;
			if (!Closed)
			{
				num++;
			}
			foreach (Vector3d vertex in Vertices)
			{
				zero += vertex;
			}
			return zero / num;
		}

		public Vector3d CenterMark()
		{
			Vector3d vector3d = Center();
			return GetSegment(NearestSegment(vector3d)).NearestPoint(vector3d);
		}

		public int NearestSegment(Vector3d position)
		{
			DistanceSquared(position, out var iNearSeg, out var _);
			return iNearSeg;
		}
	}
	public abstract class DGraph
	{
		public struct EdgeSplitInfo
		{
			public int vNew;

			public int eNewBN;
		}

		public struct EdgeCollapseInfo
		{
			public int vKept;

			public int vRemoved;

			public int eCollapsed;
		}

		public enum FailMode
		{
			DebugAssert,
			gDevAssert,
			Throw,
			ReturnOnly
		}

		public const int InvalidID = -1;

		public const int DuplicateEdgeID = -2;

		public static readonly Index2i InvalidEdgeV = new Index2i(-1, -1);

		public static readonly Index3i InvalidEdge3 = new Index3i(-1, -1, -1);

		protected RefCountVector vertices_refcount;

		protected DVector<List<int>> vertex_edges;

		protected RefCountVector edges_refcount;

		protected DVector<int> edges;

		protected int timestamp;

		protected int shape_timestamp;

		protected int max_group_id;

		public int Timestamp => timestamp;

		public int ShapeTimestamp => shape_timestamp;

		public int VertexCount => vertices_refcount.count;

		public int EdgeCount => edges_refcount.count;

		public int MaxVertexID => vertices_refcount.max_index;

		public int MaxEdgeID => edges_refcount.max_index;

		public int MaxGroupID => max_group_id;

		public bool IsCompact
		{
			get
			{
				if (vertices_refcount.is_dense)
				{
					return edges_refcount.is_dense;
				}
				return false;
			}
		}

		public bool IsCompactV => vertices_refcount.is_dense;

		public DGraph()
		{
			vertex_edges = new DVector<List<int>>();
			vertices_refcount = new RefCountVector();
			edges = new DVector<int>();
			edges_refcount = new RefCountVector();
			max_group_id = 0;
		}

		protected void updateTimeStamp(bool bShapeChange)
		{
			timestamp++;
			if (bShapeChange)
			{
				shape_timestamp++;
			}
		}

		public bool IsVertex(int vID)
		{
			return vertices_refcount.isValid(vID);
		}

		public bool IsEdge(int eID)
		{
			return edges_refcount.isValid(eID);
		}

		public ReadOnlyCollection<int> GetVtxEdges(int vID)
		{
			if (!vertices_refcount.isValid(vID))
			{
				return null;
			}
			return vertex_edges[vID].AsReadOnly();
		}

		public int GetVtxEdgeCount(int vID)
		{
			if (!vertices_refcount.isValid(vID))
			{
				return -1;
			}
			return vertex_edges[vID].Count;
		}

		public int GetMaxVtxEdgeCount()
		{
			int num = 0;
			foreach (int item in vertices_refcount)
			{
				num = Math.Max(num, vertex_edges[item].Count);
			}
			return num;
		}

		public int GetEdgeGroup(int eid)
		{
			if (!edges_refcount.isValid(eid))
			{
				return -1;
			}
			return edges[3 * eid + 2];
		}

		public void SetEdgeGroup(int eid, int group_id)
		{
			if (edges_refcount.isValid(eid))
			{
				edges[3 * eid + 2] = group_id;
				max_group_id = Math.Max(max_group_id, group_id + 1);
				updateTimeStamp(bShapeChange: false);
			}
		}

		public int AllocateEdgeGroup()
		{
			return max_group_id++;
		}

		public Index2i GetEdgeV(int eID)
		{
			if (!edges_refcount.isValid(eID))
			{
				return InvalidEdgeV;
			}
			return new Index2i(edges[3 * eID], edges[3 * eID + 1]);
		}

		public Index3i GetEdge(int eID)
		{
			int num = 3 * eID;
			if (!edges_refcount.isValid(eID))
			{
				return InvalidEdge3;
			}
			return new Index3i(edges[num], edges[num + 1], edges[num + 2]);
		}

		protected int append_vertex_internal()
		{
			int num = vertices_refcount.allocate();
			vertex_edges.insert(new List<int>(), num);
			updateTimeStamp(bShapeChange: true);
			return num;
		}

		public int AppendEdge(int v0, int v1, int gid = -1)
		{
			return AppendEdge(new Index2i(v0, v1), gid);
		}

		public int AppendEdge(Index2i ev, int gid = -1)
		{
			if (!IsVertex(ev[0]) || !IsVertex(ev[1]))
			{
				return -1;
			}
			if (ev[0] == ev[1])
			{
				return -1;
			}
			if (FindEdge(ev[0], ev[1]) != -1)
			{
				return -2;
			}
			vertices_refcount.increment(ev[0], 1);
			vertices_refcount.increment(ev[1], 1);
			max_group_id = Math.Max(max_group_id, gid + 1);
			int result = add_edge(ev[0], ev[1], gid);
			updateTimeStamp(bShapeChange: true);
			return result;
		}

		protected int add_edge(int a, int b, int gid)
		{
			if (b < a)
			{
				int num = b;
				b = a;
				a = num;
			}
			int num2 = edges_refcount.allocate();
			int num3 = 3 * num2;
			edges.insert(a, num3);
			edges.insert(b, num3 + 1);
			edges.insert(gid, num3 + 2);
			vertex_edges[a].Add(num2);
			vertex_edges[b].Add(num2);
			return num2;
		}

		public IEnumerable<int> VertexIndices()
		{
			foreach (int item in vertices_refcount)
			{
				yield return item;
			}
		}

		public IEnumerable<int> EdgeIndices()
		{
			foreach (int item in edges_refcount)
			{
				yield return item;
			}
		}

		public IEnumerable<Index3i> Edges()
		{
			foreach (int item in edges_refcount)
			{
				int num2 = 3 * item;
				yield return new Index3i(edges[num2], edges[num2 + 1], edges[num2 + 2]);
			}
		}

		public IEnumerable<int> VtxVerticesItr(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				List<int> vedges = vertex_edges[vID];
				int N = vedges.Count;
				int i = 0;
				while (i < N)
				{
					yield return edge_other_v(vedges[i], vID);
					int num = i + 1;
					i = num;
				}
			}
		}

		public IEnumerable<int> VtxEdgesItr(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				List<int> vedges = vertex_edges[vID];
				int N = vedges.Count;
				int i = 0;
				while (i < N)
				{
					yield return vedges[i];
					int num = i + 1;
					i = num;
				}
			}
		}

		public int FindEdge(int vA, int vB)
		{
			int vid = Math.Max(vA, vB);
			List<int> list = vertex_edges[Math.Min(vA, vB)];
			int count = list.Count;
			for (int i = 0; i < count; i++)
			{
				if (edge_has_v(list[i], vid))
				{
					return list[i];
				}
			}
			return -1;
		}

		public MeshResult RemoveEdge(int eID, bool bRemoveIsolatedVertices)
		{
			if (!edges_refcount.isValid(eID))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = 3 * eID;
			Index2i index2i = new Index2i(edges[num], edges[num + 1]);
			vertex_edges[index2i.a].Remove(eID);
			vertex_edges[index2i.b].Remove(eID);
			edges_refcount.decrement(eID, 1);
			for (int i = 0; i < 2; i++)
			{
				int num2 = index2i[i];
				vertices_refcount.decrement(num2, 1);
				if (bRemoveIsolatedVertices && vertices_refcount.refCount(num2) == 1)
				{
					vertices_refcount.decrement(num2, 1);
					vertex_edges[num2] = null;
				}
			}
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult RemoveVertex(int vid, bool bRemoveIsolatedVertices)
		{
			foreach (int item in new List<int>(GetVtxEdges(vid)))
			{
				MeshResult meshResult = RemoveEdge(item, bRemoveIsolatedVertices);
				if (meshResult != MeshResult.Ok)
				{
					return meshResult;
				}
			}
			return MeshResult.Ok;
		}

		public MeshResult SplitEdge(int vA, int vB, out EdgeSplitInfo split)
		{
			int num = FindEdge(vA, vB);
			if (num == -1)
			{
				split = default(EdgeSplitInfo);
				return MeshResult.Failed_NotAnEdge;
			}
			return SplitEdge(num, out split);
		}

		public MeshResult SplitEdge(int eab, out EdgeSplitInfo split)
		{
			split = default(EdgeSplitInfo);
			if (!IsEdge(eab))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = 3 * eab;
			int a = edges[num];
			int num2 = edges[num + 1];
			int gid = edges[num + 2];
			int num3 = append_new_split_vertex(a, num2);
			replace_edge_vertex(eab, num2, num3);
			vertex_edges[num2].Remove(eab);
			vertex_edges[num3].Add(eab);
			int eNewBN = add_edge(num3, num2, gid);
			vertices_refcount.increment(num3, 2);
			split.vNew = num3;
			split.eNewBN = eNewBN;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		protected virtual int append_new_split_vertex(int a, int b)
		{
			throw new NotImplementedException("DGraph2.append_new_split_vertex");
		}

		public MeshResult CollapseEdge(int vKeep, int vRemove, out EdgeCollapseInfo collapse)
		{
			bool flag = true;
			collapse = default(EdgeCollapseInfo);
			if (!IsVertex(vKeep) || !IsVertex(vRemove))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = FindEdge(vRemove, vKeep);
			if (num == -1)
			{
				return MeshResult.Failed_NotAnEdge;
			}
			List<int> list = vertex_edges[vKeep];
			List<int> list2 = vertex_edges[vRemove];
			bool flag2 = false;
			while (!flag2)
			{
				flag2 = true;
				foreach (int item in list2)
				{
					int num2 = edge_other_v(item, vRemove);
					if (num2 != vKeep && FindEdge(vKeep, num2) != -1)
					{
						RemoveEdge(item, flag);
						flag2 = false;
						break;
					}
				}
			}
			list.Remove(num);
			foreach (int item2 in list2)
			{
				if (edge_other_v(item2, vRemove) != vKeep)
				{
					replace_edge_vertex(item2, vRemove, vKeep);
					vertices_refcount.decrement(vRemove, 1);
					list.Add(item2);
					vertices_refcount.increment(vKeep, 1);
				}
			}
			edges_refcount.decrement(num, 1);
			vertices_refcount.decrement(vKeep, 1);
			vertices_refcount.decrement(vRemove, 1);
			if (flag)
			{
				vertices_refcount.decrement(vRemove, 1);
				vertex_edges[vRemove] = null;
			}
			list2.Clear();
			collapse.vKept = vKeep;
			collapse.vRemoved = vRemove;
			collapse.eCollapsed = num;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		protected bool edge_has_v(int eid, int vid)
		{
			int num = 3 * eid;
			if (edges[num] != vid)
			{
				return edges[num + 1] == vid;
			}
			return true;
		}

		protected int edge_other_v(int eID, int vID)
		{
			int num = 3 * eID;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			if (num2 != vID)
			{
				if (num3 != vID)
				{
					return -1;
				}
				return num2;
			}
			return num3;
		}

		protected int replace_edge_vertex(int eID, int vOld, int vNew)
		{
			int num = 3 * eID;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			if (num2 == vOld)
			{
				edges[num] = Math.Min(num3, vNew);
				edges[num + 1] = Math.Max(num3, vNew);
				return 0;
			}
			if (num3 == vOld)
			{
				edges[num] = Math.Min(num2, vNew);
				edges[num + 1] = Math.Max(num2, vNew);
				return 1;
			}
			return -1;
		}

		public bool IsBoundaryVertex(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				return vertex_edges[vID].Count == 1;
			}
			return false;
		}

		public bool IsJunctionVertex(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				return vertex_edges[vID].Count > 2;
			}
			return false;
		}

		public bool IsRegularVertex(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				return vertex_edges[vID].Count == 2;
			}
			return false;
		}

		public virtual bool CheckValidity(FailMode eFailMode = FailMode.Throw)
		{
			bool is_ok = true;
			Action<bool> action = delegate(bool b)
			{
				is_ok &= b;
			};
			switch (eFailMode)
			{
			case FailMode.DebugAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.gDevAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.Throw:
				action = delegate(bool b)
				{
					if (!b)
					{
						throw new Exception("DGraph3.CheckValidity: check failed");
					}
				};
				break;
			}
			foreach (int item in EdgeIndices())
			{
				action(IsEdge(item));
				action(edges_refcount.refCount(item) == 1);
				Index2i edgeV = GetEdgeV(item);
				action(IsVertex(edgeV[0]));
				action(IsVertex(edgeV[1]));
				action(edgeV[0] < edgeV[1]);
			}
			if (vertices_refcount.is_dense)
			{
				for (int num = 0; num < VertexCount; num++)
				{
					action(vertices_refcount.isValid(num));
				}
			}
			foreach (int item2 in VertexIndices())
			{
				action(IsVertex(item2));
				List<int> list = vertex_edges[item2];
				foreach (int item3 in list)
				{
					action(IsEdge(item3));
					action(edge_has_v(item3, item2));
					int num2 = edge_other_v(item3, item2);
					int num3 = FindEdge(item2, num2);
					action(num3 != -1);
					action(num3 == item3);
					num3 = FindEdge(num2, item2);
					action(num3 != -1);
					action(num3 == item3);
				}
				action(vertices_refcount.refCount(item2) == list.Count + 1);
			}
			subclass_validity_checks(action);
			return is_ok;
		}

		protected virtual void subclass_validity_checks(Action<bool> CheckOrFailF)
		{
		}

		[Conditional("DEBUG")]
		public void debug_check_is_vertex(int v)
		{
			if (!IsVertex(v))
			{
				throw new Exception("DGraph.debug_is_vertex - not a vertex!");
			}
		}

		[Conditional("DEBUG")]
		public void debug_check_is_edge(int e)
		{
			if (!IsEdge(e))
			{
				throw new Exception("DGraph.debug_is_edge - not an edge!");
			}
		}
	}
	public class DGraphN : DGraph
	{
		public int AppendVertex()
		{
			return append_vertex_internal();
		}

		protected override int append_new_split_vertex(int a, int b)
