					int vtxEdgeCount = Graph.GetVtxEdgeCount(edgeV.a);
					int vtxEdgeCount2 = Graph.GetVtxEdgeCount(edgeV.b);
					if (vtxEdgeCount != 2 && vtxEdgeCount2 != 2)
