					{
						num7 = 1;
					}
					if (num7 == -1)
					{
						double num8 = Math.Abs(Graph.OpeningAngle(edgeV.a));
						double num9 = Math.Abs(Graph.OpeningAngle(edgeV.b));
						if (num8 < num && num9 < num)
						{
							continue;
						}
						if (num8 < num)
						{
							num7 = 0;
						}
						else if (num9 < num)
						{
							num7 = 1;
						}
					}
					Vector2d vNewPos = num7 switch
					{
						0 => vertex, 
						-1 => 0.5 * (vertex + vertex2), 
