		public static Curves ExtractCurves(DGraph2 graph)
		{
			Curves curves = new Curves();
			curves.Loops = new List<Polygon2d>();
			curves.Paths = new List<PolyLine2d>();
			HashSet<int> hashSet = new HashSet<int>();
			HashSet<int> hashSet2 = new HashSet<int>();
			HashSet<int> hashSet3 = new HashSet<int>();
			foreach (int item in graph.VertexIndices())
			{
				if (graph.IsBoundaryVertex(item))
				{
					hashSet2.Add(item);
				}
				if (graph.IsJunctionVertex(item))
				{
					hashSet3.Add(item);
				}
			}
			foreach (int item2 in hashSet2)
			{
				int num = item2;
				int num2 = graph.GetVtxEdges(num)[0];
				if (!hashSet.Contains(num2))
				{
					PolyLine2d polyLine2d = new PolyLine2d();
					polyLine2d.AppendVertex(graph.GetVertex(num));
					do
					{
						hashSet.Add(num2);
						Index2i index2i = NextEdgeAndVtx(num2, num, graph);
						num2 = index2i.a;
						num = index2i.b;
						polyLine2d.AppendVertex(graph.GetVertex(num));
					}
					while (!hashSet2.Contains(num) && !hashSet3.Contains(num));
					curves.Paths.Add(polyLine2d);
				}
			}
			hashSet2.Clear();
			foreach (int item3 in hashSet3)
			{
				foreach (int item4 in graph.VtxEdgesItr(item3))
				{
					if (hashSet.Contains(item4))
					{
						continue;
					}
					int num3 = item3;
					int num4 = item4;
					PolyLine2d polyLine2d2 = new PolyLine2d();
					polyLine2d2.AppendVertex(graph.GetVertex(num3));
					bool flag = false;
					do
					{
						hashSet.Add(num4);
						Index2i index2i2 = NextEdgeAndVtx(num4, num3, graph);
						num4 = index2i2.a;
						num3 = index2i2.b;
						if (num3 == item3)
						{
							flag = true;
							break;
						}
						polyLine2d2.AppendVertex(graph.GetVertex(num3));
					}
					while (num4 != int.MaxValue && !hashSet3.Contains(num3));
					if (flag)
					{
						curves.Loops.Add(new Polygon2d(polyLine2d2.Vertices));
					}
					else
					{
						curves.Paths.Add(polyLine2d2);
					}
				}
			}
			foreach (int item5 in graph.EdgeIndices())
			{
				if (hashSet.Contains(item5))
				{
					continue;
				}
				int num5 = item5;
				int num6 = graph.GetEdgeV(num5).a;
				Polygon2d polygon2d = new Polygon2d();
				polygon2d.AppendVertex(graph.GetVertex(num6));
				do
				{
					hashSet.Add(num5);
					Index2i index2i3 = NextEdgeAndVtx(num5, num6, graph);
					num5 = index2i3.a;
					num6 = index2i3.b;
					polygon2d.AppendVertex(graph.GetVertex(num6));
					if (num5 == int.MaxValue || hashSet3.Contains(num6))
					{
						throw new Exception("how did this happen??");
					}
				}
				while (!hashSet.Contains(num5));
				polygon2d.RemoveVertex(polygon2d.VertexCount - 1);
				curves.Loops.Add(polygon2d);
			}
			return curves;
		}

		public static void ChainOpenPaths(Curves c, double epsilon = 2.220446049250313E-16)
		{
			List<PolyLine2d> list = new List<PolyLine2d>(c.Paths);
			c.Paths = new List<PolyLine2d>();
			List<PolyLine2d> list2 = new List<PolyLine2d>();
			List<PolyLine2d> list3 = new List<PolyLine2d>();
			bool flag = true;
			while (flag && list.Count > 0)
			{
				flag = false;
				foreach (PolyLine2d item in list)
				{
					List<PolyLine2d> list4 = find_connected_start(item, list, epsilon);
					List<PolyLine2d> list5 = find_connected_end(item, list, epsilon);
					if (list4.Count == 0 || list5.Count == 0)
					{
						list2.Add(item);
						flag = true;
					}
					else
					{
						list3.Add(item);
					}
				}
				list.Clear();
				list.AddRange(list3);
				list3.Clear();
			}
			flag = true;
			while (flag && list.Count > 0)
			{
				flag = false;
				while (true)
				{
					IL_00b8:
					foreach (PolyLine2d item2 in list)
					{
						List<PolyLine2d> list6 = find_connected_start(item2, list, epsilon);
						List<PolyLine2d> list7 = find_connected_end(item2, list, 2.0 * epsilon);
						if (list6.Count == 1 && list7.Count == 1 && list6[0] == list7[0])
						{
							c.Loops.Add(to_loop(item2, list6[0], epsilon));
							list.Remove(item2);
							list.Remove(list6[0]);
							list3.Remove(list6[0]);
							flag = true;
						}
						else if (list6.Count == 1 && list7.Count < 2)
						{
							list3.Add(merge_paths(list6[0], item2, 2.0 * epsilon));
							list.Remove(item2);
							list.Remove(list6[0]);
							list3.Remove(list6[0]);
							flag = true;
						}
						else
						{
							if (list7.Count != 1 || list6.Count >= 2)
							{
								list3.Add(item2);
								continue;
							}
							list3.Add(merge_paths(item2, list7[0], 2.0 * epsilon));
							list.Remove(item2);
							list.Remove(list7[0]);
							list3.Remove(list7[0]);
							flag = true;
						}
						goto IL_00b8;
					}
					break;
				}
				list.Clear();
				list.AddRange(list3);
				list3.Clear();
			}
			c.Paths.AddRange(list);
			c.Paths.AddRange(list2);
		}

		private static List<PolyLine2d> find_connected_start(PolyLine2d pTest, List<PolyLine2d> potential, double eps = 2.220446049250313E-16)
		{
			List<PolyLine2d> list = new List<PolyLine2d>();
			foreach (PolyLine2d item in potential)
			{
				if (pTest != item && (pTest.Start.Distance(item.Start) < eps || pTest.Start.Distance(item.End) < eps))
				{
					list.Add(item);
				}
			}
			return list;
		}

		private static List<PolyLine2d> find_connected_end(PolyLine2d pTest, List<PolyLine2d> potential, double eps = 2.220446049250313E-16)
		{
			List<PolyLine2d> list = new List<PolyLine2d>();
			foreach (PolyLine2d item in potential)
			{
				if (pTest != item && (pTest.End.Distance(item.Start) < eps || pTest.End.Distance(item.End) < eps))
				{
					list.Add(item);
				}
			}
			return list;
		}

		private static Polygon2d to_loop(PolyLine2d p1, PolyLine2d p2, double eps = 2.220446049250313E-16)
		{
			Polygon2d polygon2d = new Polygon2d(p1.Vertices);
			if (p1.End.Distance(p2.Start) > eps)
			{
				p2.Reverse();
			}
			polygon2d.AppendVertices(p2);
			return polygon2d;
		}

		private static PolyLine2d merge_paths(PolyLine2d p1, PolyLine2d p2, double eps = 2.220446049250313E-16)
		{
			PolyLine2d polyLine2d;
			if (p1.End.Distance(p2.Start) < eps)
			{
				polyLine2d = new PolyLine2d(p1);
				polyLine2d.AppendVertices(p2);
			}
			else if (p1.End.Distance(p2.End) < eps)
			{
				polyLine2d = new PolyLine2d(p1);
				p2.Reverse();
				polyLine2d.AppendVertices(p2);
			}
			else if (p1.Start.Distance(p2.Start) < eps)
			{
				p2.Reverse();
				polyLine2d = new PolyLine2d(p2);
				polyLine2d.AppendVertices(p1);
			}
			else
			{
				if (!(p1.Start.Distance(p2.End) < eps))
				{
					throw new Exception("shit");
				}
				polyLine2d = new PolyLine2d(p2);
				polyLine2d.AppendVertices(p1);
			}
			return polyLine2d;
		}

		public static int DisconnectJunctions(DGraph2 graph)
		{
			List<int> list = new List<int>();
			foreach (int item in graph.VertexIndices())
			{
				if (graph.IsJunctionVertex(item))
				{
					list.Add(item);
				}
			}
			foreach (int item2 in list)
			{
				Vector2d vertex = graph.GetVertex(item2);
				int[] array = graph.VtxVerticesItr(item2).ToArray();
				Index2i index2i = Index2i.Max;
				double num = 0.0;
				for (int i = 0; i < array.Length; i++)
				{
					for (int j = i + 1; j < array.Length; j++)
					{
						double value = Vector2d.AngleD((graph.GetVertex(array[i]) - vertex).Normalized, (graph.GetVertex(array[j]) - vertex).Normalized);
						value = Math.Abs(value);
						if (value > num)
						{
							num = value;
							index2i = new Index2i(array[i], array[j]);
						}
					}
				}
				for (int k = 0; k < array.Length; k++)
				{
					if (array[k] != index2i.a && array[k] != index2i.b)
					{
						int eID = graph.FindEdge(item2, array[k]);
						graph.RemoveEdge(eID, bRemoveIsolatedVertices: true);
						if (graph.IsVertex(array[k]))
						{
							Vector2d v = Vector2d.Lerp(graph.GetVertex(array[k]), vertex, 0.99);
							int v2 = graph.AppendVertex(v);
							graph.AppendEdge(array[k], v2);
						}
					}
				}
			}
			return list.Count;
		}

		public static void DisconnectJunction(DGraph2 graph, int vid, double shrinkFactor = 1.0)
		{
			Vector2d vertex = graph.GetVertex(vid);
			int[] array = graph.VtxVerticesItr(vid).ToArray();
			for (int i = 0; i < array.Length; i++)
			{
				int eID = graph.FindEdge(vid, array[i]);
				graph.RemoveEdge(eID, bRemoveIsolatedVertices: true);
				if (graph.IsVertex(array[i]))
				{
					Vector2d v = Vector2d.Lerp(graph.GetVertex(array[i]), vertex, shrinkFactor);
					int v2 = graph.AppendVertex(v);
					graph.AppendEdge(array[i], v2);
				}
			}
		}

		public static Vector2d VertexLaplacian(DGraph2 graph, int vid, out bool isValid)
		{
			Vector2d vertex = graph.GetVertex(vid);
			Vector2d zero = Vector2d.Zero;
			int num = 0;
			foreach (int item in graph.VtxVerticesItr(vid))
			{
				zero += graph.GetVertex(item);
				num++;
			}
			if (num == 2)
			{
				zero /= (double)num;
				isValid = true;
				return zero - vertex;
			}
			isValid = false;
			return vertex;
		}

		public static bool FindRayIntersection(Vector2d o, Vector2d d, out int hit_eid, out double hit_ray_t, DGraph2 graph)
		{
			Line2d line = new Line2d(o, d);
			Vector2d a = Vector2d.Zero;
			Vector2d b = Vector2d.Zero;
			int num = -1;
			double num2 = double.MaxValue;
			IntrLine2Segment2 intrLine2Segment = new IntrLine2Segment2(line, new Segment2d(a, b));
			foreach (int item in graph.VertexIndices())
			{
				graph.GetEdgeV(item, ref a, ref b);
				intrLine2Segment.Segment = new Segment2d(a, b);
				if (intrLine2Segment.Find() && intrLine2Segment.IsSimpleIntersection && intrLine2Segment.Parameter > 0.0 && intrLine2Segment.Parameter < num2)
				{
					num = item;
					num2 = intrLine2Segment.Parameter;
				}
			}
			hit_eid = num;
			hit_ray_t = num2;
			return hit_ray_t < double.MaxValue;
		}

		public static Index2i NextEdgeAndVtx(int eid, int prev_vid, DGraph2 graph)
		{
			Index2i edgeV = graph.GetEdgeV(eid);
			if (edgeV.a == -1)
			{
				return Index2i.Max;
			}
			int num = ((edgeV.a == prev_vid) ? edgeV.b : edgeV.a);
			if (graph.GetVtxEdgeCount(num) != 2)
			{
				return new Index2i(int.MaxValue, num);
			}
			foreach (int item in graph.VtxEdgesItr(num))
			{
				if (item != eid)
				{
					return new Index2i(item, num);
				}
			}
			return Index2i.Max;
		}

		public static List<int> WalkToNextNonRegularVtx(DGraph2 graph, int fromVtx, int eid)
		{
			List<int> list = new List<int>();
			list.Add(fromVtx);
			int prev_vid = fromVtx;
			int eid2 = eid;
			bool flag = true;
			while (flag)
			{
				Index2i index2i = NextEdgeAndVtx(eid2, prev_vid, graph);
				int a = index2i.a;
				int b = index2i.b;
				if (a == int.MaxValue)
				{
					if (graph.IsRegularVertex(b))
					{
						throw new Exception("WalkToNextNonRegularVtx: have no next edge but vtx is regular - how?");
					}
					list.Add(b);
					flag = false;
				}
				else
				{
					list.Add(b);
					prev_vid = b;
					eid2 = a;
				}
			}
			return list;
		}

		public static double PathLength(DGraph2 graph, IList<int> pathVertices)
		{
			double num = 0.0;
			int count = pathVertices.Count;
			Vector2d vector2d = graph.GetVertex(pathVertices[0]);
			Vector2d zero = Vector2d.Zero;
			for (int i = 1; i < count; i++)
			{
				zero = graph.GetVertex(pathVertices[i]);
				num += vector2d.Distance(zero);
				vector2d = zero;
			}
			return num;
		}
	}
	public class DGraph3 : DGraph
	{
		public static readonly Vector3d InvalidVertex = new Vector3d(double.MaxValue, 0.0, 0.0);

		private DVector<double> vertices;

		private DVector<float> colors;

		private AxisAlignedBox3d cached_bounds;

		private int cached_bounds_timestamp = -1;

		public bool HasVertexColors => colors != null;

		public AxisAlignedBox3d CachedBounds
		{
			get
			{
				if (cached_bounds_timestamp != base.Timestamp)
				{
					cached_bounds = GetBounds();
					cached_bounds_timestamp = base.Timestamp;
				}
				return cached_bounds;
			}
		}

		public DGraph3()
		{
			vertices = new DVector<double>();
		}

		public DGraph3(DGraph3 copy)
		{
			vertices = new DVector<double>();
			AppendGraph(copy);
		}

		public Vector3d GetVertex(int vID)
		{
			int num = 3 * vID;
			return new Vector3d(vertices[num], vertices[num + 1], vertices[num + 2]);
		}

		public void SetVertex(int vID, Vector3d vNewPos)
		{
			if (vertices_refcount.isValid(vID))
			{
				int num = 3 * vID;
				vertices[num] = vNewPos.x;
				vertices[num + 1] = vNewPos.y;
				vertices[num + 2] = vNewPos.z;
				updateTimeStamp(bShapeChange: true);
			}
		}

		public Vector3f GetVertexColor(int vID)
		{
			if (colors == null)
			{
				return Vector3f.One;
			}
			int num = 3 * vID;
			return new Vector3f(colors[num], colors[num + 1], colors[num + 2]);
		}

		public void SetVertexColor(int vID, Vector3f vNewColor)
		{
			if (HasVertexColors)
			{
				int num = 3 * vID;
				colors[num] = vNewColor.x;
				colors[num + 1] = vNewColor.y;
				colors[num + 2] = vNewColor.z;
				updateTimeStamp(bShapeChange: false);
			}
		}

		public bool GetEdgeV(int eID, ref Vector3d a, ref Vector3d b)
		{
			if (edges_refcount.isValid(eID))
			{
				int num = 3 * edges[3 * eID];
				a.x = vertices[num];
				a.y = vertices[num + 1];
				a.z = vertices[num + 2];
				int num2 = 3 * edges[3 * eID + 1];
				b.x = vertices[num2];
				b.y = vertices[num2 + 1];
				b.z = vertices[num2 + 2];
				return true;
			}
			return false;
		}

		public Segment3d GetEdgeSegment(int eID)
		{
			if (edges_refcount.isValid(eID))
			{
				int num = 3 * edges[3 * eID];
				int num2 = 3 * edges[3 * eID + 1];
				return new Segment3d(new Vector3d(vertices[num], vertices[num + 1], vertices[num + 2]), new Vector3d(vertices[num2], vertices[num2 + 1], vertices[num2 + 2]));
			}
			throw new Exception("DGraph3.GetEdgeSegment: invalid segment with id " + eID);
		}

		public Vector3d GetEdgeCenter(int eID)
		{
			if (edges_refcount.isValid(eID))
			{
				int num = 3 * edges[3 * eID];
				int num2 = 3 * edges[3 * eID + 1];
				return new Vector3d((vertices[num] + vertices[num2]) * 0.5, (vertices[num + 1] + vertices[num2 + 1]) * 0.5, (vertices[num + 2] + vertices[num2 + 2]) * 0.5);
			}
			throw new Exception("DGraph3.GetEdgeCenter: invalid segment with id " + eID);
		}

		public IEnumerable<Segment3d> Segments()
		{
			foreach (int item in edges_refcount)
			{
				yield return GetEdgeSegment(item);
			}
		}

		public int AppendVertex(Vector3d v)
		{
			return AppendVertex(v, Vector3f.One);
		}

		public int AppendVertex(Vector3d v, Vector3f c)
		{
			int num = append_vertex_internal();
			int num2 = 3 * num;
			vertices.insert(v[2], num2 + 2);
			vertices.insert(v[1], num2 + 1);
			vertices.insert(v[0], num2);
			if (colors != null)
			{
				colors.insert(c.z, num2 + 2);
				colors.insert(c.y, num2 + 1);
				colors.insert(c.x, num2);
			}
			return num;
		}

		public void AppendGraph(DGraph3 graph, int gid = -1)
		{
			int[] array = new int[graph.MaxVertexID];
			foreach (int item in graph.VertexIndices())
			{
				array[item] = AppendVertex(graph.GetVertex(item));
			}
			foreach (int item2 in graph.EdgeIndices())
			{
				Index2i edgeV = graph.GetEdgeV(item2);
				int gid2 = ((gid == -1) ? graph.GetEdgeGroup(item2) : gid);
				AppendEdge(array[edgeV.a], array[edgeV.b], gid2);
			}
		}

		public void EnableVertexColors(Vector3f initial_color)
		{
			if (!HasVertexColors)
			{
				colors = new DVector<float>();
				int maxVertexID = base.MaxVertexID;
				colors.resize(3 * maxVertexID);
				for (int i = 0; i < maxVertexID; i++)
				{
					int num = 3 * i;
					colors[num] = initial_color.x;
					colors[num + 1] = initial_color.y;
					colors[num + 2] = initial_color.z;
				}
			}
		}

		public void DiscardVertexColors()
		{
			colors = null;
		}

		public IEnumerable<Vector3d> Vertices()
		{
			foreach (int item in vertices_refcount)
			{
				int num2 = 3 * item;
				yield return new Vector3d(vertices[num2], vertices[num2 + 1], vertices[num2 + 2]);
			}
		}

		public AxisAlignedBox3d GetBounds()
		{
			double num = 0.0;
			double num2 = 0.0;
			double num3 = 0.0;
			IEnumerator enumerator = vertices_refcount.GetEnumerator();
			try
			{
				if (enumerator.MoveNext())
				{
					int num4 = (int)enumerator.Current;
					num = vertices[3 * num4];
					num2 = vertices[3 * num4 + 1];
					num3 = vertices[3 * num4 + 2];
				}
			}
			finally
			{
				IDisposable disposable = enumerator as IDisposable;
				if (disposable != null)
				{
					disposable.Dispose();
				}
			}
			double num5 = num;
			double num6 = num;
			double num7 = num2;
			double num8 = num2;
			double num9 = num3;
			double num10 = num3;
			foreach (int item in vertices_refcount)
			{
				int num12 = 3 * item;
				num = vertices[num12];
				num2 = vertices[num12 + 1];
				num3 = vertices[num12 + 2];
				if (num < num5)
				{
					num5 = num;
				}
				else if (num > num6)
				{
					num6 = num;
				}
				if (num2 < num7)
				{
					num7 = num2;
				}
				else if (num2 > num8)
				{
					num8 = num2;
				}
				if (num3 < num9)
				{
					num9 = num3;
				}
				else if (num3 > num10)
				{
					num10 = num3;
				}
			}
			return new AxisAlignedBox3d(num5, num7, num9, num6, num8, num10);
		}

		protected override int append_new_split_vertex(int a, int b)
		{
			Vector3d v = 0.5 * (GetVertex(a) + GetVertex(b));
			Vector3f c = (HasVertexColors ? (0.5f * (GetVertexColor(a) + GetVertexColor(b))) : Vector3f.One);
			return AppendVertex(v, c);
		}

		protected override void subclass_validity_checks(Action<bool> CheckOrFailF)
		{
			foreach (int item in VertexIndices())
			{
				Vector3d vertex = GetVertex(item);
				CheckOrFailF(!double.IsNaN(vertex.LengthSquared));
				CheckOrFailF(!double.IsInfinity(vertex.LengthSquared));
			}
		}
	}
	public static class DGraph3Util
	{
		public struct Curves
		{
			public List<DCurve3> Loops;

			public List<DCurve3> Paths;

			public HashSet<int> BoundaryV;

			public HashSet<int> JunctionV;

			public List<List<int>> LoopEdges;

			public List<List<int>> PathEdges;
		}

		public static Curves ExtractCurves(DGraph3 graph, bool bWantLoopIndices = false, Func<int, bool> CurveOrientationF = null)
		{
			Curves result = new Curves
			{
				Loops = new List<DCurve3>(),
				Paths = new List<DCurve3>()
			};
			if (bWantLoopIndices)
			{
				result.LoopEdges = new List<List<int>>();
				result.PathEdges = new List<List<int>>();
			}
			HashSet<int> hashSet = new HashSet<int>();
			HashSet<int> hashSet2 = new HashSet<int>();
			HashSet<int> hashSet3 = new HashSet<int>();
			foreach (int item in graph.VertexIndices())
			{
				if (graph.IsBoundaryVertex(item))
				{
					hashSet2.Add(item);
				}
				if (graph.IsJunctionVertex(item))
				{
					hashSet3.Add(item);
				}
			}
			foreach (int item2 in hashSet2)
			{
				int num = item2;
				int num2 = graph.GetVtxEdges(num)[0];
				if (hashSet.Contains(num2))
				{
					continue;
				}
				bool flag = CurveOrientationF?.Invoke(num2) ?? false;
				DCurve3 dCurve = new DCurve3
				{
					Closed = false
				};
				List<int> list = (bWantLoopIndices ? new List<int>() : null);
				dCurve.AppendVertex(graph.GetVertex(num));
				list?.Add(num2);
				while (true)
				{
					hashSet.Add(num2);
					Index2i index2i = NextEdgeAndVtx(num2, num, graph);
					num2 = index2i.a;
					num = index2i.b;
					dCurve.AppendVertex(graph.GetVertex(num));
					if (hashSet2.Contains(num) || hashSet3.Contains(num))
					{
						break;
					}
					list?.Add(num2);
				}
				if (flag)
				{
					dCurve.Reverse();
				}
				result.Paths.Add(dCurve);
				if (list != null)
				{
					if (flag)
					{
						list.Reverse();
					}
					result.PathEdges.Add(list);
				}
			}
			result.BoundaryV = hashSet2;
			foreach (int item3 in hashSet3)
			{
				foreach (int item4 in graph.VtxEdgesItr(item3))
				{
					if (hashSet.Contains(item4))
					{
						continue;
					}
					int num3 = item3;
					int num4 = item4;
					bool flag2 = CurveOrientationF?.Invoke(num4) ?? false;
					DCurve3 dCurve2 = new DCurve3
					{
						Closed = false
					};
					List<int> list2 = (bWantLoopIndices ? new List<int>() : null);
					dCurve2.AppendVertex(graph.GetVertex(num3));
					list2?.Add(num4);
					while (true)
					{
						hashSet.Add(num4);
						Index2i index2i2 = NextEdgeAndVtx(num4, num3, graph);
						num4 = index2i2.a;
						num3 = index2i2.b;
						dCurve2.AppendVertex(graph.GetVertex(num3));
						if (num4 == int.MaxValue || hashSet3.Contains(num3))
						{
							break;
						}
						list2?.Add(num4);
					}
					if (num3 == item3)
					{
						dCurve2.RemoveVertex(dCurve2.VertexCount - 1);
						dCurve2.Closed = true;
						if (flag2)
						{
							dCurve2.Reverse();
						}
						result.Loops.Add(dCurve2);
						if (list2 != null)
						{
							if (flag2)
							{
								list2.Reverse();
							}
							result.LoopEdges.Add(list2);
						}
						if (num4 != int.MaxValue)
						{
							hashSet.Add(num4);
						}
						continue;
					}
					if (flag2)
					{
						dCurve2.Reverse();
					}
					result.Paths.Add(dCurve2);
					if (list2 != null)
					{
						if (flag2)
						{
							list2.Reverse();
						}
						result.PathEdges.Add(list2);
					}
				}
			}
			result.JunctionV = hashSet3;
			foreach (int item5 in graph.EdgeIndices())
			{
				if (hashSet.Contains(item5))
				{
					continue;
				}
				int num5 = item5;
				int num6 = graph.GetEdgeV(num5).a;
				bool flag3 = CurveOrientationF?.Invoke(num5) ?? false;
				DCurve3 dCurve3 = new DCurve3
				{
					Closed = true
				};
				List<int> list3 = (bWantLoopIndices ? new List<int>() : null);
				dCurve3.AppendVertex(graph.GetVertex(num6));
				list3?.Add(num5);
				do
				{
					hashSet.Add(num5);
					Index2i index2i3 = NextEdgeAndVtx(num5, num6, graph);
					num5 = index2i3.a;
					num6 = index2i3.b;
					dCurve3.AppendVertex(graph.GetVertex(num6));
					list3?.Add(num5);
					if (num5 == int.MaxValue || hashSet3.Contains(num6))
					{
						throw new Exception("how did this happen??");
					}
				}
				while (!hashSet.Contains(num5));
				dCurve3.RemoveVertex(dCurve3.VertexCount - 1);
				if (flag3)
				{
					dCurve3.Reverse();
				}
				result.Loops.Add(dCurve3);
				if (list3 != null)
				{
					list3.RemoveAt(list3.Count - 1);
					if (flag3)
					{
						list3.Reverse();
					}
					result.LoopEdges.Add(list3);
				}
			}
			return result;
		}

		public static void DisconnectJunction(DGraph3 graph, int vid, double shrinkFactor = 1.0)
		{
			Vector3d vertex = graph.GetVertex(vid);
			int[] array = graph.VtxVerticesItr(vid).ToArray();
			for (int i = 0; i < array.Length; i++)
			{
				int eID = graph.FindEdge(vid, array[i]);
				graph.RemoveEdge(eID, bRemoveIsolatedVertices: true);
				if (graph.IsVertex(array[i]))
				{
					Vector3d v = Vector3d.Lerp(graph.GetVertex(array[i]), vertex, shrinkFactor);
					int v2 = graph.AppendVertex(v);
					graph.AppendEdge(array[i], v2);
				}
			}
		}

		public static Index2i NextEdgeAndVtx(int eid, int prev_vid, DGraph3 graph)
		{
			Index2i edgeV = graph.GetEdgeV(eid);
			if (edgeV.a == -1)
			{
				return Index2i.Max;
			}
			int num = ((edgeV.a == prev_vid) ? edgeV.b : edgeV.a);
			if (graph.GetVtxEdgeCount(num) != 2)
			{
				return new Index2i(int.MaxValue, num);
			}
			foreach (int item in graph.VtxEdgesItr(num))
			{
				if (item != eid)
				{
					return new Index2i(item, num);
				}
			}
			return Index2i.Max;
		}

		public static List<int> WalkToNextNonRegularVtx(DGraph3 graph, int fromVtx, int eid)
		{
			List<int> list = new List<int>();
			list.Add(fromVtx);
			int prev_vid = fromVtx;
			int eid2 = eid;
			bool flag = true;
			while (flag)
			{
				Index2i index2i = NextEdgeAndVtx(eid2, prev_vid, graph);
				int a = index2i.a;
				int b = index2i.b;
				if (a == int.MaxValue)
				{
					if (graph.IsRegularVertex(b))
					{
						throw new Exception("WalkToNextNonRegularVtx: have no next edge but vtx is regular - how?");
					}
					list.Add(b);
					flag = false;
				}
				else
				{
					list.Add(b);
					prev_vid = b;
					eid2 = a;
				}
			}
			return list;
		}

		public static void ErodeOpenSpurs(DGraph3 graph)
		{
			HashSet<int> hashSet = new HashSet<int>();
			HashSet<int> hashSet2 = new HashSet<int>();
			HashSet<int> hashSet3 = new HashSet<int>();
			foreach (int item in graph.VertexIndices())
			{
				if (graph.IsBoundaryVertex(item))
				{
					hashSet2.Add(item);
				}
				if (graph.IsJunctionVertex(item))
				{
					hashSet3.Add(item);
				}
			}
			foreach (int item2 in hashSet2)
			{
				if (!graph.IsVertex(item2))
				{
					continue;
				}
				int num = item2;
				int num2 = graph.GetVtxEdges(num)[0];
				if (hashSet.Contains(num2))
				{
					continue;
				}
				List<int> list = new List<int>();
				list?.Add(num2);
				while (true)
				{
					hashSet.Add(num2);
					Index2i index2i = NextEdgeAndVtx(num2, num, graph);
					num2 = index2i.a;
					num = index2i.b;
					if (hashSet2.Contains(num) || hashSet3.Contains(num))
					{
						break;
					}
					list?.Add(num2);
				}
				foreach (int item3 in list)
				{
					graph.RemoveEdge(item3, bRemoveIsolatedVertices: true);
				}
			}
		}
	}
	public class Ellipse2d : IParametricCurve2d
	{
		public Vector2d Center;

		public Vector2d Axis0;

		public Vector2d Axis1;

		public Vector2d Extent;

		public bool IsReversed;

		public bool IsClosed => true;

		public bool IsTransformable => true;

		public double ParamLength => 1.0;

		public bool HasArcLength => false;

		public double ArcLength
		{
			get
			{
				throw new NotImplementedException("Ellipse2.ArcLength");
			}
		}

		public double Area => Math.PI * Extent.x * Extent.y;

		public double ApproxArcLen
		{
			get
			{
				double num = Math.Max(Extent.x, Extent.y);
				double num2 = Math.Min(Extent.x, Extent.y);
				double num3 = (num - num2) / (num + num2);
				double num4 = 3.0 * num3 * num3;
				double num5 = 10.0 + Math.Sqrt(4.0 - num4);
				return Math.PI * (num + num2) * (1.0 + num4 / num5);
			}
		}

		public Ellipse2d(Vector2d center, Vector2d axis0, Vector2d axis1, Vector2d extent)
		{
			Center = center;
			Axis0 = axis0;
			Axis1 = axis1;
			Extent.x = extent.x;
			Extent.y = extent.y;
			IsReversed = false;
		}

		public Ellipse2d(Vector2d center, Vector2d axis0, Vector2d axis1, double extent0, double extent1)
		{
			Center = center;
			Axis0 = axis0;
			Axis1 = axis1;
			Extent.x = extent0;
			Extent.y = extent1;
			IsReversed = false;
		}

		public Ellipse2d(Vector2d center, double rotationAngleDeg, double extent0, double extent1)
		{
			Center = center;
			Matrix2d matrix2d = new Matrix2d(rotationAngleDeg * (Math.PI / 180.0));
			Axis0 = matrix2d * Vector2d.AxisX;
			Axis1 = matrix2d * Vector2d.AxisY;
			Extent = new Vector2d(extent0, extent1);
			IsReversed = false;
		}

		public Matrix2d GetM()
		{
			Vector2d vector2d = Axis0 / Extent[0];
			Vector2d vector2d2 = Axis1 / Extent[1];
			return new Matrix2d(vector2d, vector2d) + new Matrix2d(vector2d2, vector2d2);
		}

		public Matrix2d GetMInverse()
		{
			Vector2d vector2d = Axis0 * Extent[0];
			Vector2d vector2d2 = Axis1 * Extent[1];
			return new Matrix2d(vector2d, vector2d) + new Matrix2d(vector2d2, vector2d2);
		}

		public double[] ToCoefficients()
		{
			Matrix2d A = Matrix2d.Zero;
			Vector2d B = Vector2d.Zero;
			double C = 0.0;
			ToCoefficients(ref A, ref B, ref C);
			double[] array = Convert(A, B, C);
			double num = Math.Abs(array[3]);
			int num2 = 3;
			double num3 = Math.Abs(array[5]);
			if (num3 > num)
			{
				num = num3;
				num2 = 5;
			}
			double num4 = 1.0 / num;
			for (int i = 0; i < 6; i++)
			{
				if (i != num2)
				{
					array[i] *= num4;
				}
				else
				{
					array[i] = 1.0;
				}
			}
			return array;
		}

		public void ToCoefficients(ref Matrix2d A, ref Vector2d B, ref double C)
		{
			Vector2d vector2d = Axis0 / Extent[0];
			Vector2d vector2d2 = Axis1 / Extent[1];
			A = new Matrix2d(vector2d, vector2d) + new Matrix2d(vector2d2, vector2d2);
			B = -2.0 * (A * Center);
			C = A.QForm(Center, Center) - 1.0;
		}

		public bool FromCoefficients(double[] coeff)
		{
			Matrix2d A = Matrix2d.Zero;
			Vector2d B = Vector2d.Zero;
			double C = 0.0;
			Convert(coeff, ref A, ref B, ref C);
			return FromCoefficients(A, B, C);
		}

		public bool FromCoefficients(Matrix2d A, Vector2d B, double C)
		{
			throw new NotImplementedException("Ellipse2.FromCoefficients: need EigenDecomposition");
		}

		public double Evaluate(Vector2d point)
		{
			Vector2d v = point - Center;
			double num = Axis0.Dot(v) / Extent[0];
			double num2 = Axis1.Dot(v) / Extent[1];
			return num * num + num2 * num2 - 1.0;
		}

		public bool Contains(Vector2d point)
		{
			return Evaluate(point) <= 0.0;
		}

		private static void Convert(double[] coeff, ref Matrix2d A, ref Vector2d B, ref double C)
		{
			C = coeff[0];
			B.x = coeff[1];
			B.y = coeff[2];
			A.m00 = coeff[3];
			A.m01 = 0.5 * coeff[4];
			A.m10 = A.m01;
			A.m11 = coeff[5];
		}

		private static double[] Convert(Matrix2d A, Vector2d B, double C)
		{
			return new double[6]
			{
				C,
				B.x,
				B.y,
				A.m00,
				2.0 * A.m01,
				A.m11
			};
		}

		public void Reverse()
		{
			IsReversed = !IsReversed;
		}

		public IParametricCurve2d Clone()
		{
			return new Ellipse2d(Center, Axis0, Axis1, Extent)
			{
				IsReversed = IsReversed
			};
		}

		public void Transform(ITransform2 xform)
		{
			Center = xform.TransformP(Center);
			Axis0 = xform.TransformN(Axis0);
			Axis1 = xform.TransformN(Axis1);
			Extent.x = xform.TransformScalar(Extent.x);
			Extent.y = xform.TransformScalar(Extent.y);
		}

		public Vector2d SampleDeg(double degrees)
		{
			double num = degrees * (Math.PI / 180.0);
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return Center + Extent.x * num2 * Axis0 + Extent.y * num3 * Axis1;
		}

		public Vector2d SampleRad(double radians)
		{
			double num = Math.Cos(radians);
			double num2 = Math.Sin(radians);
			return Center + Extent.x * num * Axis0 + Extent.y * num2 * Axis1;
		}

		public Vector2d SampleT(double t)
		{
			double num = (IsReversed ? ((0.0 - t) * (Math.PI * 2.0)) : (t * (Math.PI * 2.0)));
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return Center + Extent.x * num2 * Axis0 + Extent.y * num3 * Axis1;
		}

		public Vector2d TangentT(double t)
		{
			double num = (IsReversed ? ((0.0 - t) * (Math.PI * 2.0)) : (t * (Math.PI * 2.0)));
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			Vector2d vector2d = (0.0 - Extent.x) * num3 * Axis0 + Extent.y * num2 * Axis1;
			if (IsReversed)
			{
				vector2d = -vector2d;
			}
			vector2d.Normalize();
			return vector2d;
		}

		public Vector2d SampleArcLength(double a)
		{
			throw new NotImplementedException("Ellipse2.SampleArcLength");
		}
	}
	public class EllipseArc2d : IParametricCurve2d
	{
		public Vector2d Center;

		public Vector2d Axis0;

		public Vector2d Axis1;

		public Vector2d Extent;

		public double AngleStartDeg;

		public double AngleEndDeg;

		public bool IsReversed;

		public bool IsClosed => false;

		public double ParamLength => 1.0;

		public bool HasArcLength => false;

		public double ArcLength
		{
			get
			{
				throw new NotImplementedException("Ellipse2.ArcLength");
			}
		}

		public bool IsTransformable => true;

		public EllipseArc2d(Vector2d center, double rotationAngleDeg, double extent0, double extent1, double startDeg, double endDeg)
		{
			Center = center;
			Matrix2d matrix2d = new Matrix2d(rotationAngleDeg * (Math.PI / 180.0));
			Axis0 = matrix2d * Vector2d.AxisX;
			Axis1 = matrix2d * Vector2d.AxisY;
			Extent = new Vector2d(extent0, extent1);
			IsReversed = false;
			AngleStartDeg = startDeg;
			AngleEndDeg = endDeg;
			if (AngleEndDeg < AngleStartDeg)
			{
				AngleEndDeg += 360.0;
			}
		}

		public EllipseArc2d(Vector2d center, Vector2d axis0, Vector2d axis1, Vector2d extent, double startDeg, double endDeg)
		{
			Center = center;
			Axis0 = axis0;
			Axis1 = axis1;
			Extent = extent;
			IsReversed = false;
			AngleStartDeg = startDeg;
			AngleEndDeg = endDeg;
			if (AngleEndDeg < AngleStartDeg)
			{
				AngleEndDeg += 360.0;
			}
		}

		public Vector2d SampleT(double t)
		{
			double num = (IsReversed ? ((1.0 - t) * AngleEndDeg + t * AngleStartDeg) : ((1.0 - t) * AngleStartDeg + t * AngleEndDeg)) * (Math.PI / 180.0);
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			double x = Extent.x;
			double y = Extent.y;
			double num4 = x * num3;
			double num5 = y * num2;
			double num6 = x * y / Math.Sqrt(num5 * num5 + num4 * num4);
			Vector2d vector2d = new Vector2d(num6 * num2, num6 * num3);
			return Center + vector2d.x * Axis0 + vector2d.y * Axis1;
		}

		public Vector2d TangentT(double t)
		{
			double num = (IsReversed ? ((1.0 - t) * AngleEndDeg + t * AngleStartDeg) : ((1.0 - t) * AngleStartDeg + t * AngleEndDeg)) * (Math.PI / 180.0);
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			double x = Extent.x;
			double y = Extent.y;
			double num4 = x * num3;
			double num5 = y * num2;
			double num6 = num4 * num4 + num5 * num5;
			double num7 = Math.Sqrt(num6);
			double num8 = 0.5 * (1.0 / num7) * (2.0 * x * x * num3 * num2 - 2.0 * y * y * num2 * num3);
			double num9 = ((0.0 - x) * y * num3 * num7 - num8 * (x * y * num2)) / num6;
			double num10 = (x * y * num2 * num7 - num8 * (x * y * num3)) / num6;
			Vector2d vector2d = num9 * Axis0 + num10 * Axis1;
			if (IsReversed)
			{
				vector2d = -vector2d;
			}
			vector2d.Normalize();
			return vector2d;
		}

		public Vector2d SampleArcLength(double a)
		{
			throw new NotImplementedException("Ellipse2.SampleArcLength");
		}

		public void Reverse()
		{
			IsReversed = !IsReversed;
		}

		public IParametricCurve2d Clone()
		{
			return new EllipseArc2d(Center, Axis0, Axis1, Extent, AngleStartDeg, AngleEndDeg)
			{
				IsReversed = IsReversed
			};
		}

		public void Transform(ITransform2 xform)
		{
			Center = xform.TransformP(Center);
			Axis0 = xform.TransformN(Axis0);
			Axis1 = xform.TransformN(Axis1);
			Extent.x = xform.TransformScalar(Extent.x);
			Extent.y = xform.TransformScalar(Extent.y);
		}
	}
	public class GeneralPolygon2d : IDuplicatable<GeneralPolygon2d>
	{
		private Polygon2d outer;

		private bool bOuterIsCW;

		private List<Polygon2d> holes = new List<Polygon2d>();

		public Polygon2d Outer
		{
			get
			{
				return outer;
			}
			set
			{
				outer = value;
				bOuterIsCW = outer.IsClockwise;
			}
		}

		private bool HasHoles => holes.Count > 0;

		public ReadOnlyCollection<Polygon2d> Holes => holes.AsReadOnly();

		public double Area
		{
			get
			{
				double num = (bOuterIsCW ? (-1.0) : 1.0);
				double num2 = num * Outer.SignedArea;
				foreach (Polygon2d hole in holes)
				{
					num2 += num * hole.SignedArea;
				}
				return num2;
			}
		}

		public double HoleArea
		{
			get
			{
				double num = 0.0;
				foreach (Polygon2d hole in Holes)
				{
					num += Math.Abs(hole.SignedArea);
				}
				return num;
			}
		}

		public double Perimeter
		{
			get
			{
				double num = outer.Perimeter;
				foreach (Polygon2d hole in holes)
				{
					num += hole.Perimeter;
				}
				return num;
			}
		}

		public AxisAlignedBox2d Bounds
		{
			get
			{
				AxisAlignedBox2d bounds = outer.GetBounds();
				foreach (Polygon2d hole in holes)
				{
					bounds.Contain(hole.GetBounds());
				}
				return bounds;
			}
		}

		public int VertexCount
		{
			get
			{
				int num = outer.VertexCount;
				foreach (Polygon2d hole in holes)
				{
					num += hole.VertexCount;
				}
				return num;
			}
		}

		public GeneralPolygon2d()
		{
		}

		public GeneralPolygon2d(Polygon2d outer)
		{
			Outer = outer;
		}

		public GeneralPolygon2d(GeneralPolygon2d copy)
		{
			outer = new Polygon2d(copy.outer);
			bOuterIsCW = copy.bOuterIsCW;
			holes = new List<Polygon2d>();
			foreach (Polygon2d hole in copy.holes)
			{
				holes.Add(new Polygon2d(hole));
			}
		}

		public GeneralPolygon2d(IEnumerable<DCurve3> curves, out Frame3f frame, out IEnumerable<Vector3d> AllVerticesItr)
		{
			OrthogonalPlaneFit3 orthogonalPlaneFit = new OrthogonalPlaneFit3(curves.ElementAt(0).Vertices);
			frame = new Frame3f(orthogonalPlaneFit.Origin, orthogonalPlaneFit.Normal);
			AllVerticesItr = null;
			int num = 0;
			foreach (DCurve3 curf in curves)
			{
				List<Vector3d> list = curf.Vertices.ToList();
				List<Vector2d> list2 = new List<Vector2d>();
				foreach (Vector3d item in list)
				{
					Vector2f vector2f = frame.ToPlaneUV((Vector3f)item, 3);
					if (num != 0 && !Outer.Contains(vector2f))
					{
						break;
					}
					list2.Add(vector2f);
				}
				Polygon2d polygon2d = new Polygon2d(list2);
				if (num == 0)
				{
					polygon2d = new Polygon2d(list2);
					polygon2d.Reverse();
					Outer = polygon2d;
					list.Reverse();
					AllVerticesItr = list;
				}
				else
				{
					try
					{
						try
						{
							AddHole(polygon2d);
							AllVerticesItr = AllVerticesItr.Concat(list);
						}
						catch (Exception)
						{
							polygon2d.Reverse();
							AddHole(polygon2d);
							list.Reverse();
							AllVerticesItr = AllVerticesItr.Concat(list);
						}
					}
					catch (Exception)
					{
					}
				}
				num++;
			}
		}

		public virtual GeneralPolygon2d Duplicate()
		{
			return new GeneralPolygon2d(this);
		}

		public void AddHole(Polygon2d hole, bool bCheckContainment = true, bool bCheckOrientation = true)
		{
			if (outer == null)
			{
				throw new Exception("GeneralPolygon2d.AddHole: outer polygon not set!");
			}
			if (bCheckContainment)
			{
				if (!outer.Contains(hole))
				{
					throw new Exception("GeneralPolygon2d.AddHole: outer does not contain hole!");
				}
				foreach (Polygon2d hole2 in holes)
				{
					if (hole.Intersects(hole2))
					{
						throw new Exception("GeneralPolygon2D.AddHole: new hole intersects existing hole!");
					}
				}
			}
			if (bCheckOrientation && ((bOuterIsCW && hole.IsClockwise) || (!bOuterIsCW && !hole.IsClockwise)))
			{
				throw new Exception("GeneralPolygon2D.AddHole: new hole has same orientation as outer polygon!");
			}
			holes.Add(hole);
		}

		public void ClearHoles()
		{
			holes.Clear();
		}

		public void Translate(Vector2d translate)
		{
			outer.Translate(translate);
			foreach (Polygon2d hole in holes)
			{
				hole.Translate(translate);
			}
		}

		public void Rotate(Matrix2d rotation, Vector2d origin)
		{
			outer.Rotate(rotation, origin);
			foreach (Polygon2d hole in holes)
			{
				hole.Rotate(rotation, origin);
			}
		}

		public void Scale(Vector2d scale, Vector2d origin)
		{
			outer.Scale(scale, origin);
			foreach (Polygon2d hole in holes)
			{
				hole.Scale(scale, origin);
			}
		}

		public void Transform(Func<Vector2d, Vector2d> transformF)
		{
			outer.Transform(transformF);
			foreach (Polygon2d hole in holes)
			{
				hole.Transform(transformF);
			}
		}

		public void Reverse()
		{
			Outer.Reverse();
			bOuterIsCW = Outer.IsClockwise;
			foreach (Polygon2d hole in Holes)
			{
				hole.Reverse();
			}
		}

		public bool Contains(Vector2d vTest)
		{
			if (!outer.Contains(vTest))
			{
				return false;
			}
			foreach (Polygon2d hole in holes)
			{
				if (hole.Contains(vTest))
				{
					return false;
				}
			}
			return true;
		}

		public bool Contains(Polygon2d poly)
		{
			if (!outer.Contains(poly))
			{
				return false;
			}
			foreach (Polygon2d hole in holes)
			{
				if (hole.Contains(poly))
				{
					return false;
				}
			}
			return true;
		}

		public bool Contains(Segment2d seg)
		{
			if (!outer.Contains(seg))
			{
				return false;
			}
			foreach (Polygon2d hole in holes)
			{
				if (hole.Intersects(seg))
				{
					return false;
				}
			}
			return true;
		}

		public bool Intersects(Polygon2d poly)
		{
			if (outer.Intersects(poly))
			{
				return true;
			}
			foreach (Polygon2d hole in holes)
			{
				if (hole.Intersects(poly))
				{
					return true;
				}
			}
			return false;
		}

		public Vector2d PointAt(int iSegment, double fSegT, int iHoleIndex = -1)
		{
			if (iHoleIndex == -1)
			{
				return outer.PointAt(iSegment, fSegT);
			}
			return holes[iHoleIndex].PointAt(iSegment, fSegT);
		}

		public Segment2d Segment(int iSegment, int iHoleIndex = -1)
		{
			if (iHoleIndex == -1)
			{
				return outer.Segment(iSegment);
			}
			return holes[iHoleIndex].Segment(iSegment);
		}

		public Vector2d GetNormal(int iSegment, double segT, int iHoleIndex = -1)
		{
			if (iHoleIndex == -1)
			{
				return outer.GetNormal(iSegment, segT);
			}
			return holes[iHoleIndex].GetNormal(iSegment, segT);
		}

		public double DistanceSquared(Vector2d p, out int iHoleIndex, out int iNearSeg, out double fNearSegT)
		{
			iNearSeg = (iHoleIndex = -1);
			fNearSegT = double.MaxValue;
			double num = outer.DistanceSquared(p, out iNearSeg, out fNearSegT);
			for (int i = 0; i < Holes.Count; i++)
			{
				int iNearSeg2;
				double fNearSegT2;
				double num2 = Holes[i].DistanceSquared(p, out iNearSeg2, out fNearSegT2);
				if (num2 < num)
				{
					num = num2;
					iHoleIndex = i;
					iNearSeg = iNearSeg2;
					fNearSegT = fNearSegT2;
				}
			}
			return num;
		}

		public IEnumerable<Segment2d> AllSegmentsItr()
		{
			foreach (Segment2d item in outer.SegmentItr())
			{
				yield return item;
			}
			foreach (Polygon2d hole in holes)
			{
				foreach (Segment2d item2 in hole.SegmentItr())
				{
					yield return item2;
				}
			}
		}

		public IEnumerable<Vector2d> AllVerticesItr()
		{
			foreach (Vector2d vertex in outer.Vertices)
			{
				yield return vertex;
			}
			foreach (Polygon2d hole in holes)
			{
				foreach (Vector2d vertex2 in hole.Vertices)
				{
					yield return vertex2;
				}
			}
		}

		public IEnumerable<Index2i> AllEdgesItr()
		{
			int j = Outer.VertexCount;
			for (int i = 0; i < j; i++)
			{
				yield return new Index2i(i, (i != j - 1) ? (i + 1) : 0);
			}
			foreach (Polygon2d hole in Holes)
			{
				for (int i = 0; i < hole.VertexCount; i++)
				{
					yield return new Index2i(j + i, (i != hole.VertexCount - 1) ? (j + i + 1) : j);
				}
				j += hole.VertexCount;
			}
		}

		private NativeArray<int> ToEdges()
		{
			int vertexCount = VertexCount;
			NativeArray<int> result = new NativeArray<int>(vertexCount * 2, Allocator.Persistent);
			int num = 0;
			foreach (Index2i item in AllEdgesItr())
			{
				result[num] = item.a;
				num++;
				result[num] = item.b;
				num++;
			}
			return result;
		}

		private NativeArray<float2> ToHoleSeeds()
		{
			List<Vector2d> list = new List<Vector2d>();
			foreach (Polygon2d hole in Holes)
			{
				list.Add(hole.PointInPolygon());
			}
			return new NativeArray<float2>(list.Select((Vector2d vertex) => (float2)vertex).ToArray(), Allocator.Persistent);
		}

		public Index3i[] GetMesh()
		{
			Triangulator triangulator = new Triangulator(Allocator.Persistent);
			triangulator.Input.Positions = new NativeArray<float2>((from vertex in AllVerticesItr()
				select (float2)vertex).ToArray(), Allocator.Persistent);
			triangulator.Input.ConstraintEdges = ToEdges();
			triangulator.Input.HoleSeeds = ToHoleSeeds();
			triangulator.Settings.RestoreBoundary = true;
			triangulator.Settings.ConstrainEdges = true;
			Triangulator triangulator2 = triangulator;
			try
			{
				triangulator2.Run();
				if (!triangulator2.Output.Status.IsCreated || triangulator2.Output.Status.Value != Triangulator.Status.OK)
				{
					throw new Exception("Could not create Delaunay Triangulation");
				}
				int[] array = triangulator2.Output.Triangles.AsArray().ToArray();
				int num = array.Length / 3;
				Index3i[] array2 = new Index3i[num];
				long num2 = 0L;
				for (int num3 = 0; num3 < num; num3++)
				{
					array2[num3] = new Index3i(array[num2++], array[num2++], array[num2++]);
				}
				triangulator2.Input.Positions.Dispose();
				triangulator2.Input.ConstraintEdges.Dispose();
				triangulator2.Input.HoleSeeds.Dispose();
				triangulator2.Dispose();
				return array2;
			}
			catch
			{
				triangulator2.Input.Positions.Dispose();
				triangulator2.Input.ConstraintEdges.Dispose();
				triangulator2.Input.HoleSeeds.Dispose();
				triangulator2.Dispose();
				return null;
			}
		}

		public void Simplify(double clusterTol = 0.0001, double lineDeviationTol = 0.01, bool bSimplifyStraightLines = true)
		{
			Outer.Simplify(clusterTol, lineDeviationTol, bSimplifyStraightLines);
			foreach (Polygon2d hole in holes)
			{
				hole.Simplify(clusterTol, lineDeviationTol, bSimplifyStraightLines);
			}
		}

		public bool IsOutside(Segment2d seg)
		{
			bool IsOutside = true;
			if (Outer.IsMember(seg, out IsOutside))
			{
				if (IsOutside)
				{
					return true;
				}
				return false;
			}
			foreach (Polygon2d hole in Holes)
			{
				if (hole.IsMember(seg, out IsOutside))
				{
					if (IsOutside)
					{
						return true;
					}
					return false;
				}
			}
			return false;
		}
	}
	public class Hexagon2d
	{
		public enum TopModes
		{
			Flat,
			Tip
		}

		public Vector2d Center;

		public double Radius;

		public TopModes TopMode;

		public bool IsClosed => true;

		public double InnerRadius
		{
			get
			{
				return 1.7320508075688772 * Radius / 2.0;
			}
			set
			{
				Radius = 2.0 * value / 1.7320508075688772;
			}
		}

		public double Width
		{
			get
			{
				if (TopMode != TopModes.Flat)
				{
					return 0.8660254037844386 * Height;
				}
				return Radius * 2.0;
			}
		}

		public double Height
		{
			get
			{
				if (TopMode != TopModes.Flat)
				{
					return Radius * 2.0;
				}
				return 0.8660254037844386 * Width;
			}
		}

		public double VertSpacing
		{
			get
			{
				if (TopMode != TopModes.Flat)
				{
					return Height * 3.0 / 4.0;
				}
				return Height;
			}
		}

		public double HorzSpacing
		{
			get
			{
				if (TopMode != TopModes.Flat)
				{
					return Width;
				}
				return Width * 3.0 / 4.0;
			}
		}

		public AxisAlignedBox2d Bounds => new AxisAlignedBox2d(Center, Width / 2.0, Height / 2.0);

		public Hexagon2d(Vector2d center, double radius, TopModes mode = TopModes.Flat)
		{
			Center = center;
			Radius = radius;
			TopMode = mode;
		}

		public Hexagon2d Clone()
		{
			return new Hexagon2d(Center, Radius, TopMode);
		}

		public Vector2d Corner(int i)
		{
			double num = 60.0 * (double)i;
			if (TopMode == TopModes.Tip)
			{
				num += 30.0;
			}
			double num2 = num * (Math.PI / 180.0);
			return new Vector2d(Center.x + Radius * Math.Cos(num2), Center.y + Radius * Math.Sin(num2));
		}
	}
