	public class LaplacianCurveDeformer
	{
		public struct SoftConstraintV
		{
			public Vector3d Position;

			public double Weight;

			public bool PostFix;
		}

		public DCurve3 Curve;

		public bool SolveX = true;

		public bool SolveY = true;

		public bool SolveZ = true;

		public bool ConvergeFailed;

		private PackedSparseMatrix PackedM;

		private int N;

		private int[] ToCurveV;

		private int[] ToIndex;

		private double[] Px;

		private double[] Py;

		private double[] Pz;

		private int[] nbr_counts;

		private double[] MLx;

		private double[] MLy;

		private double[] MLz;

		private Dictionary<int, SoftConstraintV> SoftConstraints = new Dictionary<int, SoftConstraintV>();

		private bool HavePostFixedConstraints;

		private bool need_solve_update;

		private DiagonalMatrix WeightsM;

		private double[] Cx;

		private double[] Cy;

		private double[] Cz;

		private double[] Bx;

		private double[] By;

		private double[] Bz;

		private DiagonalMatrix Preconditioner;

		public bool UseSoftConstraintNormalEquations = true;

		private double[] Sx;

		private double[] Sy;

		private double[] Sz;

		public LaplacianCurveDeformer(DCurve3 curve)
		{
			Curve = curve;
		}

		public void SetConstraint(int vID, Vector3d targetPos, double weight, bool bForceToFixedPos = false)
		{
			SoftConstraints[vID] = new SoftConstraintV
			{
				Position = targetPos,
				Weight = weight,
				PostFix = bForceToFixedPos
			};
			HavePostFixedConstraints |= bForceToFixedPos;
			need_solve_update = true;
		}

		public bool IsConstrained(int vID)
		{
			return SoftConstraints.ContainsKey(vID);
		}

		public void ClearConstraints()
		{
			SoftConstraints.Clear();
			HavePostFixedConstraints = false;
			need_solve_update = true;
		}

		public void Initialize()
		{
			int vertexCount = Curve.VertexCount;
			ToCurveV = new int[vertexCount];
			ToIndex = new int[vertexCount];
			N = 0;
			for (int i = 0; i < vertexCount; i++)
			{
				int num = i;
				ToCurveV[N] = num;
				ToIndex[num] = N;
				N++;
			}
			Px = new double[N];
			Py = new double[N];
			Pz = new double[N];
			nbr_counts = new int[N];
			SymmetricSparseMatrix symmetricSparseMatrix = new SymmetricSparseMatrix();
			for (int j = 0; j < N; j++)
			{
				int i2 = ToCurveV[j];
				Vector3d vertex = Curve.GetVertex(i2);
				Px[j] = vertex.x;
				Py[j] = vertex.y;
				Pz[j] = vertex.z;
				nbr_counts[j] = ((j == 0 || j == N - 1) ? 1 : 2);
			}
			for (int k = 0; k < N; k++)
			{
				int num2 = ToCurveV[k];
				_ = nbr_counts[k];
				Index2i index2i = Curve.Neighbours(num2);
				double num3 = 0.0;
				for (int l = 0; l < 2; l++)
				{
					int num4 = index2i[l];
					if (num4 != -1)
					{
						int num5 = ToIndex[num4];
						_ = nbr_counts[num5];
						double num6 = -1.0;
						symmetricSparseMatrix.Set(k, num5, num6);
						num3 += num6;
					}
				}
				num3 = 0.0 - num3;
				symmetricSparseMatrix.Set(num2, num2, num3);
			}
			if (UseSoftConstraintNormalEquations)
			{
				PackedM = symmetricSparseMatrix.SquarePackedParallel();
			}
			else
			{
				PackedM = new PackedSparseMatrix(symmetricSparseMatrix);
			}
			MLx = new double[N];
			MLy = new double[N];
			MLz = new double[N];
			PackedM.Multiply(Px, MLx);
			PackedM.Multiply(Py, MLy);
			PackedM.Multiply(Pz, MLz);
			Preconditioner = new DiagonalMatrix(N);
			WeightsM = new DiagonalMatrix(N);
			Cx = new double[N];
			Cy = new double[N];
			Cz = new double[N];
			Bx = new double[N];
			By = new double[N];
			Bz = new double[N];
			Sx = new double[N];
			Sy = new double[N];
			Sz = new double[N];
			need_solve_update = true;
			UpdateForSolve();
		}

		private void UpdateForSolve()
		{
			if (!need_solve_update)
			{
				return;
			}
			WeightsM.Clear();
			Array.Clear(Cx, 0, N);
			Array.Clear(Cy, 0, N);
			Array.Clear(Cz, 0, N);
			foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
			{
				int key = softConstraint.Key;
				int num = ToIndex[key];
				double num2 = softConstraint.Value.Weight;
				if (UseSoftConstraintNormalEquations)
				{
					num2 *= num2;
				}
				WeightsM.Set(num, num, num2);
				Vector3d position = softConstraint.Value.Position;
				Cx[num] = num2 * position.x;
				Cy[num] = num2 * position.y;
				Cz[num] = num2 * position.z;
			}
			for (int i = 0; i < N; i++)
			{
				Bx[i] = MLx[i] + Cx[i];
				By[i] = MLy[i] + Cy[i];
				Bz[i] = MLz[i] + Cz[i];
			}
			for (int j = 0; j < N; j++)
			{
				double num3 = PackedM[j, j] + WeightsM[j, j];
				Preconditioner.Set(j, j, 1.0 / num3);
			}
			need_solve_update = false;
		}

		public bool SolveMultipleCG(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			Array.Copy(Px, Sx, N);
			Array.Copy(Py, Sy, N);
			Array.Copy(Pz, Sz, N);
			Action<double[], double[]> multiplyF = delegate(double[] X, double[] B)
			{
				PackedM.Multiply_Parallel(X, B);
				for (int i = 0; i < N; i++)
				{
					B[i] += WeightsM[i, i] * X[i];
				}
			};
			List<SparseSymmetricCG> Solvers = new List<SparseSymmetricCG>();
			if (SolveX)
			{
				Solvers.Add(new SparseSymmetricCG
				{
					B = Bx,
					X = Sx,
					MultiplyF = multiplyF,
					PreconditionMultiplyF = Preconditioner.Multiply,
					UseXAsInitialGuess = true
				});
			}
			if (SolveY)
			{
				Solvers.Add(new SparseSymmetricCG
				{
					B = By,
					X = Sy,
					MultiplyF = multiplyF,
					PreconditionMultiplyF = Preconditioner.Multiply,
					UseXAsInitialGuess = true
				});
			}
			if (SolveZ)
			{
				Solvers.Add(new SparseSymmetricCG
				{
					B = Bz,
					X = Sz,
					MultiplyF = multiplyF,
					PreconditionMultiplyF = Preconditioner.Multiply,
					UseXAsInitialGuess = true
				});
			}
			bool[] ok = new bool[Solvers.Count];
			gParallel.ForEach(Interval1i.Range(Solvers.Count), delegate(int i)
			{
				ok[i] = Solvers[i].Solve();
			});
			ConvergeFailed = false;
			bool[] array = ok;
			for (int num = 0; num < array.Length; num++)
			{
				if (!array[num])
				{
					ConvergeFailed = true;
				}
			}
			for (int num2 = 0; num2 < N; num2++)
			{
				int num3 = ToCurveV[num2];
				Result[num3] = new Vector3d(Sx[num2], Sy[num2], Sz[num2]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool SolveMultipleRHS(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			double[][] b = BufferUtil.InitNxM(3, N, new double[3][] { Bx, By, Bz });
			double[][] array = BufferUtil.InitNxM(3, N, new double[3][] { Px, Py, Pz });
			Action<double[][], double[][]> multiplyF = delegate(double[][] Xt, double[][] Bt)
			{
				PackedM.Multiply_Parallel_3(Xt, Bt);
				gParallel.ForEach(Interval1i.Range(3), delegate(int j)
				{
					BufferUtil.MultiplyAdd(Bt[j], WeightsM.D, Xt[j]);
				});
			};
			if (!new SparseSymmetricCGMultipleRHS
			{
				B = b,
				X = array,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = null,
				UseXAsInitialGuess = true
			}.Solve())
			{
				return false;
			}
			for (int num = 0; num < N; num++)
			{
				int num2 = ToCurveV[num];
				Result[num2] = new Vector3d(array[0][num], array[1][num], array[2][num]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool Solve(Vector3d[] Result)
		{
			if (Curve.VertexCount < 10000)
			{
				return SolveMultipleCG(Result);
			}
			return SolveMultipleRHS(Result);
		}

		public bool SolveAndUpdateCurve()
		{
			int vertexCount = Curve.VertexCount;
			Vector3d[] array = new Vector3d[vertexCount];
			if (!Solve(array))
			{
				return false;
			}
			for (int i = 0; i < vertexCount; i++)
			{
				Curve[i] = array[i];
			}
			return true;
		}
	}
	public class NURBSCurve2 : BaseCurve2, IParametricCurve2d
	{
		public struct CurveDerivatives
		{
			public Vector2d p;

			public Vector2d d1;

			public Vector2d d2;

			public Vector2d d3;

			public bool bPosition;

			public bool bDer1;

			public bool bDer2;

			public bool bDer3;

			public void init()
			{
				bPosition = (bDer1 = (bDer2 = (bDer3 = false)));
			}

			public void init(bool pos, bool der1, bool der2, bool der3)
			{
				bPosition = pos;
				bDer1 = der1;
				bDer2 = der2;
				bDer3 = der3;
			}
		}

		protected int mNumCtrlPoints;

		protected Vector2d[] mCtrlPoint;

		protected double[] mCtrlWeight;

		protected bool mLoop;

		protected BSplineBasis mBasis;

		protected int mReplicate;

		protected bool is_closed;

		public bool IsClosed
		{
			get
			{
				return is_closed;
			}
			set
			{
				is_closed = value;
			}
		}

		public double ParamLength => mTMax - mTMin;

		public bool HasArcLength => true;

		public double ArcLength => GetTotalLength();

		public bool IsTransformable => true;

		public NURBSCurve2(int numCtrlPoints, Vector2d[] ctrlPoint, double[] ctrlWeight, int degree, bool loop, bool open)
			: base(0.0, 1.0)
		{
			if (numCtrlPoints < 2)
			{
				throw new Exception("NURBSCurve2(): only received " + numCtrlPoints + " control points!");
			}
			if (degree < 1 || degree > numCtrlPoints - 1)
			{
				throw new Exception("NURBSCurve2(): invalid degree " + degree);
			}
			mLoop = loop;
			mNumCtrlPoints = numCtrlPoints;
			mReplicate = (loop ? (open ? 1 : degree) : 0);
			CreateControl(ctrlPoint, ctrlWeight);
			mBasis = new BSplineBasis(mNumCtrlPoints + mReplicate, degree, open);
		}

		public NURBSCurve2(int numCtrlPoints, Vector2d[] ctrlPoint, double[] ctrlWeight, int degree, bool loop, double[] knot, bool bIsInteriorKnot = true)
			: base(0.0, 1.0)
		{
			if (numCtrlPoints < 2)
			{
				throw new Exception("NURBSCurve2(): only received " + numCtrlPoints + " control points!");
			}
			if (degree < 1 || degree > numCtrlPoints - 1)
			{
				throw new Exception("NURBSCurve2(): invalid degree " + degree);
			}
			if (loop)
			{
				throw new Exception("NURBSCUrve2(): loop mode is broken?");
			}
			mLoop = loop;
			mNumCtrlPoints = numCtrlPoints;
			mReplicate = (loop ? 1 : 0);
			CreateControl(ctrlPoint, ctrlWeight);
			mBasis = new BSplineBasis(mNumCtrlPoints + mReplicate, degree, knot, bIsInteriorKnot);
		}

		protected NURBSCurve2()
			: base(0.0, 1.0)
		{
		}

		public int GetNumCtrlPoints()
		{
			return mNumCtrlPoints;
		}

		public int GetDegree()
		{
			return mBasis.GetDegree();
		}

		public bool IsUniform()
		{
			return mBasis.IsUniform();
		}

		public void SetControlPoint(int i, Vector2d ctrl)
		{
			if (0 <= i && i < mNumCtrlPoints)
			{
				mCtrlPoint[i] = ctrl;
				if (i < mReplicate)
				{
					mCtrlPoint[mNumCtrlPoints + i] = ctrl;
				}
			}
		}

		public Vector2d GetControlPoint(int i)
		{
			if (0 <= i && i < mNumCtrlPoints)
			{
				return mCtrlPoint[i];
			}
			return new Vector2d(double.MaxValue, double.MaxValue);
		}

		public void SetControlWeight(int i, double weight)
		{
			if (0 <= i && i < mNumCtrlPoints)
			{
				mCtrlWeight[i] = weight;
				if (i < mReplicate)
				{
					mCtrlWeight[mNumCtrlPoints + i] = weight;
				}
			}
		}

		public double GetControlWeight(int i)
		{
			if (0 <= i && i < mNumCtrlPoints)
			{
				return mCtrlWeight[i];
			}
			return double.MaxValue;
		}

		public void SetKnot(int i, double value)
		{
			mBasis.SetInteriorKnot(i, value);
		}

		public double GetKnot(int i)
		{
			return mBasis.GetInteriorKnot(i);
		}

		public override Vector2d GetPosition(double t)
		{
			int minIndex = 0;
			int maxIndex = 0;
			mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
			if (maxIndex >= mCtrlWeight.Length)
			{
				maxIndex = mCtrlWeight.Length - 1;
			}
			Vector2d zero = Vector2d.Zero;
			double num = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD0(i) * mCtrlWeight[i];
				zero += num2 * mCtrlPoint[i];
				num += num2;
			}
			return 1.0 / num * zero;
		}

		public override Vector2d GetFirstDerivative(double t)
		{
			int minIndex = 0;
			int maxIndex = 0;
			mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
			mBasis.Compute(t, 1, ref minIndex, ref maxIndex);
			if (maxIndex >= mCtrlWeight.Length)
			{
				maxIndex = mCtrlWeight.Length - 1;
			}
			Vector2d zero = Vector2d.Zero;
			double num = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD0(i) * mCtrlWeight[i];
				zero += num2 * mCtrlPoint[i];
				num += num2;
			}
			double num3 = 1.0 / num;
			Vector2d vector2d = num3 * zero;
			Vector2d zero2 = Vector2d.Zero;
			double num4 = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD1(i) * mCtrlWeight[i];
				zero2 += num2 * mCtrlPoint[i];
				num4 += num2;
			}
			return num3 * (zero2 - num4 * vector2d);
		}

		public override Vector2d GetSecondDerivative(double t)
		{
			CurveDerivatives result = default(CurveDerivatives);
			result.init(pos: false, der1: false, der2: true, der3: false);
			Get(t, ref result);
			return result.d2;
		}

		public override Vector2d GetThirdDerivative(double t)
		{
			CurveDerivatives result = default(CurveDerivatives);
			result.init(pos: false, der1: false, der2: false, der3: true);
			Get(t, ref result);
			return result.d3;
		}

		public void Get(double t, ref CurveDerivatives result)
		{
			int minIndex = 0;
			int maxIndex = 0;
			if (result.bDer3)
			{
				mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 1, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 2, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 3, ref minIndex, ref maxIndex);
			}
			else if (result.bDer2)
			{
				mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 1, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 2, ref minIndex, ref maxIndex);
			}
			else if (result.bDer1)
			{
				mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
				mBasis.Compute(t, 1, ref minIndex, ref maxIndex);
			}
			else
			{
				mBasis.Compute(t, 0, ref minIndex, ref maxIndex);
			}
			if (maxIndex >= mCtrlWeight.Length)
			{
				maxIndex = mCtrlWeight.Length - 1;
			}
			Vector2d zero = Vector2d.Zero;
			double num = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD0(i) * mCtrlWeight[i];
				zero += num2 * mCtrlPoint[i];
				num += num2;
			}
			double num3 = 1.0 / num;
			Vector2d vector2d = (result.p = num3 * zero);
			result.bPosition = true;
			if (!result.bDer1 && !result.bDer2 && !result.bDer3)
			{
				return;
			}
			Vector2d zero2 = Vector2d.Zero;
			double num4 = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD1(i) * mCtrlWeight[i];
				zero2 += num2 * mCtrlPoint[i];
				num4 += num2;
			}
			Vector2d vector2d2 = (result.d1 = num3 * (zero2 - num4 * vector2d));
			result.bDer1 = true;
			if (!result.bDer2 && !result.bDer3)
			{
				return;
			}
			Vector2d zero3 = Vector2d.Zero;
			double num5 = 0.0;
			for (int i = minIndex; i <= maxIndex; i++)
			{
				double num2 = mBasis.GetD2(i) * mCtrlWeight[i];
				zero3 += num2 * mCtrlPoint[i];
				num5 += num2;
			}
			Vector2d vector2d3 = (result.d2 = num3 * (zero3 - 2.0 * num4 * vector2d2 - num5 * vector2d));
			result.bDer2 = true;
			if (result.bDer3)
			{
				Vector2d zero4 = Vector2d.Zero;
				double num6 = 0.0;
				for (int i = minIndex; i <= maxIndex; i++)
				{
					double num2 = mBasis.GetD3(i) * mCtrlWeight[i];
					zero4 += num2 * mCtrlPoint[i];
					num6 += num2;
				}
				result.d3 = num3 * (zero4 - 3.0 * num4 * vector2d3 - 3.0 * num5 * vector2d2 - num6 * vector2d);
			}
		}

		public BSplineBasis GetBasis()
		{
			return mBasis;
		}

		protected void CreateControl(Vector2d[] ctrlPoint, double[] ctrlWeight)
		{
			int num = mNumCtrlPoints + mReplicate;
			mCtrlPoint = new Vector2d[num];
			Array.Copy(ctrlPoint, mCtrlPoint, mNumCtrlPoints);
			mCtrlWeight = new double[num];
			Array.Copy(ctrlWeight, mCtrlWeight, mNumCtrlPoints);
			for (int i = 0; i < mReplicate; i++)
			{
				mCtrlPoint[mNumCtrlPoints + i] = ctrlPoint[i];
				mCtrlWeight[mNumCtrlPoints + i] = ctrlWeight[i];
			}
		}

		public Vector2d SampleT(double t)
		{
			return GetPosition(t);
		}

		public Vector2d TangentT(double t)
		{
			return GetFirstDerivative(t).Normalized;
		}

		public Vector2d SampleArcLength(double a)
		{
			double time = GetTime(a);
			return GetPosition(time);
		}

		public void Reverse()
		{
			throw new NotSupportedException("NURBSCurve2.Reverse: how to reverse?!?");
		}

		public IParametricCurve2d Clone()
		{
			return new NURBSCurve2
			{
				mNumCtrlPoints = mNumCtrlPoints,
				mCtrlPoint = (Vector2d[])mCtrlPoint.Clone(),
				mCtrlWeight = (double[])mCtrlWeight.Clone(),
				mLoop = mLoop,
				mBasis = mBasis.Clone(),
				mReplicate = mReplicate,
				is_closed = is_closed
			};
		}

		public void Transform(ITransform2 xform)
		{
			for (int i = 0; i < mCtrlPoint.Length; i++)
			{
				mCtrlPoint[i] = xform.TransformP(mCtrlPoint[i]);
			}
		}

		public List<double> GetParamIntervals()
		{
			List<double> list = new List<double>();
			list.Add(0.0);
			for (int i = 0; i < mBasis.KnotCount; i++)
			{
				double knot = mBasis.GetKnot(i);
				if (knot != list.Last())
				{
					list.Add(knot);
				}
			}
			if (list.Last() != 1.0)
			{
				list.Add(1.0);
			}
			return list;
		}

		public List<double> GetContinuousParamIntervals()
		{
			List<double> list = new List<double>();
			double num = -1.0;
			int num2 = 0;
			for (int i = 0; i < mBasis.KnotCount; i++)
			{
				double knot = mBasis.GetKnot(i);
				if (knot == num)
				{
					num2++;
					continue;
				}
				if (num2 > 1)
				{
					list.Add(num);
				}
				num = knot;
				num2 = 1;
			}
			if (list.Last() != 1.0)
			{
				list.Add(1.0);
			}
			return list;
		}
	}
	public class ParametricCurveSequence2 : IParametricCurve2d, IMultiCurve2d
	{
		private List<IParametricCurve2d> curves;

		private bool closed;

		public int Count => curves.Count;

		public ReadOnlyCollection<IParametricCurve2d> Curves => curves.AsReadOnly();

		public bool IsClosed
		{
			get
			{
				return closed;
			}
			set
			{
				closed = value;
			}
		}

		public double ParamLength
		{
			get
			{
				double num = 0.0;
				foreach (IParametricCurve2d curf in Curves)
				{
					num += curf.ParamLength;
				}
				return num;
			}
		}

		public bool HasArcLength
		{
			get
			{
				foreach (IParametricCurve2d curf in Curves)
				{
					if (!curf.HasArcLength)
					{
						return false;
					}
				}
				return true;
			}
		}

		public double ArcLength
		{
			get
			{
				double num = 0.0;
				foreach (IParametricCurve2d curf in Curves)
				{
					num += curf.ArcLength;
				}
				return num;
			}
		}

		public bool IsTransformable => true;

		public ParametricCurveSequence2()
		{
			curves = new List<IParametricCurve2d>();
		}

		public ParametricCurveSequence2(IEnumerable<IParametricCurve2d> curvesIn, bool isClosed = false)
		{
			curves = new List<IParametricCurve2d>(curvesIn);
			closed = true;
		}

		public void Append(IParametricCurve2d c)
		{
			curves.Add(c);
		}

		public void Prepend(IParametricCurve2d c)
		{
			curves.Insert(0, c);
		}

		public Vector2d SampleT(double t)
		{
			double num = 0.0;
			for (int i = 0; i < Curves.Count; i++)
			{
				double paramLength = curves[i].ParamLength;
				if (t <= num + paramLength)
				{
					double t2 = t - num;
					return curves[i].SampleT(t2);
				}
				num += paramLength;
			}
			throw new ArgumentException("ParametricCurveSequence2.SampleT: argument out of range");
		}

		public Vector2d TangentT(double t)
		{
			double num = 0.0;
			for (int i = 0; i < Curves.Count; i++)
			{
				double paramLength = curves[i].ParamLength;
				if (t <= num + paramLength)
				{
					double t2 = t - num;
					return curves[i].TangentT(t2);
				}
				num += paramLength;
			}
			throw new ArgumentException("ParametricCurveSequence2.SampleT: argument out of range");
		}

		public Vector2d SampleArcLength(double a)
		{
			double num = 0.0;
			for (int i = 0; i < Curves.Count; i++)
			{
				double arcLength = curves[i].ArcLength;
				if (a <= num + arcLength)
				{
					double a2 = a - num;
					return curves[i].SampleArcLength(a2);
				}
				num += arcLength;
			}
			throw new ArgumentException("ParametricCurveSequence2.SampleArcLength: argument out of range");
		}

		public void Reverse()
		{
			foreach (IParametricCurve2d curf in curves)
			{
				curf.Reverse();
			}
			curves.Reverse();
		}

		public IParametricCurve2d Clone()
		{
			ParametricCurveSequence2 parametricCurveSequence = new ParametricCurveSequence2();
			parametricCurveSequence.closed = closed;
			parametricCurveSequence.curves = new List<IParametricCurve2d>();
			foreach (IParametricCurve2d curf in curves)
			{
				parametricCurveSequence.curves.Add(curf.Clone());
			}
			return parametricCurveSequence;
		}

		public void Transform(ITransform2 xform)
		{
			foreach (IParametricCurve2d curf in curves)
			{
				curf.Transform(xform);
			}
		}
	}
	public struct ComplexSegment2d
	{
		public Segment2d seg;

		public bool isClosed;

		public PlanarComplex.Element element;
	}
	public struct ComplexEndpoint2d
	{
		public Vector2d v;

		public bool isStart;

		public PlanarComplex.SmoothCurveElement element;
	}
	public class PlanarComplex
	{
		public abstract class Element
		{
			public IParametricCurve2d source;

			public int ID;

			private Colorf color = Colorf.Black;

			private bool has_set_color;

			public Colorf Color
			{
				get
				{
					return color;
				}
				set
				{
					color = value;
					has_set_color = true;
				}
			}

			public bool HasSetColor => has_set_color;

			protected void copy_to(Element new_element)
			{
				new_element.ID = ID;
				new_element.color = color;
				new_element.has_set_color = has_set_color;
				if (source != null)
				{
					new_element.source = source.Clone();
				}
			}

			public abstract IEnumerable<Segment2d> SegmentItr();

			public abstract AxisAlignedBox2d Bounds();

			public abstract Element Clone();
		}

		public class SmoothCurveElement : Element
		{
			public PolyLine2d polyLine;

			public override IEnumerable<Segment2d> SegmentItr()
			{
				return polyLine.SegmentItr();
			}

			public override AxisAlignedBox2d Bounds()
			{
				return polyLine.GetBounds();
			}

			public override Element Clone()
			{
				SmoothCurveElement smoothCurveElement = new SmoothCurveElement();
				copy_to(smoothCurveElement);
				smoothCurveElement.polyLine = ((polyLine == source) ? (smoothCurveElement.source as PolyLine2d) : new PolyLine2d(polyLine));
				return smoothCurveElement;
			}
		}

		public class SmoothLoopElement : Element
		{
			public Polygon2d polygon;

			public override IEnumerable<Segment2d> SegmentItr()
			{
				return polygon.SegmentItr();
			}

			public override AxisAlignedBox2d Bounds()
			{
				return polygon.GetBounds();
			}

			public override Element Clone()
			{
				SmoothLoopElement smoothLoopElement = new SmoothLoopElement();
				copy_to(smoothLoopElement);
				smoothLoopElement.polygon = ((polygon == source) ? (smoothLoopElement.source as Polygon2d) : new Polygon2d(polygon));
				return smoothLoopElement;
			}
		}

		public class GeneralSolid
		{
			public Element Outer;

			public List<Element> Holes = new List<Element>();
		}

		public class SolidRegionInfo
		{
			public List<GeneralPolygon2d> Polygons;

			public List<PlanarSolid2d> Solids;

			public List<GeneralSolid> PolygonsSources;

			public AxisAlignedBox2d Bounds
			{
				get
				{
					AxisAlignedBox2d empty = AxisAlignedBox2d.Empty;
					foreach (GeneralPolygon2d polygon in Polygons)
					{
						empty.Contain(polygon.Bounds);
					}
					return empty;
				}
			}

			public double Area
			{
				get
				{
					double num = 0.0;
					foreach (GeneralPolygon2d polygon in Polygons)
					{
						num += polygon.Area;
					}
					return num;
				}
			}

			public double HolesArea
			{
				get
				{
					double num = 0.0;
					foreach (GeneralPolygon2d polygon in Polygons)
					{
						foreach (Polygon2d hole in polygon.Holes)
						{
							num += Math.Abs(hole.SignedArea);
						}
					}
					return num;
				}
			}
		}

		public struct FindSolidsOptions
		{
			public double SimplifyDeviationTolerance;

			public bool WantCurveSolids;

			public bool TrustOrientations;

			public bool AllowOverlappingHoles;

			public static readonly FindSolidsOptions Default = new FindSolidsOptions
			{
				SimplifyDeviationTolerance = 0.1,
				WantCurveSolids = true,
				TrustOrientations = false,
				AllowOverlappingHoles = false
			};

			public static readonly FindSolidsOptions SortPolygons = new FindSolidsOptions
			{
				SimplifyDeviationTolerance = 0.0,
				WantCurveSolids = false,
				TrustOrientations = true,
				AllowOverlappingHoles = false
			};
		}

		public class ClosedLoopsInfo
		{
			public List<Polygon2d> Polygons;

			public List<IParametricCurve2d> Loops;

			public AxisAlignedBox2d Bounds
			{
				get
				{
					AxisAlignedBox2d empty = AxisAlignedBox2d.Empty;
					foreach (Polygon2d polygon in Polygons)
					{
						empty.Contain(polygon.GetBounds());
					}
					return empty;
				}
			}
		}

		public class OpenCurvesInfo
		{
			public List<PolyLine2d> Polylines;

			public List<IParametricCurve2d> Curves;

			public AxisAlignedBox2d Bounds
			{
				get
				{
					AxisAlignedBox2d empty = AxisAlignedBox2d.Empty;
					foreach (PolyLine2d polyline in Polylines)
					{
						empty.Contain(polyline.GetBounds());
					}
					return empty;
				}
			}
		}

		public double DistanceAccuracy = 0.1;

		public double AngleAccuracyDeg = 5.0;

		public double SpacingT = 0.01;

		public bool MinimizeSampling;

		private int id_generator = 1;

		private List<Element> vElements;

		public int ElementCount => vElements.Count;

		public PlanarComplex()
		{
			vElements = new List<Element>();
		}

		public Element Add(IParametricCurve2d curve)
		{
			if (curve.IsClosed)
			{
				SmoothLoopElement smoothLoopElement = new SmoothLoopElement();
				smoothLoopElement.ID = id_generator++;
				smoothLoopElement.source = curve;
				UpdateSampling(smoothLoopElement);
				vElements.Add(smoothLoopElement);
				return smoothLoopElement;
			}
			SmoothCurveElement smoothCurveElement = new SmoothCurveElement();
			smoothCurveElement.ID = id_generator++;
			smoothCurveElement.source = curve;
			UpdateSampling(smoothCurveElement);
			vElements.Add(smoothCurveElement);
			return smoothCurveElement;
		}

		public Element Add(Polygon2d poly)
		{
			SmoothLoopElement smoothLoopElement = new SmoothLoopElement();
			smoothLoopElement.ID = id_generator++;
			smoothLoopElement.source = new Polygon2DCurve
			{
				Polygon = poly
			};
			smoothLoopElement.polygon = new Polygon2d(poly);
			vElements.Add(smoothLoopElement);
			return smoothLoopElement;
		}

		public Element Add(PolyLine2d pline)
		{
			SmoothCurveElement smoothCurveElement = new SmoothCurveElement();
			smoothCurveElement.ID = id_generator++;
			smoothCurveElement.source = new PolyLine2DCurve
			{
				Polyline = pline
			};
			smoothCurveElement.polyLine = new PolyLine2d(pline);
			vElements.Add(smoothCurveElement);
			return smoothCurveElement;
		}

		public void Remove(Element e)
		{
			vElements.Remove(e);
		}

		private void UpdateSampling(SmoothCurveElement c)
		{
			if (MinimizeSampling && c.source is Segment2d)
			{
				c.polyLine = new PolyLine2d();
				c.polyLine.AppendVertex(((Segment2d)(object)c.source).P0);
				c.polyLine.AppendVertex(((Segment2d)(object)c.source).P1);
			}
			else
			{
				c.polyLine = new PolyLine2d(CurveSampler2.AutoSample(c.source, DistanceAccuracy, SpacingT));
			}
		}

		private void UpdateSampling(SmoothLoopElement l)
		{
			l.polygon = new Polygon2d(CurveSampler2.AutoSample(l.source, DistanceAccuracy, SpacingT));
		}

		public void Reverse(SmoothCurveElement c)
		{
			c.source.Reverse();
			UpdateSampling(c);
		}

		public IEnumerable<ComplexSegment2d> AllSegmentsItr()
		{
			foreach (Element e in vElements)
			{
				ComplexSegment2d s = default(ComplexSegment2d);
				if (e is SmoothLoopElement)
				{
					s.isClosed = true;
				}
				else if (e is SmoothCurveElement)
				{
					s.isClosed = false;
				}
				foreach (Segment2d item in e.SegmentItr())
				{
					s.seg = item;
					s.element = e;
					yield return s;
				}
			}
		}

		public IEnumerable<Element> ElementsItr()
		{
			foreach (Element vElement in vElements)
			{
				yield return vElement;
			}
		}

		public IEnumerable<SmoothLoopElement> LoopsItr()
		{
			foreach (Element vElement in vElements)
			{
				if (vElement is SmoothLoopElement)
				{
					yield return vElement as SmoothLoopElement;
				}
			}
		}

		public IEnumerable<SmoothCurveElement> CurvesItr()
		{
			foreach (Element vElement in vElements)
			{
				if (vElement is SmoothCurveElement)
				{
					yield return vElement as SmoothCurveElement;
				}
			}
		}

		public bool HasOpenCurves()
		{
			foreach (Element vElement in vElements)
			{
				if (vElement is SmoothCurveElement)
				{
					return true;
				}
			}
			return false;
		}

		public IEnumerable<IParametricCurve2d> LoopLeafComponentsItr()
		{
			foreach (Element vElement in vElements)
			{
				if (!(vElement is SmoothLoopElement))
				{
					continue;
				}
				IParametricCurve2d source = vElement.source;
				if (source is IMultiCurve2d)
				{
					foreach (IParametricCurve2d item in CurveUtils2.LeafCurvesIteration(source))
					{
						yield return item;
					}
				}
				else
				{
					yield return source;
				}
			}
		}

		public IEnumerable<ComplexEndpoint2d> EndpointsItr()
		{
			foreach (Element vElement in vElements)
			{
				if (vElement is SmoothCurveElement)
				{
					SmoothCurveElement s = vElement as SmoothCurveElement;
					yield return new ComplexEndpoint2d
					{
						v = s.polyLine.Start,
						isStart = true,
						element = s
					};
					yield return new ComplexEndpoint2d
					{
						v = s.polyLine.End,
						isStart = false,
						element = s
					};
				}
			}
		}

		public AxisAlignedBox2d Bounds()
		{
			AxisAlignedBox2d empty = AxisAlignedBox2d.Empty;
			foreach (Element vElement in vElements)
			{
				empty.Contain(vElement.Bounds());
			}
			return empty;
		}

		public void SplitAllLoops()
		{
			List<Element> list = new List<Element>();
			List<IParametricCurve2d> list2 = new List<IParametricCurve2d>();
			foreach (SmoothLoopElement item in LoopsItr())
			{
				if (item.source is IMultiCurve2d)
				{
					list.Add(item);
					find_sub_elements(item.source as IMultiCurve2d, list2);
				}
			}
			foreach (Element item2 in list)
			{
				Remove(item2);
			}
			foreach (IParametricCurve2d item3 in list2)
			{
				Add(item3);
			}
		}

		private void find_sub_elements(IMultiCurve2d multicurve, List<IParametricCurve2d> vAdd)
		{
			foreach (IParametricCurve2d curf in multicurve.Curves)
			{
				if (curf is IMultiCurve2d)
				{
					find_sub_elements(curf as IMultiCurve2d, vAdd);
				}
				else
				{
					vAdd.Add(curf);
				}
			}
		}

		public bool JoinElements(ComplexEndpoint2d a, ComplexEndpoint2d b, double loop_tolerance = 1E-08)
		{
			if (a.element == b.element)
			{
				throw new Exception("PlanarComplex.ChainElements: same curve!!");
			}
			SmoothCurveElement element = a.element;
			SmoothCurveElement element2 = b.element;
			SmoothCurveElement smoothCurveElement = null;
			if (!a.isStart && b.isStart)
			{
				vElements.Remove(element2);
				append(element, element2);
				smoothCurveElement = element;
			}
			else if (a.isStart && !b.isStart)
			{
				vElements.Remove(element);
				append(element2, element);
				smoothCurveElement = element2;
			}
			else if (!a.isStart)
			{
				element2.source.Reverse();
				vElements.Remove(element2);
				append(element, element2);
				smoothCurveElement = element;
			}
			else if (a.isStart)
			{
				element.source.Reverse();
				vElements.Remove(element2);
				append(element, element2);
				smoothCurveElement = element;
			}
			if (smoothCurveElement != null)
			{
				if ((smoothCurveElement.polyLine.Start - smoothCurveElement.polyLine.End).Length < loop_tolerance)
				{
					if (!(smoothCurveElement.source is ParametricCurveSequence2))
					{
						throw new Exception("PlanarComplex.JoinElements: we have closed a loop but it is not a parametric seq??");
					}
					(smoothCurveElement.source as ParametricCurveSequence2).IsClosed = true;
					SmoothLoopElement smoothLoopElement = new SmoothLoopElement
					{
						ID = id_generator++,
						source = smoothCurveElement.source
					};
					vElements.Remove(smoothCurveElement);
					vElements.Add(smoothLoopElement);
					UpdateSampling(smoothLoopElement);
				}
				return true;
			}
			return false;
		}

		public void ConvertToLoop(SmoothCurveElement curve, double tolerance = 1E-08)
		{
			if (!((curve.polyLine.Start - curve.polyLine.End).Length < tolerance))
			{
				return;
			}
			if (curve.polyLine.VertexCount == 2)
			{
				vElements.Remove(curve);
				return;
			}
			if (curve.source is ParametricCurveSequence2)
			{
				(curve.source as ParametricCurveSequence2).IsClosed = true;
				SmoothLoopElement smoothLoopElement = new SmoothLoopElement
				{
					ID = id_generator++,
					source = curve.source
				};
				vElements.Remove(curve);
				vElements.Add(smoothLoopElement);
				UpdateSampling(smoothLoopElement);
				return;
			}
			throw new Exception("PlanarComplex.ConvertToLoop: we have closed a loop but it is not a parametric seq??");
		}

		private void append(SmoothCurveElement cTo, SmoothCurveElement cAppend)
		{
			ParametricCurveSequence2 parametricCurveSequence = null;
			if (cTo.source is ParametricCurveSequence2)
			{
				parametricCurveSequence = cTo.source as ParametricCurveSequence2;
			}
			else
			{
				parametricCurveSequence = new ParametricCurveSequence2();
				parametricCurveSequence.Append(cTo.source);
			}
			if (cAppend.source is ParametricCurveSequence2)
			{
				foreach (IParametricCurve2d curf in (cAppend.source as ParametricCurveSequence2).Curves)
				{
					parametricCurveSequence.Append(curf);
				}
			}
			else
			{
				parametricCurveSequence.Append(cAppend.source);
			}
			cTo.source = parametricCurveSequence;
			UpdateSampling(cTo);
		}

		public SolidRegionInfo FindSolidRegions(double fSimplifyDeviationTol = 0.1, bool bWantCurveSolids = true)
		{
			FindSolidsOptions options = FindSolidsOptions.Default;
			options.SimplifyDeviationTolerance = fSimplifyDeviationTol;
			options.WantCurveSolids = bWantCurveSolids;
			return FindSolidRegions(options);
		}

		public SolidRegionInfo FindSolidRegions(FindSolidsOptions options)
		{
			List<SmoothLoopElement> list = new List<SmoothLoopElement>(LoopsItr());
			int count = list.Count;
			int num = 0;
			foreach (SmoothLoopElement item in list)
			{
				num = Math.Max(num, item.ID + 1);
			}
			AxisAlignedBox2d[] bounds = new AxisAlignedBox2d[num];
			foreach (SmoothLoopElement item2 in list)
			{
				bounds[item2.ID] = item2.Bounds();
			}
			double num2 = 0.0;
			double simplifyDeviationTolerance = options.SimplifyDeviationTolerance;
			Polygon2d[] array = new Polygon2d[num];
			foreach (SmoothLoopElement item3 in list)
			{
				Polygon2d polygon2d = new Polygon2d(item3.polygon);
				if (num2 > 0.0 || simplifyDeviationTolerance > 0.0)
				{
					polygon2d.Simplify(num2, simplifyDeviationTolerance);
				}
				array[item3.ID] = polygon2d;
			}
			list.Sort((SmoothLoopElement x, SmoothLoopElement y) => (!bounds[x.ID].Contains(bounds[y.ID])) ? 1 : (-1));
			bool[] array2 = new bool[count];
			Dictionary<int, List<int>> dictionary = new Dictionary<int, List<int>>();
			Dictionary<int, List<int>> dictionary2 = new Dictionary<int, List<int>>();
			bool trustOrientations = options.TrustOrientations;
			bool wantCurveSolids = options.WantCurveSolids;
			bool bCheckContainment = !options.AllowOverlappingHoles;
			for (int num3 = 0; num3 < count; num3++)
			{
				SmoothLoopElement smoothLoopElement = list[num3];
				Polygon2d polygon2d2 = array[smoothLoopElement.ID];
				for (int num4 = 0; num4 < count; num4++)
				{
					if (num3 == num4)
					{
						continue;
					}
					SmoothLoopElement smoothLoopElement2 = list[num4];
					Polygon2d o = array[smoothLoopElement2.ID];
					if ((!trustOrientations || smoothLoopElement2.polygon.IsClockwise != smoothLoopElement.polygon.IsClockwise) && bounds[smoothLoopElement.ID].Contains(bounds[smoothLoopElement2.ID]) && polygon2d2.Contains(o))
					{
						if (!dictionary.ContainsKey(num3))
						{
							dictionary.Add(num3, new List<int>());
						}
						dictionary[num3].Add(num4);
						array2[num4] = true;
						if (!dictionary2.ContainsKey(num4))
						{
							dictionary2.Add(num4, new List<int>());
						}
						dictionary2[num4].Add(num3);
					}
				}
			}
			List<GeneralPolygon2d> list2 = new List<GeneralPolygon2d>();
			List<GeneralSolid> list3 = new List<GeneralSolid>();
			List<PlanarSolid2d> list4 = new List<PlanarSolid2d>();
			HashSet<SmoothLoopElement> hashSet = new HashSet<SmoothLoopElement>();
			Dictionary<SmoothLoopElement, int> dictionary3 = new Dictionary<SmoothLoopElement, int>();
			List<int> list5 = new List<int>();
			for (int num5 = 0; num5 < count; num5++)
			{
				SmoothLoopElement smoothLoopElement3 = list[num5];
				if (array2[num5])
				{
					continue;
				}
				Polygon2d polygon2d3 = array[smoothLoopElement3.ID];
				IParametricCurve2d parametricCurve2d = (wantCurveSolids ? smoothLoopElement3.source.Clone() : null);
				if (!polygon2d3.IsClockwise)
				{
					polygon2d3.Reverse();
					if (wantCurveSolids)
					{
						parametricCurve2d.Reverse();
					}
				}
				GeneralPolygon2d generalPolygon2d = new GeneralPolygon2d();
				generalPolygon2d.Outer = polygon2d3;
				PlanarSolid2d planarSolid2d = new PlanarSolid2d();
				if (wantCurveSolids)
				{
					planarSolid2d.SetOuter(parametricCurve2d, bIsClockwise: true);
				}
				int count2 = list2.Count;
				dictionary3[smoothLoopElement3] = count2;
				hashSet.Add(smoothLoopElement3);
				if (dictionary.ContainsKey(num5))
				{
					list5.Add(num5);
				}
				list2.Add(generalPolygon2d);
				list3.Add(new GeneralSolid
				{
					Outer = smoothLoopElement3
				});
				if (wantCurveSolids)
				{
					list4.Add(planarSolid2d);
				}
			}
			while (list5.Count > 0)
			{
				List<int> list6 = new List<int>();
				foreach (int item4 in list5)
				{
					SmoothLoopElement key = list[item4];
					int index = dictionary3[key];
					foreach (int item5 in dictionary[item4])
					{
						SmoothLoopElement smoothLoopElement4 = list[item5];
						if (dictionary2[item5].Count > 1)
						{
							continue;
						}
						Polygon2d polygon2d4 = array[smoothLoopElement4.ID];
						IParametricCurve2d parametricCurve2d2 = (wantCurveSolids ? smoothLoopElement4.source.Clone() : null);
						if (polygon2d4.IsClockwise)
						{
							polygon2d4.Reverse();
							if (wantCurveSolids)
							{
								parametricCurve2d2.Reverse();
							}
						}
						try
						{
							list2[index].AddHole(polygon2d4, bCheckContainment);
							list3[index].Holes.Add(smoothLoopElement4);
							if (parametricCurve2d2 != null)
							{
								list4[index].AddHole(parametricCurve2d2);
							}
						}
						catch
						{
						}
						hashSet.Add(smoothLoopElement4);
						if (dictionary.ContainsKey(item5))
						{
							list6.Add(item5);
						}
					}
					list6.Add(item4);
				}
				foreach (int item6 in list6)
				{
					dictionary.Remove(item6);
					foreach (int item7 in new List<int>(dictionary2.Keys))
					{
						if (dictionary2[item7].Contains(item6))
						{
							dictionary2[item7].Remove(item6);
						}
					}
				}
				list5.Clear();
				for (int num6 = 0; num6 < count; num6++)
				{
					SmoothLoopElement smoothLoopElement5 = list[num6];
					if (hashSet.Contains(smoothLoopElement5) || !dictionary.ContainsKey(num6) || dictionary2[num6].Count > 0)
					{
						continue;
					}
					Polygon2d polygon2d5 = array[smoothLoopElement5.ID];
					IParametricCurve2d parametricCurve2d3 = (wantCurveSolids ? smoothLoopElement5.source.Clone() : null);
					if (!polygon2d5.IsClockwise)
					{
						polygon2d5.Reverse();
						if (wantCurveSolids)
						{
							parametricCurve2d3.Reverse();
						}
					}
					GeneralPolygon2d generalPolygon2d2 = new GeneralPolygon2d();
					generalPolygon2d2.Outer = polygon2d5;
					PlanarSolid2d planarSolid2d2 = new PlanarSolid2d();
					if (wantCurveSolids)
					{
						planarSolid2d2.SetOuter(parametricCurve2d3, bIsClockwise: true);
					}
					int count3 = list2.Count;
					dictionary3[smoothLoopElement5] = count3;
					hashSet.Add(smoothLoopElement5);
					if (dictionary.ContainsKey(num6))
					{
						list5.Add(num6);
					}
					list2.Add(generalPolygon2d2);
					list3.Add(new GeneralSolid
					{
						Outer = smoothLoopElement5
					});
					if (wantCurveSolids)
					{
						list4.Add(planarSolid2d2);
					}
				}
			}
			for (int num7 = 0; num7 < count; num7++)
			{
				SmoothLoopElement smoothLoopElement6 = list[num7];
				if (hashSet.Contains(smoothLoopElement6))
				{
					continue;
				}
				Polygon2d polygon2d6 = array[smoothLoopElement6.ID];
				IParametricCurve2d parametricCurve2d4 = (wantCurveSolids ? smoothLoopElement6.source.Clone() : null);
				if (!polygon2d6.IsClockwise)
				{
					polygon2d6.Reverse();
					if (wantCurveSolids)
					{
						parametricCurve2d4.Reverse();
					}
				}
				GeneralPolygon2d generalPolygon2d3 = new GeneralPolygon2d();
				generalPolygon2d3.Outer = polygon2d6;
				PlanarSolid2d planarSolid2d3 = new PlanarSolid2d();
				if (wantCurveSolids)
				{
					planarSolid2d3.SetOuter(parametricCurve2d4, bIsClockwise: true);
				}
				list2.Add(generalPolygon2d3);
				list3.Add(new GeneralSolid
				{
					Outer = smoothLoopElement6
				});
				if (wantCurveSolids)
				{
					list4.Add(planarSolid2d3);
				}
			}
			return new SolidRegionInfo
			{
				Polygons = list2,
				PolygonsSources = list3,
				Solids = (wantCurveSolids ? list4 : null)
			};
		}

		public ClosedLoopsInfo FindClosedLoops(double fSimplifyDeviationTol = 0.1)
		{
			List<SmoothLoopElement> list = new List<SmoothLoopElement>(LoopsItr());
			_ = list.Count;
			int num = 0;
			foreach (SmoothLoopElement item in list)
			{
				num = Math.Max(num, item.ID + 1);
			}
			double num2 = 0.0;
			Polygon2d[] array = new Polygon2d[num];
			IParametricCurve2d[] array2 = new IParametricCurve2d[num];
			foreach (SmoothLoopElement item2 in list)
			{
				Polygon2d polygon2d = new Polygon2d(item2.polygon);
				if (num2 > 0.0 || fSimplifyDeviationTol > 0.0)
				{
					polygon2d.Simplify(num2, fSimplifyDeviationTol);
				}
				array[item2.ID] = polygon2d;
				array2[item2.ID] = item2.source;
			}
			ClosedLoopsInfo closedLoopsInfo = new ClosedLoopsInfo
			{
				Polygons = new List<Polygon2d>(),
				Loops = new List<IParametricCurve2d>()
			};
			for (int i = 0; i < array.Length; i++)
			{
				if (array[i] != null && array[i].VertexCount > 0)
				{
					closedLoopsInfo.Polygons.Add(array[i]);
					closedLoopsInfo.Loops.Add(array2[i]);
				}
			}
			return closedLoopsInfo;
		}

		public OpenCurvesInfo FindOpenCurves(double fSimplifyDeviationTol = 0.1)
		{
			List<SmoothCurveElement> list = new List<SmoothCurveElement>(CurvesItr());
			_ = list.Count;
			int num = 0;
			foreach (SmoothCurveElement item in list)
			{
				num = Math.Max(num, item.ID + 1);
			}
			double num2 = 0.0;
			PolyLine2d[] array = new PolyLine2d[num];
			IParametricCurve2d[] array2 = new IParametricCurve2d[num];
			foreach (SmoothCurveElement item2 in list)
			{
				PolyLine2d polyLine2d = new PolyLine2d(item2.polyLine);
				if (num2 > 0.0 || fSimplifyDeviationTol > 0.0)
				{
					polyLine2d.Simplify(num2, fSimplifyDeviationTol);
				}
				array[item2.ID] = polyLine2d;
				array2[item2.ID] = item2.source;
			}
			OpenCurvesInfo openCurvesInfo = new OpenCurvesInfo
			{
				Polylines = new List<PolyLine2d>(),
				Curves = new List<IParametricCurve2d>()
			};
			for (int i = 0; i < array.Length; i++)
			{
				if (array[i] != null && array[i].VertexCount > 0)
				{
					openCurvesInfo.Polylines.Add(array[i]);
					openCurvesInfo.Curves.Add(array2[i]);
				}
			}
			return openCurvesInfo;
		}

		public PlanarComplex Clone()
		{
			PlanarComplex planarComplex = new PlanarComplex();
			planarComplex.DistanceAccuracy = DistanceAccuracy;
			planarComplex.AngleAccuracyDeg = AngleAccuracyDeg;
			planarComplex.SpacingT = SpacingT;
			planarComplex.MinimizeSampling = MinimizeSampling;
			planarComplex.id_generator = id_generator;
			planarComplex.vElements = new List<Element>(vElements.Count);
			foreach (Element vElement in vElements)
			{
				planarComplex.vElements.Add(vElement.Clone());
			}
			return planarComplex;
		}

		public void Append(PlanarComplex append)
		{
			foreach (Element vElement in append.vElements)
			{
				vElement.ID = id_generator++;
				vElements.Add(vElement);
			}
			append.vElements.Clear();
		}

		public void Transform(ITransform2 xform, bool bApplyToSources, bool bRecomputePolygons = false)
		{
			foreach (Element vElement in vElements)
			{
				if (vElement is SmoothLoopElement)
				{
					SmoothLoopElement smoothLoopElement = vElement as SmoothLoopElement;
					if (bApplyToSources && smoothLoopElement.source != smoothLoopElement.polygon)
					{
						smoothLoopElement.source.Transform(xform);
					}
					if (bRecomputePolygons)
					{
						UpdateSampling(smoothLoopElement);
					}
					else
					{
						smoothLoopElement.polygon.Transform(xform);
					}
				}
				else if (vElement is SmoothCurveElement)
				{
					SmoothCurveElement smoothCurveElement = vElement as SmoothCurveElement;
					if (bApplyToSources && smoothCurveElement.source != smoothCurveElement.polyLine)
					{
						smoothCurveElement.source.Transform(xform);
					}
					if (bRecomputePolygons)
					{
						UpdateSampling(smoothCurveElement);
					}
					else
					{
						smoothCurveElement.polyLine.Transform(xform);
					}
				}
			}
		}

		public void PrintStats(string label = "")
		{
			Console.WriteLine("PlanarComplex Stats {0}", label);
			List<SmoothLoopElement> list = new List<SmoothLoopElement>(LoopsItr());
			List<SmoothCurveElement> list2 = new List<SmoothCurveElement>(CurvesItr());
			AxisAlignedBox2d axisAlignedBox2d = Bounds();
			Console.WriteLine("  Bounding Box  w: {0} h: {1}  range {2} ", axisAlignedBox2d.Width, axisAlignedBox2d.Height, axisAlignedBox2d);
			List<ComplexEndpoint2d> list3 = new List<ComplexEndpoint2d>(EndpointsItr());
			Console.WriteLine("  Closed Loops {0}  Open Curves {1}   Open Endpoints {2}", list.Count, list2.Count, list3.Count);
			int num = CountType(typeof(Segment2d));
			int num2 = CountType(typeof(Arc2d));
			int num3 = CountType(typeof(Circle2d));
			int num4 = CountType(typeof(NURBSCurve2));
			int num5 = CountType(typeof(Ellipse2d));
			int num6 = CountType(typeof(EllipseArc2d));
			int num7 = CountType(typeof(ParametricCurveSequence2));
			Console.WriteLine("  [Type Counts]   // {0} multi-curves", num7);
			Console.WriteLine("    segments {0,4}  arcs     {1,4}  circles      {2,4}", num, num2, num3);
			Console.WriteLine("    nurbs    {0,4}  ellipses {1,4}  ellipse-arcs {2,4}", num4, num5, num6);
		}

		public int CountType(Type t)
		{
			int num = 0;
			foreach (Element vElement in vElements)
			{
				if (vElement.source.GetType() == t)
				{
					num++;
				}
				if (vElement.source is IMultiCurve2d)
				{
					num += CountType(vElement.source as IMultiCurve2d, t);
				}
			}
			return num;
		}

		public int CountType(IMultiCurve2d curve, Type t)
		{
			int num = 0;
			foreach (IParametricCurve2d curf in curve.Curves)
			{
				if (curf.GetType() == t)
				{
					num++;
				}
				if (curf is IMultiCurve2d)
				{
					num += CountType(curf as IMultiCurve2d, t);
				}
			}
			return num;
		}
	}
	public class PlanarSolid2d
	{
		private IParametricCurve2d outer;

		private List<IParametricCurve2d> holes = new List<IParametricCurve2d>();

		public IParametricCurve2d Outer => outer;

		private bool HasHoles => Holes.Count > 0;

		public ReadOnlyCollection<IParametricCurve2d> Holes => holes.AsReadOnly();

		public bool HasArcLength
		{
			get
			{
				bool flag = outer.HasArcLength;
				foreach (IParametricCurve2d hole in Holes)
				{
					flag = flag && hole.HasArcLength;
				}
				return flag;
			}
		}

		public double Perimeter
		{
			get
			{
				if (!HasArcLength)
				{
					throw new Exception("PlanarSolid2d.Perimeter: some curves do not have arc length");
				}
				double num = outer.ArcLength;
				foreach (IParametricCurve2d hole in Holes)
				{
					num += hole.ArcLength;
				}
				return num;
			}
		}

		public void SetOuter(IParametricCurve2d loop, bool bIsClockwise)
		{
			outer = loop;
		}

		public void AddHole(IParametricCurve2d hole)
		{
			if (outer == null)
			{
				throw new Exception("PlanarSolid2d.AddHole: outer polygon not set!");
			}
			holes.Add(hole);
		}

		public GeneralPolygon2d Convert(double fSpacingLength, double fSpacingT, double fDeviationTolerance)
		{
			GeneralPolygon2d generalPolygon2d = new GeneralPolygon2d();
			generalPolygon2d.Outer = new Polygon2d(CurveSampler2.AutoSample(outer, fSpacingLength, fSpacingT));
			generalPolygon2d.Outer.Simplify(0.0, fDeviationTolerance);
			foreach (IParametricCurve2d hole in Holes)
			{
				Polygon2d polygon2d = new Polygon2d(CurveSampler2.AutoSample(hole, fSpacingLength, fSpacingT));
				polygon2d.Simplify(0.0, fDeviationTolerance);
				generalPolygon2d.AddHole(polygon2d, bCheckContainment: false);
			}
			return generalPolygon2d;
		}
	}
	public class Polygon2d : IDuplicatable<Polygon2d>
	{
		protected List<Vector2d> vertices;

		public int Timestamp;

		public Vector2d this[int key]
		{
			get
			{
				return vertices[key];
			}
			set
			{
				vertices[key] = value;
				Timestamp++;
			}
		}

		public Vector2d Start => vertices[0];

		public ReadOnlyCollection<Vector2d> Vertices => vertices.AsReadOnly();

		public int VertexCount => vertices.Count;

		public AxisAlignedBox2d Bounds => GetBounds();

		public bool IsClockwise => SignedArea < 0.0;

		public double SignedArea
		{
			get
			{
				double num = 0.0;
				int count = vertices.Count;
				if (count == 0)
				{
					return 0.0;
				}
				Vector2d vector2d = vertices[0];
				Vector2d zero = Vector2d.Zero;
				for (int i = 0; i < count; i++)
				{
					zero = vertices[(i + 1) % count];
					num += vector2d.x * zero.y - vector2d.y * zero.x;
					vector2d = zero;
				}
				return num * 0.5;
			}
		}

		public double Area => Math.Abs(SignedArea);

		public double Perimeter
		{
			get
			{
				double num = 0.0;
				int count = vertices.Count;
				for (int i = 0; i < count; i++)
				{
					num += vertices[i].Distance(vertices[(i + 1) % count]);
				}
				return num;
			}
		}

		public double ArcLength => Perimeter;

		public double AverageEdgeLength
		{
			get
			{
				double num = 0.0;
				int count = vertices.Count;
				for (int i = 1; i < count; i++)
				{
					num += vertices[i].Distance(vertices[i - 1]);
				}
				num += vertices[count - 1].Distance(vertices[0]);
				return num / (double)count;
			}
		}

		public Polygon2d()
		{
			vertices = new List<Vector2d>();
			Timestamp = 0;
		}

		public Polygon2d(Polygon2d copy)
		{
			vertices = new List<Vector2d>(copy.vertices);
			Timestamp = 0;
		}

		public Polygon2d(IList<Vector2d> copy)
		{
			vertices = new List<Vector2d>(copy);
			Timestamp = 0;
		}

		public Polygon2d(IEnumerable<Vector2d> copy)
		{
			vertices = new List<Vector2d>(copy);
			Timestamp = 0;
		}

		public Polygon2d(Vector2d[] v)
		{
			vertices = new List<Vector2d>(v);
			Timestamp = 0;
		}

		public Polygon2d(VectorArray2d v)
		{
			vertices = new List<Vector2d>(v.AsVector2d());
			Timestamp = 0;
		}

		public Polygon2d(double[] values)
		{
			int num = values.Length / 2;
			vertices = new List<Vector2d>(num);
			for (int i = 0; i < num; i++)
			{
				vertices.Add(new Vector2d(values[2 * i], values[2 * i + 1]));
			}
			Timestamp = 0;
		}

		public Polygon2d(Func<int, Vector2d> SourceF, int N)
		{
			vertices = new List<Vector2d>();
			for (int i = 0; i < N; i++)
			{
				vertices.Add(SourceF(i));
			}
			Timestamp = 0;
		}

		public virtual Polygon2d Duplicate()
		{
			return new Polygon2d(this)
			{
				Timestamp = Timestamp
			};
		}

		public void AppendVertex(Vector2d v)
		{
			vertices.Add(v);
			Timestamp++;
		}

		public void AppendVertices(IEnumerable<Vector2d> v)
		{
			vertices.AddRange(v);
			Timestamp++;
		}

		public void RemoveVertex(int idx)
		{
			vertices.RemoveAt(idx);
			Timestamp++;
		}

		public void SetVertices(List<Vector2d> newVertices, bool bTakeOwnership)
		{
			if (bTakeOwnership)
			{
				vertices = newVertices;
				return;
			}
			vertices.Clear();
			int count = newVertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices.Add(newVertices[i]);
			}
		}

		public void Reverse()
		{
			vertices.Reverse();
			Timestamp++;
		}

		public Vector2d GetTangent(int i)
		{
			Vector2d vector2d = vertices[(i + 1) % vertices.Count];
			Vector2d vector2d2 = vertices[(i == 0) ? (vertices.Count - 1) : (i - 1)];
			return (vector2d - vector2d2).Normalized;
		}

		public Vector2d GetNormal(int i)
		{
			return GetTangent(i).Perp;
		}

		public Vector2d GetNormal_FaceAvg(int i)
		{
			Vector2d vector2d = vertices[(i + 1) % vertices.Count];
			Vector2d vector2d2 = vertices[(i == 0) ? (vertices.Count - 1) : (i - 1)];
			vector2d -= vertices[i];
			vector2d.Normalize();
			vector2d2 -= vertices[i];
			vector2d2.Normalize();
			Vector2d result = vector2d.Perp - vector2d2.Perp;
			if (result.Normalize() == 0.0)
			{
				return (vector2d + vector2d2).Normalized;
			}
			return result;
		}

		public AxisAlignedBox2d GetBounds()
		{
			AxisAlignedBox2d empty = AxisAlignedBox2d.Empty;
			empty.Contain(vertices);
			return empty;
		}

		public IEnumerable<Segment2d> SegmentItr()
		{
			int i = 0;
			while (i < vertices.Count)
			{
				yield return new Segment2d(vertices[i], vertices[(i + 1) % vertices.Count]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<Vector2d> VerticesItr(bool bRepeatFirstAtEnd)
		{
			int N = vertices.Count;
			int i = 0;
			while (i < N)
			{
				yield return vertices[i];
				int num = i + 1;
				i = num;
			}
			if (bRepeatFirstAtEnd)
			{
				yield return vertices[0];
			}
		}

		public IEnumerable<Index2i> EdgeItr()
		{
			int i = 0;
			while (i < VertexCount)
			{
				yield return new Index2i(i, (i != VertexCount - 1) ? (i + 1) : 0);
				int num = i + 1;
				i = num;
			}
		}

		public bool BiContains(Segment2d seg)
		{
			foreach (Segment2d item in SegmentItr())
			{
				if (item.BiEquals(seg))
				{
					return true;
				}
			}
			return false;
		}

		public bool IsMember(Segment2d seg, out bool IsOutside)
		{
			IsOutside = true;
			if (Vertices.Contains(seg.P0) && Vertices.Contains(seg.P1))
			{
				if (BiContains(seg))
				{
					IsOutside = false;
				}
				return true;
			}
			return false;
		}

		public void NeighboursP(int iVertex, ref Vector2d p0, ref Vector2d p1)
		{
			int count = vertices.Count;
			p0 = vertices[(iVertex == 0) ? (count - 1) : (iVertex - 1)];
			p1 = vertices[(iVertex + 1) % count];
		}

		public void NeighboursV(int iVertex, ref Vector2d v0, ref Vector2d v1, bool bNormalize = false)
		{
			int count = vertices.Count;
			v0 = vertices[(iVertex == 0) ? (count - 1) : (iVertex - 1)] - vertices[iVertex];
			v1 = vertices[(iVertex + 1) % count] - vertices[iVertex];
			if (bNormalize)
			{
				v0.Normalize();
				v1.Normalize();
			}
		}

		public double OpeningAngleDeg(int iVertex)
		{
			Vector2d v = Vector2d.Zero;
			Vector2d v2 = Vector2d.Zero;
			NeighboursV(iVertex, ref v, ref v2, bNormalize: true);
			return Vector2d.AngleD(v, v2);
		}

		public double WindingIntegral(Vector2d P)
		{
			double num = 0.0;
			int count = vertices.Count;
			Vector2d vector2d = vertices[0] - P;
			Vector2d zero = Vector2d.Zero;
			for (int i = 0; i < count; i++)
			{
				zero = vertices[(i + 1) % count] - P;
				num += Math.Atan2(vector2d.x * zero.y - vector2d.y * zero.x, vector2d.x * zero.x + vector2d.y * zero.y);
				vector2d = zero;
			}
			return num / (Math.PI * 2.0);
		}

		public bool Contains(Vector2d P)
		{
			int num = 0;
			int count = vertices.Count;
			Vector2d P2 = vertices[0];
			Vector2d zero = Vector2d.Zero;
			for (int i = 0; i < count; i++)
			{
				zero = vertices[(i + 1) % count];
				if (P2.y <= P.y)
				{
					if (zero.y > P.y && MathUtil.IsLeft(ref P2, ref zero, ref P) > 0.0)
					{
						num++;
					}
				}
				else if (zero.y <= P.y && MathUtil.IsLeft(ref P2, ref zero, ref P) < 0.0)
				{
					num--;
				}
				P2 = zero;
			}
			return num != 0;
		}

		public bool Contains(Polygon2d o)
		{
			int vertexCount = o.VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				if (!Contains(o[i]))
				{
					return false;
				}
			}
			if (Intersects(o))
			{
				return false;
			}
			return true;
		}

		public bool Contains(Segment2d o)
		{
			if (!Contains(o.P0) || !Contains(o.P1))
			{
				return false;
			}
			foreach (Segment2d item in SegmentItr())
			{
				if (item.Intersects(o))
				{
					return false;
				}
			}
			return true;
		}

		public bool Intersects(Polygon2d o)
		{
			if (!GetBounds().Intersects(o.GetBounds()))
			{
				return false;
			}
			foreach (Segment2d item in SegmentItr())
			{
				foreach (Segment2d item2 in o.SegmentItr())
				{
					if (item.Intersects(item2))
					{
						return true;
					}
				}
			}
			return false;
		}

		public bool Intersects(Segment2d o)
		{
			if (Contains(o.P0) || Contains(o.P1))
			{
				return true;
			}
			foreach (Segment2d item in SegmentItr())
			{
				if (item.Intersects(o))
				{
					return true;
				}
			}
			return false;
		}

		public List<Vector2d> FindIntersections(Polygon2d o)
		{
			List<Vector2d> list = new List<Vector2d>();
			if (!GetBounds().Intersects(o.GetBounds()))
			{
				return list;
			}
			foreach (Segment2d item in SegmentItr())
			{
				foreach (Segment2d item2 in o.SegmentItr())
				{
					if (!item.Intersects(item2))
					{
						continue;
					}
					IntrSegment2Segment2 intrSegment2Segment = new IntrSegment2Segment2(item, item2);
					if (intrSegment2Segment.Find())
					{
						list.Add(intrSegment2Segment.Point0);
						if (intrSegment2Segment.Quantity == 2)
						{
							list.Add(intrSegment2Segment.Point1);
						}
					}
				}
			}
			return list;
		}

		public List<Vector2d> FindIntersections(Segment2d s)
		{
			List<Vector2d> list = new List<Vector2d>();
			foreach (Segment2d item in SegmentItr())
			{
				if (!item.Intersects(s))
				{
					continue;
				}
				IntrSegment2Segment2 intrSegment2Segment = new IntrSegment2Segment2(item, s);
				if (intrSegment2Segment.Find())
				{
					list.Add(intrSegment2Segment.Point0);
					if (intrSegment2Segment.Quantity == 2)
					{
						list.Add(intrSegment2Segment.Point1);
					}
				}
			}
			return list;
		}

		public Segment2d Segment(int iSegment)
		{
			return new Segment2d(vertices[iSegment], vertices[(iSegment + 1) % vertices.Count]);
		}

		public Vector2d PointAt(int iSegment, double fSegT)
		{
			return new Segment2d(vertices[iSegment], vertices[(iSegment + 1) % vertices.Count]).PointAt(fSegT);
		}

		public Vector2d GetNormal(int iSeg, double segT)
		{
			double num = (segT / new Segment2d(vertices[iSeg], vertices[(iSeg + 1) % vertices.Count]).Extent + 1.0) / 2.0;
			Vector2d normal = GetNormal(iSeg);
			Vector2d normal2 = GetNormal((iSeg + 1) % vertices.Count);
			return ((1.0 - num) * normal + num * normal2).Normalized;
		}

		public double DistanceSquared(Vector2d p, out int iNearSeg, out double fNearSegT)
		{
			iNearSeg = -1;
			fNearSegT = double.MaxValue;
			double num = double.MaxValue;
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				Segment2d segment2d = new Segment2d(vertices[i], vertices[(i + 1) % count]);
				double num2 = (p - segment2d.Center).Dot(segment2d.Direction);
				double num3 = double.MaxValue;
				num3 = ((num2 >= segment2d.Extent) ? segment2d.P1.DistanceSquared(p) : ((!(num2 <= 0.0 - segment2d.Extent)) ? (segment2d.PointAt(num2) - p).LengthSquared : segment2d.P0.DistanceSquared(p)));
				if (num3 < num)
				{
					num = num3;
					iNearSeg = i;
					fNearSegT = num2;
				}
			}
			return num;
		}

		public double DistanceSquared(Vector2d p)
		{
			int iNearSeg;
			double fNearSegT;
			return DistanceSquared(p, out iNearSeg, out fNearSegT);
		}

		public Polygon2d Translate(Vector2d translate)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] += translate;
			}
			Timestamp++;
			return this;
		}

		public Polygon2d Rotate(Matrix2d rotation, Vector2d origin)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] = rotation * (vertices[i] - origin) + origin;
			}
			Timestamp++;
			return this;
		}

		public Polygon2d Scale(Vector2d scale, Vector2d origin)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] = scale * (vertices[i] - origin) + origin;
			}
			Timestamp++;
			return this;
		}

		public Polygon2d Transform(Func<Vector2d, Vector2d> transformF)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] = transformF(vertices[i]);
			}
			Timestamp++;
			return this;
		}

		public Polygon2d Transform(ITransform2 xform)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] = xform.TransformP(vertices[i]);
			}
			Timestamp++;
			return this;
		}

		public void VtxNormalOffset(double dist, bool bUseFaceAvg = false)
		{
			Vector2d[] array = new Vector2d[vertices.Count];
			if (bUseFaceAvg)
			{
				for (int i = 0; i < vertices.Count; i++)
				{
					array[i] = vertices[i] + dist * GetNormal_FaceAvg(i);
				}
			}
			else
			{
				for (int j = 0; j < vertices.Count; j++)
				{
					array[j] = vertices[j] + dist * GetNormal(j);
				}
			}
			for (int k = 0; k < vertices.Count; k++)
			{
				vertices[k] = array[k];
			}
			Timestamp++;
		}

		public void PolyOffset(double dist)
		{
			Vector2d[] array = new Vector2d[vertices.Count];
			for (int i = 0; i < vertices.Count; i++)
			{
				Vector2d vector2d = vertices[i];
				Vector2d vector2d2 = vertices[(i + 1) % vertices.Count];
				Vector2d vector2d3 = vertices[(i == 0) ? (vertices.Count - 1) : (i - 1)];
				Vector2d normalized = (vector2d2 - vector2d).Normalized;
				Vector2d normalized2 = (vector2d3 - vector2d).Normalized;
				Line2d line2d = new Line2d(vector2d + dist * normalized.Perp, normalized);
				Line2d other = new Line2d(vector2d - dist * normalized2.Perp, normalized2);
				array[i] = line2d.IntersectionPoint(ref other);
				if (array[i] == Vector2d.MaxValue)
				{
					array[i] = vertices[i] + dist * GetNormal_FaceAvg(i);
				}
			}
			for (int j = 0; j < vertices.Count; j++)
			{
				vertices[j] = array[j];
			}
			Timestamp++;
		}

		private static void simplifyDP(double tol, Vector2d[] v, int j, int k, bool[] mk)
		{
			if (k <= j + 1)
			{
				return;
			}
			int num = j;
			double num2 = 0.0;
			double num3 = tol * tol;
			Segment2d segment2d = new Segment2d(v[j], v[k]);
			for (int i = j + 1; i < k; i++)
			{
				double num4 = segment2d.DistanceSquared(v[i]);
				if (!(num4 <= num2))
				{
					num = i;
					num2 = num4;
				}
			}
			if (num2 > num3)
			{
				mk[num] = true;
				simplifyDP(tol, v, j, num, mk);
				simplifyDP(tol, v, num, k, mk);
			}
		}

		public void Simplify(double clusterTol = 0.0001, double lineDeviationTol = 0.01, bool bSimplifyStraightLines = true)
		{
			int count = vertices.Count;
			if (count < 3)
			{
				return;
			}
			Vector2d[] array = new Vector2d[count + 1];
			bool[] array2 = new bool[count + 1];
			int i;
			for (i = 0; i < count + 1; i++)
			{
				array2[i] = false;
			}
			double num = clusterTol * clusterTol;
			array[0] = vertices[0];
			i = 1;
			int num2 = 1;
			int index = 0;
			for (; i < count; i++)
			{
				if (!((vertices[i] - vertices[index]).LengthSquared < num))
				{
					array[num2++] = vertices[i];
					index = i;
				}
			}
			bool flag = false;
			switch (num2)
			{
			case 1:
				array[num2++] = vertices[1];
				array[num2++] = vertices[2];
				flag = true;
				break;
			case 2:
				array[num2++] = vertices[0];
				flag = true;
				break;
			}
			array[num2++] = vertices[0];
			int num3 = 0;
			if (!flag && lineDeviationTol > 0.0)
			{
				array2[0] = (array2[num2 - 1] = true);
				simplifyDP(lineDeviationTol, array, 0, num2 - 1, array2);
				for (i = 0; i < num2 - 1; i++)
				{
					if (array2[i])
					{
						num3++;
					}
				}
			}
			else
			{
				for (i = 0; i < num2; i++)
				{
					array2[i] = true;
				}
				num3 = num2 - 1;
			}
			switch (num3)
			{
			case 2:
				for (i = 1; i < num2 - 1; i++)
				{
					if (!array2[1])
					{
						array2[1] = true;
					}
					else if (!array2[num2 - 2])
					{
						array2[num2 - 2] = true;
					}
				}
				num3++;
				break;
			case 1:
				array2[1] = true;
				array2[2] = true;
				num3 += 2;
				break;
			}
			vertices = new List<Vector2d>();
			for (i = 0; i < num2 - 1; i++)
			{
				if (array2[i])
				{
					vertices.Add(array[i]);
				}
			}
			Timestamp++;
		}

		public void Chamfer(double chamfer_dist, double minConvexAngleDeg = 30.0, double minConcaveAngleDeg = 30.0)
		{
			if (IsClockwise)
			{
				throw new Exception("must be ccw?");
			}
			List<Vector2d> list = new List<Vector2d>();
			int count = Vertices.Count;
			int num = 0;
			do
			{
				Vector2d vector2d = Vertices[num];
				int index = ((num == 0) ? (count - 1) : (num - 1));
				Vector2d vector2d2 = Vertices[index];
				int num2 = (num + 1) % count;
				Vector2d vector2d3 = Vertices[num2];
				Vector2d vector2d4 = vector2d2 - vector2d;
				double num3 = vector2d4.Normalize();
				Vector2d vector2d5 = vector2d3 - vector2d;
				double num4 = vector2d5.Normalize();
				if (num3 < 9.999999974752427E-07 || num4 < 9.999999974752427E-07)
				{
					num = num2;
					continue;
				}
				double num5 = Vector2d.AngleD(vector2d4, vector2d5);
				double num6 = ((vector2d4.Perp.Dot(vector2d5) > 0.0) ? minConcaveAngleDeg : minConvexAngleDeg);
				if (num5 > num6)
				{
					list.Add(vector2d);
					num = num2;
					continue;
				}
				double num7 = Math.Min(chamfer_dist, num3 * 0.5);
				Vector2d item = vector2d + num7 * vector2d4;
				double num8 = Math.Min(chamfer_dist, num4 * 0.5);
				Vector2d item2 = vector2d + num8 * vector2d5;
				list.Add(item);
				list.Add(item2);
				num = num2;
			}
			while (num != 0);
			vertices = list;
			Timestamp++;
		}

		public Vector2d PointInPolygon()
		{
			AxisAlignedBox2d bounds = Bounds;
			Vector2d corner = bounds.GetCorner(3);
			Vector2d corner2 = bounds.GetCorner(1);
			if (Vertices.Contains(corner) && Vertices.Contains(corner2))
			{
				corner = bounds.GetCorner(2);
				corner2 = bounds.GetCorner(0);
			}
			List<Vector2d> list = FindIntersections(new Segment2d(corner, corner2));
			Segment2d segment2d = new Segment2d(list[0], list[1]);
			if (Contains(segment2d.Center))
			{
				return segment2d.Center;
			}
			throw new Exception("Failed to find a point in the polygon");
		}

		public Box2d MinimalBoundingBox(double epsilon)
		{
			return new ContMinBox2(vertices, epsilon, QueryNumberType.QT_DOUBLE, isConvexPolygon: false).MinBox;
		}

		public static Polygon2d MakeRectangle(Vector2d center, double width, double height)
		{
			VectorArray2d vectorArray2d = new VectorArray2d(4);
			vectorArray2d.Set(0, center.x - width / 2.0, center.y - height / 2.0);
			vectorArray2d.Set(1, center.x + width / 2.0, center.y - height / 2.0);
			vectorArray2d.Set(2, center.x + width / 2.0, center.y + height / 2.0);
			vectorArray2d.Set(3, center.x - width / 2.0, center.y + height / 2.0);
			return new Polygon2d(vectorArray2d);
		}

		public static Polygon2d MakeCircle(double fRadius, int nSteps, double angleShiftRad = 0.0)
		{
			VectorArray2d vectorArray2d = new VectorArray2d(nSteps);
			for (int i = 0; i < nSteps; i++)
			{
				double num = (double)i / (double)nSteps;
				double num2 = Math.PI * 2.0 * num + angleShiftRad;
				vectorArray2d.Set(i, fRadius * Math.Cos(num2), fRadius * Math.Sin(num2));
			}
			return new Polygon2d(vectorArray2d);
		}
	}
	public class Polygon2DCurve : IParametricCurve2d
	{
		public Polygon2d Polygon;

		public bool IsClosed => true;

		public double ParamLength => Polygon.VertexCount;

		public bool HasArcLength => true;

		public double ArcLength => Polygon.ArcLength;

		public bool IsTransformable => true;

		public Vector2d SampleT(double t)
		{
			int num = (int)t;
			if (num >= Polygon.VertexCount - 1)
			{
				return Polygon[Polygon.VertexCount - 1];
			}
			Vector2d vector2d = Polygon[num];
			Vector2d vector2d2 = Polygon[num + 1];
			double num2 = t - (double)num;
			return (1.0 - num2) * vector2d + num2 * vector2d2;
		}

		public Vector2d TangentT(double t)
		{
			throw new NotImplementedException("Polygon2dCurve.TangentT");
		}

		public Vector2d SampleArcLength(double a)
		{
			throw new NotImplementedException("Polygon2dCurve.SampleArcLength");
		}

		public void Reverse()
		{
			Polygon.Reverse();
		}

		public IParametricCurve2d Clone()
		{
			return new Polygon2DCurve
			{
				Polygon = new Polygon2d(Polygon)
			};
		}

		public void Transform(ITransform2 xform)
		{
			Polygon.Transform(xform);
		}
	}
	public class PolygonFont2d
	{
		public class CharacterInfo
		{
			public GeneralPolygon2d[] Polygons;

			public AxisAlignedBox2d Bounds;
		}

		public Dictionary<string, CharacterInfo> Characters;

		public AxisAlignedBox2d MaxBounds;

		private const int SerializerVersion = 3;

		public PolygonFont2d()
		{
			Characters = new Dictionary<string, CharacterInfo>();
			MaxBounds = AxisAlignedBox2d.Empty;
		}

		public void AddCharacter(string s, GeneralPolygon2d[] polygons)
		{
			CharacterInfo characterInfo = new CharacterInfo();
			characterInfo.Polygons = polygons;
			characterInfo.Bounds = polygons[0].Bounds;
			for (int i = 1; i < polygons.Length; i++)
			{
				characterInfo.Bounds.Contain(polygons[i].Bounds);
			}
			Characters.Add(s, characterInfo);
			MaxBounds.Contain(characterInfo.Bounds);
		}

		public List<GeneralPolygon2d> GetCharacter(char c)
		{
			string key = c.ToString();
			if (!Characters.ContainsKey(key))
			{
				throw new Exception("PolygonFont2d.GetCharacterBounds: character " + c + " not available!");
			}
			return new List<GeneralPolygon2d>(Characters[key].Polygons);
		}

		public List<GeneralPolygon2d> GetCharacter(string s)
		{
			if (!Characters.ContainsKey(s))
			{
				throw new Exception("PolygonFont2d.GetCharacterBounds: character " + s + " not available!");
			}
			return new List<GeneralPolygon2d>(Characters[s].Polygons);
		}

		public AxisAlignedBox2d GetCharacterBounds(char c)
		{
			string key = c.ToString();
			if (!Characters.ContainsKey(key))
			{
				throw new Exception("PolygonFont2d.GetCharacterBounds: character " + c + " not available!");
			}
			return Characters[key].Bounds;
		}

		public bool HasCharacter(char c)
		{
			string key = c.ToString();
			return Characters.ContainsKey(key);
		}

		public static void Store(PolygonFont2d font, BinaryWriter writer)
		{
			writer.Write(3);
			int count = font.Characters.Count;
			writer.Write(count);
			foreach (KeyValuePair<string, CharacterInfo> character in font.Characters)
			{
				byte[] bytes = Encoding.Unicode.GetBytes(character.Key);
				writer.Write(bytes.Length);
				writer.Write(bytes);
				CharacterInfo value = character.Value;
				writer.Write(value.Polygons.Length);
				for (int i = 0; i < value.Polygons.Length; i++)
				{
					gSerialization.Store(value.Polygons[i], writer);
				}
			}
		}

		public static PolygonFont2d ReadFont(string filename)
		{
			using FileStream input = File.Open(filename, FileMode.Open);
			BinaryReader reader = new BinaryReader(input);
			PolygonFont2d polygonFont2d = new PolygonFont2d();
			Restore(polygonFont2d, reader);
			return polygonFont2d;
		}

		public static PolygonFont2d ReadFont(Stream s)
		{
			BinaryReader reader = new BinaryReader(s);
			PolygonFont2d polygonFont2d = new PolygonFont2d();
			Restore(polygonFont2d, reader);
			return polygonFont2d;
		}

		public static void Restore(PolygonFont2d font, BinaryReader reader)
		{
			if (reader.ReadInt32() != 3)
			{
				throw new Exception("PolygonFont2d.Restore: invalid version!");
			}
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				int count = reader.ReadInt32();
				byte[] bytes = reader.ReadBytes(count);
				string s = Encoding.Unicode.GetString(bytes);
				int num2 = reader.ReadInt32();
				GeneralPolygon2d[] array = new GeneralPolygon2d[num2];
				for (int j = 0; j < num2; j++)
				{
					array[j] = new GeneralPolygon2d();
					gSerialization.Restore(array[j], reader);
				}
				font.AddCharacter(s, array);
			}
		}
	}
	public class PolyLine2d : IEnumerable<Vector2d>, IEnumerable
	{
		protected List<Vector2d> vertices;

		public int Timestamp;

		public Vector2d this[int key]
		{
			get
			{
				return vertices[key];
			}
			set
			{
				vertices[key] = value;
				Timestamp++;
			}
		}

		public Vector2d Start => vertices[0];

		public Vector2d End => vertices[vertices.Count - 1];

		public ReadOnlyCollection<Vector2d> Vertices => vertices.AsReadOnly();

		public int VertexCount => vertices.Count;

		public AxisAlignedBox2d Bounds => GetBounds();

		[Obsolete("This method name is confusing. Will remove in future. Use ArcLength instead")]
		public double Length => ArcLength;

		public double ArcLength
		{
			get
			{
				double num = 0.0;
				int count = vertices.Count;
				for (int i = 0; i < count - 1; i++)
				{
					num += vertices[i].Distance(vertices[i + 1]);
				}
				return num;
			}
		}

		public PolyLine2d()
		{
			vertices = new List<Vector2d>();
			Timestamp = 0;
		}

		public PolyLine2d(PolyLine2d copy)
		{
			vertices = new List<Vector2d>(copy.vertices);
			Timestamp = 0;
		}

		public PolyLine2d(Polygon2d copy, bool bDuplicateFirstLast)
		{
			vertices = new List<Vector2d>(copy.VerticesItr(bDuplicateFirstLast));
			Timestamp = 0;
		}

		public PolyLine2d(IList<Vector2d> copy)
		{
			vertices = new List<Vector2d>(copy);
			Timestamp = 0;
		}

		public PolyLine2d(IEnumerable<Vector2d> copy)
		{
			vertices = new List<Vector2d>(copy);
			Timestamp = 0;
		}

		public PolyLine2d(Vector2d[] v)
		{
			vertices = new List<Vector2d>(v);
			Timestamp = 0;
		}

		public PolyLine2d(VectorArray2d v)
		{
			vertices = new List<Vector2d>(v.AsVector2d());
			Timestamp = 0;
		}

		public virtual void AppendVertex(Vector2d v)
		{
			vertices.Add(v);
			Timestamp++;
		}

		public virtual void AppendVertices(IEnumerable<Vector2d> v)
		{
			vertices.AddRange(v);
			Timestamp++;
		}

		public virtual void Reverse()
		{
			vertices.Reverse();
			Timestamp++;
		}

		public Vector2d GetTangent(int i)
		{
			if (i == 0)
			{
				return (vertices[1] - vertices[0]).Normalized;
			}
			if (i == vertices.Count - 1)
			{
				return (vertices[vertices.Count - 1] - vertices[vertices.Count - 2]).Normalized;
			}
			return (vertices[i + 1] - vertices[i - 1]).Normalized;
		}

		public Vector2d GetNormal(int i)
		{
			return GetTangent(i).Perp;
		}

		public AxisAlignedBox2d GetBounds()
		{
			if (vertices.Count == 0)
			{
				return AxisAlignedBox2d.Empty;
			}
			AxisAlignedBox2d result = new AxisAlignedBox2d(vertices[0]);
			for (int i = 1; i < vertices.Count; i++)
			{
				result.Contain(vertices[i]);
			}
			return result;
		}

		public double DistanceSquared(Vector2d point)
		{
			double num = double.MaxValue;
			for (int i = 0; i < vertices.Count - 1; i++)
			{
				double num2 = new Segment2d(vertices[i], vertices[i + 1]).DistanceSquared(point);
				if (num2 < num)
				{
					num = num2;
				}
			}
			return num;
		}

		public Segment2d Segment(int iSegment)
		{
			return new Segment2d(vertices[iSegment], vertices[iSegment + 1]);
		}

		public IEnumerable<Segment2d> SegmentItr()
		{
			int i = 0;
			while (i < vertices.Count - 1)
			{
				yield return new Segment2d(vertices[i], vertices[i + 1]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerator<Vector2d> GetEnumerator()
		{
			return vertices.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return vertices.GetEnumerator();
		}

		public void VertexOffset(double dist)
		{
			Vector2d[] array = new Vector2d[vertices.Count];
			for (int i = 0; i < vertices.Count; i++)
			{
				array[i] = vertices[i] + dist * GetNormal(i);
			}
			for (int j = 0; j < vertices.Count; j++)
			{
				vertices[j] = array[j];
			}
		}

		public bool TrimStart(double dist)
		{
			int count = vertices.Count;
			int num = 0;
			double num2 = vertices[num].Distance(vertices[num + 1]);
			double num3 = 0.0;
			while (num < count - 2 && num3 + num2 < dist)
			{
				num3 += num2;
				num++;
				num2 = vertices[num].Distance(vertices[num + 1]);
			}
			if (num == count - 2 && num3 + num2 <= dist)
			{
				return false;
			}
			double t = (dist - num3) / num2;
			Vector2d value = Segment(num).PointBetween(t);
			if (num > 0)
			{
				vertices.RemoveRange(0, num);
			}
			vertices[0] = value;
			return true;
		}

		public bool TrimEnd(double dist)
		{
			int count = vertices.Count;
			int num = count - 1;
			double num2 = vertices[num].Distance(vertices[num - 1]);
			double num3 = 0.0;
			while (num > 1 && num3 + num2 < dist)
			{
				num3 += num2;
				num--;
				num2 = vertices[num].Distance(vertices[num - 1]);
			}
			if (num == 1 && num3 + num2 <= dist)
			{
				return false;
			}
			double num4 = (dist - num3) / num2;
			Vector2d value = Segment(num - 1).PointBetween(1.0 - num4);
			if (num < count - 1)
			{
				vertices.RemoveRange(num, count - 1 - num);
			}
			vertices[num] = value;
			return true;
		}

		public bool Trim(double each_end_dist)
		{
			if (ArcLength < 2.0 * each_end_dist)
			{
				return false;
			}
			if (TrimEnd(each_end_dist))
			{
				return TrimStart(each_end_dist);
			}
			return false;
		}

		protected static void simplifyDP(double tol, Vector2d[] v, int j, int k, bool[] mk)
		{
			if (k <= j + 1)
			{
				return;
			}
			int num = j;
			double num2 = 0.0;
			double num3 = tol * tol;
			Segment2d segment2d = new Segment2d(v[j], v[k]);
			for (int i = j + 1; i < k; i++)
			{
				double num4 = segment2d.DistanceSquared(v[i]);
				if (!(num4 <= num2))
				{
					num = i;
					num2 = num4;
				}
			}
			if (num2 > num3)
			{
				mk[num] = true;
				simplifyDP(tol, v, j, num, mk);
				simplifyDP(tol, v, num, k, mk);
			}
		}

		public virtual void Simplify(double clusterTol = 0.0001, double lineDeviationTol = 0.01, bool bSimplifyStraightLines = true)
		{
			int count = vertices.Count;
			Vector2d[] array = new Vector2d[count];
			bool[] array2 = new bool[count];
			int i;
			for (i = 0; i < count; i++)
			{
				array2[i] = false;
			}
			double num = clusterTol * clusterTol;
			array[0] = vertices[0];
			int num2;
			i = (num2 = 1);
			int num3 = 0;
			for (; i < count; i++)
			{
				if (!((vertices[i] - vertices[num3]).LengthSquared < num))
				{
					array[num2++] = vertices[i];
					num3 = i;
				}
			}
			if (num3 < count - 1)
			{
				array[num2++] = vertices[count - 1];
			}
			if (lineDeviationTol > 0.0)
			{
				array2[0] = (array2[num2 - 1] = true);
				simplifyDP(lineDeviationTol, array, 0, num2 - 1, array2);
			}
			else
			{
				for (i = 0; i < num2; i++)
				{
					array2[i] = true;
				}
			}
			vertices = new List<Vector2d>();
			for (i = 0; i < num2; i++)
			{
				if (array2[i])
				{
					vertices.Add(array[i]);
				}
			}
			Timestamp++;
		}

		public PolyLine2d Transform(ITransform2 xform)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				vertices[i] = xform.TransformP(vertices[i]);
			}
			return this;
		}

		public static PolyLine2d MakeBoxSpiral(Vector2d center, double len, double spacing)
		{
			PolyLine2d polyLine2d = new PolyLine2d();
			polyLine2d.AppendVertex(center);
			Vector2d v = center;
			v.x += spacing / 2.0;
			polyLine2d.AppendVertex(v);
			v.y += spacing;
			polyLine2d.AppendVertex(v);
			double num = spacing / 2.0 + spacing;
			double num2 = spacing / 2.0;
			double num3 = spacing;
			double num4 = -1.0;
			while (num < len)
			{
				num2 += spacing;
				v.x += num4 * num2;
				polyLine2d.AppendVertex(v);
				num += num2;
				num3 += spacing;
				v.y += num4 * num3;
				polyLine2d.AppendVertex(v);
				num += num3;
				num4 *= -1.0;
			}
			return polyLine2d;
		}
	}
