	public class PolySimplification2
	{
		private List<Vector2d> Vertices;

		private bool IsLoop;

		public double StraightLineDeviationThreshold = 0.01;

		public double PreserveStraightSegLen = 2.0;

		public double SimplifyDeviationThreshold = 0.2;

		public List<Vector2d> Result;

		public PolySimplification2(Polygon2d polygon)
		{
			Vertices = new List<Vector2d>(polygon.Vertices);
			IsLoop = true;
		}

		public PolySimplification2(PolyLine2d polycurve)
		{
			Vertices = new List<Vector2d>(polycurve.Vertices);
			IsLoop = false;
		}

		public static void Simplify(GeneralPolygon2d solid, double deviationThresh)
		{
			PolySimplification2 polySimplification = new PolySimplification2(solid.Outer);
			polySimplification.SimplifyDeviationThreshold = deviationThresh;
			polySimplification.Simplify();
			solid.Outer.SetVertices(polySimplification.Result, bTakeOwnership: true);
			foreach (Polygon2d hole in solid.Holes)
			{
				PolySimplification2 polySimplification2 = new PolySimplification2(hole);
				polySimplification2.SimplifyDeviationThreshold = deviationThresh;
				polySimplification2.Simplify();
				hole.SetVertices(polySimplification2.Result, bTakeOwnership: true);
			}
		}

		public void Simplify()
		{
			bool[] array = new bool[Vertices.Count];
			Array.Clear(array, 0, array.Length);
			List<Vector2d> list = collapse_by_deviation_tol(Vertices, array, StraightLineDeviationThreshold);
			find_constrained_segments(list, array);
			Result = collapse_by_deviation_tol(list, array, SimplifyDeviationThreshold);
		}

		private void find_constrained_segments(List<Vector2d> vertices, bool[] markers)
		{
			int count = vertices.Count;
			int num = (IsLoop ? vertices.Count : (vertices.Count - 1));
			for (int i = 0; i < num; i++)
			{
				int num2 = i;
				int index = (i + 1) % count;
				if (vertices[num2].DistanceSquared(vertices[index]) > PreserveStraightSegLen)
				{
					markers[num2] = true;
				}
			}
		}

		private List<Vector2d> collapse_by_deviation_tol(List<Vector2d> input, bool[] keep_segments, double offset_threshold)
		{
			int count = input.Count;
			int num = (IsLoop ? input.Count : (input.Count - 1));
			List<Vector2d> list = new List<Vector2d>();
			list.Add(input[0]);
			double num2 = offset_threshold * offset_threshold;
			int num3 = 0;
			int num4 = 1;
			int num5 = 0;
			if (keep_segments[0])
			{
				list.Add(input[1]);
				num3 = 1;
				num4 = 2;
			}
			while (num4 < num)
			{
				int num6 = num4;
				int num7 = (num4 + 1) % count;
				if (keep_segments[num6])
				{
					if (num3 != num6 && input[num6].Distance(list[list.Count - 1]) > 2.220446049250313E-16)
					{
						list.Add(input[num6]);
					}
					list.Add(input[num7]);
					num3 = num7;
					num5 = 0;
					num4 = ((num7 != 0) ? num7 : num);
					continue;
				}
				Vector2d vector2d = input[num7] - input[num3];
				Line2d line2d = new Line2d(input[num3], vector2d.Normalized);
				double num8 = 0.0;
				for (int i = num3 + 1; i <= num4; i++)
				{
					double num9 = line2d.DistanceSquared(input[i]);
					if (num9 > num8)
					{
						num8 = num9;
					}
				}
				if (num8 > num2)
				{
					list.Add(input[num4]);
					num3 = num4;
					num4++;
					num5 = 0;
				}
				else
				{
					num4++;
					num5++;
				}
			}
			if (IsLoop)
			{
				if (list.Count < 3)
				{
					return handle_tiny_case(list, input, keep_segments, offset_threshold);
				}
				Line2d line2d2 = Line2d.FromPoints(input[num3], input[num4 % count]);
				bool flag = line2d2.DistanceSquared(list[0]) < num2;
				bool flag2 = line2d2.DistanceSquared(list[1]) < num2;
				if (flag && flag2 && list.Count > 3)
				{
					list[0] = input[num3];
					list.RemoveAt(list.Count - 1);
				}
				else if (!flag)
				{
					list.Add(input[input.Count - 1]);
				}
			}
			else
			{
				list.Add(input[input.Count - 1]);
			}
			return list;
		}

		private List<Vector2d> handle_tiny_case(List<Vector2d> result, List<Vector2d> input, bool[] keep_segments, double offset_threshold)
		{
			int count = input.Count;
			if (count == 3)
			{
				return input;
			}
			result.Clear();
			result.Add(input[0]);
			result.Add(input[count / 3]);
			result.Add(input[count - count / 3]);
			return result;
		}
	}
	public abstract class SculptCurveDeformation
	{
		public struct DeformInfo
		{
			public bool bNoChange;

			public double maxEdgeLenSqr;

			public double minEdgeLenSqr;
		}

		protected DCurve3 _curve;

		protected Func<double, double, double> _weightfunc;

		protected double radius = 0.10000000149011612;

		protected Frame3f vPreviousPos;

		public DCurve3 Curve
		{
			get
			{
				return _curve;
			}
			set
			{
				if (_curve != value)
				{
					_curve = value;
				}
			}
		}

		public Func<double, double, double> WeightFunc
		{
			get
			{
				return _weightfunc;
			}
			set
			{
				if (_weightfunc != value)
				{
					_weightfunc = value;
				}
			}
		}

		public double Radius
		{
			get
			{
				return radius;
			}
			set
			{
				radius = value;
			}
		}

		public SculptCurveDeformation()
		{
			WeightFunc = (double d, double r) => MathUtil.WyvillFalloff01(MathUtil.Clamp(d / r, 0.0, 1.0));
		}

		public virtual void BeginDeformation(Frame3f vStartPos)
		{
			vPreviousPos = vStartPos;
		}

		public virtual DeformInfo UpdateDeformation(Frame3f vNextPos)
		{
			DeformInfo result = Apply(vNextPos);
			vPreviousPos = vNextPos;
			return result;
		}

		public abstract DeformInfo Apply(Frame3f vNextPos);
	}
	public class StandardSculptCurveDeformation : SculptCurveDeformation
	{
		public Func<int, double, Vector3d> DeformF;

		public double SmoothAlpha = 0.10000000149011612;

		public int SmoothIterations = 1;

		public DVector<Vector3d> NewV;

		public BitArray ModifiedV;

		public StandardSculptCurveDeformation()
		{
			NewV = new DVector<Vector3d>();
			NewV.resize(256);
			ModifiedV = new BitArray(256);
		}

		public override DeformInfo Apply(Frame3f vNextPos)
		{
			Interval1d empty = Interval1d.Empty;
			int vertexCount = base.Curve.VertexCount;
			if (vertexCount > NewV.size)
			{
				NewV.resize(vertexCount);
			}
			if (vertexCount > ModifiedV.Length)
			{
				ModifiedV = new BitArray(2 * vertexCount);
			}
			ModifiedV.SetAll(value: false);
			bool flag = SmoothAlpha > 0.0 && SmoothIterations > 0;
			double num = base.Radius * base.Radius;
			if (DeformF != null)
			{
				for (int i = 0; i < vertexCount; i++)
				{
					double lengthSquared = (base.Curve[i] - vPreviousPos.Origin).LengthSquared;
					if (!(lengthSquared < num))
					{
						continue;
					}
					double arg = base.WeightFunc(Math.Sqrt(lengthSquared), base.Radius);
					Vector3d value = DeformF(i, arg);
					if (!flag)
					{
						if (i > 0)
						{
							empty.Contain(value.DistanceSquared(base.Curve[i - 1]));
						}
						if (i < vertexCount - 1)
						{
							empty.Contain(value.DistanceSquared(base.Curve[i + 1]));
						}
					}
					NewV[i] = value;
					ModifiedV[i] = true;
				}
			}
			if (flag)
			{
				for (int j = 0; j < SmoothIterations; j++)
				{
					bool num2 = !base.Curve.Closed;
					int num3 = (base.Curve.Closed ? vertexCount : (vertexCount - 1));
					for (int k = (num2 ? 1 : 0); k < num3; k++)
					{
						Vector3d vector3d = (ModifiedV[k] ? NewV[k] : base.Curve[k]);
						double lengthSquared2 = (vector3d - vPreviousPos.Origin).LengthSquared;
						if (ModifiedV[k] || lengthSquared2 < num)
						{
							double num4 = SmoothAlpha * base.WeightFunc(Math.Sqrt(lengthSquared2), base.Radius);
							int num5 = ((k == 0) ? (vertexCount - 1) : (k - 1));
							int num6 = (k + 1) % vertexCount;
							Vector3d obj = (ModifiedV[num5] ? NewV[num5] : base.Curve[num5]);
							Vector3d vector3d2 = (ModifiedV[num6] ? NewV[num6] : base.Curve[num6]);
							Vector3d vector3d3 = (obj + vector3d2) * 0.5;
							NewV[k] = (1.0 - num4) * vector3d + num4 * vector3d3;
							ModifiedV[k] = true;
							if (k > 0)
							{
								empty.Contain(NewV[k].DistanceSquared(base.Curve[k - 1]));
							}
							if (k < vertexCount - 1)
							{
								empty.Contain(NewV[k].DistanceSquared(base.Curve[k + 1]));
							}
						}
					}
				}
			}
			for (int l = 0; l < vertexCount; l++)
			{
				if (ModifiedV[l])
				{
					base.Curve[l] = NewV[l];
				}
			}
			return new DeformInfo
			{
				bNoChange = false,
				minEdgeLenSqr = empty.a,
				maxEdgeLenSqr = empty.b
			};
		}
	}
	public class SculptCurveSmooth : StandardSculptCurveDeformation
	{
		public SculptCurveSmooth()
		{
			DeformF = null;
			SmoothAlpha = 0.10000000149011612;
			SmoothIterations = 3;
		}
	}
	public class SculptCurveMove : StandardSculptCurveDeformation
	{
		public SculptCurveMove()
		{
			SmoothAlpha = 0.0;
			SmoothIterations = 0;
		}

		public override DeformInfo Apply(Frame3f vNextPos)
		{
			if (((Vector3d)(vNextPos.Origin - vPreviousPos.Origin)).Length < 9.999999747378752E-05)
			{
				return new DeformInfo
				{
					bNoChange = true,
					maxEdgeLenSqr = 0.0,
					minEdgeLenSqr = double.MaxValue
				};
			}
			DeformF = delegate(int idx, double t)
			{
				Vector3d v = vPreviousPos.ToFrameP(base.Curve[idx]);
				Vector3d b = vNextPos.FromFrameP(v);
				return Vector3d.Lerp(base.Curve[idx], b, t);
			};
			return base.Apply(vNextPos);
		}
	}
