			double num12 = num11 + (num9 * a + num6 * b) * num10;
			Grid.get_x_pair(num, num3, num4, out a, out b);
			num10 = num7 * (1.0 - num8);
			double num13 = num12 + (num9 * a + num6 * b) * num10;
			Grid.get_x_pair(num, num3, num5, out a, out b);
			num10 = num7 * num8;
