	public class ImplicitBlend3d : BoundedImplicitFunction3d, ImplicitFunction3d
	{
		public BoundedImplicitFunction3d A;

		public BoundedImplicitFunction3d B;

		private double weightA = 0.01;

		private double weightB = 0.01;

		private double blend = 2.0;

		public double ExpandBounds = 0.25;

		public double WeightA
		{
			get
			{
				return weightA;
			}
			set
			{
				weightA = MathUtil.Clamp(value, 1E-05, 100000.0);
			}
		}

		public double WeightB
		{
			get
			{
				return weightB;
			}
			set
			{
				weightB = MathUtil.Clamp(value, 1E-05, 100000.0);
			}
		}

		public double Blend
		{
			get
			{
				return blend;
			}
			set
			{
				blend = MathUtil.Clamp(value, 0.0, 100000.0);
			}
		}

		public double Value(ref Vector3d pt)
		{
			double num = A.Value(ref pt);
			double num2 = B.Value(ref pt);
			double num3 = num * num + num2 * num2;
			if (num3 > 1000000000000.0)
			{
				return Math.Min(num, num2);
			}
			double num4 = num / weightA;
			double num5 = num2 / weightB;
			double num6 = blend / (1.0 + num4 * num4 + num5 * num5);
			return 0.666666 * (num + num2 - Math.Sqrt(num3 - num * num2)) - num6;
		}

		public AxisAlignedBox3d Bounds()
		{
			AxisAlignedBox3d result = A.Bounds();
			result.Contain(B.Bounds());
			result.Expand(ExpandBounds * result.MaxDim);
			return result;
		}
	}
	public class DistanceFieldToSkeletalField : BoundedImplicitFunction3d, ImplicitFunction3d
	{
		public BoundedImplicitFunction3d DistanceField;

		public double FalloffDistance;

		public const double ZeroIsocontour = 27.0 / 64.0;

		public AxisAlignedBox3d Bounds()
		{
			AxisAlignedBox3d result = DistanceField.Bounds();
			result.Expand(FalloffDistance);
			return result;
		}

		public double Value(ref Vector3d pt)
		{
			double num = DistanceField.Value(ref pt);
			if (num > FalloffDistance)
			{
				return 0.0;
			}
			if (num < 0.0 - FalloffDistance)
			{
				return 1.0;
			}
			double num2 = (num + FalloffDistance) / (2.0 * FalloffDistance);
			double num3 = 1.0 - num2 * num2;
			return num3 * num3 * num3;
		}
	}
	public class SkeletalBlend3d : BoundedImplicitFunction3d, ImplicitFunction3d
	{
		public BoundedImplicitFunction3d A;

		public BoundedImplicitFunction3d B;

		public double Value(ref Vector3d pt)
		{
			return A.Value(ref pt) + B.Value(ref pt);
		}

		public AxisAlignedBox3d Bounds()
		{
			AxisAlignedBox3d result = A.Bounds();
			result.Contain(B.Bounds());
			result.Expand(0.25 * result.MaxDim);
			return result;
		}
	}
	public class SkeletalRicciBlend3d : BoundedImplicitFunction3d, ImplicitFunction3d
	{
		public BoundedImplicitFunction3d A;

		public BoundedImplicitFunction3d B;

		public double BlendPower = 2.0;

		public double Value(ref Vector3d pt)
		{
			double num = A.Value(ref pt);
			double num2 = B.Value(ref pt);
			if (BlendPower == 1.0)
			{
				return num + num2;
			}
			if (BlendPower == 2.0)
			{
				return Math.Sqrt(num * num + num2 * num2);
			}
			return Math.Pow(Math.Pow(num, BlendPower) + Math.Pow(num2, BlendPower), 1.0 / BlendPower);
		}

		public AxisAlignedBox3d Bounds()
		{
			AxisAlignedBox3d result = A.Bounds();
			result.Contain(B.Bounds());
			result.Expand(0.25 * result.MaxDim);
			return result;
		}
	}
	public class SkeletalRicciNaryBlend3d : BoundedImplicitFunction3d, ImplicitFunction3d
	{
		public List<BoundedImplicitFunction3d> Children;

		public double BlendPower = 2.0;

		public double FieldShift;

		public double Value(ref Vector3d pt)
		{
			int count = Children.Count;
			double num = 0.0;
			if (BlendPower == 1.0)
			{
				for (int i = 0; i < count; i++)
				{
					num += Children[i].Value(ref pt);
				}
			}
			else if (BlendPower == 2.0)
			{
				for (int j = 0; j < count; j++)
				{
					double num2 = Children[j].Value(ref pt);
					num += num2 * num2;
				}
				num = Math.Sqrt(num);
			}
			else
			{
				for (int k = 0; k < count; k++)
				{
					double x = Children[k].Value(ref pt);
					num += Math.Pow(x, BlendPower);
				}
				num = Math.Pow(num, 1.0 / BlendPower);
			}
			return num + FieldShift;
		}

		public AxisAlignedBox3d Bounds()
		{
			AxisAlignedBox3d result = Children[0].Bounds();
			int count = Children.Count;
			for (int i = 1; i < count; i++)
			{
				result.Contain(Children[i].Bounds());
			}
			result.Expand(0.25 * result.MaxDim);
			return result;
		}
	}
	public class ImplicitFieldSampler3d
	{
		public enum CombineModes
		{
			DistanceMinUnion
		}

		public DenseGrid3f Grid;

		public double CellSize;

		public Vector3d GridOrigin;

		public ShiftGridIndexer3 Indexer;

		public AxisAlignedBox3i GridBounds;

		public float BackgroundValue;

		public CombineModes CombineMode;

		public ImplicitFieldSampler3d(AxisAlignedBox3d fieldBounds, double cellSize)
		{
			CellSize = cellSize;
			GridOrigin = fieldBounds.Min;
			Indexer = new ShiftGridIndexer3(GridOrigin, CellSize);
			Vector3d vector3d = fieldBounds.Max + cellSize;
			int num = (int)((vector3d.x - GridOrigin.x) / CellSize) + 1;
			int num2 = (int)((vector3d.y - GridOrigin.y) / CellSize) + 1;
			int num3 = (int)((vector3d.z - GridOrigin.z) / CellSize) + 1;
			GridBounds = new AxisAlignedBox3i(0, 0, 0, num, num2, num3);
			BackgroundValue = (float)((double)(num + num2 + num3) * CellSize);
			Grid = new DenseGrid3f(num, num2, num3, BackgroundValue);
		}

		public DenseGridTrilinearImplicit ToImplicit()
		{
			return new DenseGridTrilinearImplicit(Grid, GridOrigin, CellSize);
		}

		public void Clear(float f)
		{
			BackgroundValue = f;
			Grid.assign(BackgroundValue);
		}

		public void Sample(BoundedImplicitFunction3d f, double expandRadius = 0.0)
		{
			AxisAlignedBox3d axisAlignedBox3d = f.Bounds();
			Vector3d vector3d = expandRadius * Vector3d.One;
			Vector3i v = Indexer.ToGrid(axisAlignedBox3d.Min - vector3d);
			Vector3i v2 = Indexer.ToGrid(axisAlignedBox3d.Max + vector3d) + Vector3i.One;
			v = GridBounds.ClampExclusive(v);
			v2 = GridBounds.ClampExclusive(v2);
			AxisAlignedBox3i axisAlignedBox3i = new AxisAlignedBox3i(v, v2);
			if (CombineMode == CombineModes.DistanceMinUnion)
			{
				sample_min(f, axisAlignedBox3i.IndicesInclusive());
			}
		}

		private void sample_min(BoundedImplicitFunction3d f, IEnumerable<Vector3i> indices)
		{
			gParallel.ForEach(indices, delegate(Vector3i idx)
			{
				Vector3d pt = Indexer.FromGrid(idx);
				double num = f.Value(ref pt);
				Grid.set_min(ref idx, (float)num);
			});
		}
	}
	public abstract class ImplicitNAryOp2d : ImplicitOperator2d, ImplicitField2d
	{
		protected List<ImplicitField2d> m_vChildren;

		public virtual AxisAlignedBox2f Bounds
		{
			get
			{
				AxisAlignedBox2f result = default(AxisAlignedBox2f);
				for (int i = 0; i < m_vChildren.Count; i++)
				{
					result.Contain(m_vChildren[i].Bounds);
				}
				return result;
			}
		}

		public ImplicitNAryOp2d()
		{
			m_vChildren = new List<ImplicitField2d>();
		}

		public void AddChild(ImplicitField2d pField)
		{
			m_vChildren.Add(pField);
		}

		public virtual float Value(float fX, float fY)
		{
			return 0f;
		}

		public virtual void Gradient(float fX, float fY, ref float fGX, ref float fGY)
		{
			float num = Value(fX, fY);
			fGX = (Value(fX + 0.001f, fY) - num) / 0.001f;
			fGY = (Value(fX, fY + 0.001f) - num) / 0.001f;
		}
	}
	public class ImplicitBlend2d : ImplicitNAryOp2d
	{
		public override float Value(float fX, float fY)
		{
			float num = 0f;
			foreach (ImplicitField2d vChild in m_vChildren)
			{
				num += vChild.Value(fX, fY);
			}
			return num;
		}

		public override void Gradient(float fX, float fY, ref float fGX, ref float fGY)
		{
			fGX = (fGY = 0f);
			float fGX2 = 0f;
			float fGY2 = 0f;
			foreach (ImplicitField2d vChild in m_vChildren)
			{
				vChild.Gradient(fX, fY, ref fGX2, ref fGY2);
				fGX += fGX2;
				fGY += fGY2;
			}
		}
	}
	public class ImplicitUnion2d : ImplicitNAryOp2d
	{
		public override float Value(float fX, float fY)
		{
			float num = 0f;
			foreach (ImplicitField2d vChild in m_vChildren)
			{
				num = Math.Max(num, vChild.Value(fX, fY));
			}
			return num;
		}

		public override void Gradient(float fX, float fY, ref float fGX, ref float fGY)
		{
			float num = 0f;
			int num2 = -1;
			for (int i = 0; i < m_vChildren.Count; i++)
			{
				float num3 = m_vChildren[i].Value(fX, fY);
				if (num3 > num)
				{
					num2 = i;
					num = num3;
				}
			}
			if (num2 >= 0)
			{
				m_vChildren[num2].Gradient(fX, fY, ref fGX, ref fGY);
			}
			else
			{
				fGX = (fGY = 0f);
			}
		}
	}
	public class ImplicitIntersection2d : ImplicitNAryOp2d
	{
		public override float Value(float fX, float fY)
		{
			float num = 1E+10f;
			foreach (ImplicitField2d vChild in m_vChildren)
			{
				num = Math.Min(num, vChild.Value(fX, fY));
			}
			return num;
		}

		public override void Gradient(float fX, float fY, ref float fGX, ref float fGY)
		{
			float num = 1E+10f;
			int num2 = -1;
			for (int i = 0; i < m_vChildren.Count; i++)
			{
				float num3 = m_vChildren[i].Value(fX, fY);
				if (num3 < num)
				{
					num2 = i;
				}
				num = num3;
			}
			if (num2 >= 0)
			{
				m_vChildren[num2].Gradient(fX, fY, ref fGX, ref fGY);
			}
			else
			{
				fGX = (fGY = 0f);
			}
		}
	}
	public class ImplicitDifference2d : ImplicitNAryOp2d
	{
		public override float Value(float fX, float fY)
		{
			if (m_vChildren.Count <= 0)
			{
				return 0f;
			}
			float num = m_vChildren[0].Value(fX, fY);
			for (int i = 1; i < m_vChildren.Count; i++)
			{
				float num2 = 1f - m_vChildren[i].Value(fX, fY);
				if (num2 < num)
				{
					num = num2;
				}
			}
			return num;
		}

		public override void Gradient(float fX, float fY, ref float fGX, ref float fGY)
		{
			if (m_vChildren.Count <= 0)
			{
				fGX = (fGY = 0f);
				return;
			}
			int num = 0;
			float num2 = m_vChildren[0].Value(fX, fY);
			for (int i = 1; i < m_vChildren.Count; i++)
			{
				float num3 = 1f - m_vChildren[i].Value(fX, fY);
				if (num3 < num2)
				{
					num = i;
					num2 = num3;
				}
			}
			m_vChildren[num].Gradient(fX, fY, ref fGX, ref fGY);
			if (num > 0)
			{
				fGX = 0f - fGX;
				fGY = 0f - fGY;
			}
		}
	}
	public class MarchingQuads
	{
		private struct Cell
		{
			private uint nPosition;

			public float fValue;

			public int nLeftVertex;

			public int nTopVertex;

			public bool bTouched;

			public uint x
			{
				get
				{
					return nPosition & 0xFFFF;
				}
				set
				{
					nPosition = (y << 16) | (value & 0xFFFF);
				}
			}

			public uint y
			{
				get
				{
					return (nPosition >> 16) & 0xFFFF;
				}
				set
				{
					nPosition = ((value & 0xFFFF) << 16) | x;
				}
			}

			public void Initialize(uint x, uint y)
			{
				this.x = x;
				this.y = y;
				fValue = s_fValueSentinel;
				nLeftVertex = (nTopVertex = -1);
				bTouched = false;
			}
		}

		private struct SeedPoint(float fX, float fY)
		{
			public float x = fX;

			public float y = fY;
		}

		private DPolyLine2f m_stroke;

		private AxisAlignedBox2f m_bounds;

		private float m_fXShift;

		private float m_fYShift;

		private float m_fScale;

		private int m_nCells;

		private float m_fCellSize;

		private static float s_fValueSentinel = 9999999f;

		private float m_fIsoValue;

		private static int LEFT = 1;

		private static int TOP = 2;

		private static int RIGHT = 4;

		private static int BOTTOM = 8;

		private static int ALL = 15;

		private Cell[][] m_cells;

		private ArrayList m_seedPoints;

		private ImplicitField2d m_field;

		private ArrayList m_cellStack;

		private bool[] m_bEdgeSigns;

		public int Subdivisions
		{
			get
			{
				return m_nCells;
			}
			set
			{
				m_nCells = value;
				SetBounds(m_bounds);
				InitializeCells();
			}
		}

		public AxisAlignedBox2f Bounds
		{
			get
			{
				return m_bounds;
			}
			set
			{
				SetBounds(value);
			}
		}

		public DPolyLine2f Stroke => m_stroke;

		public MarchingQuads(int nSubdivisions, AxisAlignedBox2f bounds, float fIsoValue)
		{
			m_stroke = new DPolyLine2f();
			m_bounds = default(AxisAlignedBox2f);
			m_nCells = nSubdivisions;
			SetBounds(bounds);
			m_cells = null;
			InitializeCells();
			m_seedPoints = new ArrayList();
			m_cellStack = new ArrayList();
			m_bEdgeSigns = new bool[4];
			m_fIsoValue = fIsoValue;
		}

		public AxisAlignedBox2f GetBounds()
		{
			return m_bounds;
		}

		public void AddSeedPoint(float x, float y)
		{
			m_seedPoints.Add(new SeedPoint(x - m_fXShift, y - m_fYShift));
		}

		public void ClearSeedPoints()
		{
			m_seedPoints.Clear();
		}

		public void ClearStroke()
		{
			m_stroke.Clear();
		}

		public void Polygonize(ImplicitField2d field)
		{
			m_field = field;
			ResetCells();
			m_cellStack.Clear();
			for (int i = 0; i < m_seedPoints.Count; i++)
			{
				SeedPoint obj = (SeedPoint)m_seedPoints[i];
				int num = (int)(obj.x / m_fCellSize);
				int num2 = (int)(obj.y / m_fCellSize);
				bool flag = false;
				while (!flag && num2 > 0 && num2 < m_cells.Length - 1 && num > 0 && num < m_cells[0].Length - 1)
				{
					if (!m_cells[num2][num].bTouched)
					{
						if (ProcessCell(num, num2))
						{
							flag = true;
						}
					}
					else
					{
						flag = true;
					}
					num--;
				}
				while (m_cellStack.Count != 0)
				{
					Cell cell = (Cell)m_cellStack[m_cellStack.Count - 1];
					m_cellStack.RemoveAt(m_cellStack.Count - 1);
					if (!m_cells[cell.y][cell.x].bTouched)
					{
						ProcessCell((int)cell.x, (int)cell.y);
					}
				}
			}
		}

		private void SubdivideStep(ref float fValue1, ref float fValue2, ref float fX1, ref float fY1, ref float fX2, ref float fY2, bool bVerticalEdge)
		{
			float num = 0.5f;
			float num2 = 0f;
			float num3 = 0f;
			if (bVerticalEdge)
			{
				num2 = fX1;
				num3 = num * fY1 + (1f - num) * fY2;
			}
			else
			{
				num2 = num * fX1 + (1f - num) * fX2;
				num3 = fY1;
			}
			float num4 = m_field.Value(num2, num3);
			if (num4 < m_fIsoValue)
			{
				fValue1 = num4;
				fX1 = num2;
				fY1 = num3;
			}
			else
			{
				fValue2 = num4;
				fX2 = num2;
				fY2 = num3;
			}
		}

		private int LerpAndAddStrokeVertex(float fValue1, float fValue2, int x1, int y1, int x2, int y2, bool bVerticalEdge)
		{
			if (fValue1 > fValue2)
			{
				int num = x1;
				x1 = x2;
				x2 = num;
				int num2 = y1;
				y1 = y2;
				y2 = num2;
				float num3 = fValue1;
				fValue1 = fValue2;
				fValue2 = num3;
			}
			float fValue3 = fValue1;
			float fValue4 = fValue2;
			float fX = (float)x1 * m_fCellSize + m_fXShift;
			float fY = (float)y1 * m_fCellSize + m_fYShift;
			float fX2 = (float)x2 * m_fCellSize + m_fXShift;
			float fY2 = (float)y2 * m_fCellSize + m_fYShift;
			for (int i = 0; i < 10; i++)
			{
				SubdivideStep(ref fValue3, ref fValue4, ref fX, ref fY, ref fX2, ref fY2, bVerticalEdge);
			}
			if (Math.Abs(fValue3) < Math.Abs(fValue4))
			{
				return m_stroke.AddVertex(fX, fY);
			}
			return m_stroke.AddVertex(fX2, fY2);
		}

		private int GetLeftEdgeVertex(int xi, int yi)
		{
			Cell cell = m_cells[yi][xi];
			if (cell.nLeftVertex != -1)
			{
				return cell.nLeftVertex;
			}
			m_cells[yi][xi].nLeftVertex = LerpAndAddStrokeVertex(cell.fValue, m_cells[yi + 1][xi].fValue, xi, yi, xi, yi + 1, bVerticalEdge: true);
			return m_cells[yi][xi].nLeftVertex;
		}

		private int GetRightEdgeVertex(int xi, int yi)
		{
			Cell cell = m_cells[yi][xi + 1];
			if (cell.nLeftVertex != -1)
			{
				return cell.nLeftVertex;
			}
			m_cells[yi][xi + 1].nLeftVertex = LerpAndAddStrokeVertex(cell.fValue, m_cells[yi + 1][xi + 1].fValue, xi + 1, yi, xi + 1, yi + 1, bVerticalEdge: true);
			return m_cells[yi][xi + 1].nLeftVertex;
		}

		private int GetTopEdgeVertex(int xi, int yi)
		{
			Cell cell = m_cells[yi][xi];
			if (cell.nTopVertex != -1)
			{
				return cell.nTopVertex;
			}
			m_cells[yi][xi].nTopVertex = LerpAndAddStrokeVertex(cell.fValue, m_cells[yi][xi + 1].fValue, xi, yi, xi + 1, yi, bVerticalEdge: false);
			return m_cells[yi][xi].nTopVertex;
		}

		private int GetBottomEdgeVertex(int xi, int yi)
		{
			Cell cell = m_cells[yi + 1][xi];
			if (cell.nTopVertex != -1)
			{
				return cell.nTopVertex;
			}
			m_cells[yi + 1][xi].nTopVertex = LerpAndAddStrokeVertex(cell.fValue, m_cells[yi + 1][xi + 1].fValue, xi, yi + 1, xi + 1, yi + 1, bVerticalEdge: false);
			return m_cells[yi + 1][xi].nTopVertex;
		}

		private bool ProcessCell(int xi, int yi)
		{
			m_cells[yi][xi].bTouched = true;
			int num = 0;
			for (int i = 0; i < 4; i++)
			{
				int num2 = xi + (i & 1);
				int num3 = yi + ((i >> 1) & 1);
				if (m_cells[num3][num2].fValue == s_fValueSentinel)
				{
					m_cells[num3][num2].fValue = m_field.Value((float)num2 * m_fCellSize + m_fXShift, (float)num3 * m_fCellSize + m_fYShift);
				}
				m_bEdgeSigns[i] = m_cells[num3][num2].fValue > m_fIsoValue;
				num |= (m_bEdgeSigns[i] ? 1 : 0) << i;
			}
			if (num == 0 || num == 15)
			{
				return false;
			}
			int num4 = 0;
			int num5 = 0;
			int num6 = 0;
			int num7 = 0;
			if (m_bEdgeSigns[0] != m_bEdgeSigns[2])
			{
				num4 = GetLeftEdgeVertex(xi, yi);
			}
			if (m_bEdgeSigns[1] != m_bEdgeSigns[3])
			{
				num5 = GetRightEdgeVertex(xi, yi);
			}
			if (m_bEdgeSigns[0] != m_bEdgeSigns[1])
			{
				num6 = GetTopEdgeVertex(xi, yi);
			}
			if (m_bEdgeSigns[2] != m_bEdgeSigns[3])
			{
				num7 = GetBottomEdgeVertex(xi, yi);
			}
			float num8 = 0f;
			if (num == 6 || num == 9)
			{
				num8 = m_field.Value((float)xi * m_fCellSize + m_fCellSize / 2f + m_fXShift, (float)yi * m_fCellSize + m_fCellSize / 2f + m_fYShift);
			}
			int num9 = 0;
			switch (num)
			{
			case 1:
			case 14:
				m_stroke.AddEdge(num4, num6);
				num9 = LEFT | TOP;
				break;
			case 2:
			case 13:
				m_stroke.AddEdge(num6, num5);
				num9 = RIGHT | TOP;
				break;
			case 4:
			case 11:
				m_stroke.AddEdge(num7, num4);
				num9 = LEFT | BOTTOM;
				break;
			case 7:
			case 8:
				m_stroke.AddEdge(num5, num7);
				num9 = RIGHT | BOTTOM;
				break;
			case 3:
			case 12:
				m_stroke.AddEdge(num5, num4);
				num9 = LEFT | RIGHT;
				break;
			case 5:
			case 10:
				m_stroke.AddEdge(num6, num7);
				num9 = BOTTOM | TOP;
				break;
			case 9:
				if (num8 > m_fIsoValue)
				{
					m_stroke.AddEdge(num4, num7);
					m_stroke.AddEdge(num6, num5);
				}
				else
				{
					m_stroke.AddEdge(num4, num6);
					m_stroke.AddEdge(num7, num5);
				}
				num9 = ALL;
				break;
			case 6:
				if (num8 > m_fIsoValue)
				{
					m_stroke.AddEdge(num4, num6);
					m_stroke.AddEdge(num7, num5);
				}
				else
				{
					m_stroke.AddEdge(num4, num7);
					m_stroke.AddEdge(num6, num5);
				}
				num9 = ALL;
				break;
			}
			if ((num9 & LEFT) != 0 && xi - 1 >= 0 && !m_cells[yi][xi - 1].bTouched)
			{
				m_cellStack.Add(m_cells[yi][xi - 1]);
			}
			if ((num9 & RIGHT) != 0 && xi + 1 < m_nCells && !m_cells[yi][xi + 1].bTouched)
			{
				m_cellStack.Add(m_cells[yi][xi + 1]);
			}
			if ((num9 & BOTTOM) != 0 && yi + 1 < m_nCells && !m_cells[yi + 1][xi].bTouched)
			{
				m_cellStack.Add(m_cells[yi + 1][xi]);
			}
			if ((num9 & TOP) != 0 && yi - 1 >= 0 && !m_cells[yi - 1][xi].bTouched)
			{
				m_cellStack.Add(m_cells[yi - 1][xi]);
			}
			return true;
		}

		private void ResetCells()
		{
			for (uint num = 0u; num < m_cells.Length; num++)
			{
				for (uint num2 = 0u; num2 < m_cells.Length; num2++)
				{
					m_cells[num][num2].bTouched = false;
					m_cells[num][num2].nLeftVertex = (m_cells[num][num2].nTopVertex = -1);
				}
			}
		}

		private void InitializeCells()
		{
			m_cells = new Cell[m_nCells + 1][];
			for (uint num = 0u; num < m_cells.Length; num++)
			{
				m_cells[num] = new Cell[m_nCells + 1];
				for (uint num2 = 0u; num2 < m_cells.Length; num2++)
				{
					m_cells[num][num2].Initialize(num2, num);
				}
			}
		}

		private void SetBounds(AxisAlignedBox2f bounds)
		{
			m_bounds = bounds;
			m_fXShift = ((bounds.Min.x < 0f) ? bounds.Min.x : (0f - bounds.Min.x));
			m_fYShift = ((bounds.Min.y < 0f) ? bounds.Min.y : (0f - bounds.Min.y));
			m_fScale = ((bounds.Width > bounds.Height) ? bounds.Width : bounds.Height);
			m_fCellSize = m_fScale / (float)m_nCells;
		}
	}
	public class Intersector1
	{
		public Interval1d U;

		public Interval1d V;

		public int NumIntersections;

		private Interval1d Intersections = Interval1d.Zero;

		public bool Test
		{
			get
			{
				if (U.a <= V.b)
				{
					return U.b >= V.a;
				}
				return false;
			}
		}

		public Intersector1(double u0, double u1, double v0, double v1)
		{
			U = new Interval1d(u0, u1);
			V = new Interval1d(v0, v1);
		}

		public Intersector1(Interval1d u, Interval1d v)
		{
			U = u;
			V = v;
		}

		public double GetIntersection(int i)
		{
			return Intersections[i];
		}

		public bool Find()
		{
			if (U.b < V.a || U.a > V.b)
			{
				NumIntersections = 0;
			}
			else if (U.b > V.a)
			{
				if (U.a < V.b)
				{
					NumIntersections = 2;
					Intersections.a = ((U.a < V.a) ? V.a : U.a);
					Intersections.b = ((U.b > V.b) ? V.b : U.b);
					if (Intersections.a == Intersections.b)
					{
						NumIntersections = 1;
					}
				}
				else
				{
					NumIntersections = 1;
					Intersections.a = U.a;
				}
			}
			else
			{
				NumIntersections = 1;
				Intersections.a = U.b;
			}
			return NumIntersections > 0;
		}
	}
	public class IntrLine2Line2
	{
		private Line2d line1;

		private Line2d line2;

		private double dotThresh = 1E-08;

		public int Quantity;

		public IntersectionResult Result;

		public IntersectionType Type;

		public Vector2d Point;

		public double Segment1Parameter;

		public double Segment2Parameter;

		public Line2d Line1
		{
			get
			{
				return line1;
			}
			set
			{
				line1 = value;
				Result = IntersectionResult.NotComputed;
			}
		}

		public Line2d Line2
		{
			get
			{
				return line2;
			}
			set
			{
				line2 = value;
				Result = IntersectionResult.NotComputed;
			}
		}

		public double DotThreshold
		{
			get
			{
				return dotThresh;
			}
			set
			{
				dotThresh = Math.Max(value, 0.0);
				Result = IntersectionResult.NotComputed;
			}
		}

		public bool IsSimpleIntersection
		{
			get
			{
				if (Result == IntersectionResult.Intersects)
				{
					return Type == IntersectionType.Point;
				}
				return false;
			}
		}

		public IntrLine2Line2(Line2d l1, Line2d l2)
		{
			line1 = l1;
			line2 = l2;
		}

		public IntrLine2Line2 Compute()
		{
			Find();
			return this;
		}

		public bool Find()
		{
			if (Result != IntersectionResult.NotComputed)
			{
				return Result == IntersectionResult.Intersects;
			}
			if (!line1.Direction.IsNormalized || !line2.Direction.IsNormalized)
			{
				Type = IntersectionType.Empty;
				Result = IntersectionResult.InvalidQuery;
				return false;
			}
			Vector2d s = Vector2d.Zero;
			Type = Classify(line1.Origin, line1.Direction, line2.Origin, line2.Direction, dotThresh, ref s);
			if (Type == IntersectionType.Point)
			{
				Quantity = 1;
				Point = line1.Origin + s.x * line1.Direction;
				Segment1Parameter = s.x;
				Segment2Parameter = s.y;
			}
			else if (Type == IntersectionType.Line)
			{
				Quantity = int.MaxValue;
			}
			else
			{
				Quantity = 0;
			}
			Result = ((Type != IntersectionType.Empty) ? IntersectionResult.Intersects : IntersectionResult.NoIntersection);
			return Result == IntersectionResult.Intersects;
		}

		public static IntersectionType Classify(Vector2d P0, Vector2d D0, Vector2d P1, Vector2d D1, double dotThreshold, ref Vector2d s)
		{
			dotThreshold = Math.Max(dotThreshold, 0.0);
			Vector2d vector2d = P1 - P0;
			double num = D0.DotPerp(D1);
			if (Math.Abs(num) > dotThreshold)
			{
				double num2 = 1.0 / num;
				double num3 = vector2d.DotPerp(D0);
				double num4 = vector2d.DotPerp(D1);
				s[0] = num4 * num2;
				s[1] = num3 * num2;
				return IntersectionType.Point;
			}
			vector2d.Normalize();
			if (Math.Abs(vector2d.DotPerp(D1)) <= dotThreshold)
			{
				return IntersectionType.Line;
			}
			return IntersectionType.Empty;
		}
	}
