			}
			zero[1] = Math.Abs(segment.Direction.Dot(box.AxisY));
			zero2[1] = Math.Abs(v.Dot(box.AxisY));
			num = box.Extent.y + segment.Extent * zero[1];
			if (zero2[1] > num)
