			vector3dTuple.V1 = triangle0.V2 - triangle0.V1;
			vector3dTuple.V2 = triangle0.V0 - triangle0.V2;
			Vector3d axis = vector3dTuple.V0.UnitCross(ref vector3dTuple.V1);
			double num = axis.Dot(ref triangle0.V0);
			ProjectOntoAxis(ref triangle1, ref axis, out var fmin, out var fmax);
			if (num < fmin || num > fmax)
			{
				return false;
			}
			Vector3dTuple3 vector3dTuple2 = default(Vector3dTuple3);
			vector3dTuple2.V0 = triangle1.V1 - triangle1.V0;
			vector3dTuple2.V1 = triangle1.V2 - triangle1.V1;
			vector3dTuple2.V2 = triangle1.V0 - triangle1.V2;
			Vector3d v = vector3dTuple2.V0.UnitCross(ref vector3dTuple2.V1);
			Vector3d v2 = axis.UnitCross(ref v);
			double fmin2;
			double fmax2;
			if (v2.Dot(ref v2) >= 1E-08)
			{
				double num2 = v.Dot(ref triangle1.V0);
				ProjectOntoAxis(ref triangle0, ref v, out fmin2, out fmax2);
				if (num2 < fmin2 || num2 > fmax2)
				{
					return false;
				}
				for (int i = 0; i < 3; i++)
				{
					for (int j = 0; j < 3; j++)
					{
						Vector3d axis2 = vector3dTuple[j].UnitCross(vector3dTuple2[i]);
						ProjectOntoAxis(ref triangle0, ref axis2, out fmin2, out fmax2);
						ProjectOntoAxis(ref triangle1, ref axis2, out fmin, out fmax);
						if (fmax2 < fmin || fmax < fmin2)
						{
							return false;
						}
					}
				}
				type = IntersectionType.Unknown;
			}
			else
			{
				for (int j = 0; j < 3; j++)
				{
					Vector3d axis2 = axis.UnitCross(vector3dTuple[j]);
					ProjectOntoAxis(ref triangle0, ref axis2, out fmin2, out fmax2);
					ProjectOntoAxis(ref triangle1, ref axis2, out fmin, out fmax);
					if (fmax2 < fmin || fmax < fmin2)
					{
						return false;
					}
				}
				for (int i = 0; i < 3; i++)
				{
					Vector3d axis2 = v.UnitCross(vector3dTuple2[i]);
					ProjectOntoAxis(ref triangle0, ref axis2, out fmin2, out fmax2);
					ProjectOntoAxis(ref triangle1, ref axis2, out fmin, out fmax);
					if (fmax2 < fmin || fmax < fmin2)
					{
						return false;
					}
				}
				type = IntersectionType.Plane;
			}
			return true;
		}

		public static void ProjectOntoAxis(ref Triangle3d triangle, ref Vector3d axis, out double fmin, out double fmax)
		{
			double num = axis.Dot(triangle.V0);
			double num2 = axis.Dot(triangle.V1);
			double num3 = axis.Dot(triangle.V2);
			fmin = num;
			fmax = fmin;
			if (num2 < fmin)
			{
				fmin = num2;
			}
			else if (num2 > fmax)
			{
				fmax = num2;
			}
			if (num3 < fmin)
			{
				fmin = num3;
			}
			else if (num3 > fmax)
			{
				fmax = num3;
			}
		}

		public static void TrianglePlaneRelations(ref Triangle3d triangle, ref Plane3d plane, out Vector3d distance, out Index3i sign, out int positive, out int negative, out int zero)
		{
			positive = 0;
			negative = 0;
			zero = 0;
			distance = Vector3d.Zero;
			sign = Index3i.Zero;
			for (int i = 0; i < 3; i++)
			{
				distance[i] = plane.DistanceTo(triangle[i]);
				if (distance[i] > 1E-08)
				{
					sign[i] = 1;
					positive++;
				}
				else if (distance[i] < -1E-08)
				{
					sign[i] = -1;
					negative++;
				}
				else
				{
					distance[i] = 0.0;
					sign[i] = 0;
					zero++;
				}
			}
		}

		private bool ContainsPoint(ref Triangle3d triangle, ref Plane3d plane, Vector3d point)
		{
			Vector3d u = Vector3d.Zero;
			Vector3d v = Vector3d.Zero;
			Vector3d.GenerateComplementBasis(ref u, ref v, plane.Normal);
			Vector3d v2 = point - triangle[0];
			Vector3d v3 = triangle[1] - triangle[0];
			Vector3d v4 = triangle[2] - triangle[0];
			Vector2d test = new Vector2d(u.Dot(v2), v.Dot(v2));
			if (new QueryTuple2d(new Vector2dTuple3(Vector2d.Zero, new Vector2d(u.Dot(v3), v.Dot(v3)), new Vector2d(u.Dot(v4), v.Dot(v4)))).ToTriangle(test, 0, 1, 2) <= 0)
			{
				Result = IntersectionResult.Intersects;
				Type = IntersectionType.Point;
				Quantity = 1;
				Points[0] = point;
				return true;
			}
			return false;
		}

		private bool IntersectsSegment(ref Plane3d plane, ref Triangle3d triangle, Vector3d end0, Vector3d end1)
		{
			int num = 0;
			double num2 = Math.Abs(plane.Normal.x);
			double num3 = Math.Abs(plane.Normal.y);
			if (num3 > num2)
			{
				num = 1;
				num2 = num3;
			}
			num3 = Math.Abs(plane.Normal.z);
			if (num3 > num2)
			{
				num = 2;
			}
			Triangle2d t = default(Triangle2d);
			Vector2d zero = Vector2d.Zero;
			Vector2d zero2 = Vector2d.Zero;
			switch (num)
			{
			case 0:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = triangle[i].yz;
					zero.x = end0.y;
					zero.y = end0.z;
					zero2.x = end1.y;
					zero2.y = end1.z;
				}
				break;
			}
			case 1:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = triangle[i].xz;
					zero.x = end0.x;
					zero.y = end0.z;
					zero2.x = end1.x;
					zero2.y = end1.z;
				}
				break;
			}
			default:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = triangle[i].xy;
					zero.x = end0.x;
					zero.y = end0.y;
					zero2.x = end1.x;
					zero2.y = end1.y;
				}
				break;
			}
			}
			IntrSegment2Triangle2 intrSegment2Triangle = new IntrSegment2Triangle2(new Segment2d(zero, zero2), t);
			if (!intrSegment2Triangle.Find())
			{
				return false;
			}
			Vector2dTuple2 vector2dTuple = default(Vector2dTuple2);
			if (intrSegment2Triangle.Type == IntersectionType.Segment)
			{
				Result = IntersectionResult.Intersects;
				Type = IntersectionType.Segment;
				Quantity = 2;
				vector2dTuple.V0 = intrSegment2Triangle.Point0;
				vector2dTuple.V1 = intrSegment2Triangle.Point1;
			}
			else
			{
				Result = IntersectionResult.Intersects;
				Type = IntersectionType.Point;
				Quantity = 1;
				vector2dTuple.V0 = intrSegment2Triangle.Point0;
			}
			switch (num)
			{
			case 0:
			{
				double num5 = 1.0 / plane.Normal.x;
				for (int i = 0; i < Quantity; i++)
				{
					double x2 = vector2dTuple[i].x;
					double y2 = vector2dTuple[i].y;
					double x3 = num5 * (plane.Constant - plane.Normal.y * x2 - plane.Normal.z * y2);
					Points[i] = new Vector3d(x3, x2, y2);
				}
				break;
			}
			case 1:
			{
				double num6 = 1.0 / plane.Normal.y;
				for (int i = 0; i < Quantity; i++)
				{
					double x4 = vector2dTuple[i].x;
					double y3 = vector2dTuple[i].y;
					double y4 = num6 * (plane.Constant - plane.Normal.x * x4 - plane.Normal.z * y3);
					Points[i] = new Vector3d(x4, y4, y3);
				}
				break;
			}
			default:
			{
				double num4 = 1.0 / plane.Normal.z;
				for (int i = 0; i < Quantity; i++)
				{
					double x = vector2dTuple[i].x;
					double y = vector2dTuple[i].y;
					double z = num4 * (plane.Constant - plane.Normal.x * x - plane.Normal.y * y);
					Points[i] = new Vector3d(x, y, z);
				}
				break;
			}
			}
			return true;
		}

		private bool GetCoplanarIntersection(ref Plane3d plane, ref Triangle3d tri0, ref Triangle3d tri1)
		{
			int num = 0;
			double num2 = Math.Abs(plane.Normal.x);
			double num3 = Math.Abs(plane.Normal.y);
			if (num3 > num2)
			{
				num = 1;
				num2 = num3;
			}
			num3 = Math.Abs(plane.Normal.z);
			if (num3 > num2)
			{
				num = 2;
			}
			Triangle2d t = default(Triangle2d);
			Triangle2d t2 = default(Triangle2d);
			switch (num)
			{
			case 0:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = tri0[i].yz;
					t2[i] = tri1[i].yz;
				}
				break;
			}
			case 1:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = tri0[i].xz;
					t2[i] = tri1[i].xz;
				}
				break;
			}
			default:
			{
				for (int i = 0; i < 3; i++)
				{
					t[i] = tri0[i].xy;
					t2[i] = tri1[i].xy;
				}
				break;
			}
			}
			Vector2d vector2d = t[1] - t[0];
			Vector2d v = t[2] - t[0];
			if (vector2d.DotPerp(v) < 0.0)
			{
				Vector2d value = t[1];
				t[1] = t[2];
				t[2] = value;
			}
			vector2d = t2[1] - t2[0];
			v = t2[2] - t2[0];
			if (vector2d.DotPerp(v) < 0.0)
			{
				Vector2d value = t2[1];
				t2[1] = t2[2];
				t2[2] = value;
			}
			IntrTriangle2Triangle2 intrTriangle2Triangle = new IntrTriangle2Triangle2(t, t2);
			if (!intrTriangle2Triangle.Find())
			{
				return false;
			}
			PolygonPoints = new Vector3d[intrTriangle2Triangle.Quantity];
			Quantity = intrTriangle2Triangle.Quantity;
			switch (num)
			{
			case 0:
			{
				double num5 = 1.0 / plane.Normal.x;
				for (int i = 0; i < Quantity; i++)
				{
					double x2 = intrTriangle2Triangle.Points[i].x;
					double y2 = intrTriangle2Triangle.Points[i].y;
					double x3 = num5 * (plane.Constant - plane.Normal.y * x2 - plane.Normal.z * y2);
					PolygonPoints[i] = new Vector3d(x3, x2, y2);
				}
				break;
			}
			case 1:
			{
				double num6 = 1.0 / plane.Normal.y;
				for (int i = 0; i < Quantity; i++)
				{
					double x4 = intrTriangle2Triangle.Points[i].x;
					double y3 = intrTriangle2Triangle.Points[i].y;
					double y4 = num6 * (plane.Constant - plane.Normal.x * x4 - plane.Normal.z * y3);
					PolygonPoints[i] = new Vector3d(x4, y4, y3);
				}
				break;
			}
			default:
			{
				double num4 = 1.0 / plane.Normal.z;
				for (int i = 0; i < Quantity; i++)
				{
					double x = intrTriangle2Triangle.Points[i].x;
					double y = intrTriangle2Triangle.Points[i].y;
					double z = num4 * (plane.Constant - plane.Normal.x * x - plane.Normal.y * y);
					PolygonPoints[i] = new Vector3d(x, y, z);
				}
				break;
			}
			}
			Result = IntersectionResult.Intersects;
			Type = IntersectionType.Polygon;
			return true;
		}
	}
	public class BinaryG3Writer : IMeshWriter
	{
		public IOWriteResult Write(BinaryWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			int count = vMeshes.Count;
			writer.Write(count);
			for (int i = 0; i < vMeshes.Count; i++)
			{
				gSerialization.Store((vMeshes[i].Mesh as DMesh3) ?? throw new NotImplementedException("BinaryG3Writer.Write: can only write DMesh3 meshes"), writer);
			}
			return new IOWriteResult(IOCode.Ok, "");
		}

		public IOWriteResult Write(TextWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			throw new NotSupportedException("BinaryG3 Writer does not support ascii mode");
		}
	}
	public class BinaryG3Reader : IMeshReader
	{
		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				DMesh3 dMesh = new DMesh3();
				gSerialization.Restore(dMesh, reader);
				builder.AppendNewMesh(dMesh);
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			throw new NotSupportedException("BinaryG3Reader Writer does not support ascii mode");
		}
	}
	internal class DS3Reader : IMeshReader
	{
		private Dictionary<string, int> warningCount = new Dictionary<string, int>();

		private string MeshName;

		private bool hasMesh;

		private bool is3ds;

		public event ParsingMessagesHandler warningEvent;

		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			string text = "";
			MeshName = "";
			hasMesh = false;
			is3ds = false;
			while (true)
			{
				ushort num;
				try
				{
					num = reader.ReadUInt16();
				}
				catch
				{
					break;
				}
				text = num.ToString("X");
				uint num2 = reader.ReadUInt32();
				switch (text)
				{
				case "4D4D":
					is3ds = true;
					reader.ReadChars(10);
					break;
				case "3D3D":
					reader.ReadChars(10);
					break;
				case "4000":
				{
					List<char> list2 = new List<char>();
					while (true)
					{
						char c2 = reader.ReadChar();
						if (c2 == '\0')
						{
							break;
						}
						list2.Add(c2);
					}
					MeshName = new string(Enumerable.ToArray(list2));
					break;
				}
				case "4100":
					builder.AppendNewMesh(bHaveVtxNormals: false, bHaveVtxColors: false, bHaveVtxUVs: false, bHaveFaceGroups: false);
					if (builder.SupportsMetaData)
					{
						builder.AppendMetaData("name", MeshName);
					}
					break;
				case "4110":
				{
					ushort num5 = reader.ReadUInt16();
					for (int i = 0; i < num5; i++)
					{
						double x = reader.ReadSingle();
						double y = reader.ReadSingle();
						double z = reader.ReadSingle();
						builder.AppendVertex(x, y, z);
					}
					break;
				}
				case "4120":
				{
					ushort num7 = reader.ReadUInt16();
					for (int k = 0; k < num7; k++)
					{
						int i2 = reader.ReadInt16();
						int j2 = reader.ReadInt16();
						int k2 = reader.ReadInt16();
						reader.ReadUInt16();
						builder.AppendTriangle(i2, j2, k2);
					}
					break;
				}
				case "4130":
				{
					List<char> list = new List<char>();
					while (true)
					{
						char c = reader.ReadChar();
						if (c == '\0')
						{
							break;
						}
						list.Add(c);
					}
					new string(Enumerable.ToArray(list));
					ushort num6 = reader.ReadUInt16();
					for (int j = 0; j < num6; j++)
					{
						reader.ReadUInt16();
					}
					break;
				}
				case "4140":
				{
					ushort num3 = reader.ReadUInt16();
					for (ushort num4 = 0; num4 < num3; num4++)
					{
						Vector2f uvs = new Vector2f(reader.ReadSingle(), reader.ReadSingle());
						builder.SetVertexUV(num4, uvs);
					}
					break;
				}
				default:
					reader.ReadChars((int)(num2 - 6));
					break;
				}
			}
			if (!is3ds)
			{
				return new IOReadResult(IOCode.FileAccessError, "File is not in .3DS format");
			}
			if (!hasMesh)
			{
				return new IOReadResult(IOCode.FileParsingError, "no mesh found in file");
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			return new IOReadResult(IOCode.FormatNotSupportedError, "text read not supported for 3DS format");
		}

		private void emit_warning(string sMessage)
		{
			string key = sMessage.Substring(0, 15);
			int num = (warningCount.ContainsKey(key) ? warningCount[key] : 0);
			num++;
			warningCount[key] = num;
			if (num <= 10)
			{
				if (num == 10)
				{
					sMessage += " (additional message surpressed)";
				}
				this.warningEvent?.Invoke(sMessage, null);
			}
		}
	}
	public static class gSerialization
	{
		public static int DMesh3Version = 1;

		public static void Store(Vector2f v, BinaryWriter writer)
		{
			writer.Write(v.x);
			writer.Write(v.y);
		}

		public static void Restore(ref Vector2f v, BinaryReader reader)
		{
			v.x = reader.ReadSingle();
			v.y = reader.ReadSingle();
		}

		public static void Store(Vector2d v, BinaryWriter writer)
		{
			writer.Write(v.x);
			writer.Write(v.y);
		}

		public static void Restore(ref Vector2d v, BinaryReader reader)
		{
			v.x = reader.ReadDouble();
			v.y = reader.ReadDouble();
		}

		public static void Store(Vector3f v, BinaryWriter writer)
		{
			writer.Write(v.x);
			writer.Write(v.y);
			writer.Write(v.z);
		}

		public static void Restore(ref Vector3f v, BinaryReader reader)
		{
			v.x = reader.ReadSingle();
			v.y = reader.ReadSingle();
			v.z = reader.ReadSingle();
		}

		public static void Store(Vector3d v, BinaryWriter writer)
		{
			writer.Write(v.x);
			writer.Write(v.y);
			writer.Write(v.z);
		}

		public static void Restore(ref Vector3d v, BinaryReader reader)
		{
			v.x = reader.ReadDouble();
			v.y = reader.ReadDouble();
			v.z = reader.ReadDouble();
		}

		public static void Store(Quaternionf q, BinaryWriter writer)
		{
			writer.Write(q.x);
			writer.Write(q.y);
			writer.Write(q.z);
			writer.Write(q.w);
		}

		public static void Restore(ref Quaternionf q, BinaryReader reader)
		{
			q.x = reader.ReadSingle();
			q.y = reader.ReadSingle();
			q.z = reader.ReadSingle();
			q.w = reader.ReadSingle();
		}

		public static void Store(Frame3f vFrame, BinaryWriter writer)
		{
			Store(vFrame.Origin, writer);
			Store(vFrame.Rotation, writer);
		}

		public static void Restore(ref Frame3f vFrame, BinaryReader reader)
		{
			Vector3f v = Vector3f.Zero;
			Quaternionf q = Quaternionf.Identity;
			Restore(ref v, reader);
			Restore(ref q, reader);
			vFrame = new Frame3f(v, q);
		}

		public static void Store(AxisAlignedBox2d b, BinaryWriter writer)
		{
			Store(b.Min, writer);
			Store(b.Max, writer);
		}

		public static void Restore(ref AxisAlignedBox2d b, BinaryReader reader)
		{
			Restore(ref b.Min, reader);
			Restore(ref b.Max, reader);
		}

		public static void Store(List<int> values, BinaryWriter writer)
		{
			writer.Write(values.Count);
			for (int i = 0; i < values.Count; i++)
			{
				writer.Write(values[i]);
			}
		}

		public static void Restore(List<int> values, BinaryReader reader)
		{
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				values.Add(reader.ReadInt32());
			}
		}

		public static void Store(List<float> values, BinaryWriter writer)
		{
			writer.Write(values.Count);
			for (int i = 0; i < values.Count; i++)
			{
				writer.Write(values[i]);
			}
		}

		public static void Restore(List<float> values, BinaryReader reader)
		{
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				values.Add(reader.ReadSingle());
			}
		}

		public static void Store(List<double> values, BinaryWriter writer)
		{
			writer.Write(values.Count);
			for (int i = 0; i < values.Count; i++)
			{
				writer.Write(values[i]);
			}
		}

		public static void Restore(List<double> values, BinaryReader reader)
		{
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				values.Add(reader.ReadDouble());
			}
		}

		public static void Store(DCurve3 curve, BinaryWriter writer)
		{
			writer.Write(curve.Closed);
			writer.Write(curve.VertexCount);
			for (int i = 0; i < curve.VertexCount; i++)
			{
				writer.Write(curve[i].x);
				writer.Write(curve[i].y);
				writer.Write(curve[i].z);
			}
		}

		public static void Restore(DCurve3 curve, BinaryReader reader)
		{
			curve.Closed = reader.ReadBoolean();
			int num = reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				double x = reader.ReadDouble();
				double y = reader.ReadDouble();
				double z = reader.ReadDouble();
				curve.AppendVertex(new Vector3d(x, y, z));
			}
		}

		public static void Store(PolyLine2d polyline, BinaryWriter writer)
		{
			writer.Write(polyline.VertexCount);
			for (int i = 0; i < polyline.VertexCount; i++)
			{
				writer.Write(polyline[i].x);
				writer.Write(polyline[i].y);
			}
		}

