	public static class MeshIOUtil
	{
		public static List<GenericMaterial> FindUniqueMaterialList(List<WriteMesh> meshes)
		{
			List<GenericMaterial> list = new List<GenericMaterial>();
			foreach (WriteMesh mesh in meshes)
			{
				if (mesh.Materials == null)
				{
					continue;
				}
				foreach (GenericMaterial material in mesh.Materials)
				{
					if (!list.Contains(material))
					{
						list.Add(material);
					}
				}
			}
			return list;
		}
	}
	internal struct Triangle
	{
		public const int InvalidMaterialID = -1;

		public const int InvalidGroupID = -1;

		public Index3i vIndices;

		public Index3i vNormals;

		public Index3i vUVs;

		public int nMaterialID;

		public int nGroupID;

		public void clear()
		{
			nMaterialID = -1;
			nGroupID = -1;
			vIndices = (vNormals = (vUVs = new Index3i(-1, -1, -1)));
		}

		public void set_vertex(int j, int vi, int ni = -1, int ui = -1)
		{
			vIndices[j] = vi;
			if (ni != -1)
			{
				vNormals[j] = ni;
			}
			if (ui != -1)
			{
				vUVs[j] = ui;
			}
		}

		public void move_vertex(int jFrom, int jTo)
		{
			vIndices[jTo] = vIndices[jFrom];
			vNormals[jTo] = vNormals[jFrom];
			vUVs[jTo] = vUVs[jFrom];
		}

		public bool is_complex()
		{
			for (int i = 0; i < 3; i++)
			{
				if (vNormals[i] != -1 && vNormals[i] != vNormals[i])
				{
					return true;
				}
				if (vUVs[i] != -1 && vUVs[i] != vUVs[i])
				{
					return true;
				}
			}
			return false;
		}
	}
	public class OBJReader : IMeshReader
	{
		private DVector<double> vPositions;

		private DVector<float> vNormals;

		private DVector<float> vUVs;

		private DVector<float> vColors;

		private DVector<Triangle> vTriangles;

		private Dictionary<string, OBJMaterial> Materials;

		private Dictionary<int, string> UsedMaterials;

		private bool m_bOBJHasPerVertexColors;

		private int m_nUVComponents;

		private bool m_bOBJHasTriangleGroups;

		private int m_nSetInvalidGroupsTo;

		private string[] splitDoubleSlash;

		private char[] splitSlash;

		private int nWarningLevel;

		private Dictionary<string, int> warningCount = new Dictionary<string, int>();

		public List<string> MTLFileSearchPaths { get; set; }

		public bool HasPerVertexColors => m_bOBJHasPerVertexColors;

		public int UVDimension => m_nUVComponents;

		public bool HasTriangleGroups => m_bOBJHasTriangleGroups;

		public bool HasComplexVertices { get; set; }

		public event ParsingMessagesHandler warningEvent;

		public OBJReader()
		{
			splitDoubleSlash = new string[1] { "//" };
			splitSlash = new char[1] { '/' };
			MTLFileSearchPaths = new List<string>();
		}

		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			throw new NotImplementedException();
		}

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			Materials = new Dictionary<string, OBJMaterial>();
			UsedMaterials = new Dictionary<int, string>();
			HasComplexVertices = false;
			if (nWarningLevel >= 1)
			{
				emit_warning("[OBJReader] starting parse");
			}
			IOReadResult result = ParseInput(reader, options);
			if (result.code != IOCode.Ok)
			{
				return result;
			}
			if (nWarningLevel >= 1)
			{
				emit_warning("[OBJReader] completed parse. building.");
			}
			IOReadResult result2 = ((UsedMaterials.Count > 1 || HasComplexVertices) ? BuildMeshes_ByMaterial(options, builder) : BuildMeshes_Simple(options, builder));
			if (nWarningLevel >= 1)
			{
				emit_warning("[OBJReader] build complete.");
			}
			if (result2.code != IOCode.Ok)
			{
				return result2;
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		private int append_vertex(IMeshBuilder builder, Index3i vertIdx, bool bHaveNormals, bool bHaveColors, bool bHaveUVs)
		{
			int num = 3 * vertIdx.a;
			if (vertIdx.a < 0 || vertIdx.a >= vPositions.Length / 3)
			{
				emit_warning("[OBJReader] append_vertex() referencing invalid vertex " + vertIdx.a);
				return -1;
			}
			if (!bHaveNormals && !bHaveColors && !bHaveUVs)
			{
				return builder.AppendVertex(vPositions[num], vPositions[num + 1], vPositions[num + 2]);
			}
			NewVertexInfo info = default(NewVertexInfo);
			info.bHaveC = (info.bHaveN = (info.bHaveUV = false));
			info.v = new Vector3d(vPositions[num], vPositions[num + 1], vPositions[num + 2]);
			if (bHaveNormals)
			{
				info.bHaveN = true;
				int num2 = 3 * vertIdx.b;
				info.n = new Vector3f(vNormals[num2], vNormals[num2 + 1], vNormals[num2 + 2]);
			}
			if (bHaveColors)
			{
				info.bHaveC = true;
				info.c = new Vector3f(vColors[num], vColors[num + 1], vColors[num + 2]);
			}
			if (bHaveUVs)
			{
				info.bHaveUV = true;
				int num3 = 2 * vertIdx.c;
				info.uv = new Vector2f(vUVs[num3], vUVs[num3 + 1]);
			}
			return builder.AppendVertex(info);
		}

		private int append_triangle(IMeshBuilder builder, int nTri, int[] mapV)
		{
			Triangle triangle = vTriangles[nTri];
			int num = mapV[triangle.vIndices[0] - 1];
			int num2 = mapV[triangle.vIndices[1] - 1];
			int num3 = mapV[triangle.vIndices[2] - 1];
			if (num == -1 || num2 == -1 || num3 == -1)
			{
				emit_warning($"[OBJReader] invalid triangle:  {triangle.vIndices[0]} {triangle.vIndices[1]} {triangle.vIndices[2]}  mapped to {num} {num2} {num3}");
				return -1;
			}
			int g = ((vTriangles[nTri].nGroupID == -1) ? m_nSetInvalidGroupsTo : vTriangles[nTri].nGroupID);
			return builder.AppendTriangle(num, num2, num3, g);
		}

		private int append_triangle(IMeshBuilder builder, Triangle t)
		{
			if (t.vIndices[0] < 0 || t.vIndices[1] < 0 || t.vIndices[2] < 0)
			{
				emit_warning($"[OBJReader] invalid triangle:  {t.vIndices[0]} {t.vIndices[1]} {t.vIndices[2]}");
				return -1;
			}
			int g = ((t.nGroupID == -1) ? m_nSetInvalidGroupsTo : t.nGroupID);
			return builder.AppendTriangle(t.vIndices[0], t.vIndices[1], t.vIndices[2], g);
		}

		private IOReadResult BuildMeshes_Simple(ReadOptions options, IMeshBuilder builder)
		{
			if (vPositions.Length == 0)
			{
				return new IOReadResult(IOCode.GarbageDataError, "No vertices in file");
			}
			if (vTriangles.Length == 0)
			{
				return new IOReadResult(IOCode.GarbageDataError, "No triangles in file");
			}
			bool flag = vNormals.Length == vPositions.Length;
			bool flag2 = vColors.Length == vPositions.Length;
			bool flag3 = vUVs.Length / 2 == vPositions.Length / 3;
			int num = vPositions.Length / 3;
			int[] array = new int[num];
			int meshID = builder.AppendNewMesh(flag, flag2, flag3, m_bOBJHasTriangleGroups);
			for (int i = 0; i < num; i++)
			{
				Index3i vertIdx = new Index3i(i, i, i);
				array[i] = append_vertex(builder, vertIdx, flag, flag2, flag3);
			}
			for (int j = 0; j < vTriangles.Length; j++)
			{
				append_triangle(builder, j, array);
			}
			if (UsedMaterials.Count == 1)
			{
				int key = UsedMaterials.Keys.First();
				string key2 = UsedMaterials[key];
				OBJMaterial m = Materials[key2];
				int materialID = builder.BuildMaterial(m);
				builder.AssignMaterial(materialID, meshID);
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		private IOReadResult BuildMeshes_ByMaterial(ReadOptions options, IMeshBuilder builder)
		{
			if (vPositions.Length == 0)
			{
				return new IOReadResult(IOCode.GarbageDataError, "No vertices in file");
			}
			if (vTriangles.Length == 0)
			{
				return new IOReadResult(IOCode.GarbageDataError, "No triangles in file");
			}
			bool flag = vNormals.Length > 0;
			bool flag2 = vColors.Length > 0;
			bool flag3 = vUVs.Length > 0;
			foreach (int item in new List<int>(UsedMaterials.Keys) { -1 })
			{
				int num = -1;
				if (item != -1)
				{
					string key = UsedMaterials[item];
					OBJMaterial m = Materials[key];
					num = builder.BuildMaterial(m);
				}
				bool flag4 = item != -1 && flag3;
				int num2 = -1;
				Dictionary<Index3i, int> dictionary = new Dictionary<Index3i, int>();
				for (int i = 0; i < vTriangles.Length; i++)
				{
					Triangle triangle = vTriangles[i];
					if (triangle.nMaterialID == item)
					{
						if (num2 == -1)
						{
							num2 = builder.AppendNewMesh(flag, flag2, flag4, bHaveFaceGroups: false);
						}
						Triangle t = default(Triangle);
						for (int j = 0; j < 3; j++)
						{
							Index3i index3i = new Index3i(triangle.vIndices[j] - 1, triangle.vNormals[j] - 1, triangle.vUVs[j] - 1);
							int num3 = -1;
							num3 = (dictionary.ContainsKey(index3i) ? dictionary[index3i] : (dictionary[index3i] = append_vertex(builder, index3i, flag, flag2, flag4)));
							t.vIndices[j] = num3;
						}
						append_triangle(builder, t);
					}
				}
				if (num != -1)
				{
					builder.AssignMaterial(num, num2);
				}
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		public IOReadResult ParseInput(TextReader reader, ReadOptions options)
		{
			vPositions = new DVector<double>();
			vNormals = new DVector<float>();
			vUVs = new DVector<float>();
			vColors = new DVector<float>();
			vTriangles = new DVector<Triangle>();
			bool bOBJHasPerVertexColors = false;
			int num = 0;
			OBJMaterial oBJMaterial = null;
			Dictionary<string, int> dictionary = new Dictionary<string, int>();
			int num2 = 0;
			int num3 = -1;
			int num4 = 0;
			while (reader.Peek() >= 0)
			{
				string text = reader.ReadLine();
				num4++;
				string[] array = text.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array.Length == 0)
				{
					continue;
				}
				try
				{
					if (array[0][0] == 'v')
					{
						if (array[0].Length == 1)
						{
							if (array.Length == 7)
							{
								vPositions.Add(double.Parse(array[1]));
								vPositions.Add(double.Parse(array[2]));
								vPositions.Add(double.Parse(array[3]));
								vColors.Add(float.Parse(array[4]));
								vColors.Add(float.Parse(array[5]));
								vColors.Add(float.Parse(array[6]));
								bOBJHasPerVertexColors = true;
							}
							else if (array.Length >= 4)
							{
								vPositions.Add(double.Parse(array[1]));
								vPositions.Add(double.Parse(array[2]));
								vPositions.Add(double.Parse(array[3]));
							}
							if (array.Length != 4 && array.Length != 7)
							{
								emit_warning("[OBJReader] vertex has unknown format: " + text);
							}
						}
						else if (array[0][1] == 'n')
						{
							if (array.Length >= 4)
							{
								vNormals.Add(float.Parse(array[1]));
								vNormals.Add(float.Parse(array[2]));
								vNormals.Add(float.Parse(array[3]));
							}
							if (array.Length != 4)
							{
								emit_warning("[OBJReader] normal has more than 3 coordinates: " + text);
							}
						}
						else if (array[0][1] == 't')
						{
							if (array.Length >= 3)
							{
								vUVs.Add(float.Parse(array[1]));
								vUVs.Add(float.Parse(array[2]));
								num = Math.Max(num, array.Length);
							}
							if (array.Length != 3)
							{
								emit_warning("[OBJReader] UV has unknown format: " + text);
							}
						}
					}
					else if (array[0][0] == 'f')
					{
						if (array.Length < 4)
						{
							emit_warning("[OBJReader] degenerate face specified : " + text);
						}
						else if (array.Length == 4)
						{
							Triangle t = default(Triangle);
							parse_triangle(array, ref t);
							t.nGroupID = num3;
							if (oBJMaterial != null)
							{
								t.nMaterialID = oBJMaterial.id;
								UsedMaterials[oBJMaterial.id] = oBJMaterial.name;
							}
							vTriangles.Add(t);
							if (t.is_complex())
							{
								HasComplexVertices = true;
							}
						}
						else
						{
							append_face(array, oBJMaterial, num3);
						}
					}
					else if (array[0][0] == 'g')
					{
						string key = ((array.Length == 2) ? array[1] : text.Substring(text.IndexOf(array[1])));
						if (dictionary.ContainsKey(key))
						{
							num3 = dictionary[key];
							continue;
						}
						num3 = num2;
						dictionary[key] = num2++;
					}
					else
					{
						if (array[0][0] == 'o')
						{
							continue;
						}
						if (array[0] == "mtllib" && options.ReadMaterials)
						{
							if (MTLFileSearchPaths.Count == 0)
							{
								emit_warning("Materials requested but Material Search Paths not initialized!");
							}
							string text2 = ((array.Length == 2) ? array[1] : text.Substring(text.IndexOf(array[1])));
							string text3 = FindMTLFile(text2);
							if (text3 != null)
							{
								IOReadResult iOReadResult = ReadMaterials(text3);
								if (iOReadResult.code != IOCode.Ok)
								{
									emit_warning("error parsing " + text3 + " : " + iOReadResult.message);
								}
							}
							else
							{
								emit_warning("material file " + text2 + " could not be found in material search paths");
							}
						}
						else if (array[0] == "usemtl" && options.ReadMaterials)
						{
							oBJMaterial = find_material(array[1]);
						}
						continue;
					}
				}
				catch (Exception ex)
				{
					emit_warning("error parsing line " + num4 + ": " + text + ", exception " + ex.Message);
				}
			}
			m_bOBJHasPerVertexColors = bOBJHasPerVertexColors;
			m_bOBJHasTriangleGroups = num3 != -1;
			m_nSetInvalidGroupsTo = num2++;
			m_nUVComponents = num;
			return new IOReadResult(IOCode.Ok, "");
		}

		private int parse_v(string sToken)
		{
			int num = int.Parse(sToken);
			if (num < 0)
			{
				num = vPositions.Length / 3 + num + 1;
			}
			return num;
		}

		private int parse_n(string sToken)
		{
			int num = int.Parse(sToken);
			if (num < 0)
			{
				num = vNormals.Length / 3 + num + 1;
			}
			return num;
		}

		private int parse_u(string sToken)
		{
			int num = int.Parse(sToken);
			if (num < 0)
			{
				num = vUVs.Length / 2 + num + 1;
			}
			return num;
		}

		private void append_face(string[] tokens, OBJMaterial activeMaterial, int nActiveGroup)
		{
			int num = 0;
			if (tokens[1].IndexOf("//") != -1)
			{
				num = 1;
			}
			else if (tokens[1].IndexOf('/') != -1)
			{
				num = 2;
			}
			Triangle value = default(Triangle);
			value.clear();
			for (int i = 0; i < tokens.Length - 1; i++)
			{
				int num2 = ((i < 3) ? i : 2);
				if (i >= 3)
				{
					value.move_vertex(2, 1);
				}
				switch (num)
				{
				case 0:
					value.set_vertex(num2, parse_v(tokens[i + 1]));
					break;
				case 1:
				{
					string[] array2 = tokens[i + 1].Split(splitDoubleSlash, StringSplitOptions.RemoveEmptyEntries);
					value.set_vertex(num2, parse_v(array2[0]), parse_n(array2[1]));
					break;
				}
				case 2:
				{
					string[] array = tokens[i + 1].Split(splitSlash, StringSplitOptions.RemoveEmptyEntries);
					if (array.Length == 2)
					{
						value.set_vertex(num2, parse_v(array[0]), -1, parse_u(array[1]));
					}
					else if (array.Length == 3)
					{
						value.set_vertex(num2, parse_v(array[0]), parse_n(array[2]), parse_u(array[1]));
					}
					else
					{
						emit_warning("parse_triangle unexpected face component " + tokens[num2]);
					}
					break;
				}
				}
				if (i >= 2)
				{
					if (activeMaterial != null)
					{
						value.nMaterialID = activeMaterial.id;
						UsedMaterials[activeMaterial.id] = activeMaterial.name;
					}
					value.nGroupID = nActiveGroup;
					vTriangles.Add(value);
					if (value.is_complex())
					{
						HasComplexVertices = true;
					}
				}
			}
		}

		private void parse_triangle(string[] tokens, ref Triangle t)
		{
			int num = 0;
			if (tokens[1].IndexOf("//") != -1)
			{
				num = 1;
			}
			else if (tokens[1].IndexOf('/') != -1)
			{
				num = 2;
			}
			t.clear();
			for (int i = 0; i < 3; i++)
			{
				switch (num)
				{
				case 0:
					t.set_vertex(i, parse_v(tokens[i + 1]));
					break;
				case 1:
				{
					string[] array2 = tokens[i + 1].Split(splitDoubleSlash, StringSplitOptions.RemoveEmptyEntries);
					t.set_vertex(i, parse_v(array2[0]), parse_n(array2[1]));
					break;
				}
				case 2:
				{
					string[] array = tokens[i + 1].Split(splitSlash, StringSplitOptions.RemoveEmptyEntries);
					if (array.Length == 2)
					{
						t.set_vertex(i, parse_v(array[0]), -1, parse_u(array[1]));
					}
					else if (array.Length == 3)
					{
						t.set_vertex(i, parse_v(array[0]), parse_n(array[2]), parse_u(array[1]));
					}
					else
					{
						emit_warning("parse_triangle unexpected face component " + tokens[i]);
					}
					break;
				}
				}
			}
		}

		private string FindMTLFile(string sMTLFilePath)
		{
			foreach (string mTLFileSearchPath in MTLFileSearchPaths)
			{
				string text = Path.Combine(mTLFileSearchPath, sMTLFilePath);
				if (File.Exists(text))
				{
					return text;
				}
			}
			return null;
		}

		public IOReadResult ReadMaterials(string sPath)
		{
			if (nWarningLevel >= 1)
			{
				emit_warning("[OBJReader] ReadMaterials " + sPath);
			}
			StreamReader streamReader;
			try
			{
				streamReader = new StreamReader(sPath);
				if (streamReader.EndOfStream)
				{
					return new IOReadResult(IOCode.FileAccessError, "");
				}
			}
			catch
			{
				return new IOReadResult(IOCode.FileAccessError, "");
			}
			OBJMaterial oBJMaterial = null;
			while (streamReader.Peek() >= 0)
			{
				string text = streamReader.ReadLine();
				string[] array = text.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array.Length == 0 || array[0][0] == '#')
				{
					continue;
				}
				if (array[0] == "newmtl")
				{
					oBJMaterial = new OBJMaterial();
					oBJMaterial.name = array[1];
					oBJMaterial.id = Materials.Count;
					if (Materials.ContainsKey(oBJMaterial.name))
					{
						emit_warning("Material file " + sPath + " / material " + oBJMaterial.name + " : already exists in Material set. Replacing.");
					}
					if (nWarningLevel >= 1)
					{
						emit_warning("[OBJReader] parsing material " + oBJMaterial.name);
					}
					Materials[oBJMaterial.name] = oBJMaterial;
				}
				else if (array[0] == "Ka")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Ka = parse_mtl_color(array);
					}
				}
				else if (array[0] == "Kd")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Kd = parse_mtl_color(array);
					}
				}
				else if (array[0] == "Ks")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Ks = parse_mtl_color(array);
					}
				}
				else if (array[0] == "Ke")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Ke = parse_mtl_color(array);
					}
				}
				else if (array[0] == "Tf")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Tf = parse_mtl_color(array);
					}
				}
				else if (array[0] == "illum")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.illum = int.Parse(array[1]);
					}
				}
				else if (array[0] == "d")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.d = float.Parse(array[1]);
					}
				}
				else if (array[0] == "Tr")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.d = 1f - float.Parse(array[1]);
					}
				}
				else if (array[0] == "Ns")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Ns = float.Parse(array[1]);
					}
				}
				else if (array[0] == "sharpness")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.sharpness = float.Parse(array[1]);
					}
				}
				else if (array[0] == "Ni")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.Ni = float.Parse(array[1]);
					}
				}
				else if (array[0] == "map_Ka")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_Ka = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "map_Kd")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_Kd = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "map_Ks")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_Ks = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "map_Ke")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_Ke = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "map_d")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_d = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "map_Ns")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.map_Ns = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "bump" || array[0] == "map_bump")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.bump = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "disp")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.disp = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "decal")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.decal = parse_mtl_path(text, array);
					}
				}
				else if (array[0] == "refl")
				{
					if (oBJMaterial != null)
					{
						oBJMaterial.refl = parse_mtl_path(text, array);
					}
				}
				else
				{
					emit_warning("unknown material command " + array[0]);
				}
			}
			if (nWarningLevel >= 1)
			{
				emit_warning("[OBJReader] ReadMaterials completed");
			}
			return new IOReadResult(IOCode.Ok, "ok");
		}

		private string parse_mtl_path(string line, string[] tokens)
		{
			if (tokens.Length == 2)
			{
				return tokens[1];
			}
			return line.Substring(line.IndexOf(tokens[1]));
		}

		private Vector3f parse_mtl_color(string[] tokens)
		{
			if (tokens[1] == "spectral")
			{
				emit_warning("OBJReader::parse_material_color : spectral color not supported!");
				return new Vector3f(1f, 0f, 0f);
			}
			if (tokens[1] == "xyz")
			{
				emit_warning("OBJReader::parse_material_color : xyz color not supported!");
				return new Vector3f(1f, 0f, 0f);
			}
			float x = float.Parse(tokens[1]);
			float y = float.Parse(tokens[2]);
			float z = float.Parse(tokens[3]);
			return new Vector3f(x, y, z);
		}

		private OBJMaterial find_material(string sName)
		{
			if (Materials.ContainsKey(sName))
			{
				return Materials[sName];
			}
			try
			{
				return Materials.First((KeyValuePair<string, OBJMaterial> x) => string.Equals(x.Key, sName, StringComparison.OrdinalIgnoreCase)).Value;
			}
			catch
			{
			}
			emit_warning("unknown material " + sName + " referenced");
			return null;
		}

		private void emit_warning(string sMessage)
		{
			string key = sMessage.Substring(0, 15);
			int num = (warningCount.ContainsKey(key) ? warningCount[key] : 0);
			num++;
			warningCount[key] = num;
			if (num <= 10)
			{
				if (num == 10)
				{
					sMessage += " (additional message surpressed)";
				}
				this.warningEvent?.Invoke(sMessage, null);
			}
		}
	}
	public class OBJWriter : IMeshWriter
	{
		public Func<string, Stream> OpenStreamF = (string sFilename) => File.Open(sFilename, FileMode.Create);

		public Action<Stream> CloseStreamF = delegate(Stream stream)
		{
			stream.Dispose();
		};

		public string GroupNamePrefix = "mmGroup";

		public Func<int, string> GroupNameF;

		public IOWriteResult Write(BinaryWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			throw new NotImplementedException();
		}

		public IOWriteResult Write(TextWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			if (options.groupNamePrefix != null)
			{
				GroupNamePrefix = options.groupNamePrefix;
			}
			if (options.GroupNameF != null)
			{
				GroupNameF = options.GroupNameF;
			}
			int num = 1;
			int num2 = 1;
			string text = "";
			int num3 = 0;
			if (options.bWriteMaterials && options.MaterialFilePath.Length > 0)
			{
				List<GenericMaterial> vMaterials = MeshIOUtil.FindUniqueMaterialList(vMeshes);
				if (write_materials(vMaterials, options).code == IOCode.Ok)
				{
					text = Path.GetFileName(options.MaterialFilePath);
					num3 = vMeshes.Count;
				}
			}
			if (options.AsciiHeaderFunc != null)
			{
				writer.WriteLine(options.AsciiHeaderFunc());
			}
			if (text != "")
			{
				writer.WriteLine("mtllib {0}", text);
			}
			for (int i = 0; i < vMeshes.Count; i++)
			{
				IMesh mesh = vMeshes[i].Mesh;
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(i, vMeshes.Count);
				}
				bool flag = options.bPerVertexColors && mesh.HasVertexColors;
				bool flag2 = options.bPerVertexNormals && mesh.HasVertexNormals;
				bool flag3 = options.bPerVertexUVs && mesh.HasVertexUVs;
				if (vMeshes[i].UVs != null)
				{
					flag3 = false;
				}
				int[] array = new int[mesh.MaxVertexID];
				foreach (int item in mesh.VertexIndices())
				{
					array[item] = num++;
					Vector3d vertex = mesh.GetVertex(item);
					if (flag)
					{
						Vector3d vector3d = mesh.GetVertexColor(item);
						writer.WriteLine("v {0} {1} {2} {3:F8} {4:F8} {5:F8}", vertex[0], vertex[1], vertex[2], vector3d[0], vector3d[1], vector3d[2]);
					}
					else
					{
						writer.WriteLine("v {0} {1} {2}", vertex[0], vertex[1], vertex[2]);
					}
					if (flag2)
					{
						Vector3d vector3d2 = mesh.GetVertexNormal(item);
						writer.WriteLine("vn {0:F10} {1:F10} {2:F10}", vector3d2[0], vector3d2[1], vector3d2[2]);
					}
					if (flag3)
					{
						Vector2f vertexUV = mesh.GetVertexUV(item);
						writer.WriteLine("vt {0:F10} {1:F10}", vertexUV.x, vertexUV.y);
					}
				}
				IIndexMap mapUV = (flag3 ? new IdentityIndexMap() : null);
				DenseUVMesh denseUVMesh = null;
				if (vMeshes[i].UVs != null)
				{
					denseUVMesh = vMeshes[i].UVs;
					int length = denseUVMesh.UVs.Length;
					IndexMap indexMap = new IndexMap(bForceSparse: false, length);
					for (int j = 0; j < length; j++)
					{
						writer.WriteLine("vt {0:F8} {1:F8}", denseUVMesh.UVs[j].x, denseUVMesh.UVs[j].y);
						indexMap[j] = num2++;
					}
					mapUV = indexMap;
				}
				bool bMaterials = num3 > 0 && vMeshes[i].TriToMaterialMap != null && vMeshes[i].Materials != null;
				if (options.bWriteGroups && mesh.HasTriangleGroups)
				{
					write_triangles_bygroup(writer, mesh, array, denseUVMesh, mapUV, flag2);
				}
				else
				{
					write_triangles_flat(writer, vMeshes[i], array, denseUVMesh, mapUV, flag2, bMaterials);
				}
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(i + 1, vMeshes.Count);
				}
			}
			return new IOWriteResult(IOCode.Ok, "");
		}

		private void write_triangles_bygroup(TextWriter writer, IMesh mesh, int[] mapV, DenseUVMesh uvSet, IIndexMap mapUV, bool bNormals)
		{
			bool flag = mapUV != null;
			HashSet<int> hashSet = new HashSet<int>();
			foreach (int item in mesh.TriangleIndices())
			{
				hashSet.Add(mesh.GetTriangleGroup(item));
			}
			List<int> list = new List<int>(hashSet);
			list.Sort();
			foreach (int item2 in list)
			{
				string groupNamePrefix = GroupNamePrefix;
				groupNamePrefix = ((GroupNameF == null) ? $"{GroupNamePrefix}{item2}" : GroupNameF(item2));
				writer.WriteLine("g " + groupNamePrefix);
				foreach (int item3 in mesh.TriangleIndices())
				{
					if (mesh.GetTriangleGroup(item3) == item2)
					{
						Index3i t = mesh.GetTriangle(item3);
						t[0] = mapV[t[0]];
						t[1] = mapV[t[1]];
						t[2] = mapV[t[2]];
						if (flag)
						{
							Index3i tuv = uvSet?.TriangleUVs[item3] ?? t;
							tuv[0] = mapUV[tuv[0]];
							tuv[1] = mapUV[tuv[1]];
							tuv[2] = mapUV[tuv[2]];
							write_tri(writer, ref t, bNormals, bUVs: true, ref tuv);
						}
						else
						{
							write_tri(writer, ref t, bNormals, bUVs: false, ref t);
						}
					}
				}
			}
		}

		private void write_triangles_flat(TextWriter writer, WriteMesh write_mesh, int[] mapV, DenseUVMesh uvSet, IIndexMap mapUV, bool bNormals, bool bMaterials)
		{
			bool flag = mapUV != null;
			int cur_material = -1;
			IMesh mesh = write_mesh.Mesh;
			foreach (int item in mesh.TriangleIndices())
			{
				if (bMaterials)
				{
					set_current_material(writer, item, write_mesh, ref cur_material);
				}
				Index3i t = mesh.GetTriangle(item);
				t[0] = mapV[t[0]];
				t[1] = mapV[t[1]];
				t[2] = mapV[t[2]];
				if (flag)
				{
					Index3i tuv = uvSet?.TriangleUVs[item] ?? t;
					tuv[0] = mapUV[tuv[0]];
					tuv[1] = mapUV[tuv[1]];
					tuv[2] = mapUV[tuv[2]];
					write_tri(writer, ref t, bNormals, bUVs: true, ref tuv);
				}
				else
				{
					write_tri(writer, ref t, bNormals, bUVs: false, ref t);
				}
			}
		}

		public void set_current_material(TextWriter writer, int ti, WriteMesh mesh, ref int cur_material)
		{
			int num = mesh.TriToMaterialMap[ti];
			if (num != cur_material && num >= 0 && num < mesh.Materials.Count)
			{
				writer.WriteLine("usemtl " + mesh.Materials[num].name);
				cur_material = num;
			}
		}

		private void write_tri(TextWriter writer, ref Index3i t, bool bNormals, bool bUVs, ref Index3i tuv)
		{
			if (!bNormals && !bUVs)
			{
				writer.WriteLine("f {0} {1} {2}", t[0], t[1], t[2]);
			}
			else if (bNormals && !bUVs)
			{
				writer.WriteLine("f {0}//{0} {1}//{1} {2}//{2}", t[0], t[1], t[2]);
			}
			else if (!bNormals && bUVs)
			{
				writer.WriteLine("f {0}/{3} {1}/{4} {2}/{5}", t[0], t[1], t[2], tuv[0], tuv[1], tuv[2]);
			}
			else
			{
				writer.WriteLine("f {0}/{3}/{0} {1}/{4}/{1} {2}/{5}/{2}", t[0], t[1], t[2], tuv[0], tuv[1], tuv[2]);
			}
		}

		private IOWriteResult write_materials(List<GenericMaterial> vMaterials, WriteOptions options)
		{
			Stream stream = OpenStreamF(options.MaterialFilePath);
			if (stream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + options.MaterialFilePath + " for writing");
			}
			try
			{
				StreamWriter streamWriter = new StreamWriter(stream);
				foreach (GenericMaterial vMaterial in vMaterials)
				{
					if (vMaterial is OBJMaterial)
					{
						OBJMaterial oBJMaterial = vMaterial as OBJMaterial;
						streamWriter.WriteLine("newmtl {0}", oBJMaterial.name);
						if (oBJMaterial.Ka != GenericMaterial.Invalid)
						{
							streamWriter.WriteLine("Ka {0} {1} {2}", oBJMaterial.Ka.x, oBJMaterial.Ka.y, oBJMaterial.Ka.z);
						}
						if (oBJMaterial.Kd != GenericMaterial.Invalid)
						{
							streamWriter.WriteLine("Kd {0} {1} {2}", oBJMaterial.Kd.x, oBJMaterial.Kd.y, oBJMaterial.Kd.z);
						}
						if (oBJMaterial.Ks != GenericMaterial.Invalid)
						{
							streamWriter.WriteLine("Ks {0} {1} {2}", oBJMaterial.Ks.x, oBJMaterial.Ks.y, oBJMaterial.Ks.z);
						}
						if (oBJMaterial.Ke != GenericMaterial.Invalid)
						{
							streamWriter.WriteLine("Ke {0} {1} {2}", oBJMaterial.Ke.x, oBJMaterial.Ke.y, oBJMaterial.Ke.z);
						}
						if (oBJMaterial.Tf != GenericMaterial.Invalid)
						{
							streamWriter.WriteLine("Tf {0} {1} {2}", oBJMaterial.Tf.x, oBJMaterial.Tf.y, oBJMaterial.Tf.z);
						}
						if (oBJMaterial.d != float.MinValue)
						{
							streamWriter.WriteLine("d {0}", oBJMaterial.d);
						}
						if (oBJMaterial.Ns != float.MinValue)
						{
							streamWriter.WriteLine("Ns {0}", oBJMaterial.Ns);
						}
						if (oBJMaterial.Ni != float.MinValue)
						{
							streamWriter.WriteLine("Ni {0}", oBJMaterial.Ni);
						}
						if (oBJMaterial.sharpness != float.MinValue)
						{
							streamWriter.WriteLine("sharpness {0}", oBJMaterial.sharpness);
						}
						if (oBJMaterial.illum != -1)
						{
							streamWriter.WriteLine("illum {0}", oBJMaterial.illum);
						}
						if (oBJMaterial.map_Ka != null && oBJMaterial.map_Ka != "")
						{
							streamWriter.WriteLine("map_Ka {0}", oBJMaterial.map_Ka);
						}
						if (oBJMaterial.map_Kd != null && oBJMaterial.map_Kd != "")
						{
							streamWriter.WriteLine("map_Kd {0}", oBJMaterial.map_Kd);
						}
						if (oBJMaterial.map_Ks != null && oBJMaterial.map_Ks != "")
						{
							streamWriter.WriteLine("map_Ks {0}", oBJMaterial.map_Ks);
						}
						if (oBJMaterial.map_Ke != null && oBJMaterial.map_Ke != "")
						{
							streamWriter.WriteLine("map_Ke {0}", oBJMaterial.map_Ke);
						}
						if (oBJMaterial.map_d != null && oBJMaterial.map_d != "")
						{
							streamWriter.WriteLine("map_d {0}", oBJMaterial.map_d);
						}
						if (oBJMaterial.map_Ns != null && oBJMaterial.map_Ns != "")
						{
							streamWriter.WriteLine("map_Ns {0}", oBJMaterial.map_Ns);
						}
						if (oBJMaterial.bump != null && oBJMaterial.bump != "")
						{
							streamWriter.WriteLine("bump {0}", oBJMaterial.bump);
						}
						if (oBJMaterial.disp != null && oBJMaterial.disp != "")
						{
							streamWriter.WriteLine("disp {0}", oBJMaterial.disp);
						}
						if (oBJMaterial.decal != null && oBJMaterial.decal != "")
						{
							streamWriter.WriteLine("decal {0}", oBJMaterial.decal);
						}
						if (oBJMaterial.refl != null && oBJMaterial.refl != "")
						{
							streamWriter.WriteLine("refl {0}", oBJMaterial.refl);
						}
					}
				}
			}
			finally
			{
				CloseStreamF(stream);
			}
			return IOWriteResult.Ok;
		}
	}
	internal class OFFReader : IMeshReader
	{
		private Dictionary<string, int> warningCount = new Dictionary<string, int>();

		public event ParsingMessagesHandler warningEvent;

		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			return new IOReadResult(IOCode.FormatNotSupportedError, "binary read not supported for OFF format");
		}

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			if (!reader.ReadLine().StartsWith("OFF"))
			{
				return new IOReadResult(IOCode.FileParsingError, "ascii OFF file must start with OFF header");
			}
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			while (reader.Peek() >= 0)
			{
				string text = reader.ReadLine();
				num3++;
				string[] array = text.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array.Length != 0 && !array[0].StartsWith("#"))
				{
					if (array.Length != 3)
					{
						return new IOReadResult(IOCode.FileParsingError, "first non-comment line of OFF must be vertex/tri/edge counts, found: " + text);
					}
					num = int.Parse(array[0]);
					num2 = int.Parse(array[1]);
					break;
				}
			}
			builder.AppendNewMesh(bHaveVtxNormals: false, bHaveVtxColors: false, bHaveVtxUVs: false, bHaveFaceGroups: false);
			int num4 = 0;
			while (num4 < num && reader.Peek() > 0)
			{
				string text2 = reader.ReadLine();
				num3++;
				string[] array2 = text2.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array2.Length != 0 && !array2[0].StartsWith("#"))
				{
					if (array2.Length != 3)
					{
						emit_warning("found invalid OFF vertex line: " + text2);
					}
					double x = double.Parse(array2[0]);
					double y = double.Parse(array2[1]);
					double z = double.Parse(array2[2]);
					builder.AppendVertex(x, y, z);
					num4++;
				}
			}
			if (num4 < num)
			{
				return new IOReadResult(IOCode.FileParsingError, $"File specified {num} vertices but only found {num4}");
			}
			int num5 = 0;
			while (num5 < num2 && reader.Peek() > 0)
			{
				string text3 = reader.ReadLine();
				num3++;
				string[] array3 = text3.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array3.Length != 0 && !array3[0].StartsWith("#"))
				{
					if (array3.Length < 4)
					{
						emit_warning("found invalid OFF triangle line: " + text3);
					}
					if (int.Parse(array3[0]) != 3)
					{
						emit_warning("found non-triangle polygon in OFF, currently unsupported: " + text3);
					}
					int i = int.Parse(array3[1]);
					int j = int.Parse(array3[2]);
					int k = int.Parse(array3[3]);
					builder.AppendTriangle(i, j, k);
					num5++;
				}
			}
			if (num5 < num2)
			{
				emit_warning($"File specified {num2} triangles but only found {num5}");
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		private void emit_warning(string sMessage)
		{
			string key = sMessage.Substring(0, 15);
			int num = (warningCount.ContainsKey(key) ? warningCount[key] : 0);
			num++;
			warningCount[key] = num;
			if (num <= 10)
			{
				if (num == 10)
				{
					sMessage += " (additional message surpressed)";
				}
				this.warningEvent?.Invoke(sMessage, null);
			}
		}
	}
	public class OFFWriter : IMeshWriter
	{
		public IOWriteResult Write(BinaryWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			return new IOWriteResult(IOCode.FormatNotSupportedError, "binary write not supported for OFF format");
		}

		public IOWriteResult Write(TextWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			int count = vMeshes.Count;
			writer.WriteLine("OFF");
			string format = Util.MakeVec3FormatString(0, 1, 2, options.RealPrecisionDigits);
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			int[][] array = new int[count][];
			for (int i = 0; i < count; i++)
			{
				num += vMeshes[i].Mesh.VertexCount;
				num2 += vMeshes[i].Mesh.TriangleCount;
				num3 = num3;
				array[i] = new int[vMeshes[i].Mesh.MaxVertexID];
			}
			writer.WriteLine($"{num} {num2} {num3}");
			int num4 = 0;
			for (int j = 0; j < count; j++)
			{
				IMesh mesh = vMeshes[j].Mesh;
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(j, 2 * (count - 1));
				}
				foreach (int item in mesh.VertexIndices())
				{
					Vector3d vertex = mesh.GetVertex(item);
					writer.WriteLine(format, vertex.x, vertex.y, vertex.z);
					array[j][item] = num4;
					num4++;
				}
			}
			for (int k = 0; k < count; k++)
			{
				IMesh mesh2 = vMeshes[k].Mesh;
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(count + k, 2 * (count - 1));
				}
				foreach (int item2 in mesh2.TriangleIndices())
				{
					Index3i triangle = mesh2.GetTriangle(item2);
					triangle[0] = array[k][triangle[0]];
					triangle[1] = array[k][triangle[1]];
					triangle[2] = array[k][triangle[2]];
					writer.WriteLine($"3 {triangle[0]} {triangle[1]} {triangle[2]}");
				}
			}
			return new IOWriteResult(IOCode.Ok, "");
		}
	}
	internal class PLYReader : IMeshReader
	{
		public struct element
		{
			public string name;

			public List<string> properties;

			public List<string> types;

			public List<bool> list;

			public int size;

			public bool Equals(element other)
			{
				return name == other.name;
			}
		}

		private static char[] TRIM_CHARS = new char[4] { '"', '/', '\\', ' ' };

		private Dictionary<string, int> warningCount = new Dictionary<string, int>();

		private bool hasMesh;

		public event ParsingMessagesHandler warningEvent;

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			List<element> list = new List<element>();
			if (!reader.ReadLine().Contains("ply"))
			{
				return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - Magic number failure");
			}
			string text = reader.ReadLine();
			if (text == null)
			{
				return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
			}
			string[] array;
			while (true)
			{
				if (text.StartsWith("element"))
				{
					array = text.Split(' ');
					if (array.Length != 3)
					{
						return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
					}
					element item = new element
					{
						properties = new List<string>(),
						types = new List<string>(),
						list = new List<bool>(),
						name = array[1],
						size = ParseInt(array[2])
					};
					while (true)
					{
						text = reader.ReadLine();
						if (text == null)
						{
							return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
						}
						if (!text.StartsWith("property"))
						{
							break;
						}
						array = text.Split(' ');
						switch (array.Length)
						{
						case 3:
							item.properties.Add(array[2].ToLower());
							item.types.Add(array[1].ToLower());
							item.list.Add(item: false);
							break;
						case 5:
							item.properties.Add(array[4].ToLower());
							item.types.Add(array[3].ToLower());
							item.list.Add(item: true);
							break;
						default:
							return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - invalid element line" + text);
						}
					}
					list.Add(item);
					continue;
				}
				if (text.StartsWith("end_header"))
				{
					break;
				}
				if (text.StartsWith("binary"))
				{
					continue;
				}
				if (text.StartsWith("comment crs "))
				{
					text.Remove(12);
					text = reader.ReadLine();
					if (text == null)
					{
						return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
					}
				}
				else
				{
					text = reader.ReadLine();
					if (text == null)
					{
						return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
					}
				}
			}
			bool flag = false;
			bool flag2 = false;
			bool flag3 = false;
			for (int i = 0; i < list.Count; i++)
			{
				element element2 = list[i];
				if (element2.name == "vertex")
				{
					if (!element2.properties.Contains("x") || !element2.properties.Contains("y") || !element2.properties.Contains("z"))
					{
						return new IOReadResult(IOCode.GarbageDataError, "Verteces do not have XYZ");
					}
					if (element2.properties.Contains("red") && element2.properties.Contains("blue") && element2.properties.Contains("green"))
					{
						flag = true;
					}
					if (element2.properties.Contains("nx") && element2.properties.Contains("ny") && element2.properties.Contains("nz"))
					{
						flag2 = true;
					}
					if (element2.properties.Contains("u") && element2.properties.Contains("v"))
					{
						flag3 = true;
					}
				}
				if (element2.name == "faces" && !element2.properties.Contains("vertex_indices"))
				{
					return new IOReadResult(IOCode.GarbageDataError, "Faces do not have vertex indices");
				}
				if (element2.name == "edges" && (!element2.properties.Contains("vertex1") || !element2.properties.Contains("vertex2")))
				{
					return new IOReadResult(IOCode.GarbageDataError, "Edges do not have vertex indices");
				}
			}
			builder.AppendNewMesh(flag2, flag, flag3, bHaveFaceGroups: false);
			text = reader.ReadLine();
			if (text == null)
			{
				return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - header is corrupt");
			}
			array = text.Split(' ');
			for (int j = 0; j < list.Count; j++)
			{
				element element3 = list[j];
				for (int k = 0; k < element3.size; k++)
				{
					int num = element3.properties.Count;
					if (element3.list[0])
					{
						num += ParseInt(array[0]);
					}
					if (array.Length != num)
					{
						return new IOReadResult(IOCode.GarbageDataError, "Not a valid PLY file - contains invalid line : " + text);
					}
					if (element3.name == "vertex")
					{
						Vector3d vtx = default(Vector3d);
						Vector3f norm = default(Vector3f);
						Vector3f cols = default(Vector3f);
						Vector2f uvs = default(Vector2f);
						vtx.x = ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "x")]);
						vtx.y = ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "y")]);
						vtx.z = ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "z")]);
						if (flag2)
						{
							norm.x = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "nx")]);
							norm.y = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "ny")]);
							norm.z = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "nz")]);
						}
						if (flag)
						{
							cols.x = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "red")]);
							cols.y = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "blue")]);
							cols.z = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "green")]);
						}
						if (flag3)
						{
							uvs.x = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "u")]);
							uvs.y = (float)ParseValue(array[element3.properties.FindIndex((string text2) => text2 == "v")]);
						}
						append_vertex(builder, vtx, norm, cols, uvs, flag2, flag, flag3);
					}
					else if (element3.name == "face")
					{
						if (ParseInt(array[0]) != 3)
						{
							emit_warning("[PLYReader] cann only read triangles");
							return new IOReadResult(IOCode.FormatNotSupportedError, "Can only read tri faces");
						}
						append_triangle(builder, new Index3i
						{
							a = ParseInt(array[1]),
							b = ParseInt(array[2]),
							c = ParseInt(array[3])
						});
					}
					text = reader.ReadLine();
					if (text == null && j != list.Count - 1 && k != element3.size - 1)
					{
						return new IOReadResult(IOCode.GarbageDataError, " does not contain enough definitions of type " + element3.name);
					}
					array = text?.Split(' ');
				}
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		private int append_vertex(IMeshBuilder builder, Vector3d vtx, Vector3f norm, Vector3f cols, Vector2f uvs, bool bHaveNormals, bool bHaveColors, bool bHaveUVs)
		{
			if (!bHaveNormals && !bHaveColors && !bHaveUVs)
			{
				return builder.AppendVertex(vtx.x, vtx.y, vtx.z);
			}
			NewVertexInfo info = default(NewVertexInfo);
			info.bHaveC = (info.bHaveN = (info.bHaveUV = false));
			info.v = vtx;
			if (bHaveNormals)
			{
				info.bHaveN = true;
				info.n = norm;
			}
			if (bHaveColors)
			{
				info.bHaveC = true;
				info.c = cols;
			}
			if (bHaveUVs)
			{
				info.bHaveUV = true;
				info.uv = uvs;
			}
			return builder.AppendVertex(info);
		}

		private int append_triangle(IMeshBuilder builder, Index3i tri)
		{
			if (tri.a < 0 || tri.b < 0 || tri.c < 0)
			{
				emit_warning($"[PLYReader] invalid triangle:  {tri.a} {tri.b} {tri.c}");
				return -1;
			}
			return builder.AppendTriangle(tri.a, tri.b, tri.c);
		}

		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			return new IOReadResult(IOCode.FormatNotSupportedError, "text read not supported for 3DS format");
		}

		private void emit_warning(string sMessage)
		{
			string key = sMessage.Substring(0, 15);
			int num = (warningCount.ContainsKey(key) ? warningCount[key] : 0);
			num++;
			warningCount[key] = num;
			if (num <= 10)
			{
				if (num == 10)
				{
					sMessage += " (additional message surpressed)";
				}
				this.warningEvent?.Invoke(sMessage, null);
			}
		}

		private double ParseValue(string value)
		{
			value = value.TrimStart(TRIM_CHARS).TrimEnd(TRIM_CHARS).Replace("\\", "");
			if (double.TryParse(value, out var result))
			{
				return result;
			}
			return 0.0;
		}

		private int ParseInt(string value)
		{
			value = value.TrimStart(TRIM_CHARS).TrimEnd(TRIM_CHARS).Replace("\\", "");
			if (int.TryParse(value, out var result))
			{
				return result;
			}
			return 0;
		}
	}
	public delegate void ParsingMessagesHandler(string message, object extra_data);
	public interface MeshFormatReader
	{
		List<string> SupportedExtensions { get; }

		IOReadResult ReadFile(string sFilename, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler warnings);

		IOReadResult ReadFile(Stream stream, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler warnings);
	}
	public class StandardMeshReader
	{
		public bool ReadInvariantCulture = true;

		private List<MeshFormatReader> Readers = new List<MeshFormatReader>();

		public IMeshBuilder MeshBuilder { get; set; }

		public event ParsingMessagesHandler warningEvent;

		public StandardMeshReader(bool bIncludeDefaultReaders = true)
		{
			Readers = new List<MeshFormatReader>();
			MeshBuilder = new DMesh3Builder();
			if (bIncludeDefaultReaders)
			{
				Readers.Add(new OBJFormatReader());
				Readers.Add(new STLFormatReader());
				Readers.Add(new OFFFormatReader());
				Readers.Add(new BinaryG3FormatReader());
				Readers.Add(new DS3FormatReader());
				Readers.Add(new PLYFormatReader());
			}
		}

		public bool SupportsFormat(string sExtension)
		{
			foreach (MeshFormatReader reader in Readers)
			{
				foreach (string supportedExtension in reader.SupportedExtensions)
				{
					if (supportedExtension.Equals(sExtension, StringComparison.OrdinalIgnoreCase))
					{
						return true;
					}
				}
			}
			return false;
		}

		public void AddFormatHandler(MeshFormatReader reader)
		{
			foreach (string supportedExtension in reader.SupportedExtensions)
			{
				if (SupportsFormat(supportedExtension))
				{
					throw new Exception("StandardMeshReader.AddFormatHandler: format " + supportedExtension + " is already registered!");
				}
			}
			Readers.Add(reader);
		}

		public IOReadResult Read(string sFilename, ReadOptions options)
		{
			if (MeshBuilder == null)
			{
				return new IOReadResult(IOCode.GenericReaderError, "MeshBuilder is null!");
			}
			string extension = Path.GetExtension(sFilename);
			if (extension.Length < 2)
			{
				return new IOReadResult(IOCode.InvalidFilenameError, "filename " + sFilename + " does not contain valid extension");
			}
			extension = extension.Substring(1);
			MeshFormatReader meshFormatReader = null;
			foreach (MeshFormatReader reader in Readers)
			{
				foreach (string supportedExtension in reader.SupportedExtensions)
				{
					if (supportedExtension.Equals(extension, StringComparison.OrdinalIgnoreCase))
					{
						meshFormatReader = reader;
					}
				}
				if (meshFormatReader != null)
				{
					break;
				}
			}
			if (meshFormatReader == null)
			{
				return new IOReadResult(IOCode.UnknownFormatError, "format " + extension + " is not supported");
			}
			CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
			try
			{
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = CultureInfo.InvariantCulture;
				}
				IOReadResult result = meshFormatReader.ReadFile(sFilename, MeshBuilder, options, on_warning);
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return result;
			}
			catch (Exception ex)
			{
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return new IOReadResult(IOCode.GenericReaderError, "Unknown error : exception : " + ex.Message);
			}
		}

		public IOReadResult Read(Stream stream, string sExtension, ReadOptions options)
		{
			if (MeshBuilder == null)
			{
				return new IOReadResult(IOCode.GenericReaderError, "MeshBuilder is null!");
			}
			MeshFormatReader meshFormatReader = null;
			foreach (MeshFormatReader reader in Readers)
			{
				foreach (string supportedExtension in reader.SupportedExtensions)
				{
					if (supportedExtension.Equals(sExtension, StringComparison.OrdinalIgnoreCase))
					{
						meshFormatReader = reader;
					}
				}
				if (meshFormatReader != null)
				{
					break;
				}
			}
			if (meshFormatReader == null)
			{
				return new IOReadResult(IOCode.UnknownFormatError, "format " + sExtension + " is not supported");
			}
			CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
			try
			{
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = CultureInfo.InvariantCulture;
				}
				IOReadResult result = meshFormatReader.ReadFile(stream, MeshBuilder, options, on_warning);
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return result;
			}
			catch (Exception ex)
			{
				if (ReadInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return new IOReadResult(IOCode.GenericReaderError, "Unknown error : exception : " + ex.Message);
			}
		}

		public static IOReadResult ReadFile(string sFilename, ReadOptions options, IMeshBuilder builder)
		{
			return new StandardMeshReader
			{
				MeshBuilder = builder
			}.Read(sFilename, options);
		}

		public static IOReadResult ReadFile(Stream stream, string sExtension, ReadOptions options, IMeshBuilder builder)
		{
			return new StandardMeshReader
			{
				MeshBuilder = builder
			}.Read(stream, sExtension, options);
		}

		public static DMesh3 ReadMesh(string sFilename)
		{
			DMesh3Builder dMesh3Builder = new DMesh3Builder();
			if (ReadFile(sFilename, ReadOptions.Defaults, dMesh3Builder).code != IOCode.Ok)
			{
				return null;
			}
			return dMesh3Builder.Meshes[0];
		}

		public static DMesh3 ReadMesh(Stream stream, string sExtension)
		{
			DMesh3Builder dMesh3Builder = new DMesh3Builder();
			if (ReadFile(stream, sExtension, ReadOptions.Defaults, dMesh3Builder).code != IOCode.Ok)
			{
				return null;
			}
			return dMesh3Builder.Meshes[0];
		}

		private void on_warning(string message, object extra_data)
		{
			if (this.warningEvent != null)
			{
				this.warningEvent(message, extra_data);
			}
		}
	}
	public class OBJFormatReader : MeshFormatReader
	{
		public List<string> SupportedExtensions => new List<string> { "obj" };

		public IOReadResult ReadFile(string sFilename, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler messages)
		{
			try
			{
				using FileStream stream = File.Open(sFilename, FileMode.Open, FileAccess.Read, FileShare.Read);
				OBJReader oBJReader = new OBJReader();
				if (options.ReadMaterials)
				{
					oBJReader.MTLFileSearchPaths.Add(Path.GetDirectoryName(sFilename));
				}
				oBJReader.warningEvent += messages;
				return oBJReader.Read(new StreamReader(stream), options, builder);
			}
			catch (Exception ex)
			{
				return new IOReadResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for reading : " + ex.Message);
			}
		}

		public IOReadResult ReadFile(Stream stream, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler messages)
		{
			OBJReader oBJReader = new OBJReader();
			oBJReader.warningEvent += messages;
			return oBJReader.Read(new StreamReader(stream), options, builder);
		}
	}
	public class STLFormatReader : MeshFormatReader
	{
		public List<string> SupportedExtensions => new List<string> { "stl" };

		public IOReadResult ReadFile(string sFilename, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler messages)
		{
			try
			{
				using FileStream stream = File.Open(sFilename, FileMode.Open, FileAccess.Read, FileShare.Read);
				return ReadFile(stream, builder, options, messages);
			}
			catch (Exception ex)
			{
				return new IOReadResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for reading : " + ex.Message);
			}
		}

		public IOReadResult ReadFile(Stream stream, IMeshBuilder builder, ReadOptions options, ParsingMessagesHandler messages)
		{
			bool num = Util.IsBinaryStream(stream, 500);
			stream.Seek(0L, SeekOrigin.Begin);
			STLReader sTLReader = new STLReader();
			sTLReader.warningEvent += messages;
			if (!num)
			{
				return sTLReader.Read(new StreamReader(stream), options, builder);
			}
			return sTLReader.Read(new BinaryReader(stream), options, builder);
		}
	}
