	public class StandardMeshWriter : IDisposable
	{
		public bool WriteInvariantCulture = true;

		public Func<string, Stream> OpenStreamF = (string sFilename) => File.Open(sFilename, FileMode.Create);

		public Action<Stream> CloseStreamF = delegate(Stream stream)
		{
			stream.Close();
			stream.Dispose();
		};

		public void Dispose()
		{
		}

		public static IOWriteResult WriteMeshes(string sFilename, List<DMesh3> vMeshes, WriteOptions options)
		{
			List<WriteMesh> list = new List<WriteMesh>();
			foreach (DMesh3 vMesh in vMeshes)
			{
				list.Add(new WriteMesh(vMesh));
			}
			return new StandardMeshWriter().Write(sFilename, list, options);
		}

		public static IOWriteResult WriteFile(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			return new StandardMeshWriter().Write(sFilename, vMeshes, options);
		}

		public static IOWriteResult WriteMesh(string sFilename, IMesh mesh, WriteOptions options)
		{
			return new StandardMeshWriter().Write(sFilename, new List<WriteMesh>
			{
				new WriteMesh(mesh)
			}, options);
		}

		public IOWriteResult Write(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			Func<string, List<WriteMesh>, WriteOptions, IOWriteResult> func = null;
			string extension = Path.GetExtension(sFilename);
			if (extension.Equals(".obj", StringComparison.OrdinalIgnoreCase))
			{
				func = Write_OBJ;
			}
			else if (extension.Equals(".stl", StringComparison.OrdinalIgnoreCase))
			{
				func = Write_STL;
			}
			else if (extension.Equals(".off", StringComparison.OrdinalIgnoreCase))
			{
				func = Write_OFF;
			}
			else if (extension.Equals(".g3mesh", StringComparison.OrdinalIgnoreCase))
			{
				func = Write_G3Mesh;
			}
			if (func == null)
			{
				return new IOWriteResult(IOCode.UnknownFormatError, "format " + extension + " is not supported");
			}
			CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
			try
			{
				if (WriteInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = CultureInfo.InvariantCulture;
				}
				IOWriteResult result = func(sFilename, vMeshes, options);
				if (WriteInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return result;
			}
			catch (Exception ex)
			{
				if (WriteInvariantCulture)
				{
					Thread.CurrentThread.CurrentCulture = currentCulture;
				}
				return new IOWriteResult(IOCode.WriterError, "Unknown error : exception : " + ex.Message);
			}
		}

		private IOWriteResult Write_OBJ(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			Stream stream = OpenStreamF(sFilename);
			if (stream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for writing");
			}
			try
			{
				StreamWriter streamWriter = new StreamWriter(stream);
				IOWriteResult result = new OBJWriter
				{
					OpenStreamF = OpenStreamF,
					CloseStreamF = CloseStreamF
				}.Write(streamWriter, vMeshes, options);
				streamWriter.Flush();
				return result;
			}
			finally
			{
				CloseStreamF(stream);
			}
		}

		private IOWriteResult Write_OFF(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			Stream stream = OpenStreamF(sFilename);
			if (stream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for writing");
			}
			try
			{
				StreamWriter streamWriter = new StreamWriter(stream);
				IOWriteResult result = new OFFWriter().Write(streamWriter, vMeshes, options);
				streamWriter.Flush();
				return result;
			}
			finally
			{
				CloseStreamF(stream);
			}
		}

		private IOWriteResult Write_STL(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			Stream stream = OpenStreamF(sFilename);
			if (stream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for writing");
			}
			try
			{
				if (options.bWriteBinary)
				{
					BinaryWriter binaryWriter = new BinaryWriter(stream);
					IOWriteResult result = new STLWriter().Write(binaryWriter, vMeshes, options);
					binaryWriter.Flush();
					return result;
				}
				StreamWriter streamWriter = new StreamWriter(stream);
				IOWriteResult result2 = new STLWriter().Write(streamWriter, vMeshes, options);
				streamWriter.Flush();
				return result2;
			}
			finally
			{
				CloseStreamF(stream);
			}
		}

		private IOWriteResult Write_G3Mesh(string sFilename, List<WriteMesh> vMeshes, WriteOptions options)
		{
			Stream stream = OpenStreamF(sFilename);
			if (stream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for writing");
			}
			try
			{
				BinaryWriter binaryWriter = new BinaryWriter(stream);
				IOWriteResult result = new BinaryG3Writer().Write(binaryWriter, vMeshes, options);
				binaryWriter.Flush();
				return result;
			}
			finally
			{
				CloseStreamF(stream);
			}
		}
	}
	public class STLReader : IMeshReader
	{
		public enum Strategy
		{
			NoProcessing,
			IdenticalVertexWeld,
			TolerantVertexWeld,
			AutoBestResult
		}

		protected class STLSolid
		{
			public string Name;

			public DVectorArray3f Vertices = new DVectorArray3f();

			public DVector<short> TriAttribs;
		}

		[StructLayout(LayoutKind.Sequential, Pack = 1)]
		private struct stl_triangle
		{
			public float nx;

			public float ny;

			public float nz;

			public float ax;

			public float ay;

			public float az;

			public float bx;

			public float by;

			public float bz;

			public float cx;

			public float cy;

			public float cz;

			public short attrib;
		}

		public Strategy RebuildStrategy = Strategy.AutoBestResult;

		public double WeldTolerance = 9.999999974752427E-07;

		public bool WantPerTriAttribs;

		public static string PerTriAttribMetadataName = "tri_attrib";

		private Dictionary<string, int> warningCount = new Dictionary<string, int>();

		public const string StrategyFlag = "-stl-weld-strategy";

		public const string PerTriAttribFlag = "-want-tri-attrib";

		private List<STLSolid> Objects;

		public event ParsingMessagesHandler warningEvent;

		private void ParseArguments(CommandArgumentSet args)
		{
			if (args.Integers.ContainsKey("-stl-weld-strategy"))
			{
				RebuildStrategy = (Strategy)args.Integers["-stl-weld-strategy"];
			}
			if (args.Flags.ContainsKey("-want-tri-attrib"))
			{
				WantPerTriAttribs = true;
			}
		}

		private void append_vertex(float x, float y, float z)
		{
			Objects.Last().Vertices.Append(x, y, z);
		}

		public IOReadResult Read(BinaryReader reader, ReadOptions options, IMeshBuilder builder)
		{
			if (options.CustomFlags != null)
			{
				ParseArguments(options.CustomFlags);
			}
			reader.ReadBytes(80);
			int num = reader.ReadInt32();
			Objects = new List<STLSolid>();
			Objects.Add(new STLSolid());
			int num2 = 50;
			IntPtr intPtr = Marshal.AllocHGlobal(num2);
			Type type = default(stl_triangle).GetType();
			DVector<short> dVector = new DVector<short>();
			try
			{
				for (int i = 0; i < num; i++)
				{
					byte[] array = reader.ReadBytes(50);
					if (array.Length >= 50)
					{
						Marshal.Copy(array, 0, intPtr, num2);
						stl_triangle stl_triangle2 = (stl_triangle)Marshal.PtrToStructure(intPtr, type);
						append_vertex(stl_triangle2.ax, stl_triangle2.ay, stl_triangle2.az);
						append_vertex(stl_triangle2.bx, stl_triangle2.by, stl_triangle2.bz);
						append_vertex(stl_triangle2.cx, stl_triangle2.cy, stl_triangle2.cz);
						dVector.Add(stl_triangle2.attrib);
						continue;
					}
					break;
				}
			}
			catch (Exception ex)
			{
				return new IOReadResult(IOCode.GenericReaderError, "exception: " + ex.Message);
			}
			Marshal.FreeHGlobal(intPtr);
			if (Objects.Count == 1)
			{
				Objects[0].TriAttribs = dVector;
			}
			foreach (STLSolid @object in Objects)
			{
				BuildMesh(@object, builder);
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		public IOReadResult Read(TextReader reader, ReadOptions options, IMeshBuilder builder)
		{
			if (options.CustomFlags != null)
			{
				ParseArguments(options.CustomFlags);
			}
			bool flag = false;
			Objects = new List<STLSolid>();
			int num = 0;
			while (reader.Peek() >= 0)
			{
				string text = reader.ReadLine();
				num++;
				string[] array = text.Split((char[])null, StringSplitOptions.RemoveEmptyEntries);
				if (array.Length == 0)
				{
					continue;
				}
				if (array[0].Equals("vertex", StringComparison.OrdinalIgnoreCase))
				{
					float x = ((array.Length > 1) ? float.Parse(array[1]) : 0f);
					float y = ((array.Length > 2) ? float.Parse(array[2]) : 0f);
					float z = ((array.Length > 3) ? float.Parse(array[3]) : 0f);
					append_vertex(x, y, z);
				}
				else if (array[0].Equals("facet", StringComparison.OrdinalIgnoreCase))
				{
					if (!flag)
					{
						Objects.Add(new STLSolid
						{
							Name = "unknown_solid"
						});
						flag = true;
					}
				}
				else if (array[0].Equals("solid", StringComparison.OrdinalIgnoreCase))
				{
					STLSolid sTLSolid = new STLSolid();
					if (array.Length == 2)
					{
						sTLSolid.Name = array[1];
					}
					else
					{
						sTLSolid.Name = "object_" + Objects.Count;
					}
					Objects.Add(sTLSolid);
					flag = true;
				}
				else if (array[0].Equals("endsolid", StringComparison.OrdinalIgnoreCase))
				{
					flag = false;
				}
			}
			foreach (STLSolid @object in Objects)
			{
				BuildMesh(@object, builder);
			}
			return new IOReadResult(IOCode.Ok, "");
		}

		protected virtual void BuildMesh(STLSolid solid, IMeshBuilder builder)
		{
			if (RebuildStrategy == Strategy.AutoBestResult)
			{
				DMesh3 existingMesh = BuildMesh_Auto(solid);
				builder.AppendNewMesh(existingMesh);
			}
			else if (RebuildStrategy == Strategy.IdenticalVertexWeld)
			{
				DMesh3 existingMesh2 = BuildMesh_IdenticalWeld(solid);
				builder.AppendNewMesh(existingMesh2);
			}
			else if (RebuildStrategy == Strategy.TolerantVertexWeld)
			{
				DMesh3 existingMesh3 = BuildMesh_TolerantWeld(solid, WeldTolerance);
				builder.AppendNewMesh(existingMesh3);
			}
			else
			{
				BuildMesh_NoMerge(solid, builder);
			}
			if (WantPerTriAttribs && solid.TriAttribs != null && builder.SupportsMetaData)
			{
				builder.AppendMetaData(PerTriAttribMetadataName, solid.TriAttribs);
			}
		}

		protected virtual void BuildMesh_NoMerge(STLSolid solid, IMeshBuilder builder)
		{
			builder.AppendNewMesh(bHaveVtxNormals: false, bHaveVtxColors: false, bHaveVtxUVs: false, bHaveFaceGroups: false);
			DVectorArray3f vertices = solid.Vertices;
			int num = vertices.Count / 3;
			for (int i = 0; i < num; i++)
			{
				Vector3f vector3f = vertices[3 * i];
				int i2 = builder.AppendVertex(vector3f.x, vector3f.y, vector3f.z);
				Vector3f vector3f2 = vertices[3 * i + 1];
				int j = builder.AppendVertex(vector3f2.x, vector3f2.y, vector3f2.z);
				Vector3f vector3f3 = vertices[3 * i + 2];
				int k = builder.AppendVertex(vector3f3.x, vector3f3.y, vector3f3.z);
				builder.AppendTriangle(i2, j, k);
			}
		}

		protected virtual DMesh3 BuildMesh_Auto(STLSolid solid)
		{
			DMesh3 dMesh = BuildMesh_IdenticalWeld(solid);
			if (check_for_cracks(dMesh, out var boundary_edge_count, WeldTolerance))
			{
				DMesh3 dMesh2 = BuildMesh_TolerantWeld(solid, WeldTolerance);
				if (count_boundary_edges(dMesh2) < boundary_edge_count)
				{
					return dMesh2;
				}
				return dMesh;
			}
			return dMesh;
		}

		protected int count_boundary_edges(DMesh3 mesh)
		{
			int num = 0;
			foreach (int item in mesh.BoundaryEdgeIndices())
			{
				_ = item;
				num++;
			}
			return num;
		}

		protected bool check_for_cracks(DMesh3 mesh, out int boundary_edge_count, double crack_tol = 9.999999974752427E-07)
		{
			boundary_edge_count = 0;
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(mesh);
			foreach (int item in mesh.BoundaryEdgeIndices())
			{
				Index2i edgeV = mesh.GetEdgeV(item);
				meshVertexSelection.Select(edgeV.a);
				meshVertexSelection.Select(edgeV.b);
				boundary_edge_count++;
			}
			if (meshVertexSelection.Count == 0)
			{
				return false;
			}
			PointHashGrid3d<int> pointHashGrid3d = new PointHashGrid3d<int>(mesh.CachedBounds.MaxDim / 128.0, -1);
			foreach (int item2 in meshVertexSelection)
			{
				Vector3d v = mesh.GetVertex(item2);
				if (pointHashGrid3d.FindNearestInRadius(v, crack_tol, (int existing_vid) => v.Distance(mesh.GetVertex(existing_vid))).Key != -1)
				{
					return true;
				}
				pointHashGrid3d.InsertPoint(item2, v);
			}
			return false;
		}

		protected virtual DMesh3 BuildMesh_IdenticalWeld(STLSolid solid)
		{
			DMesh3Builder dMesh3Builder = new DMesh3Builder();
			dMesh3Builder.AppendNewMesh(bHaveVtxNormals: false, bHaveVtxColors: false, bHaveVtxUVs: false, bHaveFaceGroups: false);
			DVectorArray3f vertices = solid.Vertices;
			int count = vertices.Count;
			int[] array = new int[count];
			Dictionary<Vector3f, int> dictionary = new Dictionary<Vector3f, int>();
			for (int i = 0; i < count; i++)
			{
				Vector3f key = vertices[i];
				if (dictionary.TryGetValue(key, out var value))
				{
					array[i] = value;
					continue;
				}
				int num = (dictionary[key] = dMesh3Builder.AppendVertex(key.x, key.y, key.z));
				array[i] = num;
			}
			append_mapped_triangles(solid, dMesh3Builder, array);
			return dMesh3Builder.Meshes[0];
		}

		protected virtual DMesh3 BuildMesh_TolerantWeld(STLSolid solid, double weld_tolerance)
		{
			DMesh3Builder dMesh3Builder = new DMesh3Builder();
			dMesh3Builder.AppendNewMesh(bHaveVtxNormals: false, bHaveVtxColors: false, bHaveVtxUVs: false, bHaveFaceGroups: false);
			DVectorArray3f vertices = solid.Vertices;
			int count = vertices.Count;
			int[] array = new int[count];
			AxisAlignedBox3d empty = AxisAlignedBox3d.Empty;
			for (int i = 0; i < count; i++)
			{
				empty.Contain(vertices[i]);
			}
			int num = 256;
			if (count > 100000)
			{
				num = 512;
			}
			if (count > 1000000)
			{
				num = 1024;
			}
			if (count > 2000000)
			{
				num = 2048;
			}
			if (count > 5000000)
			{
				num = 4096;
			}
			PointHashGrid3d<int> pointHashGrid3d = new PointHashGrid3d<int>(empty.MaxDim / (double)(float)num, -1);
			Vector3f[] pos = new Vector3f[count];
			for (int j = 0; j < count; j++)
			{
				Vector3f v = vertices[j];
				KeyValuePair<int, double> keyValuePair = pointHashGrid3d.FindNearestInRadius(v, weld_tolerance, (int vid) => v.Distance(pos[vid]));
				if (keyValuePair.Key == -1)
				{
					int num2 = dMesh3Builder.AppendVertex(v.x, v.y, v.z);
					pointHashGrid3d.InsertPoint(num2, v);
					array[j] = num2;
					pos[num2] = v;
				}
				else
				{
					array[j] = keyValuePair.Key;
				}
			}
			append_mapped_triangles(solid, dMesh3Builder, array);
			return dMesh3Builder.Meshes[0];
		}

		private void append_mapped_triangles(STLSolid solid, DMesh3Builder builder, int[] mapV)
		{
			int num = solid.Vertices.Count / 3;
			for (int i = 0; i < num; i++)
			{
				int num2 = mapV[3 * i];
				int num3 = mapV[3 * i + 1];
				int num4 = mapV[3 * i + 2];
				if (num2 != num3 && num2 != num4 && num3 != num4)
				{
					builder.AppendTriangle(num2, num3, num4);
				}
			}
		}

		private void emit_warning(string sMessage)
		{
			string key = sMessage.Substring(0, 15);
			int num = (warningCount.ContainsKey(key) ? warningCount[key] : 0);
			num++;
			warningCount[key] = num;
			if (num <= 10)
			{
				if (num == 10)
				{
					sMessage += " (additional message surpressed)";
				}
				this.warningEvent?.Invoke(sMessage, null);
			}
		}
	}
	public class STLWriter : IMeshWriter
	{
		[StructLayout(LayoutKind.Sequential, Pack = 1)]
		private struct stl_triangle
		{
			public float nx;

			public float ny;

			public float nz;

			public float ax;

			public float ay;

			public float az;

			public float bx;

			public float by;

			public float bz;

			public float cx;

			public float cy;

			public float cz;

			public short attrib;
		}

		public IOWriteResult Write(BinaryWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			string s = "g3sharp_stl ";
			byte[] bytes = Encoding.ASCII.GetBytes(s);
			byte[] array = new byte[80];
			Array.Clear(array, 0, array.Length);
			Array.Copy(bytes, array, bytes.Length);
			writer.Write(array);
			int num = 0;
			foreach (WriteMesh vMesh in vMeshes)
			{
				num += vMesh.Mesh.TriangleCount;
			}
			writer.Write(num);
			for (int i = 0; i < vMeshes.Count; i++)
			{
				IMesh mesh = vMeshes[i].Mesh;
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(i, vMeshes.Count - 1);
				}
				Func<int, stl_triangle> producerF = delegate(int ti)
				{
					stl_triangle result = default(stl_triangle);
					Index3i triangle = mesh.GetTriangle(ti);
					Vector3d vertex = mesh.GetVertex(triangle.a);
					Vector3d vertex2 = mesh.GetVertex(triangle.b);
					Vector3d vertex3 = mesh.GetVertex(triangle.c);
					Vector3d vector3d = MathUtil.Normal(vertex, vertex2, vertex3);
					result.nx = (float)vector3d.x;
					result.ny = (float)vector3d.y;
					result.nz = (float)vector3d.z;
					result.ax = (float)vertex.x;
					result.ay = (float)vertex.y;
					result.az = (float)vertex.z;
					result.bx = (float)vertex2.x;
					result.by = (float)vertex2.y;
					result.bz = (float)vertex2.z;
					result.cx = (float)vertex3.x;
					result.cy = (float)vertex3.y;
					result.cz = (float)vertex3.z;
					result.attrib = 0;
					return result;
				};
				Action<stl_triangle> consumerF = delegate(stl_triangle tri)
				{
					byte[] buffer = Util.StructureToByteArray(tri);
					writer.Write(buffer);
				};
				ParallelStream<int, stl_triangle> parallelStream = new ParallelStream<int, stl_triangle>();
				parallelStream.ProducerF = producerF;
				parallelStream.ConsumerF = consumerF;
				parallelStream.Run(mesh.TriangleIndices());
			}
			return new IOWriteResult(IOCode.Ok, "");
		}

		public IOWriteResult Write(TextWriter writer, List<WriteMesh> vMeshes, WriteOptions options)
		{
			if (options.bCombineMeshes)
			{
				writer.WriteLine("solid \"mesh\"");
			}
			string text = Util.MakeVec3FormatString(0, 1, 2, options.RealPrecisionDigits);
			for (int i = 0; i < vMeshes.Count; i++)
			{
				IMesh mesh = vMeshes[i].Mesh;
				if (options.ProgressFunc != null)
				{
					options.ProgressFunc(i, vMeshes.Count - 1);
				}
				string arg = $"mesh_{i}";
				if (!options.bCombineMeshes)
				{
					if (vMeshes[i].Name != null && vMeshes[i].Name.Length > 0)
					{
						arg = vMeshes[i].Name;
					}
					writer.WriteLine("solid \"{0}\"", arg);
				}
				foreach (int item in mesh.TriangleIndices())
				{
					Index3i triangle = mesh.GetTriangle(item);
					Vector3d vertex = mesh.GetVertex(triangle.a);
					Vector3d vertex2 = mesh.GetVertex(triangle.b);
					Vector3d vertex3 = mesh.GetVertex(triangle.c);
					Vector3d vector3d = MathUtil.Normal(vertex, vertex2, vertex3);
					writer.WriteLine("facet normal " + text, vector3d.x, vector3d.y, vector3d.z);
					writer.WriteLine("outer loop" + writer.NewLine + "vertex " + text, vertex.x, vertex.y, vertex.z);
					writer.WriteLine("vertex " + text, vertex2.x, vertex2.y, vertex2.z);
					writer.WriteLine("vertex " + text, vertex3.x, vertex3.y, vertex3.z);
					writer.WriteLine("endloop" + writer.NewLine + "endfacet");
				}
				if (!options.bCombineMeshes)
				{
					writer.WriteLine("endsolid \"{0}\"", arg);
				}
			}
			if (options.bCombineMeshes)
			{
				writer.WriteLine("endsolid \"mesh\"");
			}
			return new IOWriteResult(IOCode.Ok, "");
		}
	}
	public class SVGWriter
	{
		public struct Style
		{
			public string fill;

			public string stroke;

			public float stroke_width;

			public static readonly Style Default = new Style
			{
				fill = "none",
				stroke = "black",
				stroke_width = 1f
			};

			public static Style Filled(string fillCol, string strokeCol = "", float strokeWidth = 0f)
			{
				return new Style
				{
					fill = fillCol,
					stroke = strokeCol,
					stroke_width = strokeWidth
				};
			}

			public static Style Outline(string strokeCol, float strokeWidth)
			{
				return new Style
				{
					fill = "none",
					stroke = strokeCol,
					stroke_width = strokeWidth
				};
			}

			public override string ToString()
			{
				StringBuilder stringBuilder = new StringBuilder();
				if (fill.Length > 0)
				{
					stringBuilder.Append("fill:");
					stringBuilder.Append(fill);
					stringBuilder.Append(';');
				}
				if (stroke.Length > 0)
				{
					stringBuilder.Append("stroke:");
					stringBuilder.Append(stroke);
					stringBuilder.Append(';');
				}
				if (stroke_width > 0f)
				{
					stringBuilder.Append("stroke-width:");
					stringBuilder.Append(stroke_width);
					stringBuilder.Append(";");
				}
				return stringBuilder.ToString();
			}
		}

		public bool FlipY = true;

		private Dictionary<object, Style> Styles = new Dictionary<object, Style>();

		public Style DefaultPolygonStyle;

		public Style DefaultPolylineStyle;

		public Style DefaultDGraphStyle;

		public Style DefaultCircleStyle;

		public Style DefaultArcStyle;

		public Style DefaultLineStyle;

		private List<object> Objects;

		private AxisAlignedBox2d Bounds;

		public int Precision = 3;

		public double BoundsPad = 10.0;

		public SVGWriter()
		{
			Objects = new List<object>();
			Bounds = AxisAlignedBox2d.Empty;
			DefaultPolygonStyle = Style.Outline("grey", 1f);
			DefaultPolylineStyle = Style.Outline("cyan", 1f);
			DefaultCircleStyle = Style.Filled("green", "black", 1f);
			DefaultArcStyle = Style.Outline("magenta", 1f);
			DefaultLineStyle = Style.Outline("black", 1f);
			DefaultDGraphStyle = Style.Outline("blue", 1f);
		}

		public void SetDefaultLineWidth(float width)
		{
			DefaultPolygonStyle.stroke_width = width;
			DefaultPolylineStyle.stroke_width = width;
			DefaultCircleStyle.stroke_width = width;
			DefaultArcStyle.stroke_width = width;
			DefaultLineStyle.stroke_width = width;
			DefaultDGraphStyle.stroke_width = width;
		}

		public void AddPolygon(Polygon2d poly)
		{
			Objects.Add(poly);
			Bounds.Contain(poly.Bounds);
		}

		public void AddPolygon(Polygon2d poly, Style style)
		{
			Objects.Add(poly);
			Styles[poly] = style;
			Bounds.Contain(poly.Bounds);
		}

		public void AddBox(AxisAlignedBox2d box)
		{
			AddBox(box, DefaultPolygonStyle);
		}

		public void AddBox(AxisAlignedBox2d box, Style style)
		{
			Polygon2d polygon2d = new Polygon2d();
			for (int i = 0; i < 4; i++)
			{
				polygon2d.AppendVertex(box.GetCorner(i));
			}
			AddPolygon(polygon2d, style);
		}

		public void AddPolyline(PolyLine2d poly)
		{
			Objects.Add(poly);
			Bounds.Contain(poly.Bounds);
		}

		public void AddPolyline(PolyLine2d poly, Style style)
		{
			Objects.Add(poly);
			Styles[poly] = style;
			Bounds.Contain(poly.Bounds);
		}

		public void AddGraph(DGraph2 graph)
		{
			Objects.Add(graph);
			Bounds.Contain(graph.GetBounds());
		}

		public void AddGraph(DGraph2 graph, Style style)
		{
			Objects.Add(graph);
			Styles[graph] = style;
			Bounds.Contain(graph.GetBounds());
		}

		public void AddCircle(Circle2d circle)
		{
			Objects.Add(circle);
			Bounds.Contain(circle.Bounds);
		}

		public void AddCircle(Circle2d circle, Style style)
		{
			Objects.Add(circle);
			Styles[circle] = style;
			Bounds.Contain(circle.Bounds);
		}

		public void AddArc(Arc2d arc)
		{
			Objects.Add(arc);
			Bounds.Contain(arc.Bounds);
		}

		public void AddArc(Arc2d arc, Style style)
		{
			Objects.Add(arc);
			Styles[arc] = style;
			Bounds.Contain(arc.Bounds);
		}

		public void AddLine(Segment2d segment)
		{
			Objects.Add(new Segment2dBox(segment));
			Bounds.Contain(segment.P0);
			Bounds.Contain(segment.P1);
		}

		public void AddLine(Segment2d segment, Style style)
		{
			Segment2dBox segment2dBox = new Segment2dBox(segment);
			Objects.Add(segment2dBox);
			Styles[segment2dBox] = style;
			Bounds.Contain(segment.P0);
			Bounds.Contain(segment.P1);
		}

		public void AddComplex(PlanarComplex complex)
		{
			Objects.Add(complex);
			Bounds.Contain(complex.Bounds());
		}

		public IOWriteResult Write(string sFilename)
		{
			CultureInfo currentCulture = Thread.CurrentThread.CurrentCulture;
			try
			{
				Thread.CurrentThread.CurrentCulture = CultureInfo.InvariantCulture;
				using (StreamWriter streamWriter = new StreamWriter(sFilename))
				{
					if (streamWriter.BaseStream == null)
					{
						return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sFilename + " for writing");
					}
					write_header_1_1(streamWriter);
					foreach (object @object in Objects)
					{
						if (@object is Polygon2d)
						{
							write_polygon(@object as Polygon2d, streamWriter);
							continue;
						}
						if (@object is PolyLine2d)
						{
							write_polyline(@object as PolyLine2d, streamWriter);
							continue;
						}
						if (@object is Circle2d)
						{
							write_circle(@object as Circle2d, streamWriter);
							continue;
						}
						if (@object is Arc2d)
						{
							write_arc(@object as Arc2d, streamWriter);
							continue;
						}
						if (@object is Segment2dBox)
						{
							write_line(@object as Segment2dBox, streamWriter);
							continue;
						}
						if (@object is DGraph2)
						{
							write_graph(@object as DGraph2, streamWriter);
							continue;
						}
						if (@object is PlanarComplex)
						{
							write_complex(@object as PlanarComplex, streamWriter);
							continue;
						}
						throw new Exception("SVGWriter.Write: unknown object type " + @object.GetType().ToString());
					}
					streamWriter.WriteLine("</svg>");
				}
				Thread.CurrentThread.CurrentCulture = currentCulture;
				return IOWriteResult.Ok;
			}
			catch (Exception ex)
			{
				Thread.CurrentThread.CurrentCulture = currentCulture;
				return new IOWriteResult(IOCode.WriterError, "Unknown error : exception : " + ex.Message);
			}
		}

		public static void QuickWrite(List<GeneralPolygon2d> polygons, string sPath, double line_width = 1.0)
		{
			SVGWriter sVGWriter = new SVGWriter();
			Style style = Style.Outline("black", 2f * (float)line_width);
			Style style2 = Style.Outline("green", 2f * (float)line_width);
			Style style3 = Style.Outline("red", (float)line_width);
			foreach (GeneralPolygon2d polygon in polygons)
			{
				if (polygon.Outer.IsClockwise)
				{
					sVGWriter.AddPolygon(polygon.Outer, style);
				}
				else
				{
					sVGWriter.AddPolygon(polygon.Outer, style2);
				}
				foreach (Polygon2d hole in polygon.Holes)
				{
					sVGWriter.AddPolygon(hole, style3);
				}
			}
			sVGWriter.Write(sPath);
		}

		public static void QuickWrite(DGraph2 graph, string sPath, double line_width = 1.0)
		{
			SVGWriter sVGWriter = new SVGWriter();
			Style style = Style.Outline("black", (float)line_width);
			sVGWriter.AddGraph(graph, style);
			sVGWriter.Write(sPath);
		}

		public static void QuickWrite(List<GeneralPolygon2d> polygons1, string color1, float width1, List<GeneralPolygon2d> polygons2, string color2, float width2, string sPath)
		{
			SVGWriter sVGWriter = new SVGWriter();
			Style style = Style.Outline(color1, width1);
			Style style2 = Style.Outline(color1, width1 / 2f);
			foreach (GeneralPolygon2d item in polygons1)
			{
				sVGWriter.AddPolygon(item.Outer, style);
				foreach (Polygon2d hole in item.Holes)
				{
					sVGWriter.AddPolygon(hole, style2);
				}
			}
			Style style3 = Style.Outline(color2, width2);
			Style style4 = Style.Outline(color2, width2 / 2f);
			foreach (GeneralPolygon2d item2 in polygons2)
			{
				sVGWriter.AddPolygon(item2.Outer, style3);
				foreach (Polygon2d hole2 in item2.Holes)
				{
					sVGWriter.AddPolygon(hole2, style4);
				}
			}
			sVGWriter.Write(sPath);
		}

		protected virtual Vector2d MapPt(Vector2d v)
		{
			if (FlipY)
			{
				return new Vector2d(v.x, Bounds.Min.y + (Bounds.Max.y - v.y));
			}
			return v;
		}

		private void write_header_1_1(StreamWriter w)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("<svg ");
			stringBuilder.Append("version=\"1.1\" ");
			stringBuilder.Append("xmlns=\"http://www.w3.org/2000/svg\" ");
			stringBuilder.Append("xmlns:xlink=\"http://www.w3.org/1999/xlink\" ");
			stringBuilder.Append("x=\"0px\" y=\"0px\" ");
			stringBuilder.Append($"viewBox=\"{Math.Round(Bounds.Min.x - BoundsPad, Precision)} {Math.Round(Bounds.Min.y - BoundsPad, Precision)} {Math.Round(Bounds.Width + 2.0 * BoundsPad, Precision)} {Math.Round(Bounds.Height + 2.0 * BoundsPad, Precision)}\" ");
			stringBuilder.Append('>');
			w.WriteLine(stringBuilder);
		}

		private void write_polygon(Polygon2d poly, StreamWriter w)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("<polygon points=\"");
			for (int i = 0; i < poly.VertexCount; i++)
			{
				Vector2d vector2d = MapPt(poly[i]);
				stringBuilder.Append(Math.Round(vector2d.x, Precision));
				stringBuilder.Append(',');
				stringBuilder.Append(Math.Round(vector2d.y, Precision));
				if (i < poly.VertexCount - 1)
				{
					stringBuilder.Append(' ');
				}
			}
			stringBuilder.Append("\" ");
			append_style(stringBuilder, poly, ref DefaultPolygonStyle);
			stringBuilder.Append(" />");
			w.WriteLine(stringBuilder);
		}

		private void write_polyline(PolyLine2d poly, StreamWriter w)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("<polyline points=\"");
			for (int i = 0; i < poly.VertexCount; i++)
			{
				Vector2d vector2d = MapPt(poly[i]);
				stringBuilder.Append(Math.Round(vector2d.x, Precision));
				stringBuilder.Append(',');
				stringBuilder.Append(Math.Round(vector2d.y, Precision));
				if (i < poly.VertexCount - 1)
				{
					stringBuilder.Append(' ');
				}
			}
			stringBuilder.Append("\" ");
			append_style(stringBuilder, poly, ref DefaultPolylineStyle);
			stringBuilder.Append(" />");
			w.WriteLine(stringBuilder);
		}

		private void write_graph(DGraph2 graph, StreamWriter w)
		{
			string value = get_style(graph, ref DefaultDGraphStyle);
			StringBuilder stringBuilder = new StringBuilder();
			foreach (int item in graph.EdgeIndices())
			{
				Segment2d edgeSegment = graph.GetEdgeSegment(item);
				stringBuilder.Append("<line ");
				Vector2d vector2d = MapPt(edgeSegment.P0);
				Vector2d vector2d2 = MapPt(edgeSegment.P1);
				append_property("x1", vector2d.x, stringBuilder);
				append_property("y1", vector2d.y, stringBuilder);
				append_property("x2", vector2d2.x, stringBuilder);
				append_property("y2", vector2d2.y, stringBuilder);
				stringBuilder.Append(value);
				stringBuilder.Append(" />");
				stringBuilder.AppendLine();
			}
			w.WriteLine(stringBuilder);
		}

		private void write_circle(Circle2d circle, StreamWriter w)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("<circle ");
			Vector2d vector2d = MapPt(circle.Center);
			append_property("cx", vector2d.x, stringBuilder);
			append_property("cy", vector2d.y, stringBuilder);
			append_property("r", circle.Radius, stringBuilder);
			append_style(stringBuilder, circle, ref DefaultCircleStyle);
			stringBuilder.Append(" />");
			w.WriteLine(stringBuilder);
		}

		private void write_arc(Arc2d arc, StreamWriter w)
		{
			StringBuilder stringBuilder = new StringBuilder();
			Vector2d vector2d = MapPt(arc.P0);
			Vector2d vector2d2 = MapPt(arc.P1);
			stringBuilder.Append("<path ");
			stringBuilder.Append("d=\"");
			stringBuilder.Append("M");
			stringBuilder.Append(Math.Round(vector2d.x, Precision));
			stringBuilder.Append(",");
			stringBuilder.Append(Math.Round(vector2d.y, Precision));
			stringBuilder.Append(" ");
			stringBuilder.Append("A");
			stringBuilder.Append(Math.Round(arc.Radius, Precision));
			stringBuilder.Append(",");
			stringBuilder.Append(Math.Round(arc.Radius, Precision));
			stringBuilder.Append(" ");
			stringBuilder.Append("0 ");
			int value = ((arc.AngleEndDeg - arc.AngleStartDeg > 180.0) ? 1 : 0);
			int value2 = (arc.IsReversed ? 1 : 0);
			stringBuilder.Append(value);
			stringBuilder.Append(",");
			stringBuilder.Append(value2);
			stringBuilder.Append(Math.Round(vector2d2.x, Precision));
			stringBuilder.Append(",");
			stringBuilder.Append(Math.Round(vector2d2.y, Precision));
			stringBuilder.Append("\" ");
			append_style(stringBuilder, arc, ref DefaultArcStyle);
			stringBuilder.Append(" />");
			w.WriteLine(stringBuilder);
		}

		private void write_line(Segment2dBox segbox, StreamWriter w)
		{
			Segment2d segment2d = segbox;
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("<line ");
			Vector2d vector2d = MapPt(segment2d.P0);
			Vector2d vector2d2 = MapPt(segment2d.P1);
			append_property("x1", vector2d.x, stringBuilder);
			append_property("y1", vector2d.y, stringBuilder);
			append_property("x2", vector2d2.x, stringBuilder);
			append_property("y2", vector2d2.y, stringBuilder);
			append_style(stringBuilder, segbox, ref DefaultLineStyle);
			stringBuilder.Append(" />");
			w.WriteLine(stringBuilder);
		}

		private void write_complex(PlanarComplex complex, StreamWriter w)
		{
			foreach (PlanarComplex.Element item in complex.ElementsItr())
			{
				foreach (IParametricCurve2d item2 in CurveUtils2.Flatten(item.source))
				{
					if (item2 is Segment2d)
					{
						write_line(new Segment2dBox((Segment2d)(object)item2), w);
					}
					else if (item2 is Circle2d)
					{
						write_circle(item2 as Circle2d, w);
					}
					else if (item2 is Polygon2DCurve)
					{
						write_polygon((item2 as Polygon2DCurve).Polygon, w);
					}
					else if (item2 is PolyLine2DCurve)
					{
						write_polyline((item2 as PolyLine2DCurve).Polyline, w);
					}
					else if (item2 is Arc2d)
					{
						write_arc(item2 as Arc2d, w);
					}
				}
			}
		}

		private void append_property(string name, double val, StringBuilder b, bool trailSpace = true)
		{
			b.Append(name);
			b.Append("=\"");
			b.Append(Math.Round(val, Precision));
			if (trailSpace)
			{
				b.Append("\" ");
			}
			else
			{
				b.Append("\"");
			}
		}

		private void append_style(StringBuilder b, object o, ref Style defaultStyle)
		{
			if (!Styles.TryGetValue(o, out var value))
			{
				value = defaultStyle;
			}
			b.Append("style=\"");
			b.Append(value.ToString());
			b.Append("\"");
		}

		private string get_style(object o, ref Style defaultStyle)
		{
			if (!Styles.TryGetValue(o, out var value))
			{
				value = defaultStyle;
			}
			return "style=\"" + value.ToString() + "\"";
		}
	}
	public struct AxisAlignedBox2d
	{
		public enum ScaleMode
		{
			ScaleRight,
			ScaleLeft,
			ScaleUp,
			ScaleDown,
			ScaleCenter
		}

		public Vector2d Min;

		public Vector2d Max;

		public static readonly AxisAlignedBox2d Empty;

		public static readonly AxisAlignedBox2d Zero;

		public static readonly AxisAlignedBox2d UnitPositive;

		public static readonly AxisAlignedBox2d Infinite;

		public double Width => Math.Max(Max.x - Min.x, 0.0);

		public double Height => Math.Max(Max.y - Min.y, 0.0);

		public double Area => Width * Height;

		public double DiagonalLength => Math.Sqrt((Max.x - Min.x) * (Max.x - Min.x) + (Max.y - Min.y) * (Max.y - Min.y));

		public double MaxDim => Math.Max(Width, Height);

		public double MinDim => Math.Min(Width, Height);

		public double MaxUnsignedCoordinate => Math.Max(Math.Max(Math.Abs(Min.x), Math.Abs(Max.x)), Math.Max(Math.Abs(Min.y), Math.Abs(Max.y)));

		public Vector2d Diagonal => new Vector2d(Max.x - Min.x, Max.y - Min.y);

		public Vector2d Center => new Vector2d(0.5 * (Min.x + Max.x), 0.5 * (Min.y + Max.y));

		public AxisAlignedBox2d(bool bIgnore)
		{
			Min = new Vector2d(double.MaxValue, double.MaxValue);
			Max = new Vector2d(double.MinValue, double.MinValue);
		}

		public AxisAlignedBox2d(double xmin, double ymin, double xmax, double ymax)
		{
			Min = new Vector2d(xmin, ymin);
			Max = new Vector2d(xmax, ymax);
		}

		public AxisAlignedBox2d(double fSquareSize)
		{
			Min = new Vector2d(0f, 0f);
			Max = new Vector2d(fSquareSize, fSquareSize);
		}

		public AxisAlignedBox2d(double fWidth, double fHeight)
		{
			Min = new Vector2d(0f, 0f);
			Max = new Vector2d(fWidth, fHeight);
		}

		public AxisAlignedBox2d(Vector2d vMin, Vector2d vMax)
		{
			Min = new Vector2d(Math.Min(vMin.x, vMax.x), Math.Min(vMin.y, vMax.y));
			Max = new Vector2d(Math.Max(vMin.x, vMax.x), Math.Max(vMin.y, vMax.y));
		}

		public AxisAlignedBox2d(Vector2d vCenter, double fHalfWidth, double fHalfHeight)
		{
			Min = new Vector2d(vCenter.x - fHalfWidth, vCenter.y - fHalfHeight);
			Max = new Vector2d(vCenter.x + fHalfWidth, vCenter.y + fHalfHeight);
		}

		public AxisAlignedBox2d(Vector2d vCenter, double fHalfWidth)
		{
			Min = new Vector2d(vCenter.x - fHalfWidth, vCenter.y - fHalfWidth);
			Max = new Vector2d(vCenter.x + fHalfWidth, vCenter.y + fHalfWidth);
		}

		public AxisAlignedBox2d(Vector2d vCenter)
		{
			Min = (Max = vCenter);
		}

		public AxisAlignedBox2d(AxisAlignedBox2d o)
		{
			Min = new Vector2d(o.Min);
			Max = new Vector2d(o.Max);
		}

		public Vector2d GetCorner(int i)
		{
			return new Vector2d((i % 3 == 0) ? Min.x : Max.x, (i < 2) ? Min.y : Max.y);
		}

		public Vector2d SampleT(double tx, double sy)
		{
			return new Vector2d((1.0 - tx) * Min.x + tx * Max.x, (1.0 - sy) * Min.y + sy * Max.y);
		}

		public void Expand(double fRadius)
		{
			Min.x -= fRadius;
			Min.y -= fRadius;
			Max.x += fRadius;
			Max.y += fRadius;
		}

		public void Contract(double fRadius)
		{
			Min.x += fRadius;
			Min.y += fRadius;
			Max.x -= fRadius;
			Max.y -= fRadius;
		}

		[Obsolete("This method name is confusing. Will remove in future. Use Add() instead")]
		public void Pad(double fPadLeft, double fPadRight, double fPadBottom, double fPadTop)
		{
			Min.x += fPadLeft;
			Min.y += fPadBottom;
			Max.x += fPadRight;
			Max.y += fPadTop;
		}

		public void Add(double left, double right, double bottom, double top)
		{
			Min.x += left;
			Min.y += bottom;
			Max.x += right;
			Max.y += top;
		}

		public void SetWidth(double fNewWidth, ScaleMode eScaleMode)
		{
			switch (eScaleMode)
			{
			case ScaleMode.ScaleLeft:
				Min.x = Max.x - fNewWidth;
				break;
			case ScaleMode.ScaleRight:
				Max.x = Min.x + fNewWidth;
				break;
			case ScaleMode.ScaleCenter:
			{
				Vector2d center = Center;
				Min.x = center.x - 0.5 * fNewWidth;
				Max.x = center.x + 0.5 * fNewWidth;
				break;
			}
			default:
				throw new Exception("Invalid scale mode...");
			}
		}

		public void SetHeight(double fNewHeight, ScaleMode eScaleMode)
		{
			switch (eScaleMode)
			{
			case ScaleMode.ScaleDown:
				Min.y = Max.y - fNewHeight;
				break;
			case ScaleMode.ScaleUp:
				Max.y = Min.y + fNewHeight;
				break;
			case ScaleMode.ScaleCenter:
			{
				Vector2d center = Center;
				Min.y = center.y - 0.5 * fNewHeight;
				Max.y = center.y + 0.5 * fNewHeight;
				break;
			}
			default:
				throw new Exception("Invalid scale mode...");
			}
		}

		public void Contain(Vector2d v)
		{
			if (v.x < Min.x)
			{
				Min.x = v.x;
			}
			if (v.x > Max.x)
			{
				Max.x = v.x;
			}
			if (v.y < Min.y)
			{
				Min.y = v.y;
			}
			if (v.y > Max.y)
			{
				Max.y = v.y;
			}
		}

		public void Contain(ref Vector2d v)
		{
			if (v.x < Min.x)
			{
				Min.x = v.x;
			}
			if (v.x > Max.x)
			{
				Max.x = v.x;
			}
			if (v.y < Min.y)
			{
				Min.y = v.y;
			}
			if (v.y > Max.y)
			{
				Max.y = v.y;
			}
		}

		public void Contain(AxisAlignedBox2d box)
		{
			if (box.Min.x < Min.x)
			{
				Min.x = box.Min.x;
			}
			if (box.Max.x > Max.x)
			{
				Max.x = box.Max.x;
			}
			if (box.Min.y < Min.y)
			{
				Min.y = box.Min.y;
			}
			if (box.Max.y > Max.y)
			{
				Max.y = box.Max.y;
			}
		}

		public void Contain(ref AxisAlignedBox2d box)
		{
			if (box.Min.x < Min.x)
			{
				Min.x = box.Min.x;
			}
			if (box.Max.x > Max.x)
			{
				Max.x = box.Max.x;
			}
			if (box.Min.y < Min.y)
			{
				Min.y = box.Min.y;
			}
			if (box.Max.y > Max.y)
			{
				Max.y = box.Max.y;
			}
		}

		public void Contain(IList<Vector2d> points)
		{
			int count = points.Count;
			if (count <= 0)
			{
				return;
			}
			Vector2d v = points[0];
			Contain(ref v);
			for (int i = 1; i < count; i++)
			{
				v = points[i];
				if (v.x < Min.x)
				{
					Min.x = v.x;
				}
				else if (v.x > Max.x)
				{
					Max.x = v.x;
				}
				if (v.y < Min.y)
				{
					Min.y = v.y;
				}
				else if (v.y > Max.y)
				{
					Max.y = v.y;
				}
			}
		}

		public AxisAlignedBox2d Intersect(AxisAlignedBox2d box)
		{
			AxisAlignedBox2d result = new AxisAlignedBox2d(Math.Max(Min.x, box.Min.x), Math.Max(Min.y, box.Min.y), Math.Min(Max.x, box.Max.x), Math.Min(Max.y, box.Max.y));
			if (result.Height <= 0.0 || result.Width <= 0.0)
			{
				return Empty;
			}
			return result;
		}

		public bool Contains(Vector2d v)
		{
			if (Min.x < v.x && Min.y < v.y && Max.x > v.x)
			{
				return Max.y > v.y;
			}
			return false;
		}

		public bool Contains(ref Vector2d v)
		{
			if (Min.x < v.x && Min.y < v.y && Max.x > v.x)
			{
				return Max.y > v.y;
			}
			return false;
		}

		public bool Contains(AxisAlignedBox2d box2)
		{
			if (Contains(ref box2.Min))
			{
				return Contains(ref box2.Max);
			}
			return false;
		}

		public bool Contains(ref AxisAlignedBox2d box2)
		{
			if (Contains(ref box2.Min))
			{
				return Contains(ref box2.Max);
			}
			return false;
		}

		public bool Intersects(AxisAlignedBox2d box)
		{
			if (!(box.Max.x < Min.x) && !(box.Min.x > Max.x) && !(box.Max.y < Min.y))
			{
				return !(box.Min.y > Max.y);
			}
			return false;
		}

		public bool Intersects(ref AxisAlignedBox2d box)
		{
			if (!(box.Max.x < Min.x) && !(box.Min.x > Max.x) && !(box.Max.y < Min.y))
			{
				return !(box.Min.y > Max.y);
			}
			return false;
		}

		public double Distance(Vector2d v)
		{
			double num = Math.Abs(v.x - Center.x);
			double num2 = Math.Abs(v.y - Center.y);
			double num3 = Width * 0.5;
			double num4 = Height * 0.5;
			if (num < num3 && num2 < num4)
			{
				return 0.0;
			}
			if (num > num3 && num2 > num4)
			{
				return Math.Sqrt((num - num3) * (num - num3) + (num2 - num4) * (num2 - num4));
			}
			if (num > num3)
			{
				return num - num3;
			}
			if (num2 > num4)
			{
				return num2 - num4;
			}
			return 0.0;
		}

		public void Translate(Vector2d vTranslate)
		{
			Min.Add(vTranslate);
			Max.Add(vTranslate);
		}

		public void Scale(double scale)
		{
			Min *= scale;
			Max *= scale;
		}

		public void Scale(double scale, Vector2d origin)
		{
			Min = (Min - origin) * scale + origin;
			Max = (Max - origin) * scale + origin;
		}

		public void MoveMin(Vector2d vNewMin)
		{
			Max.x = vNewMin.x + (Max.x - Min.x);
			Max.y = vNewMin.y + (Max.y - Min.y);
