			Min.z = Math.Min(Min.z, (float)box.Min.z);
			Max.x = Math.Max(Max.x, (float)box.Max.x);
			Max.y = Math.Max(Max.y, (float)box.Max.y);
			Max.z = Math.Max(Max.z, (float)box.Max.z);
		}

