			float num2 = ((v.y < Min.y) ? (Min.y - v.y) : ((v.y > Max.y) ? (v.y - Max.y) : 0f));
			float num3 = ((v.z < Min.z) ? (Min.z - v.z) : ((v.z > Max.z) ? (v.z - Max.z) : 0f));
			return num * num + num2 * num2 + num3 * num3;
