				double num3;
				if (i == 0)
				{
					num2 = v.Dot(AxisX);
					num3 = Extent.x;
				}
				else
				{
					num2 = v.Dot(AxisY);
					num3 = Extent.y;
				}
				if (num2 < 0.0 - num3)
				{
					double num4 = num2 + num3;
					num += num4 * num4;
				}
				else if (num2 > num3)
				{
					double num4 = num2 - num3;
					num += num4 * num4;
				}
			}
			return num;
		}

		public Vector2d ClosestPoint(Vector2d v)
