		{
			return new Box2f((Vector2f)v.Center, (Vector2f)v.AxisX, (Vector2f)v.AxisY, (Vector2f)v.Extent);
		}

		static Box2d()
		{
			Empty = new Box2d(Vector2d.Zero);
		}
