			result.Contain(Center + vector3d - vector3d2 - vector3d3);
			result.Contain(Center + vector3d + vector3d2 - vector3d3);
			result.Contain(Center - vector3d + vector3d2 - vector3d3);
			result.Contain(Center - vector3d - vector3d2 + vector3d3);
			result.Contain(Center + vector3d - vector3d2 + vector3d3);
