			Matrix3d rot2 = new Matrix3d(ref box1.AxisX, ref box1.AxisY, ref box1.AxisZ, bRows: false);
			quaterniond2.SetFromRotationMatrix(ref rot2);
			if (quaterniond.Dot(quaterniond2) < 0.0)
			{
				quaterniond2 = -quaterniond2;
			}
			Quaterniond quaterniond3 = quaterniond + quaterniond2;
			double num = 1.0 / Math.Sqrt(quaterniond3.Dot(quaterniond3));
			Matrix3d matrix3d = (quaterniond3 * num).ToRotationMatrix();
			result.AxisX = matrix3d.Column(0);
			result.AxisY = matrix3d.Column(1);
			result.AxisZ = matrix3d.Column(2);
			Vector3d[] array = new Vector3d[8];
			Vector3d zero = Vector3d.Zero;
			Vector3d zero2 = Vector3d.Zero;
			box0.ComputeVertices(array);
			for (int i = 0; i < 8; i++)
			{
				Vector3d v = array[i] - result.Center;
				for (int j = 0; j < 3; j++)
				{
					double num2 = result.Axis(j).Dot(ref v);
					if (num2 > zero2[j])
					{
						zero2[j] = num2;
					}
					else if (num2 < zero[j])
					{
						zero[j] = num2;
					}
				}
			}
			box1.ComputeVertices(array);
			for (int i = 0; i < 8; i++)
			{
				Vector3d v2 = array[i] - result.Center;
				for (int j = 0; j < 3; j++)
				{
					double num2 = result.Axis(j).Dot(ref v2);
					if (num2 > zero2[j])
					{
						zero2[j] = num2;
					}
					else if (num2 < zero[j])
					{
						zero[j] = num2;
					}
				}
			}
			for (int j = 0; j < 3; j++)
			{
				result.Center += 0.5 * (zero2[j] + zero[j]) * result.Axis(j);
				result.Extent[j] = 0.5 * (zero2[j] - zero[j]);
			}
			return result;
		}

		public static implicit operator Box3d(Box3f v)
		{
			return new Box3d(v.Center, v.AxisX, v.AxisY, v.AxisZ, v.Extent);
		}

		public static explicit operator Box3f(Box3d v)
		{
			return new Box3f((Vector3f)v.Center, (Vector3f)v.AxisX, (Vector3f)v.AxisY, (Vector3f)v.AxisZ, (Vector3f)v.Extent);
		}

		static Box3d()
		{
			Empty = new Box3d(Vector3d.Zero);
			UnitZeroCentered = new Box3d(Vector3d.Zero, 0.5 * Vector3d.One);
			UnitPositive = new Box3d(0.5 * Vector3d.One, 0.5 * Vector3d.One);
		}
	}
	public struct Box3f
	{
		public Vector3f Center;

		public Vector3f AxisX;

		public Vector3f AxisY;

		public Vector3f AxisZ;

		public Vector3f Extent;

		public static readonly Box3f Empty;

		public double MaxExtent => Math.Max(Extent.x, Math.Max(Extent.y, Extent.z));

		public double MinExtent => Math.Min(Extent.x, Math.Max(Extent.y, Extent.z));

		public Vector3f Diagonal => Extent.x * AxisX + Extent.y * AxisY + Extent.z * AxisZ - ((0f - Extent.x) * AxisX - Extent.y * AxisY - Extent.z * AxisZ);

		public double Volume => 2f * Extent.x * 2f * Extent.y * 2f * Extent.z;

		public Box3f(Vector3f center)
		{
			Center = center;
			AxisX = Vector3f.AxisX;
			AxisY = Vector3f.AxisY;
			AxisZ = Vector3f.AxisZ;
			Extent = Vector3f.Zero;
		}

		public Box3f(Vector3f center, Vector3f x, Vector3f y, Vector3f z, Vector3f extent)
		{
			Center = center;
			AxisX = x;
			AxisY = y;
			AxisZ = z;
			Extent = extent;
		}

		public Box3f(Vector3f center, Vector3f extent)
		{
			Center = center;
			Extent = extent;
			AxisX = Vector3f.AxisX;
			AxisY = Vector3f.AxisY;
			AxisZ = Vector3f.AxisZ;
		}

		public Box3f(AxisAlignedBox3f aaBox)
		{
			Extent = new Vector3f(aaBox.Width * 0.5f, aaBox.Height * 0.5f, aaBox.Depth * 0.5f);
			Center = aaBox.Center;
			AxisX = Vector3f.AxisX;
			AxisY = Vector3f.AxisY;
			AxisZ = Vector3f.AxisZ;
		}

		public Vector3f Axis(int i)
		{
			return i switch
			{
				1 => AxisY, 
				0 => AxisX, 
				_ => AxisZ, 
			};
		}

		public Vector3f[] ComputeVertices()
		{
			Vector3f[] array = new Vector3f[8];
			ComputeVertices(array);
			return array;
		}

		public void ComputeVertices(Vector3f[] vertex)
		{
			Vector3f vector3f = Extent.x * AxisX;
			Vector3f vector3f2 = Extent.y * AxisY;
			Vector3f vector3f3 = Extent.z * AxisZ;
			vertex[0] = Center - vector3f - vector3f2 - vector3f3;
			vertex[1] = Center + vector3f - vector3f2 - vector3f3;
			vertex[2] = Center + vector3f + vector3f2 - vector3f3;
			vertex[3] = Center - vector3f + vector3f2 - vector3f3;
			vertex[4] = Center - vector3f - vector3f2 + vector3f3;
			vertex[5] = Center + vector3f - vector3f2 + vector3f3;
			vertex[6] = Center + vector3f + vector3f2 + vector3f3;
			vertex[7] = Center - vector3f + vector3f2 + vector3f3;
		}

		public IEnumerable<Vector3f> VerticesItr()
		{
			Vector3f extAxis0 = Extent.x * AxisX;
			Vector3f extAxis1 = Extent.y * AxisY;
			Vector3f extAxis2 = Extent.z * AxisZ;
			yield return Center - extAxis0 - extAxis1 - extAxis2;
			yield return Center + extAxis0 - extAxis1 - extAxis2;
			yield return Center + extAxis0 + extAxis1 - extAxis2;
			yield return Center - extAxis0 + extAxis1 - extAxis2;
			yield return Center - extAxis0 - extAxis1 + extAxis2;
			yield return Center + extAxis0 - extAxis1 + extAxis2;
			yield return Center + extAxis0 + extAxis1 + extAxis2;
			yield return Center - extAxis0 + extAxis1 + extAxis2;
		}

		public AxisAlignedBox3f ToAABB()
		{
			Vector3f vector3f = Extent.x * AxisX;
			Vector3f vector3f2 = Extent.y * AxisY;
			Vector3f vector3f3 = Extent.z * AxisZ;
			AxisAlignedBox3f result = new AxisAlignedBox3f(Center - vector3f - vector3f2 - vector3f3);
			result.Contain(Center + vector3f - vector3f2 - vector3f3);
			result.Contain(Center + vector3f + vector3f2 - vector3f3);
			result.Contain(Center - vector3f + vector3f2 - vector3f3);
			result.Contain(Center - vector3f - vector3f2 + vector3f3);
			result.Contain(Center + vector3f - vector3f2 + vector3f3);
			result.Contain(Center + vector3f + vector3f2 + vector3f3);
			result.Contain(Center - vector3f + vector3f2 + vector3f3);
			return result;
		}

		public void Contain(Vector3f v)
		{
			Vector3f vector3f = v - Center;
			for (int i = 0; i < 3; i++)
			{
				double num = vector3f.Dot(Axis(i));
				if (Math.Abs(num) > (double)Extent[i])
				{
					double num2 = 0f - Extent[i];
					double num3 = Extent[i];
					if (num < num2)
					{
						num2 = num;
					}
					else if (num > num3)
					{
						num3 = num;
					}
					Extent[i] = (float)(num3 - num2) * 0.5f;
					Center += (float)(num3 + num2) * 0.5f * Axis(i);
				}
			}
		}

		public void Contain(Box3f o)
		{
			Vector3f[] array = o.ComputeVertices();
			for (int i = 0; i < 8; i++)
			{
				Contain(array[i]);
			}
		}

		public bool Contains(Vector3f v)
		{
			Vector3f vector3f = v - Center;
			if (Math.Abs(vector3f.Dot(AxisX)) <= Extent.x && Math.Abs(vector3f.Dot(AxisY)) <= Extent.y)
			{
				return Math.Abs(vector3f.Dot(AxisZ)) <= Extent.z;
			}
			return false;
		}

		public void Expand(float f)
		{
			Extent += f;
		}

		public void Translate(Vector3f v)
		{
			Center += v;
		}

		public void Scale(Vector3f s)
		{
			Center *= s;
			Extent *= s;
			AxisX *= s;
			AxisX.Normalize();
			AxisY *= s;
			AxisY.Normalize();
			AxisZ *= s;
			AxisZ.Normalize();
		}

		public void ScaleExtents(Vector3f s)
		{
			Extent *= s;
		}

		static Box3f()
		{
			Empty = new Box3f(Vector3f.Zero);
		}
	}
	public static class FastTriWinding
	{
		public static void ComputeCoeffs(DMesh3 mesh, IEnumerable<int> triangles, ref Vector3d p, ref double r, ref Vector3d order1, ref Matrix3d order2, MeshTriInfoCache triCache = null)
		{
			p = Vector3d.Zero;
			order1 = Vector3d.Zero;
			order2 = Matrix3d.Zero;
			r = 0.0;
			Vector3d v = Vector3d.Zero;
			Vector3d v2 = Vector3d.Zero;
			Vector3d v3 = Vector3d.Zero;
			double num = 0.0;
			foreach (int triangle in triangles)
			{
				if (triCache != null)
				{
					double num2 = triCache.Areas[triangle];
					num += num2;
					p += num2 * triCache.Centroids[triangle];
				}
				else
				{
					mesh.GetTriVertices(triangle, ref v, ref v2, ref v3);
					double num3 = MathUtil.Area(ref v, ref v2, ref v3);
					num += num3;
					p += num3 * ((v + v2 + v3) / 3.0);
				}
			}
			p /= num;
			Vector3d n = Vector3d.Zero;
			Vector3d c = Vector3d.Zero;
			double area = 0.0;
			foreach (int triangle2 in triangles)
			{
				mesh.GetTriVertices(triangle2, ref v, ref v2, ref v3);
				if (triCache == null)
				{
					c = 1.0 / 3.0 * (v + v2 + v3);
					n = MathUtil.FastNormalArea(ref v, ref v2, ref v3, out area);
				}
				else
				{
					triCache.GetTriInfo(triangle2, ref n, ref area, ref c);
				}
				order1 += area * n;
				Vector3d u = c - p;
				order2 += area * new Matrix3d(ref u, ref n);
				double d = MathUtil.Max(v.DistanceSquared(ref p), v2.DistanceSquared(ref p), v3.DistanceSquared(ref p));
				r = Math.Max(r, Math.Sqrt(d));
			}
		}

		public static double EvaluateOrder1Approx(ref Vector3d center, ref Vector3d order1Coeff, ref Vector3d q)
		{
			Vector3d vector3d = center - q;
			double length = vector3d.Length;
			return 1.0 / (4.0 * Math.PI) * order1Coeff.Dot(vector3d / (length * length * length));
		}

		public static double EvaluateOrder2Approx(ref Vector3d center, ref Vector3d order1Coeff, ref Matrix3d order2Coeff, ref Vector3d q)
		{
			Vector3d v = center - q;
			double length = v.Length;
			double num = length * length * length;
			double num2 = 1.0 / (Math.PI * 4.0 * num);
			double num3 = num2 * order1Coeff.Dot(ref v);
			double num4 = -3.0 / (Math.PI * 4.0 * num * length * length);
			Matrix3d m = new Matrix3d(num2 + num4 * v.x * v.x, num4 * v.x * v.y, num4 * v.x * v.z, num4 * v.y * v.x, num2 + num4 * v.y * v.y, num4 * v.y * v.z, num4 * v.z * v.x, num4 * v.z * v.y, num2 + num4 * v.z * v.z);
			double num5 = order2Coeff.InnerProduct(ref m);
			return num3 + num5;
		}

		public static double Order1Approx(ref Triangle3d t, ref Vector3d p, ref Vector3d xn, ref double xA, ref Vector3d q)
		{
			Vector3d vector3d = xA * xn;
			Vector3d vector3d2 = p - q;
			double length = vector3d2.Length;
			return 1.0 / (4.0 * Math.PI) * vector3d.Dot(vector3d2 / (length * length * length));
		}

		public static double Order2Approx(ref Triangle3d t, ref Vector3d p, ref Vector3d xn, ref double xA, ref Vector3d q)
		{
			Vector3d u = p - q;
			double length = u.Length;
			double num = length * length * length;
			double num2 = xA / (Math.PI * 4.0) * xn.Dot(u / num);
			Matrix3d matrix3d = new Matrix3d(ref u, ref u);
			matrix3d *= 3.0 / (Math.PI * 4.0 * num * length * length);
			double num3 = 1.0 / (Math.PI * 4.0 * num);
			Matrix3d m = new Matrix3d(num3, num3, num3) - matrix3d;
			Vector3d u2 = new Vector3d((t.V0.x + t.V1.x + t.V2.x) / 3.0, (t.V0.y + t.V1.y + t.V2.y) / 3.0, (t.V0.z + t.V1.z + t.V2.z) / 3.0) - p;
			Matrix3d matrix3d2 = new Matrix3d(ref u2, ref xn);
			double num4 = xA * matrix3d2.InnerProduct(ref m);
			return num2 + num4;
		}
	}
	public static class FastPointWinding
	{
		public static void ComputeCoeffs(IPointSet pointSet, IEnumerable<int> points, double[] pointAreas, ref Vector3d p, ref double r, ref Vector3d order1, ref Matrix3d order2)
		{
			if (!pointSet.HasVertexNormals)
			{
				throw new Exception("FastPointWinding.ComputeCoeffs: point set does not have normals!");
			}
			p = Vector3d.Zero;
			order1 = Vector3d.Zero;
			order2 = Matrix3d.Zero;
			r = 0.0;
			double num = 0.0;
			foreach (int point in points)
			{
				num += pointAreas[point];
				p += pointAreas[point] * pointSet.GetVertex(point);
			}
			p /= num;
			foreach (int point2 in points)
			{
				Vector3d vertex = pointSet.GetVertex(point2);
				Vector3d v = pointSet.GetVertexNormal(point2);
				double num2 = pointAreas[point2];
				order1 += num2 * v;
				Vector3d u = vertex - p;
				order2 += num2 * new Matrix3d(ref u, ref v);
				r = Math.Max(r, vertex.Distance(p));
			}
		}

		public static double EvaluateOrder1Approx(ref Vector3d center, ref Vector3d order1Coeff, ref Vector3d q)
		{
			Vector3d vector3d = center - q;
			double length = vector3d.Length;
			return 1.0 / (4.0 * Math.PI) * order1Coeff.Dot(vector3d / (length * length * length));
		}

		public static double EvaluateOrder2Approx(ref Vector3d center, ref Vector3d order1Coeff, ref Matrix3d order2Coeff, ref Vector3d q)
		{
			Vector3d v = center - q;
			double length = v.Length;
			double num = length * length * length;
			double num2 = 1.0 / (Math.PI * 4.0 * num);
			double num3 = num2 * order1Coeff.Dot(ref v);
			double num4 = -3.0 / (Math.PI * 4.0 * num * length * length);
			Matrix3d m = new Matrix3d(num2 + num4 * v.x * v.x, num4 * v.x * v.y, num4 * v.x * v.z, num4 * v.y * v.x, num2 + num4 * v.y * v.y, num4 * v.y * v.z, num4 * v.z * v.x, num4 * v.z * v.y, num2 + num4 * v.z * v.z);
			double num5 = order2Coeff.InnerProduct(ref m);
			return num3 + num5;
		}

		public static double ExactEval(ref Vector3d x, ref Vector3d xn, double xA, ref Vector3d q)
		{
			Vector3d vector3d = x - q;
			double length = vector3d.Length;
			return xA / (Math.PI * 4.0) * xn.Dot(vector3d / (length * length * length));
		}

		public static double Order1Approx(ref Vector3d x, ref Vector3d p, ref Vector3d xn, double xA, ref Vector3d q)
		{
			Vector3d vector3d = p - q;
			double length = vector3d.Length;
			return xA / (Math.PI * 4.0) * xn.Dot(vector3d / (length * length * length));
		}

		public static double Order2Approx(ref Vector3d x, ref Vector3d p, ref Vector3d xn, double xA, ref Vector3d q)
		{
			Vector3d u = p - q;
			Vector3d u2 = x - p;
			double length = u.Length;
			double num = length * length * length;
			double num2 = xA / (Math.PI * 4.0) * xn.Dot(u / num);
			Matrix3d matrix3d = new Matrix3d(ref u, ref u);
			matrix3d *= 3.0 / (Math.PI * 4.0 * num * length * length);
			double num3 = 1.0 / (Math.PI * 4.0 * num);
			Matrix3d m = new Matrix3d(num3, num3, num3) - matrix3d;
			double num4 = xA * new Matrix3d(ref u2, ref xn).InnerProduct(ref m);
			return num2 + num4;
		}
	}
	public struct Frame3f
	{
		private Quaternionf rotation;

		private Vector3f origin;

		public static readonly Frame3f Identity;

		public Quaternionf Rotation
		{
			get
			{
				return rotation;
			}
			set
			{
				rotation = value;
			}
		}

		public Vector3f Origin
		{
			get
			{
				return origin;
			}
			set
			{
				origin = value;
			}
		}

		public Vector3f X => rotation.AxisX;

		public Vector3f Y => rotation.AxisY;

		public Vector3f Z => rotation.AxisZ;

		public Frame3f(Frame3f copy)
		{
			rotation = copy.rotation;
			origin = copy.origin;
		}

		public Frame3f(Vector3f origin)
		{
			rotation = Quaternionf.Identity;
			this.origin = origin;
		}

		public Frame3f(Vector3d origin)
		{
			rotation = Quaternionf.Identity;
			this.origin = (Vector3f)origin;
		}

		public Frame3f(Vector3f origin, Vector3f setZ)
		{
			rotation = Quaternionf.FromTo(Vector3f.AxisZ, setZ);
			this.origin = origin;
		}

		public Frame3f(Vector3d origin, Vector3d setZ)
		{
			rotation = Quaternionf.FromTo(Vector3f.AxisZ, (Vector3f)setZ);
			this.origin = (Vector3f)origin;
		}

		public Frame3f(Vector3f origin, Vector3f setAxis, int nAxis)
		{
			switch (nAxis)
			{
			case 0:
				rotation = Quaternionf.FromTo(Vector3f.AxisX, setAxis);
				break;
			case 1:
				rotation = Quaternionf.FromTo(Vector3f.AxisY, setAxis);
				break;
			default:
				rotation = Quaternionf.FromTo(Vector3f.AxisZ, setAxis);
				break;
			}
			this.origin = origin;
		}

		public Frame3f(Vector3f origin, Quaternionf orientation)
		{
			rotation = orientation;
			this.origin = origin;
		}

		public Frame3f(Vector3f origin, Vector3f x, Vector3f y, Vector3f z)
		{
			this.origin = origin;
			rotation = new Matrix3f(x, y, z, bRows: false).ToQuaternion();
		}

		public Vector3f GetAxis(int nAxis)
		{
			return nAxis switch
			{
				0 => rotation * Vector3f.AxisX, 
				1 => rotation * Vector3f.AxisY, 
				2 => rotation * Vector3f.AxisZ, 
				_ => throw new ArgumentOutOfRangeException("nAxis"), 
			};
		}

		public void Translate(Vector3f v)
		{
			origin += v;
		}

		public Frame3f Translated(Vector3f v)
		{
			return new Frame3f(origin + v, rotation);
		}

		public Frame3f Translated(float fDistance, int nAxis)
		{
			return new Frame3f(origin + fDistance * GetAxis(nAxis), rotation);
		}

		public void Scale(float f)
		{
			origin *= f;
		}

		public void Scale(Vector3f scale)
		{
			origin *= scale;
		}

		public Frame3f Scaled(float f)
		{
			return new Frame3f(f * origin, rotation);
		}

		public Frame3f Scaled(Vector3f scale)
		{
			return new Frame3f(scale * origin, rotation);
		}

		public void Rotate(Quaternionf q)
		{
			rotation = q * rotation;
		}

		public Frame3f Rotated(Quaternionf q)
		{
			return new Frame3f(origin, q * rotation);
		}

		public Frame3f Rotated(float fAngle, int nAxis)
		{
			return Rotated(new Quaternionf(GetAxis(nAxis), fAngle));
		}

		public void RotateAroundAxes(Quaternionf q)
		{
			rotation *= q;
		}

		public void RotateAround(Vector3f point, Quaternionf q)
		{
			Vector3f vector3f = q * (origin - point);
			rotation = q * rotation;
			origin = point + vector3f;
		}

		public Frame3f RotatedAround(Vector3f point, Quaternionf q)
		{
			Vector3f vector3f = q * (origin - point);
			return new Frame3f(point + vector3f, q * rotation);
		}

		public void AlignAxis(int nAxis, Vector3f vTo)
		{
			Quaternionf q = Quaternionf.FromTo(GetAxis(nAxis), vTo);
			Rotate(q);
		}

		public void ConstrainedAlignAxis(int nAxis, Vector3f vTo, Vector3f vAround)
		{
			float angleDeg = MathUtil.PlaneAngleSignedD(GetAxis(nAxis), vTo, vAround);
			Quaternionf q = Quaternionf.AxisAngleD(vAround, angleDeg);
			Rotate(q);
		}

		public Vector3f ProjectToPlane(Vector3f p, int nNormal)
		{
			Vector3f vector3f = p - origin;
			Vector3f axis = GetAxis(nNormal);
			return origin + (vector3f - vector3f.Dot(axis) * axis);
		}

		public Vector3f FromPlaneUV(Vector2f v, int nPlaneNormalAxis)
		{
			Vector3f vector3f = new Vector3f(v[0], v[1], 0f);
			switch (nPlaneNormalAxis)
			{
			case 0:
				vector3f[0] = 0f;
				vector3f[2] = v[0];
				break;
			case 1:
				vector3f[1] = 0f;
				vector3f[2] = v[1];
				break;
			}
			return rotation * vector3f + origin;
		}

		[Obsolete("replaced with FromPlaneUV")]
		public Vector3f FromFrameP(Vector2f v, int nPlaneNormalAxis)
		{
			return FromPlaneUV(v, nPlaneNormalAxis);
		}

		public Vector2f ToPlaneUV(Vector3f p, int nNormal)
		{
			int nAxis = 0;
			int nAxis2 = 1;
			switch (nNormal)
			{
			case 0:
				nAxis = 2;
				break;
			case 1:
				nAxis2 = 2;
				break;
			}
			Vector3f vector3f = p - origin;
			float x = vector3f.Dot(GetAxis(nAxis));
			float y = vector3f.Dot(GetAxis(nAxis2));
			return new Vector2f(x, y);
		}

		[Obsolete("Use explicit ToPlaneUV instead")]
		public Vector2f ToPlaneUV(Vector3f p, int nNormal, int nAxis0 = -1, int nAxis1 = -1)
		{
			if (nAxis0 != -1 || nAxis1 != -1)
			{
				throw new Exception("[RMS] was this being used?");
			}
			return ToPlaneUV(p, nNormal);
		}

		public float DistanceToPlane(Vector3f p, int nNormal)
		{
			return Math.Abs((p - origin).Dot(GetAxis(nNormal)));
		}

		public float DistanceToPlaneSigned(Vector3f p, int nNormal)
		{
