		public Vector3f ToFrameP(Vector3f v)
		{
			v.x -= origin.x;
			v.y -= origin.y;
			v.z -= origin.z;
			return rotation.InverseMultiply(ref v);
		}

		public Vector3f ToFrameP(ref Vector3f v)
		{
			Vector3f v2 = new Vector3f(v.x - origin.x, v.y - origin.y, v.z - origin.z);
