			new Vector3i(1, -1, 0),
			new Vector3i(-1, -1, 0),
			new Vector3i(0, -1, 1),
			new Vector3i(0, -1, -1),
			new Vector3i(1, 1, 1),
			new Vector3i(-1, 1, 1),
			new Vector3i(1, 1, -1),
			new Vector3i(-1, 1, -1),
			new Vector3i(1, -1, 1),
			new Vector3i(-1, -1, 1),
			new Vector3i(1, -1, -1),
			new Vector3i(-1, -1, -1)
		};

		public static IEnumerable<Vector3i> Grid3Indices(int nx, int ny, int nz)
		{
			int z = 0;
			while (z < nz)
			{
				int num;
				for (int y = 0; y < ny; y = num)
				{
					for (int x = 0; x < nx; x = num)
					{
						yield return new Vector3i(x, y, z);
						num = x + 1;
					}
					num = y + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public static IEnumerable<Vector3i> Grid3IndicesYZ(int ny, int nz)
		{
			int z = 0;
			while (z < nz)
			{
				int num;
				for (int y = 0; y < ny; y = num)
				{
					yield return new Vector3i(0, y, z);
					num = y + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public static IEnumerable<Vector3i> Grid3IndicesXZ(int nx, int nz)
		{
			int z = 0;
			while (z < nz)
			{
				int num;
				for (int x = 0; x < nx; x = num)
				{
					yield return new Vector3i(x, 0, z);
					num = x + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public static IEnumerable<Vector3i> Grid3IndicesXY(int nx, int ny)
		{
			int y = 0;
			while (y < ny)
			{
				int num;
				for (int x = 0; x < nx; x = num)
				{
					yield return new Vector3i(x, y, 0);
					num = x + 1;
				}
				num = y + 1;
				y = num;
			}
		}
	}
	public static class Integrate1d
	{
		private static readonly double[] root = new double[5] { -0.9061798459, -0.5384693101, 0.0, 0.5384693101, 0.9061798459 };

		private static readonly double[] coeff = new double[5] { 0.236926885, 0.4786286705, 0.5688888889, 0.4786286705, 0.236926885 };

		public static double RombergIntegral(int order, double a, double b, Func<double, object, double> function, object userData)
		{
			if (order <= 0)
			{
				throw new Exception("Integrate1d.RombergIntegral: Integration order must be positive\n");
			}
			double[,] array = new double[2, order];
			double num = b - a;
			array[0, 0] = 0.5 * num * (function(a, userData) + function(b, userData));
			int num2 = 2;
			int num3 = 1;
			while (num2 <= order)
			{
				double num4 = 0.0;
				for (int i = 1; i <= num3; i++)
				{
					num4 += function(a + num * ((double)i - 0.5), userData);
				}
				array[1, 0] = 0.5 * (array[0, 0] + num * num4);
				int num5 = 1;
				int num6 = 4;
				while (num5 < num2)
				{
					array[1, num5] = ((double)num6 * array[1, num5 - 1] - array[0, num5 - 1]) / (double)(num6 - 1);
					num5++;
					num6 *= 4;
				}
				for (int i = 0; i < num2; i++)
				{
					array[0, i] = array[1, i];
				}
				num2++;
				num3 *= 2;
				num *= 0.5;
			}
			return array[0, order - 1];
		}

		public static double GaussianQuadrature(double a, double b, Func<double, object, double> function, object userData)
		{
			double num = 0.5 * (b - a);
			double num2 = 0.5 * (b + a);
			double num3 = 0.0;
			for (int i = 0; i < 5; i++)
			{
				num3 += coeff[i] * function(num * root[i] + num2, userData);
			}
			return num3 * num;
		}

		public static double TrapezoidRule(int numSamples, double a, double b, Func<double, object, double> function, object userData)
		{
			if (numSamples < 2)
			{
				throw new Exception("Integrate1d.TrapezoidRule: Must have more than two samples\n");
			}
			double num = (b - a) / (double)(numSamples - 1);
			double num2 = 0.5 * (function(a, userData) + function(b, userData));
			for (int i = 1; i <= numSamples - 2; i++)
			{
				num2 += function(a + (double)i * num, userData);
			}
			return num2 * num;
		}
	}
	public struct Interval1d
	{
		public double a;

		public double b;

		public static readonly Interval1d Zero;

		public static readonly Interval1d Empty;

		public static readonly Interval1d Infinite;

		public double this[int key]
		{
			get
			{
				if (key != 0)
				{
					return b;
				}
				return a;
			}
			set
			{
				if (key == 0)
				{
					a = value;
				}
				else
				{
					b = value;
				}
			}
		}

		public double LengthSquared => (a - b) * (a - b);

		public double Length => b - a;

		public bool IsConstant => b == a;

		public double Center => (b + a) * 0.5;

		public Interval1d(double f)
		{
			a = (b = f);
		}

		public Interval1d(double x, double y)
		{
			a = x;
			b = y;
		}

		public Interval1d(double[] v2)
		{
			a = v2[0];
			b = v2[1];
		}

		public Interval1d(float f)
		{
			a = (b = f);
		}

		public Interval1d(float x, float y)
		{
			a = x;
			b = y;
		}

		public Interval1d(float[] v2)
		{
			a = v2[0];
			b = v2[1];
		}

		public Interval1d(Interval1d copy)
		{
			a = copy.a;
			b = copy.b;
		}

		public static Interval1d Unsorted(double x, double y)
		{
			if (!(x < y))
			{
				return new Interval1d(y, x);
			}
			return new Interval1d(x, y);
		}

		public void Contain(double d)
		{
			if (d < a)
			{
				a = d;
			}
			if (d > b)
			{
				b = d;
			}
		}

		public bool Contains(double d)
		{
			if (d >= a)
			{
				return d <= b;
			}
			return false;
		}

		public bool Overlaps(Interval1d o)
		{
			if (!(o.a > b))
			{
				return !(o.b < a);
			}
			return false;
		}

		public double SquaredDist(Interval1d o)
		{
			if (b < o.a)
			{
				return (o.a - b) * (o.a - b);
			}
			if (a > o.b)
			{
				return (a - o.b) * (a - o.b);
			}
			return 0.0;
		}

		public double Dist(Interval1d o)
		{
			if (b < o.a)
			{
				return o.a - b;
			}
			if (a > o.b)
			{
				return a - o.b;
			}
			return 0.0;
		}

		public Interval1d IntersectionWith(ref Interval1d o)
		{
			if (o.a > b || o.b < a)
			{
				return Empty;
			}
			return new Interval1d(Math.Max(a, o.a), Math.Min(b, o.b));
		}

		public double Clamp(double f)
		{
			if (!(f < a))
			{
				if (!(f > b))
				{
					return f;
				}
				return b;
			}
			return a;
		}

		public double Interpolate(double t)
		{
			return (1.0 - t) * a + t * b;
		}

		public double GetT(double value)
		{
			if (value <= a)
			{
				return 0.0;
			}
			if (value >= b)
			{
				return 1.0;
			}
			if (a == b)
			{
				return 0.5;
			}
			return (value - a) / (b - a);
		}

		public void Set(Interval1d o)
		{
			a = o.a;
			b = o.b;
		}

		public void Set(double fA, double fB)
		{
			a = fA;
			b = fB;
		}

		public static Interval1d operator -(Interval1d v)
		{
			return new Interval1d(0.0 - v.a, 0.0 - v.b);
		}

		public static Interval1d operator +(Interval1d a, double f)
		{
			return new Interval1d(a.a + f, a.b + f);
		}

		public static Interval1d operator -(Interval1d a, double f)
		{
			return new Interval1d(a.a - f, a.b - f);
		}

		public static Interval1d operator *(Interval1d a, double f)
		{
			return new Interval1d(a.a * f, a.b * f);
		}

		public override string ToString()
		{
			return $"[{a:F8},{b:F8}]";
		}

		static Interval1d()
		{
			Zero = new Interval1d(0f, 0f);
			Empty = new Interval1d(double.MaxValue, double.MinValue);
			Infinite = new Interval1d(double.MinValue, double.MaxValue);
		}
	}
