		public static double ClampAngleDeg(double theta, double min, double max)
		{
			double num = (min + max) * 0.5;
			double num2 = max - num;
			theta %= 360.0;
			theta -= num;
			if (theta < -180.0)
			{
				theta += 360.0;
			}
			else if (theta > 180.0)
			{
				theta -= 360.0;
			}
			if (theta < 0.0 - num2)
			{
				theta = 0.0 - num2;
			}
			else if (theta > num2)
			{
				theta = num2;
			}
			return theta + num;
		}

		public static double ClampAngleRad(double theta, double min, double max)
		{
			double num = (min + max) * 0.5;
			double num2 = max - num;
			theta %= Math.PI * 2.0;
			theta -= num;
			if (theta < -Math.PI)
			{
				theta += Math.PI * 2.0;
			}
			else if (theta > Math.PI)
			{
				theta -= Math.PI * 2.0;
			}
			if (theta < 0.0 - num2)
			{
				theta = 0.0 - num2;
			}
			else if (theta > num2)
			{
				theta = num2;
			}
			return theta + num;
		}

