		public static void MinMax(double a, double b, double c, out double min, out double max)
		{
			if (a < b)
			{
				if (a < c)
				{
					min = a;
					max = Math.Max(b, c);
				}
				else
				{
					min = c;
					max = b;
				}
			}
			else if (a > c)
			{
				max = a;
				min = Math.Min(b, c);
			}
			else
			{
				min = b;
				max = c;
			}
		}

