			vFrom.Normalize();
			vTo.Normalize();
			Vector3f v = Vector3f.Cross(vFrom, vTo);
			if (v.LengthSquared < 1E-06f)
			{
				if (!(vFrom.Dot(vTo) < 0f))
				{
					return 0f;
				}
				return 180f;
			}
			return (float)Math.Sign(Vector3f.Dot(v, planeN)) * Vector3f.AngleD(vFrom, vTo);
		}

