			double num2 = Math.Abs(f.Y.Dot(vDir));
			double val = Math.Abs(f.Z.Dot(vDir));
			double num3 = Math.Max(num, Math.Max(num2, val));
			if (num3 != num)
			{
				if (num3 != num2)
				{
					return 2;
				}
				return 1;
			}
