		public static float WyvillRise01(float fX)
		{
			float num = Clamp(1f - fX * fX, 0f, 1f);
			return 1f - num * num * num;
		}

		public static double WyvillRise01(double fX)
		{
			double num = Clamp(1.0 - fX * fX, 0.0, 1.0);
			return 1.0 - num * num * num;
