		public static IEnumerable<int> ModuloIteration(int nMaxExclusive, int nPrime = 31337)
		{
			int i = 0;
			bool flag = false;
			while (!flag)
			{
				yield return i;
				i = (i + nPrime) % nMaxExclusive;
				flag = i == 0;
			}
		}
