			m00 *= num;
			m10 *= num;
			double num2 = m00 * m01 + m10 * m11;
			m01 -= num2 * m00;
			m11 -= num2 * m10;
			num = 1.0 / Math.Sqrt(m01 * m01 + m11 * m11);
