				rot.m11 = 1.0;
				diag.m00 = m00;
				diag.m01 = 0.0;
				diag.m10 = 0.0;
				diag.m11 = m11;
				return;
			}
			double num2 = m00 + m11;
			double num3 = m00 - m11;
			double num4 = Math.Sqrt(num3 * num3 + 4.0 * m01 * m01);
			double num5 = 0.5 * (num2 - num4);
			double num6 = 0.5 * (num2 + num4);
			diag.SetToDiagonal(num5, num6);
			double num7;
			double num8;
