				num8 = num5 - m00;
			}
			else
			{
				num7 = num5 - m11;
				num8 = m01;
			}
			double num9 = 1.0 / Math.Sqrt(num7 * num7 + num8 * num8);
			num7 *= num9;
			num8 *= num9;
			rot.m00 = num7;
			rot.m01 = 0.0 - num8;
			rot.m10 = num8;
			rot.m11 = num7;
