	public struct Matrix3d
	{
		public Vector3d Row0;

		public Vector3d Row1;

		public Vector3d Row2;

		public static readonly Matrix3d Identity = new Matrix3d(bIdentity: true);

		public static readonly Matrix3d Zero = new Matrix3d(bIdentity: false);

		public double this[int r, int c]
		{
			get
			{
				return r switch
				{
					1 => Row1[c], 
					0 => Row0[c], 
					_ => Row2[c], 
				};
			}
			set
			{
				switch (r)
				{
				case 0:
					Row0[c] = value;
					break;
				case 1:
					Row1[c] = value;
					break;
				default:
					Row2[c] = value;
					break;
				}
			}
		}

		public double this[int i]
		{
			get
			{
				if (i <= 5)
				{
					if (i <= 2)
					{
						return Row0[i % 3];
					}
					return Row1[i % 3];
				}
				return Row2[i % 3];
			}
			set
			{
				if (i > 5)
				{
					Row2[i % 3] = value;
				}
				else if (i > 2)
				{
					Row1[i % 3] = value;
				}
				else
				{
					Row0[i % 3] = value;
				}
			}
		}

		public double Determinant
		{
			get
			{
				double x = Row0.x;
				double y = Row0.y;
				double z = Row0.z;
				double x2 = Row1.x;
				double y2 = Row1.y;
				double z2 = Row1.z;
				double x3 = Row2.x;
				double y3 = Row2.y;
				double z3 = Row2.z;
				double num = z3 * y2 - y3 * z2;
				double num2 = 0.0 - (z3 * y - y3 * z);
				double num3 = z2 * y - y2 * z;
				return x * num + x2 * num2 + x3 * num3;
			}
		}

