			{
				return r switch
				{
					1 => Row1[c], 
					0 => Row0[c], 
					_ => Row2[c], 
				};
			}
			set
			{
				switch (r)
				{
				case 0:
					Row0[c] = value;
					break;
				case 1:
					Row1[c] = value;
					break;
				default:
					Row2[c] = value;
					break;
				}
			}
		}

		public float this[int i]
		{
			get
			{
				if (i <= 5)
				{
					if (i <= 2)
					{
						return Row0[i % 3];
					}
					return Row1[i % 3];
				}
				return Row2[i % 3];
			}
			set
			{
				if (i > 5)
				{
					Row2[i % 3] = value;
				}
				else if (i > 2)
				{
					Row1[i % 3] = value;
				}
				else
				{
					Row0[i % 3] = value;
				}
			}
		}

