		}

		public static void SetIdentity3x3(double[] M, double a, double b, double c)
		{
			Array.Clear(M, 0, 9);
			M[0] = (M[4] = (M[8] = 1.0));
		}

		public static double[] MakeDiagonal3x3(double a, double b, double c)
		{
			return new double[9] { a, 0.0, 0.0, 0.0, b, 0.0, 0.0, 0.0, c };
