		public static void SetDiagonal3x3(double[] M, double a, double b, double c)
		{
			Array.Clear(M, 0, 9);
			M[0] = a;
			M[4] = b;
			M[8] = c;
		}

		public static double Determinant3x3(double[] M)
		{
			double num = M[4] * M[8] - M[5] * M[7];
			double num2 = M[5] * M[6] - M[3] * M[8];
			double num3 = M[3] * M[7] - M[4] * M[6];
			return M[0] * num + M[1] * num2 + M[2] * num3;
		}

		public static void Transpose3x3(double[] M)
		{
			double num = M[1];
			M[1] = M[3];
			M[3] = num;
			num = M[2];
			M[2] = M[6];
			M[6] = num;
			num = M[5];
			M[5] = M[7];
			M[7] = num;
		}

		public static void Transpose3x3(double[] M, double[] MTranspose)
		{
			MTranspose[0] = M[0];
			MTranspose[1] = M[3];
			MTranspose[2] = M[6];
			MTranspose[3] = M[1];
			MTranspose[4] = M[4];
			MTranspose[5] = M[7];
			MTranspose[6] = M[2];
			MTranspose[7] = M[5];
		}

		public static void Multiply3x3(double[] A, double[] B, double[] C)
		{
			C[0] = A[0] * B[0] + A[1] * B[3] + A[2] * B[6];
			C[1] = A[0] * B[1] + A[1] * B[4] + A[2] * B[7];
			C[2] = A[0] * B[2] + A[1] * B[5] + A[2] * B[8];
			C[3] = A[3] * B[0] + A[4] * B[3] + A[5] * B[6];
			C[4] = A[3] * B[1] + A[4] * B[4] + A[5] * B[7];
			C[5] = A[3] * B[2] + A[4] * B[5] + A[5] * B[8];
			C[6] = A[6] * B[0] + A[7] * B[3] + A[8] * B[6];
			C[7] = A[6] * B[1] + A[7] * B[4] + A[8] * B[7];
			C[8] = A[6] * B[2] + A[7] * B[5] + A[8] * B[8];
		}

		public static Vector3d Multiply3x3(double[] M, Vector3d vec)
		{
			return new Vector3d(M[0] * vec.x + M[1] * vec.y + M[2] * vec.z, M[3] * vec.x + M[4] * vec.y + M[5] * vec.z, M[6] * vec.x + M[7] * vec.y + M[8] * vec.z);
		}
	}
	public struct Plane3d
	{
		public Vector3d Normal;

		public double Constant;

		public Plane3d(Vector3d normal, double constant)
		{
			Normal = normal;
			Constant = constant;
		}

		public Plane3d(Vector3d normal, Vector3d point)
		{
			Normal = normal;
			Constant = Normal.Dot(point);
		}

		public Plane3d(Vector3d p0, Vector3d p1, Vector3d p2)
		{
			Vector3d vector3d = p1 - p0;
			Vector3d v = p2 - p0;
			Normal = vector3d.UnitCross(v);
			Constant = Normal.Dot(p0);
		}

		public double DistanceTo(Vector3d p)
		{
			return Normal.Dot(p) - Constant;
		}

		public int WhichSide(Vector3d p)
		{
			double num = DistanceTo(p);
			if (num < 0.0)
			{
				return -1;
			}
			if (num > 0.0)
			{
				return 1;
			}
			return 0;
		}
	}
	public struct Plane3f
	{
		public Vector3f Normal;

		public float Constant;

		public Plane3f(Vector3f normal, float constant)
		{
			Normal = normal;
			Constant = constant;
		}

		public Plane3f(Vector3f normal, Vector3f point)
		{
			Normal = normal;
			Constant = Normal.Dot(point);
		}

		public Plane3f(Vector3f p0, Vector3f p1, Vector3f p2)
		{
			Vector3f vector3f = p1 - p0;
			Vector3f v = p2 - p0;
			Normal = vector3f.UnitCross(v);
			Constant = Normal.Dot(p0);
		}

		public float DistanceTo(Vector3f p)
		{
			return Normal.Dot(p) - Constant;
		}

		public int WhichSide(Vector3f p)
		{
			float num = DistanceTo(p);
			if (num < 0f)
			{
				return -1;
			}
			if (num > 0f)
			{
				return 1;
			}
			return 0;
		}
	}
	internal class PrimalQuery2d
	{
		public enum OrderType
		{
			ORDER_Q0_EQUALS_Q1,
			ORDER_P_EQUALS_Q0,
			ORDER_P_EQUALS_Q1,
			ORDER_POSITIVE,
			ORDER_NEGATIVE,
			ORDER_COLLINEAR_LEFT,
			ORDER_COLLINEAR_RIGHT,
			ORDER_COLLINEAR_CONTAIN
		}

		private Func<int, Vector2d> PointF;

		public PrimalQuery2d(Func<int, Vector2d> PositionFunc)
		{
			PointF = PositionFunc;
		}

		public int ToLine(int i, int v0, int v1)
		{
			return ToLine(PointF(i), v0, v1);
		}

		public int ToLine(Vector2d test, int v0, int v1)
		{
			Vector2d vector2d = PointF(v0);
			Vector2d vector2d2 = PointF(v1);
			double num = test[0] - vector2d[0];
			double num2 = test[1] - vector2d[1];
			double num3 = vector2d2[0] - vector2d[0];
			double num4 = vector2d2[1] - vector2d[1];
			double num5 = num * num4;
			double num6 = num3 * num2;
			double num7 = num5 - num6;
			if (!(num7 > 0.0))
			{
				if (!(num7 < 0.0))
				{
					return 0;
				}
				return -1;
			}
			return 1;
		}

		public int ToLine(int i, int v0, int v1, out int order)
		{
			return ToLine(PointF(i), v0, v1, out order);
		}

		public int ToLine(Vector2d test, int v0, int v1, out int order)
		{
			Vector2d vector2d = PointF(v0);
			Vector2d vector2d2 = PointF(v1);
			double num = test[0] - vector2d[0];
			double num2 = test[1] - vector2d[1];
			double num3 = vector2d2[0] - vector2d[0];
			double num4 = vector2d2[1] - vector2d[1];
			double num5 = num * num4;
			double num6 = num3 * num2;
			double num7 = num5 - num6;
			if (num7 > 0.0)
			{
				order = 3;
				return 1;
			}
			if (num7 < 0.0)
			{
				order = -3;
				return -1;
			}
			double num8 = num * num3;
			double num9 = num2 * num4;
			double num10 = num8 + num9;
			if (num10 == 0.0)
			{
				order = -1;
			}
			else if (num10 < 0.0)
			{
				order = -2;
			}
			else
			{
				double num11 = num * num;
				double num12 = num2 * num2;
				double num13 = num11 + num12;
				if (num10 == num13)
				{
					order = 1;
				}
				else if (num10 > num13)
				{
					order = 2;
				}
				else
				{
					order = 0;
				}
			}
			return 0;
		}

		public int ToTriangle(int i, int v0, int v1, int v2)
		{
			return ToTriangle(PointF(i), v0, v1, v2);
		}

		public int ToTriangle(Vector2d test, int v0, int v1, int v2)
		{
			int num = ToLine(test, v1, v2);
			if (num > 0)
			{
				return 1;
			}
			int num2 = ToLine(test, v0, v2);
			if (num2 < 0)
			{
				return 1;
			}
			int num3 = ToLine(test, v0, v1);
			if (num3 > 0)
			{
				return 1;
			}
			if (num == 0 || num2 == 0 || num3 == 0)
			{
				return 0;
			}
			return -1;
		}

		public int ToTriangleUnsigned(int i, int v0, int v1, int v2)
		{
			return ToTriangleUnsigned(PointF(i), v0, v1, v2);
		}

		public int ToTriangleUnsigned(Vector2d test, int v0, int v1, int v2)
		{
			int num = ToLine(test, v1, v2);
			int num2 = ToLine(test, v0, v2);
			int num3 = ToLine(test, v0, v1);
			if ((num <= 0 && num2 >= 0 && num3 <= 0) || (num >= 0 && num2 <= 0 && num3 >= 0))
			{
				if (num == 0 || num2 == 0 || num3 == 0)
				{
					return 0;
				}
				return -1;
			}
			return 1;
		}

		public int ToCircumcircle(int i, int v0, int v1, int v2)
		{
			return ToCircumcircle(PointF(i), v0, v1, v2);
		}

		public int ToCircumcircle(Vector2d test, int v0, int v1, int v2)
		{
			Vector2d vector2d = PointF(v0);
			Vector2d vector2d2 = PointF(v1);
			Vector2d vector2d3 = PointF(v2);
			double num = vector2d[0] - test[0];
			double num2 = vector2d[1] - test[1];
			double num3 = vector2d[0] + test[0];
			double num4 = vector2d[1] + test[1];
			double num5 = num3 * num;
			double num6 = num4 * num2;
			double num7 = num5 + num6;
			double num8 = vector2d2[0] - test[0];
			double num9 = vector2d2[1] - test[1];
			double num10 = vector2d2[0] + test[0];
			double num11 = vector2d2[1] + test[1];
			double num12 = num10 * num8;
			double num13 = num11 * num9;
			double num14 = num12 + num13;
			double num15 = vector2d3[0] - test[0];
			double num16 = vector2d3[1] - test[1];
			double num17 = vector2d3[0] + test[0];
			double num18 = vector2d3[1] + test[1];
			double num19 = num17 * num15;
			double num20 = num18 * num16;
			double num21 = num19 + num20;
			double num22 = num2 * num14;
			double num23 = num2 * num21;
			double num24 = num9 * num7;
			double num25 = num9 * num21;
			double num26 = num16 * num7;
			double num27 = num16 * num14;
			double num28 = num25 - num27;
			double num29 = num26 - num23;
			double num30 = num22 - num24;
			double num31 = num * num28;
			double num32 = num8 * num29;
			double num33 = num15 * num30;
			double num34 = num31 + num32 + num33;
			if (!(num34 < 0.0))
			{
				if (!(num34 > 0.0))
				{
					return 0;
				}
				return -1;
			}
			return 1;
		}

		public OrderType ToLineExtended(Vector2d P, Vector2d Q0, Vector2d Q1)
		{
			double num = Q1[0] - Q0[0];
			double num2 = Q1[1] - Q0[1];
			if (num == 0.0 && num2 == 0.0)
			{
				return OrderType.ORDER_Q0_EQUALS_Q1;
			}
			double num3 = P[0] - Q0[0];
			double num4 = P[1] - Q0[1];
			if (num3 == 0.0 && num4 == 0.0)
			{
				return OrderType.ORDER_P_EQUALS_Q0;
			}
			double num5 = P[0] - Q1[0];
			double num6 = P[1] - Q1[1];
			if (num5 == 0.0 && num6 == 0.0)
			{
				return OrderType.ORDER_P_EQUALS_Q1;
			}
			double num7 = num * num4;
			double num8 = num3 * num2;
			double num9 = num7 - num8;
			if (num9 != 0.0)
			{
				if (num9 > 0.0)
				{
					return OrderType.ORDER_POSITIVE;
				}
				return OrderType.ORDER_NEGATIVE;
			}
			double num10 = num * num3;
			double num11 = num2 * num4;
			double num12 = num10 + num11;
			if (num12 < 0.0)
			{
				return OrderType.ORDER_COLLINEAR_LEFT;
			}
			double num13 = num * num;
			double num14 = num2 * num2;
			double num15 = num13 + num14;
			if (num12 > num15)
			{
				return OrderType.ORDER_COLLINEAR_RIGHT;
			}
			return OrderType.ORDER_COLLINEAR_CONTAIN;
		}
	}
	public struct Quaterniond
	{
		public double x;

		public double y;

		public double z;

		public double w;

		public static readonly Quaterniond Zero;

		public static readonly Quaterniond Identity;

		public double this[int key]
		{
			get
			{
				return key switch
				{
					0 => x, 
					1 => y, 
					2 => z, 
					_ => w, 
				};
			}
			set
			{
				switch (key)
				{
				case 0:
					x = value;
					break;
				case 1:
					y = value;
					break;
				case 2:
					z = value;
					break;
				default:
					w = value;
					break;
				}
			}
		}

		public double LengthSquared => x * x + y * y + z * z + w * w;

		public double Length => Math.Sqrt(x * x + y * y + z * z + w * w);

		public Quaterniond Normalized
		{
			get
			{
				Quaterniond result = new Quaterniond(this);
				result.Normalize();
				return result;
			}
		}

		public Vector3d AxisX
		{
			get
			{
				double num = 2.0 * y;
				double num2 = 2.0 * z;
				double num3 = num * w;
				double num4 = num2 * w;
				double num5 = num * x;
				double num6 = num2 * x;
				double num7 = num * y;
				double num8 = num2 * z;
				return new Vector3d(1.0 - (num7 + num8), num5 + num4, num6 - num3);
			}
		}

		public Vector3d AxisY
		{
			get
			{
				double num = 2.0 * x;
				double num2 = 2.0 * y;
				double num3 = 2.0 * z;
				double num4 = num * w;
				double num5 = num3 * w;
				double num6 = num * x;
				double num7 = num2 * x;
				double num8 = num3 * y;
				double num9 = num3 * z;
				return new Vector3d(num7 - num5, 1.0 - (num6 + num9), num8 + num4);
			}
		}

		public Vector3d AxisZ
		{
			get
			{
				double num = 2.0 * x;
				double num2 = 2.0 * y;
				double num3 = 2.0 * z;
				double num4 = num * w;
				double num5 = num2 * w;
				double num6 = num * x;
				double num7 = num3 * x;
				double num8 = num2 * y;
				double num9 = num3 * y;
				return new Vector3d(num7 + num5, num9 - num4, 1.0 - (num6 + num8));
			}
		}

		public Quaterniond(double x, double y, double z, double w)
		{
			this.x = x;
			this.y = y;
			this.z = z;
			this.w = w;
		}

		public Quaterniond(double[] v2)
		{
			x = v2[0];
			y = v2[1];
			z = v2[2];
			w = v2[3];
		}

		public Quaterniond(Quaterniond q2)
		{
			x = q2.x;
			y = q2.y;
			z = q2.z;
			w = q2.w;
		}

		public Quaterniond(Vector3d axis, double AngleDeg)
		{
			x = (y = (z = 0.0));
			w = 1.0;
			SetAxisAngleD(axis, AngleDeg);
		}

		public Quaterniond(Vector3d vFrom, Vector3d vTo)
		{
			x = (y = (z = 0.0));
			w = 1.0;
			SetFromTo(vFrom, vTo);
		}

		public Quaterniond(Quaterniond p, Quaterniond q, double t)
		{
			x = (y = (z = 0.0));
			w = 1.0;
			SetToSlerp(p, q, t);
		}

		public Quaterniond(Matrix3d mat)
		{
			x = (y = (z = 0.0));
			w = 1.0;
			SetFromRotationMatrix(mat);
		}

		public double Normalize(double epsilon = 0.0)
		{
			double num = Length;
			if (num > epsilon)
			{
				double num2 = 1.0 / num;
				x *= num2;
				y *= num2;
				z *= num2;
				w *= num2;
			}
			else
			{
				num = 0.0;
				x = (y = (z = (w = 0.0)));
			}
			return num;
		}

		public double Dot(Quaterniond q2)
		{
			return x * q2.x + y * q2.y + z * q2.z + w * q2.w;
		}

		public static Quaterniond operator -(Quaterniond q2)
		{
			return new Quaterniond(0.0 - q2.x, 0.0 - q2.y, 0.0 - q2.z, 0.0 - q2.w);
		}

		public static Quaterniond operator *(Quaterniond a, Quaterniond b)
		{
			double num = a.w * b.w - a.x * b.x - a.y * b.y - a.z * b.z;
			double num2 = a.w * b.x + a.x * b.w + a.y * b.z - a.z * b.y;
			double num3 = a.w * b.y + a.y * b.w + a.z * b.x - a.x * b.z;
			double num4 = a.w * b.z + a.z * b.w + a.x * b.y - a.y * b.x;
			return new Quaterniond(num2, num3, num4, num);
		}

		public static Quaterniond operator *(Quaterniond q1, double d)
		{
			return new Quaterniond(d * q1.x, d * q1.y, d * q1.z, d * q1.w);
		}

		public static Quaterniond operator *(double d, Quaterniond q1)
		{
			return new Quaterniond(d * q1.x, d * q1.y, d * q1.z, d * q1.w);
		}

		public static Quaterniond operator -(Quaterniond q1, Quaterniond q2)
		{
			return new Quaterniond(q1.x - q2.x, q1.y - q2.y, q1.z - q2.z, q1.w - q2.w);
		}

		public static Quaterniond operator +(Quaterniond q1, Quaterniond q2)
		{
			return new Quaterniond(q1.x + q2.x, q1.y + q2.y, q1.z + q2.z, q1.w + q2.w);
		}

		public static Vector3d operator *(Quaterniond q, Vector3d v)
		{
			double num = 2.0 * q.x;
			double num2 = 2.0 * q.y;
			double num3 = 2.0 * q.z;
			double num4 = num * q.w;
			double num5 = num2 * q.w;
			double num6 = num3 * q.w;
			double num7 = num * q.x;
			double num8 = num2 * q.x;
			double num9 = num3 * q.x;
			double num10 = num2 * q.y;
			double num11 = num3 * q.y;
			double num12 = num3 * q.z;
			return new Vector3d(v.x * (1.0 - (num10 + num12)) + v.y * (num8 - num6) + v.z * (num9 + num5), v.x * (num8 + num6) + v.y * (1.0 - (num7 + num12)) + v.z * (num11 - num4), v.x * (num9 - num5) + v.y * (num11 + num4) + v.z * (1.0 - (num7 + num10)));
		}

		public Quaterniond Inverse()
		{
			double lengthSquared = LengthSquared;
			if (lengthSquared > 0.0)
			{
				double num = 1.0 / lengthSquared;
				return new Quaterniond((0.0 - x) * num, (0.0 - y) * num, (0.0 - z) * num, w * num);
			}
			return Zero;
		}

		public static Quaterniond Inverse(Quaterniond q)
		{
			return q.Inverse();
		}

		public Quaterniond Conjugate()
		{
			return new Quaterniond(0.0 - x, 0.0 - y, 0.0 - z, w);
		}

		public Matrix3d ToRotationMatrix()
		{
			double num = 2.0 * x;
			double num2 = 2.0 * y;
			double num3 = 2.0 * z;
			double num4 = num * w;
			double num5 = num2 * w;
			double num6 = num3 * w;
			double num7 = num * x;
			double num8 = num2 * x;
			double num9 = num3 * x;
			double num10 = num2 * y;
			double num11 = num3 * y;
			double num12 = num3 * z;
			return new Matrix3d(1.0 - (num10 + num12), num8 - num6, num9 + num5, num8 + num6, 1.0 - (num7 + num12), num11 - num4, num9 - num5, num11 + num4, 1.0 - (num7 + num10));
		}

		public void SetAxisAngleD(Vector3d axis, double AngleDeg)
		{
			double num = Math.PI / 180.0 * AngleDeg;
			double num2 = 0.5 * num;
			double num3 = Math.Sin(num2);
			w = Math.Cos(num2);
			x = num3 * axis.x;
			y = num3 * axis.y;
			z = num3 * axis.z;
		}

		public static Quaterniond AxisAngleD(Vector3d axis, double angleDeg)
		{
			return new Quaterniond(axis, angleDeg);
		}

		public static Quaterniond AxisAngleR(Vector3d axis, double angleRad)
		{
			return new Quaterniond(axis, angleRad * 57.295780181884766);
		}

		public void SetFromTo(Vector3d vFrom, Vector3d vTo)
		{
			Vector3d normalized = vFrom.Normalized;
			Vector3d normalized2 = vTo.Normalized;
			Vector3d normalized3 = (normalized + normalized2).Normalized;
			w = normalized.Dot(normalized3);
			if (w != 0.0)
			{
				Vector3d vector3d = normalized.Cross(normalized3);
				x = vector3d.x;
				y = vector3d.y;
				z = vector3d.z;
			}
			else if (Math.Abs(normalized.x) >= Math.Abs(normalized.y))
			{
				double num = 1.0 / Math.Sqrt(normalized.x * normalized.x + normalized.z * normalized.z);
				x = (0.0 - normalized.z) * num;
				y = 0.0;
				z = normalized.x * num;
			}
			else
			{
				double num = 1.0 / Math.Sqrt(normalized.y * normalized.y + normalized.z * normalized.z);
				x = 0.0;
				y = normalized.z * num;
				z = (0.0 - normalized.y) * num;
			}
			Normalize();
		}

		public static Quaterniond FromTo(Vector3d vFrom, Vector3d vTo)
		{
			return new Quaterniond(vFrom, vTo);
		}

		public static Quaterniond FromToConstrained(Vector3d vFrom, Vector3d vTo, Vector3d vAround)
		{
			double angleDeg = MathUtil.PlaneAngleSignedD(vFrom, vTo, vAround);
			return AxisAngleD(vAround, angleDeg);
		}

		public void SetToSlerp(Quaterniond p, Quaterniond q, double t)
		{
			double num = Math.Acos(p.Dot(q));
			if (Math.Abs(num) >= 1E-08)
			{
				double num2 = Math.Sin(num);
				double num3 = 1.0 / num2;
				double num4 = t * num;
				double num5 = Math.Sin(num - num4) * num3;
				double num6 = Math.Sin(num4) * num3;
				x = num5 * p.x + num6 * q.x;
				y = num5 * p.y + num6 * q.y;
				z = num5 * p.z + num6 * q.z;
				w = num5 * p.w + num6 * q.w;
			}
			else
			{
				x = p.x;
				y = p.y;
				z = p.z;
				w = p.w;
			}
		}

		public static Quaterniond Slerp(Quaterniond p, Quaterniond q, double t)
		{
			return new Quaterniond(p, q, t);
		}

		public void SetFromRotationMatrix(Matrix3d rot)
		{
			SetFromRotationMatrix(ref rot);
		}

		public void SetFromRotationMatrix(ref Matrix3d rot)
		{
			Index3i index3i = new Index3i(1, 2, 0);
			double num = rot[0, 0] + rot[1, 1] + rot[2, 2];
			if (num > 0.0)
			{
				double num2 = Math.Sqrt(num + 1.0);
				w = 0.5 * num2;
				num2 = 0.5 / num2;
