			Vector3f normalized3 = (normalized + normalized2).Normalized;
			w = normalized.Dot(normalized3);
			if (w != 0f)
			{
				Vector3f vector3f = normalized.Cross(normalized3);
				x = vector3f.x;
				y = vector3f.y;
				z = vector3f.z;
