			else if (Math.Abs(normalized.x) >= Math.Abs(normalized.y))
			{
				float num = (float)(1.0 / Math.Sqrt(normalized.x * normalized.x + normalized.z * normalized.z));
				x = (0f - normalized.z) * num;
				y = 0f;
