				return P0;
			}
			return Center + num * Direction;
		}

		public double Project(Vector3d p)
		{
			return (p - Center).Dot(Direction);
		}

		private void update_from_endpoints(Vector3d p0, Vector3d p1)
		{
			Center = 0.5 * (p0 + p1);
			Direction = p1 - p0;
			Extent = 0.5 * Direction.Normalize();
		}

		public static implicit operator Segment3d(Segment3f v)
		{
			return new Segment3d(v.Center, v.Direction, v.Extent);
		}

		public static explicit operator Segment3f(Segment3d v)
		{
			return new Segment3f((Vector3f)v.Center, (Vector3f)v.Direction, (float)v.Extent);
		}

		public Vector3d SampleT(double t)
		{
			return Center + (2.0 * t - 1.0) * Extent * Direction;
		}

		public Vector3d TangentT(double t)
		{
			return Direction;
		}

		public Vector3d SampleArcLength(double a)
		{
			return P0 + a * Direction;
		}

		public void Reverse()
		{
			update_from_endpoints(P1, P0);
		}

		public IParametricCurve3d Clone()
		{
			return new Segment3d(Center, Direction, Extent);
		}
	}
	public struct Segment3f
	{
		public Vector3f Center;

		public Vector3f Direction;

		public float Extent;

		public Vector3f P0
		{
			get
			{
				return Center - Extent * Direction;
			}
			set
			{
				update_from_endpoints(value, P1);
			}
		}

		public Vector3f P1
		{
			get
			{
				return Center + Extent * Direction;
			}
			set
			{
				update_from_endpoints(P0, value);
			}
		}

		public float Length => 2f * Extent;

		public Segment3f(Vector3f p0, Vector3f p1)
		{
			Center = 0.5f * (p0 + p1);
			Direction = p1 - p0;
			Extent = 0.5f * Direction.Normalize();
		}

		public Segment3f(Vector3f center, Vector3f direction, float extent)
		{
			Center = center;
			Direction = direction;
			Extent = extent;
		}

		public void SetEndpoints(Vector3f p0, Vector3f p1)
		{
			update_from_endpoints(p0, p1);
		}

		public Vector3f PointAt(float d)
		{
			return Center + d * Direction;
		}

		public Vector3f PointBetween(float t)
		{
			return Center + (2f * t - 1f) * Extent * Direction;
		}

		public float DistanceSquared(Vector3f p)
		{
			float num = (p - Center).Dot(Direction);
			if (num >= Extent)
			{
				return P1.DistanceSquared(p);
			}
			if (num <= 0f - Extent)
			{
				return P0.DistanceSquared(p);
			}
			return (Center + num * Direction - p).LengthSquared;
		}

		public Vector3f NearestPoint(Vector3f p)
		{
			float num = (p - Center).Dot(Direction);
			if (num >= Extent)
			{
				return P1;
			}
			if (num <= 0f - Extent)
			{
				return P0;
			}
			return Center + num * Direction;
		}

		public float Project(Vector3f p)
		{
			return (p - Center).Dot(Direction);
		}

		private void update_from_endpoints(Vector3f p0, Vector3f p1)
		{
			Center = 0.5f * (p0 + p1);
			Direction = p1 - p0;
			Extent = 0.5f * Direction.Normalize();
		}
	}
	public class TransformSequence
	{
		private enum XFormType
		{
			Translation,
			QuaterionRotation,
			QuaternionRotateAroundPoint,
			Scale,
			ScaleAroundPoint,
			ToFrame,
			FromFrame
		}

		private struct XForm
		{
			public XFormType type;

			public Vector3dTuple3 data;

			public Vector3d Translation => data.V0;

			public Vector3d Scale => data.V0;

			public Quaternionf Quaternion => new Quaternionf((float)data.V0.x, (float)data.V0.y, (float)data.V0.z, (float)data.V1.x);

			public Vector3d RotateOrigin => data.V2;

			public Frame3f Frame => new Frame3f((Vector3f)RotateOrigin, Quaternion);
		}

		private List<XForm> Operations;

		public TransformSequence()
		{
			Operations = new List<XForm>();
		}

		public TransformSequence(TransformSequence copy)
		{
			Operations = new List<XForm>(copy.Operations);
		}

		public void Append(TransformSequence sequence)
		{
			Operations.AddRange(sequence.Operations);
		}

		public void AppendTranslation(Vector3d dv)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Translation,
				data = new Vector3dTuple3(dv, Vector3d.Zero, Vector3d.Zero)
			});
		}

		public void AppendTranslation(double dx, double dy, double dz)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Translation,
				data = new Vector3dTuple3(new Vector3d(dx, dy, dz), Vector3d.Zero, Vector3d.Zero)
			});
		}

		public void AppendRotation(Quaternionf q)
		{
			Operations.Add(new XForm
			{
				type = XFormType.QuaterionRotation,
				data = new Vector3dTuple3(new Vector3d(q.x, q.y, q.z), new Vector3d(q.w, 0.0, 0.0), Vector3d.Zero)
			});
		}

		public void AppendRotation(Quaternionf q, Vector3d aroundPt)
		{
			Operations.Add(new XForm
			{
				type = XFormType.QuaternionRotateAroundPoint,
				data = new Vector3dTuple3(new Vector3d(q.x, q.y, q.z), new Vector3d(q.w, 0.0, 0.0), aroundPt)
			});
		}

		public void AppendScale(Vector3d s)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Scale,
				data = new Vector3dTuple3(s, Vector3d.Zero, Vector3d.Zero)
			});
		}

		public void AppendScale(Vector3d s, Vector3d aroundPt)
		{
			Operations.Add(new XForm
			{
				type = XFormType.ScaleAroundPoint,
				data = new Vector3dTuple3(s, Vector3d.Zero, aroundPt)
			});
		}

		public void AppendToFrame(Frame3f frame)
		{
			Quaternionf rotation = frame.Rotation;
			Operations.Add(new XForm
			{
				type = XFormType.ToFrame,
				data = new Vector3dTuple3(new Vector3d(rotation.x, rotation.y, rotation.z), new Vector3d(rotation.w, 0.0, 0.0), frame.Origin)
			});
		}

		public void AppendFromFrame(Frame3f frame)
		{
			Quaternionf rotation = frame.Rotation;
			Operations.Add(new XForm
			{
				type = XFormType.FromFrame,
				data = new Vector3dTuple3(new Vector3d(rotation.x, rotation.y, rotation.z), new Vector3d(rotation.w, 0.0, 0.0), frame.Origin)
			});
		}

		public Vector3d TransformP(Vector3d p)
		{
			int count = Operations.Count;
			for (int i = 0; i < count; i++)
			{
				switch (Operations[i].type)
				{
				case XFormType.Translation:
					p += Operations[i].Translation;
					break;
				case XFormType.QuaterionRotation:
					p = Operations[i].Quaternion * p;
					break;
				case XFormType.QuaternionRotateAroundPoint:
					p -= Operations[i].RotateOrigin;
					p = Operations[i].Quaternion * p;
					p += Operations[i].RotateOrigin;
					break;
				case XFormType.Scale:
					p *= Operations[i].Scale;
					break;
				case XFormType.ScaleAroundPoint:
					p -= Operations[i].RotateOrigin;
					p *= Operations[i].Scale;
					p += Operations[i].RotateOrigin;
					break;
				case XFormType.ToFrame:
					p = Operations[i].Frame.ToFrameP(ref p);
					break;
				case XFormType.FromFrame:
					p = Operations[i].Frame.FromFrameP(ref p);
					break;
				default:
					throw new NotImplementedException("TransformSequence.TransformP: unhandled type!");
				}
			}
			return p;
		}

		public Vector3d TransformV(Vector3d v)
		{
			int count = Operations.Count;
			for (int i = 0; i < count; i++)
			{
				switch (Operations[i].type)
				{
				case XFormType.QuaterionRotation:
				case XFormType.QuaternionRotateAroundPoint:
					v = Operations[i].Quaternion * v;
					break;
				case XFormType.Scale:
				case XFormType.ScaleAroundPoint:
					v *= Operations[i].Scale;
					break;
				case XFormType.ToFrame:
					v = Operations[i].Frame.ToFrameV(ref v);
					break;
				case XFormType.FromFrame:
					v = Operations[i].Frame.FromFrameV(ref v);
					break;
				default:
					throw new NotImplementedException("TransformSequence.TransformV: unhandled type!");
				case XFormType.Translation:
					break;
				}
			}
			return v;
		}

		public Vector3f TransformP(Vector3f p)
		{
			return (Vector3f)TransformP((Vector3d)p);
		}

		public TransformSequence MakeInverse()
		{
			TransformSequence transformSequence = new TransformSequence();
			for (int num = Operations.Count - 1; num >= 0; num--)
			{
				switch (Operations[num].type)
				{
				case XFormType.Translation:
					transformSequence.AppendTranslation(-Operations[num].Translation);
					break;
				case XFormType.QuaterionRotation:
					transformSequence.AppendRotation(Operations[num].Quaternion.Inverse());
					break;
				case XFormType.QuaternionRotateAroundPoint:
					transformSequence.AppendRotation(Operations[num].Quaternion.Inverse(), Operations[num].RotateOrigin);
					break;
				case XFormType.Scale:
					transformSequence.AppendScale(1.0 / Operations[num].Scale);
					break;
				case XFormType.ScaleAroundPoint:
					transformSequence.AppendScale(1.0 / Operations[num].Scale, Operations[num].RotateOrigin);
					break;
				case XFormType.ToFrame:
					transformSequence.AppendFromFrame(Operations[num].Frame);
					break;
				case XFormType.FromFrame:
					transformSequence.AppendToFrame(Operations[num].Frame);
					break;
				default:
					throw new NotImplementedException("TransformSequence.MakeInverse: unhandled type!");
				}
			}
			return transformSequence;
		}

		public void Store(BinaryWriter writer)
		{
			writer.Write(1);
			writer.Write(Operations.Count);
			for (int i = 0; i < Operations.Count; i++)
			{
				writer.Write((int)Operations[i].type);
				gSerialization.Store(Operations[i].data.V0, writer);
				gSerialization.Store(Operations[i].data.V1, writer);
				gSerialization.Store(Operations[i].data.V2, writer);
			}
		}

		public void Restore(BinaryReader reader)
		{
			if (reader.ReadInt32() != 1)
			{
				throw new Exception("TransformSequence.Restore: unknown version number!");
			}
			int num = reader.ReadInt32();
			Operations = new List<XForm>();
			for (int i = 0; i < num; i++)
			{
				int type = reader.ReadInt32();
				XForm item = new XForm
				{
					type = (XFormType)type
				};
				gSerialization.Restore(ref item.data.V0, reader);
				gSerialization.Restore(ref item.data.V1, reader);
				gSerialization.Restore(ref item.data.V2, reader);
				Operations.Add(item);
			}
		}
	}
	public interface ITransform2
	{
		Vector2d TransformP(Vector2d p);

		Vector2d TransformN(Vector2d n);

		double TransformScalar(double s);
	}
	public class TransformSequence2 : ITransform2
	{
		private enum XFormType
		{
			Translation = 0,
			Rotation = 1,
			RotateAroundPoint = 2,
			Scale = 3,
			ScaleAroundPoint = 4,
			NestedITransform2 = 10
		}

		private struct XForm
		{
			public XFormType type;

			public Vector2dTuple2 data;

			public object xform;

			public Vector2d Translation => data.V0;

			public Vector2d Scale => data.V0;

			public Matrix2d Rotation => new Matrix2d(data.V0.x);

			public Vector2d RotateOrigin => data.V1;

			public bool ScaleIsUniform => data.V0.EpsilonEqual(data.V1, 1.1920928955078125E-07);

			public ITransform2 NestedITransform2 => xform as ITransform2;
		}

		private List<XForm> Operations;

		public TransformSequence2()
		{
			Operations = new List<XForm>();
		}

		public TransformSequence2 Translation(Vector2d dv)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Translation,
				data = new Vector2dTuple2(dv, Vector2d.Zero)
			});
			return this;
		}

		public TransformSequence2 Translation(double dx, double dy)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Translation,
				data = new Vector2dTuple2(new Vector2d(dx, dy), Vector2d.Zero)
			});
			return this;
		}

		public TransformSequence2 RotationRad(double angle)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Rotation,
				data = new Vector2dTuple2(new Vector2d(angle, 0.0), Vector2d.Zero)
			});
			return this;
		}

		public TransformSequence2 RotationDeg(double angle)
		{
			return RotationRad(angle * (Math.PI / 180.0));
		}

		public TransformSequence2 RotationRad(double angle, Vector2d aroundPt)
		{
			Operations.Add(new XForm
			{
				type = XFormType.RotateAroundPoint,
				data = new Vector2dTuple2(new Vector2d(angle, 0.0), aroundPt)
			});
			return this;
		}

		public TransformSequence2 RotationDeg(double angle, Vector2d aroundPt)
		{
			return RotationRad(angle * (Math.PI / 180.0), aroundPt);
		}

		public TransformSequence2 Scale(Vector2d s)
		{
			Operations.Add(new XForm
			{
				type = XFormType.Scale,
				data = new Vector2dTuple2(s, Vector2d.Zero)
			});
			return this;
		}

		public TransformSequence2 Scale(Vector2d s, Vector2d aroundPt)
		{
			Operations.Add(new XForm
			{
				type = XFormType.ScaleAroundPoint,
				data = new Vector2dTuple2(s, aroundPt)
			});
			return this;
		}

		public TransformSequence2 Append(ITransform2 t2)
		{
			Operations.Add(new XForm
			{
				type = XFormType.NestedITransform2,
				xform = t2
			});
			return this;
		}

		public Vector2d TransformP(Vector2d p)
		{
			int count = Operations.Count;
			for (int i = 0; i < count; i++)
			{
				switch (Operations[i].type)
				{
				case XFormType.Translation:
					p += Operations[i].Translation;
					break;
				case XFormType.Rotation:
					p = Operations[i].Rotation * p;
					break;
				case XFormType.RotateAroundPoint:
					p -= Operations[i].RotateOrigin;
					p = Operations[i].Rotation * p;
					p += Operations[i].RotateOrigin;
					break;
				case XFormType.Scale:
					p *= Operations[i].Scale;
					break;
				case XFormType.ScaleAroundPoint:
					p -= Operations[i].RotateOrigin;
					p *= Operations[i].Scale;
					p += Operations[i].RotateOrigin;
					break;
				case XFormType.NestedITransform2:
					p = Operations[i].NestedITransform2.TransformP(p);
					break;
				default:
					throw new NotImplementedException("TransformSequence.TransformP: unhandled type!");
				}
			}
			return p;
		}

		public Vector2d TransformN(Vector2d n)
		{
			int count = Operations.Count;
			for (int i = 0; i < count; i++)
			{
				switch (Operations[i].type)
				{
				case XFormType.Rotation:
					n = Operations[i].Rotation * n;
					break;
				case XFormType.RotateAroundPoint:
					n = Operations[i].Rotation * n;
					break;
				case XFormType.Scale:
					n *= Operations[i].Scale;
					break;
				case XFormType.ScaleAroundPoint:
					n *= Operations[i].Scale;
					break;
				case XFormType.NestedITransform2:
					n = Operations[i].NestedITransform2.TransformN(n);
					break;
				default:
					throw new NotImplementedException("TransformSequence.TransformN: unhandled type!");
				case XFormType.Translation:
					break;
				}
			}
			return n;
		}

		public double TransformScalar(double s)
		{
			int count = Operations.Count;
			for (int i = 0; i < count; i++)
			{
				switch (Operations[i].type)
				{
				case XFormType.Scale:
					s *= Operations[i].Scale.x;
					break;
				case XFormType.ScaleAroundPoint:
					s *= Operations[i].Scale.x;
					break;
				case XFormType.NestedITransform2:
					s = Operations[i].NestedITransform2.TransformScalar(s);
					break;
				default:
					throw new NotImplementedException("TransformSequence.TransformScalar: unhandled type!");
				case XFormType.Translation:
				case XFormType.Rotation:
				case XFormType.RotateAroundPoint:
					break;
				}
			}
			return s;
		}
	}
	public struct Triangle2d(Vector2d v0, Vector2d v1, Vector2d v2)
	{
		public Vector2d V0 = v0;

		public Vector2d V1 = v1;

		public Vector2d V2 = v2;

		public Vector2d this[int key]
		{
			get
			{
				return key switch
				{
					1 => V1, 
					0 => V0, 
					_ => V2, 
				};
			}
			set
			{
				switch (key)
				{
				case 0:
					V0 = value;
					break;
				case 1:
					V1 = value;
					break;
				default:
					V2 = value;
					break;
				}
			}
		}

		public Vector2d PointAt(double bary0, double bary1, double bary2)
		{
			return bary0 * V0 + bary1 * V1 + bary2 * V2;
		}

		public Vector2d PointAt(Vector3d bary)
		{
			return bary.x * V0 + bary.y * V1 + bary.z * V2;
		}

		public Vector2d Centroid()
		{
			return PointAt(0.3, 0.3, 0.3);
		}

		public static implicit operator Triangle2d(Triangle2f v)
		{
			return new Triangle2d(v.V0, v.V1, v.V2);
		}

		public static explicit operator Triangle2f(Triangle2d v)
		{
			return new Triangle2f((Vector2f)v.V0, (Vector2f)v.V1, (Vector2f)v.V2);
		}
	}
