		{
			double num = v2.x - x;
			double num2 = v2.y - y;
			double num3 = v2.z - z;
			return num * num + num2 * num2 + num3 * num3;
		}

		public double DistanceSquared(ref Vector3d v2)
		{
			double num = v2.x - x;
			double num2 = v2.y - y;
			double num3 = v2.z - z;
