		public Vector2d V3 = v3;

		public Vector2d this[int key]
		{
			get
			{
				if (key <= 1)
				{
					if (key != 1)
					{
						return V0;
					}
					return V1;
				}
				if (key != 2)
				{
					return V3;
				}
				return V2;
			}
			set
			{
				if (key > 1)
				{
					if (key == 2)
					{
						V2 = value;
					}
					else
					{
						V3 = value;
					}
				}
				else if (key == 1)
				{
