			}
			vertex_edges = new SmallListSet();
			vertices_refcount = new RefCountVector();
			triangles = new DVector<int>();
			triangle_edges = new DVector<int>();
			triangles_refcount = new RefCountVector();
			if (bWantTriGroups)
			{
