		public bool IsSameMesh(DMesh3 m2, bool bCheckConnectivity, bool bCheckEdgeIDs = false, bool bCheckNormals = false, bool bCheckColors = false, bool bCheckUVs = false, bool bCheckGroups = false, float Epsilon = 1.1920929E-07f)
		{
			if (VertexCount != m2.VertexCount)
			{
				return false;
			}
			if (TriangleCount != m2.TriangleCount)
			{
				return false;
			}
			foreach (int item in VertexIndices())
			{
				if (!m2.IsVertex(item) || !GetVertex(item).EpsilonEqual(m2.GetVertex(item), Epsilon))
				{
					return false;
				}
			}
			foreach (int item2 in TriangleIndices())
			{
				if (!m2.IsTriangle(item2) || !GetTriangle(item2).Equals(m2.GetTriangle(item2)))
				{
					return false;
				}
			}
			if (bCheckConnectivity)
			{
				foreach (int item3 in EdgeIndices())
				{
					Index4i edge = GetEdge(item3);
					int num = m2.FindEdge(edge.a, edge.b);
					if (num == -1)
					{
						return false;
					}
					Index4i edge2 = m2.GetEdge(num);
					if (Math.Min(edge.c, edge.d) != Math.Min(edge2.c, edge2.d) || Math.Max(edge.c, edge.d) != Math.Max(edge2.c, edge2.d))
					{
						return false;
					}
				}
			}
			if (bCheckEdgeIDs)
			{
				if (EdgeCount != m2.EdgeCount)
				{
					return false;
				}
				foreach (int item4 in EdgeIndices())
				{
					if (!m2.IsEdge(item4) || !GetEdge(item4).Equals(m2.GetEdge(item4)))
					{
						return false;
					}
				}
			}
			if (bCheckNormals)
			{
				if (HasVertexNormals != m2.HasVertexNormals)
				{
					return false;
				}
				if (HasVertexNormals)
				{
					foreach (int item5 in VertexIndices())
					{
						if (!GetVertexNormal(item5).EpsilonEqual(m2.GetVertexNormal(item5), Epsilon))
						{
							return false;
						}
					}
				}
			}
			if (bCheckColors)
			{
				if (HasVertexColors != m2.HasVertexColors)
				{
					return false;
				}
				if (HasVertexColors)
				{
					foreach (int item6 in VertexIndices())
					{
						if (!GetVertexColor(item6).EpsilonEqual(m2.GetVertexColor(item6), Epsilon))
						{
							return false;
						}
					}
				}
			}
			if (bCheckUVs)
			{
				if (HasVertexUVs != m2.HasVertexUVs)
				{
					return false;
				}
				if (HasVertexUVs)
				{
					foreach (int item7 in VertexIndices())
					{
						if (!GetVertexUV(item7).EpsilonEqual(m2.GetVertexUV(item7), Epsilon))
						{
							return false;
						}
					}
				}
			}
			if (bCheckGroups)
			{
				if (HasTriangleGroups != m2.HasTriangleGroups)
				{
					return false;
				}
				if (HasTriangleGroups)
				{
					foreach (int item8 in TriangleIndices())
					{
						if (GetTriangleGroup(item8) != m2.GetTriangleGroup(item8))
						{
							return false;
						}
					}
				}
			}
			return true;
		}

		public bool CheckValidity(bool bAllowNonManifoldVertices = false, FailMode eFailMode = FailMode.Throw)
		{
			int[] array = new int[MaxVertexID];
			bool is_ok = true;
			Action<bool> action = delegate(bool b)
			{
				is_ok &= b;
			};
			switch (eFailMode)
			{
			case FailMode.DebugAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.gDevAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.Throw:
				action = delegate(bool b)
				{
					if (!b)
					{
						throw new Exception("DMesh3.CheckValidity: check failed");
					}
				};
				break;
			}
			if (normals != null)
			{
				action(normals.size == vertices.size);
			}
			if (colors != null)
			{
				action(colors.size == vertices.size);
			}
			if (uv != null)
			{
				action(uv.size / 2 == vertices.size / 3);
			}
			if (triangle_groups != null)
			{
				action(triangle_groups.size == triangles.size / 3);
			}
			foreach (int item in TriangleIndices())
			{
				action(IsTriangle(item));
				action(triangles_refcount.refCount(item) == 1);
				Index3i triangle = GetTriangle(item);
				for (int num = 0; num < 3; num++)
				{
					action(IsVertex(triangle[num]));
					array[triangle[num]]++;
				}
				Index3i index3i = default(Index3i);
				for (int num2 = 0; num2 < 3; num2++)
				{
					int vA = triangle[num2];
					int vB = triangle[(num2 + 1) % 3];
					index3i[num2] = FindEdge(vA, vB);
					action(index3i[num2] != -1);
					action(edge_has_t(index3i[num2], item));
					action(index3i[num2] == FindEdgeFromTri(vA, vB, item));
				}
				action(index3i[0] != index3i[1] && index3i[0] != index3i[2] && index3i[1] != index3i[2]);
				Index3i triEdges = GetTriEdges(item);
				for (int num3 = 0; num3 < 3; num3++)
				{
					int eID = triEdges[num3];
					action(IsEdge(eID));
					int num4 = edge_other_t(eID, item);
					if (num4 == -1)
					{
						action(tri_is_boundary(item));
						continue;
					}
					action(tri_has_neighbour_t(num4, item));
					int num5 = triangle[num3];
					int num6 = triangle[(num3 + 1) % 3];
					Index2i edgeV = GetEdgeV(triEdges[num3]);
					action(IndexUtil.same_pair_unordered(num5, num6, edgeV[0], edgeV[1]));
					int num7 = IndexUtil.find_tri_ordered_edge(num6, num5, GetTriangle(num4).array);
					action(num7 != -1);
				}
			}
			foreach (int item2 in EdgeIndices())
			{
				action(IsEdge(item2));
				action(edges_refcount.refCount(item2) == 1);
				Index2i edgeV2 = GetEdgeV(item2);
				Index2i edgeT = GetEdgeT(item2);
				action(IsVertex(edgeV2[0]));
				action(IsVertex(edgeV2[1]));
				action(edgeT[0] != -1);
				action(edgeV2[0] < edgeV2[1]);
				action(IsTriangle(edgeT[0]));
				if (edgeT[1] != -1)
				{
					action(IsTriangle(edgeT[1]));
				}
			}
			if (vertices_refcount.is_dense)
			{
				for (int num8 = 0; num8 < vertices.Length / 3; num8++)
				{
					action(vertices_refcount.isValid(num8));
				}
			}
			foreach (int item3 in VertexIndices())
			{
				action(IsVertex(item3));
				Vector3d vertex = GetVertex(item3);
				action(!double.IsNaN(vertex.LengthSquared));
				action(!double.IsInfinity(vertex.LengthSquared));
				foreach (int item4 in vertex_edges.ValueItr(item3))
				{
					action(IsEdge(item4));
					action(edge_has_v(item4, item3));
					int num9 = edge_other_v(item4, item3);
					int num10 = find_edge(item3, num9);
					action(num10 != -1);
					action(num10 == item4);
					num10 = find_edge(num9, item3);
					action(num10 != -1);
					action(num10 == item4);
				}
				foreach (int item5 in VtxVerticesItr(item3))
				{
					action(IsVertex(item5));
					int eID2 = find_edge(item3, item5);
					action(IsEdge(eID2));
				}
				List<int> list = new List<int>();
				List<int> list2 = new List<int>();
				GetVtxTriangles(item3, list, bUseOrientation: false);
				GetVtxTriangles(item3, list2, bUseOrientation: true);
				action(list.Count == list2.Count);
				if (bAllowNonManifoldVertices)
				{
					action(list.Count <= GetVtxEdgeCount(item3));
				}
				else
				{
					action(list.Count == GetVtxEdgeCount(item3) || list.Count == GetVtxEdgeCount(item3) - 1);
				}
				action(vertices_refcount.refCount(item3) == list.Count + 1);
				action(array[item3] == list.Count);
				foreach (int item6 in list)
				{
					action(tri_has_v(item6, item3));
				}
				List<int> list3 = new List<int>(list);
				foreach (int item7 in vertex_edges.ValueItr(item3))
				{
					Index2i edgeT2 = GetEdgeT(item7);
					action(list.Contains(edgeT2[0]));
					if (edgeT2[1] != -1)
					{
						action(list.Contains(edgeT2[1]));
					}
					list3.Remove(edgeT2[0]);
					if (edgeT2[1] != -1)
					{
						list3.Remove(edgeT2[1]);
					}
				}
				action(list3.Count == 0);
			}
			return is_ok;
		}

		public MeshResult ReverseTriOrientation(int tID)
		{
			if (!IsTriangle(tID))
			{
				return MeshResult.Failed_NotATriangle;
			}
			internal_reverse_tri_orientation(tID);
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		private void internal_reverse_tri_orientation(int tID)
		{
			Index3i triangle = GetTriangle(tID);
			set_triangle(tID, triangle[1], triangle[0], triangle[2]);
			Index3i triEdges = GetTriEdges(tID);
			set_triangle_edges(tID, triEdges[0], triEdges[2], triEdges[1]);
		}

		public void ReverseOrientation(bool bFlipNormals = true)
		{
			foreach (int item in TriangleIndices())
			{
				internal_reverse_tri_orientation(item);
			}
			if (bFlipNormals && HasVertexNormals)
			{
				foreach (int item2 in VertexIndices())
				{
					int num = 3 * item2;
					normals[num] = 0f - normals[num];
					normals[num + 1] = 0f - normals[num + 1];
					normals[num + 2] = 0f - normals[num + 2];
				}
			}
			updateTimeStamp(bShapeChange: true);
			Clockwise = !Clockwise;
		}

		public MeshResult RemoveVertex(int vID, bool bRemoveAllTriangles = true, bool bPreserveManifold = false)
		{
			if (!vertices_refcount.isValid(vID))
			{
				return MeshResult.Failed_NotAVertex;
			}
			if (bRemoveAllTriangles)
			{
				if (bPreserveManifold)
				{
					foreach (int item in VtxTrianglesItr(vID))
					{
						Index3i tri_verts = GetTriangle(item);
						int num = IndexUtil.find_tri_index(vID, ref tri_verts);
						int num2 = tri_verts[(num + 1) % 3];
						int num3 = tri_verts[(num + 2) % 3];
						int eid = find_edge(num2, num3);
						if (!IsBoundaryEdge(eid) && (IsBoundaryVertex(num2) || IsBoundaryVertex(num3)))
						{
							return MeshResult.Failed_WouldCreateBowtie;
						}
					}
				}
				List<int> list = new List<int>();
				GetVtxTriangles(vID, list, bUseOrientation: true);
				foreach (int item2 in list)
				{
					MeshResult meshResult = RemoveTriangle(item2, bRemoveIsolatedVertices: false, bPreserveManifold);
					if (meshResult != MeshResult.Ok)
					{
						return meshResult;
					}
				}
			}
			if (vertices_refcount.refCount(vID) != 1)
			{
				throw new NotImplementedException("DMesh3.RemoveVertex: vertex is still referenced");
			}
			vertices_refcount.decrement(vID, 1);
			vertex_edges.Clear(vID);
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult RemoveTriangle(int tID, bool bRemoveIsolatedVertices = true, bool bPreserveManifold = false)
		{
			if (!triangles_refcount.isValid(tID))
			{
				return MeshResult.Failed_NotATriangle;
			}
			Index3i triangle = GetTriangle(tID);
			Index3i triEdges = GetTriEdges(tID);
			if (bPreserveManifold)
			{
				for (int i = 0; i < 3; i++)
				{
					if (IsBoundaryVertex(triangle[i]) && !IsBoundaryEdge(triEdges[i]) && !IsBoundaryEdge(triEdges[(i + 2) % 3]))
					{
						return MeshResult.Failed_WouldCreateBowtie;
					}
				}
			}
			for (int j = 0; j < 3; j++)
			{
				int num = triEdges[j];
				replace_edge_triangle(num, tID, -1);
				if (edges[4 * num + 2] == -1)
				{
					int list_index = edges[4 * num];
					vertex_edges.Remove(list_index, num);
					int list_index2 = edges[4 * num + 1];
					vertex_edges.Remove(list_index2, num);
					edges_refcount.decrement(num, 1);
				}
			}
			triangles_refcount.decrement(tID, 1);
			for (int k = 0; k < 3; k++)
			{
				int num2 = triangle[k];
				vertices_refcount.decrement(num2, 1);
				if (bRemoveIsolatedVertices && vertices_refcount.refCount(num2) == 1)
				{
					vertices_refcount.decrement(num2, 1);
					vertex_edges.Clear(num2);
				}
			}
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public virtual MeshResult SetTriangle(int tID, Index3i newv, bool bRemoveIsolatedVertices = true)
		{
			Index3i triangle = GetTriangle(tID);
			Index3i triEdges = GetTriEdges(tID);
			if (triangle.a == newv.a && triangle.b == newv.b)
			{
				triEdges.a = -1;
			}
			if (triangle.b == newv.b && triangle.c == newv.c)
			{
				triEdges.b = -1;
			}
			if (triangle.c == newv.c && triangle.a == newv.a)
			{
				triEdges.c = -1;
			}
			if (!triangles_refcount.isValid(tID))
			{
				return MeshResult.Failed_NotATriangle;
			}
			if (!IsVertex(newv[0]) || !IsVertex(newv[1]) || !IsVertex(newv[2]))
			{
				return MeshResult.Failed_NotAVertex;
			}
			if (newv[0] == newv[1] || newv[0] == newv[2] || newv[1] == newv[2])
			{
				return MeshResult.Failed_BrokenTopology;
			}
			int num = find_edge(newv[0], newv[1]);
			int num2 = find_edge(newv[1], newv[2]);
			int num3 = find_edge(newv[2], newv[0]);
			if ((triEdges.a != -1 && num != -1 && !IsBoundaryEdge(num)) || (triEdges.b != -1 && num2 != -1 && !IsBoundaryEdge(num2)) || (triEdges.c != -1 && num3 != -1 && !IsBoundaryEdge(num3)))
			{
				return MeshResult.Failed_BrokenTopology;
			}
			for (int i = 0; i < 3; i++)
			{
				int num4 = triEdges[i];
				if (num4 != -1)
				{
					replace_edge_triangle(num4, tID, -1);
					if (edges[4 * num4 + 2] == -1)
					{
						int list_index = edges[4 * num4];
						vertex_edges.Remove(list_index, num4);
						int list_index2 = edges[4 * num4 + 1];
						vertex_edges.Remove(list_index2, num4);
						edges_refcount.decrement(num4, 1);
					}
				}
			}
			for (int j = 0; j < 3; j++)
			{
				int num5 = triangle[j];
				if (num5 != newv[j])
				{
					vertices_refcount.decrement(num5, 1);
					if (bRemoveIsolatedVertices && vertices_refcount.refCount(num5) == 1)
					{
						vertices_refcount.decrement(num5, 1);
						vertex_edges.Clear(num5);
					}
				}
			}
			int num6 = 3 * tID;
			for (int k = 0; k < 3; k++)
			{
				if (newv[k] != triangle[k])
				{
					triangles[num6 + k] = newv[k];
					vertices_refcount.increment(newv[k], 1);
				}
			}
			if (triEdges.a != -1)
			{
				add_tri_edge(tID, newv[0], newv[1], 0, num);
			}
			if (triEdges.b != -1)
			{
				add_tri_edge(tID, newv[1], newv[2], 1, num2);
			}
			if (triEdges.c != -1)
			{
				add_tri_edge(tID, newv[2], newv[0], 2, num3);
			}
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult SplitEdge(int vA, int vB, out EdgeSplitInfo split)
		{
			int num = find_edge(vA, vB);
			if (num == -1)
			{
				split = default(EdgeSplitInfo);
				return MeshResult.Failed_NotAnEdge;
			}
			return SplitEdge(num, out split);
		}

		public MeshResult SplitEdge(int eab, out EdgeSplitInfo split, double split_t = 0.5)
		{
			split = default(EdgeSplitInfo);
			if (!IsEdge(eab))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = 4 * eab;
			int a = edges[num];
			int b = edges[num + 1];
			int num2 = edges[num + 2];
			if (num2 == -1)
			{
				return MeshResult.Failed_BrokenTopology;
			}
			int[] array = GetTriangle(num2).array;
			int num3 = IndexUtil.orient_tri_edge_and_find_other_vtx(ref a, ref b, array);
			if (vertices_refcount.rawRefCount(num3) > 32764)
			{
				return MeshResult.Failed_HitValenceLimit;
			}
			if (a != edges[num])
			{
				split_t = 1.0 - split_t;
			}
			if (IsBoundaryEdge(eab))
			{
				Vector3d v = Vector3d.Lerp(GetVertex(a), GetVertex(b), split_t);
				int num4 = AppendVertex(v);
				if (HasVertexNormals)
				{
					SetVertexNormal(num4, Vector3f.Lerp(GetVertexNormal(a), GetVertexNormal(b), (float)split_t).Normalized);
				}
				if (HasVertexColors)
				{
					SetVertexColor(num4, Colorf.Lerp(GetVertexColor(a), GetVertexColor(b), (float)split_t));
				}
				if (HasVertexUVs)
				{
					SetVertexUV(num4, Vector2f.Lerp(GetVertexUV(a), GetVertexUV(b), (float)split_t));
				}
				int num5 = GetTriEdges(num2)[IndexUtil.find_edge_index_in_tri(b, num3, array)];
				replace_tri_vertex(num2, b, num4);
				int num6 = add_triangle_only(num4, b, num3, -1, -1, -1);
				if (triangle_groups != null)
				{
					triangle_groups.insert(triangle_groups[num2], num6);
				}
				replace_edge_triangle(num5, num2, num6);
				replace_edge_vertex(eab, b, num4);
				vertex_edges.Remove(b, eab);
				vertex_edges.Insert(num4, eab);
				int num7 = add_edge(num4, b, num6);
				int num8 = add_edge(num4, num3, num2, num6);
				replace_triangle_edge(num2, num5, num8);
				set_triangle_edges(num6, num7, num5, num8);
				vertices_refcount.increment(num3, 1);
				vertices_refcount.increment(num4, 2);
				split.bIsBoundary = true;
				split.vNew = num4;
				split.eNewBN = num7;
				split.eNewCN = num8;
				split.eNewDN = -1;
				split.eNewT2 = num6;
				split.eNewT3 = -1;
				updateTimeStamp(bShapeChange: true);
				return MeshResult.Ok;
			}
			int num9 = edges[num + 3];
			int[] array2 = GetTriangle(num9).array;
			int num10 = IndexUtil.find_tri_other_vtx(a, b, array2);
			if (vertices_refcount.rawRefCount(num10) > 32764)
			{
				return MeshResult.Failed_HitValenceLimit;
			}
			Vector3d v2 = Vector3d.Lerp(GetVertex(a), GetVertex(b), split_t);
			int num11 = AppendVertex(v2);
			if (HasVertexNormals)
			{
				SetVertexNormal(num11, Vector3f.Lerp(GetVertexNormal(a), GetVertexNormal(b), (float)split_t).Normalized);
			}
			if (HasVertexColors)
			{
				SetVertexColor(num11, Colorf.Lerp(GetVertexColor(a), GetVertexColor(b), (float)split_t));
			}
			if (HasVertexUVs)
			{
				SetVertexUV(num11, Vector2f.Lerp(GetVertexUV(a), GetVertexUV(b), (float)split_t));
			}
			int num12 = GetTriEdges(num2)[IndexUtil.find_edge_index_in_tri(b, num3, array)];
			int num13 = GetTriEdges(num9)[IndexUtil.find_edge_index_in_tri(num10, b, array2)];
			replace_tri_vertex(num2, b, num11);
			replace_tri_vertex(num9, b, num11);
			int num14 = add_triangle_only(num11, b, num3, -1, -1, -1);
			int num15 = add_triangle_only(num11, num10, b, -1, -1, -1);
			if (triangle_groups != null)
			{
				triangle_groups.insert(triangle_groups[num2], num14);
				triangle_groups.insert(triangle_groups[num9], num15);
			}
			replace_edge_triangle(num12, num2, num14);
			replace_edge_triangle(num13, num9, num15);
			replace_edge_vertex(eab, b, num11);
			vertex_edges.Remove(b, eab);
			vertex_edges.Insert(num11, eab);
			int num16 = add_edge(num11, b, num14, num15);
			int num17 = add_edge(num11, num3, num2, num14);
			int num18 = add_edge(num10, num11, num9, num15);
			replace_triangle_edge(num2, num12, num17);
			replace_triangle_edge(num9, num13, num18);
			set_triangle_edges(num14, num16, num12, num17);
			set_triangle_edges(num15, num18, num13, num16);
			vertices_refcount.increment(num3, 1);
			vertices_refcount.increment(num10, 1);
			vertices_refcount.increment(num11, 4);
			split.bIsBoundary = false;
			split.vNew = num11;
			split.eNewBN = num16;
			split.eNewCN = num17;
			split.eNewDN = num18;
			split.eNewT2 = num14;
			split.eNewT3 = num15;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult FlipEdge(int vA, int vB, out EdgeFlipInfo flip)
		{
			int num = find_edge(vA, vB);
			if (num == -1)
			{
				flip = default(EdgeFlipInfo);
				return MeshResult.Failed_NotAnEdge;
			}
			return FlipEdge(num, out flip);
		}

		public MeshResult FlipEdge(int eab, out EdgeFlipInfo flip)
		{
			flip = default(EdgeFlipInfo);
			if (!IsEdge(eab))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			if (IsBoundaryEdge(eab))
			{
				return MeshResult.Failed_IsBoundaryEdge;
			}
			int num = 4 * eab;
			int a = edges[num];
			int b = edges[num + 1];
			int num2 = edges[num + 2];
			int num3 = edges[num + 3];
			int[] array = GetTriangle(num2).array;
			int[] array2 = GetTriangle(num3).array;
			int num4 = IndexUtil.orient_tri_edge_and_find_other_vtx(ref a, ref b, array);
			int num5 = IndexUtil.find_tri_other_vtx(a, b, array2);
			if (num4 == -1 || num5 == -1)
			{
				return MeshResult.Failed_BrokenTopology;
			}
			if (find_edge(num4, num5) != -1)
			{
				return MeshResult.Failed_FlippedEdgeExists;
			}
			int e = find_tri_neighbour_edge(num2, b, num4);
			int num6 = find_tri_neighbour_edge(num2, num4, a);
			int e2 = find_tri_neighbour_edge(num3, a, num5);
			int num7 = find_tri_neighbour_edge(num3, num5, b);
			set_triangle(num2, num4, num5, b);
			set_triangle(num3, num5, num4, a);
			set_edge_vertices(eab, num4, num5);
			set_edge_triangles(eab, num2, num3);
			if (replace_edge_triangle(num6, num2, num3) == -1)
			{
				throw new ArgumentException("DMesh3.FlipEdge: first replace_edge_triangle failed");
			}
			if (replace_edge_triangle(num7, num3, num2) == -1)
			{
				throw new ArgumentException("DMesh3.FlipEdge: second replace_edge_triangle failed");
			}
			set_triangle_edges(num2, eab, num7, e);
			set_triangle_edges(num3, eab, num6, e2);
			if (!vertex_edges.Remove(a, eab))
			{
				throw new ArgumentException("DMesh3.FlipEdge: first edge list remove failed");
			}
			if (!vertex_edges.Remove(b, eab))
			{
				throw new ArgumentException("DMesh3.FlipEdge: second edge list remove failed");
			}
			vertices_refcount.decrement(a, 1);
			vertices_refcount.decrement(b, 1);
			if (!IsVertex(a) || !IsVertex(b))
			{
				throw new ArgumentException("DMesh3.FlipEdge: either a or b is not a vertex?");
			}
			vertex_edges.Insert(num4, eab);
			vertex_edges.Insert(num5, eab);
			vertices_refcount.increment(num4, 1);
			vertices_refcount.increment(num5, 1);
			flip.eID = eab;
			flip.v0 = a;
			flip.v1 = b;
			flip.ov0 = num4;
			flip.ov1 = num5;
			flip.t0 = num2;
			flip.t1 = num3;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		private void debug_fail(string s)
		{
		}

		private void check_tri(int t)
		{
			Index3i triangle = GetTriangle(t);
			if (triangle[0] != triangle[1] && triangle[0] != triangle[2])
			{
				_ = triangle[1];
				_ = triangle[2];
			}
		}

		private void check_edge(int e)
		{
			_ = GetEdgeT(e)[0];
			_ = -1;
		}

		public MeshResult CollapseEdge(int vKeep, int vRemove, out EdgeCollapseInfo collapse)
		{
			collapse = default(EdgeCollapseInfo);
			if (!IsVertex(vKeep) || !IsVertex(vRemove))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = find_edge(vRemove, vKeep);
			if (num == -1)
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num2 = edges[4 * num + 2];
			if (num2 == -1)
			{
				return MeshResult.Failed_BrokenTopology;
			}
			Index3i triangle = GetTriangle(num2);
			int num3 = IndexUtil.find_tri_other_vtx(vRemove, vKeep, triangle);
			bool flag = false;
			int num4 = -1;
			int num5 = edges[4 * num + 3];
			if (num5 != -1)
			{
				Index3i triangle2 = GetTriangle(num5);
				num4 = IndexUtil.find_tri_other_vtx(vRemove, vKeep, triangle2);
				if (num3 == num4)
				{
					return MeshResult.Failed_FoundDuplicateTriangle;
				}
			}
			else
			{
				flag = true;
			}
			int num6 = vertex_edges.Count(vRemove);
			int num7 = -1;
			int num8 = -1;
			int num9 = -1;
			int num10 = -1;
			foreach (int item in vertex_edges.ValueItr(vRemove))
			{
				int num11 = edge_other_v(item, vRemove);
				if (num11 == num3)
				{
					num7 = item;
				}
				else if (num11 == num4)
				{
					num8 = item;
				}
				else
				{
					if (num11 == vKeep)
					{
						continue;
					}
					foreach (int item2 in vertex_edges.ValueItr(vKeep))
					{
						if (edge_other_v(item2, vKeep) == num11)
						{
							return MeshResult.Failed_InvalidNeighbourhood;
						}
					}
				}
			}
			if (num6 == 3 && !flag)
			{
				int num12 = find_edge(num4, num3);
				int num13 = 4 * num12;
				if (num12 != -1 && edges[num13 + 3] != -1)
				{
					int tID = edges[num13 + 2];
					int tID2 = edges[num13 + 3];
					if ((tri_has_v(tID, vRemove) && tri_has_v(tID2, vKeep)) || (tri_has_v(tID, vKeep) && tri_has_v(tID2, vRemove)))
					{
						return MeshResult.Failed_CollapseTetrahedron;
					}
				}
			}
			else if (flag && IsBoundaryEdge(num7))
			{
				num9 = find_edge_from_tri(vKeep, num3, num2);
				if (IsBoundaryEdge(num9))
				{
					return MeshResult.Failed_CollapseTriangle;
				}
			}
			if (!flag && IsBoundaryVertex(vRemove) && IsBoundaryVertex(vKeep))
			{
				return MeshResult.Failed_InvalidNeighbourhood;
			}
			int num14 = -1;
			int num15 = -1;
			foreach (int item3 in vertex_edges.ValueItr(vRemove))
			{
				int num16 = edge_other_v(item3, vRemove);
				if (num16 == vKeep)
				{
					if (!vertex_edges.Remove(vKeep, item3))
					{
						debug_fail("remove case o == b");
					}
				}
				else if (num16 == num3)
				{
					if (!vertex_edges.Remove(num3, item3))
					{
						debug_fail("remove case o == c");
					}
					num15 = edge_other_t(item3, num2);
				}
				else if (num16 == num4)
				{
					if (!vertex_edges.Remove(num4, item3))
					{
						debug_fail("remove case o == c, step 1");
					}
					num14 = edge_other_t(item3, num5);
				}
				else
				{
					if (replace_edge_vertex(item3, vRemove, vKeep) == -1)
					{
						debug_fail("remove case else");
					}
					vertex_edges.Insert(vKeep, item3);
				}
				for (int i = 0; i < 2; i++)
				{
					int num17 = edges[4 * item3 + 2 + i];
					if (num17 != -1 && num17 != num2 && num17 != num5 && tri_has_v(num17, vRemove))
					{
						if (replace_tri_vertex(num17, vRemove, vKeep) == -1)
						{
							debug_fail("remove last check");
						}
						vertices_refcount.increment(vKeep, 1);
						vertices_refcount.decrement(vRemove, 1);
					}
				}
			}
			if (!flag)
			{
				vertex_edges.Clear(vRemove);
				vertices_refcount.decrement(vRemove, 3);
				triangles_refcount.decrement(num2, 1);
				triangles_refcount.decrement(num5, 1);
				vertices_refcount.decrement(num3, 1);
				vertices_refcount.decrement(num4, 1);
				vertices_refcount.decrement(vKeep, 2);
				edges_refcount.decrement(num8, 1);
				edges_refcount.decrement(num, 1);
				edges_refcount.decrement(num7, 1);
				num10 = find_edge_from_tri(vKeep, num4, num5);
				if (num9 == -1)
				{
					num9 = find_edge_from_tri(vKeep, num3, num2);
				}
				if (replace_edge_triangle(num10, num5, num14) == -1)
				{
					debug_fail("isboundary=false branch, ebd replace triangle");
				}
				if (replace_edge_triangle(num9, num2, num15) == -1)
				{
					debug_fail("isboundary=false branch, ebc replace triangle");
				}
				if (num14 != -1 && replace_triangle_edge(num14, num8, num10) == -1)
				{
					debug_fail("isboundary=false branch, ebd replace triangle");
				}
				if (num15 != -1 && replace_triangle_edge(num15, num7, num9) == -1)
				{
					debug_fail("isboundary=false branch, ebd replace triangle");
				}
			}
			else
			{
				vertex_edges.Clear(vRemove);
				vertices_refcount.decrement(vRemove, 2);
				triangles_refcount.decrement(num2, 1);
				vertices_refcount.decrement(num3, 1);
				vertices_refcount.decrement(vKeep, 1);
				edges_refcount.decrement(num, 1);
				edges_refcount.decrement(num7, 1);
				num9 = find_edge_from_tri(vKeep, num3, num2);
				if (replace_edge_triangle(num9, num2, num15) == -1)
				{
					debug_fail("isboundary=false branch, ebc replace triangle");
				}
				if (num15 != -1 && replace_triangle_edge(num15, num7, num9) == -1)
				{
					debug_fail("isboundary=true branch, ebd replace triangle");
				}
			}
			collapse.vKept = vKeep;
			collapse.vRemoved = vRemove;
			collapse.bIsBoundary = flag;
			collapse.eCollapsed = num;
			collapse.tRemoved0 = num2;
			collapse.tRemoved1 = num5;
			collapse.eRemoved0 = num7;
			collapse.eRemoved1 = num8;
			collapse.eKept0 = num9;
			collapse.eKept1 = num10;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult MergeEdges(int eKeep, int eDiscard, out MergeEdgesInfo merge_info)
		{
			merge_info = default(MergeEdgesInfo);
			if (!IsEdge(eKeep) || !IsEdge(eDiscard))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			Index4i edge = GetEdge(eKeep);
			Index4i edge2 = GetEdge(eDiscard);
			if (edge.d != -1 || edge2.d != -1)
			{
				return MeshResult.Failed_NotABoundaryEdge;
			}
			int a = edge.a;
			int b = edge.b;
			int c = edge.c;
			int a2 = edge2.a;
			int b2 = edge2.b;
			int c2 = edge2.c;
			IndexUtil.orient_tri_edge(ref a, ref b, GetTriangle(c));
			IndexUtil.orient_tri_edge(ref a2, ref b2, GetTriangle(c2));
			int num = a2;
			a2 = b2;
			b2 = num;
			Vector3d vertex = GetVertex(a);
			Vector3d vertex2 = GetVertex(b);
			Vector3d vertex3 = GetVertex(a2);
			Vector3d vertex4 = GetVertex(b2);
			if (vertex.DistanceSquared(vertex3) + vertex2.DistanceSquared(vertex4) > vertex.DistanceSquared(vertex4) + vertex2.DistanceSquared(vertex3))
			{
				return MeshResult.Failed_SameOrientation;
			}
			merge_info.eKept = eKeep;
			merge_info.eRemoved = eDiscard;
			if (a != a2 && find_edge(a, a2) != -1)
			{
				return MeshResult.Failed_InvalidNeighbourhood;
			}
			if (b != b2 && find_edge(b, b2) != -1)
			{
				return MeshResult.Failed_InvalidNeighbourhood;
			}
			if (a != a2)
			{
				int num2 = 0;
				int num3 = 0;
				int num4 = ((b == b2) ? b : (-1));
				foreach (int item in VtxVerticesItr(a2))
				{
					if (item != num4 && (num2 = find_edge(a, item)) != -1)
					{
						num3 = find_edge(a2, item);
						if (!IsBoundaryEdge(num2) || !IsBoundaryEdge(num3))
						{
							return MeshResult.Failed_InvalidNeighbourhood;
						}
					}
				}
			}
			if (b != b2)
			{
				int num5 = 0;
				int num6 = 0;
				int num7 = ((a == a2) ? a : (-1));
				foreach (int item2 in VtxVerticesItr(b2))
				{
					if (item2 != num7 && (num5 = find_edge(b, item2)) != -1)
					{
						num6 = find_edge(b2, item2);
						if (!IsBoundaryEdge(num5) || !IsBoundaryEdge(num6))
						{
							return MeshResult.Failed_InvalidNeighbourhood;
						}
					}
				}
			}
			if (a != a2)
			{
				foreach (int item3 in vertex_edges.ValueItr(a2))
				{
					if (item3 != eDiscard)
					{
						replace_edge_vertex(item3, a2, a);
						short num8 = 0;
						if (replace_tri_vertex(edges[4 * item3 + 2], a2, a) >= 0)
						{
							num8++;
						}
						if (edges[4 * item3 + 3] != -1 && replace_tri_vertex(edges[4 * item3 + 3], a2, a) >= 0)
						{
							num8++;
						}
						vertex_edges.Insert(a, item3);
						if (num8 > 0)
						{
							vertices_refcount.increment(a, num8);
							vertices_refcount.decrement(a2, num8);
						}
					}
				}
				vertex_edges.Clear(a2);
				vertices_refcount.decrement(a2, 1);
				merge_info.vRemoved[0] = a2;
			}
			else
			{
				vertex_edges.Remove(a, eDiscard);
				merge_info.vRemoved[0] = -1;
			}
			merge_info.vKept[0] = a;
			if (b2 != b)
			{
				foreach (int item4 in vertex_edges.ValueItr(b2))
				{
					if (item4 != eDiscard)
					{
						replace_edge_vertex(item4, b2, b);
						short num9 = 0;
						if (replace_tri_vertex(edges[4 * item4 + 2], b2, b) >= 0)
						{
							num9++;
						}
						if (edges[4 * item4 + 3] != -1 && replace_tri_vertex(edges[4 * item4 + 3], b2, b) >= 0)
						{
							num9++;
						}
						vertex_edges.Insert(b, item4);
						if (num9 > 0)
						{
							vertices_refcount.increment(b, num9);
							vertices_refcount.decrement(b2, num9);
						}
					}
				}
				vertex_edges.Clear(b2);
				vertices_refcount.decrement(b2, 1);
				merge_info.vRemoved[1] = b2;
			}
			else
			{
				vertex_edges.Remove(b, eDiscard);
				merge_info.vRemoved[1] = -1;
			}
			merge_info.vKept[1] = b;
			replace_triangle_edge(c2, eDiscard, eKeep);
			edges_refcount.decrement(eDiscard, 1);
			set_edge_triangles(eKeep, c, c2);
			merge_info.eRemovedExtra = new Vector2i(-1, -1);
			merge_info.eKeptExtra = merge_info.eRemovedExtra;
			for (int i = 0; i < 2; i++)
			{
				int num10 = a;
				int num11 = a2;
				if (i == 1)
				{
					num10 = b;
					num11 = b2;
				}
				if (num10 == num11)
				{
					continue;
				}
				List<int> list = vertex_edges_list(num10);
				int count = list.Count;
				bool flag = false;
				for (int j = 0; j < count; j++)
				{
					if (flag)
					{
						break;
					}
					int num12 = list[j];
					if (!IsBoundaryEdge(num12))
					{
						continue;
					}
					int num13 = edge_other_v(num12, num10);
					for (int k = j + 1; k < count; k++)
					{
						int num14 = list[k];
						int num15 = edge_other_v(num14, num10);
						if (num13 == num15 && IsBoundaryEdge(num14))
						{
							int t = edges[4 * num12 + 2];
							int num16 = edges[4 * num14 + 2];
							replace_triangle_edge(num16, num14, num12);
							set_edge_triangles(num12, t, num16);
							vertex_edges.Remove(num10, num14);
							vertex_edges.Remove(num13, num14);
							edges_refcount.decrement(num14, 1);
							merge_info.eRemovedExtra[i] = num14;
							merge_info.eKeptExtra[i] = num12;
							flag = true;
							break;
						}
					}
				}
			}
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public virtual MeshResult PokeTriangle(int tid, out PokeTriangleInfo result)
		{
			return PokeTriangle(tid, Vector3d.One / 3.0, out result);
		}

		public virtual MeshResult PokeTriangle(int tid, Vector3d baryCoordinates, out PokeTriangleInfo result)
		{
			result = default(PokeTriangleInfo);
			if (!IsTriangle(tid))
			{
				return MeshResult.Failed_NotATriangle;
			}
			Index3i triangle = GetTriangle(tid);
			Index3i triEdges = GetTriEdges(tid);
			GetTriBaryPoint(tid, baryCoordinates.x, baryCoordinates.y, baryCoordinates.z, out var vinfo);
			int num = AppendVertex(vinfo);
			int num2 = add_edge(triangle.a, num, -1);
			int num3 = add_edge(triangle.b, num, -1);
			int num4 = add_edge(triangle.c, num, -1);
			vertices_refcount.increment(triangle.a, 1);
			vertices_refcount.increment(triangle.b, 1);
			vertices_refcount.increment(triangle.c, 1);
			vertices_refcount.increment(num, 3);
			set_triangle(tid, triangle.a, triangle.b, num);
			set_triangle_edges(tid, triEdges.a, num3, num2);
			int num5 = add_triangle_only(triangle.b, triangle.c, num, triEdges.b, num4, num3);
			int num6 = add_triangle_only(triangle.c, triangle.a, num, triEdges.c, num2, num4);
			replace_edge_triangle(triEdges.b, tid, num5);
			replace_edge_triangle(triEdges.c, tid, num6);
			set_edge_triangles(num2, tid, num6);
			set_edge_triangles(num3, tid, num5);
			set_edge_triangles(num4, num5, num6);
			if (HasTriangleGroups)
			{
				int value = triangle_groups[tid];
				triangle_groups.insert(value, num5);
				triangle_groups.insert(value, num6);
			}
			result.new_vid = num;
			result.new_t1 = num5;
			result.new_t2 = num6;
			result.new_edges = new Index3i(num2, num3, num4);
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		private void set_triangle(int tid, int v0, int v1, int v2)
		{
			int num = 3 * tid;
			triangles[num] = v0;
			triangles[num + 1] = v1;
			triangles[num + 2] = v2;
		}

		private void set_triangle_edges(int tid, int e0, int e1, int e2)
		{
			int num = 3 * tid;
			triangle_edges[num] = e0;
			triangle_edges[num + 1] = e1;
			triangle_edges[num + 2] = e2;
		}

		private int add_edge(int vA, int vB, int tA, int tB = -1)
		{
			if (vB < vA)
			{
				int num = vB;
				vB = vA;
				vA = num;
			}
			int num2 = edges_refcount.allocate();
			int num3 = 4 * num2;
			edges.insert(vA, num3);
			edges.insert(vB, num3 + 1);
			edges.insert(tA, num3 + 2);
			edges.insert(tB, num3 + 3);
			vertex_edges.Insert(vA, num2);
			vertex_edges.Insert(vB, num2);
			return num2;
		}

		private int replace_tri_vertex(int tID, int vOld, int vNew)
		{
			int num = 3 * tID;
			if (triangles[num] == vOld)
			{
				triangles[num] = vNew;
				return 0;
			}
			if (triangles[num + 1] == vOld)
			{
				triangles[num + 1] = vNew;
				return 1;
			}
			if (triangles[num + 2] == vOld)
			{
				triangles[num + 2] = vNew;
				return 2;
			}
			return -1;
		}

		private int add_triangle_only(int a, int b, int c, int e0, int e1, int e2)
		{
			int num = triangles_refcount.allocate();
			int num2 = 3 * num;
			triangles.insert(c, num2 + 2);
			triangles.insert(b, num2 + 1);
			triangles.insert(a, num2);
			triangle_edges.insert(e2, num2 + 2);
			triangle_edges.insert(e1, num2 + 1);
			triangle_edges.insert(e0, num2);
			return num;
		}

		private void allocate_edges_list(int vid)
		{
			if (vid < vertex_edges.Size)
			{
				vertex_edges.Clear(vid);
			}
			vertex_edges.AllocateAt(vid);
		}

		private List<int> vertex_edges_list(int vid)
		{
			return new List<int>(vertex_edges.ValueItr(vid));
		}

		private List<int> vertex_vertices_list(int vid)
		{
			List<int> list = new List<int>();
			foreach (int item in vertex_edges.ValueItr(vid))
			{
				list.Add(edge_other_v(item, vid));
			}
			return list;
		}

		private void set_edge_vertices(int eID, int a, int b)
		{
			int num = 4 * eID;
			edges[num] = Math.Min(a, b);
			edges[num + 1] = Math.Max(a, b);
		}

		private void set_edge_triangles(int eID, int t0, int t1)
		{
			int num = 4 * eID;
			edges[num + 2] = t0;
			edges[num + 3] = t1;
		}

		private int replace_edge_vertex(int eID, int vOld, int vNew)
		{
			int num = 4 * eID;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			if (num2 == vOld)
			{
				edges[num] = Math.Min(num3, vNew);
				edges[num + 1] = Math.Max(num3, vNew);
				return 0;
			}
			if (num3 == vOld)
			{
				edges[num] = Math.Min(num2, vNew);
				edges[num + 1] = Math.Max(num2, vNew);
				return 1;
			}
			return -1;
		}

		private int replace_edge_triangle(int eID, int tOld, int tNew)
		{
			int num = 4 * eID;
			int num2 = edges[num + 2];
			int num3 = edges[num + 3];
			if (num2 == tOld)
			{
				if (tNew == -1)
				{
					edges[num + 2] = num3;
					edges[num + 3] = -1;
				}
				else
				{
					edges[num + 2] = tNew;
				}
				return 0;
			}
			if (num3 == tOld)
			{
				edges[num + 3] = tNew;
				return 1;
			}
			return -1;
		}

		private int replace_triangle_edge(int tID, int eOld, int eNew)
		{
			int num = 3 * tID;
			if (triangle_edges[num] == eOld)
			{
				triangle_edges[num] = eNew;
				return 0;
			}
			if (triangle_edges[num + 1] == eOld)
			{
				triangle_edges[num + 1] = eNew;
				return 1;
			}
			if (triangle_edges[num + 2] == eOld)
			{
				triangle_edges[num + 2] = eNew;
				return 2;
			}
			return -1;
		}
	}
	public class DMesh3Builder : IMeshBuilder
	{
		public enum AddTriangleFailBehaviors
		{
			DiscardTriangle,
			DuplicateAllVertices
		}

		public AddTriangleFailBehaviors NonManifoldTriBehavior = AddTriangleFailBehaviors.DuplicateAllVertices;

		public AddTriangleFailBehaviors DuplicateTriBehavior;

		public List<DMesh3> Meshes;

		public List<GenericMaterial> Materials;

		public List<int> MaterialAssignment;

		public List<Dictionary<string, object>> Metadata;

		private int nActiveMesh;

		public bool SupportsMetaData => true;

		public DMesh3Builder()
		{
			Meshes = new List<DMesh3>();
			Materials = new List<GenericMaterial>();
			MaterialAssignment = new List<int>();
			Metadata = new List<Dictionary<string, object>>();
			nActiveMesh = -1;
		}

		public int AppendNewMesh(bool bHaveVtxNormals, bool bHaveVtxColors, bool bHaveVtxUVs, bool bHaveFaceGroups)
		{
			int count = Meshes.Count;
			DMesh3 item = new DMesh3(bHaveVtxNormals, bHaveVtxColors, bHaveVtxUVs, bHaveFaceGroups);
			Meshes.Add(item);
			MaterialAssignment.Add(-1);
			Metadata.Add(new Dictionary<string, object>());
			nActiveMesh = count;
			return count;
		}

		public int AppendNewMesh(DMesh3 existingMesh)
		{
			int count = Meshes.Count;
			Meshes.Add(existingMesh);
			MaterialAssignment.Add(-1);
			Metadata.Add(new Dictionary<string, object>());
			nActiveMesh = count;
			return count;
		}

		public void SetActiveMesh(int id)
		{
			if (id >= 0 && id < Meshes.Count)
			{
				nActiveMesh = id;
				return;
			}
			throw new ArgumentOutOfRangeException("active mesh id is out of range");
		}

		public int AppendTriangle(int i, int j, int k)
		{
			return AppendTriangle(i, j, k, -1);
		}

		public int AppendTriangle(int i, int j, int k, int g)
		{
			int num = Meshes[nActiveMesh].FindTriangle(i, j, k);
			if (num != -1)
			{
				if (DuplicateTriBehavior == AddTriangleFailBehaviors.DuplicateAllVertices)
				{
					return append_duplicate_triangle(i, j, k, g);
				}
				return num;
			}
			int num2 = Meshes[nActiveMesh].AppendTriangle(i, j, k, g);
			if (num2 == -2)
			{
				if (NonManifoldTriBehavior == AddTriangleFailBehaviors.DuplicateAllVertices)
				{
					return append_duplicate_triangle(i, j, k, g);
				}
				return -2;
			}
			return num2;
		}

		private int append_duplicate_triangle(int i, int j, int k, int g)
		{
			NewVertexInfo vinfo = default(NewVertexInfo);
			Meshes[nActiveMesh].GetVertex(i, ref vinfo, bWantNormals: true, bWantColors: true, bWantUVs: true);
			int v = Meshes[nActiveMesh].AppendVertex(vinfo);
			Meshes[nActiveMesh].GetVertex(j, ref vinfo, bWantNormals: true, bWantColors: true, bWantUVs: true);
			int v2 = Meshes[nActiveMesh].AppendVertex(vinfo);
			Meshes[nActiveMesh].GetVertex(k, ref vinfo, bWantNormals: true, bWantColors: true, bWantUVs: true);
			int v3 = Meshes[nActiveMesh].AppendVertex(vinfo);
			return Meshes[nActiveMesh].AppendTriangle(v, v2, v3, g);
		}

		public int AppendVertex(double x, double y, double z)
		{
			return Meshes[nActiveMesh].AppendVertex(new Vector3d(x, y, z));
		}

		public int AppendVertex(NewVertexInfo info)
		{
			return Meshes[nActiveMesh].AppendVertex(info);
		}

		public void AppendMetaData(string identifier, object data)
		{
			Metadata[nActiveMesh].Add(identifier, data);
		}

		public void SetVertexUV(int vID, Vector2f UV)
		{
			Meshes[nActiveMesh].SetVertexUV(vID, UV);
		}

		public int BuildMaterial(GenericMaterial m)
		{
			int count = Materials.Count;
			Materials.Add(m);
			return count;
		}

		public void AssignMaterial(int materialID, int meshID)
		{
			if (meshID >= MaterialAssignment.Count || materialID >= Materials.Count)
			{
				throw new ArgumentOutOfRangeException("[SimpleMeshBuilder::AssignMaterial] meshID or materialID are out-of-range");
			}
			MaterialAssignment[meshID] = materialID;
		}

		public static DMesh3 Build<VType, TType, NType>(IEnumerable<VType> Vertices, IEnumerable<TType> Triangles, IEnumerable<NType> Normals = null, IEnumerable<int> TriGroups = null)
		{
			DMesh3 dMesh = new DMesh3(Normals != null, bWantColors: false, bWantUVs: false, TriGroups != null);
			Vector3d[] array = BufferUtil.ToVector3d(Vertices);
			for (int i = 0; i < array.Length; i++)
			{
				dMesh.AppendVertex(array[i]);
			}
			if (Normals != null)
			{
				Vector3f[] array2 = BufferUtil.ToVector3f(Normals);
				if (array2.Length != array.Length)
				{
					throw new Exception("DMesh3Builder.Build: incorrect number of normals provided");
				}
				for (int j = 0; j < array2.Length; j++)
				{
					dMesh.SetVertexNormal(j, array2[j]);
				}
			}
			Index3i[] array3 = BufferUtil.ToIndex3i(Triangles);
			for (int k = 0; k < array3.Length; k++)
			{
				dMesh.AppendTriangle(array3[k]);
			}
			if (TriGroups != null)
			{
				List<int> list = new List<int>(TriGroups);
				if (list.Count != array3.Length)
				{
					throw new Exception("DMesh3Builder.Build: incorect number of triangle groups");
				}
				for (int l = 0; l < array3.Length; l++)
				{
					dMesh.SetTriangleGroup(l, list[l]);
				}
			}
			return dMesh;
		}
	}
	public class ModifyVerticesMeshChange
	{
		public DVector<int> ModifiedV;

		public DVector<Vector3d> OldPositions;

		public DVector<Vector3d> NewPositions;

		public DVector<Vector3f> OldNormals;

		public DVector<Vector3f> NewNormals;

		public DVector<Vector3f> OldColors;

		public DVector<Vector3f> NewColors;

		public DVector<Vector2f> OldUVs;

		public DVector<Vector2f> NewUVs;

		public Action<ModifyVerticesMeshChange> OnApplyF;

		public Action<ModifyVerticesMeshChange> OnRevertF;

		public ModifyVerticesMeshChange(DMesh3 mesh, MeshComponents wantComponents = MeshComponents.All)
		{
			initialize_buffers(mesh, wantComponents);
		}

		public int AppendNewVertex(DMesh3 mesh, int vid)
		{
			int length = ModifiedV.Length;
			ModifiedV.Add(vid);
			OldPositions.Add(mesh.GetVertex(vid));
			NewPositions.Add(OldPositions[length]);
			if (NewNormals != null)
			{
				OldNormals.Add(mesh.GetVertexNormal(vid));
				NewNormals.Add(OldNormals[length]);
			}
			if (NewColors != null)
			{
				OldColors.Add(mesh.GetVertexColor(vid));
				NewColors.Add(OldColors[length]);
			}
			if (NewUVs != null)
			{
				OldUVs.Add(mesh.GetVertexUV(vid));
				NewUVs.Add(OldUVs[length]);
			}
			return length;
		}

		public void Apply(DMesh3 mesh)
		{
			int size = ModifiedV.size;
			for (int i = 0; i < size; i++)
			{
				int vID = ModifiedV[i];
				mesh.SetVertex(vID, NewPositions[i]);
				if (NewNormals != null)
				{
					mesh.SetVertexNormal(vID, NewNormals[i]);
				}
				if (NewColors != null)
				{
					mesh.SetVertexColor(vID, NewColors[i]);
				}
				if (NewUVs != null)
				{
					mesh.SetVertexUV(vID, NewUVs[i]);
				}
			}
			if (OnApplyF != null)
			{
				OnApplyF(this);
			}
		}

		public void Revert(DMesh3 mesh)
		{
			int size = ModifiedV.size;
			for (int i = 0; i < size; i++)
			{
				int vID = ModifiedV[i];
				mesh.SetVertex(vID, OldPositions[i]);
				if (NewNormals != null)
				{
					mesh.SetVertexNormal(vID, OldNormals[i]);
				}
				if (NewColors != null)
				{
					mesh.SetVertexColor(vID, OldColors[i]);
				}
				if (NewUVs != null)
				{
					mesh.SetVertexUV(vID, OldUVs[i]);
				}
			}
			if (OnRevertF != null)
			{
				OnRevertF(this);
			}
		}

		private void initialize_buffers(DMesh3 mesh, MeshComponents components)
		{
			ModifiedV = new DVector<int>();
			NewPositions = new DVector<Vector3d>();
			OldPositions = new DVector<Vector3d>();
			if (mesh.HasVertexNormals && (components & MeshComponents.VertexNormals) != MeshComponents.None)
			{
				NewNormals = new DVector<Vector3f>();
				OldNormals = new DVector<Vector3f>();
			}
			if (mesh.HasVertexColors && (components & MeshComponents.VertexColors) != MeshComponents.None)
			{
				NewColors = new DVector<Vector3f>();
				OldColors = new DVector<Vector3f>();
			}
			if (mesh.HasVertexUVs && (components & MeshComponents.VertexUVs) != MeshComponents.None)
			{
				NewUVs = new DVector<Vector2f>();
				OldUVs = new DVector<Vector2f>();
			}
		}
	}
	public class SetVerticesMeshChange
	{
		public DVector<double> OldPositions;

		public DVector<double> NewPositions;

		public DVector<float> OldNormals;

		public DVector<float> NewNormals;

		public DVector<float> OldColors;

		public DVector<float> NewColors;

		public DVector<float> OldUVs;

		public DVector<float> NewUVs;

		public Action<SetVerticesMeshChange> OnApplyF;

		public Action<SetVerticesMeshChange> OnRevertF;

		public void Apply(DMesh3 mesh)
		{
			if (NewPositions != null)
			{
				mesh.VerticesBuffer.copy(NewPositions);
			}
			if (mesh.HasVertexNormals && NewNormals != null)
			{
				mesh.NormalsBuffer.copy(NewNormals);
			}
			if (mesh.HasVertexColors && NewColors != null)
			{
				mesh.ColorsBuffer.copy(NewColors);
			}
			if (mesh.HasVertexUVs && NewUVs != null)
			{
				mesh.UVBuffer.copy(NewUVs);
			}
			if (OnApplyF != null)
			{
				OnApplyF(this);
			}
		}

		public void Revert(DMesh3 mesh)
		{
			if (OldPositions != null)
			{
				mesh.VerticesBuffer.copy(OldPositions);
			}
			if (mesh.HasVertexNormals && OldNormals != null)
			{
				mesh.NormalsBuffer.copy(OldNormals);
			}
			if (mesh.HasVertexColors && OldColors != null)
			{
				mesh.ColorsBuffer.copy(OldColors);
			}
			if (mesh.HasVertexUVs && OldUVs != null)
			{
				mesh.UVBuffer.copy(OldUVs);
			}
			if (OnRevertF != null)
			{
				OnRevertF(this);
			}
		}
	}
	public class RemoveTrianglesMeshChange
	{
		protected DVector<int> RemovedV;

		protected DVector<Vector3d> Positions;

		protected DVector<Vector3f> Normals;

		protected DVector<Vector3f> Colors;

		protected DVector<Vector2f> UVs;

		protected DVector<int> RemovedT;

		protected DVector<Index4i> Triangles;

		public Action<IEnumerable<int>, IEnumerable<int>> OnApplyF;

		public Action<IEnumerable<int>, IEnumerable<int>> OnRevertF;

		public void InitializeFromApply(DMesh3 mesh, IEnumerable<int> triangles)
		{
			initialize_buffers(mesh);
			bool hasTriangleGroups = mesh.HasTriangleGroups;
			foreach (int triangle2 in triangles)
			{
				if (mesh.IsTriangle(triangle2))
				{
					Index3i triangle = mesh.GetTriangle(triangle2);
					save_vertex(mesh, triangle.a);
					save_vertex(mesh, triangle.b);
					save_vertex(mesh, triangle.c);
					Index4i value = new Index4i(triangle.a, triangle.b, triangle.c, hasTriangleGroups ? mesh.GetTriangleGroup(triangle2) : (-1));
					RemovedT.Add(triangle2);
					Triangles.Add(value);
					MeshResult meshResult = mesh.RemoveTriangle(triangle2);
					if (meshResult != MeshResult.Ok)
					{
						throw new Exception("RemoveTrianglesMeshChange.Initialize: exception in RemoveTriangle(" + triangle2 + "): " + meshResult);
					}
				}
			}
		}

		public void InitializeFromExisting(DMesh3 mesh, IEnumerable<int> remove_t)
		{
			initialize_buffers(mesh);
			bool hasTriangleGroups = mesh.HasTriangleGroups;
			HashSet<int> hashSet = new HashSet<int>(remove_t);
			HashSet<int> hashSet2 = new HashSet<int>();
			IndexUtil.TrianglesToVertices(mesh, remove_t, hashSet2);
			List<int> list = new List<int>();
			foreach (int item in hashSet2)
			{
				bool flag = true;
				foreach (int item2 in mesh.VtxTrianglesItr(item))
				{
					if (!hashSet.Contains(item2))
					{
						flag = false;
						break;
					}
				}
				if (flag)
				{
					list.Add(item);
				}
			}
			foreach (int item3 in list)
			{
				save_vertex(mesh, item3, force: true);
			}
			foreach (int item4 in remove_t)
			{
				Index3i triangle = mesh.GetTriangle(item4);
				Index4i value = new Index4i(triangle.a, triangle.b, triangle.c, hasTriangleGroups ? mesh.GetTriangleGroup(item4) : (-1));
				RemovedT.Add(item4);
				Triangles.Add(value);
			}
		}

		public void Apply(DMesh3 mesh)
		{
			int size = RemovedT.size;
			for (int i = 0; i < size; i++)
			{
				int num = RemovedT[i];
				MeshResult meshResult = mesh.RemoveTriangle(RemovedT[i]);
				if (meshResult != MeshResult.Ok)
				{
					throw new Exception("RemoveTrianglesMeshChange.Apply: error in RemoveTriangle(" + num + "): " + meshResult);
				}
			}
			if (OnApplyF != null)
			{
				OnApplyF(RemovedV, RemovedT);
			}
		}

		public void Revert(DMesh3 mesh)
		{
			int size = RemovedV.size;
			if (size > 0)
			{
				NewVertexInfo info = new NewVertexInfo(Positions[0]);
				mesh.BeginUnsafeVerticesInsert();
				for (int i = 0; i < size; i++)
				{
					int vid = RemovedV[i];
					info.v = Positions[i];
					if (Normals != null)
					{
						info.bHaveN = true;
						info.n = Normals[i];
					}
					if (Colors != null)
					{
						info.bHaveC = true;
						info.c = Colors[i];
					}
					if (UVs != null)
					{
						info.bHaveUV = true;
						info.uv = UVs[i];
					}
					MeshResult meshResult = mesh.InsertVertex(vid, ref info, bUnsafe: true);
					if (meshResult != MeshResult.Ok)
					{
						throw new Exception("RemoveTrianglesMeshChange.Revert: error in InsertVertex(" + vid + "): " + meshResult);
					}
				}
				mesh.EndUnsafeVerticesInsert();
			}
			int size2 = RemovedT.size;
			if (size2 > 0)
			{
				mesh.BeginUnsafeTrianglesInsert();
				for (int j = 0; j < size2; j++)
				{
					int tid = RemovedT[j];
					Index4i index4i = Triangles[j];
					MeshResult meshResult2 = mesh.InsertTriangle(tv: new Index3i(index4i.a, index4i.b, index4i.c), tid: tid, gid: index4i.d, bUnsafe: true);
					if (meshResult2 != MeshResult.Ok)
					{
						throw new Exception("RemoveTrianglesMeshChange.Revert: error in InsertTriangle(" + tid + "): " + meshResult2);
					}
				}
				mesh.EndUnsafeTrianglesInsert();
			}
			if (OnRevertF != null)
			{
				OnRevertF(RemovedV, RemovedT);
			}
		}

		private bool save_vertex(DMesh3 mesh, int vid, bool force = false)
		{
			if (force || mesh.VerticesRefCounts.refCount(vid) == 2)
			{
				RemovedV.Add(vid);
				Positions.Add(mesh.GetVertex(vid));
				if (Normals != null)
				{
					Normals.Add(mesh.GetVertexNormal(vid));
				}
				if (Colors != null)
				{
					Colors.Add(mesh.GetVertexColor(vid));
				}
				if (UVs != null)
				{
					UVs.Add(mesh.GetVertexUV(vid));
				}
				return false;
			}
			return true;
		}

		private void initialize_buffers(DMesh3 mesh)
		{
			RemovedV = new DVector<int>();
			Positions = new DVector<Vector3d>();
			if (mesh.HasVertexNormals)
			{
				Normals = new DVector<Vector3f>();
			}
			if (mesh.HasVertexColors)
			{
				Colors = new DVector<Vector3f>();
			}
			if (mesh.HasVertexUVs)
			{
				UVs = new DVector<Vector2f>();
			}
			RemovedT = new DVector<int>();
			Triangles = new DVector<Index4i>();
		}
	}
	public class AddTrianglesMeshChange
	{
		protected DVector<int> AddedV;

		protected DVector<Vector3d> Positions;

		protected DVector<Vector3f> Normals;

		protected DVector<Vector3f> Colors;

		protected DVector<Vector2f> UVs;

		protected DVector<int> AddedT;

		protected DVector<Index4i> Triangles;

		public Action<IEnumerable<int>, IEnumerable<int>> OnApplyF;

		public Action<IEnumerable<int>, IEnumerable<int>> OnRevertF;

		public void InitializeFromExisting(DMesh3 mesh, IEnumerable<int> added_v, IEnumerable<int> added_t)
		{
			initialize_buffers(mesh);
			bool hasTriangleGroups = mesh.HasTriangleGroups;
			if (added_v != null)
			{
				foreach (int item in added_v)
				{
					append_vertex(mesh, item);
				}
			}
			foreach (int item2 in added_t)
			{
				Index3i triangle = mesh.GetTriangle(item2);
				Index4i value = new Index4i(triangle.a, triangle.b, triangle.c, hasTriangleGroups ? mesh.GetTriangleGroup(item2) : (-1));
				AddedT.Add(item2);
				Triangles.Add(value);
			}
		}

		public void Apply(DMesh3 mesh)
		{
			int size = AddedV.size;
			if (size > 0)
			{
				NewVertexInfo info = new NewVertexInfo(Positions[0]);
				mesh.BeginUnsafeVerticesInsert();
				for (int i = 0; i < size; i++)
				{
					int vid = AddedV[i];
					info.v = Positions[i];
					if (Normals != null)
					{
						info.bHaveN = true;
						info.n = Normals[i];
					}
					if (Colors != null)
					{
						info.bHaveC = true;
						info.c = Colors[i];
					}
					if (UVs != null)
					{
						info.bHaveUV = true;
						info.uv = UVs[i];
					}
					MeshResult meshResult = mesh.InsertVertex(vid, ref info, bUnsafe: true);
					if (meshResult != MeshResult.Ok)
					{
						throw new Exception("AddTrianglesMeshChange.Revert: error in InsertVertex(" + vid + "): " + meshResult);
					}
				}
				mesh.EndUnsafeVerticesInsert();
			}
			int size2 = AddedT.size;
			if (size2 > 0)
			{
				mesh.BeginUnsafeTrianglesInsert();
				for (int j = 0; j < size2; j++)
				{
					int tid = AddedT[j];
					Index4i index4i = Triangles[j];
					MeshResult meshResult2 = mesh.InsertTriangle(tv: new Index3i(index4i.a, index4i.b, index4i.c), tid: tid, gid: index4i.d, bUnsafe: true);
					if (meshResult2 != MeshResult.Ok)
					{
						throw new Exception("AddTrianglesMeshChange.Revert: error in InsertTriangle(" + tid + "): " + meshResult2);
					}
				}
				mesh.EndUnsafeTrianglesInsert();
			}
			if (OnApplyF != null)
			{
				OnApplyF(AddedV, AddedT);
			}
		}

		public void Revert(DMesh3 mesh)
		{
			int size = AddedT.size;
			for (int i = 0; i < size; i++)
			{
				int num = AddedT[i];
				MeshResult meshResult = mesh.RemoveTriangle(AddedT[i]);
				if (meshResult != MeshResult.Ok)
				{
					throw new Exception("AddTrianglesMeshChange.Apply: error in RemoveTriangle(" + num + "): " + meshResult);
				}
			}
			if (OnRevertF != null)
			{
				OnRevertF(AddedV, AddedT);
			}
		}

		private void append_vertex(DMesh3 mesh, int vid)
		{
			AddedV.Add(vid);
			Positions.Add(mesh.GetVertex(vid));
			if (Normals != null)
			{
				Normals.Add(mesh.GetVertexNormal(vid));
			}
			if (Colors != null)
			{
				Colors.Add(mesh.GetVertexColor(vid));
			}
			if (UVs != null)
			{
				UVs.Add(mesh.GetVertexUV(vid));
			}
		}

		private void initialize_buffers(DMesh3 mesh)
		{
			AddedV = new DVector<int>();
			Positions = new DVector<Vector3d>();
			if (mesh.HasVertexNormals)
			{
				Normals = new DVector<Vector3f>();
			}
			if (mesh.HasVertexColors)
			{
				Colors = new DVector<Vector3f>();
			}
			if (mesh.HasVertexUVs)
			{
				UVs = new DVector<Vector2f>();
			}
			AddedT = new DVector<int>();
			Triangles = new DVector<Index4i>();
		}
	}
	public class DSubmesh3
	{
		public DMesh3 BaseMesh;

		public DMesh3 SubMesh;

		public MeshComponents WantComponents = MeshComponents.All;

		public bool ComputeTriMaps;

		public int OverrideGroupID = -1;

		public IndexFlagSet BaseSubmeshV;

		public IndexMap BaseToSubV;

		public DVector<int> SubToBaseV;

		public IndexMap BaseToSubT;

		public DVector<int> SubToBaseT;

		public IndexHashSet BaseBorderE;

		public IndexHashSet BaseBoundaryE;

		public IndexHashSet BaseBorderV;

		public DSubmesh3(DMesh3 mesh, int[] subTriangles)
		{
			BaseMesh = mesh;
			compute(subTriangles, subTriangles.Length);
		}

		public DSubmesh3(DMesh3 mesh, IEnumerable<int> subTriangles, int nTriEstimate = 0)
		{
			BaseMesh = mesh;
			compute(subTriangles, nTriEstimate);
		}

		public DSubmesh3(DMesh3 mesh)
		{
			BaseMesh = mesh;
		}

		public void Compute(int[] subTriangles)
		{
			compute(subTriangles, subTriangles.Length);
		}

		public void Compute(IEnumerable<int> subTriangles, int nTriEstimate = 0)
		{
			compute(subTriangles, nTriEstimate);
		}

		public int MapVertexToSubmesh(int base_vID)
		{
			return BaseToSubV[base_vID];
		}

		public int MapVertexToBaseMesh(int sub_vID)
		{
			if (sub_vID < SubToBaseV.Length)
			{
				return SubToBaseV[sub_vID];
			}
			return -1;
		}

		public Index2i MapVerticesToSubmesh(Index2i v)
		{
			return new Index2i(BaseToSubV[v.a], BaseToSubV[v.b]);
		}

		public Index2i MapVerticesToBaseMesh(Index2i v)
		{
			return new Index2i(MapVertexToBaseMesh(v.a), MapVertexToBaseMesh(v.b));
		}

		public void MapVerticesToSubmesh(int[] vertices)
		{
			for (int i = 0; i < vertices.Length; i++)
			{
				vertices[i] = BaseToSubV[vertices[i]];
			}
		}

		public int MapEdgeToSubmesh(int base_eid)
		{
			Index2i edgeV = BaseMesh.GetEdgeV(base_eid);
			Index2i index2i = MapVerticesToSubmesh(edgeV);
			return SubMesh.FindEdge(index2i.a, index2i.b);
		}

		public void MapEdgesToSubmesh(int[] edges)
		{
			for (int i = 0; i < edges.Length; i++)
			{
				edges[i] = MapEdgeToSubmesh(edges[i]);
			}
		}

		public int MapEdgeToBaseMesh(int sub_eid)
		{
			Index2i edgeV = SubMesh.GetEdgeV(sub_eid);
			Index2i index2i = MapVerticesToBaseMesh(edgeV);
			return BaseMesh.FindEdge(index2i.a, index2i.b);
		}

		public int MapTriangleToSubmesh(int base_tID)
		{
			if (!ComputeTriMaps)
			{
				throw new InvalidOperationException("DSubmesh3.MapTriangleToSubmesh: must set ComputeTriMaps = true!");
			}
			return BaseToSubT[base_tID];
		}

		public int MapTriangleToBaseMesh(int sub_tID)
		{
			if (!ComputeTriMaps)
			{
				throw new InvalidOperationException("DSubmesh3.MapTriangleToBaseMesh: must set ComputeTriMaps = true!");
			}
			if (sub_tID < SubToBaseT.Length)
			{
				return SubToBaseT[sub_tID];
			}
			return -1;
		}

		public void MapTrianglesToSubmesh(int[] triangles)
		{
			if (!ComputeTriMaps)
			{
				throw new InvalidOperationException("DSubmesh3.MapTrianglesToSubmesh: must set ComputeTriMaps = true!");
			}
			for (int i = 0; i < triangles.Length; i++)
			{
				triangles[i] = BaseToSubT[triangles[i]];
			}
		}

		public void ComputeBoundaryInfo(int[] subTriangles)
		{
			ComputeBoundaryInfo(subTriangles, subTriangles.Length);
		}

		public void ComputeBoundaryInfo(IEnumerable<int> triangles, int tri_count_est)
		{
			IndexFlagSet indexFlagSet = new IndexFlagSet(BaseMesh.MaxTriangleID, tri_count_est);
			foreach (int triangle in triangles)
			{
				indexFlagSet[triangle] = true;
			}
			BaseBorderV = new IndexHashSet();
			BaseBorderE = new IndexHashSet();
			BaseBoundaryE = new IndexHashSet();
			foreach (int triangle2 in triangles)
			{
				Index3i triEdges = BaseMesh.GetTriEdges(triangle2);
				for (int i = 0; i < 3; i++)
				{
					int num = triEdges[i];
					Index2i edgeT = BaseMesh.GetEdgeT(num);
					if (edgeT.b == -1)
					{
						BaseBoundaryE[num] = true;
					}
					else if (indexFlagSet[edgeT.a] != indexFlagSet[edgeT.b])
					{
						BaseBorderE[num] = true;
						Index2i edgeV = BaseMesh.GetEdgeV(num);
						BaseBorderV[edgeV.a] = true;
						BaseBorderV[edgeV.b] = true;
					}
				}
			}
		}

		private void compute(IEnumerable<int> triangles, int tri_count_est)
		{
			int subsetCountEst = tri_count_est / 2;
			SubMesh = new DMesh3(BaseMesh.Components & WantComponents);
			BaseSubmeshV = new IndexFlagSet(BaseMesh.MaxVertexID, subsetCountEst);
			BaseToSubV = new IndexMap(BaseMesh.MaxVertexID, subsetCountEst);
			SubToBaseV = new DVector<int>();
			if (ComputeTriMaps)
			{
				BaseToSubT = new IndexMap(BaseMesh.MaxTriangleID, tri_count_est);
				SubToBaseT = new DVector<int>();
			}
			foreach (int triangle2 in triangles)
			{
				if (!BaseMesh.IsTriangle(triangle2))
				{
					throw new Exception("DSubmesh3.compute: triangle " + triangle2 + " does not exist in BaseMesh!");
				}
				Index3i triangle = BaseMesh.GetTriangle(triangle2);
				Index3i zero = Index3i.Zero;
				int gid = BaseMesh.GetTriangleGroup(triangle2);
				for (int i = 0; i < 3; i++)
				{
					int num = triangle[i];
					int num2 = -1;
					if (!BaseSubmeshV[num])
					{
						num2 = SubMesh.AppendVertex(BaseMesh, num);
						BaseSubmeshV[num] = true;
						BaseToSubV[num] = num2;
						SubToBaseV.insert(num, num2);
					}
					else
					{
						num2 = BaseToSubV[num];
					}
					zero[i] = num2;
				}
				if (OverrideGroupID >= 0)
				{
					gid = OverrideGroupID;
				}
				int num3 = SubMesh.AppendTriangle(zero, gid);
				if (ComputeTriMaps)
				{
					BaseToSubT[triangle2] = num3;
					SubToBaseT.insert(triangle2, num3);
				}
			}
		}

		public static DMesh3 QuickSubmesh(DMesh3 mesh, int[] triangles)
		{
			return new DSubmesh3(mesh, triangles).SubMesh;
		}

		public static DMesh3 QuickSubmesh(DMesh3 mesh, IEnumerable<int> triangles)
		{
			return QuickSubmesh(mesh, triangles.ToArray());
		}
	}
	public class DSubmesh3Set : IEnumerable<DSubmesh3>, IEnumerable
	{
		public DMesh3 Mesh;

		public IEnumerable<object> TriangleSetKeys;

		public Func<object, IEnumerable<int>> TriangleSetF;

		public List<DSubmesh3> Submeshes;

		public Dictionary<object, DSubmesh3> KeyToMesh;

		public DSubmesh3Set(DMesh3 mesh, IEnumerable<object> keys, Func<object, IEnumerable<int>> indexSetsF)
		{
			Mesh = mesh;
			TriangleSetKeys = keys;
			TriangleSetF = indexSetsF;
			ComputeSubMeshes();
		}

		public DSubmesh3Set(DMesh3 mesh, MeshConnectedComponents components)
		{
			Mesh = mesh;
			TriangleSetF = (object idx) => components.Components[(int)idx].Indices;
			List<object> list = new List<object>();
			for (int num = 0; num < components.Count; num++)
			{
				list.Add(num);
			}
			TriangleSetKeys = list;
			ComputeSubMeshes();
		}

		public IEnumerator<DSubmesh3> GetEnumerator()
		{
			return Submeshes.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return Submeshes.GetEnumerator();
		}

		protected virtual void ComputeSubMeshes()
		{
			Submeshes = new List<DSubmesh3>();
			KeyToMesh = new Dictionary<object, DSubmesh3>();
			SpinLock data_lock = default(SpinLock);
			gParallel.ForEach(TriangleSetKeys, delegate(object obj)
			{
				DSubmesh3 dSubmesh = new DSubmesh3(Mesh, TriangleSetF(obj));
				bool lockTaken = false;
				data_lock.Enter(ref lockTaken);
				Submeshes.Add(dSubmesh);
				KeyToMesh[obj] = dSubmesh;
				data_lock.Exit();
			});
		}
	}
	public class EdgeLoop
	{
		public DMesh3 Mesh;

		public int[] Vertices;

		public int[] Edges;

		public int[] BowtieVertices;

		public int VertexCount => Vertices.Length;

		public int EdgeCount => Edges.Length;

		public EdgeLoop(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public EdgeLoop(DMesh3 mesh, int[] vertices, int[] edges, bool bCopyArrays)
		{
			Mesh = mesh;
			if (bCopyArrays)
			{
				Vertices = new int[vertices.Length];
				Array.Copy(vertices, Vertices, Vertices.Length);
				Edges = new int[edges.Length];
				Array.Copy(edges, Edges, Edges.Length);
			}
			else
			{
				Vertices = vertices;
				Edges = edges;
			}
		}

		public EdgeLoop(EdgeLoop copy)
		{
			Mesh = copy.Mesh;
			Vertices = new int[copy.Vertices.Length];
			Array.Copy(copy.Vertices, Vertices, Vertices.Length);
			Edges = new int[copy.Edges.Length];
			Array.Copy(copy.Edges, Edges, Edges.Length);
			if (copy.BowtieVertices != null)
			{
				BowtieVertices = new int[copy.BowtieVertices.Length];
				Array.Copy(copy.BowtieVertices, BowtieVertices, BowtieVertices.Length);
			}
		}

		public static EdgeLoop FromEdges(DMesh3 mesh, IList<int> edges)
		{
			int[] array = new int[edges.Count];
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = edges[i];
			}
			int[] array2 = new int[array.Length];
			Index2i ev = mesh.GetEdgeV(array[0]);
			Index2i ev2 = ev;
			for (int j = 1; j < array.Length; j++)
			{
				Index2i ev3 = mesh.GetEdgeV(array[j % array.Length]);
				array2[j] = IndexUtil.find_shared_edge_v(ref ev2, ref ev3);
				ev2 = ev3;
			}
			array2[0] = IndexUtil.find_edge_other_v(ref ev, array2[1]);
			return new EdgeLoop(mesh, array2, array, bCopyArrays: false);
		}

		public static EdgeLoop FromVertices(DMesh3 mesh, IList<int> vertices)
		{
			int count = vertices.Count;
			int[] array = new int[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = vertices[i];
			}
			int num = count;
			int[] array2 = new int[num];
			for (int j = 0; j < num; j++)
			{
				array2[j] = mesh.FindEdge(array[j], array[(j + 1) % num]);
				if (array2[j] == -1)
				{
					throw new Exception("EdgeLoop.FromVertices: vertices are not connected by edge!");
				}
			}
			return new EdgeLoop(mesh, array, array2, bCopyArrays: false);
		}

		public static EdgeLoop FromVertices(DMesh3 mesh, IList<int> vertices, bool bAutoOrient = true)
		{
			int[] array = new int[vertices.Count];
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = vertices[i];
			}
			if (bAutoOrient)
			{
				int num = array[0];
				int num2 = array[1];
				int num3 = mesh.FindEdge(num, num2);
				if (mesh.IsBoundaryEdge(num3))
				{
					Index2i orientedBoundaryEdgeV = mesh.GetOrientedBoundaryEdgeV(num3);
					if (orientedBoundaryEdgeV.a == num2 && orientedBoundaryEdgeV.b == num)
					{
						Array.Reverse(array);
					}
				}
			}
			int[] array2 = new int[array.Length];
			for (int j = 0; j < array2.Length; j++)
			{
				int vA = array[j];
				int vB = array[(j + 1) % array.Length];
				array2[j] = mesh.FindEdge(vA, vB);
				if (array2[j] == -1)
				{
					throw new Exception("EdgeLoop.FromVertices: invalid edge [" + vA + "," + vB + "]");
				}
			}
			return new EdgeLoop(mesh, array, array2, bCopyArrays: false);
		}

		public Vector3d GetVertex(int i)
		{
			return Mesh.GetVertex(Vertices[i]);
		}

		public AxisAlignedBox3d GetBounds()
		{
			AxisAlignedBox3d empty = AxisAlignedBox3d.Empty;
			for (int i = 0; i < Vertices.Length; i++)
			{
				empty.Contain(Mesh.GetVertex(Vertices[i]));
			}
			return empty;
		}

		public DCurve3 ToCurve(DMesh3 sourceMesh = null)
		{
