		public int FindNearestVertex(Vector3d v)
		{
			int result = -1;
			double num = double.MaxValue;
			int num2 = Vertices.Length;
			for (int i = 0; i < num2; i++)
			{
				Vector3d vertex = Mesh.GetVertex(Vertices[i]);
				double num3 = v.DistanceSquared(vertex);
				if (num3 < num)
