	public class MeshTriInfoCache
	{
		public DVector<Vector3d> Centroids;

		public DVector<Vector3d> Normals;

		public DVector<double> Areas;

		public MeshTriInfoCache(DMesh3 mesh)
		{
			MeshTriInfoCache meshTriInfoCache = this;
			int triangleCount = mesh.TriangleCount;
			Centroids = new DVector<Vector3d>();
			Centroids.resize(triangleCount);
			Normals = new DVector<Vector3d>();
			Normals.resize(triangleCount);
			Areas = new DVector<double>();
			Areas.resize(triangleCount);
			gParallel.ForEach(mesh.TriangleIndices(), delegate(int tid)
			{
				mesh.GetTriInfo(tid, out var normal, out var fArea, out var vCentroid);
				meshTriInfoCache.Centroids[tid] = vCentroid;
				meshTriInfoCache.Normals[tid] = normal;
				meshTriInfoCache.Areas[tid] = fArea;
			});
		}

		public void GetTriInfo(int tid, ref Vector3d n, ref double a, ref Vector3d c)
		{
			c = Centroids[tid];
			n = Normals[tid];
			a = Areas[tid];
		}
	}
	[Flags]
	public enum EdgeRefineFlags
	{
		NoConstraint = 0,
		NoFlip = 1,
		NoSplit = 2,
		NoCollapse = 4,
		FullyConstrained = 7,
		PreserveTopology = 8
	}
	public struct EdgeConstraint
	{
		private EdgeRefineFlags refineFlags;

		public IProjectionTarget Target;

		public int TrackingSetID;

		public static readonly EdgeConstraint Unconstrained;

		public static readonly EdgeConstraint NoFlips;

		public static readonly EdgeConstraint FullyConstrained;

		public bool CanFlip => (refineFlags & EdgeRefineFlags.NoFlip) == 0;

		public bool CanSplit => (refineFlags & EdgeRefineFlags.NoSplit) == 0;

		public bool CanCollapse => (refineFlags & EdgeRefineFlags.NoCollapse) == 0;

		public bool NoModifications => (refineFlags & EdgeRefineFlags.FullyConstrained) == EdgeRefineFlags.FullyConstrained;

		public bool IsUnconstrained
		{
			get
			{
				if (refineFlags == EdgeRefineFlags.NoConstraint)
				{
					return Target == null;
				}
				return false;
			}
		}

		public EdgeConstraint(EdgeRefineFlags rflags)
		{
			refineFlags = rflags;
			Target = null;
			TrackingSetID = -1;
		}

		public EdgeConstraint(EdgeRefineFlags rflags, IProjectionTarget target)
		{
			refineFlags = rflags;
			Target = target;
			TrackingSetID = -1;
		}

		static EdgeConstraint()
		{
			Unconstrained = new EdgeConstraint
			{
				refineFlags = EdgeRefineFlags.NoConstraint,
				TrackingSetID = -1
			};
			NoFlips = new EdgeConstraint
			{
				refineFlags = EdgeRefineFlags.NoFlip,
				TrackingSetID = -1
			};
			FullyConstrained = new EdgeConstraint
			{
				refineFlags = EdgeRefineFlags.FullyConstrained,
				TrackingSetID = -1
			};
		}
	}
	public struct VertexConstraint
	{
		public bool Fixed;

		public int FixedSetID;

		public IProjectionTarget Target;

		public const int InvalidSetID = -1;

		public static readonly VertexConstraint Unconstrained;

		public static readonly VertexConstraint Pinned;

		public VertexConstraint(bool isFixed, int setID = -1)
		{
			Fixed = isFixed;
			FixedSetID = setID;
			Target = null;
		}

		public VertexConstraint(IProjectionTarget target)
		{
			Fixed = false;
			FixedSetID = -1;
			Target = target;
		}

		static VertexConstraint()
		{
			Unconstrained = new VertexConstraint
			{
				Fixed = false,
				FixedSetID = -1,
				Target = null
			};
			Pinned = new VertexConstraint
			{
				Fixed = true,
				FixedSetID = -1,
				Target = null
			};
		}
	}
	public class MeshConstraints
	{
		private Dictionary<int, EdgeConstraint> Edges = new Dictionary<int, EdgeConstraint>();

		private int set_id_counter;

		private Dictionary<int, VertexConstraint> Vertices = new Dictionary<int, VertexConstraint>();

		public bool HasConstraints
		{
			get
			{
				if (Edges.Count <= 0)
				{
					return Vertices.Count > 0;
				}
				return true;
			}
		}

		public MeshConstraints()
		{
			set_id_counter = 0;
		}

		public int AllocateSetID()
		{
			return set_id_counter++;
		}

		public bool HasEdgeConstraint(int eid)
		{
			return Edges.ContainsKey(eid);
		}

		public EdgeConstraint GetEdgeConstraint(int eid)
		{
			if (Edges.TryGetValue(eid, out var value))
			{
				return value;
			}
			return EdgeConstraint.Unconstrained;
		}

		public void SetOrUpdateEdgeConstraint(int eid, EdgeConstraint ec)
		{
			Edges[eid] = ec;
		}

		public void ClearEdgeConstraint(int eid)
		{
			Edges.Remove(eid);
		}

		public List<int> FindConstrainedEdgesBySetID(int setID)
		{
			List<int> list = new List<int>();
			foreach (KeyValuePair<int, EdgeConstraint> edge in Edges)
			{
				if (edge.Value.TrackingSetID == setID)
				{
					list.Add(edge.Key);
				}
			}
			return list;
		}

		public bool HasVertexConstraint(int vid)
		{
			return Vertices.ContainsKey(vid);
		}

		public VertexConstraint GetVertexConstraint(int vid)
		{
			if (Vertices.TryGetValue(vid, out var value))
			{
				return value;
			}
			return VertexConstraint.Unconstrained;
		}

		public bool GetVertexConstraint(int vid, ref VertexConstraint vc)
		{
			return Vertices.TryGetValue(vid, out vc);
		}

		public void SetOrUpdateVertexConstraint(int vid, VertexConstraint vc)
		{
			Vertices[vid] = vc;
		}

		public void ClearVertexConstraint(int vid)
		{
			Vertices.Remove(vid);
		}

		public IEnumerable VertexConstraintsItr()
		{
			foreach (KeyValuePair<int, VertexConstraint> vertex in Vertices)
			{
				yield return vertex;
			}
		}
	}
	public static class MeshConstraintUtil
	{
		public static void FixEdges(MeshConstraints cons, DMesh3 mesh, IEnumerable<int> edges)
		{
			foreach (int edge in edges)
			{
				if (mesh.IsEdge(edge))
				{
					cons.SetOrUpdateEdgeConstraint(edge, EdgeConstraint.FullyConstrained);
					Index2i edgeV = mesh.GetEdgeV(edge);
					cons.SetOrUpdateVertexConstraint(edgeV.a, VertexConstraint.Pinned);
					cons.SetOrUpdateVertexConstraint(edgeV.b, VertexConstraint.Pinned);
				}
			}
		}

		public static void FixAllBoundaryEdges(MeshConstraints cons, DMesh3 mesh)
		{
			int maxEdgeID = mesh.MaxEdgeID;
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (mesh.IsEdge(i) && mesh.IsBoundaryEdge(i))
				{
					cons.SetOrUpdateEdgeConstraint(i, EdgeConstraint.FullyConstrained);
					Index2i edgeV = mesh.GetEdgeV(i);
					cons.SetOrUpdateVertexConstraint(edgeV.a, VertexConstraint.Pinned);
					cons.SetOrUpdateVertexConstraint(edgeV.b, VertexConstraint.Pinned);
				}
			}
		}

		public static void FixAllBoundaryEdges(Remesher r)
		{
			if (r.Constraints == null)
			{
				r.SetExternalConstraints(new MeshConstraints());
			}
			FixAllBoundaryEdges(r.Constraints, r.Mesh);
		}

		public static void FixAllBoundaryEdges_AllowCollapse(MeshConstraints cons, DMesh3 mesh, int setID)
		{
			EdgeConstraint ec = new EdgeConstraint(EdgeRefineFlags.NoFlip | EdgeRefineFlags.NoSplit);
			VertexConstraint vc = new VertexConstraint(isFixed: true, setID);
			int maxEdgeID = mesh.MaxEdgeID;
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (mesh.IsEdge(i) && mesh.IsBoundaryEdge(i))
				{
					cons.SetOrUpdateEdgeConstraint(i, ec);
					Index2i edgeV = mesh.GetEdgeV(i);
					cons.SetOrUpdateVertexConstraint(edgeV.a, vc);
					cons.SetOrUpdateVertexConstraint(edgeV.b, vc);
				}
			}
		}

		public static void FixAllBoundaryEdges_AllowSplit(MeshConstraints cons, DMesh3 mesh, int setID)
		{
			EdgeConstraint ec = new EdgeConstraint(EdgeRefineFlags.NoFlip | EdgeRefineFlags.NoCollapse);
			VertexConstraint vc = new VertexConstraint(isFixed: true, setID);
			int maxEdgeID = mesh.MaxEdgeID;
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (mesh.IsEdge(i) && mesh.IsBoundaryEdge(i))
				{
					cons.SetOrUpdateEdgeConstraint(i, ec);
					Index2i edgeV = mesh.GetEdgeV(i);
					cons.SetOrUpdateVertexConstraint(edgeV.a, vc);
					cons.SetOrUpdateVertexConstraint(edgeV.b, vc);
				}
			}
		}

		public static void FixSubmeshBoundaryEdges(MeshConstraints cons, DSubmesh3 sub)
		{
			foreach (int item in sub.BaseBorderE)
			{
				Index2i edgeV = sub.BaseMesh.GetEdgeV(item);
				Index2i index2i = sub.MapVerticesToSubmesh(edgeV);
				int eid = sub.SubMesh.FindEdge(index2i.a, index2i.b);
				cons.SetOrUpdateEdgeConstraint(eid, EdgeConstraint.FullyConstrained);
				cons.SetOrUpdateVertexConstraint(index2i.a, VertexConstraint.Pinned);
				cons.SetOrUpdateVertexConstraint(index2i.b, VertexConstraint.Pinned);
			}
		}

		public static void FixAllGroupBoundaryEdges(MeshConstraints cons, DMesh3 mesh, bool bPinVertices)
		{
			int maxEdgeID = mesh.MaxEdgeID;
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (mesh.IsEdge(i) && mesh.IsGroupBoundaryEdge(i))
				{
					cons.SetOrUpdateEdgeConstraint(i, EdgeConstraint.FullyConstrained);
					if (bPinVertices)
					{
						Index2i edgeV = mesh.GetEdgeV(i);
						cons.SetOrUpdateVertexConstraint(edgeV.a, VertexConstraint.Pinned);
						cons.SetOrUpdateVertexConstraint(edgeV.b, VertexConstraint.Pinned);
					}
				}
			}
		}

		public static void FixAllGroupBoundaryEdges(Remesher r, bool bPinVertices)
		{
			if (r.Constraints == null)
			{
				r.SetExternalConstraints(new MeshConstraints());
			}
			FixAllGroupBoundaryEdges(r.Constraints, r.Mesh, bPinVertices);
		}

		public static void ConstrainVtxLoopTo(MeshConstraints cons, DMesh3 mesh, IList<int> loopV, IProjectionTarget target, int setID = -1)
		{
			VertexConstraint vc = new VertexConstraint(target);
			int count = loopV.Count;
			for (int i = 0; i < count; i++)
			{
				cons.SetOrUpdateVertexConstraint(loopV[i], vc);
			}
			EdgeConstraint ec = new EdgeConstraint(EdgeRefineFlags.NoFlip, target);
			ec.TrackingSetID = setID;
			for (int j = 0; j < count; j++)
			{
				int vA = loopV[j];
				int vB = loopV[(j + 1) % count];
				int num = mesh.FindEdge(vA, vB);
				if (num != -1)
				{
					cons.SetOrUpdateEdgeConstraint(num, ec);
				}
			}
		}

		public static void ConstrainVtxLoopTo(Remesher r, int[] loopV, IProjectionTarget target, int setID = -1)
		{
			if (r.Constraints == null)
			{
				r.SetExternalConstraints(new MeshConstraints());
			}
			ConstrainVtxLoopTo(r.Constraints, r.Mesh, loopV, target);
		}

		public static void ConstrainVtxSpanTo(MeshConstraints cons, DMesh3 mesh, IList<int> spanV, IProjectionTarget target, int setID = -1)
		{
			VertexConstraint vc = new VertexConstraint(target);
			int count = spanV.Count;
			for (int i = 1; i < count - 1; i++)
			{
				cons.SetOrUpdateVertexConstraint(spanV[i], vc);
			}
			cons.SetOrUpdateVertexConstraint(spanV[0], VertexConstraint.Pinned);
			cons.SetOrUpdateVertexConstraint(spanV[count - 1], VertexConstraint.Pinned);
			EdgeConstraint ec = new EdgeConstraint(EdgeRefineFlags.NoFlip, target);
			ec.TrackingSetID = setID;
			for (int j = 0; j < count - 1; j++)
			{
				int vA = spanV[j];
				int vB = spanV[j + 1];
				int num = mesh.FindEdge(vA, vB);
				if (num != -1)
				{
					cons.SetOrUpdateEdgeConstraint(num, ec);
				}
			}
		}

		public static void ConstrainVtxSpanTo(Remesher r, int[] spanV, IProjectionTarget target, int setID = -1)
		{
			if (r.Constraints == null)
			{
				r.SetExternalConstraints(new MeshConstraints());
			}
			ConstrainVtxSpanTo(r.Constraints, r.Mesh, spanV, target);
		}

		public static void PreserveBoundaryLoops(MeshConstraints cons, DMesh3 mesh)
		{
			foreach (EdgeLoop item in new MeshBoundaryLoops(mesh))
			{
				DCurveProjectionTarget target = new DCurveProjectionTarget(MeshUtil.ExtractLoopV(mesh, item.Vertices));
				ConstrainVtxLoopTo(cons, mesh, item.Vertices, target);
			}
		}

		public static void PreserveBoundaryLoops(Remesher r)
		{
			if (r.Constraints == null)
			{
				r.SetExternalConstraints(new MeshConstraints());
			}
			PreserveBoundaryLoops(r.Constraints, r.Mesh);
		}

		public static void AddTrackedEdges(MeshConstraints cons, int[] edges, int setID)
		{
			EdgeConstraint unconstrained = EdgeConstraint.Unconstrained;
			unconstrained.TrackingSetID = setID;
			for (int i = 0; i < edges.Length; i++)
			{
				cons.SetOrUpdateEdgeConstraint(edges[i], unconstrained);
			}
		}
	}
	public interface IMeshComponentManager
	{
		void AddComponent(MeshDecomposition.Component C);

		void ClearAllComponents();
	}
	public class MeshDecomposition
	{
		public struct Component
		{
			public int id;

			public int[] triangles;

			public int tri_count;

			public int[] source_vertices;
		}

		private DMesh3 mesh;

		public bool TrackVertexMapping = true;

		private Index2i[] mapTo;

		private DVector<int> mapToMulti;

		public int MaxComponentSize { get; set; }

		public IMeshComponentManager Manager { get; set; }

		public MeshDecomposition(DMesh3 mesh, IMeshComponentManager manager)
		{
			MaxComponentSize = 62000;
			this.mesh = mesh;
			Manager = manager;
		}

		public void BuildLinear()
		{
			int maxVertexID = mesh.MaxVertexID;
			if (TrackVertexMapping)
			{
				mapTo = new Index2i[maxVertexID];
				for (int i = 0; i < maxVertexID; i++)
				{
					mapTo[i] = Index2i.Zero;
				}
				mapToMulti = new DVector<int>();
			}
			int[] mapToCur = new int[maxVertexID];
			Array.Clear(mapToCur, 0, mapToCur.Length);
			_ = mesh.MaxTriangleID;
			int[] cur_subt = new int[MaxComponentSize];
			int subti = 0;
			int subi = 1;
			int[] cur_subv = new int[MaxComponentSize];
			BitArray vert_bits = new BitArray(mesh.MaxVertexID);
			int subvcount = 0;
			Action action = delegate
			{
				Index2i mapRange;
				int max_subv;
				Component c = extract_submesh(subi++, cur_subt, subti, mapToCur, cur_subv, out mapRange, out max_subv);
				Manager.AddComponent(c);
				Array.Clear(cur_subt, 0, subti);
				subti = 0;
				Array.Clear(mapToCur, mapRange.a, mapRange.b - mapRange.a + 1);
				Array.Clear(cur_subv, 0, max_subv);
				subvcount = 0;
				vert_bits.SetAll(value: false);
			};
			int[] tri_order_by_axis_sort = get_tri_order_by_axis_sort();
			int num = tri_order_by_axis_sort.Length;
			for (int num2 = 0; num2 < num; num2++)
			{
				int num3 = tri_order_by_axis_sort[num2];
				Index3i triangle = mesh.GetTriangle(num3);
				if (!vert_bits[triangle.a])
				{
					vert_bits[triangle.a] = true;
					subvcount++;
				}
				if (!vert_bits[triangle.b])
				{
					vert_bits[triangle.b] = true;
					subvcount++;
				}
				if (!vert_bits[triangle.c])
				{
					vert_bits[triangle.c] = true;
					subvcount++;
				}
				cur_subt[subti++] = num3;
				if (subti == MaxComponentSize || subvcount > MaxComponentSize - 3)
				{
					action();
				}
			}
			if (subti > 0)
			{
				action();
			}
		}

		private int[] get_tri_order_by_axis_sort()
		{
			int num = 0;
			int[] array = new int[mesh.TriangleCount];
			int maxTriangleID = mesh.MaxTriangleID;
			for (int i = 0; i < maxTriangleID; i++)
			{
				if (mesh.IsTriangle(i))
				{
					array[num++] = i;
				}
			}
			Vector3d[] centroids = new Vector3d[mesh.MaxTriangleID];
			gParallel.ForEach(mesh.TriangleIndices(), delegate(int ti)
			{
				if (mesh.IsTriangle(ti))
				{
					centroids[ti] = mesh.GetTriCentroid(ti);
				}
			});
			Array.Sort(array, delegate(int t0, int t1)
			{
				double x = centroids[t0].x;
				double x2 = centroids[t1].x;
				return (x != x2) ? ((!(x < x2)) ? 1 : (-1)) : 0;
			});
			return array;
		}

		private Component extract_submesh(int submesh_index, int[] subt, int Nt, int[] mapToCur, int[] subv, out Index2i mapRange, out int max_subv)
		{
			int num = 0;
			Component result = new Component
			{
				id = submesh_index,
				triangles = new int[Nt * 3],
				tri_count = Nt
			};
			mapRange = new Index2i(int.MaxValue, int.MinValue);
			for (int i = 0; i < Nt; i++)
			{
				int tID = subt[i];
				Index3i triangle = mesh.GetTriangle(tID);
				for (int j = 0; j < 3; j++)
				{
					int num2 = triangle[j];
					if (mapToCur[num2] == 0)
					{
						mapToCur[num2] = num + 1;
						subv[num] = num2;
						if (num2 < mapRange.a)
						{
							mapRange.a = num2;
						}
						else if (num2 > mapRange.b)
						{
							mapRange.b = num2;
						}
						if (TrackVertexMapping)
						{
							add_submesh_mapv(num2, result.id, num);
						}
						num++;
					}
					result.triangles[3 * i + j] = mapToCur[num2] - 1;
				}
			}
			result.source_vertices = new int[num];
			Array.Copy(subv, result.source_vertices, num);
			max_subv = num;
			return result;
		}

		private void add_submesh_mapv(int orig_vid, int submesh_i, int submesh_vid)
		{
			if (mapTo[orig_vid].a == 0)
			{
				mapTo[orig_vid].a = submesh_i;
				mapTo[orig_vid].b = submesh_vid;
			}
			else if (mapTo[orig_vid].a > 0)
			{
				int size = mapToMulti.size;
				mapToMulti.push_back(mapTo[orig_vid].a);
				mapToMulti.push_back(mapTo[orig_vid].b);
				mapToMulti.push_back(-1);
				int size2 = mapToMulti.size;
				mapToMulti.push_back(submesh_i);
				mapToMulti.push_back(submesh_vid);
				mapToMulti.push_back(size);
				mapTo[orig_vid].a = -2;
				mapTo[orig_vid].b = size2;
			}
			else
			{
				mapTo[orig_vid].a--;
				int b = mapTo[orig_vid].b;
				int size3 = mapToMulti.size;
				mapToMulti.push_back(submesh_i);
				mapToMulti.push_back(submesh_vid);
				mapToMulti.push_back(b);
				mapTo[orig_vid].b = size3;
			}
		}
	}
	public class MeshEditor
	{
		public enum DuplicateTriBehavior
		{
			AssertContinue,
			AssertAbort,
			UseExisting,
			Replace
		}

		public DMesh3 Mesh;

		public MeshEditor(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public virtual int[] AddTriangleStrip(IList<Frame3f> frames, IList<Interval1d> spans, int group_id = -1)
		{
			int count = frames.Count;
			if (count != spans.Count)
			{
				throw new Exception("MeshEditor.AddTriangleStrip: spans list is not the same size!");
			}
			int[] array = new int[2 * (count - 1)];
			int num = -1;
			int v = -1;
			int num2 = 0;
			int num3 = 0;
			for (num2 = 0; num2 < count; num2++)
			{
				Frame3f frame3f = frames[num2];
				Interval1d interval1d = spans[num2];
				Vector3d v2 = frame3f.Origin + (float)interval1d.a * frame3f.Y;
				Vector3d v3 = frame3f.Origin + (float)interval1d.b * frame3f.Y;
				int num4 = Mesh.AppendVertex(v2);
				int num5 = Mesh.AppendVertex(v3);
				if (num != -1)
				{
					array[num3++] = Mesh.AppendTriangle(num, num5, v);
					array[num3++] = Mesh.AppendTriangle(num, num4, num5);
				}
				num = num4;
				v = num5;
			}
			return array;
		}

		public virtual int[] AddTriangleFan_OrderedVertexLoop(int center, int[] vertex_loop, int group_id = -1)
		{
			int num = vertex_loop.Length;
			int[] array = new int[num];
			int num2 = 0;
			num2 = 0;
			while (true)
			{
				if (num2 < num)
				{
					int kk = vertex_loop[num2];
					int jj = vertex_loop[(num2 + 1) % num];
					Index3i tv = new Index3i(center, jj, kk);
					int num3 = Mesh.AppendTriangle(tv, group_id);
					if (num3 < 0)
					{
						break;
					}
					array[num2] = num3;
					num2++;
					continue;
				}
				return array;
			}
			if (num2 > 0 && !remove_triangles(array, num2))
			{
				throw new Exception("MeshEditor.AddTriangleFan_OrderedVertexLoop: failed to add fan, and also falied to back out changes.");
			}
			return null;
		}

		public virtual int[] AddTriangleFan_OrderedEdgeLoop(int center, int[] edge_loop, int group_id = -1)
		{
			int num = edge_loop.Length;
			int[] array = new int[num];
			int num2 = 0;
			num2 = 0;
			while (true)
			{
				if (num2 < num)
				{
					if (!Mesh.IsBoundaryEdge(edge_loop[num2]))
					{
						break;
					}
					Index2i orientedBoundaryEdgeV = Mesh.GetOrientedBoundaryEdgeV(edge_loop[num2]);
					int a = orientedBoundaryEdgeV.a;
					int b = orientedBoundaryEdgeV.b;
					Index3i tv = new Index3i(center, b, a);
					int num3 = Mesh.AppendTriangle(tv, group_id);
					if (num3 < 0)
					{
						break;
					}
					array[num2] = num3;
					num2++;
					continue;
				}
				return array;
			}
			if (num2 > 0 && !remove_triangles(array, num2 - 1))
			{
				throw new Exception("MeshEditor.AddTriangleFan_OrderedEdgeLoop: failed to add fan, and also failed to back out changes.");
			}
			return null;
		}

		public virtual int[] StitchLoop(int[] vloop1, int[] vloop2, int group_id = -1)
		{
			int num = vloop1.Length;
			if (num != vloop2.Length)
			{
				throw new Exception("MeshEditor.StitchLoop: loops are not the same length!!");
			}
			int[] array = new int[num * 2];
			int num2 = 0;
			while (true)
			{
				if (num2 < num)
				{
					int num3 = vloop1[num2];
					int ii = vloop1[(num2 + 1) % num];
					int jj = vloop2[num2];
					int kk = vloop2[(num2 + 1) % num];
					Index3i tv = new Index3i(ii, num3, kk);
					Index3i tv2 = new Index3i(num3, jj, kk);
					int num4 = Mesh.AppendTriangle(tv, group_id);
					int num5 = Mesh.AppendTriangle(tv2, group_id);
					array[2 * num2] = num4;
					array[2 * num2 + 1] = num5;
					if (num4 < 0 || num5 < 0)
					{
						break;
					}
					num2++;
					continue;
				}
				return array;
			}
			if (num2 > 0 && !remove_triangles(array, 2 * num2 + 1))
			{
				throw new Exception("MeshEditor.StitchLoop: failed to add all triangles, and also failed to back out changes.");
			}
			return null;
		}

		public virtual int[] StitchVertexLoops_NearestV(int[] loop0, int[] loop1, int group_id = -1)
		{
			int num = loop0.Length;
			Index2i index2i = Index2i.Zero;
			double num2 = double.MaxValue;
			for (int i = 0; i < num; i++)
			{
				Vector3d vertex = Mesh.GetVertex(loop0[i]);
				for (int j = 0; j < num; j++)
				{
					double num3 = vertex.DistanceSquared(Mesh.GetVertex(loop1[j]));
					if (num3 < num2)
					{
						num2 = num3;
						index2i = new Index2i(i, j);
					}
				}
			}
			if (index2i.a != index2i.b)
			{
				int[] array = new int[num];
				int[] array2 = new int[num];
				for (int k = 0; k < num; k++)
				{
					array[k] = loop0[(index2i.a + k) % num];
					array2[k] = loop1[(index2i.b + k) % num];
				}
				return StitchLoop(array, array2, group_id);
			}
			return StitchLoop(loop0, loop1, group_id);
		}

		public virtual int[] StitchUnorderedEdges(List<Index2i> EdgePairs, int group_id, bool bAbortOnFailure, out bool stitch_incomplete)
		{
			int count = EdgePairs.Count;
			int[] array = new int[count * 2];
			if (!bAbortOnFailure)
			{
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = -1;
				}
			}
			stitch_incomplete = false;
			int num = 0;
			while (true)
			{
				if (num < count)
				{
					Index2i index2i = EdgePairs[num];
					Index4i edge = Mesh.GetEdge(index2i.a);
					if (edge.d != -1)
					{
						if (bAbortOnFailure)
						{
							break;
						}
						stitch_incomplete = true;
					}
					else
					{
						Index3i triangle = Mesh.GetTriangle(edge.c);
						int a = edge.a;
						int b = edge.b;
						IndexUtil.orient_tri_edge(ref a, ref b, triangle);
						Index4i edge2 = Mesh.GetEdge(index2i.b);
						if (edge2.d != -1)
						{
							if (bAbortOnFailure)
							{
								break;
							}
							stitch_incomplete = true;
						}
						else
						{
							Index3i triangle2 = Mesh.GetTriangle(edge2.c);
							int a2 = edge2.a;
							int b2 = edge2.b;
							IndexUtil.orient_tri_edge(ref a2, ref b2, triangle2);
							int num2 = a2;
							a2 = b2;
							b2 = num2;
							Index3i tv = new Index3i(b, a, b2);
							Index3i tv2 = new Index3i(a, a2, b2);
							int num3 = Mesh.AppendTriangle(tv, group_id);
							int num4 = Mesh.AppendTriangle(tv2, group_id);
							if (num3 < 0 || num4 < 0)
							{
								if (bAbortOnFailure)
								{
									break;
								}
								stitch_incomplete = true;
							}
							else
							{
								array[2 * num] = num3;
								array[2 * num + 1] = num4;
							}
						}
					}
					num++;
					continue;
				}
				return array;
			}
			if (num > 0 && !remove_triangles(array, 2 * (num - 1)))
			{
				throw new Exception("MeshEditor.StitchLoop: failed to add all triangles, and also failed to back out changes.");
			}
			return null;
		}

		public virtual int[] StitchUnorderedEdges(List<Index2i> EdgePairs, int group_id = -1, bool bAbortOnFailure = true)
		{
			bool stitch_incomplete = false;
			return StitchUnorderedEdges(EdgePairs, group_id, bAbortOnFailure, out stitch_incomplete);
		}

		public virtual int[] StitchSpan(IList<int> vspan1, IList<int> vspan2, int group_id = -1)
		{
			int count = vspan1.Count;
			if (count != vspan2.Count)
			{
				throw new Exception("MeshEditor.StitchSpan: spans are not the same length!!");
			}
			count--;
			int[] array = new int[count * 2];
			int num = 0;
			while (true)
			{
				if (num < count)
				{
					int num2 = vspan1[num];
					int ii = vspan1[num + 1];
					int jj = vspan2[num];
					int kk = vspan2[num + 1];
					Index3i tv = new Index3i(ii, num2, kk);
					Index3i tv2 = new Index3i(num2, jj, kk);
					int num3 = Mesh.AppendTriangle(tv, group_id);
					int num4 = Mesh.AppendTriangle(tv2, group_id);
					if (num3 < 0 || num4 < 0)
					{
						break;
					}
					array[2 * num] = num3;
					array[2 * num + 1] = num4;
					num++;
					continue;
				}
				return array;
			}
			if (num > 0 && !remove_triangles(array, 2 * (num - 1)))
			{
				throw new Exception("MeshEditor.StitchLoop: failed to add all triangles, and also failed to back out changes.");
			}
			return null;
		}

		public bool RemoveTriangles(IList<int> triangles, bool bRemoveIsolatedVerts)
		{
			bool result = true;
			for (int i = 0; i < triangles.Count; i++)
			{
				if (triangles[i] != -1 && Mesh.RemoveTriangle(triangles[i], bRemoveIsolatedVerts) != MeshResult.Ok)
				{
					result = false;
				}
			}
			return result;
		}

		public bool RemoveTriangles(IEnumerable<int> triangles, bool bRemoveIsolatedVerts)
		{
			bool result = true;
			foreach (int triangle in triangles)
			{
				if (!Mesh.IsTriangle(triangle))
				{
					result = false;
				}
				else if (Mesh.RemoveTriangle(triangle, bRemoveIsolatedVerts) != MeshResult.Ok)
				{
					result = false;
				}
			}
			return result;
		}

		public bool RemoveTriangles(Func<int, bool> selectorF, bool bRemoveIsolatedVerts)
		{
			bool result = true;
			int maxTriangleID = Mesh.MaxTriangleID;
			for (int i = 0; i < maxTriangleID; i++)
			{
				if (Mesh.IsTriangle(i) && selectorF(i) && Mesh.RemoveTriangle(i, bRemoveIsolatedVerts) != MeshResult.Ok)
				{
					result = false;
				}
			}
			return result;
		}

		public static bool RemoveTriangles(DMesh3 Mesh, IList<int> triangles, bool bRemoveIsolatedVerts = true)
		{
			return new MeshEditor(Mesh).RemoveTriangles(triangles, bRemoveIsolatedVerts);
		}

		public static bool RemoveTriangles(DMesh3 Mesh, IEnumerable<int> triangles, bool bRemoveIsolatedVerts = true)
		{
			return new MeshEditor(Mesh).RemoveTriangles(triangles, bRemoveIsolatedVerts);
		}

		public static bool RemoveIsolatedTriangles(DMesh3 mesh)
		{
			return new MeshEditor(mesh).RemoveTriangles(delegate(int tid)
			{
				Index3i triNeighbourTris = mesh.GetTriNeighbourTris(tid);
				return triNeighbourTris.a == -1 && triNeighbourTris.b == -1 && triNeighbourTris.c == -1;
			}, bRemoveIsolatedVerts: true);
		}

		public static int RemoveFinTriangles(DMesh3 mesh, Func<DMesh3, int, bool> removeF = null, bool bRepeatToConvergence = true)
		{
			new MeshEditor(mesh);
			int num = 0;
			List<int> list = new List<int>();
			do
			{
				foreach (int item in mesh.TriangleIndices())
				{
					Index3i triNeighbourTris = mesh.GetTriNeighbourTris(item);
					if (((triNeighbourTris.a != -1) ? 1 : 0) + ((triNeighbourTris.b != -1) ? 1 : 0) + ((triNeighbourTris.c != -1) ? 1 : 0) <= 1 && (removeF == null || removeF(mesh, item)))
					{
						list.Add(item);
					}
				}
				if (list.Count == 0)
				{
					return num;
				}
				num += list.Count;
				RemoveTriangles(mesh, list);
				list.Clear();
			}
			while (bRepeatToConvergence);
			return num;
		}

		public bool SeparateTriangles(IEnumerable<int> triangles, bool bComputeEdgePairs, out List<Index2i> EdgePairs)
		{
			HashSet<int> hashSet = new HashSet<int>(triangles);
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			EdgePairs = null;
			HashSet<int> hashSet2 = null;
			List<Index2i> list = null;
			if (bComputeEdgePairs)
			{
				EdgePairs = new List<Index2i>();
				hashSet2 = new HashSet<int>();
				list = new List<Index2i>();
			}
			foreach (int triangle2 in triangles)
			{
				Index3i triEdges = Mesh.GetTriEdges(triangle2);
				for (int i = 0; i < 3; i++)
				{
					Index2i edgeT = Mesh.GetEdgeT(triEdges[i]);
					if (edgeT.b == -1 || (edgeT.a == triangle2 && hashSet.Contains(edgeT.b)) || (edgeT.b == triangle2 && hashSet.Contains(edgeT.a)))
					{
						triEdges[i] = -1;
					}
				}
				for (int j = 0; j < 3; j++)
				{
					if (triEdges[j] != -1)
					{
						Index2i edgeV = Mesh.GetEdgeV(triEdges[j]);
						if (!dictionary.ContainsKey(edgeV.a))
						{
							dictionary[edgeV.a] = Mesh.AppendVertex(Mesh, edgeV.a);
						}
						if (!dictionary.ContainsKey(edgeV.b))
						{
							dictionary[edgeV.b] = Mesh.AppendVertex(Mesh, edgeV.b);
						}
						if (bComputeEdgePairs && !hashSet2.Contains(triEdges[j]))
						{
							hashSet2.Add(triEdges[j]);
							list.Add(edgeV);
							EdgePairs.Add(new Index2i(triEdges[j], -1));
						}
					}
				}
			}
			foreach (int triangle3 in triangles)
			{
				Index3i triangle = Mesh.GetTriangle(triangle3);
				Index3i index3i = triangle;
				for (int k = 0; k < 3; k++)
				{
					if (dictionary.TryGetValue(triangle[k], out var value))
					{
						index3i[k] = value;
					}
				}
				if (index3i != triangle)
				{
					Mesh.SetTriangle(triangle3, index3i);
				}
			}
			if (bComputeEdgePairs)
			{
				for (int l = 0; l < EdgePairs.Count; l++)
				{
					Index2i index2i = list[l];
					int vA = dictionary[index2i.a];
					int vB = dictionary[index2i.b];
					int jj = Mesh.FindEdge(vA, vB);
					EdgePairs[l] = new Index2i(EdgePairs[l].a, jj);
				}
			}
			return true;
		}

		public List<int> DuplicateTriangles(IEnumerable<int> triangles, ref IndexMap MapV, int group_id = -1)
		{
			List<int> list = new List<int>();
			foreach (int triangle2 in triangles)
			{
				Index3i triangle = Mesh.GetTriangle(triangle2);
				for (int i = 0; i < 3; i++)
				{
					int num = triangle[i];
					if (!MapV.Contains(num))
					{
						int value = Mesh.AppendVertex(Mesh, num);
						MapV[num] = value;
						triangle[i] = value;
					}
					else
					{
						triangle[i] = MapV[num];
					}
				}
				int item = Mesh.AppendTriangle(triangle, group_id);
				list.Add(item);
			}
			return list;
		}

		public void ReverseTriangles(IEnumerable<int> triangles, bool bFlipVtxNormals = true)
		{
			if (!bFlipVtxNormals)
			{
				foreach (int triangle2 in triangles)
				{
					Mesh.ReverseTriOrientation(triangle2);
				}
				return;
			}
			BitArray bitArray = new BitArray(Mesh.MaxVertexID);
			foreach (int triangle3 in triangles)
			{
				Mesh.ReverseTriOrientation(triangle3);
				Index3i triangle = Mesh.GetTriangle(triangle3);
				for (int i = 0; i < 3; i++)
				{
					int num = triangle[i];
					if (!bitArray[num])
					{
						Mesh.SetVertexNormal(num, -Mesh.GetVertexNormal(num));
						bitArray[num] = true;
					}
				}
			}
		}

		public void DisconnectBowtie(int vid)
		{
			List<List<int>> list = new List<List<int>>();
			foreach (int item2 in Mesh.VtxTrianglesItr(vid))
			{
				Index3i triNeighbourTris = Mesh.GetTriNeighbourTris(item2);
				bool flag = false;
				foreach (List<int> item3 in list)
				{
					if (item3.Contains(triNeighbourTris.a) || item3.Contains(triNeighbourTris.b) || item3.Contains(triNeighbourTris.c))
					{
						item3.Add(item2);
						flag = true;
						break;
					}
				}
				if (!flag)
				{
					List<int> item = new List<int> { item2 };
					list.Add(item);
				}
			}
			if (list.Count == 1)
			{
				return;
			}
			list.Sort(bowtie_sorter);
			for (int i = 1; i < list.Count; i++)
			{
				int num = Mesh.AppendVertex(Mesh, vid);
				foreach (int item4 in list[i])
				{
					Index3i triangle = Mesh.GetTriangle(item4);
					if (triangle.a == vid)
					{
						triangle.a = num;
					}
					else if (triangle.b == vid)
					{
						triangle.b = num;
					}
					else
					{
						triangle.c = num;
					}
					Mesh.SetTriangle(item4, triangle, bRemoveIsolatedVertices: false);
				}
			}
		}

		private static int bowtie_sorter(List<int> l1, List<int> l2)
		{
			if (l1.Count == l2.Count)
			{
				return 0;
			}
			if (l1.Count <= l2.Count)
			{
				return 1;
			}
			return -1;
		}

		public int DisconnectAllBowties(int nMaxIters = 10)
		{
			List<int> list = new List<int>(MeshIterators.BowtieVertices(Mesh));
			int num = 0;
			while (list.Count > 0 && num++ < nMaxIters)
			{
				foreach (int item in list)
				{
					DisconnectBowtie(item);
				}
				list = new List<int>(MeshIterators.BowtieVertices(Mesh));
			}
			return list.Count;
		}

		public bool ReinsertSubmesh(DSubmesh3 sub, ref int[] new_tris, out IndexMap SubToNewV, DuplicateTriBehavior eDuplicateBehavior = DuplicateTriBehavior.AssertAbort)
		{
			if (sub.BaseBorderV == null)
			{
				throw new Exception("MeshEditor.ReinsertSubmesh: Submesh does not have required boundary info. Call ComputeBoundaryInfo()!");
			}
			DMesh3 subMesh = sub.SubMesh;
			bool result = true;
			IndexFlagSet indexFlagSet = new IndexFlagSet(subMesh.MaxVertexID, subMesh.TriangleCount / 2);
			SubToNewV = new IndexMap(subMesh.MaxVertexID, subMesh.VertexCount);
			int num = 0;
			int maxTriangleID = subMesh.MaxTriangleID;
			for (int i = 0; i < maxTriangleID; i++)
			{
				if (!subMesh.IsTriangle(i))
				{
					continue;
				}
				Index3i triangle = subMesh.GetTriangle(i);
				int triangleGroup = subMesh.GetTriangleGroup(i);
				Index3i zero = Index3i.Zero;
				for (int j = 0; j < 3; j++)
				{
					int num2 = triangle[j];
					int num3 = -1;
					if (!indexFlagSet[num2])
					{
						if (subMesh.IsBoundaryVertex(num2))
						{
							int num4 = ((num2 < sub.SubToBaseV.size) ? sub.SubToBaseV[num2] : (-1));
							if (num4 >= 0 && Mesh.IsVertex(num4) && sub.BaseBorderV[num4] && Mesh.IsBoundaryVertex(num4))
							{
								num3 = num4;
							}
						}
						if (num3 == -1)
						{
							num3 = Mesh.AppendVertex(subMesh, num2);
						}
						SubToNewV[num2] = num3;
						indexFlagSet[num2] = true;
					}
					else
					{
						num3 = SubToNewV[num2];
					}
					zero[j] = num3;
				}
				if (eDuplicateBehavior != DuplicateTriBehavior.AssertContinue)
				{
					int num5 = Mesh.FindTriangle(zero.a, zero.b, zero.c);
					if (num5 != -1)
					{
						switch (eDuplicateBehavior)
						{
						case DuplicateTriBehavior.AssertAbort:
							return false;
						case DuplicateTriBehavior.UseExisting:
							if (new_tris != null)
							{
								new_tris[num++] = num5;
							}
							continue;
						case DuplicateTriBehavior.Replace:
							Mesh.RemoveTriangle(num5, bRemoveIsolatedVertices: false);
							break;
						}
					}
				}
				int num6 = Mesh.AppendTriangle(zero, triangleGroup);
				if (!Mesh.IsTriangle(num6))
				{
					result = false;
				}
				if (new_tris != null)
				{
					new_tris[num++] = num6;
				}
			}
			return result;
		}

		public bool AppendMesh(IMesh appendMesh, int appendGID = -1)
		{
			int[] mapV;
			return AppendMesh(appendMesh, out mapV, appendGID);
		}

		public bool AppendMesh(IMesh appendMesh, out int[] mapV, int appendGID = -1)
		{
			mapV = new int[appendMesh.MaxVertexID];
			foreach (int item in appendMesh.VertexIndices())
			{
				NewVertexInfo vertexAll = appendMesh.GetVertexAll(item);
				int num = Mesh.AppendVertex(vertexAll);
				mapV[item] = num;
			}
			foreach (int item2 in appendMesh.TriangleIndices())
			{
				Index3i triangle = appendMesh.GetTriangle(item2);
				triangle.a = mapV[triangle.a];
				triangle.b = mapV[triangle.b];
				triangle.c = mapV[triangle.c];
				int gid = appendMesh.GetTriangleGroup(item2);
				if (appendGID >= 0)
				{
					gid = appendGID;
				}
				Mesh.AppendTriangle(triangle, gid);
			}
			return true;
		}

		public static DMesh3 Combine(params IMesh[] appendMeshes)
		{
			DMesh3 dMesh = new DMesh3();
			MeshEditor meshEditor = new MeshEditor(dMesh);
			foreach (IMesh appendMesh in appendMeshes)
			{
				meshEditor.AppendMesh(appendMesh, dMesh.AllocateTriangleGroup());
			}
			return dMesh;
		}

		public static void Append(DMesh3 appendTo, DMesh3 append)
		{
			new MeshEditor(appendTo).AppendMesh(append, appendTo.AllocateTriangleGroup());
		}

		public bool AppendMesh(IMesh appendMesh, IndexMap mergeMapV, out int[] mapV, int appendGID = -1)
		{
			mapV = new int[appendMesh.MaxVertexID];
			foreach (int item in appendMesh.VertexIndices())
			{
				if (mergeMapV.Contains(item))
				{
					mapV[item] = mergeMapV[item];
					continue;
				}
				NewVertexInfo vertexAll = appendMesh.GetVertexAll(item);
				int num = Mesh.AppendVertex(vertexAll);
				mapV[item] = num;
			}
			foreach (int item2 in appendMesh.TriangleIndices())
			{
				Index3i triangle = appendMesh.GetTriangle(item2);
				triangle.a = mapV[triangle.a];
				triangle.b = mapV[triangle.b];
				triangle.c = mapV[triangle.c];
				int gid = appendMesh.GetTriangleGroup(item2);
				if (appendGID >= 0)
				{
					gid = appendGID;
				}
				Mesh.AppendTriangle(triangle, gid);
			}
			return true;
		}

