		{
			double num = 0.0;
			foreach (int triangleIndex in triangleIndices)
			{
				num += mesh.GetTriArea(triangleIndex);
			}
			return num;
		}

		public static AxisAlignedBox3d BoundsInFrame(DMesh3 mesh, Frame3f frame, Func<Vector3d, Vector3d> TransformF = null)
		{
			AxisAlignedBox3d empty = AxisAlignedBox3d.Empty;
			if (TransformF == null)
			{
				foreach (Vector3d item in mesh.Vertices())
				{
					Vector3d v = frame.ToFrameP(item);
					empty.Contain(ref v);
				}
			}
			else
			{
				foreach (Vector3d item2 in mesh.Vertices())
				{
					Vector3d v2 = TransformF(item2);
					Vector3d v3 = frame.ToFrameP(ref v2);
					empty.Contain(ref v3);
				}
			}
			return empty;
		}

		public static Interval1d ExtentsOnAxis(DMesh3 mesh, Vector3d axis, Func<Vector3d, Vector3d> TransformF = null)
		{
			Interval1d empty = Interval1d.Empty;
			if (TransformF == null)
			{
				foreach (Vector3d item in mesh.Vertices())
				{
					empty.Contain(item.Dot(ref axis));
				}
			}
			else
			{
				foreach (Vector3d item2 in mesh.Vertices())
				{
					empty.Contain(TransformF(item2).Dot(ref axis));
				}
			}
			return empty;
		}

		public static Interval1d ExtentsOnAxis(IMesh mesh, Vector3d axis, Func<Vector3d, Vector3d> TransformF = null)
		{
			Interval1d empty = Interval1d.Empty;
			if (TransformF == null)
			{
				foreach (int item in mesh.VertexIndices())
				{
					empty.Contain(mesh.GetVertex(item).Dot(ref axis));
				}
			}
			else
			{
				foreach (int item2 in mesh.VertexIndices())
				{
					empty.Contain(TransformF(mesh.GetVertex(item2)).Dot(ref axis));
				}
			}
			return empty;
		}

		public static Interval1i ExtremeVertices(DMesh3 mesh, Vector3d axis, Func<Vector3d, Vector3d> TransformF = null)
		{
			Interval1d empty = Interval1d.Empty;
			Interval1i result = new Interval1i(-1, -1);
			if (TransformF == null)
			{
				foreach (int item in mesh.VertexIndices())
				{
					double num = mesh.GetVertex(item).Dot(ref axis);
					if (num < empty.a)
					{
						empty.a = num;
						result.a = item;
					}
					else if (num > empty.b)
					{
						empty.b = num;
						result.b = item;
					}
				}
			}
			else
			{
				foreach (int item2 in mesh.VertexIndices())
				{
					double num2 = TransformF(mesh.GetVertex(item2)).Dot(ref axis);
					if (num2 < empty.a)
					{
						empty.a = num2;
						result.a = item2;
					}
					else if (num2 > empty.b)
					{
						empty.b = num2;
						result.b = item2;
					}
				}
			}
			return result;
		}

		public static GenusResult Genus(DMesh3 mesh)
		{
			GenusResult result = new GenusResult
			{
				Valid = false,
				Genus = -1
			};
			if (!mesh.CachedIsClosed)
			{
				result.HasBoundary = true;
				return result;
			}
			MeshConnectedComponents meshConnectedComponents = new MeshConnectedComponents(mesh);
			meshConnectedComponents.FindConnectedT();
			if (meshConnectedComponents.Count > 1)
			{
				result.MultipleConnectedComponents = true;
				return result;
			}
			int num = 0;
			foreach (int item in mesh.VertexIndices())
			{
				if (mesh.IsBowtieVertex(item))
				{
					result.HasBowtieVertices = true;
					return result;
				}
				if (mesh.GetVtxTriangleCount(item) == 0)
				{
					num++;
				}
			}
			int num2 = mesh.VertexCount - num;
			int triangleCount = mesh.TriangleCount;
			int edgeCount = mesh.EdgeCount;
			result.Genus = (2 - (num2 + triangleCount - edgeCount)) / 2;
			result.Valid = true;
			return result;
		}
	}
	public class MeshNormals
	{
		public enum NormalsTypes
		{
			Vertex_OneRingFaceAverage_AreaWeighted
		}

		public IMesh Mesh;

		public DVector<Vector3d> Normals;

		public Func<int, Vector3d> VertexF;

		public NormalsTypes NormalType;

		public Vector3d this[int vid] => Normals[vid];

		public MeshNormals(IMesh mesh, NormalsTypes eType = NormalsTypes.Vertex_OneRingFaceAverage_AreaWeighted)
		{
			Mesh = mesh;
			NormalType = eType;
			Normals = new DVector<Vector3d>();
			VertexF = Mesh.GetVertex;
		}

		public void Compute()
		{
			Compute_FaceAvg_AreaWeighted();
		}

		public void CopyTo(DMesh3 SetMesh)
		{
			if (SetMesh.MaxVertexID < Mesh.MaxVertexID)
			{
				throw new Exception("MeshNormals.Set: SetMesh does not have enough vertices!");
			}
			if (!SetMesh.HasVertexNormals)
			{
				SetMesh.EnableVertexNormals(Vector3f.AxisY);
			}
			int maxVertexID = Mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (Mesh.IsVertex(i) && SetMesh.IsVertex(i))
				{
					SetMesh.SetVertexNormal(i, (Vector3f)Normals[i]);
				}
			}
		}

		private void Compute_FaceAvg_AreaWeighted()
		{
			int maxVertexID = Mesh.MaxVertexID;
			if (maxVertexID != Normals.size)
			{
				Normals.resize(maxVertexID);
			}
			for (int i = 0; i < maxVertexID; i++)
			{
				Normals[i] = Vector3d.Zero;
			}
			SpinLock Normals_lock = default(SpinLock);
			gParallel.ForEach(Mesh.TriangleIndices(), delegate(int ti)
			{
				Index3i triangle = Mesh.GetTriangle(ti);
				Vector3d v = Mesh.GetVertex(triangle.a);
				Vector3d v2 = Mesh.GetVertex(triangle.b);
				Vector3d v3 = Mesh.GetVertex(triangle.c);
				Vector3d vector3d = MathUtil.Normal(ref v, ref v2, ref v3);
				double num = MathUtil.Area(ref v, ref v2, ref v3);
				bool lockTaken = false;
				Normals_lock.Enter(ref lockTaken);
				Normals[triangle.a] += num * vector3d;
				Normals[triangle.b] += num * vector3d;
				Normals[triangle.c] += num * vector3d;
				Normals_lock.Exit();
			});
			gParallel.BlockStartEnd(0, maxVertexID - 1, delegate(int vi_start, int vi_end)
			{
				for (int j = vi_start; j <= vi_end; j++)
				{
					if (Normals[j].LengthSquared > 9.999999974752427E-07)
					{
						Normals[j] = Normals[j].Normalized;
					}
				}
			});
		}

		public static void QuickCompute(DMesh3 mesh)
		{
			MeshNormals meshNormals = new MeshNormals(mesh);
			meshNormals.Compute();
			meshNormals.CopyTo(mesh);
		}

		public static Vector3d QuickCompute(DMesh3 mesh, int vid, NormalsTypes type = NormalsTypes.Vertex_OneRingFaceAverage_AreaWeighted)
		{
			Vector3d zero = Vector3d.Zero;
			foreach (int item in mesh.VtxTrianglesItr(vid))
			{
				mesh.GetTriInfo(item, out var normal, out var fArea, out var _);
				zero += fArea * normal;
			}
			return zero.Normalized;
		}
	}
