	public class MeshBoundaryEdgeMidpoints : IPointSet
	{
		private int num_boundary_edges;

		public DMesh3 Mesh;

		public int VertexCount => num_boundary_edges;

		public int MaxVertexID => Mesh.MaxEdgeID;

		public bool HasVertexNormals => false;

		public bool HasVertexColors => false;

		public int Timestamp => Mesh.Timestamp;

		public MeshBoundaryEdgeMidpoints(DMesh3 mesh)
		{
			Mesh = mesh;
			num_boundary_edges = 0;
			foreach (int item in mesh.BoundaryEdgeIndices())
			{
				_ = item;
				num_boundary_edges++;
			}
		}

		public Vector3d GetVertex(int i)
		{
			return Mesh.GetEdgePoint(i, 0.5);
		}

		public Vector3f GetVertexNormal(int i)
		{
			return Vector3f.AxisY;
		}

		public Vector3f GetVertexColor(int i)
		{
			return Vector3f.One;
		}

		public bool IsVertex(int vID)
		{
			if (Mesh.IsEdge(vID))
			{
				return Mesh.IsBoundaryEdge(vID);
			}
			return false;
		}

		public IEnumerable<int> VertexIndices()
		{
			return Mesh.BoundaryEdgeIndices();
		}
	}
	public class MeshRefinerBase
	{
		protected DMesh3 mesh;

		protected MeshConstraints constraints;

		public bool AllowCollapseFixedVertsWithSameSetID = true;

		protected double edge_flip_tol;

		public ProgressCancel Progress;

		public double EdgeFlipTolerance
		{
			get
			{
				return edge_flip_tol;
			}
			set
			{
				edge_flip_tol = MathUtil.Clamp(value, -1.0, 1.0);
			}
		}

		public DMesh3 Mesh => mesh;

		public MeshConstraints Constraints => constraints;

		public MeshRefinerBase(DMesh3 mesh)
		{
			this.mesh = mesh;
		}

		protected MeshRefinerBase()
		{
		}

		public void SetExternalConstraints(MeshConstraints cons)
		{
			constraints = cons;
		}

		protected virtual bool Cancelled()
		{
			if (Progress != null)
			{
				return Progress.Cancelled();
			}
			return false;
		}

		protected double edge_flip_metric(ref Vector3d n0, ref Vector3d n1)
		{
			if (edge_flip_tol == 0.0)
			{
				return n0.Dot(n1);
			}
			return n0.Normalized.Dot(n1.Normalized);
		}

		protected bool collapse_creates_flip_or_invalid(int vid, int vother, ref Vector3d newv, int tc, int td)
		{
			Vector3d v = Vector3d.Zero;
			Vector3d v2 = Vector3d.Zero;
			Vector3d v3 = Vector3d.Zero;
			foreach (int item in mesh.VtxTrianglesItr(vid))
			{
				if (item == tc || item == td)
				{
					continue;
				}
				Index3i triangle = mesh.GetTriangle(item);
				if (triangle.a == vother || triangle.b == vother || triangle.c == vother)
				{
					return true;
				}
				mesh.GetTriVertices(item, ref v, ref v2, ref v3);
				Vector3d n = (v2 - v).Cross(v3 - v);
				double num = 0.0;
				if (triangle.a == vid)
				{
					Vector3d n2 = (v2 - newv).Cross(v3 - newv);
					num = edge_flip_metric(ref n, ref n2);
				}
				else if (triangle.b == vid)
				{
					Vector3d n3 = (newv - v).Cross(v3 - v);
					num = edge_flip_metric(ref n, ref n3);
				}
				else
				{
					if (triangle.c != vid)
					{
						throw new Exception("should never be here!");
					}
					Vector3d n4 = (v2 - v).Cross(newv - v);
					num = edge_flip_metric(ref n, ref n4);
				}
				if (num <= edge_flip_tol)
				{
					return true;
				}
			}
			return false;
		}

		protected bool flip_inverts_normals(int a, int b, int c, int d, int t0)
		{
			Vector3d v = mesh.GetVertex(c);
			Vector3d v2 = mesh.GetVertex(d);
			Index3i tri_verts = mesh.GetTriangle(t0);
			int a2 = a;
			int b2 = b;
			IndexUtil.orient_tri_edge(ref a2, ref b2, ref tri_verts);
			Vector3d v3 = mesh.GetVertex(a2);
			Vector3d v4 = mesh.GetVertex(b2);
			Vector3d n = MathUtil.FastNormalDirection(ref v3, ref v4, ref v);
			Vector3d n2 = MathUtil.FastNormalDirection(ref v4, ref v3, ref v2);
			Vector3d n3 = MathUtil.FastNormalDirection(ref v, ref v2, ref v4);
			if (edge_flip_metric(ref n, ref n3) <= edge_flip_tol || edge_flip_metric(ref n2, ref n3) <= edge_flip_tol)
			{
				return true;
			}
			Vector3d n4 = MathUtil.FastNormalDirection(ref v2, ref v, ref v3);
			if (edge_flip_metric(ref n, ref n4) <= edge_flip_tol || edge_flip_metric(ref n2, ref n4) <= edge_flip_tol)
			{
				return true;
			}
			return false;
		}

		protected bool can_collapse_constraints(int eid, int a, int b, int c, int d, int tc, int td, out int collapse_to)
		{
			collapse_to = -1;
			if (constraints == null)
			{
				return true;
			}
			if (!can_collapse_vtx(eid, a, b, out collapse_to))
			{
				return false;
			}
			int vA = ((collapse_to == a) ? b : a);
			if (c != -1)
			{
				int eid2 = mesh.FindEdgeFromTri(vA, c, tc);
				if (!constraints.GetEdgeConstraint(eid2).IsUnconstrained)
				{
					return false;
				}
			}
			if (d != -1)
			{
				int eid3 = mesh.FindEdgeFromTri(vA, d, td);
				if (!constraints.GetEdgeConstraint(eid3).IsUnconstrained)
				{
					return false;
				}
			}
			return true;
		}

		protected bool can_collapse_vtx(int eid, int a, int b, out int collapse_to)
		{
			collapse_to = -1;
			if (constraints == null)
			{
				return true;
			}
			VertexConstraint vertexConstraint = constraints.GetVertexConstraint(a);
			VertexConstraint vertexConstraint2 = constraints.GetVertexConstraint(b);
			if (!vertexConstraint.Fixed && !vertexConstraint2.Fixed && vertexConstraint.Target == null && vertexConstraint2.Target == null)
			{
				return true;
			}
			if (vertexConstraint.Fixed && !vertexConstraint2.Fixed)
			{
				if (vertexConstraint2.Target != null && vertexConstraint2.Target != vertexConstraint.Target)
				{
					return false;
				}
				collapse_to = a;
				return true;
			}
			if (vertexConstraint2.Fixed && !vertexConstraint.Fixed)
			{
				if (vertexConstraint.Target != null && vertexConstraint.Target != vertexConstraint2.Target)
				{
					return false;
				}
				collapse_to = b;
				return true;
			}
			if (AllowCollapseFixedVertsWithSameSetID && vertexConstraint.FixedSetID >= 0 && vertexConstraint.FixedSetID == vertexConstraint2.FixedSetID)
			{
				return true;
			}
			if (vertexConstraint.Target != null && vertexConstraint2.Target == null)
			{
				collapse_to = a;
				return true;
			}
			if (vertexConstraint2.Target != null && vertexConstraint.Target == null)
			{
				collapse_to = b;
				return true;
			}
			if (vertexConstraint2.Target != null && vertexConstraint.Target != null && vertexConstraint.Target == vertexConstraint2.Target && constraints.GetEdgeConstraint(eid).Target == vertexConstraint.Target)
			{
				return true;
			}
			return false;
		}

		protected bool vertex_is_fixed(int vid)
		{
			if (constraints != null && constraints.GetVertexConstraint(vid).Fixed)
			{
				return true;
			}
			return false;
		}

		protected bool vertex_is_constrained(int vid)
		{
			if (constraints != null)
			{
				VertexConstraint vertexConstraint = constraints.GetVertexConstraint(vid);
				if (vertexConstraint.Fixed || vertexConstraint.Target != null)
				{
					return true;
				}
			}
			return false;
		}

		protected VertexConstraint get_vertex_constraint(int vid)
		{
			if (constraints != null)
			{
				return constraints.GetVertexConstraint(vid);
			}
			return VertexConstraint.Unconstrained;
		}

		protected bool get_vertex_constraint(int vid, ref VertexConstraint vc)
		{
			if (constraints != null)
			{
				return constraints.GetVertexConstraint(vid, ref vc);
			}
			return false;
		}
	}
	public static class MeshTransforms
	{
		public static void Translate(IDeformableMesh mesh, Vector3d v)
		{
			Translate(mesh, v.x, v.y, v.z);
		}

		public static void Translate(IDeformableMesh mesh, double tx, double ty, double tz)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					vertex.x += tx;
					vertex.y += ty;
					vertex.z += tz;
					mesh.SetVertex(i, vertex);
				}
			}
		}

		public static Vector3d Rotate(Vector3d pos, Vector3d origin, Quaternionf rotation)
		{
			Vector3d vector3d = pos - origin;
			vector3d = rotation * (Vector3f)vector3d;
			return vector3d + origin;
		}

		public static Frame3f Rotate(Frame3f f, Vector3d origin, Quaternionf rotation)
		{
			f.Rotate(rotation);
			f.Origin = (Vector3f)Rotate(f.Origin, origin, rotation);
			return f;
		}

		public static Frame3f Rotate(Frame3f f, Vector3d origin, Quaterniond rotation)
		{
			f.Rotate((Quaternionf)rotation);
			f.Origin = (Vector3f)Rotate(f.Origin, origin, rotation);
			return f;
		}

		public static void Rotate(IDeformableMesh mesh, Vector3d origin, Quaternionf rotation)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					vertex -= origin;
					vertex = rotation * (Vector3f)vertex;
					vertex += origin;
					mesh.SetVertex(i, vertex);
				}
			}
		}

		public static Vector3d Rotate(Vector3d pos, Vector3d origin, Quaterniond rotation)
		{
			return rotation * (pos - origin) + origin;
		}

		public static void Rotate(IDeformableMesh mesh, Vector3d origin, Quaterniond rotation)
		{
			bool hasVertexNormals = mesh.HasVertexNormals;
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vNewPos = rotation * (mesh.GetVertex(i) - origin) + origin;
					mesh.SetVertex(i, vNewPos);
					if (hasVertexNormals)
					{
						mesh.SetVertexNormal(i, (Vector3f)(rotation * mesh.GetVertexNormal(i)));
					}
				}
			}
		}

		public static void Scale(IDeformableMesh mesh, Vector3d scale, Vector3d origin)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					vertex.x -= origin.x;
					vertex.y -= origin.y;
					vertex.z -= origin.z;
					vertex.x *= scale.x;
					vertex.y *= scale.y;
					vertex.z *= scale.z;
					vertex.x += origin.x;
					vertex.y += origin.y;
					vertex.z += origin.z;
					mesh.SetVertex(i, vertex);
				}
			}
		}

		public static void Scale(IDeformableMesh mesh, double sx, double sy, double sz)
		{
			Scale(mesh, new Vector3d(sx, sy, sz), Vector3d.Zero);
		}

		public static void Scale(IDeformableMesh mesh, double s)
		{
			Scale(mesh, s, s, s);
		}

		public static void ToFrame(IDeformableMesh mesh, Frame3f f)
		{
			int maxVertexID = mesh.MaxVertexID;
			bool hasVertexNormals = mesh.HasVertexNormals;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d v = mesh.GetVertex(i);
					Vector3d vNewPos = f.ToFrameP(ref v);
					mesh.SetVertex(i, vNewPos);
					if (hasVertexNormals)
					{
						Vector3f v2 = mesh.GetVertexNormal(i);
						Vector3f vNewNormal = f.ToFrameV(ref v2);
						mesh.SetVertexNormal(i, vNewNormal);
					}
				}
			}
		}

		public static void FromFrame(IDeformableMesh mesh, Frame3f f)
		{
			int maxVertexID = mesh.MaxVertexID;
			bool hasVertexNormals = mesh.HasVertexNormals;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d v = mesh.GetVertex(i);
					Vector3d vNewPos = f.FromFrameP(ref v);
					mesh.SetVertex(i, vNewPos);
					if (hasVertexNormals)
					{
						Vector3f v2 = mesh.GetVertexNormal(i);
						Vector3f vNewNormal = f.FromFrameV(ref v2);
						mesh.SetVertexNormal(i, vNewNormal);
					}
				}
			}
		}

		public static Vector3d ConvertZUpToYUp(Vector3d v)
		{
			return new Vector3d(v.x, v.z, 0.0 - v.y);
		}

		public static Vector3f ConvertZUpToYUp(Vector3f v)
		{
			return new Vector3f(v.x, v.z, 0f - v.y);
		}

		public static Frame3f ConvertZUpToYUp(Frame3f f)
		{
			return new Frame3f(ConvertZUpToYUp(f.Origin), ConvertZUpToYUp(f.X), ConvertZUpToYUp(f.Y), ConvertZUpToYUp(f.Z));
		}

		public static void ConvertZUpToYUp(IDeformableMesh mesh)
		{
			int maxVertexID = mesh.MaxVertexID;
			bool hasVertexNormals = mesh.HasVertexNormals;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					mesh.SetVertex(i, new Vector3d(vertex.x, vertex.z, 0.0 - vertex.y));
					if (hasVertexNormals)
					{
						Vector3f vertexNormal = mesh.GetVertexNormal(i);
						mesh.SetVertexNormal(i, new Vector3f(vertexNormal.x, vertexNormal.z, 0f - vertexNormal.y));
					}
				}
			}
		}

		public static Vector3d ConvertYUpToZUp(Vector3d v)
		{
			return new Vector3d(v.x, 0.0 - v.z, v.y);
		}

		public static Vector3f ConvertYUpToZUp(Vector3f v)
		{
			return new Vector3f(v.x, 0f - v.z, v.y);
		}

		public static Frame3f ConvertYUpToZUp(Frame3f f)
		{
			return new Frame3f(ConvertYUpToZUp(f.Origin), ConvertYUpToZUp(f.X), ConvertYUpToZUp(f.Y), ConvertYUpToZUp(f.Z));
		}

		public static void ConvertYUpToZUp(IDeformableMesh mesh)
		{
			int maxVertexID = mesh.MaxVertexID;
			bool hasVertexNormals = mesh.HasVertexNormals;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					mesh.SetVertex(i, new Vector3d(vertex.x, 0.0 - vertex.z, vertex.y));
					if (hasVertexNormals)
					{
						Vector3f vertexNormal = mesh.GetVertexNormal(i);
						mesh.SetVertexNormal(i, new Vector3f(vertexNormal.x, 0f - vertexNormal.z, vertexNormal.y));
					}
				}
			}
		}

		public static Vector3d FlipLeftRightCoordSystems(Vector3d v)
		{
			return new Vector3d(v.x, v.y, 0.0 - v.z);
		}

		public static Vector3f FlipLeftRightCoordSystems(Vector3f v)
		{
			return new Vector3f(v.x, v.y, 0f - v.z);
		}

		public static Frame3f FlipLeftRightCoordSystems(Frame3f f)
		{
			throw new NotImplementedException("this doesn't work...frame becomes broken somehow?");
		}

		public static void FlipLeftRightCoordSystems(IDeformableMesh mesh)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vertex = mesh.GetVertex(i);
					vertex.z = 0.0 - vertex.z;
					mesh.SetVertex(i, vertex);
					if (mesh.HasVertexNormals)
					{
						Vector3f vertexNormal = mesh.GetVertexNormal(i);
						vertexNormal.z = 0f - vertexNormal.z;
						mesh.SetVertexNormal(i, vertexNormal);
					}
				}
			}
			if (mesh is DMesh3)
			{
				(mesh as DMesh3).ReverseOrientation(bFlipNormals: false);
				return;
			}
			throw new Exception("argh don't want this in IDeformableMesh...but then for SimpleMesh??");
		}

		public static void VertexNormalOffset(IDeformableMesh mesh, double offsetDistance)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vNewPos = mesh.GetVertex(i) + offsetDistance * (Vector3d)mesh.GetVertexNormal(i);
					mesh.SetVertex(i, vNewPos);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, Func<Vector3d, Vector3d> TransformF)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vNewPos = TransformF(mesh.GetVertex(i));
					mesh.SetVertex(i, vNewPos);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, Func<Vector3d, Vector3f, Vector3d> TransformF)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3d vNewPos = TransformF(mesh.GetVertex(i), mesh.GetVertexNormal(i));
					mesh.SetVertex(i, vNewPos);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, Func<Vector3d, Vector3f, Vector3dTuple2> TransformF)
		{
			int maxVertexID = mesh.MaxVertexID;
			for (int i = 0; i < maxVertexID; i++)
			{
				if (mesh.IsVertex(i))
				{
					Vector3dTuple2 vector3dTuple = TransformF(mesh.GetVertex(i), mesh.GetVertexNormal(i));
					mesh.SetVertex(i, vector3dTuple.V0);
					mesh.SetVertexNormal(i, (Vector3f)vector3dTuple.V1);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, TransformSequence xform)
		{
			int maxVertexID = mesh.MaxVertexID;
			if (mesh.HasVertexNormals)
			{
				for (int i = 0; i < maxVertexID; i++)
				{
					if (mesh.IsVertex(i))
					{
						mesh.SetVertex(i, xform.TransformP(mesh.GetVertex(i)));
						mesh.SetVertexNormal(i, (Vector3f)xform.TransformV(mesh.GetVertexNormal(i)));
					}
				}
				return;
			}
			for (int j = 0; j < maxVertexID; j++)
			{
				if (mesh.IsVertex(j))
				{
					mesh.SetVertex(j, xform.TransformP(mesh.GetVertex(j)));
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, IEnumerable<int> vertices, Func<Vector3d, int, Vector3d> TransformF)
		{
			foreach (int vertex in vertices)
			{
				if (mesh.IsVertex(vertex))
				{
					Vector3d vNewPos = TransformF(mesh.GetVertex(vertex), vertex);
					mesh.SetVertex(vertex, vNewPos);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh mesh, IEnumerable<int> vertices, Func<int, int> MapV, Func<Vector3d, int, int, Vector3d> TransformF)
		{
			foreach (int vertex in vertices)
			{
				int num = MapV(vertex);
				if (mesh.IsVertex(num))
				{
					Vector3d vNewPos = TransformF(mesh.GetVertex(num), vertex, num);
					mesh.SetVertex(num, vNewPos);
				}
			}
		}

		public static void PerVertexTransform(IDeformableMesh targetMesh, IDeformableMesh sourceMesh, int[] mapV, Func<Vector3d, int, int, Vector3d> TransformF)
		{
			foreach (int item in sourceMesh.VertexIndices())
			{
				int num = mapV[item];
				if (targetMesh.IsVertex(num))
				{
					Vector3d vNewPos = TransformF(targetMesh.GetVertex(num), item, num);
					targetMesh.SetVertex(num, vNewPos);
				}
			}
		}
	}
	public static class MeshUtil
	{
		public static Vector3d UniformSmooth(DMesh3 mesh, int vID, double t)
		{
			Vector3d vertex = mesh.GetVertex(vID);
			Vector3d centroid = Vector3d.Zero;
			mesh.VtxOneRingCentroid(vID, ref centroid);
			double num = 1.0 - t;
			vertex.x = num * vertex.x + t * centroid.x;
			vertex.y = num * vertex.y + t * centroid.y;
			vertex.z = num * vertex.z + t * centroid.z;
			return vertex;
		}

		public static Vector3d MeanValueSmooth(DMesh3 mesh, int vID, double t)
		{
			Vector3d vertex = mesh.GetVertex(vID);
			Vector3d vector3d = MeshWeights.MeanValueCentroid(mesh, vID);
			return (1.0 - t) * vertex + t * vector3d;
		}

		public static Vector3d CotanSmooth(DMesh3 mesh, int vID, double t)
		{
			Vector3d vertex = mesh.GetVertex(vID);
			Vector3d vector3d = MeshWeights.CotanCentroid(mesh, vID);
			return (1.0 - t) * vertex + t * vector3d;
		}

		public static void ScaleMesh(DMesh3 mesh, Frame3f f, Vector3f vScale)
		{
			foreach (int item in mesh.VertexIndices())
			{
				Vector3f v = (Vector3f)mesh.GetVertex(item);
				Vector3f v2 = f.ToFrameP(ref v) * vScale;
				Vector3d vNewPos = f.FromFrameP(ref v2);
				mesh.SetVertex(item, vNewPos);
			}
		}

		public static double OpeningAngleD(DMesh3 mesh, int eid)
		{
			Index2i edgeT = mesh.GetEdgeT(eid);
			if (edgeT[1] == -1)
			{
				return double.MaxValue;
			}
			Vector3d triNormal = mesh.GetTriNormal(edgeT[0]);
			Vector3d triNormal2 = mesh.GetTriNormal(edgeT[1]);
			return Vector3d.AngleD(triNormal, triNormal2);
		}

		public static double DiscreteGaussCurvature(DMesh3 mesh, int vid)
		{
			double num = 0.0;
			foreach (int item in mesh.VtxTrianglesItr(vid))
			{
				Index3i tri_verts = mesh.GetTriangle(item);
				int i = IndexUtil.find_tri_index(vid, ref tri_verts);
				num += mesh.GetTriInternalAngleR(item, i);
			}
			return num - Math.PI * 2.0;
		}

		public static bool CheckIfCollapseCreatesFlip(DMesh3 mesh, int edgeID, Vector3d newv)
		{
			Index4i edge = mesh.GetEdge(edgeID);
			int c = edge.c;
			int d = edge.d;
			for (int i = 0; i < 2; i++)
			{
				int num = edge[i];
				int num2 = edge[(i + 1) % 2];
				foreach (int item in mesh.VtxTrianglesItr(num))
				{
					if (item == c || item == d)
					{
						continue;
					}
					Index3i triangle = mesh.GetTriangle(item);
					if (triangle.a == num2 || triangle.b == num2 || triangle.c == num2)
					{
						return true;
					}
					Vector3d vertex = mesh.GetVertex(triangle.a);
					Vector3d vertex2 = mesh.GetVertex(triangle.b);
					Vector3d vertex3 = mesh.GetVertex(triangle.c);
					Vector3d vector3d = (vertex2 - vertex).Cross(vertex3 - vertex);
					double num3 = 0.0;
					if (triangle.a == num)
					{
						Vector3d v = (vertex2 - newv).Cross(vertex3 - newv);
						num3 = vector3d.Dot(v);
					}
					else if (triangle.b == num)
					{
						Vector3d v2 = (newv - vertex).Cross(vertex3 - vertex);
						num3 = vector3d.Dot(v2);
					}
					else
					{
						if (triangle.c != num)
						{
							throw new Exception("should never be here!");
						}
						Vector3d v3 = (vertex2 - vertex).Cross(newv - vertex);
						num3 = vector3d.Dot(v3);
					}
					if (num3 <= 0.0)
					{
						return true;
					}
				}
			}
			return false;
		}

		public static bool CheckIfEdgeFlipCreatesFlip(DMesh3 mesh, int eID, double flip_dot_tol = 0.0)
		{
			Index4i edge = mesh.GetEdge(eID);
			Index2i edgeOpposingV = mesh.GetEdgeOpposingV(eID);
			int a = edge.a;
			int b = edge.b;
			int a2 = edgeOpposingV.a;
			int b2 = edgeOpposingV.b;
			int c = edge.c;
			Vector3d v = mesh.GetVertex(a2);
			Vector3d v2 = mesh.GetVertex(b2);
			Index3i tri_verts = mesh.GetTriangle(c);
			int a3 = a;
			int b3 = b;
			IndexUtil.orient_tri_edge(ref a3, ref b3, ref tri_verts);
			Vector3d v3 = mesh.GetVertex(a3);
			Vector3d v4 = mesh.GetVertex(b3);
			Vector3d n = MathUtil.FastNormalDirection(ref v3, ref v4, ref v);
			Vector3d n2 = MathUtil.FastNormalDirection(ref v4, ref v3, ref v2);
			Vector3d n3 = MathUtil.FastNormalDirection(ref v, ref v2, ref v4);
			if (edge_flip_metric(ref n, ref n3, flip_dot_tol) <= flip_dot_tol || edge_flip_metric(ref n2, ref n3, flip_dot_tol) <= flip_dot_tol)
			{
				return true;
			}
			Vector3d n4 = MathUtil.FastNormalDirection(ref v2, ref v, ref v3);
			if (edge_flip_metric(ref n, ref n4, flip_dot_tol) <= flip_dot_tol || edge_flip_metric(ref n2, ref n4, flip_dot_tol) <= flip_dot_tol)
			{
				return true;
			}
			return false;
		}

		private static double edge_flip_metric(ref Vector3d n0, ref Vector3d n1, double flip_dot_tol)
		{
			if (flip_dot_tol != 0.0)
			{
				return n0.Normalized.Dot(n1.Normalized);
			}
			return n0.Dot(n1);
		}

		public static void GetEdgeFlipTris(DMesh3 mesh, int eID, out Index3i orig_t0, out Index3i orig_t1, out Index3i flip_t0, out Index3i flip_t1)
		{
			Index4i edge = mesh.GetEdge(eID);
			Index2i edgeOpposingV = mesh.GetEdgeOpposingV(eID);
			int a = edge.a;
			int b = edge.b;
			int a2 = edgeOpposingV.a;
			int b2 = edgeOpposingV.b;
			int c = edge.c;
			Index3i tri_verts = mesh.GetTriangle(c);
			int a3 = a;
			int b3 = b;
			IndexUtil.orient_tri_edge(ref a3, ref b3, ref tri_verts);
			orig_t0 = new Index3i(a3, b3, a2);
			orig_t1 = new Index3i(b3, a3, b2);
			flip_t0 = new Index3i(a2, b2, b3);
			flip_t1 = new Index3i(b2, a2, a3);
		}

		public static void GetEdgeFlipNormals(DMesh3 mesh, int eID, out Vector3d n1, out Vector3d n2, out Vector3d on1, out Vector3d on2)
		{
			Index4i edge = mesh.GetEdge(eID);
			Index2i edgeOpposingV = mesh.GetEdgeOpposingV(eID);
			int a = edge.a;
			int b = edge.b;
			int a2 = edgeOpposingV.a;
			int b2 = edgeOpposingV.b;
			int c = edge.c;
			Vector3d v = mesh.GetVertex(a2);
			Vector3d v2 = mesh.GetVertex(b2);
			Index3i tri_verts = mesh.GetTriangle(c);
			int a3 = a;
			int b3 = b;
			IndexUtil.orient_tri_edge(ref a3, ref b3, ref tri_verts);
			Vector3d v3 = mesh.GetVertex(a3);
			Vector3d v4 = mesh.GetVertex(b3);
			n1 = MathUtil.Normal(ref v3, ref v4, ref v);
			n2 = MathUtil.Normal(ref v4, ref v3, ref v2);
			on1 = MathUtil.Normal(ref v, ref v2, ref v4);
			on2 = MathUtil.Normal(ref v2, ref v, ref v3);
		}

		public static DCurve3 ExtractLoopV(IMesh mesh, IEnumerable<int> vertices)
		{
			DCurve3 dCurve = new DCurve3();
			foreach (int vertex in vertices)
			{
				dCurve.AppendVertex(mesh.GetVertex(vertex));
			}
			dCurve.Closed = true;
			return dCurve;
		}

		public static DCurve3 ExtractLoopV(IMesh mesh, int[] vertices)
		{
			DCurve3 dCurve = new DCurve3();
			for (int i = 0; i < vertices.Length; i++)
			{
				dCurve.AppendVertex(mesh.GetVertex(vertices[i]));
			}
			dCurve.Closed = true;
			return dCurve;
		}
	}
