			a.y = vertices[num + 1];
			a.z = vertices[num + 2];
			int num2 = 3 * edges[2 * eID + 1];
			b.x = vertices[num2];
			b.y = vertices[num2 + 1];
			b.z = vertices[num2 + 2];
			return true;
		}

