		public MeshResult GetVtxTriangles(int vID, List<int> vTriangles)
		{
			if (!IsVertex(vID))
			{
				return MeshResult.Failed_NotAVertex;
			}
			vTriangles.Clear();
			foreach (int item in vertex_edges.ValueItr(vID))
			{
				foreach (int item2 in edge_triangles.ValueItr(item))
				{
					if (!vTriangles.Contains(item2))
					{
						vTriangles.Add(item2);
					}
				}
			}
			return MeshResult.Ok;
		}

		public int GetVtxTriangleCount(int vID, bool bBruteForce = false)
		{
			List<int> list = new List<int>();
			if (GetVtxTriangles(vID, list) != MeshResult.Ok)
			{
				return -1;
			}
			return list.Count;
		}

		public IEnumerable<int> VtxTrianglesItr(int vID)
		{
			if (!IsVertex(vID))
			{
				yield break;
			}
			List<int> list = new List<int>();
			GetVtxTriangles(vID, list);
			foreach (int item in list)
			{
				yield return item;
			}
		}

		protected bool tri_has_v(int tID, int vID)
		{
			int num = 3 * tID;
			if (triangles[num] != vID && triangles[num + 1] != vID)
			{
				return triangles[num + 2] == vID;
			}
			return true;
		}

		protected bool tri_is_boundary(int tID)
		{
			int num = 3 * tID;
			if (!edge_is_boundary(triangle_edges[num]) && !edge_is_boundary(triangle_edges[num + 1]))
			{
				return edge_is_boundary(triangle_edges[num + 2]);
			}
			return true;
		}

		protected bool tri_has_neighbour_t(int tCheck, int tNbr)
		{
			int num = 3 * tCheck;
			if (!edge_has_t(triangle_edges[num], tNbr) && !edge_has_t(triangle_edges[num + 1], tNbr))
			{
				return edge_has_t(triangle_edges[num + 2], tNbr);
			}
			return true;
		}

		protected bool tri_has_sequential_v(int tID, int vA, int vB)
		{
			int num = 3 * tID;
			int num2 = triangles[num];
			int num3 = triangles[num + 1];
			int num4 = triangles[num + 2];
			if (num2 == vA && num3 == vB)
			{
				return true;
			}
			if (num3 == vA && num4 == vB)
			{
				return true;
			}
			if (num4 == vA && num2 == vB)
			{
				return true;
			}
			return false;
		}

		protected int find_tri_neighbour_edge(int tID, int vA, int vB)
		{
			int num = 3 * tID;
			int num2 = triangles[num];
			int num3 = triangles[num + 1];
			if (IndexUtil.same_pair_unordered(num2, num3, vA, vB))
			{
				return triangle_edges[3 * tID];
			}
			int num4 = triangles[num + 2];
			if (IndexUtil.same_pair_unordered(num3, num4, vA, vB))
			{
				return triangle_edges[3 * tID + 1];
			}
			if (IndexUtil.same_pair_unordered(num4, num2, vA, vB))
			{
				return triangle_edges[3 * tID + 2];
			}
			return -1;
		}

		protected int find_tri_neighbour_index(int tID, int vA, int vB)
		{
			int num = 3 * tID;
			int num2 = triangles[num];
			int num3 = triangles[num + 1];
			if (IndexUtil.same_pair_unordered(num2, num3, vA, vB))
			{
				return 0;
			}
			int num4 = triangles[num + 2];
			if (IndexUtil.same_pair_unordered(num3, num4, vA, vB))
			{
				return 1;
			}
			if (IndexUtil.same_pair_unordered(num4, num2, vA, vB))
			{
				return 2;
			}
			return -1;
		}

		public bool IsNonManifoldEdge(int eid)
		{
			return edge_triangles.Count(eid) > 2;
		}

		public bool IsBoundaryEdge(int eid)
		{
			return edge_triangles.Count(eid) == 1;
		}

		protected bool edge_is_boundary(int eid)
		{
			return edge_triangles.Count(eid) == 1;
		}

		protected bool edge_has_v(int eid, int vid)
		{
			int num = 2 * eid;
			if (edges[num] != vid)
			{
				return edges[num + 1] == vid;
			}
			return true;
		}

		protected bool edge_has_t(int eid, int tid)
		{
			return edge_triangles.Contains(eid, tid);
		}

		protected int edge_other_v(int eID, int vID)
		{
			int num = 2 * eID;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			if (num2 != vID)
			{
				if (num3 != vID)
				{
					return -1;
				}
				return num2;
			}
			return num3;
		}

		public bool vertex_is_boundary(int vID)
		{
			return IsBoundaryVertex(vID);
		}

		public bool IsBoundaryVertex(int vID)
		{
			foreach (int item in vertex_edges.ValueItr(vID))
			{
				if (edge_triangles.Count(item) == 1)
				{
					return true;
				}
			}
			return false;
		}

		public bool IsBoundaryTriangle(int tID)
		{
			int num = 3 * tID;
			if (!IsBoundaryEdge(triangle_edges[num]) && !IsBoundaryEdge(triangle_edges[num + 1]))
			{
				return IsBoundaryEdge(triangle_edges[num + 2]);
			}
			return true;
		}

		private int find_edge(int vA, int vB)
		{
			int num = Math.Max(vA, vB);
			int list_index = Math.Min(vA, vB);
			foreach (int item in vertex_edges.ValueItr(list_index))
			{
				if (edges[2 * item + 1] == num)
				{
					return item;
				}
			}
			return -1;
		}

		private int find_edge_from_tri(int vA, int vB, int tID)
		{
			int num = 3 * tID;
			int num2 = triangles[num];
			int num3 = triangles[num + 1];
			if (IndexUtil.same_pair_unordered(vA, vB, num2, num3))
			{
				return triangle_edges[num];
			}
			int num4 = triangles[num + 2];
			if (IndexUtil.same_pair_unordered(vA, vB, num3, num4))
			{
				return triangle_edges[num + 1];
			}
			if (IndexUtil.same_pair_unordered(vA, vB, num4, num2))
			{
				return triangle_edges[num + 2];
			}
			return -1;
		}

		public bool IsBowtieVertex(int vID)
		{
			if (vertices_refcount.isValid(vID))
			{
				int vtxTriangleCount = GetVtxTriangleCount(vID);
				int vtxEdgeCount = GetVtxEdgeCount(vID);
				if (vtxTriangleCount != vtxEdgeCount && vtxTriangleCount != vtxEdgeCount - 1)
				{
					return true;
				}
				return false;
			}
			throw new Exception("NTMesh3.IsBowtieVertex: " + vID + " is not a valid vertex");
		}

		public AxisAlignedBox3d GetBounds()
		{
			double num = 0.0;
			double num2 = 0.0;
			double num3 = 0.0;
			IEnumerator enumerator = vertices_refcount.GetEnumerator();
			try
			{
				if (enumerator.MoveNext())
				{
					int num4 = (int)enumerator.Current;
					num = vertices[3 * num4];
					num2 = vertices[3 * num4 + 1];
					num3 = vertices[3 * num4 + 2];
				}
			}
			finally
			{
				IDisposable disposable = enumerator as IDisposable;
				if (disposable != null)
				{
					disposable.Dispose();
				}
			}
			double num5 = num;
			double num6 = num;
			double num7 = num2;
			double num8 = num2;
			double num9 = num3;
			double num10 = num3;
			foreach (int item in vertices_refcount)
			{
				num = vertices[3 * item];
				num2 = vertices[3 * item + 1];
				num3 = vertices[3 * item + 2];
				if (num < num5)
				{
					num5 = num;
				}
				else if (num > num6)
				{
					num6 = num;
				}
				if (num2 < num7)
				{
					num7 = num2;
				}
				else if (num2 > num8)
				{
					num8 = num2;
				}
				if (num3 < num9)
				{
					num9 = num3;
				}
				else if (num3 > num10)
				{
					num10 = num3;
				}
			}
			return new AxisAlignedBox3d(num5, num7, num9, num6, num8, num10);
		}

		public bool IsClosed()
		{
			if (TriangleCount == 0)
			{
				return false;
			}
			if (MaxEdgeID / EdgeCount > 5)
			{
				foreach (int item in edges_refcount)
				{
					if (edge_is_boundary(item))
					{
						return false;
					}
				}
			}
			else
			{
				int maxEdgeID = MaxEdgeID;
				for (int i = 0; i < maxEdgeID; i++)
				{
					if (edges_refcount.isValid(i) && edge_is_boundary(i))
					{
						return false;
					}
				}
			}
			return true;
		}

		private void set_triangle(int tid, int v0, int v1, int v2)
		{
			int num = 3 * tid;
			triangles[num] = v0;
			triangles[num + 1] = v1;
			triangles[num + 2] = v2;
		}

		private void set_triangle_edges(int tid, int e0, int e1, int e2)
		{
			int num = 3 * tid;
			triangle_edges[num] = e0;
			triangle_edges[num + 1] = e1;
			triangle_edges[num + 2] = e2;
		}

		private int add_edge(int vA, int vB, int tA, int tB = -1)
		{
			if (vB < vA)
			{
				int num = vB;
				vB = vA;
				vA = num;
			}
			int num2 = edges_refcount.allocate();
			allocate_edge_triangles_list(num2);
			int num3 = 2 * num2;
			edges.insert(vA, num3);
			edges.insert(vB, num3 + 1);
			if (tA != -1)
			{
				edge_triangles.Insert(num2, tA);
			}
			if (tB != -1)
			{
				edge_triangles.Insert(num2, tB);
			}
			vertex_edges.Insert(vA, num2);
			vertex_edges.Insert(vB, num2);
			return num2;
		}

		private int replace_tri_vertex(int tID, int vOld, int vNew)
		{
			int num = 3 * tID;
			if (triangles[num] == vOld)
			{
				triangles[num] = vNew;
				return 0;
			}
			if (triangles[num + 1] == vOld)
			{
				triangles[num + 1] = vNew;
				return 1;
			}
			if (triangles[num + 2] == vOld)
			{
				triangles[num + 2] = vNew;
				return 2;
			}
			return -1;
		}

		private int add_triangle_only(int a, int b, int c, int e0, int e1, int e2)
		{
			int num = triangles_refcount.allocate();
			int num2 = 3 * num;
			triangles.insert(c, num2 + 2);
			triangles.insert(b, num2 + 1);
			triangles.insert(a, num2);
			triangle_edges.insert(e2, num2 + 2);
			triangle_edges.insert(e1, num2 + 1);
			triangle_edges.insert(e0, num2);
			return num;
		}

		private void allocate_vertex_edges_list(int vid)
		{
			if (vid < vertex_edges.Size)
			{
				vertex_edges.Clear(vid);
			}
			vertex_edges.AllocateAt(vid);
		}

		private List<int> vertex_edges_list(int vid)
		{
			return new List<int>(vertex_edges.ValueItr(vid));
		}

		private void allocate_edge_triangles_list(int eid)
		{
			if (eid < edge_triangles.Size)
			{
				edge_triangles.Clear(eid);
			}
			edge_triangles.AllocateAt(eid);
		}

		private void set_edge_vertices(int eID, int a, int b)
		{
			int num = 2 * eID;
			edges[num] = Math.Min(a, b);
			edges[num + 1] = Math.Max(a, b);
		}

		private int replace_edge_vertex(int eID, int vOld, int vNew)
		{
			int num = 2 * eID;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			if (num2 == vOld)
			{
				edges[num] = Math.Min(num3, vNew);
				edges[num + 1] = Math.Max(num3, vNew);
				return 0;
			}
			if (num3 == vOld)
			{
				edges[num] = Math.Min(num2, vNew);
				edges[num + 1] = Math.Max(num2, vNew);
				return 1;
			}
			return -1;
		}

		private bool replace_edge_triangle(int eID, int tOld, int tNew)
		{
			bool result = edge_triangles.Remove(eID, tOld);
			edge_triangles.Insert(eID, tNew);
			return result;
		}

		private void add_edge_triangle(int eID, int tID)
		{
			edge_triangles.Insert(eID, tID);
		}

		private bool remove_edge_triangle(int eID, int tID)
		{
			return edge_triangles.Remove(eID, tID);
		}

		private int replace_triangle_edge(int tID, int eOld, int eNew)
		{
			int num = 3 * tID;
			if (triangle_edges[num] == eOld)
			{
				triangle_edges[num] = eNew;
				return 0;
			}
			if (triangle_edges[num + 1] == eOld)
			{
				triangle_edges[num + 1] = eNew;
				return 1;
			}
			if (triangle_edges[num + 2] == eOld)
			{
				triangle_edges[num + 2] = eNew;
				return 2;
			}
			return -1;
		}

		public MeshResult RemoveTriangle(int tID, bool bRemoveIsolatedVertices = true)
		{
			if (!triangles_refcount.isValid(tID))
			{
				return MeshResult.Failed_NotATriangle;
			}
			Index3i triangle = GetTriangle(tID);
			Index3i triEdges = GetTriEdges(tID);
			for (int i = 0; i < 3; i++)
			{
				int num = triEdges[i];
				remove_edge_triangle(num, tID);
				if (edge_triangles.Count(num) == 0)
				{
					int list_index = edges[2 * num];
					vertex_edges.Remove(list_index, num);
					int list_index2 = edges[2 * num + 1];
					vertex_edges.Remove(list_index2, num);
					edges_refcount.decrement(num, 1);
				}
			}
			triangles_refcount.decrement(tID, 1);
			for (int j = 0; j < 3; j++)
			{
				int num2 = triangle[j];
				vertices_refcount.decrement(num2, 1);
				if (bRemoveIsolatedVertices && vertices_refcount.refCount(num2) == 1)
				{
					vertices_refcount.decrement(num2, 1);
					vertex_edges.Clear(num2);
				}
			}
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public MeshResult SplitEdge(int vA, int vB, out EdgeSplitInfo split)
		{
			int num = find_edge(vA, vB);
			if (num == -1)
			{
				split = default(EdgeSplitInfo);
				return MeshResult.Failed_NotAnEdge;
			}
			return SplitEdge(num, out split);
		}

		public MeshResult SplitEdge(int eab, out EdgeSplitInfo split)
		{
			split = default(EdgeSplitInfo);
			if (!IsEdge(eab))
			{
				return MeshResult.Failed_NotAnEdge;
			}
			int num = 2 * eab;
			int num2 = edges[num];
			int num3 = edges[num + 1];
			List<int> list = new List<int>(edge_triangles.ValueItr(eab));
			if (list.Count < 1)
			{
				return MeshResult.Failed_BrokenTopology;
			}
			Vector3d v = 0.5 * (GetVertex(num2) + GetVertex(num3));
			int num4 = AppendVertex(v);
			if (HasVertexNormals)
			{
				SetVertexNormal(num4, (GetVertexNormal(num2) + GetVertexNormal(num3)).Normalized);
			}
			if (HasVertexColors)
			{
				SetVertexColor(num4, 0.5f * (GetVertexColor(num2) + GetVertexColor(num3)));
			}
			replace_edge_vertex(eab, num3, num4);
			vertex_edges.Remove(num3, eab);
			vertex_edges.Insert(num4, eab);
			int num5 = add_edge(num4, num3, -1);
			vertices_refcount.increment(num4, (short)list.Count);
			split.NewEdges = new List<int>();
			split.eNewBN = num5;
			foreach (int item in list)
			{
				Index3i tri_verts = GetTriangle(item);
				Index3i triEdges = GetTriEdges(item);
				int num6 = IndexUtil.find_tri_other_vtx(num2, num3, tri_verts);
				replace_tri_vertex(item, num3, num4);
				int num7 = triEdges[IndexUtil.find_edge_index_in_tri(num3, num6, ref tri_verts)];
				bool num8 = IndexUtil.is_ordered(num2, num3, ref tri_verts);
				int num9 = (num8 ? add_triangle_only(num4, num3, num6, -1, -1, -1) : add_triangle_only(num3, num4, num6, -1, -1, -1));
				if (triangle_groups != null)
				{
					triangle_groups.insert(triangle_groups[item], num9);
				}
				replace_edge_triangle(num7, item, num9);
				add_edge_triangle(num5, num9);
				int num10 = add_edge(num6, num4, item, num9);
				split.NewEdges.Add(num10);
				replace_triangle_edge(item, num7, num10);
				if (num8)
				{
					set_triangle_edges(num9, num5, num7, num10);
				}
				else
				{
					set_triangle_edges(num9, num5, num10, num7);
				}
				vertices_refcount.increment(num6, 1);
				vertices_refcount.increment(num4, 1);
			}
			split.bIsBoundary = list.Count == 1;
			split.vNew = num4;
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public virtual MeshResult PokeTriangle(int tid, out PokeTriangleInfo result)
		{
			return PokeTriangle(tid, Vector3d.One / 3.0, out result);
		}

		public virtual MeshResult PokeTriangle(int tid, Vector3d baryCoordinates, out PokeTriangleInfo result)
		{
			result = default(PokeTriangleInfo);
			if (!IsTriangle(tid))
			{
				return MeshResult.Failed_NotATriangle;
			}
			Index3i triangle = GetTriangle(tid);
			Index3i triEdges = GetTriEdges(tid);
			Vector3d v = (GetVertex(triangle.a) + GetVertex(triangle.b) + GetVertex(triangle.c)) / 3.0;
			int num = AppendVertex(v);
			int num2 = add_edge(triangle.a, num, -1);
			int num3 = add_edge(triangle.b, num, -1);
			int num4 = add_edge(triangle.c, num, -1);
			vertices_refcount.increment(triangle.a, 1);
			vertices_refcount.increment(triangle.b, 1);
			vertices_refcount.increment(triangle.c, 1);
			vertices_refcount.increment(num, 3);
			set_triangle(tid, triangle.a, triangle.b, num);
			set_triangle_edges(tid, triEdges.a, num3, num2);
			int num5 = add_triangle_only(triangle.b, triangle.c, num, triEdges.b, num4, num3);
			int num6 = add_triangle_only(triangle.c, triangle.a, num, triEdges.c, num2, num4);
			replace_edge_triangle(triEdges.b, tid, num5);
			replace_edge_triangle(triEdges.c, tid, num6);
			add_edge_triangle(num2, tid);
			add_edge_triangle(num2, num6);
			add_edge_triangle(num3, tid);
			add_edge_triangle(num3, num5);
			add_edge_triangle(num4, num5);
			add_edge_triangle(num4, num6);
			if (HasTriangleGroups)
			{
				int value = triangle_groups[tid];
				triangle_groups.insert(value, num5);
				triangle_groups.insert(value, num6);
			}
			result.new_vid = num;
			result.new_t1 = num5;
			result.new_t2 = num6;
			result.new_edges = new Index3i(num2, num3, num4);
			updateTimeStamp(bShapeChange: true);
			return MeshResult.Ok;
		}

		public DMesh3 Deconstruct()
		{
			DMesh3 dMesh = new DMesh3();
			foreach (Index3i item in Triangles())
			{
				dMesh.AppendTriangle(dMesh.AppendVertex(GetVertex(item.a)), dMesh.AppendVertex(GetVertex(item.b)), dMesh.AppendVertex(GetVertex(item.c)));
			}
			return dMesh;
		}

		[Conditional("DEBUG")]
		public void debug_check_is_vertex(int v)
		{
			if (!IsVertex(v))
			{
				throw new Exception("DMesh3.debug_is_vertex - not a vertex!");
			}
		}

		[Conditional("DEBUG")]
		public void debug_check_is_triangle(int t)
		{
			if (!IsTriangle(t))
			{
				throw new Exception("DMesh3.debug_is_triangle - not a triangle!");
			}
		}

		[Conditional("DEBUG")]
		public void debug_check_is_edge(int e)
		{
			if (!IsEdge(e))
			{
				throw new Exception("DMesh3.debug_is_edge - not an edge!");
			}
		}

		public bool CheckValidity(FailMode eFailMode = FailMode.Throw)
		{
			int[] array = new int[MaxVertexID];
			bool is_ok = true;
			Action<bool> action = delegate(bool b)
			{
				is_ok &= b;
			};
			switch (eFailMode)
			{
			case FailMode.DebugAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.gDevAssert:
				action = delegate(bool b)
				{
					is_ok &= b;
				};
				break;
			case FailMode.Throw:
				action = delegate(bool b)
				{
					if (!b)
					{
						throw new Exception("DMesh3.CheckValidity: check failed");
					}
				};
				break;
			}
			if (normals != null)
			{
				action(normals.size == vertices.size);
			}
			if (colors != null)
			{
				action(colors.size == vertices.size);
			}
			if (triangle_groups != null)
			{
				action(triangle_groups.size == triangles.size / 3);
			}
			foreach (int item in TriangleIndices())
			{
				action(IsTriangle(item));
				action(triangles_refcount.refCount(item) == 1);
				Index3i triangle = GetTriangle(item);
				for (int num = 0; num < 3; num++)
				{
					action(IsVertex(triangle[num]));
					array[triangle[num]]++;
				}
				Index3i index3i = default(Index3i);
				for (int num2 = 0; num2 < 3; num2++)
				{
					int vA = triangle[num2];
					int vB = triangle[(num2 + 1) % 3];
					index3i[num2] = FindEdge(vA, vB);
					action(index3i[num2] != -1);
					action(edge_has_t(index3i[num2], item));
					action(index3i[num2] == FindEdgeFromTri(vA, vB, item));
				}
				action(index3i[0] != index3i[1] && index3i[0] != index3i[2] && index3i[1] != index3i[2]);
				Index3i triEdges = GetTriEdges(item);
				for (int num3 = 0; num3 < 3; num3++)
				{
					int num4 = triEdges[num3];
					action(IsEdge(num4));
					if (edge_is_boundary(num4))
					{
						action(tri_is_boundary(item));
						continue;
					}
					bool obj = false;
					foreach (int item2 in EdgeTrianglesItr(num4))
					{
						if (item2 != item)
						{
							action(tri_has_neighbour_t(item2, item));
						}
						else
						{
							obj = true;
						}
					}
					action(obj);
					int a = triangle[num3];
					int a2 = triangle[(num3 + 1) % 3];
					Index2i edgeV = GetEdgeV(triEdges[num3]);
					action(IndexUtil.same_pair_unordered(a, a2, edgeV[0], edgeV[1]));
				}
			}
			foreach (int item3 in EdgeIndices())
			{
				action(IsEdge(item3));
				action(edges_refcount.refCount(item3) == 1);
				Index2i edgeV2 = GetEdgeV(item3);
				action(IsVertex(edgeV2[0]));
				action(IsVertex(edgeV2[1]));
				action(edgeV2[0] < edgeV2[1]);
				foreach (int item4 in EdgeTrianglesItr(item3))
				{
					action(IsTriangle(item4));
				}
			}
			if (vertices_refcount.is_dense)
			{
				for (int num5 = 0; num5 < vertices.Length / 3; num5++)
				{
					action(vertices_refcount.isValid(num5));
				}
			}
			foreach (int item5 in VertexIndices())
			{
				action(IsVertex(item5));
				Vector3d vertex = GetVertex(item5);
				action(!double.IsNaN(vertex.LengthSquared));
				action(!double.IsInfinity(vertex.LengthSquared));
				foreach (int item6 in vertex_edges.ValueItr(item5))
				{
					action(IsEdge(item6));
					action(edge_has_v(item6, item5));
					int num6 = edge_other_v(item6, item5);
					int num7 = find_edge(item5, num6);
					action(num7 != -1);
					action(num7 == item6);
					num7 = find_edge(num6, item5);
					action(num7 != -1);
					action(num7 == item6);
				}
				foreach (int item7 in VtxVerticesItr(item5))
				{
					action(IsVertex(item7));
					int eID = find_edge(item5, item7);
					action(IsEdge(eID));
				}
				List<int> list = new List<int>();
				GetVtxTriangles(item5, list);
				action(vertices_refcount.refCount(item5) == list.Count + 1);
				action(array[item5] == list.Count);
				foreach (int item8 in list)
				{
					action(tri_has_v(item8, item5));
				}
				List<int> list2 = new List<int>(list);
				foreach (int item9 in vertex_edges.ValueItr(item5))
				{
					foreach (int item10 in EdgeTrianglesItr(item9))
					{
						action(list.Contains(item10));
						list2.Remove(item10);
					}
				}
				action(list2.Count == 0);
			}
			return is_ok;
		}
	}
	public class Reducer : MeshRefinerBase
	{
		public enum TargetProjectionMode
		{
			NoProjection,
			AfterRefinement,
			Inline
		}

		protected enum TargetModes
		{
			TriangleCount,
			VertexCount,
			MinEdgeLength
		}

		protected struct QEdge(int edge_id, ref QuadricError qin, ref Vector3d pt)
		{
			public int eid = edge_id;

			public QuadricError q = qin;

			public Vector3d collapse_pt = pt;
		}

		protected enum ProcessResult
		{
			Ok_Collapsed,
			Ignored_CannotCollapse,
			Ignored_EdgeIsFullyConstrained,
			Ignored_EdgeTooLong,
			Ignored_Constrained,
			Ignored_CreatesFlip,
			Failed_OpNotSuccessful,
			Failed_NotAnEdge
		}

		protected IProjectionTarget target;

		public bool MinimizeQuadricPositionError = true;

		public bool PreserveBoundaryShape = true;

		public List<int> DebugEdges = new List<int>();

		public TargetProjectionMode ProjectionMode = TargetProjectionMode.AfterRefinement;

		public bool ENABLE_PROFILING;

		protected double MinEdgeLength = double.MaxValue;

		protected int TargetCount = int.MaxValue;

		protected TargetModes ReduceMode;

		protected QuadricError[] vertQuadrics;

		protected QEdge[] EdgeQuadrics;

		protected IndexPriorityQueue EdgeQueue;

		protected bool HaveBoundary;

		protected bool[] IsBoundaryVtxCache;

		private const int nPrime = 31337;

		private int nMaxEdgeID;

		public bool ENABLE_DEBUG_CHECKS;

		private int COUNT_COLLAPSES;

		private int COUNT_ITERATIONS;

		private Stopwatch AllOpsW;

		private Stopwatch SetupW;

		private Stopwatch ProjectW;

		private Stopwatch CollapseW;

		private bool EnableInlineProjection => ProjectionMode == TargetProjectionMode.Inline;

		public Reducer(DMesh3 m)
			: base(m)
		{
		}

		protected Reducer()
		{
		}

		public void SetProjectionTarget(IProjectionTarget target)
		{
			this.target = target;
		}

		public virtual void DoReduce()
		{
			if (mesh.TriangleCount == 0)
			{
				return;
			}
			begin_pass();
			begin_setup();
			Precompute();
			if (Cancelled())
			{
				return;
			}
			InitializeVertexQuadrics();
			if (Cancelled())
			{
				return;
			}
			InitializeQueue();
			if (Cancelled())
			{
				return;
			}
			end_setup();
			begin_ops();
			begin_collapse();
			while (EdgeQueue.Count > 0)
			{
				if (ReduceMode == TargetModes.VertexCount)
				{
					if (mesh.VertexCount <= TargetCount)
					{
						break;
					}
				}
				else if (mesh.TriangleCount <= TargetCount)
				{
					break;
				}
				COUNT_ITERATIONS++;
				int num = EdgeQueue.Dequeue();
				if (mesh.IsEdge(num))
				{
					if (Cancelled())
					{
						return;
					}
					if (CollapseEdge(num, EdgeQuadrics[num].collapse_pt, out var collapseToV) == ProcessResult.Ok_Collapsed)
					{
						vertQuadrics[collapseToV] = EdgeQuadrics[num].q;
						UpdateNeighbours(collapseToV);
					}
				}
			}
			end_collapse();
			end_ops();
			if (!Cancelled())
			{
				Reproject();
				end_pass();
			}
		}

		public virtual void ReduceToTriangleCount(int nCount)
		{
			ReduceMode = TargetModes.TriangleCount;
			TargetCount = Math.Max(1, nCount);
			MinEdgeLength = double.MaxValue;
			DoReduce();
		}

		public virtual void ReduceToVertexCount(int nCount)
		{
			ReduceMode = TargetModes.VertexCount;
			TargetCount = Math.Max(3, nCount);
			MinEdgeLength = double.MaxValue;
			DoReduce();
		}

		public virtual void ReduceToEdgeLength(double minEdgeLen)
		{
			ReduceMode = TargetModes.MinEdgeLength;
			TargetCount = 1;
			MinEdgeLength = minEdgeLen;
			DoReduce();
		}

		public virtual void FastCollapsePass(double fMinEdgeLength, int nRounds = 1, bool MeshIsClosedHint = false)
		{
			if (mesh.TriangleCount == 0)
			{
				return;
			}
			MinEdgeLength = fMinEdgeLength;
			double num = MinEdgeLength * MinEdgeLength;
			HaveBoundary = false;
			begin_pass();
			begin_setup();
			Precompute(MeshIsClosedHint);
			if (Cancelled())
			{
				return;
			}
			end_setup();
			begin_ops();
			begin_collapse();
			int maxEdgeID = mesh.MaxEdgeID;
			int num2 = 0;
			for (int i = 0; i < nRounds; i++)
			{
				num2 = 0;
				Vector3d a = Vector3d.Zero;
				Vector3d b = Vector3d.Zero;
				for (int j = 0; j < maxEdgeID; j++)
				{
					if (!mesh.IsEdge(j) || mesh.IsBoundaryEdge(j))
					{
						continue;
					}
					if (Cancelled())
					{
						return;
					}
					mesh.GetEdgeV(j, ref a, ref b);
					if (!(a.DistanceSquared(ref b) > num))
					{
						COUNT_ITERATIONS++;
						Vector3d vNewPos = (a + b) * 0.5;
						if (CollapseEdge(j, vNewPos, out var _) == ProcessResult.Ok_Collapsed)
						{
							num2++;
						}
					}
				}
				if (num2 == 0)
				{
					break;
				}
			}
			end_collapse();
			end_ops();
			if (!Cancelled())
			{
				Reproject();
				end_pass();
			}
		}

		protected virtual void InitializeVertexQuadrics()
		{
			int maxTriangleID = mesh.MaxTriangleID;
			QuadricError[] triQuadrics = new QuadricError[maxTriangleID];
			double[] triAreas = new double[maxTriangleID];
			gParallel.BlockStartEnd(0, mesh.MaxTriangleID - 1, delegate(int start_tid, int end_tid)
			{
				for (int i = start_tid; i <= end_tid; i++)
				{
					if (mesh.IsTriangle(i))
					{
						mesh.GetTriInfo(i, out var normal, out triAreas[i], out var vCentroid);
						triQuadrics[i] = new QuadricError(ref normal, ref vCentroid);
					}
				}
			});
			int maxVertexID = mesh.MaxVertexID;
			vertQuadrics = new QuadricError[maxVertexID];
			gParallel.BlockStartEnd(0, mesh.MaxVertexID - 1, delegate(int start_vid, int end_vid)
			{
				for (int i = start_vid; i <= end_vid; i++)
				{
					vertQuadrics[i] = QuadricError.Zero;
					if (mesh.IsVertex(i))
					{
						foreach (int item in mesh.VtxTrianglesItr(i))
						{
							vertQuadrics[i].Add(triAreas[item], ref triQuadrics[item]);
						}
					}
				}
			});
		}

		protected virtual void InitializeQueue()
		{
			_ = mesh.EdgeCount;
			int maxEdgeID = mesh.MaxEdgeID;
			EdgeQuadrics = new QEdge[maxEdgeID];
			EdgeQueue = new IndexPriorityQueue(maxEdgeID);
			float[] edgeErrors = new float[maxEdgeID];
			gParallel.BlockStartEnd(0, maxEdgeID - 1, delegate(int start_eid, int end_eid)
			{
				for (int i = start_eid; i <= end_eid; i++)
				{
					if (mesh.IsEdge(i))
					{
						Index2i edgeV = mesh.GetEdgeV(i);
						QuadricError q = new QuadricError(ref vertQuadrics[edgeV.a], ref vertQuadrics[edgeV.b]);
						Vector3d pt = OptimalPoint(i, ref q, edgeV.a, edgeV.b);
						edgeErrors[i] = (float)q.Evaluate(ref pt);
						EdgeQuadrics[i] = new QEdge(i, ref q, ref pt);
					}
				}
			});
			int[] array = new int[maxEdgeID];
			for (int num = 0; num < maxEdgeID; num++)
			{
				array[num] = num;
			}
			Array.Sort(edgeErrors, array);
			for (int num2 = 0; num2 < edgeErrors.Length; num2++)
			{
				int num3 = array[num2];
				if (mesh.IsEdge(num3))
				{
					QEdge qEdge = EdgeQuadrics[num3];
					EdgeQueue.Insert(qEdge.eid, edgeErrors[num2]);
				}
			}
		}

		protected Vector3d OptimalPoint(int eid, ref QuadricError q, int ea, int eb)
		{
			if (HaveBoundary && PreserveBoundaryShape)
			{
				if (mesh.IsBoundaryEdge(eid))
				{
					return (mesh.GetVertex(ea) + mesh.GetVertex(eb)) * 0.5;
				}
				if (IsBoundaryV(ea))
				{
					return mesh.GetVertex(ea);
				}
				if (IsBoundaryV(eb))
				{
					return mesh.GetVertex(eb);
				}
			}
			if (!MinimizeQuadricPositionError)
			{
				return project((mesh.GetVertex(ea) + mesh.GetVertex(eb)) * 0.5);
			}
			Vector3d result = Vector3d.Zero;
			if (q.OptimalPoint(ref result))
			{
				return project(result);
			}
			Vector3d pt = mesh.GetVertex(ea);
			Vector3d pt2 = mesh.GetVertex(eb);
			Vector3d pt3 = project((pt + pt2) * 0.5);
			double num = q.Evaluate(ref pt);
			double num2 = q.Evaluate(ref pt2);
			double c = q.Evaluate(ref pt3);
			double num3 = MathUtil.Min(num, num2, c);
			if (num3 == num)
			{
				return pt;
			}
			if (num3 == num2)
			{
				return pt2;
			}
			return pt3;
		}

		private Vector3d project(Vector3d pos)
		{
			if (EnableInlineProjection && target != null)
			{
				return target.Project(pos);
			}
			return pos;
		}

		protected virtual void UpdateNeighbours(int vid)
		{
			foreach (int item in mesh.VtxEdgesItr(vid))
			{
				Index2i edgeV = mesh.GetEdgeV(item);
				QuadricError q = new QuadricError(ref vertQuadrics[edgeV.a], ref vertQuadrics[edgeV.b]);
				Vector3d pt = OptimalPoint(item, ref q, edgeV.a, edgeV.b);
				double num = q.Evaluate(ref pt);
				EdgeQuadrics[item] = new QEdge(item, ref q, ref pt);
				if (EdgeQueue.Contains(item))
				{
					EdgeQueue.Update(item, (float)num);
				}
				else
				{
					EdgeQueue.Insert(item, (float)num);
				}
			}
		}

		protected virtual void Reproject()
		{
			begin_project();
			if (target != null && ProjectionMode == TargetProjectionMode.AfterRefinement)
			{
				FullProjectionPass();
				DoDebugChecks();
			}
			end_project();
		}

		protected virtual void Precompute(bool bMeshIsClosed = false)
		{
			HaveBoundary = false;
			IsBoundaryVtxCache = new bool[mesh.MaxVertexID];
			if (bMeshIsClosed)
			{
				return;
			}
			foreach (int item in mesh.BoundaryEdgeIndices())
			{
				Index2i edgeV = mesh.GetEdgeV(item);
				IsBoundaryVtxCache[edgeV.a] = true;
				IsBoundaryVtxCache[edgeV.b] = true;
				HaveBoundary = true;
			}
		}

		protected bool IsBoundaryV(int vid)
		{
			return IsBoundaryVtxCache[vid];
		}

		protected virtual void OnEdgeCollapse(int edgeID, int va, int vb, DMesh3.EdgeCollapseInfo collapseInfo)
		{
		}

		protected virtual int start_edges()
		{
			nMaxEdgeID = mesh.MaxEdgeID;
			return 0;
		}

		protected virtual int next_edge(int cur_eid, out bool bDone)
		{
			int num = (cur_eid + 31337) % nMaxEdgeID;
			bDone = num == 0;
			return num;
		}

		protected virtual IEnumerable<int> project_vertices()
		{
			return mesh.VertexIndices();
		}

		protected virtual ProcessResult CollapseEdge(int edgeID, Vector3d vNewPos, out int collapseToV)
		{
			collapseToV = -1;
			EdgeConstraint edgeConstraint = ((constraints == null) ? EdgeConstraint.Unconstrained : constraints.GetEdgeConstraint(edgeID));
			if (edgeConstraint.NoModifications)
			{
				return ProcessResult.Ignored_EdgeIsFullyConstrained;
			}
			if (!edgeConstraint.CanCollapse)
			{
				return ProcessResult.Ignored_EdgeIsFullyConstrained;
			}
			int a = 0;
			int b = 0;
			int t = 0;
			int t2 = 0;
			if (!mesh.GetEdge(edgeID, ref a, ref b, ref t, ref t2))
			{
				return ProcessResult.Failed_NotAnEdge;
			}
			bool num = t2 == -1;
			int c = IndexUtil.find_tri_other_vtx(tri_verts: mesh.GetTriangle(t), a: a, b: b);
			Index3i tri_verts = (num ? DMesh3.InvalidTriangle : mesh.GetTriangle(t2));
			int d = (num ? (-1) : IndexUtil.find_tri_other_vtx(a, b, tri_verts));
			Vector3d vertex = mesh.GetVertex(a);
			Vector3d vertex2 = mesh.GetVertex(b);
			if ((vertex - vertex2).LengthSquared > MinEdgeLength * MinEdgeLength)
			{
				return ProcessResult.Ignored_EdgeTooLong;
			}
			begin_collapse();
			int collapse_to = -1;
			if (!can_collapse_constraints(edgeID, a, b, c, d, t, t2, out collapse_to))
			{
				return ProcessResult.Ignored_Constrained;
			}
			if (PreserveBoundaryShape && HaveBoundary)
			{
				if (collapse_to != -1 && ((IsBoundaryV(b) && collapse_to != b) || (IsBoundaryV(a) && collapse_to != a)))
				{
					return ProcessResult.Ignored_Constrained;
				}
				if (IsBoundaryV(b))
				{
					collapse_to = b;
				}
				else if (IsBoundaryV(a))
				{
					collapse_to = a;
				}
			}
			ProcessResult result = ProcessResult.Failed_OpNotSuccessful;
			int num2 = b;
			int num3 = a;
			if (collapse_to == b)
			{
				vNewPos = vertex2;
			}
			else if (collapse_to == a)
			{
				num2 = a;
				num3 = b;
				vNewPos = vertex;
			}
			else
			{
				vNewPos = get_projected_collapse_position(num2, vNewPos);
			}
			if (collapse_creates_flip_or_invalid(a, b, ref vNewPos, t, t2) || collapse_creates_flip_or_invalid(b, a, ref vNewPos, t, t2))
			{
				result = ProcessResult.Ignored_CreatesFlip;
			}
			else
			{
				COUNT_COLLAPSES++;
				if (mesh.CollapseEdge(num2, num3, out var collapse) == MeshResult.Ok)
				{
					collapseToV = num2;
					mesh.SetVertex(num2, vNewPos);
					if (constraints != null)
					{
						constraints.ClearEdgeConstraint(edgeID);
						constraints.ClearEdgeConstraint(collapse.eRemoved0);
						if (collapse.eRemoved1 != -1)
						{
							constraints.ClearEdgeConstraint(collapse.eRemoved1);
						}
						constraints.ClearVertexConstraint(num3);
					}
					OnEdgeCollapse(edgeID, num2, num3, collapse);
					DoDebugChecks();
					result = ProcessResult.Ok_Collapsed;
				}
			}
			end_collapse();
			return result;
		}

		protected void project_vertex(int vID, IProjectionTarget targetIn)
		{
			Vector3d vertex = mesh.GetVertex(vID);
			Vector3d vNewPos = targetIn.Project(vertex, vID);
			mesh.SetVertex(vID, vNewPos);
		}

		protected Vector3d get_projected_collapse_position(int vid, Vector3d vNewPos)
		{
			if (constraints != null)
			{
				VertexConstraint vertexConstraint = constraints.GetVertexConstraint(vid);
				if (vertexConstraint.Target != null)
				{
					return vertexConstraint.Target.Project(vNewPos, vid);
				}
				_ = vertexConstraint.Fixed;
				return vNewPos;
			}
			return vNewPos;
		}

		protected virtual void FullProjectionPass()
		{
			Action<int> body = delegate(int vID)
			{
				if (!vertex_is_constrained(vID))
				{
					Vector3d vertex = mesh.GetVertex(vID);
					Vector3d vNewPos = target.Project(vertex, vID);
					mesh.SetVertex(vID, vNewPos);
				}
			};
			gParallel.ForEach(project_vertices(), body);
		}

		[Conditional("DEBUG")]
		protected virtual void RuntimeDebugCheck(int eid)
		{
			if (DebugEdges.Contains(eid))
			{
				Debugger.Break();
			}
		}

		protected virtual void DoDebugChecks()
		{
			if (ENABLE_DEBUG_CHECKS)
			{
				DebugCheckVertexConstraints();
			}
		}

		protected virtual void DebugCheckVertexConstraints()
		{
			if (constraints == null)
			{
				return;
			}
			foreach (KeyValuePair<int, VertexConstraint> item in constraints.VertexConstraintsItr())
			{
				int key = item.Key;
				if (item.Value.Target != null)
				{
					Vector3d vertex = mesh.GetVertex(key);
					Vector3d v = item.Value.Target.Project(vertex, key);
					if (vertex.DistanceSquared(v) > 9.999999747378752E-05)
					{
						Util.gBreakToDebugger();
					}
				}
			}
		}

		protected virtual void begin_pass()
		{
			if (ENABLE_PROFILING)
			{
				COUNT_COLLAPSES = 0;
				COUNT_ITERATIONS = 0;
				AllOpsW = new Stopwatch();
				SetupW = new Stopwatch();
				ProjectW = new Stopwatch();
				CollapseW = new Stopwatch();
			}
		}

		protected virtual void end_pass()
		{
			if (ENABLE_PROFILING)
			{
				Console.WriteLine($"ReducePass: T {mesh.TriangleCount} V {mesh.VertexCount} collapses {COUNT_COLLAPSES}  iterations {COUNT_ITERATIONS}");
				Console.WriteLine($"           Timing1: setup {Util.ToSecMilli(SetupW.Elapsed)} ops {Util.ToSecMilli(AllOpsW.Elapsed)} project {Util.ToSecMilli(ProjectW.Elapsed)}");
			}
		}

		protected virtual void begin_ops()
		{
			if (ENABLE_PROFILING)
			{
				AllOpsW.Start();
			}
		}

		protected virtual void end_ops()
		{
			if (ENABLE_PROFILING)
			{
				AllOpsW.Stop();
			}
		}

		protected virtual void begin_setup()
		{
			if (ENABLE_PROFILING)
			{
				SetupW.Start();
			}
		}

		protected virtual void end_setup()
		{
			if (ENABLE_PROFILING)
			{
				SetupW.Stop();
			}
		}

		protected virtual void begin_project()
		{
			if (ENABLE_PROFILING)
			{
				ProjectW.Start();
			}
		}

		protected virtual void end_project()
		{
			if (ENABLE_PROFILING)
			{
				ProjectW.Stop();
			}
		}

		protected virtual void begin_collapse()
		{
			if (ENABLE_PROFILING)
			{
				CollapseW.Start();
			}
		}

		protected virtual void end_collapse()
		{
			if (ENABLE_PROFILING)
			{
				CollapseW.Stop();
			}
		}
	}
	public struct QuadricError
	{
		public double Axx;

		public double Axy;

		public double Axz;

		public double Ayy;

		public double Ayz;

		public double Azz;

		public double bx;

		public double by;

		public double bz;

		public double c;

		public static readonly QuadricError Zero;

		public QuadricError(ref Vector3d n, ref Vector3d p)
		{
			Axx = n.x * n.x;
			Axy = n.x * n.y;
			Axz = n.x * n.z;
			Ayy = n.y * n.y;
			Ayz = n.y * n.z;
			Azz = n.z * n.z;
			bx = (by = (bz = (c = 0.0)));
			Vector3d v = multiplyA(ref p);
			bx = 0.0 - v.x;
			by = 0.0 - v.y;
			bz = 0.0 - v.z;
			c = p.Dot(ref v);
		}

		public QuadricError(ref QuadricError a, ref QuadricError b)
		{
			Axx = a.Axx + b.Axx;
			Axy = a.Axy + b.Axy;
			Axz = a.Axz + b.Axz;
			Ayy = a.Ayy + b.Ayy;
			Ayz = a.Ayz + b.Ayz;
			Azz = a.Azz + b.Azz;
			bx = a.bx + b.bx;
			by = a.by + b.by;
			bz = a.bz + b.bz;
			c = a.c + b.c;
		}

		public void Add(double w, ref QuadricError b)
		{
			Axx += w * b.Axx;
			Axy += w * b.Axy;
			Axz += w * b.Axz;
			Ayy += w * b.Ayy;
			Ayz += w * b.Ayz;
			Azz += w * b.Azz;
			bx += w * b.bx;
			by += w * b.by;
			bz += w * b.bz;
			c += w * b.c;
		}

		public double Evaluate(ref Vector3d pt)
		{
			double num = Axx * pt.x + Axy * pt.y + Axz * pt.z;
			double num2 = Axy * pt.x + Ayy * pt.y + Ayz * pt.z;
			double num3 = Axz * pt.x + Ayz * pt.y + Azz * pt.z;
			return pt.x * num + pt.y * num2 + pt.z * num3 + 2.0 * (pt.x * bx + pt.y * by + pt.z * bz) + c;
		}

		private Vector3d multiplyA(ref Vector3d pt)
		{
			double x = Axx * pt.x + Axy * pt.y + Axz * pt.z;
			double y = Axy * pt.x + Ayy * pt.y + Ayz * pt.z;
			double z = Axz * pt.x + Ayz * pt.y + Azz * pt.z;
			return new Vector3d(x, y, z);
		}

		public bool OptimalPoint(ref Vector3d result)
		{
			double num = Azz * Ayy - Ayz * Ayz;
			double num2 = Axz * Ayz - Azz * Axy;
			double num3 = Axy * Ayz - Axz * Ayy;
			double num4 = Azz * Axx - Axz * Axz;
			double num5 = Axy * Axz - Axx * Ayz;
			double num6 = Axx * Ayy - Axy * Axy;
			double num7 = Axx * num + Axy * num2 + Axz * num3;
			if (Math.Abs(num7) > 2.220446049250313E-13)
			{
				num7 = 1.0 / num7;
				num *= num7;
				num2 *= num7;
				num3 *= num7;
				num4 *= num7;
				num5 *= num7;
				num6 *= num7;
				double num8 = num * bx + num2 * by + num3 * bz;
				double num9 = num2 * bx + num4 * by + num5 * bz;
				double num10 = num3 * bx + num5 * by + num6 * bz;
				result = new Vector3d(0.0 - num8, 0.0 - num9, 0.0 - num10);
				return true;
			}
			return false;
		}

		static QuadricError()
		{
			Zero = new QuadricError
			{
				Axx = 0.0,
				Axy = 0.0,
				Axz = 0.0,
				Ayy = 0.0,
				Ayz = 0.0,
				Azz = 0.0,
				bx = 0.0,
				by = 0.0,
				bz = 0.0,
				c = 0.0
			};
		}
	}
	public class RegionRemesher : Remesher
	{
		[Flags]
		public enum QuickRemeshFlags
		{
			NoFlags = 0,
			PreventNormalFlips = 1
		}

		public DMesh3 BaseMesh;

		public DSubmesh3 Region;

		public IndexMap ReinsertSubToBaseMapV;

		public MeshEditor.DuplicateTriBehavior ReinsertDuplicateTriBehavior;

		private MeshConstraints bdry_constraints;

		private int[] cur_base_tris;

		public int[] CurrentBaseTriangles => cur_base_tris;

		public RegionRemesher(DMesh3 mesh, int[] regionTris)
		{
			BaseMesh = mesh;
			Region = new DSubmesh3(mesh, regionTris);
			Region.ComputeBoundaryInfo(regionTris);
			base.mesh = Region.SubMesh;
			cur_base_tris = (int[])regionTris.Clone();
			bdry_constraints = new MeshConstraints();
			MeshConstraintUtil.FixSubmeshBoundaryEdges(bdry_constraints, Region);
			SetExternalConstraints(bdry_constraints);
		}

		public RegionRemesher(DMesh3 mesh, IEnumerable<int> regionTris)
		{
			BaseMesh = mesh;
			Region = new DSubmesh3(mesh, regionTris);
			int tri_count_est = regionTris.Count();
			Region.ComputeBoundaryInfo(regionTris, tri_count_est);
			base.mesh = Region.SubMesh;
			cur_base_tris = regionTris.ToArray();
			bdry_constraints = new MeshConstraints();
			MeshConstraintUtil.FixSubmeshBoundaryEdges(bdry_constraints, Region);
			SetExternalConstraints(bdry_constraints);
		}

		public void RepairPossibleNonManifoldEdges()
		{
			int maxEdgeID = Region.SubMesh.MaxEdgeID;
			List<int> list = new List<int>();
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (!Region.SubMesh.IsEdge(i) || Region.SubMesh.IsBoundaryEdge(i))
				{
					continue;
				}
				Index2i edgeV = Region.SubMesh.GetEdgeV(i);
				if (Region.SubMesh.IsBoundaryVertex(edgeV.a) && Region.SubMesh.IsBoundaryVertex(edgeV.b))
				{
					int num = Region.MapVertexToBaseMesh(edgeV.a);
					int num2 = Region.MapVertexToBaseMesh(edgeV.b);
					if (num != -1 && num2 != -1 && Region.BaseMesh.FindEdge(num, num2) != -1)
					{
						list.Add(i);
					}
				}
			}
			for (int j = 0; j < list.Count; j++)
			{
				Region.SubMesh.SplitEdge(list[j], out var _);
			}
		}

		public void SetSubmeshGroupID(int gid)
		{
			FaceGroupUtil.SetGroupID(Region.SubMesh, gid);
		}

		public bool BackPropropagate(bool bAllowSubmeshRepairs = true)
		{
			if (bAllowSubmeshRepairs)
			{
				RepairPossibleNonManifoldEdges();
			}
			MeshEditor meshEditor = new MeshEditor(BaseMesh);
			meshEditor.RemoveTriangles(cur_base_tris, bRemoveIsolatedVerts: true);
			int[] new_tris = new int[Region.SubMesh.TriangleCount];
			ReinsertSubToBaseMapV = null;
			bool result = meshEditor.ReinsertSubmesh(Region, ref new_tris, out ReinsertSubToBaseMapV, ReinsertDuplicateTriBehavior);
			cur_base_tris = new_tris;
			return result;
		}

		public static RegionRemesher QuickRemesh(DMesh3 mesh, int[] tris, double minEdgeLen, double maxEdgeLen, double smoothSpeed, int rounds, IProjectionTarget target, QuickRemeshFlags flags = QuickRemeshFlags.PreventNormalFlips)
		{
			RegionRemesher regionRemesher = new RegionRemesher(mesh, tris);
			if (target != null)
			{
				regionRemesher.SetProjectionTarget(target);
			}
			regionRemesher.MinEdgeLength = minEdgeLen;
			regionRemesher.MaxEdgeLength = maxEdgeLen;
			regionRemesher.SmoothSpeedT = smoothSpeed;
			if ((flags & QuickRemeshFlags.PreventNormalFlips) != QuickRemeshFlags.NoFlags)
			{
				regionRemesher.PreventNormalFlips = true;
			}
			for (int i = 0; i < rounds; i++)
			{
				regionRemesher.BasicRemeshPass();
			}
			regionRemesher.BackPropropagate();
			return regionRemesher;
		}

		public static RegionRemesher QuickRemesh(DMesh3 mesh, int[] tris, double targetEdgeLen, double smoothSpeed, int rounds, IProjectionTarget target, QuickRemeshFlags flags = QuickRemeshFlags.PreventNormalFlips)
		{
			RegionRemesher regionRemesher = new RegionRemesher(mesh, tris);
			if (target != null)
			{
				regionRemesher.SetProjectionTarget(target);
			}
			regionRemesher.SetTargetEdgeLength(targetEdgeLen);
			regionRemesher.SmoothSpeedT = smoothSpeed;
			if ((flags & QuickRemeshFlags.PreventNormalFlips) != QuickRemeshFlags.NoFlags)
			{
				regionRemesher.PreventNormalFlips = true;
			}
			for (int i = 0; i < rounds; i++)
			{
				regionRemesher.BasicRemeshPass();
			}
			regionRemesher.BackPropropagate();
			return regionRemesher;
		}
	}
	public class Remesher : MeshRefinerBase
	{
		public enum SmoothTypes
		{
			Uniform,
			Cotan,
			MeanValue
		}

		[Flags]
		public enum VertexControl
		{
			AllowAll = 0,
			NoSmooth = 1,
			NoProject = 2,
			NoMovement = 3
		}

		public enum TargetProjectionMode
		{
			NoProjection,
			AfterRefinement,
			Inline
		}

		protected enum ProcessResult
		{
			Ok_Collapsed,
			Ok_Flipped,
			Ok_Split,
			Ignored_EdgeIsFine,
			Ignored_EdgeIsFullyConstrained,
			Failed_OpNotSuccessful,
			Failed_NotAnEdge
		}

		private IProjectionTarget target;

		public bool EnableFlips = true;

		public bool EnableCollapses = true;

		public bool EnableSplits = true;

		public bool EnableSmoothing = true;

		public bool PreventNormalFlips;

		public double MinEdgeLength = 0.0010000000474974513;

		public double MaxEdgeLength = 0.10000000149011612;

		public double SmoothSpeedT = 0.10000000149011612;

		public SmoothTypes SmoothType;

		public Func<DMesh3, int, double, Vector3d> CustomSmoothF;

		public Func<int, VertexControl> VertexControlF;

		public List<int> DebugEdges = new List<int>();

		public TargetProjectionMode ProjectionMode = TargetProjectionMode.AfterRefinement;

		public bool EnableParallelProjection = true;

		public bool EnableParallelSmooth = true;

		public bool EnableSmoothInPlace;

		public bool ENABLE_PROFILING;

		private bool MeshIsClosed;

		public int ModifiedEdgesLastPass;

		private const int nPrime = 31337;

		private int nMaxEdgeID;

		protected DVector<Vector3d> vBufferV = new DVector<Vector3d>();

		protected BitArray vModifiedV = new BitArray(4096);

		public bool ENABLE_DEBUG_CHECKS;

		private int COUNT_SPLITS;

		private int COUNT_COLLAPSES;

		private int COUNT_FLIPS;

		private Stopwatch AllOpsW;

		private Stopwatch SmoothW;

		private Stopwatch ProjectW;

		private Stopwatch FlipW;

		private Stopwatch SplitW;

		private Stopwatch CollapseW;

		private bool EnableInlineProjection => ProjectionMode == TargetProjectionMode.Inline;

		public IProjectionTarget ProjectionTarget => target;

		public Remesher(DMesh3 m)
			: base(m)
		{
		}

		protected Remesher()
		{
		}

		public void SetProjectionTarget(IProjectionTarget target)
		{
			this.target = target;
		}

		public void SetTargetEdgeLength(double fLength)
		{
			MinEdgeLength = fLength * 0.66;
			MaxEdgeLength = fLength * 1.33;
		}

		public virtual void Precompute()
		{
			MeshIsClosed = true;
			foreach (int item in mesh.EdgeIndices())
			{
				if (mesh.IsBoundaryEdge(item))
				{
					MeshIsClosed = false;
					break;
				}
			}
		}

		public virtual void BasicRemeshPass()
		{
			if (mesh.TriangleCount == 0)
			{
				return;
			}
			begin_pass();
			begin_ops();
			int num = start_edges();
			bool bDone = false;
			ModifiedEdgesLastPass = 0;
			do
			{
				if (mesh.IsEdge(num))
				{
					ProcessResult processResult = ProcessEdge(num);
					if (processResult == ProcessResult.Ok_Collapsed || processResult == ProcessResult.Ok_Flipped || processResult == ProcessResult.Ok_Split)
					{
						ModifiedEdgesLastPass++;
					}
				}
				if (Cancelled())
				{
					return;
				}
				num = next_edge(num, out bDone);
			}
			while (!bDone);
			end_ops();
			if (Cancelled())
			{
				return;
			}
			begin_smooth();
			if (EnableSmoothing && SmoothSpeedT > 0.0)
			{
				if (EnableSmoothInPlace)
				{
					FullSmoothPass_InPlace(EnableParallelSmooth);
				}
				else
				{
					FullSmoothPass_Buffer(EnableParallelSmooth);
				}
				DoDebugChecks();
			}
			end_smooth();
			if (!Cancelled())
			{
				begin_project();
				if (target != null && ProjectionMode == TargetProjectionMode.AfterRefinement)
				{
					FullProjectionPass();
					DoDebugChecks();
				}
				end_project();
				if (!Cancelled())
				{
					end_pass();
				}
			}
		}

		protected virtual void OnEdgeSplit(int edgeID, int va, int vb, DMesh3.EdgeSplitInfo splitInfo)
		{
		}

		protected virtual void OnEdgeCollapse(int edgeID, int va, int vb, DMesh3.EdgeCollapseInfo collapseInfo)
		{
		}

		protected virtual int start_edges()
		{
			nMaxEdgeID = mesh.MaxEdgeID;
			return 0;
		}

		protected virtual int next_edge(int cur_eid, out bool bDone)
		{
			int num = (cur_eid + 31337) % nMaxEdgeID;
			bDone = num == 0;
			return num;
		}

		protected virtual IEnumerable<int> smooth_vertices()
		{
			return mesh.VertexIndices();
		}

		protected virtual IEnumerable<int> project_vertices()
		{
			return mesh.VertexIndices();
		}

		protected virtual ProcessResult ProcessEdge(int edgeID)
		{
			EdgeConstraint edgeConstraint = ((constraints == null) ? EdgeConstraint.Unconstrained : constraints.GetEdgeConstraint(edgeID));
			if (edgeConstraint.NoModifications)
			{
				return ProcessResult.Ignored_EdgeIsFullyConstrained;
			}
			int a = 0;
			int b = 0;
			int t = 0;
			int t2 = 0;
			if (!mesh.GetEdge(edgeID, ref a, ref b, ref t, ref t2))
			{
				return ProcessResult.Failed_NotAnEdge;
			}
			bool flag = t2 == -1;
			Index2i edgeOpposingV = mesh.GetEdgeOpposingV(edgeID);
			int a2 = edgeOpposingV.a;
			int b2 = edgeOpposingV.b;
			Vector3d vertex = mesh.GetVertex(a);
			Vector3d vertex2 = mesh.GetVertex(b);
			double num = vertex.DistanceSquared(vertex2);
			begin_collapse();
			int collapse_to = -1;
			bool num2 = EnableCollapses && edgeConstraint.CanCollapse && num < MinEdgeLength * MinEdgeLength && can_collapse_constraints(edgeID, a, b, a2, b2, t, t2, out collapse_to);
			bool flag2 = false;
			if (num2)
			{
				int num3 = b;
				int num4 = a;
				Vector3d vNewPos = (vertex + vertex2) * 0.5;
				if (collapse_to == b)
				{
					vNewPos = vertex2;
				}
				else if (collapse_to == a)
				{
					num3 = a;
					num4 = b;
					vNewPos = vertex;
				}
				else
				{
					vNewPos = get_projected_collapse_position(num3, vNewPos);
				}
				if (!PreventNormalFlips || (!collapse_creates_flip_or_invalid(a, b, ref vNewPos, t, t2) && !collapse_creates_flip_or_invalid(b, a, ref vNewPos, t, t2)))
				{
					COUNT_COLLAPSES++;
					if (mesh.CollapseEdge(num3, num4, out var collapse) == MeshResult.Ok)
					{
						mesh.SetVertex(num3, vNewPos);
						if (constraints != null)
						{
							constraints.ClearEdgeConstraint(edgeID);
							constraints.ClearEdgeConstraint(collapse.eRemoved0);
							if (collapse.eRemoved1 != -1)
							{
								constraints.ClearEdgeConstraint(collapse.eRemoved1);
							}
							constraints.ClearVertexConstraint(num4);
						}
						OnEdgeCollapse(edgeID, num3, num4, collapse);
						DoDebugChecks();
						return ProcessResult.Ok_Collapsed;
					}
					flag2 = true;
				}
			}
			end_collapse();
			begin_flip();
			bool flag3 = false;
			if (EnableFlips && edgeConstraint.CanFlip && !flag)
			{
				bool flag4 = !MeshIsClosed && (flag || mesh.IsBoundaryVertex(a));
				bool flag5 = !MeshIsClosed && (flag || mesh.IsBoundaryVertex(b));
				bool flag6 = !MeshIsClosed && mesh.IsBoundaryVertex(a2);
				bool num5 = !MeshIsClosed && mesh.IsBoundaryVertex(b2);
				int vtxEdgeCount = mesh.GetVtxEdgeCount(a);
				int vtxEdgeCount2 = mesh.GetVtxEdgeCount(b);
				int vtxEdgeCount3 = mesh.GetVtxEdgeCount(a2);
				int vtxEdgeCount4 = mesh.GetVtxEdgeCount(b2);
				int num6 = (flag4 ? vtxEdgeCount : 6);
				int num7 = (flag5 ? vtxEdgeCount2 : 6);
				int num8 = (flag6 ? vtxEdgeCount3 : 6);
				int num9 = (num5 ? vtxEdgeCount4 : 6);
				int num10 = Math.Abs(vtxEdgeCount - num6) + Math.Abs(vtxEdgeCount2 - num7) + Math.Abs(vtxEdgeCount3 - num8) + Math.Abs(vtxEdgeCount4 - num9);
				bool flag7 = Math.Abs(vtxEdgeCount - 1 - num6) + Math.Abs(vtxEdgeCount2 - 1 - num7) + Math.Abs(vtxEdgeCount3 + 1 - num8) + Math.Abs(vtxEdgeCount4 + 1 - num9) < num10;
				if (flag7 && PreventNormalFlips && flip_inverts_normals(a, b, a2, b2, t))
				{
					flag7 = false;
				}
				if (flag7)
				{
					COUNT_FLIPS++;
					if (mesh.FlipEdge(edgeID, out var _) == MeshResult.Ok)
					{
						DoDebugChecks();
						return ProcessResult.Ok_Flipped;
					}
					flag3 = true;
				}
			}
			end_flip();
			begin_split();
			bool flag8 = false;
			if (EnableSplits && edgeConstraint.CanSplit && num > MaxEdgeLength * MaxEdgeLength)
			{
				COUNT_SPLITS++;
				if (mesh.SplitEdge(edgeID, out var split) == MeshResult.Ok)
				{
					update_after_split(edgeID, a, b, ref split);
					OnEdgeSplit(edgeID, a, b, split);
					DoDebugChecks();
					return ProcessResult.Ok_Split;
				}
				flag8 = true;
			}
			end_split();
			if (flag3 || flag8 || flag2)
			{
				return ProcessResult.Failed_OpNotSuccessful;
			}
			return ProcessResult.Ignored_EdgeIsFine;
		}

		protected virtual void update_after_split(int edgeID, int va, int vb, ref DMesh3.EdgeSplitInfo splitInfo)
		{
			bool flag = false;
			if (constraints != null && constraints.HasEdgeConstraint(edgeID))
			{
				constraints.SetOrUpdateEdgeConstraint(splitInfo.eNewBN, constraints.GetEdgeConstraint(edgeID));
				VertexConstraint vertexConstraint = constraints.GetVertexConstraint(va);
				VertexConstraint vertexConstraint2 = constraints.GetVertexConstraint(vb);
				if (vertexConstraint.Fixed && vertexConstraint2.Fixed)
				{
					int setID = ((vertexConstraint.FixedSetID > 0 && vertexConstraint.FixedSetID == vertexConstraint2.FixedSetID) ? vertexConstraint.FixedSetID : (-1));
					constraints.SetOrUpdateVertexConstraint(splitInfo.vNew, new VertexConstraint(isFixed: true, setID));
					flag = true;
				}
				if (vertexConstraint.Target != null || vertexConstraint2.Target != null)
				{
					IProjectionTarget projectionTarget = constraints.GetEdgeConstraint(edgeID).Target;
					IProjectionTarget projectionTarget2 = null;
					if (vertexConstraint.Target == vertexConstraint2.Target && vertexConstraint.Target == projectionTarget)
					{
						projectionTarget2 = projectionTarget;
					}
					else if (vertexConstraint.Target == projectionTarget && vertexConstraint2.Fixed)
					{
						projectionTarget2 = projectionTarget;
					}
					else if (vertexConstraint2.Target == projectionTarget && vertexConstraint.Fixed)
					{
						projectionTarget2 = projectionTarget;
					}
					if (projectionTarget2 != null)
					{
						constraints.SetOrUpdateVertexConstraint(splitInfo.vNew, new VertexConstraint(projectionTarget2));
						project_vertex(splitInfo.vNew, projectionTarget2);
						flag = true;
					}
				}
			}
			if (EnableInlineProjection && !flag && target != null)
			{
				project_vertex(splitInfo.vNew, target);
			}
		}

		protected virtual void project_vertex(int vID, IProjectionTarget targetIn)
		{
			Vector3d vertex = mesh.GetVertex(vID);
			Vector3d vNewPos = targetIn.Project(vertex, vID);
			mesh.SetVertex(vID, vNewPos);
		}

		protected virtual Vector3d get_projected_collapse_position(int vid, Vector3d vNewPos)
		{
			if (constraints != null)
			{
				VertexConstraint vertexConstraint = constraints.GetVertexConstraint(vid);
				if (vertexConstraint.Target != null)
				{
					return vertexConstraint.Target.Project(vNewPos, vid);
				}
				if (vertexConstraint.Fixed)
				{
					return vNewPos;
				}
			}
			if (EnableInlineProjection && target != null && (VertexControlF == null || (VertexControlF(vid) & VertexControl.NoProject) == 0))
			{
				return target.Project(vNewPos, vid);
			}
			return vNewPos;
		}

		protected virtual void FullSmoothPass_InPlace(bool bParallel)
		{
			Func<DMesh3, int, double, Vector3d> smoothFunc = MeshUtil.UniformSmooth;
			if (CustomSmoothF != null)
			{
				smoothFunc = CustomSmoothF;
			}
			else if (SmoothType == SmoothTypes.MeanValue)
			{
				smoothFunc = MeshUtil.MeanValueSmooth;
			}
			else if (SmoothType == SmoothTypes.Cotan)
			{
				smoothFunc = MeshUtil.CotanSmooth;
			}
			Action<int> action = delegate(int vID)
			{
				bool bModified = false;
				Vector3d vNewPos = ComputeSmoothedVertexPos(vID, smoothFunc, out bModified);
				if (bModified)
				{
					mesh.SetVertex(vID, vNewPos);
				}
			};
			if (bParallel)
			{
				gParallel.ForEach(smooth_vertices(), action);
				return;
			}
			foreach (int item in smooth_vertices())
			{
				action(item);
			}
		}

		protected virtual void FullSmoothPass_Buffer(bool bParallel)
		{
			InitializeVertexBufferForPass();
			Func<DMesh3, int, double, Vector3d> smoothFunc = MeshUtil.UniformSmooth;
			if (CustomSmoothF != null)
			{
				smoothFunc = CustomSmoothF;
			}
			else if (SmoothType == SmoothTypes.MeanValue)
			{
				smoothFunc = MeshUtil.MeanValueSmooth;
			}
			else if (SmoothType == SmoothTypes.Cotan)
			{
				smoothFunc = MeshUtil.CotanSmooth;
			}
			Action<int> action = delegate(int vID)
			{
				bool bModified = false;
				Vector3d value = ComputeSmoothedVertexPos(vID, smoothFunc, out bModified);
				if (bModified)
				{
					vModifiedV[vID] = true;
					vBufferV[vID] = value;
				}
			};
			if (bParallel)
			{
				gParallel.ForEach(smooth_vertices(), action);
			}
			else
			{
				foreach (int item in smooth_vertices())
				{
					action(item);
				}
			}
			ApplyVertexBuffer(bParallel);
		}

		protected virtual void InitializeVertexBufferForPass()
		{
			if (vBufferV.size < mesh.MaxVertexID)
			{
				vBufferV.resize(mesh.MaxVertexID + mesh.MaxVertexID / 5);
			}
			if (vModifiedV.Length < mesh.MaxVertexID)
			{
				vModifiedV = new BitArray(2 * mesh.MaxVertexID);
			}
			else
			{
				vModifiedV.SetAll(value: false);
			}
		}

		protected virtual void ApplyVertexBuffer(bool bParallel)
		{
			if (bParallel)
			{
				gParallel.BlockStartEnd(0, mesh.MaxVertexID - 1, delegate(int a, int b)
				{
					for (int i = a; i <= b; i++)
					{
						if (vModifiedV[i])
						{
							base.Mesh.SetVertex(i, vBufferV[i]);
						}
					}
				});
				return;
			}
			foreach (int item in mesh.VertexIndices())
			{
				if (vModifiedV[item])
				{
					base.Mesh.SetVertex(item, vBufferV[item]);
				}
			}
		}

		protected virtual Vector3d ComputeSmoothedVertexPos(int vID, Func<DMesh3, int, double, Vector3d> smoothFunc, out bool bModified)
		{
			bModified = false;
			VertexConstraint vc = VertexConstraint.Unconstrained;
			get_vertex_constraint(vID, ref vc);
			if (vc.Fixed)
			{
				return base.Mesh.GetVertex(vID);
			}
			VertexControl vertexControl = ((VertexControlF != null) ? VertexControlF(vID) : VertexControl.AllowAll);
			if ((vertexControl & VertexControl.NoSmooth) != VertexControl.AllowAll)
			{
				return base.Mesh.GetVertex(vID);
			}
			Vector3d vector3d = smoothFunc(mesh, vID, SmoothSpeedT);
			if (vc.Target != null)
			{
				vector3d = vc.Target.Project(vector3d, vID);
			}
			else if (EnableInlineProjection && target != null && (vertexControl & VertexControl.NoProject) == 0)
			{
				vector3d = target.Project(vector3d, vID);
			}
			bModified = true;
			return vector3d;
		}

		protected virtual void FullProjectionPass()
		{
			Action<int> action = delegate(int vID)
			{
				if (!vertex_is_constrained(vID) && (VertexControlF == null || (VertexControlF(vID) & VertexControl.NoProject) == 0))
				{
					Vector3d vertex = mesh.GetVertex(vID);
					Vector3d vNewPos = target.Project(vertex, vID);
					mesh.SetVertex(vID, vNewPos);
				}
			};
			if (EnableParallelProjection)
			{
				gParallel.ForEach(project_vertices(), action);
				return;
			}
			foreach (int item in project_vertices())
			{
				action(item);
			}
		}

		[Conditional("DEBUG")]
		private void RuntimeDebugCheck(int eid)
		{
			if (DebugEdges.Contains(eid))
			{
				Debugger.Break();
			}
		}

		protected virtual void DoDebugChecks()
		{
			if (ENABLE_DEBUG_CHECKS)
			{
				DebugCheckVertexConstraints();
			}
		}

		private void DebugCheckVertexConstraints()
		{
			if (constraints == null)
			{
				return;
			}
			foreach (KeyValuePair<int, VertexConstraint> item in constraints.VertexConstraintsItr())
			{
				int key = item.Key;
				if (item.Value.Target != null)
				{
					Vector3d vertex = mesh.GetVertex(key);
					Vector3d v = item.Value.Target.Project(vertex, key);
					if (vertex.DistanceSquared(v) > 9.999999747378752E-05)
					{
						Util.gBreakToDebugger();
					}
				}
			}
		}

		protected virtual void begin_pass()
		{
			if (ENABLE_PROFILING)
			{
				COUNT_SPLITS = (COUNT_COLLAPSES = (COUNT_FLIPS = 0));
				AllOpsW = new Stopwatch();
				SmoothW = new Stopwatch();
				ProjectW = new Stopwatch();
				FlipW = new Stopwatch();
				SplitW = new Stopwatch();
				CollapseW = new Stopwatch();
			}
		}

		protected virtual void end_pass()
		{
			if (ENABLE_PROFILING)
			{
				Console.WriteLine($"RemeshPass: T {mesh.TriangleCount} V {mesh.VertexCount} splits {COUNT_SPLITS} flips {COUNT_FLIPS} collapses {COUNT_COLLAPSES}");
				Console.WriteLine($"           Timing1:  ops {Util.ToSecMilli(AllOpsW.Elapsed)} smooth {Util.ToSecMilli(SmoothW.Elapsed)} project {Util.ToSecMilli(ProjectW.Elapsed)}");
				Console.WriteLine($"           Timing2:  collapse {Util.ToSecMilli(CollapseW.Elapsed)} flip {Util.ToSecMilli(FlipW.Elapsed)} split {Util.ToSecMilli(SplitW.Elapsed)}");
			}
		}

		protected virtual void begin_ops()
		{
			if (ENABLE_PROFILING)
			{
				AllOpsW.Start();
			}
		}

		protected virtual void end_ops()
		{
			if (ENABLE_PROFILING)
			{
				AllOpsW.Stop();
			}
		}

		protected virtual void begin_smooth()
		{
			if (ENABLE_PROFILING)
			{
				SmoothW.Start();
			}
		}

		protected virtual void end_smooth()
		{
			if (ENABLE_PROFILING)
			{
				SmoothW.Stop();
			}
		}

		protected virtual void begin_project()
		{
			if (ENABLE_PROFILING)
			{
				ProjectW.Start();
			}
		}

		protected virtual void end_project()
		{
			if (ENABLE_PROFILING)
			{
				ProjectW.Stop();
			}
		}

		protected virtual void begin_collapse()
		{
			if (ENABLE_PROFILING)
			{
				CollapseW.Start();
			}
		}

		protected virtual void end_collapse()
		{
			if (ENABLE_PROFILING)
			{
				CollapseW.Stop();
			}
		}

		protected virtual void begin_flip()
		{
			if (ENABLE_PROFILING)
			{
				FlipW.Start();
			}
		}

		protected virtual void end_flip()
		{
			if (ENABLE_PROFILING)
			{
				FlipW.Stop();
			}
		}

		protected virtual void begin_split()
		{
			if (ENABLE_PROFILING)
			{
				SplitW.Start();
			}
		}

		protected virtual void end_split()
		{
			if (ENABLE_PROFILING)
			{
				SplitW.Stop();
			}
		}
	}
	public class SimpleMesh : IDeformableMesh, IMesh, IPointSet
	{
		public DVector<double> Vertices;

		public DVector<float> Normals;

		public DVector<float> Colors;

		public DVector<float> UVs;

		public DVector<int> Triangles;

		public DVector<int> FaceGroups;

		private int timestamp;

		public MeshComponents Components
		{
			get
			{
				MeshComponents meshComponents = MeshComponents.None;
				if (Normals != null)
				{
					meshComponents |= MeshComponents.VertexNormals;
				}
				if (Colors != null)
				{
					meshComponents |= MeshComponents.VertexColors;
				}
				if (UVs != null)
				{
					meshComponents |= MeshComponents.VertexUVs;
				}
				if (FaceGroups != null)
				{
					meshComponents |= MeshComponents.FaceGroups;
				}
				return meshComponents;
			}
		}

		public int Timestamp => timestamp;

		public int VertexCount => Vertices.Length / 3;

		public int TriangleCount => Triangles.Length / 3;

		public int MaxVertexID => VertexCount;

		public int MaxTriangleID => TriangleCount;

		public bool HasVertexColors
		{
			get
			{
				if (Colors != null)
				{
					return Colors.Length == Vertices.Length;
				}
				return false;
			}
		}

		public bool HasVertexNormals
		{
			get
			{
				if (Normals != null)
				{
					return Normals.Length == Vertices.Length;
				}
				return false;
			}
		}

		public bool HasVertexUVs
		{
			get
			{
				if (UVs != null)
				{
					return UVs.Length / 2 == Vertices.Length / 3;
				}
				return false;
			}
		}

		public bool HasTriangleGroups
		{
			get
			{
				if (FaceGroups != null)
				{
					return FaceGroups.Length == Triangles.Length / 3;
				}
				return false;
			}
		}

		public SimpleMesh()
		{
			Initialize();
		}

		public SimpleMesh(IMesh copy)
		{
			Initialize(copy.HasVertexNormals, copy.HasVertexColors, copy.HasVertexUVs, copy.HasTriangleGroups);
			int[] array = new int[copy.MaxVertexID];
			foreach (int item in copy.VertexIndices())
			{
				NewVertexInfo vertexAll = copy.GetVertexAll(item);
				int num = AppendVertex(vertexAll);
				array[item] = num;
			}
			foreach (int item2 in copy.TriangleIndices())
			{
				Index3i triangle = copy.GetTriangle(item2);
				triangle[0] = array[triangle[0]];
				triangle[1] = array[triangle[1]];
				triangle[2] = array[triangle[2]];
				if (copy.HasTriangleGroups)
				{
					AppendTriangle(triangle[0], triangle[1], triangle[2], copy.GetTriangleGroup(item2));
				}
				else
				{
					AppendTriangle(triangle[0], triangle[1], triangle[2]);
				}
			}
		}

		public void Initialize(bool bWantNormals = true, bool bWantColors = true, bool bWantUVs = true, bool bWantFaceGroups = true)
		{
			Vertices = new DVector<double>();
			Normals = (bWantNormals ? new DVector<float>() : null);
			Colors = (bWantColors ? new DVector<float>() : null);
			UVs = (bWantUVs ? new DVector<float>() : null);
			Triangles = new DVector<int>();
			FaceGroups = (bWantFaceGroups ? new DVector<int>() : null);
		}

		public void Initialize(VectorArray3d v, VectorArray3i t, VectorArray3f n = null, VectorArray3f c = null, VectorArray2f uv = null, int[] g = null)
		{
			Vertices = new DVector<double>(v);
			Triangles = new DVector<int>(t);
			Normals = (Colors = (UVs = null));
			FaceGroups = null;
			if (n != null)
			{
				Normals = new DVector<float>(n);
			}
			if (c != null)
			{
				Colors = new DVector<float>(c);
			}
			if (uv != null)
			{
				UVs = new DVector<float>(uv);
			}
			if (g != null)
			{
				FaceGroups = new DVector<int>(g);
			}
		}

		private void updateTimeStamp()
		{
			timestamp++;
		}

		public int AppendVertex(double x, double y, double z)
		{
			int result = Vertices.Length / 3;
			if (HasVertexNormals)
			{
				Normals.Add(0f);
				Normals.Add(1f);
				Normals.Add(0f);
			}
			if (HasVertexColors)
			{
				Colors.Add(1f);
				Colors.Add(1f);
				Colors.Add(1f);
			}
			if (HasVertexUVs)
			{
				UVs.Add(0f);
				UVs.Add(0f);
			}
			Vertices.Add(x);
			Vertices.Add(y);
			Vertices.Add(z);
			updateTimeStamp();
			return result;
		}

		public int AppendVertex(NewVertexInfo info)
		{
			int result = Vertices.Length / 3;
			if (info.bHaveN && HasVertexNormals)
			{
				Normals.Add(info.n[0]);
				Normals.Add(info.n[1]);
				Normals.Add(info.n[2]);
			}
			else if (HasVertexNormals)
			{
				Normals.Add(0f);
				Normals.Add(1f);
				Normals.Add(0f);
			}
			if (info.bHaveC && HasVertexColors)
			{
				Colors.Add(info.c[0]);
				Colors.Add(info.c[1]);
				Colors.Add(info.c[2]);
			}
			else if (HasVertexColors)
			{
				Colors.Add(1f);
				Colors.Add(1f);
				Colors.Add(1f);
			}
			if (info.bHaveUV && HasVertexUVs)
			{
				UVs.Add(info.uv[0]);
				UVs.Add(info.uv[1]);
			}
			else if (HasVertexUVs)
			{
				UVs.Add(0f);
				UVs.Add(0f);
			}
			Vertices.Add(info.v[0]);
			Vertices.Add(info.v[1]);
			Vertices.Add(info.v[2]);
			updateTimeStamp();
			return result;
		}

		public void AppendVertices(VectorArray3d v, VectorArray3f n = null, VectorArray3f c = null, VectorArray2f uv = null)
		{
			bool hasVertexNormals = HasVertexNormals;
			bool hasVertexColors = HasVertexColors;
			bool hasVertexUVs = HasVertexUVs;
			Vertices.Add(v.array);
			if (n != null && hasVertexNormals)
			{
				Normals.Add(n.array);
			}
			else if (hasVertexNormals)
			{
				Normals.Add(new float[3] { 0f, 1f, 0f }, v.Count);
			}
			if (c != null && hasVertexColors)
			{
				Colors.Add(c.array);
			}
			else if (hasVertexColors)
			{
				Colors.Add(new float[3] { 1f, 1f, 1f }, v.Count);
			}
			if (uv != null && hasVertexUVs)
			{
				UVs.Add(uv.array);
			}
			else if (hasVertexUVs)
			{
				UVs.Add(new float[2], v.Count);
			}
			updateTimeStamp();
		}

		public int AppendTriangle(int i, int j, int k, int g = -1)
		{
			int result = Triangles.Length / 3;
			if (HasTriangleGroups)
			{
				FaceGroups.Add((g != -1) ? g : 0);
			}
			Triangles.Add(i);
			Triangles.Add(j);
			Triangles.Add(k);
			updateTimeStamp();
			return result;
		}

		public void AppendTriangles(int[] vTriangles, int[] vertexMap, int g = -1)
		{
			for (int i = 0; i < vTriangles.Length; i++)
			{
				Triangles.Add(vertexMap[vTriangles[i]]);
			}
			if (HasTriangleGroups)
			{
				for (int j = 0; j < vTriangles.Length / 3; j++)
				{
					FaceGroups.Add((g != -1) ? g : 0);
				}
			}
			updateTimeStamp();
		}

		public void AppendTriangles(IndexArray3i t, int[] groups = null)
		{
			Triangles.Add(t.array);
			if (HasTriangleGroups)
			{
				if (groups != null)
				{
					FaceGroups.Add(groups);
				}
				else
				{
					FaceGroups.Add(0, t.Count);
				}
			}
			updateTimeStamp();
		}

		public void Translate(double tx, double ty, double tz)
		{
			int vertexCount = VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				Vertices[3 * i] += tx;
				Vertices[3 * i + 1] += ty;
				Vertices[3 * i + 2] += tz;
			}
			updateTimeStamp();
		}

		public void Scale(double sx, double sy, double sz)
		{
			int vertexCount = VertexCount;
			for (int i = 0; i < vertexCount; i++)
			{
				Vertices[3 * i] *= sx;
				Vertices[3 * i + 1] *= sy;
				Vertices[3 * i + 2] *= sz;
			}
			updateTimeStamp();
		}

		public void Scale(double s)
		{
			Scale(s, s, s);
			updateTimeStamp();
		}

		public bool IsVertex(int vID)
		{
			return vID * 3 < Vertices.Length;
		}

		public bool IsTriangle(int tID)
		{
			return tID * 3 < Triangles.Length;
		}

		public Vector3d GetVertex(int i)
		{
			return new Vector3d(Vertices[3 * i], Vertices[3 * i + 1], Vertices[3 * i + 2]);
		}

		public Vector3f GetVertexNormal(int i)
		{
			return new Vector3f(Normals[3 * i], Normals[3 * i + 1], Normals[3 * i + 2]);
		}

		public Vector3f GetVertexColor(int i)
		{
			return new Vector3f(Colors[3 * i], Colors[3 * i + 1], Colors[3 * i + 2]);
		}

		public Vector2f GetVertexUV(int i)
		{
			return new Vector2f(UVs[2 * i], UVs[2 * i + 1]);
		}

		public NewVertexInfo GetVertexAll(int i)
		{
			NewVertexInfo result = new NewVertexInfo
			{
				v = GetVertex(i)
			};
			if (HasVertexNormals)
			{
				result.bHaveN = true;
				result.n = GetVertexNormal(i);
			}
			else
			{
				result.bHaveN = false;
			}
			if (HasVertexColors)
			{
				result.bHaveC = true;
				result.c = GetVertexColor(i);
			}
			else
			{
				result.bHaveC = false;
			}
			if (HasVertexUVs)
			{
				result.bHaveUV = true;
				result.uv = GetVertexUV(i);
			}
			else
			{
				result.bHaveUV = false;
			}
			return result;
		}

		public Index3i GetTriangle(int i)
		{
			return new Index3i(Triangles[3 * i], Triangles[3 * i + 1], Triangles[3 * i + 2]);
		}

		public int GetTriangleGroup(int i)
		{
			return FaceGroups[i];
		}

		public IEnumerable<Vector3d> VerticesItr()
		{
			int N = VertexCount;
			int i = 0;
			while (i < N)
			{
				yield return new Vector3d(Vertices[3 * i], Vertices[3 * i + 1], Vertices[3 * i + 2]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<Vector3f> NormalsItr()
		{
			int N = VertexCount;
			int i = 0;
			while (i < N)
			{
				yield return new Vector3f(Normals[3 * i], Normals[3 * i + 1], Normals[3 * i + 2]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<Vector3f> ColorsItr()
		{
			int N = VertexCount;
			int i = 0;
			while (i < N)
			{
				yield return new Vector3f(Colors[3 * i], Colors[3 * i + 1], Colors[3 * i + 2]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<Vector2f> UVsItr()
		{
			int N = VertexCount;
			int i = 0;
			while (i < N)
			{
				yield return new Vector2f(UVs[2 * i], UVs[2 * i + 1]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<Index3i> TrianglesItr()
		{
			int N = TriangleCount;
			int i = 0;
			while (i < N)
			{
				yield return new Index3i(Triangles[3 * i], Triangles[3 * i + 1], Triangles[3 * i + 2]);
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<int> TriangleGroupsItr()
		{
			int N = TriangleCount;
			int i = 0;
			while (i < N)
			{
				yield return FaceGroups[i];
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<int> VertexIndices()
		{
			int N = VertexCount;
			int i = 0;
			while (i < N)
			{
				yield return i;
				int num = i + 1;
				i = num;
			}
		}

		public IEnumerable<int> TriangleIndices()
		{
			int N = TriangleCount;
			int i = 0;
			while (i < N)
			{
				yield return i;
				int num = i + 1;
				i = num;
			}
		}

		public void SetVertex(int i, Vector3d v)
		{
			Vertices[3 * i] = v.x;
			Vertices[3 * i + 1] = v.y;
			Vertices[3 * i + 2] = v.z;
			updateTimeStamp();
		}

		public void SetVertexNormal(int i, Vector3f n)
		{
			Normals[3 * i] = n.x;
			Normals[3 * i + 1] = n.y;
			Normals[3 * i + 2] = n.z;
			updateTimeStamp();
		}

		public void SetVertexColor(int i, Vector3f c)
		{
			Colors[3 * i] = c.x;
			Colors[3 * i + 1] = c.y;
			Colors[3 * i + 2] = c.z;
			updateTimeStamp();
		}

		public void SetVertexUV(int i, Vector2f uv)
		{
			UVs[2 * i] = uv.x;
			UVs[2 * i + 1] = uv.y;
			updateTimeStamp();
		}

		public double[] GetVertexArray()
		{
			return Vertices.GetBuffer();
		}

		public float[] GetVertexArrayFloat()
		{
			float[] array = new float[Vertices.Length];
			for (int i = 0; i < Vertices.Length; i++)
			{
				array[i] = (float)Vertices[i];
			}
			return array;
		}

		public float[] GetVertexNormalArray()
		{
			if (!HasVertexNormals)
			{
				return null;
			}
			return Normals.GetBuffer();
		}

		public float[] GetVertexColorArray()
		{
			if (!HasVertexColors)
			{
				return null;
			}
			return Colors.GetBuffer();
		}

		public float[] GetVertexUVArray()
		{
			if (!HasVertexUVs)
			{
				return null;
			}
			return UVs.GetBuffer();
		}

		public int[] GetTriangleArray()
		{
			return Triangles.GetBuffer();
		}

		public int[] GetFaceGroupsArray()
		{
			if (!HasTriangleGroups)
			{
				return null;
			}
			return FaceGroups.GetBuffer();
		}

		public unsafe void GetVertexBuffer(double* pBuffer)
		{
			DVector<double>.FastGetBuffer(Vertices, pBuffer);
		}

		public unsafe void GetVertexNormalBuffer(float* pBuffer)
		{
			if (HasVertexNormals)
			{
				DVector<float>.FastGetBuffer(Normals, pBuffer);
			}
		}

		public unsafe void GetVertexColorBuffer(float* pBuffer)
		{
			if (HasVertexColors)
			{
				DVector<float>.FastGetBuffer(Colors, pBuffer);
			}
		}

		public unsafe void GetVertexUVBuffer(float* pBuffer)
		{
			if (HasVertexUVs)
			{
				DVector<float>.FastGetBuffer(UVs, pBuffer);
			}
		}

		public unsafe void GetTriangleBuffer(int* pBuffer)
		{
			DVector<int>.FastGetBuffer(Triangles, pBuffer);
		}

		public unsafe void GetFaceGroupsBuffer(int* pBuffer)
		{
			if (HasTriangleGroups)
			{
				DVector<int>.FastGetBuffer(FaceGroups, pBuffer);
			}
		}
	}
	public class SimpleMeshBuilder : IMeshBuilder
	{
		public List<SimpleMesh> Meshes;

		public List<GenericMaterial> Materials;

		public List<int> MaterialAssignment;

		private int nActiveMesh;

		public bool SupportsMetaData => false;

		public SimpleMeshBuilder()
		{
			Meshes = new List<SimpleMesh>();
			Materials = new List<GenericMaterial>();
			MaterialAssignment = new List<int>();
			nActiveMesh = -1;
		}

		public int AppendNewMesh(bool bHaveVtxNormals, bool bHaveVtxColors, bool bHaveVtxUVs, bool bHaveFaceGroups)
		{
			int count = Meshes.Count;
			SimpleMesh simpleMesh = new SimpleMesh();
			simpleMesh.Initialize(bHaveVtxNormals, bHaveVtxColors, bHaveVtxUVs, bHaveFaceGroups);
			Meshes.Add(simpleMesh);
			MaterialAssignment.Add(-1);
			nActiveMesh = count;
			return count;
		}

		public int AppendNewMesh(DMesh3 existingMesh)
		{
			int count = Meshes.Count;
			SimpleMesh item = new SimpleMesh(existingMesh);
			Meshes.Add(item);
			MaterialAssignment.Add(-1);
			nActiveMesh = count;
			return count;
		}

		public void SetActiveMesh(int id)
		{
			if (id >= 0 && id < Meshes.Count)
			{
				nActiveMesh = id;
				return;
			}
			throw new ArgumentOutOfRangeException("active mesh id is out of range");
		}

		public int AppendTriangle(int i, int j, int k)
		{
			return Meshes[nActiveMesh].AppendTriangle(i, j, k);
		}

		public int AppendTriangle(int i, int j, int k, int g)
		{
			return Meshes[nActiveMesh].AppendTriangle(i, j, k, g);
		}

		public int AppendVertex(double x, double y, double z)
		{
			return Meshes[nActiveMesh].AppendVertex(x, y, z);
		}

		public int AppendVertex(NewVertexInfo info)
		{
			return Meshes[nActiveMesh].AppendVertex(info);
		}

		public void AppendMetaData(string identifier, object data)
		{
			throw new NotImplementedException("SimpleMeshBuilder: metadata not supported");
		}

		public int BuildMaterial(GenericMaterial m)
		{
			int count = Materials.Count;
			Materials.Add(m);
			return count;
		}

		public void AssignMaterial(int materialID, int meshID)
		{
			if (meshID >= MaterialAssignment.Count || materialID >= Materials.Count)
			{
				throw new ArgumentOutOfRangeException("[SimpleMeshBuilder::AssignMaterial] meshID or materialID are out-of-range");
			}
			MaterialAssignment[meshID] = materialID;
		}

		public void SetVertexUV(int vID, Vector2f UV)
		{
			Meshes[nActiveMesh].SetVertexUV(vID, UV);
		}
	}
	public class SimpleQuadMesh
	{
		public DVector<double> Vertices;

		public DVector<float> Normals;

		public DVector<float> Colors;

		public DVector<float> UVs;

		public DVector<int> Quads;

		public DVector<int> FaceGroups;

		public MeshComponents Components
		{
			get
			{
				MeshComponents meshComponents = MeshComponents.None;
				if (Normals != null)
				{
					meshComponents |= MeshComponents.VertexNormals;
				}
				if (Colors != null)
				{
					meshComponents |= MeshComponents.VertexColors;
				}
				if (UVs != null)
				{
					meshComponents |= MeshComponents.VertexUVs;
				}
				if (FaceGroups != null)
				{
					meshComponents |= MeshComponents.FaceGroups;
				}
				return meshComponents;
			}
		}

		public int VertexCount => Vertices.Length / 3;

		public int QuadCount => Quads.Length / 4;

		public int MaxVertexID => VertexCount;

		public int MaxQuadID => QuadCount;

		public bool HasVertexColors
		{
			get
			{
				if (Colors != null)
				{
					return Colors.Length == Vertices.Length;
				}
				return false;
			}
		}

		public bool HasVertexNormals
		{
			get
			{
				if (Normals != null)
				{
					return Normals.Length == Vertices.Length;
				}
				return false;
			}
		}

		public bool HasVertexUVs
		{
			get
			{
				if (UVs != null)
				{
					return UVs.Length / 2 == Vertices.Length / 3;
				}
				return false;
			}
		}

		public bool HasFaceGroups
		{
			get
			{
				if (FaceGroups != null)
				{
					return FaceGroups.Length == Quads.Length / 4;
				}
				return false;
			}
		}

		public SimpleQuadMesh()
		{
			Initialize();
		}

		public void Initialize(bool bWantNormals = true, bool bWantColors = true, bool bWantUVs = true, bool bWantFaceGroups = true)
		{
			Vertices = new DVector<double>();
			Normals = (bWantNormals ? new DVector<float>() : null);
			Colors = (bWantColors ? new DVector<float>() : null);
			UVs = (bWantUVs ? new DVector<float>() : null);
			Quads = new DVector<int>();
			FaceGroups = (bWantFaceGroups ? new DVector<int>() : null);
		}

		public int AppendVertex(double x, double y, double z)
		{
			int result = Vertices.Length / 3;
			if (HasVertexNormals)
			{
				Normals.Add(0f);
				Normals.Add(1f);
				Normals.Add(0f);
			}
			if (HasVertexColors)
			{
				Colors.Add(1f);
				Colors.Add(1f);
				Colors.Add(1f);
			}
			if (HasVertexUVs)
			{
				UVs.Add(0f);
				UVs.Add(0f);
			}
			Vertices.Add(x);
			Vertices.Add(y);
			Vertices.Add(z);
			return result;
		}

		public int AppendVertex(Vector3d v)
		{
			return AppendVertex(v.x, v.y, v.z);
		}

		public int AppendVertex(NewVertexInfo info)
		{
			int result = Vertices.Length / 3;
			if (info.bHaveN && HasVertexNormals)
			{
				Normals.Add(info.n[0]);
				Normals.Add(info.n[1]);
				Normals.Add(info.n[2]);
			}
			else if (HasVertexNormals)
			{
				Normals.Add(0f);
				Normals.Add(1f);
				Normals.Add(0f);
			}
			if (info.bHaveC && HasVertexColors)
			{
				Colors.Add(info.c[0]);
				Colors.Add(info.c[1]);
				Colors.Add(info.c[2]);
			}
			else if (HasVertexColors)
			{
				Colors.Add(1f);
				Colors.Add(1f);
				Colors.Add(1f);
			}
			if (info.bHaveUV && HasVertexUVs)
			{
				UVs.Add(info.uv[0]);
				UVs.Add(info.uv[1]);
			}
			else if (HasVertexUVs)
			{
				UVs.Add(0f);
				UVs.Add(0f);
			}
			Vertices.Add(info.v[0]);
			Vertices.Add(info.v[1]);
			Vertices.Add(info.v[2]);
			return result;
		}

		public int AppendQuad(int i, int j, int k, int l, int g = -1)
		{
			int result = Quads.Length / 4;
			if (HasFaceGroups)
			{
				FaceGroups.Add((g != -1) ? g : 0);
			}
			Quads.Add(i);
			Quads.Add(j);
			Quads.Add(k);
			Quads.Add(l);
			return result;
		}

		public bool IsVertex(int vID)
		{
			return vID * 3 < Vertices.Length;
		}

		public bool IsQuad(int qID)
		{
			return qID * 4 < Quads.Length;
		}

		public Vector3d GetVertex(int i)
		{
			return new Vector3d(Vertices[3 * i], Vertices[3 * i + 1], Vertices[3 * i + 2]);
		}

		public Vector3f GetVertexNormal(int i)
		{
			return new Vector3f(Normals[3 * i], Normals[3 * i + 1], Normals[3 * i + 2]);
		}

