		public static IOWriteResult WriteOBJ(SimpleQuadMesh mesh, string sPath, WriteOptions options)
		{
			StreamWriter streamWriter = new StreamWriter(sPath);
			if (streamWriter.BaseStream == null)
			{
				return new IOWriteResult(IOCode.FileAccessError, "Could not open file " + sPath + " for writing");
			}
			bool flag = options.bPerVertexColors && mesh.HasVertexColors;
			bool flag2 = options.bPerVertexNormals && mesh.HasVertexNormals;
			bool flag3 = options.bPerVertexUVs && mesh.HasVertexUVs;
			if (mesh.UVs != null)
			{
				flag3 = false;
			}
			int[] array = new int[mesh.MaxVertexID];
			int num = 1;
			foreach (int item in mesh.VertexIndices())
			{
				array[item] = num++;
				Vector3d vertex = mesh.GetVertex(item);
				if (flag)
				{
					Vector3d vector3d = mesh.GetVertexColor(item);
					streamWriter.WriteLine("v {0} {1} {2} {3:F8} {4:F8} {5:F8}", vertex[0], vertex[1], vertex[2], vector3d[0], vector3d[1], vector3d[2]);
				}
				else
				{
					streamWriter.WriteLine("v {0} {1} {2}", vertex[0], vertex[1], vertex[2]);
				}
				if (flag2)
				{
					Vector3d vector3d2 = mesh.GetVertexNormal(item);
					streamWriter.WriteLine("vn {0:F10} {1:F10} {2:F10}", vector3d2[0], vector3d2[1], vector3d2[2]);
				}
				if (flag3)
				{
					Vector2f vertexUV = mesh.GetVertexUV(item);
					streamWriter.WriteLine("vt {0:F10} {1:F10}", vertexUV.x, vertexUV.y);
				}
			}
			foreach (int item2 in mesh.QuadIndices())
			{
				Index4i q = mesh.GetQuad(item2);
				q[0] = array[q[0]];
				q[1] = array[q[1]];
				q[2] = array[q[2]];
				q[3] = array[q[3]];
				write_quad(streamWriter, ref q, flag2, flag3, ref q);
			}
			streamWriter.Close();
			return IOWriteResult.Ok;
		}

		private static void write_quad(TextWriter writer, ref Index4i q, bool bNormals, bool bUVs, ref Index4i tuv)
		{
			if (!bNormals && !bUVs)
			{
				writer.WriteLine("f {0} {1} {2} {3}", q[0], q[1], q[2], q[3]);
			}
			else if (bNormals && !bUVs)
			{
				writer.WriteLine("f {0}//{0} {1}//{1} {2}//{2} {3}//{3}", q[0], q[1], q[2], q[3]);
			}
			else if (!bNormals && bUVs)
			{
				writer.WriteLine("f {0}/{4} {1}/{5} {2}/{6} {3}/{7}", q[0], q[1], q[2], q[3], tuv[0], tuv[1], tuv[2], tuv[3]);
			}
			else
			{
				writer.WriteLine("f {0}/{4}/{0} {1}/{5}/{1} {2}/{6}/{2} {3}/{7}/{3}", q[0], q[1], q[2], q[3], tuv[0], tuv[1], tuv[2], tuv[3]);
			}
		}
	}
	public class Radial3DArrowGenerator : VerticalGeneralizedCylinderGenerator
	{
		public float StickRadius = 0.5f;

		public float StickLength = 1f;

		public float HeadBaseRadius = 1f;

		public float TipRadius;

		public float HeadLength = 0.5f;

		public override MeshGenerator Generate()
		{
			Sections = new CircularSection[4];
			Sections[0] = new CircularSection(StickRadius, 0f);
			Sections[1] = new CircularSection(StickRadius, StickLength);
			Sections[2] = new CircularSection(HeadBaseRadius, StickLength);
			Sections[3] = new CircularSection(TipRadius, StickLength + HeadLength);
			Capped = true;
			NoSharedVertices = true;
			base.Generate();
			return this;
		}
	}
	public class TrivialBox3Generator : MeshGenerator
	{
		public Box3d Box = Box3d.UnitZeroCentered;

		public bool NoSharedVertices;

		public override MeshGenerator Generate()
		{
			vertices = new VectorArray3d(NoSharedVertices ? 24 : 8);
			uv = new VectorArray2f(vertices.Count);
			normals = new VectorArray3f(vertices.Count);
			triangles = new IndexArray3i(12);
			if (!NoSharedVertices)
			{
				for (int i = 0; i < 8; i++)
				{
					vertices[i] = Box.Corner(i);
					normals[i] = (Vector3f)(vertices[i] - Box.Center[i]).Normalized;
					uv[i] = Vector2f.Zero;
				}
				int num = 0;
				for (int j = 0; j < 6; j++)
				{
					triangles.Set(num++, gIndices.BoxFaces[j, 0], gIndices.BoxFaces[j, 1], gIndices.BoxFaces[j, 2], Clockwise);
					triangles.Set(num++, gIndices.BoxFaces[j, 0], gIndices.BoxFaces[j, 2], gIndices.BoxFaces[j, 3], Clockwise);
				}
			}
			else
			{
				int num2 = 0;
				int num3 = 0;
				Vector2f[] array = new Vector2f[4]
				{
					Vector2f.Zero,
					new Vector2f(1f, 0f),
					new Vector2f(1f, 1f),
					new Vector2f(0f, 1f)
				};
				for (int k = 0; k < 6; k++)
				{
					int num4 = num3++;
					num3 += 3;
					int value = gIndices.BoxFaceNormals[k];
					Vector3f value2 = (Vector3f)(Math.Sign(value) * Box.Axis(Math.Abs(value) - 1));
					for (int l = 0; l < 4; l++)
					{
						vertices[num4 + l] = Box.Corner(gIndices.BoxFaces[k, l]);
						normals[num4 + l] = value2;
						uv[num4 + l] = array[l];
					}
					triangles.Set(num2++, num4, num4 + 1, num4 + 2, Clockwise);
					triangles.Set(num2++, num4, num4 + 2, num4 + 3, Clockwise);
				}
			}
			return this;
		}
	}
	public class GridBox3Generator : MeshGenerator
	{
		public Box3d Box = Box3d.UnitZeroCentered;

		public int EdgeVertices = 8;

		public bool NoSharedVertices;

		public override MeshGenerator Generate()
		{
			int N = ((EdgeVertices > 1) ? EdgeVertices : 2);
			int num = N - 2;
			int num2 = N - 1;
			int num3 = N * N;
			vertices = new VectorArray3d(NoSharedVertices ? (num3 * 6) : (8 + num * 12 + num * num * 6));
			uv = new VectorArray2f(vertices.Count);
			normals = new VectorArray3f(vertices.Count);
			triangles = new IndexArray3i(2 * num2 * num2 * 6);
			groups = new int[triangles.Count];
			Vector3d[] array = Box.ComputeVertices();
			int vi = 0;
			int num4 = 0;
			if (NoSharedVertices)
			{
				for (int i = 0; i < 6; i++)
				{
					Vector3d v = array[gIndices.BoxFaces[i, 0]];
					Vector3d v2 = array[gIndices.BoxFaces[i, 1]];
					Vector3d v3 = array[gIndices.BoxFaces[i, 2]];
					Vector3d v4 = array[gIndices.BoxFaces[i, 3]];
					Vector3f value = Math.Sign(gIndices.BoxFaceNormals[i]) * (Vector3f)Box.Axis(Math.Abs(gIndices.BoxFaceNormals[i]) - 1);
					int num5 = vi;
					for (int j = 0; j < N; j++)
					{
						double num6 = (double)j / (double)(N - 1);
						for (int k = 0; k < N; k++)
						{
							double num7 = (double)k / (double)(N - 1);
							normals[vi] = value;
							uv[vi] = new Vector2f(num7, num6);
							vertices[vi++] = bilerp(ref v, ref v2, ref v3, ref v4, num7, num6);
						}
					}
					for (int l = 0; l < num2; l++)
					{
						for (int m = 0; m < num2; m++)
						{
							int num8 = num5 + l * N + m;
							int num9 = num5 + (l + 1) * N + m;
							int b = num8 + 1;
							int num10 = num9 + 1;
							groups[num4] = i;
							triangles.Set(num4++, num8, b, num10, Clockwise);
							groups[num4] = i;
							triangles.Set(num4++, num8, num10, num9, Clockwise);
						}
					}
				}
			}
			else
			{
				Vector3i[] array2 = new Vector3i[array.Length];
				for (int n = 0; n < array.Length; n++)
				{
					Vector3d vector3d = array[n] - Box.Center;
					array2[n] = new Vector3i((!(vector3d.x < 0.0)) ? (N - 1) : 0, (!(vector3d.y < 0.0)) ? (N - 1) : 0, (!(vector3d.z < 0.0)) ? (N - 1) : 0);
				}
				int[] array3 = new int[num3];
				Dictionary<Vector3i, int> edgeVerts = new Dictionary<Vector3i, int>();
				for (int num11 = 0; num11 < 6; num11++)
				{
					int num12 = gIndices.BoxFaces[num11, 0];
					int num13 = gIndices.BoxFaces[num11, 1];
					int num14 = gIndices.BoxFaces[num11, 2];
					int num15 = gIndices.BoxFaces[num11, 3];
					Vector3d vector3d2 = array[num12];
					Vector3i vector3i = array2[num12];
					Vector3d vector3d3 = array[num13];
					Vector3i vector3i2 = array2[num13];
					Vector3d vector3d4 = array[num14];
					Vector3i vector3i3 = array2[num14];
					Vector3d vector3d5 = array[num15];
					Vector3i vector3i4 = array2[num15];
					Action<Vector3d, Vector3d, Vector3i, Vector3i> action = delegate(Vector3d a2, Vector3d b3, Vector3i ai, Vector3i bi)
					{
						for (int num30 = 0; num30 < N; num30++)
						{
							double t = (double)num30 / (double)(N - 1);
							Vector3i key2 = lerp(ref ai, ref bi, t);
							if (!edgeVerts.ContainsKey(key2))
							{
								Vector3d value5 = Vector3d.Lerp(ref a2, ref b3, t);
								normals[vi] = (Vector3f)value5.Normalized;
								uv[vi] = Vector2f.Zero;
								edgeVerts[key2] = vi;
								vertices[vi++] = value5;
							}
						}
					};
					action(vector3d2, vector3d3, vector3i, vector3i2);
					action(vector3d3, vector3d4, vector3i2, vector3i3);
					action(vector3d4, vector3d5, vector3i3, vector3i4);
					action(vector3d5, vector3d2, vector3i4, vector3i);
				}
				for (int num16 = 0; num16 < 6; num16++)
				{
					int num17 = gIndices.BoxFaces[num16, 0];
					int num18 = gIndices.BoxFaces[num16, 1];
					int num19 = gIndices.BoxFaces[num16, 2];
					int num20 = gIndices.BoxFaces[num16, 3];
					Vector3d v5 = array[num17];
					Vector3i v6 = array2[num17];
					Vector3d v7 = array[num18];
					Vector3i v8 = array2[num18];
					Vector3d v9 = array[num19];
					Vector3i v10 = array2[num19];
					Vector3d v11 = array[num20];
					Vector3i v12 = array2[num20];
					Vector3f value2 = Math.Sign(gIndices.BoxFaceNormals[num16]) * (Vector3f)Box.Axis(Math.Abs(gIndices.BoxFaceNormals[num16]) - 1);
					for (int num21 = 0; num21 < N; num21++)
					{
						double num22 = (double)num21 / (double)(N - 1);
						for (int num23 = 0; num23 < N; num23++)
						{
							double num24 = (double)num23 / (double)(N - 1);
							Vector3i key = bilerp(ref v6, ref v8, ref v10, ref v12, num24, num22);
							if (!edgeVerts.TryGetValue(key, out var value3))
							{
								Vector3d value4 = bilerp(ref v5, ref v7, ref v9, ref v11, num24, num22);
								value3 = vi++;
								normals[value3] = value2;
								uv[value3] = new Vector2f(num24, num22);
								vertices[value3] = value4;
							}
							array3[num21 * N + num23] = value3;
						}
					}
					for (int num25 = 0; num25 < num2; num25++)
					{
						int num26 = num25 + 1;
						for (int num27 = 0; num27 < num2; num27++)
						{
							int num28 = num27 + 1;
							int a = array3[num25 * N + num27];
							int b2 = array3[num25 * N + num28];
							int num29 = array3[num26 * N + num28];
							int c = array3[num26 * N + num27];
							groups[num4] = num16;
							triangles.Set(num4++, a, b2, num29, Clockwise);
							groups[num4] = num16;
							triangles.Set(num4++, a, num29, c, Clockwise);
						}
					}
				}
			}
			return this;
		}
	}
	public class OpenCylinderGenerator : MeshGenerator
	{
		public float BaseRadius = 1f;

		public float TopRadius = 1f;

		public float Height = 1f;

		public float StartAngleDeg;

		public float EndAngleDeg = 360f;

		public int Slices = 16;

		public bool NoSharedVertices;

		public override MeshGenerator Generate()
		{
			bool flag = EndAngleDeg - StartAngleDeg > 359.99f;
			int num = ((NoSharedVertices && flag) ? (Slices + 1) : Slices);
			vertices = new VectorArray3d(2 * num);
			uv = new VectorArray2f(vertices.Count);
			normals = new VectorArray3f(vertices.Count);
			triangles = new IndexArray3i(2 * Slices);
			float num2 = (EndAngleDeg - StartAngleDeg) * (MathF.PI / 180f);
			float num3 = StartAngleDeg * (MathF.PI / 180f);
			float num4 = (flag ? (num2 / (float)Slices) : (num2 / (float)(Slices - 1)));
			for (int i = 0; i < num; i++)
			{
				float num5 = num3 + (float)i * num4;
				double num6 = Math.Cos(num5);
				double num7 = Math.Sin(num5);
				vertices[i] = new Vector3d((double)BaseRadius * num6, 0.0, (double)BaseRadius * num7);
				vertices[num + i] = new Vector3d((double)TopRadius * num6, Height, (double)TopRadius * num7);
				float x = (float)i / (float)Slices;
				uv[i] = new Vector2f(x, 0f);
				uv[num + i] = new Vector2f(x, 1f);
				Vector3f vector3f = new Vector3f((float)num6, 0f, (float)num7);
				vector3f.Normalize();
				VectorArray3f vectorArray3f = normals;
				int i2 = i;
				Vector3f value = (normals[num + i] = vector3f);
				vectorArray3f[i2] = value;
			}
			int num8 = 0;
			for (int j = 0; j < num - 1; j++)
			{
				triangles.Set(num8++, j, j + 1, num + j + 1, Clockwise);
				triangles.Set(num8++, j, num + j + 1, num + j, Clockwise);
			}
			if (flag && !NoSharedVertices)
			{
				triangles.Set(num8++, num - 1, 0, num, Clockwise);
				triangles.Set(num8++, num - 1, num, 2 * num - 1, Clockwise);
			}
			return this;
		}
	}
	public class CappedCylinderGenerator : MeshGenerator
	{
		public float BaseRadius = 1f;

		public float TopRadius = 1f;

		public float Height = 1f;

		public float StartAngleDeg;

		public float EndAngleDeg = 360f;

		public int Slices = 16;

		public bool NoSharedVertices;

		public override MeshGenerator Generate()
		{
			bool flag = EndAngleDeg - StartAngleDeg > 359.99f;
			int num = ((NoSharedVertices && flag) ? (Slices + 1) : Slices);
			int num2 = ((!NoSharedVertices) ? 1 : (Slices + 1));
			int num3 = ((NoSharedVertices && !flag) ? 8 : 0);
			vertices = new VectorArray3d(2 * num + 2 * num2 + num3);
			uv = new VectorArray2f(vertices.Count);
			normals = new VectorArray3f(vertices.Count);
			int num4 = 2 * Slices;
			int num5 = 2 * Slices;
			int num6 = ((!flag) ? 4 : 0);
			triangles = new IndexArray3i(num4 + num5 + num6);
			groups = new int[triangles.Count];
			float num7 = (EndAngleDeg - StartAngleDeg) * (MathF.PI / 180f);
			float num8 = StartAngleDeg * (MathF.PI / 180f);
			float num9 = (flag ? (num7 / (float)Slices) : (num7 / (float)(Slices - 1)));
			for (int i = 0; i < num; i++)
			{
				float num10 = num8 + (float)i * num9;
				double num11 = Math.Cos(num10);
				double num12 = Math.Sin(num10);
				vertices[i] = new Vector3d((double)BaseRadius * num11, 0.0, (double)BaseRadius * num12);
				vertices[num + i] = new Vector3d((double)TopRadius * num11, Height, (double)TopRadius * num12);
				float x = (float)i / (float)Slices;
