		public MarchingCubes()
		{
			Implicit = new ImplicitSphere3d();
			Bounds = new AxisAlignedBox3d(Vector3d.Zero, 8.0);
			CubeSize = 0.25;
		}

		public void Generate()
		{
			Mesh = new DMesh3();
			VertexHash = new Dictionary<Vector3d, int>();
			int x = (int)(Bounds.Width / CubeSize) + 1;
			int y = (int)(Bounds.Height / CubeSize) + 1;
			int z = (int)(Bounds.Depth / CubeSize) + 1;
			CellDimensions = new Vector3i(x, y, z);
			if (ParallelCompute)
			{
				generate_parallel();
			}
			else
			{
				generate_basic();
			}
		}

		private void GridToPos(int x, int y, int z, ref Vector3d p)
		{
			p.x = Bounds.Min.x + CubeSize * (double)x;
			p.y = Bounds.Min.y + CubeSize * (double)y;
			p.z = Bounds.Min.z + CubeSize * (double)z;
		}

		private void initialize_cell(GridCell cell, ref Vector3i idx)
		{
			double x = Bounds.Min.x + CubeSize * (double)idx.x;
			double y = Bounds.Min.y + CubeSize * (double)idx.y;
			double z = Bounds.Min.z + CubeSize * (double)idx.z;
			double x2 = Bounds.Min.x + CubeSize * (double)(idx.x + 1);
			double y2 = Bounds.Min.y + CubeSize * (double)(idx.y + 1);
			double z2 = Bounds.Min.z + CubeSize * (double)(idx.z + 1);
			cell.p[0].x = x;
			cell.p[0].y = y;
			cell.p[0].z = z;
			cell.p[1].x = x2;
			cell.p[1].y = y;
			cell.p[1].z = z;
			cell.p[2].x = x2;
			cell.p[2].y = y;
			cell.p[2].z = z2;
			cell.p[3].x = x;
			cell.p[3].y = y;
			cell.p[3].z = z2;
			cell.p[4].x = x;
			cell.p[4].y = y2;
			cell.p[4].z = z;
			cell.p[5].x = x2;
			cell.p[5].y = y2;
			cell.p[5].z = z;
			cell.p[6].x = x2;
			cell.p[6].y = y2;
			cell.p[6].z = z2;
			cell.p[7].x = x;
			cell.p[7].y = y2;
			cell.p[7].z = z2;
			for (int i = 0; i < 8; i++)
			{
				cell.f[i] = Implicit.Value(ref cell.p[i]);
			}
		}

		private void shift_cell_x(GridCell cell, int xi)
		{
			double x = cell.p[1].x;
			double x2 = Bounds.Min.x + CubeSize * (double)(xi + 1);
			cell.p[0].x = x;
			cell.p[1].x = x2;
			cell.p[2].x = x2;
			cell.p[3].x = x;
			cell.p[4].x = x;
			cell.p[5].x = x2;
			cell.p[6].x = x2;
			cell.p[7].x = x;
			cell.f[0] = cell.f[1];
			cell.f[3] = cell.f[2];
			cell.f[4] = cell.f[5];
			cell.f[7] = cell.f[6];
			cell.f[1] = Implicit.Value(ref cell.p[1]);
			cell.f[2] = Implicit.Value(ref cell.p[2]);
			cell.f[5] = Implicit.Value(ref cell.p[5]);
			cell.f[6] = Implicit.Value(ref cell.p[6]);
		}

		private void generate_parallel()
		{
			hash_lock = default(SpinLock);
			mesh_lock = default(SpinLock);
			bParallel = true;
			gParallel.ForEach(Interval1i.Range(CellDimensions.z), delegate(int zi)
			{
				GridCell cell = new GridCell();
				Vector3d[] vertList = new Vector3d[12];
				for (int i = 0; i < CellDimensions.y; i++)
				{
					if (CancelF())
					{
						break;
					}
					Vector3i idx = new Vector3i(0, i, zi);
					initialize_cell(cell, ref idx);
					polygonize_cell(cell, vertList);
					for (int j = 1; j < CellDimensions.x; j++)
					{
						shift_cell_x(cell, j);
						polygonize_cell(cell, vertList);
					}
				}
			});
			bParallel = false;
		}

		private void generate_basic()
		{
			GridCell cell = new GridCell();
			Vector3d[] vertList = new Vector3d[12];
			for (int i = 0; i < CellDimensions.z; i++)
			{
				for (int j = 0; j < CellDimensions.y; j++)
				{
					if (CancelF())
					{
						return;
					}
					Vector3i idx = new Vector3i(0, j, i);
					initialize_cell(cell, ref idx);
					polygonize_cell(cell, vertList);
					for (int k = 1; k < CellDimensions.x; k++)
					{
						shift_cell_x(cell, k);
						polygonize_cell(cell, vertList);
					}
				}
			}
		}

		private bool polygonize_cell(GridCell cell, Vector3d[] vertList)
		{
			int num = 0;
			int num2 = 1;
			for (int i = 0; i < 8; i++)
			{
				if (cell.f[i] < IsoValue)
				{
					num |= num2;
				}
				num2 <<= 1;
			}
			if (edgeTable[num] == 0)
			{
				return false;
			}
			num2 = 1;
			for (int j = 0; j <= 11; j++)
			{
				if ((edgeTable[num] & num2) != 0)
				{
					int num3 = edge_indices[j, 0];
					int num4 = edge_indices[j, 1];
					find_iso(ref cell.p[num3], ref cell.p[num4], cell.f[num3], cell.f[num4], ref vertList[j]);
				}
				num2 <<= 1;
			}
			int num5 = 0;
			for (int k = 0; triTable[num, k] != -1; k += 3)
			{
				int num6 = triTable[num, k];
				int num7 = find_or_append_vertex(ref vertList[num6]);
				int num8 = triTable[num, k + 1];
				int num9 = find_or_append_vertex(ref vertList[num8]);
				int num10 = triTable[num, k + 2];
				int num11 = find_or_append_vertex(ref vertList[num10]);
				if (num7 != num9 && num7 != num11 && num9 != num11)
				{
					append_triangle(num7, num9, num11);
					num5++;
				}
			}
			return num5 > 0;
		}

		private int find_or_append_vertex(ref Vector3d pos)
		{
			bool lockTaken = false;
			if (bParallel)
			{
				hash_lock.Enter(ref lockTaken);
			}
			if (!VertexHash.TryGetValue(pos, out var value))
			{
				value = append_vertex(pos);
				VertexHash[pos] = value;
			}
			if (lockTaken)
			{
				hash_lock.Exit();
			}
			return value;
		}

		private int append_vertex(Vector3d v)
		{
			bool lockTaken = false;
			if (bParallel)
			{
				mesh_lock.Enter(ref lockTaken);
			}
			int result = Mesh.AppendVertex(v);
			if (lockTaken)
			{
				mesh_lock.Exit();
			}
			return result;
		}

		private int append_triangle(int a, int b, int c)
		{
			bool lockTaken = false;
			if (bParallel)
			{
				mesh_lock.Enter(ref lockTaken);
			}
			int result = Mesh.AppendTriangle(a, b, c);
			if (lockTaken)
			{
				mesh_lock.Exit();
			}
			return result;
		}

		private void find_iso(ref Vector3d p1, ref Vector3d p2, double valp1, double valp2, ref Vector3d pIso)
		{
			if (Math.Abs(valp1 - valp2) < 1E-05)
			{
				pIso = (p1 + p2) * 0.5;
				return;
			}
			if (Math.Abs(IsoValue - valp1) < 1E-05)
			{
				pIso = 0.999999 * p1 + 1.0000000000287557E-06 * p2;
				return;
			}
			if (Math.Abs(IsoValue - valp2) < 1E-05)
			{
				pIso = 0.999999 * p2 + 1.0000000000287557E-06 * p1;
				return;
			}
			Vector3d a = p1;
			Vector3d b = p2;
			double num = valp1;
			double num2 = valp2;
			if (valp2 < valp1)
			{
				a = p2;
				b = p1;
				num2 = valp1;
				num = valp2;
			}
			if (RootMode == RootfindingModes.Bisection)
			{
				for (int i = 0; i < RootModeSteps; i++)
				{
					pIso.x = (a.x + b.x) * 0.5;
					pIso.y = (a.y + b.y) * 0.5;
					pIso.z = (a.z + b.z) * 0.5;
					double num3 = Implicit.Value(ref pIso);
					if (num3 < IsoValue)
					{
						a = pIso;
						num = num3;
					}
					else
					{
						b = pIso;
						num2 = num3;
					}
				}
				pIso = Vector3d.Lerp(a, b, 0.5);
				return;
			}
			double num4 = 0.0;
			if (RootMode == RootfindingModes.LerpSteps)
			{
				for (int j = 0; j < RootModeSteps; j++)
				{
					num4 = (IsoValue - num) / (num2 - num);
					pIso.x = a.x + num4 * (b.x - a.x);
					pIso.y = a.y + num4 * (b.y - a.y);
					pIso.z = a.z + num4 * (b.z - a.z);
					double num5 = Implicit.Value(ref pIso);
					if (num5 < IsoValue)
					{
						a = pIso;
						num = num5;
					}
					else
					{
						b = pIso;
						num2 = num5;
					}
				}
			}
			num4 = (IsoValue - num) / (num2 - num);
			pIso.x = a.x + num4 * (b.x - a.x);
			pIso.y = a.y + num4 * (b.y - a.y);
			pIso.z = a.z + num4 * (b.z - a.z);
		}
	}
	public abstract class MeshGenerator
	{
		public struct CircularSection(float r, float y)
		{
			public float Radius = r;

			public float SectionY = y;
		}

		public VectorArray3d vertices;

		public VectorArray2f uv;

		public VectorArray3f normals;

		public IndexArray3i triangles;

		public int[] groups;

		public bool WantUVs = true;

		public bool WantNormals = true;

		public bool WantGroups = true;

		public bool Clockwise;

		public abstract MeshGenerator Generate();

		public virtual void MakeMesh(SimpleMesh m)
		{
			m.AppendVertices(vertices, WantNormals ? normals : null, null, WantUVs ? uv : null);
			m.AppendTriangles(triangles);
		}

		public virtual SimpleMesh MakeSimpleMesh()
		{
			SimpleMesh simpleMesh = new SimpleMesh();
			MakeMesh(simpleMesh);
			return simpleMesh;
		}

		public virtual void MakeMesh(DMesh3 m)
		{
			int count = vertices.Count;
			bool flag = WantNormals && normals != null && normals.Count == vertices.Count;
			if (flag)
			{
				m.EnableVertexNormals(Vector3f.AxisY);
			}
			bool flag2 = WantUVs && uv != null && uv.Count == vertices.Count;
			if (flag2)
			{
				m.EnableVertexUVs(Vector2f.Zero);
			}
			for (int i = 0; i < count; i++)
			{
				NewVertexInfo info = new NewVertexInfo
				{
					v = vertices[i]
				};
				if (flag)
				{
					info.bHaveN = true;
					info.n = normals[i];
				}
				if (flag2)
				{
					info.bHaveUV = true;
					info.uv = uv[i];
				}
				m.AppendVertex(info);
			}
			int count2 = triangles.Count;
			if (WantGroups && groups != null && groups.Length == count2)
			{
				m.EnableTriangleGroups();
				for (int j = 0; j < count2; j++)
				{
					m.AppendTriangle(triangles[j], groups[j]);
				}
			}
			else
			{
				for (int k = 0; k < count2; k++)
				{
					m.AppendTriangle(triangles[k]);
				}
			}
		}

		public virtual DMesh3 MakeDMesh()
		{
			DMesh3 dMesh = new DMesh3();
			MakeMesh(dMesh);
			return dMesh;
		}

		public virtual void MakeMesh(NTMesh3 m)
		{
			int count = vertices.Count;
			for (int i = 0; i < count; i++)
			{
				m.AppendVertex(vertices[i]);
			}
			int count2 = triangles.Count;
			if (WantGroups && groups != null && groups.Length == count2)
			{
				m.EnableTriangleGroups();
				for (int j = 0; j < count2; j++)
				{
					m.AppendTriangle(triangles[j], groups[j]);
				}
			}
			else
			{
				for (int k = 0; k < count2; k++)
				{
					m.AppendTriangle(triangles[k]);
				}
			}
		}

		public virtual NTMesh3 MakeNTMesh()
		{
			NTMesh3 nTMesh = new NTMesh3();
			MakeMesh(nTMesh);
			return nTMesh;
		}

		protected void duplicate_vertex_span(int nStart, int nCount)
		{
			for (int i = 0; i < nCount; i++)
			{
				vertices[nStart + nCount + i] = vertices[nStart + i];
				normals[nStart + nCount + i] = normals[nStart + i];
				uv[nStart + nCount + i] = uv[nStart + i];
			}
		}

		protected void append_disc(int Slices, int nCenterV, int nRingStart, bool bClosed, bool bCycle, ref int tri_counter, int groupid = -1)
		{
			int num = nRingStart + Slices;
			for (int i = nRingStart; i < num - 1; i++)
			{
				if (groupid >= 0)
				{
					groups[tri_counter] = groupid;
				}
				triangles.Set(tri_counter++, i, nCenterV, i + 1, bCycle);
			}
			if (bClosed)
			{
				if (groupid >= 0)
				{
					groups[tri_counter] = groupid;
				}
				triangles.Set(tri_counter++, num - 1, nCenterV, nRingStart, bCycle);
			}
		}

		protected void append_rectangle(int v0, int v1, int v2, int v3, bool bCycle, ref int tri_counter, int groupid = -1)
		{
			if (groupid >= 0)
			{
				groups[tri_counter] = groupid;
			}
			triangles.Set(tri_counter++, v0, v1, v2, bCycle);
			if (groupid >= 0)
			{
				groups[tri_counter] = groupid;
			}
			triangles.Set(tri_counter++, v0, v2, v3, bCycle);
		}

		protected void append_2d_disc_segment(int iCenter, int iEnd1, int iEnd2, int nSteps, bool bCycle, ref int vtx_counter, ref int tri_counter, int groupid = -1, double force_r = 0.0)
		{
			Vector3d vector3d = vertices[iCenter];
			Vector3d vector3d2 = vertices[iEnd1];
			Vector3d vector3d3 = vertices[iEnd2];
			Vector3d vector3d4 = vector3d2 - vector3d;
			double num = vector3d4.Normalize();
			if (force_r > 0.0)
			{
				num = force_r;
			}
			double num2 = Math.Atan2(vector3d4.z, vector3d4.x);
			Vector3d vector3d5 = vector3d3 - vector3d;
			double num3 = vector3d5.Normalize();
			if (force_r > 0.0)
			{
				num3 = force_r;
			}
			double num4 = Math.Atan2(vector3d5.z, vector3d5.x);
			if (num2 < 0.0)
			{
				num2 += Math.PI * 2.0;
			}
			if (num4 < 0.0)
			{
				num4 += Math.PI * 2.0;
			}
			if (num4 < num2)
			{
				num4 += Math.PI * 2.0;
			}
			int b = iEnd1;
			for (int i = 0; i < nSteps; i++)
			{
				double num5 = (double)(i + 1) / (double)(nSteps + 1);
				double num6 = (1.0 - num5) * num2 + num5 * num4;
				Vector3d vector3d6 = vector3d + new Vector3d(num * Math.Cos(num6), 0.0, num3 * Math.Sin(num6));
				vertices.Set(vtx_counter, vector3d6.x, vector3d6.y, vector3d6.z);
				if (groupid >= 0)
				{
					groups[tri_counter] = groupid;
				}
				triangles.Set(tri_counter++, iCenter, b, vtx_counter, bCycle);
				b = vtx_counter++;
			}
			if (groupid >= 0)
			{
				groups[tri_counter] = groupid;
			}
			triangles.Set(tri_counter++, iCenter, b, iEnd2, bCycle);
		}

		protected Vector3f estimate_normal(int v0, int v1, int v2)
		{
			Vector3d vector3d = vertices[v0];
			Vector3d vector3d2 = vertices[v1];
			Vector3d vector3d3 = vertices[v2];
			Vector3d normalized = (vector3d2 - vector3d).Normalized;
			Vector3d normalized2 = (vector3d3 - vector3d).Normalized;
			return new Vector3f(normalized.Cross(normalized2));
		}

		protected Vector3d bilerp(ref Vector3d v00, ref Vector3d v10, ref Vector3d v11, ref Vector3d v01, double tx, double ty)
		{
			Vector3d a = Vector3d.Lerp(ref v00, ref v01, ty);
			Vector3d b = Vector3d.Lerp(ref v10, ref v11, ty);
			return Vector3d.Lerp(a, b, tx);
		}

		protected Vector2d bilerp(ref Vector2d v00, ref Vector2d v10, ref Vector2d v11, ref Vector2d v01, double tx, double ty)
		{
			Vector2d a = Vector2d.Lerp(ref v00, ref v01, ty);
			Vector2d b = Vector2d.Lerp(ref v10, ref v11, ty);
			return Vector2d.Lerp(a, b, tx);
		}

		protected Vector2f bilerp(ref Vector2f v00, ref Vector2f v10, ref Vector2f v11, ref Vector2f v01, float tx, float ty)
		{
			Vector2f a = Vector2f.Lerp(ref v00, ref v01, ty);
			Vector2f b = Vector2f.Lerp(ref v10, ref v11, ty);
			return Vector2f.Lerp(a, b, tx);
		}

		protected Vector3i bilerp(ref Vector3i v00, ref Vector3i v10, ref Vector3i v11, ref Vector3i v01, double tx, double ty)
		{
			Vector3d a = Vector3d.Lerp((Vector3d)v00, (Vector3d)v01, ty);
			Vector3d b = Vector3d.Lerp((Vector3d)v10, (Vector3d)v11, ty);
			Vector3d vector3d = Vector3d.Lerp(a, b, tx);
			return new Vector3i((int)Math.Round(vector3d.x), (int)Math.Round(vector3d.y), (int)Math.Round(vector3d.z));
		}

		protected Vector3i lerp(ref Vector3i a, ref Vector3i b, double t)
		{
			Vector3d vector3d = Vector3d.Lerp((Vector3d)a, (Vector3d)b, t);
			return new Vector3i((int)Math.Round(vector3d.x), (int)Math.Round(vector3d.y), (int)Math.Round(vector3d.z));
		}

		private static Vector3[] ToUnityVector3(VectorArray3f a, bool bFlipLR = false)
		{
			Vector3[] array = new Vector3[a.Count];
			float num = ((!bFlipLR) ? 1 : (-1));
			for (int i = 0; i < a.Count; i++)
			{
				array[i].x = a.array[3 * i];
				array[i].y = a.array[3 * i + 1];
				array[i].z = num * a.array[3 * i + 2];
			}
			return array;
		}

		private static Vector3[] ToUnityVector3(VectorArray3d a, bool bFlipLR = false)
		{
			Vector3[] array = new Vector3[a.Count];
			float num = ((!bFlipLR) ? 1 : (-1));
			for (int i = 0; i < a.Count; i++)
			{
				array[i].x = (float)a.array[3 * i];
				array[i].y = (float)a.array[3 * i + 1];
				array[i].z = num * (float)a.array[3 * i + 2];
			}
			return array;
		}

		private static Vector2[] ToUnityVector2(VectorArray2f a)
		{
			Vector2[] array = new Vector2[a.Count];
			for (int i = 0; i < a.Count; i++)
			{
				array[i].x = a.array[2 * i];
				array[i].y = a.array[2 * i + 1];
			}
			return array;
		}

		public void MakeMesh(Mesh m, bool bRecalcNormals = false, bool bFlipLR = false)
		{
			m.vertices = ToUnityVector3(vertices, bFlipLR);
			if (uv != null && WantUVs)
			{
				m.uv = ToUnityVector2(uv);
			}
			if (normals != null && WantNormals)
			{
				m.normals = ToUnityVector3(normals, bFlipLR);
			}
			if (m.vertexCount > 64000 || triangles.Count > 64000)
			{
				m.indexFormat = IndexFormat.UInt32;
			}
			m.triangles = triangles.array;
			if (bRecalcNormals)
			{
				m.RecalculateNormals();
			}
		}
	}
