		{
			double num = CurveUtils.ArcLength(Curve);
			SampledArcLengthParam sampledArcLengthParam = new SampledArcLengthParam(Axis, Axis.Length);
			double num2 = sampledArcLengthParam.ArcLength / num;
			int num3 = Curve.Length;
			int num4 = (NoSharedVertices ? (Slices + 1) : Slices);
			int num5 = ((!NoSharedVertices) ? 1 : (Slices + 1));
			if (!Capped)
			{
				num5 = 0;
			}
			vertices = new VectorArray3d(num4 * num3 + 2 * num5);
			uv = new VectorArray2f(vertices.Count);
			normals = new VectorArray3f(vertices.Count);
			int num6 = (num3 - 1) * (2 * Slices);
			int num7 = (Capped ? (2 * Slices) : 0);
			triangles = new IndexArray3i(num6 + num7);
			float num8 = (float)(Math.PI * 2.0 / (double)Slices);
			double num9 = 0.0;
			CurveSample curveSample = sampledArcLengthParam.Sample(num9);
			Frame3f frame3f = new Frame3f((Vector3f)curveSample.position, (Vector3f)curveSample.tangent, 1);
			Frame3f frame3f2 = frame3f;
			for (int i = 0; i < num3; i++)
			{
				if (i > 0)
				{
					num9 += (Curve[i] - Curve[i - 1]).Length;
					curveSample = sampledArcLengthParam.Sample(num9 * num2);
					frame3f2.Origin = (Vector3f)curveSample.position;
					frame3f2.AlignAxis(1, (Vector3f)curveSample.tangent);
				}
				Vector3d vector3d = Curve[i];
				Vector3f vector3f = frame3f2.ToFrameP((Vector3f)vector3d);
				float x = (float)i / (float)(num3 - 1);
				int num10 = i * num4;
				for (int j = 0; j < num4; j++)
				{
					float angleRad = (float)j * num8;
					Vector3f v = Quaternionf.AxisAngleR(Vector3f.AxisY, angleRad) * vector3f;
					Vector3d vector3d2 = frame3f2.FromFrameP(v);
					int i2 = num10 + j;
					vertices[i2] = vector3d2;
					float y = (float)j / (float)num4;
					uv[i2] = new Vector2f(x, y);
					Vector3f value = (Vector3f)(vector3d2 - frame3f2.Origin).Normalized;
					normals[i2] = value;
				}
			}
			int tri_counter = 0;
			for (int k = 0; k < num3 - 1; k++)
			{
				int num11 = k * num4;
				int num12 = num11 + num4;
				for (int l = 0; l < num4 - 1; l++)
				{
					triangles.Set(tri_counter++, num11 + l, num11 + l + 1, num12 + l + 1, Clockwise);
					triangles.Set(tri_counter++, num11 + l, num12 + l + 1, num12 + l, Clockwise);
				}
				if (!NoSharedVertices)
				{
					triangles.Set(tri_counter++, num12 - 1, num11, num12, Clockwise);
					triangles.Set(tri_counter++, num12 - 1, num12, num12 + num4 - 1, Clockwise);
				}
			}
			if (Capped)
			{
				Vector3d zero = Vector3d.Zero;
				Vector3d zero2 = Vector3d.Zero;
				for (int m = 0; m < Slices; m++)
				{
					zero += vertices[m];
					zero2 += vertices[(num3 - 1) * num4 + m];
				}
				zero /= (double)Slices;
				zero2 /= (double)Slices;
				Frame3f frame3f3 = frame3f;
				frame3f3.Origin = (Vector3f)zero;
				Frame3f frame3f4 = frame3f2;
				frame3f4.Origin = (Vector3f)zero2;
				int num13 = num3 * num4;
				vertices[num13] = frame3f3.Origin;
				uv[num13] = new Vector2f(0.5f, 0.5f);
				normals[num13] = -frame3f3.Z;
				startCapCenterIndex = num13;
				int num14 = num13 + 1;
				vertices[num14] = frame3f4.Origin;
				uv[num14] = new Vector2f(0.5f, 0.5f);
				normals[num14] = frame3f4.Z;
				endCapCenterIndex = num14;
				if (NoSharedVertices)
				{
					int num15 = 0;
					int num16 = num14 + 1;
					for (int n = 0; n < Slices; n++)
					{
						vertices[num16 + n] = vertices[num15 + n];
						float num17 = (float)n * num8;
						double num18 = Math.Cos(num17);
						double num19 = Math.Sin(num17);
						uv[num16 + n] = new Vector2f(0.5 * (1.0 + num18), 0.5 * (1.0 + num19));
						normals[num16 + n] = normals[num13];
					}
					append_disc(Slices, num13, num16, bClosed: true, Clockwise, ref tri_counter);
					int num20 = num4 * (num3 - 1);
					int num21 = num16 + Slices;
					for (int num22 = 0; num22 < Slices; num22++)
					{
						vertices[num21 + num22] = vertices[num20 + num22];
						float num23 = (float)num22 * num8;
						double num24 = Math.Cos(num23);
						double num25 = Math.Sin(num23);
						uv[num21 + num22] = new Vector2f(0.5 * (1.0 + num24), 0.5 * (1.0 + num25));
						normals[num21 + num22] = normals[num14];
					}
					append_disc(Slices, num14, num21, bClosed: true, !Clockwise, ref tri_counter);
				}
				else
				{
					append_disc(Slices, num13, 0, bClosed: true, Clockwise, ref tri_counter);
					append_disc(Slices, num14, num4 * (num3 - 1), bClosed: true, !Clockwise, ref tri_counter);
				}
			}
			return this;
		}
	}
	public class Sphere3Generator_NormalizedCube : GridBox3Generator
	{
		public enum NormalizationTypes
		{
			NormalizedVector,
			CubeMapping
		}

		public double Radius = 1.0;

		private NormalizationTypes NormalizeType = NormalizationTypes.CubeMapping;

		public override MeshGenerator Generate()
		{
			base.Generate();
			for (int i = 0; i < vertices.Count; i++)
			{
				Vector3d vector3d = vertices[i] - Box.Center;
				if (NormalizeType == NormalizationTypes.CubeMapping)
				{
					double num = vector3d.Dot(Box.AxisX) / Box.Extent.x;
					double num2 = vector3d.Dot(Box.AxisY) / Box.Extent.y;
					double num3 = vector3d.Dot(Box.AxisZ) / Box.Extent.z;
					double num4 = num * num;
					double num5 = num2 * num2;
					double num6 = num3 * num3;
					double num7 = num * Math.Sqrt(1.0 - num5 * 0.5 - num6 * 0.5 + num5 * num6 / 3.0);
					double num8 = num2 * Math.Sqrt(1.0 - num4 * 0.5 - num6 * 0.5 + num4 * num6 / 3.0);
					double num9 = num3 * Math.Sqrt(1.0 - num4 * 0.5 - num5 * 0.5 + num4 * num5 / 3.0);
					vector3d = num7 * Box.AxisX + num8 * Box.AxisY + num9 * Box.AxisZ;
				}
				vector3d.Normalize();
				vertices[i] = Box.Center + Radius * vector3d;
				normals[i] = (Vector3f)vector3d;
			}
			return this;
		}
	}
	public class TriangulatedPolygonGenerator : MeshGenerator
	{
		public GeneralPolygon2d Polygon;

		public Vector3f FixedNormal = Vector3f.AxisZ;

		public TrivialRectGenerator.UVModes UVMode;

		public int Subdivisions = 1;

		public override MeshGenerator Generate()
		{
			MeshInsertPolygon insertion;
			DMesh3 dMesh = new DMesh3(ComputeResult(out insertion), bCompact: true);
			int vertexCount = dMesh.VertexCount;
			vertices = new VectorArray3d(vertexCount);
			uv = new VectorArray2f(vertexCount);
			normals = new VectorArray3f(vertexCount);
			for (int i = 0; i < vertexCount; i++)
			{
				vertices[i] = dMesh.GetVertex(i);
				uv[i] = dMesh.GetVertexUV(i);
				normals[i] = FixedNormal;
			}
			int triangleCount = dMesh.TriangleCount;
			triangles = new IndexArray3i(triangleCount);
			for (int j = 0; j < triangleCount; j++)
			{
				triangles[j] = dMesh.GetTriangle(j);
			}
			return this;
		}

		public DMesh3 ComputeResult(out MeshInsertPolygon insertion)
		{
			AxisAlignedBox2d bounds = Polygon.Bounds;
			double fRadius = 0.1 * bounds.DiagonalLength;
			bounds.Expand(fRadius);
			TrivialRectGenerator obj = ((Subdivisions == 1) ? new TrivialRectGenerator() : new GriddedRectGenerator
			{
				EdgeVertices = Subdivisions
			});
			obj.Width = (float)bounds.Width;
			obj.Height = (float)bounds.Height;
			obj.IndicesMap = new Index2i(1, 2);
			obj.UVMode = UVMode;
			obj.Clockwise = true;
			obj.Generate();
			DMesh3 dMesh = new DMesh3();
			obj.MakeMesh(dMesh);
			GeneralPolygon2d generalPolygon2d = new GeneralPolygon2d(Polygon);
			Vector2d center = bounds.Center;
			generalPolygon2d.Translate(-center);
			MeshInsertPolygon meshInsertPolygon = new MeshInsertPolygon
			{
				Mesh = dMesh,
				Polygon = generalPolygon2d
			};
			if (!meshInsertPolygon.Insert())
			{
				throw new Exception("TriangulatedPolygonGenerator: failed to Insert()");
			}
			MeshFaceSelection selected = meshInsertPolygon.InteriorTriangles;
			new MeshEditor(dMesh).RemoveTriangles((int tid) => !selected.IsSelected(tid), bRemoveIsolatedVerts: true);
			Vector3d v = new Vector3d(center.x, center.y, 0.0);
			MeshTransforms.Translate(dMesh, v);
			insertion = meshInsertPolygon;
			return dMesh;
		}
	}
	public class VoxelSurfaceGenerator
	{
		public IBinaryVoxelGrid Voxels;

		public bool SkipInteriorFaces = true;

		public bool CapAtBoundary = true;

		public bool Clockwise;

		public Func<Vector3i, Colorf> ColorSourceF;

		public int MaxMeshElementCount = int.MaxValue;

		public List<DMesh3> Meshes;

		private DMesh3 cur_mesh;

		private void append_mesh()
		{
			if (Meshes == null || Meshes.Count == 0)
			{
				Meshes = new List<DMesh3>();
			}
			cur_mesh = new DMesh3(MeshComponents.VertexNormals);
			if (ColorSourceF != null)
			{
				cur_mesh.EnableVertexColors(Colorf.White);
			}
			Meshes.Add(cur_mesh);
		}

		private void check_counts_or_append(int newV, int newT)
		{
			if (cur_mesh.MaxVertexID + newV >= MaxMeshElementCount || cur_mesh.MaxTriangleID + newT >= MaxMeshElementCount)
			{
				append_mesh();
			}
		}

		public void Generate()
		{
			append_mesh();
			AxisAlignedBox3i gridBounds = Voxels.GridBounds;
			gridBounds.Max -= Vector3i.One;
			int[] array = new int[4];
			foreach (Vector3i item in Voxels.NonZeros())
			{
				check_counts_or_append(6, 2);
				Box3d unitZeroCentered = Box3d.UnitZeroCentered;
				unitZeroCentered.Center = (Vector3d)item;
				for (int i = 0; i < 6; i++)
				{
					Index3i index3i = item + gIndices.GridOffsets6[i];
					if (gridBounds.Contains(index3i))
					{
						if (SkipInteriorFaces && Voxels.Get(index3i))
						{
							continue;
						}
					}
					else if (!CapAtBoundary)
					{
						continue;
					}
					int value = gIndices.BoxFaceNormals[i];
					Vector3f n = (Vector3f)(Math.Sign(value) * unitZeroCentered.Axis(Math.Abs(value) - 1));
					NewVertexInfo info = new NewVertexInfo(Vector3d.Zero, n);
					if (ColorSourceF != null)
					{
						info.c = ColorSourceF(item);
						info.bHaveC = true;
					}
					for (int j = 0; j < 4; j++)
					{
						info.v = unitZeroCentered.Corner(gIndices.BoxFaces[i, j]);
						array[j] = cur_mesh.AppendVertex(info);
					}
					Index3i tv = new Index3i(array[0], array[1], array[2], Clockwise);
					Index3i tv2 = new Index3i(array[0], array[2], array[3], Clockwise);
					cur_mesh.AppendTriangle(tv);
					cur_mesh.AppendTriangle(tv2);
				}
			}
		}
	}
	public class LaplacianMeshDeformer
	{
		public struct SoftConstraintV
		{
			public Vector3d Position;

			public double Weight;

			public bool PostFix;
		}

		public DMesh3 Mesh;

		private PackedSparseMatrix PackedM;

		private int N;

		private int[] ToMeshV;

		private int[] ToIndex;

		private double[] Px;

		private double[] Py;

		private double[] Pz;

		private int[] nbr_counts;

		private double[] MLx;

		private double[] MLy;

		private double[] MLz;

		private Dictionary<int, SoftConstraintV> SoftConstraints = new Dictionary<int, SoftConstraintV>();

		private bool HavePostFixedConstraints;

		private bool need_solve_update;

		private DiagonalMatrix WeightsM;

		private double[] Cx;

		private double[] Cy;

		private double[] Cz;

		private double[] Bx;

		private double[] By;

		private double[] Bz;

		private DiagonalMatrix Preconditioner;

		public bool UseSoftConstraintNormalEquations = true;

		private double[] Sx;

		private double[] Sy;

		private double[] Sz;

		public LaplacianMeshDeformer(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public void SetConstraint(int vID, Vector3d targetPos, double weight, bool bForceToFixedPos = false)
		{
			SoftConstraints[vID] = new SoftConstraintV
			{
				Position = targetPos,
				Weight = weight,
				PostFix = bForceToFixedPos
			};
			HavePostFixedConstraints |= bForceToFixedPos;
			need_solve_update = true;
		}

		public bool IsConstrained(int vID)
		{
			return SoftConstraints.ContainsKey(vID);
		}

		public void ClearConstraints()
		{
			SoftConstraints.Clear();
			HavePostFixedConstraints = false;
			need_solve_update = true;
		}

		public void Initialize()
		{
			ToMeshV = new int[Mesh.MaxVertexID];
			ToIndex = new int[Mesh.MaxVertexID];
			N = 0;
			foreach (int item in Mesh.VertexIndices())
			{
				ToMeshV[N] = item;
				ToIndex[item] = N;
				N++;
			}
			Px = new double[N];
			Py = new double[N];
			Pz = new double[N];
			nbr_counts = new int[N];
			SymmetricSparseMatrix symmetricSparseMatrix = new SymmetricSparseMatrix();
			for (int i = 0; i < N; i++)
			{
				int vID = ToMeshV[i];
				Vector3d vertex = Mesh.GetVertex(vID);
				Px[i] = vertex.x;
				Py[i] = vertex.y;
				Pz[i] = vertex.z;
				nbr_counts[i] = Mesh.GetVtxEdgeCount(vID);
			}
			for (int j = 0; j < N; j++)
			{
				int num = ToMeshV[j];
				int num2 = nbr_counts[j];
				double num3 = 0.0;
				foreach (int item2 in Mesh.VtxVerticesItr(num))
				{
					int num4 = ToIndex[item2];
					int num5 = nbr_counts[num4];
					double num6 = -1.0 / Math.Sqrt(num2 + num5);
					symmetricSparseMatrix.Set(j, num4, num6);
					num3 += num6;
				}
				num3 = 0.0 - num3;
				symmetricSparseMatrix.Set(num, num, num3);
			}
			if (UseSoftConstraintNormalEquations)
			{
				PackedM = symmetricSparseMatrix.SquarePackedParallel();
			}
			else
			{
				PackedM = new PackedSparseMatrix(symmetricSparseMatrix);
			}
			MLx = new double[N];
			MLy = new double[N];
			MLz = new double[N];
			PackedM.Multiply(Px, MLx);
			PackedM.Multiply(Py, MLy);
			PackedM.Multiply(Pz, MLz);
			Preconditioner = new DiagonalMatrix(N);
			WeightsM = new DiagonalMatrix(N);
			Cx = new double[N];
			Cy = new double[N];
			Cz = new double[N];
			Bx = new double[N];
			By = new double[N];
			Bz = new double[N];
			Sx = new double[N];
			Sy = new double[N];
			Sz = new double[N];
			need_solve_update = true;
			UpdateForSolve();
		}

		private void UpdateForSolve()
		{
			if (!need_solve_update)
			{
				return;
			}
			WeightsM.Clear();
			Array.Clear(Cx, 0, N);
			Array.Clear(Cy, 0, N);
			Array.Clear(Cz, 0, N);
			foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
			{
				int key = softConstraint.Key;
				int num = ToIndex[key];
				double num2 = softConstraint.Value.Weight;
				if (UseSoftConstraintNormalEquations)
				{
					num2 *= num2;
				}
				WeightsM.Set(num, num, num2);
				Vector3d position = softConstraint.Value.Position;
				Cx[num] = num2 * position.x;
				Cy[num] = num2 * position.y;
				Cz[num] = num2 * position.z;
			}
			for (int i = 0; i < N; i++)
			{
				Bx[i] = MLx[i] + Cx[i];
				By[i] = MLy[i] + Cy[i];
				Bz[i] = MLz[i] + Cz[i];
			}
			for (int j = 0; j < N; j++)
			{
				double num3 = PackedM[j, j] + WeightsM[j, j];
				Preconditioner.Set(j, j, 1.0 / num3);
			}
			need_solve_update = false;
		}

		public bool SolveMultipleCG(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			Array.Copy(Px, Sx, N);
			Array.Copy(Py, Sy, N);
			Array.Copy(Pz, Sz, N);
			Action<double[], double[]> multiplyF = delegate(double[] X, double[] B)
			{
				PackedM.Multiply_Parallel(X, B);
				for (int i = 0; i < N; i++)
				{
					B[i] += WeightsM[i, i] * X[i];
				}
			};
			SparseSymmetricCG sparseSymmetricCG = new SparseSymmetricCG
			{
				B = Bx,
				X = Sx,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG sparseSymmetricCG2 = new SparseSymmetricCG
			{
				B = By,
				X = Sy,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG sparseSymmetricCG3 = new SparseSymmetricCG
			{
				B = Bz,
				X = Sz,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG[] solvers = new SparseSymmetricCG[3] { sparseSymmetricCG, sparseSymmetricCG2, sparseSymmetricCG3 };
			bool[] ok = new bool[3];
			int[] source = new int[3] { 0, 1, 2 };
			Action<int> body = delegate(int i)
			{
				ok[i] = solvers[i].Solve();
			};
			gParallel.ForEach(source, body);
			if (!ok[0] || !ok[1] || !ok[2])
			{
				return false;
			}
			for (int num = 0; num < N; num++)
			{
				int num2 = ToMeshV[num];
				Result[num2] = new Vector3d(Sx[num], Sy[num], Sz[num]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool SolveMultipleRHS(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			double[][] b = BufferUtil.InitNxM(3, N, new double[3][] { Bx, By, Bz });
			double[][] array = BufferUtil.InitNxM(3, N, new double[3][] { Px, Py, Pz });
			Action<double[][], double[][]> multiplyF = delegate(double[][] Xt, double[][] Bt)
			{
				PackedM.Multiply_Parallel_3(Xt, Bt);
				gParallel.ForEach(Interval1i.Range(3), delegate(int j)
				{
					BufferUtil.MultiplyAdd(Bt[j], WeightsM.D, Xt[j]);
				});
			};
			if (!new SparseSymmetricCGMultipleRHS
			{
				B = b,
				X = array,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = null,
				UseXAsInitialGuess = true
			}.Solve())
			{
				return false;
			}
			for (int num = 0; num < N; num++)
			{
				int num2 = ToMeshV[num];
				Result[num2] = new Vector3d(array[0][num], array[1][num], array[2][num]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool Solve(Vector3d[] Result)
		{
			if (Mesh.VertexCount < 10000)
			{
				return SolveMultipleCG(Result);
			}
			return SolveMultipleRHS(Result);
		}

		public bool SolveAndUpdateMesh()
		{
			int maxVertexID = Mesh.MaxVertexID;
			Vector3d[] array = new Vector3d[maxVertexID];
			if (!Solve(array))
			{
				return false;
			}
			for (int i = 0; i < maxVertexID; i++)
			{
				if (Mesh.IsVertex(i))
				{
					Mesh.SetVertex(i, array[i]);
				}
			}
			return true;
		}
	}
	public class LaplacianMeshSmoother
	{
		public struct SoftConstraintV
		{
			public Vector3d Position;

			public double Weight;

			public bool PostFix;
		}

		public DMesh3 Mesh;

		private PackedSparseMatrix PackedM;

		private int N;

		private int[] ToMeshV;

		private int[] ToIndex;

		private double[] Px;

		private double[] Py;

		private double[] Pz;

		private int[] nbr_counts;

		private double[] MLx;

		private double[] MLy;

		private double[] MLz;

		private Dictionary<int, SoftConstraintV> SoftConstraints = new Dictionary<int, SoftConstraintV>();

		private bool HavePostFixedConstraints;

		private bool need_solve_update;

		private DiagonalMatrix WeightsM;

		private double[] Cx;

		private double[] Cy;

		private double[] Cz;

		private double[] Bx;

		private double[] By;

		private double[] Bz;

		private DiagonalMatrix Preconditioner;

		public bool UseSoftConstraintNormalEquations = true;

		private double[] Sx;

		private double[] Sy;

		private double[] Sz;

		public LaplacianMeshSmoother(DMesh3 mesh)
		{
			Mesh = mesh;
		}

		public void SetConstraint(int vID, Vector3d targetPos, double weight, bool bForceToFixedPos = false)
		{
			SoftConstraints[vID] = new SoftConstraintV
			{
				Position = targetPos,
				Weight = weight,
				PostFix = bForceToFixedPos
			};
			HavePostFixedConstraints |= bForceToFixedPos;
			need_solve_update = true;
		}

		public bool IsConstrained(int vID)
		{
			return SoftConstraints.ContainsKey(vID);
		}

		public void ClearConstraints()
		{
			SoftConstraints.Clear();
			HavePostFixedConstraints = false;
			need_solve_update = true;
		}

		public void Initialize()
		{
			ToMeshV = new int[Mesh.MaxVertexID];
			ToIndex = new int[Mesh.MaxVertexID];
			N = 0;
			foreach (int item in Mesh.VertexIndices())
			{
				ToMeshV[N] = item;
				ToIndex[item] = N;
				N++;
			}
			Px = new double[N];
			Py = new double[N];
			Pz = new double[N];
			nbr_counts = new int[N];
			SymmetricSparseMatrix symmetricSparseMatrix = new SymmetricSparseMatrix();
			for (int i = 0; i < N; i++)
			{
				int vID = ToMeshV[i];
				Vector3d vertex = Mesh.GetVertex(vID);
				Px[i] = vertex.x;
				Py[i] = vertex.y;
				Pz[i] = vertex.z;
				nbr_counts[i] = Mesh.GetVtxEdgeCount(vID);
			}
			for (int j = 0; j < N; j++)
			{
				int num = ToMeshV[j];
				int num2 = nbr_counts[j];
				double num3 = 0.0;
				foreach (int item2 in Mesh.VtxVerticesItr(num))
				{
					int num4 = ToIndex[item2];
					int num5 = nbr_counts[num4];
					double num6 = -1.0 / Math.Sqrt(num2 + num5);
					symmetricSparseMatrix.Set(j, num4, num6);
					num3 += num6;
				}
				num3 = 0.0 - num3;
				symmetricSparseMatrix.Set(num, num, num3);
			}
			if (UseSoftConstraintNormalEquations)
			{
				PackedM = symmetricSparseMatrix.SquarePackedParallel();
			}
			else
			{
				PackedM = new PackedSparseMatrix(symmetricSparseMatrix);
			}
			MLx = new double[N];
			MLy = new double[N];
			MLz = new double[N];
			PackedM.Multiply(Px, MLx);
			PackedM.Multiply(Py, MLy);
			PackedM.Multiply(Pz, MLz);
			for (int k = 0; k < Px.Length; k++)
			{
				MLx[k] = 0.0;
				MLy[k] = 0.0;
				MLz[k] = 0.0;
			}
			Preconditioner = new DiagonalMatrix(N);
			WeightsM = new DiagonalMatrix(N);
			Cx = new double[N];
			Cy = new double[N];
			Cz = new double[N];
			Bx = new double[N];
			By = new double[N];
			Bz = new double[N];
			Sx = new double[N];
			Sy = new double[N];
			Sz = new double[N];
			need_solve_update = true;
			UpdateForSolve();
		}

		private void UpdateForSolve()
		{
			if (!need_solve_update)
			{
				return;
			}
			WeightsM.Clear();
			Array.Clear(Cx, 0, N);
			Array.Clear(Cy, 0, N);
			Array.Clear(Cz, 0, N);
			foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
			{
				int key = softConstraint.Key;
				int num = ToIndex[key];
				double num2 = softConstraint.Value.Weight;
				if (UseSoftConstraintNormalEquations)
				{
					num2 *= num2;
				}
				WeightsM.Set(num, num, num2);
				Vector3d position = softConstraint.Value.Position;
				Cx[num] = num2 * position.x;
				Cy[num] = num2 * position.y;
				Cz[num] = num2 * position.z;
			}
			for (int i = 0; i < N; i++)
			{
				Bx[i] = MLx[i] + Cx[i];
				By[i] = MLy[i] + Cy[i];
				Bz[i] = MLz[i] + Cz[i];
			}
			for (int j = 0; j < N; j++)
			{
				double num3 = PackedM[j, j] + WeightsM[j, j];
				Preconditioner.Set(j, j, 1.0 / num3);
			}
			need_solve_update = false;
		}

		public bool SolveMultipleCG(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			Array.Copy(Px, Sx, N);
			Array.Copy(Py, Sy, N);
			Array.Copy(Pz, Sz, N);
			Action<double[], double[]> multiplyF = delegate(double[] X, double[] B)
			{
				PackedM.Multiply_Parallel(X, B);
				for (int i = 0; i < N; i++)
				{
					B[i] += WeightsM.D[i] * X[i];
				}
			};
			SparseSymmetricCG sparseSymmetricCG = new SparseSymmetricCG
			{
				B = Bx,
				X = Sx,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG sparseSymmetricCG2 = new SparseSymmetricCG
			{
				B = By,
				X = Sy,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG sparseSymmetricCG3 = new SparseSymmetricCG
			{
				B = Bz,
				X = Sz,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = Preconditioner.Multiply,
				UseXAsInitialGuess = true
			};
			SparseSymmetricCG[] solvers = new SparseSymmetricCG[3] { sparseSymmetricCG, sparseSymmetricCG2, sparseSymmetricCG3 };
			bool[] ok = new bool[3];
			int[] source = new int[3] { 0, 1, 2 };
			Action<int> body = delegate(int i)
			{
				ok[i] = solvers[i].SolvePreconditioned();
			};
			gParallel.ForEach(source, body);
			if (!ok[0] || !ok[1] || !ok[2])
			{
				return false;
			}
			for (int num = 0; num < N; num++)
			{
				int num2 = ToMeshV[num];
				Result[num2] = new Vector3d(Sx[num], Sy[num], Sz[num]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool SolveMultipleRHS(Vector3d[] Result)
		{
			if (WeightsM == null)
			{
				Initialize();
			}
			UpdateForSolve();
			double[][] b = BufferUtil.InitNxM(3, N, new double[3][] { Bx, By, Bz });
			double[][] array = BufferUtil.InitNxM(3, N, new double[3][] { Px, Py, Pz });
			Action<double[][], double[][]> multiplyF = delegate(double[][] Xt, double[][] Bt)
			{
				PackedM.Multiply_Parallel_3(Xt, Bt);
				gParallel.ForEach(Interval1i.Range(3), delegate(int j)
				{
					BufferUtil.MultiplyAdd(Bt[j], WeightsM.D, Xt[j]);
				});
			};
			Action<double[][], double[][]> preconditionMultiplyF = delegate(double[][] Xt, double[][] Bt)
			{
				gParallel.ForEach(Interval1i.Range(3), delegate(int j)
				{
					Preconditioner.Multiply(Xt[j], Bt[j]);
				});
			};
			if (!new SparseSymmetricCGMultipleRHS
			{
				B = b,
				X = array,
				MultiplyF = multiplyF,
				PreconditionMultiplyF = preconditionMultiplyF,
				UseXAsInitialGuess = true
			}.SolvePreconditioned())
			{
				return false;
			}
			for (int num = 0; num < N; num++)
			{
				int num2 = ToMeshV[num];
				Result[num2] = new Vector3d(array[0][num], array[1][num], array[2][num]);
			}
			if (HavePostFixedConstraints)
			{
				foreach (KeyValuePair<int, SoftConstraintV> softConstraint in SoftConstraints)
				{
					if (softConstraint.Value.PostFix)
					{
						int key = softConstraint.Key;
						Result[key] = softConstraint.Value.Position;
					}
				}
			}
			return true;
		}

		public bool Solve(Vector3d[] Result)
		{
			if (Mesh.VertexCount < 10000)
			{
				return SolveMultipleCG(Result);
			}
			return SolveMultipleRHS(Result);
		}

		public bool SolveAndUpdateMesh()
		{
			int maxVertexID = Mesh.MaxVertexID;
			Vector3d[] array = new Vector3d[maxVertexID];
			if (!Solve(array))
			{
				return false;
			}
			for (int i = 0; i < maxVertexID; i++)
			{
				if (Mesh.IsVertex(i))
				{
					Mesh.SetVertex(i, array[i]);
				}
			}
			return true;
		}

		public static void RegionSmooth(DMesh3 mesh, IEnumerable<int> triangles, int nConstrainLoops, int nIncludeExteriorRings, bool bPreserveExteriorRings, double borderWeight = 10.0, double interiorWeight = 0.0)
		{
			HashSet<int> hashSet = new HashSet<int>();
			if (nIncludeExteriorRings > 0)
			{
				MeshFaceSelection meshFaceSelection = new MeshFaceSelection(mesh);
				meshFaceSelection.Select(triangles);
				if (bPreserveExteriorRings)
				{
					MeshEdgeSelection meshEdgeSelection = new MeshEdgeSelection(mesh);
					meshEdgeSelection.SelectBoundaryTriEdges(meshFaceSelection);
					meshFaceSelection.ExpandToOneRingNeighbours(nIncludeExteriorRings);
					MeshVertexSelection meshVertexSelection = new MeshVertexSelection(mesh);
					meshVertexSelection.SelectTriangleVertices(triangles);
					meshVertexSelection.DeselectEdges(meshEdgeSelection);
					foreach (int item in new MeshVertexSelection(mesh, meshFaceSelection))
					{
						if (!meshVertexSelection.IsSelected(item))
						{
							hashSet.Add(item);
						}
					}
				}
				else
				{
					meshFaceSelection.ExpandToOneRingNeighbours(nIncludeExteriorRings);
				}
				triangles = meshFaceSelection;
			}
			RegionOperator regionOperator = new RegionOperator(mesh, triangles);
			DSubmesh3 region = regionOperator.Region;
			DMesh3 subMesh = region.SubMesh;
			LaplacianMeshSmoother laplacianMeshSmoother = new LaplacianMeshSmoother(subMesh);
			HashSet<int> hashSet2 = new HashSet<int>();
			foreach (int item2 in hashSet)
			{
				hashSet2.Add(region.MapVertexToSubmesh(item2));
			}
			double num = borderWeight;
			HashSet<int> hashSet3 = ((region.BaseBorderV.Count > 0) ? new HashSet<int>() : null);
			foreach (int item3 in region.BaseBorderV)
			{
				int num2 = region.BaseToSubV[item3];
				laplacianMeshSmoother.SetConstraint(num2, subMesh.GetVertex(num2), num, bForceToFixedPos: true);
				hashSet3?.Add(num2);
			}
			if (hashSet3.Count > 0)
			{
				num = Math.Sqrt(num);
				for (int i = 0; i < nConstrainLoops; i++)
				{
					HashSet<int> hashSet4 = new HashSet<int>();
					foreach (int item4 in hashSet3)
					{
						foreach (int item5 in subMesh.VtxVerticesItr(item4))
						{
							if (!hashSet3.Contains(item5))
							{
								if (!laplacianMeshSmoother.IsConstrained(item5))
								{
									laplacianMeshSmoother.SetConstraint(item5, subMesh.GetVertex(item5), num, hashSet2.Contains(item5));
								}
								hashSet4.Add(item5);
							}
						}
					}
					hashSet3.UnionWith(hashSet4);
					num = Math.Sqrt(num);
				}
			}
			if (interiorWeight > 0.0)
			{
				foreach (int item6 in subMesh.VertexIndices())
				{
					if (!laplacianMeshSmoother.IsConstrained(item6))
					{
						laplacianMeshSmoother.SetConstraint(item6, subMesh.GetVertex(item6), interiorWeight, hashSet2.Contains(item6));
					}
				}
			}
			else if (hashSet2.Count > 0)
			{
				foreach (int item7 in hashSet2)
				{
					if (!laplacianMeshSmoother.IsConstrained(item7))
					{
						laplacianMeshSmoother.SetConstraint(item7, subMesh.GetVertex(item7), 0.0, bForceToFixedPos: true);
					}
				}
			}
			laplacianMeshSmoother.SolveAndUpdateMesh();
			regionOperator.BackPropropagateVertices(bRecomputeBoundaryNormals: true);
		}
	}
	public class MeshBoolean
	{
		public DMesh3 Target;

		public DMesh3 Tool;

		public double VertexSnapTol = 1E-05;

		public DMesh3 Result;

		private MeshMeshCut cutTargetOp;

		private MeshMeshCut cutToolOp;

		private DMesh3 cutTargetMesh;

		private DMesh3 cutToolMesh;

		public bool Compute()
		{
			cutTargetOp = new MeshMeshCut
			{
				Target = new DMesh3(Target),
				CutMesh = Tool,
				VertexSnapTol = VertexSnapTol
			};
			cutTargetOp.Compute();
			cutTargetOp.RemoveContained();
			cutTargetMesh = cutTargetOp.Target;
			cutToolOp = new MeshMeshCut
			{
				Target = new DMesh3(Tool),
				CutMesh = Target,
				VertexSnapTol = VertexSnapTol
			};
			cutToolOp.Compute();
			cutToolOp.RemoveContained();
			cutToolMesh = cutToolOp.Target;
			resolve_vtx_pairs();
			Result = cutToolMesh;
			MeshEditor.Append(Result, cutTargetMesh);
			return true;
		}

		private void resolve_vtx_pairs()
		{
			HashSet<int> hashSet = new HashSet<int>(MeshIterators.BoundaryVertices(cutTargetMesh));
			HashSet<int> hashSet2 = new HashSet<int>(MeshIterators.BoundaryVertices(cutToolMesh));
			split_missing(cutTargetOp, cutToolOp, cutTargetMesh, cutToolMesh, hashSet, hashSet2);
			split_missing(cutToolOp, cutTargetOp, cutToolMesh, cutTargetMesh, hashSet2, hashSet);
		}

		private void split_missing(MeshMeshCut fromOp, MeshMeshCut toOp, DMesh3 fromMesh, DMesh3 toMesh, HashSet<int> fromVerts, HashSet<int> toVerts)
		{
			List<int> list = new List<int>();
			foreach (int fromVert in fromVerts)
			{
				Vector3d vertex = fromMesh.GetVertex(fromVert);
				if (find_nearest_vertex(toMesh, vertex, toVerts) == -1)
				{
					list.Add(fromVert);
				}
			}
			foreach (int item in list)
			{
				Vector3d vertex2 = fromMesh.GetVertex(item);
				int num = find_nearest_edge(toMesh, vertex2, toVerts);
				if (num == -1)
				{
					Console.WriteLine("could not find edge to split?");
					continue;
				}
				if (toMesh.SplitEdge(num, out var split) != MeshResult.Ok)
				{
					Console.WriteLine("edge split failed");
					continue;
				}
				toMesh.SetVertex(split.vNew, vertex2);
				toVerts.Add(split.vNew);
			}
		}

		private int find_nearest_vertex(DMesh3 mesh, Vector3d v, HashSet<int> vertices)
		{
			int result = -1;
			double num = VertexSnapTol * VertexSnapTol;
			foreach (int vertex in vertices)
			{
				double num2 = mesh.GetVertex(vertex).DistanceSquared(ref v);
				if (num2 < num)
				{
					result = vertex;
					num = num2;
				}
			}
			return result;
		}

		private int find_nearest_edge(DMesh3 mesh, Vector3d v, HashSet<int> vertices)
		{
			int result = -1;
			double num = VertexSnapTol * VertexSnapTol;
			foreach (int item in mesh.BoundaryEdgeIndices())
			{
				Index2i edgeV = mesh.GetEdgeV(item);
				if (vertices.Contains(edgeV.a) && vertices.Contains(edgeV.b))
				{
					double num2 = new Segment3d(mesh.GetVertex(edgeV.a), mesh.GetVertex(edgeV.b)).DistanceSquared(v);
					if (num2 < num)
					{
						result = item;
						num = num2;
					}
				}
			}
			return result;
		}
	}
	public class MeshExtrudeFaces
	{
		public DMesh3 Mesh;

		public int[] Triangles;

		public SetGroupBehavior Group = SetGroupBehavior.AutoGenerate;

		public Func<Vector3d, Vector3f, int, Vector3d> ExtrudedPositionF;

		public List<Index2i> EdgePairs;

		public MeshVertexSelection ExtrudeVertices;

		public int[] JoinTriangles;

		public int JoinGroupID;

		public bool JoinIncomplete;

		public MeshExtrudeFaces(DMesh3 mesh, int[] triangles, bool bForceCopyArray = false)
		{
			Mesh = mesh;
			if (bForceCopyArray)
			{
				Triangles = (int[])triangles.Clone();
			}
			else
			{
				Triangles = triangles;
			}
			ExtrudedPositionF = (Vector3d pos, Vector3f normal, int idx) => pos + Vector3d.AxisY;
		}

		public MeshExtrudeFaces(DMesh3 mesh, IEnumerable<int> triangles)
		{
			Mesh = mesh;
			Triangles = triangles.ToArray();
			ExtrudedPositionF = (Vector3d pos, Vector3f normal, int idx) => pos + Vector3d.AxisY;
		}

		public virtual ValidationStatus Validate()
		{
			return ValidationStatus.Ok;
		}

		public virtual bool Extrude()
		{
			MeshEditor meshEditor = new MeshEditor(Mesh);
			meshEditor.SeparateTriangles(Triangles, bComputeEdgePairs: true, out EdgePairs);
			MeshNormals meshNormals = null;
			bool hasVertexNormals = Mesh.HasVertexNormals;
			if (!hasVertexNormals)
			{
				meshNormals = new MeshNormals(Mesh);
				meshNormals.Compute();
			}
			ExtrudeVertices = new MeshVertexSelection(Mesh);
			ExtrudeVertices.SelectTriangleVertices(Triangles);
			Vector3d[] array = new Vector3d[ExtrudeVertices.Count];
			int num = 0;
			foreach (int extrudeVertex in ExtrudeVertices)
			{
				Vector3d vertex = Mesh.GetVertex(extrudeVertex);
				Vector3f arg = (hasVertexNormals ? Mesh.GetVertexNormal(extrudeVertex) : ((Vector3f)meshNormals.Normals[extrudeVertex]));
				array[num++] = ExtrudedPositionF(vertex, arg, extrudeVertex);
			}
			num = 0;
			foreach (int extrudeVertex2 in ExtrudeVertices)
			{
				Mesh.SetVertex(extrudeVertex2, array[num++]);
			}
			JoinGroupID = Group.GetGroupID(Mesh);
			JoinTriangles = meshEditor.StitchUnorderedEdges(EdgePairs, JoinGroupID, bAbortOnFailure: false, out JoinIncomplete);
			if (JoinTriangles != null)
			{
				return !JoinIncomplete;
			}
			return false;
		}
	}
	public class MeshExtrudeLoop
	{
		public DMesh3 Mesh;

		public EdgeLoop Loop;

		public Func<Vector3d, Vector3f, int, Vector3d> PositionF;

		public int[] NewTriangles;

		public EdgeLoop NewLoop;

		public MeshExtrudeLoop(DMesh3 mesh, EdgeLoop loop)
		{
			Mesh = mesh;
			Loop = loop;
			PositionF = (Vector3d pos, Vector3f normal, int idx) => pos + Vector3d.AxisY;
		}

		public virtual ValidationStatus Validate()
		{
			return MeshValidation.IsBoundaryLoop(Mesh, Loop);
		}

		public virtual bool Extrude(int group_id = -1)
		{
			int num = Loop.Vertices.Length;
			NewLoop = new EdgeLoop(Mesh);
			NewLoop.Vertices = new int[num];
			for (int i = 0; i < num; i++)
			{
				int fromVID = Loop.Vertices[i];
				NewLoop.Vertices[i] = Mesh.AppendVertex(Mesh, fromVID);
			}
			for (int j = 0; j < num; j++)
			{
				Vector3d vertex = Mesh.GetVertex(Loop.Vertices[j]);
				Vector3f vertexNormal = Mesh.GetVertexNormal(Loop.Vertices[j]);
				Vector3d vNewPos = PositionF(vertex, vertexNormal, Loop.Vertices[j]);
				Mesh.SetVertex(NewLoop.Vertices[j], vNewPos);
			}
			MeshEditor meshEditor = new MeshEditor(Mesh);
			NewTriangles = meshEditor.StitchLoop(Loop.Vertices, NewLoop.Vertices, group_id);
			return true;
		}
	}
	public class MeshExtrudeMesh
	{
		public DMesh3 Mesh;

		public SetGroupBehavior OffsetGroup = SetGroupBehavior.AutoGenerate;

		public SetGroupBehavior StitchGroups = SetGroupBehavior.AutoGenerate;

		public Func<Vector3d, Vector3f, int, Vector3d> ExtrudedPositionF;

		public bool IsPositiveOffset = true;

		public MeshBoundaryLoops InitialLoops;

		public int[] InitialTriangles;

		public int[] InitialVertices;

		public IndexMap InitialToOffsetMapV;

		private List<int> OffsetTriangles;

		public int OffsetGroupID;

		public EdgeLoop[] NewLoops;

		public int[][] StitchTriangles;

		public int[] StitchGroupIDs;

		public MeshExtrudeMesh(DMesh3 mesh)
		{
			Mesh = mesh;
			ExtrudedPositionF = (Vector3d pos, Vector3f normal, int idx) => pos + normal;
		}

		public virtual ValidationStatus Validate()
		{
			return ValidationStatus.Ok;
		}

		public virtual bool Extrude()
		{
			MeshNormals meshNormals = null;
			bool hasVertexNormals = Mesh.HasVertexNormals;
			if (!hasVertexNormals)
			{
				meshNormals = new MeshNormals(Mesh);
				meshNormals.Compute();
			}
			InitialLoops = new MeshBoundaryLoops(Mesh);
			InitialTriangles = Mesh.TriangleIndices().ToArray();
			InitialVertices = Mesh.VertexIndices().ToArray();
			InitialToOffsetMapV = new IndexMap(Mesh.MaxVertexID, Mesh.MaxVertexID);
			OffsetGroupID = OffsetGroup.GetGroupID(Mesh);
			MeshEditor meshEditor = new MeshEditor(Mesh);
			OffsetTriangles = meshEditor.DuplicateTriangles(InitialTriangles, ref InitialToOffsetMapV, OffsetGroupID);
			int[] initialVertices = InitialVertices;
			foreach (int num in initialVertices)
			{
				int vID = InitialToOffsetMapV[num];
				if (Mesh.IsVertex(vID))
				{
					Vector3d vertex = Mesh.GetVertex(num);
					Vector3f arg = (hasVertexNormals ? Mesh.GetVertexNormal(num) : ((Vector3f)meshNormals.Normals[num]));
					Vector3d vNewPos = ExtrudedPositionF(vertex, arg, num);
					Mesh.SetVertex(vID, vNewPos);
				}
			}
			if (IsPositiveOffset)
			{
				meshEditor.ReverseTriangles(InitialTriangles);
			}
			else
			{
				meshEditor.ReverseTriangles(OffsetTriangles);
			}
			NewLoops = new EdgeLoop[InitialLoops.Count];
			StitchTriangles = new int[InitialLoops.Count][];
			StitchGroupIDs = new int[InitialLoops.Count];
			int num2 = 0;
			foreach (EdgeLoop initialLoop in InitialLoops)
			{
				int[] array = new int[initialLoop.VertexCount];
				for (int j = 0; j < array.Length; j++)
				{
					array[j] = InitialToOffsetMapV[initialLoop.Vertices[j]];
				}
				StitchGroupIDs[num2] = StitchGroups.GetGroupID(Mesh);
				if (IsPositiveOffset)
				{
					StitchTriangles[num2] = meshEditor.StitchLoop(array, initialLoop.Vertices, StitchGroupIDs[num2]);
				}
				else
				{
					StitchTriangles[num2] = meshEditor.StitchLoop(initialLoop.Vertices, array, StitchGroupIDs[num2]);
				}
				NewLoops[num2] = EdgeLoop.FromVertices(Mesh, array);
				num2++;
			}
			return true;
		}
	}
	public class MeshICP
	{
		public IPointSet Source;

		public DMeshAABBTree3 TargetSurface;

		public Vector3d Translation;

		public Quaterniond Rotation;

		public Action<string> VerboseF;

		public int MaxIterations = 50;

		public bool UseNormals;

		public double MaxAllowableDistance = double.MaxValue;

		public double ConvergeTolerance = 1E-05;

		public bool Converged;

		private bool is_initialized;

		private int[] MapV;

		private Vector3d[] From;

		private Vector3d[] To;

		private double[] Weights;

		private double LastError;

		public double Error => LastError;

		public MeshICP(IPointSet source, DMeshAABBTree3 target)
		{
			Source = source;
			TargetSurface = target;
			Translation = Vector3d.Zero;
			Rotation = Quaterniond.Identity;
		}

		public void Solve(bool bUpdate = false)
		{
			if (!bUpdate)
			{
				is_initialized = false;
			}
			if (!is_initialized)
			{
				initialize();
				is_initialized = true;
			}
			update_from();
			update_to();
			LastError = measure_error();
			int num = 0;
			int num2 = 5;
			for (int i = 0; i < MaxIterations; i++)
			{
				if (num >= num2)
				{
					break;
				}
				if (VerboseF != null)
				{
					VerboseF($"[ICP] iter {i} : error {LastError}");
				}
				update_transformation();
				update_from();
				update_to();
				double num3 = measure_error();
				if (Math.Abs(LastError - num3) < ConvergeTolerance)
				{
					num++;
					continue;
				}
				LastError = num3;
				num = 0;
			}
			Converged = num >= num2;
		}

		public void UpdateVertices(IDeformableMesh target)
		{
			bool hasVertexNormals = target.HasVertexNormals;
			update_from();
			foreach (int item in target.VertexIndices())
			{
				int num = MapV[item];
				target.SetVertex(item, From[num]);
				if (hasVertexNormals)
				{
					target.SetVertexNormal(item, (Vector3f)(Rotation * target.GetVertexNormal(item)));
				}
			}
		}

		private void initialize()
		{
			From = new Vector3d[Source.VertexCount];
			To = new Vector3d[Source.VertexCount];
			Weights = new double[Source.VertexCount];
			MapV = new int[Source.MaxVertexID];
			int num = 0;
			foreach (int item in Source.VertexIndices())
			{
				MapV[item] = num;
				Weights[num] = 1.0;
				From[num++] = Source.GetVertex(item);
			}
		}

		private void update_from()
		{
			int num = 0;
			foreach (int item in Source.VertexIndices())
			{
				Weights[num] = 1.0;
				Vector3d vertex = Source.GetVertex(item);
				From[num++] = Rotation * vertex + Translation;
			}
		}

		private void update_to()
		{
			double max_dist = double.MaxValue;
			bool bNormals = UseNormals && Source.HasVertexNormals;
			gParallel.ForEach(Interval1i.Range(From.Length), delegate(int vi)
			{
				int num = TargetSurface.FindNearestTriangle(From[vi], max_dist);
				if (num == -1)
				{
					Weights[vi] = 0.0;
				}
				else
				{
					DistPoint3Triangle3 distPoint3Triangle = MeshQueries.TriangleDistance(TargetSurface.Mesh, num, From[vi]);
					if (distPoint3Triangle.DistanceSquared > MaxAllowableDistance * MaxAllowableDistance)
					{
						Weights[vi] = 0.0;
					}
					else
					{
						To[vi] = distPoint3Triangle.TriangleClosest;
						Weights[vi] = 1.0;
						if (bNormals)
						{
							Vector3d vector3d = Rotation * Source.GetVertexNormal(vi);
							Vector3d triNormal = TargetSurface.Mesh.GetTriNormal(num);
							double num2 = vector3d.Dot(triNormal);
							if (num2 < 0.0)
							{
								Weights[vi] = 0.0;
							}
							else
							{
								Weights[vi] += Math.Sqrt(num2);
							}
						}
					}
				}
			});
		}

		private double measure_error()
		{
			double num = 0.0;
			double num2 = 0.0;
			for (int i = 0; i < From.Length; i++)
			{
				num += Weights[i] * From[i].Distance(To[i]);
				num2 += Weights[i];
			}
			return num / num2;
		}

		private void update_transformation()
		{
			int num = From.Length;
			double num2 = 0.0;
			for (int i = 0; i < num; i++)
			{
				num2 += Weights[i];
			}
			double num3 = 1.0 / num2;
			Vector3d zero = Vector3d.Zero;
			Vector3d zero2 = Vector3d.Zero;
			for (int j = 0; j < num; j++)
			{
				zero += Weights[j] * num3 * From[j];
				zero2 += Weights[j] * num3 * To[j];
			}
			for (int k = 0; k < num; k++)
			{
				From[k] -= zero;
				To[k] -= zero2;
			}
			double[] array = new double[9];
			for (int l = 0; l < 3; l++)
			{
				int num4 = 3 * l;
				for (int m = 0; m < num; m++)
				{
					double num5 = Weights[m] * num3 * From[m][l];
					array[num4] += num5 * To[m].x;
					array[num4 + 1] += num5 * To[m].y;
					array[num4 + 2] += num5 * To[m].z;
				}
			}
			SingularValueDecomposition singularValueDecomposition = new SingularValueDecomposition(3, 3, 100);
			singularValueDecomposition.Solve(array);
			double[] array2 = new double[9];
			double[] array3 = new double[9];
			double[] array4 = new double[9];
			singularValueDecomposition.GetU(array2);
			singularValueDecomposition.GetV(array3);
			double[] array5 = new double[9];
			double num6 = MatrixUtil.Determinant3x3(array2);
			double num7 = MatrixUtil.Determinant3x3(array3);
			if (num6 * num7 < 0.0)
			{
				double[] b = MatrixUtil.MakeDiagonal3x3(1.0, 1.0, -1.0);
				MatrixUtil.Multiply3x3(array3, b, array4);
				MatrixUtil.Transpose3x3(array2);
				MatrixUtil.Multiply3x3(array4, array2, array5);
			}
			else
			{
				MatrixUtil.Transpose3x3(array2);
				MatrixUtil.Multiply3x3(array3, array2, array5);
			}
			Matrix3d mat = new Matrix3d(array5);
			Quaterniond quaterniond = new Quaterniond(mat);
			Vector3d vector3d = zero2 - quaterniond * zero;
			Translation += vector3d;
			Rotation = quaterniond * Rotation;
		}
	}
	public class MeshInsertPolygon
	{
		public DMesh3 Mesh;

		public GeneralPolygon2d Polygon;

		public bool SimplifyInsertion = true;

		public MeshInsertUVPolyCurve OuterInsert;

		public List<MeshInsertUVPolyCurve> HoleInserts;

		public HashSet<int> InsertedPolygonEdges;

		public MeshFaceSelection InteriorTriangles;

		public bool Insert()
		{
			OuterInsert = new MeshInsertUVPolyCurve(Mesh, Polygon.Outer);
			if (!OuterInsert.Apply() || OuterInsert.Loops.Count == 0)
			{
				return false;
			}
			if (SimplifyInsertion)
			{
				OuterInsert.Simplify();
			}
			HoleInserts = new List<MeshInsertUVPolyCurve>(Polygon.Holes.Count);
			for (int i = 0; i < Polygon.Holes.Count; i++)
			{
				MeshInsertUVPolyCurve meshInsertUVPolyCurve = new MeshInsertUVPolyCurve(Mesh, Polygon.Holes[i]);
				meshInsertUVPolyCurve.Apply();
				if (SimplifyInsertion)
				{
					meshInsertUVPolyCurve.Simplify();
				}
				HoleInserts.Add(meshInsertUVPolyCurve);
			}
			int num = -1;
			EdgeLoop edgeLoop = OuterInsert.Loops[0];
			for (int j = 0; j < edgeLoop.EdgeCount; j++)
			{
				if (Mesh.IsEdge(edgeLoop.Edges[j]))
				{
					Index2i edgeT = Mesh.GetEdgeT(edgeLoop.Edges[j]);
					Vector3d triCentroid = Mesh.GetTriCentroid(edgeT.a);
					bool flag = Polygon.Outer.Contains(triCentroid.xy);
					Vector3d triCentroid2 = Mesh.GetTriCentroid(edgeT.b);
					bool flag2 = Polygon.Outer.Contains(triCentroid2.xy);
					if (flag && !flag2)
					{
						num = edgeT.a;
						break;
					}
					if (flag2 && !flag)
					{
						num = edgeT.b;
						break;
					}
				}
			}
			if (num == -1)
			{
				throw new Exception("MeshPolygonsInserter: could not find seed triangle!");
			}
			InsertedPolygonEdges = new HashSet<int>(edgeLoop.Edges);
			foreach (MeshInsertUVPolyCurve holeInsert in HoleInserts)
			{
				int[] edges = holeInsert.Loops[0].Edges;
				foreach (int item in edges)
				{
					InsertedPolygonEdges.Add(item);
				}
			}
			InteriorTriangles = new MeshFaceSelection(Mesh);
			InteriorTriangles.FloodFill(num, null, (int eid) => !InsertedPolygonEdges.Contains(eid));
			return true;
		}
	}
	public class MeshInsertUVPolyCurve
	{
		public DMesh3 Mesh;

		public PolyLine2d Curve;

		public bool IsLoop;

		public Func<int, Vector2d> PointF;

		public Action<int, Vector2d> SetPointF;

		public bool EnableCutSpansAndLoops = true;

		public bool UseTriSpatial = true;

		public double SpatialEpsilon = 1E-08;

		public int[] CurveVertices;

		public HashSet<int> OnCutEdges;

		public List<EdgeSpan> Spans;

		public List<EdgeLoop> Loops;

		private TriangleBinsGrid2d triSpatial;

		public MeshInsertUVPolyCurve(DMesh3 mesh, PolyLine2d curve, bool isLoop = false)
		{
			Mesh = mesh;
			Curve = curve;
			IsLoop = isLoop;
			PointF = (int vid) => Mesh.GetVertex(vid).xy;
			SetPointF = delegate(int vid, Vector2d pos)
			{
				Mesh.SetVertex(vid, new Vector3d(pos.x, pos.y, 0.0));
			};
		}

		public MeshInsertUVPolyCurve(DMesh3 mesh, Polygon2d loop)
		{
			Mesh = mesh;
			Curve = new PolyLine2d(loop.Vertices);
			IsLoop = true;
			PointF = (int vid) => Mesh.GetVertex(vid).xy;
			SetPointF = delegate(int vid, Vector2d pos)
			{
				Mesh.SetVertex(vid, new Vector3d(pos.x, pos.y, 0.0));
			};
		}

		public MeshInsertUVPolyCurve(DMesh3 mesh, PolyLine2d path)
		{
			Mesh = mesh;
			Curve = new PolyLine2d(path.Vertices);
			IsLoop = false;
			PointF = (int vid) => Mesh.GetVertex(vid).xy;
			SetPointF = delegate(int vid, Vector2d pos)
			{
				Mesh.SetVertex(vid, new Vector3d(pos.x, pos.y, 0.0));
			};
		}

		public virtual ValidationStatus Validate(double fDegenerateTol = 9.999999974752427E-07)
		{
			double num = fDegenerateTol * fDegenerateTol;
			int num2 = (IsLoop ? (Curve.VertexCount - 1) : Curve.VertexCount);
			for (int i = 0; i < num2; i++)
			{
				Vector2d vector2d = Curve[i];
				Vector2d v = Curve[(i + 1) % Curve.VertexCount];
				if (vector2d.DistanceSquared(v) < num)
				{
					return ValidationStatus.NearDenegerateInputGeometry;
				}
			}
			foreach (int item in Mesh.EdgeIndices())
			{
				Index2i edgeV = Mesh.GetEdgeV(item);
				if (PointF(edgeV.a).DistanceSquared(PointF(edgeV.b)) < num)
				{
					return ValidationStatus.NearDegenerateMeshEdges;
				}
			}
			return ValidationStatus.Ok;
		}

		private void spatial_add_triangle(int tid)
		{
			if (triSpatial != null)
			{
				Index3i triangle = Mesh.GetTriangle(tid);
				Vector2d a = PointF(triangle.a);
				Vector2d b = PointF(triangle.b);
				Vector2d c = PointF(triangle.c);
				triSpatial.InsertTriangleUnsafe(tid, ref a, ref b, ref c);
			}
		}

		private void spatial_add_triangles(int t0, int t1)
		{
			if (triSpatial != null)
			{
				spatial_add_triangle(t0);
				if (t1 != -1)
				{
					spatial_add_triangle(t1);
				}
			}
		}

		private void spatial_remove_triangle(int tid)
		{
			if (triSpatial != null)
			{
				Index3i triangle = Mesh.GetTriangle(tid);
				Vector2d a = PointF(triangle.a);
				Vector2d b = PointF(triangle.b);
				Vector2d c = PointF(triangle.c);
				triSpatial.RemoveTriangleUnsafe(tid, ref a, ref b, ref c);
			}
		}

		private void spatial_remove_triangles(int t0, int t1)
		{
			if (triSpatial != null)
			{
				spatial_remove_triangle(t0);
				if (t1 != -1)
				{
					spatial_remove_triangle(t1);
				}
			}
		}

		private void insert_corners(HashSet<int> MeshVertsOnCurve)
		{
			PrimalQuery2d query = new PrimalQuery2d(PointF);
			if (UseTriSpatial)
			{
				int num = Mesh.TriangleCount + Curve.VertexCount;
				int numCells = 32;
				if (num < 25)
				{
					numCells = 8;
				}
				else if (num < 100)
				{
					numCells = 16;
				}
				AxisAlignedBox3d cachedBounds = Mesh.CachedBounds;
				AxisAlignedBox2d bounds = new AxisAlignedBox2d(cachedBounds.Min.xy, cachedBounds.Max.xy);
				triSpatial = new TriangleBinsGrid2d(bounds, numCells);
				foreach (int item in Mesh.TriangleIndices())
				{
					spatial_add_triangle(item);
				}
			}
			Func<int, Vector2d, bool> containsF = delegate(int tid, Vector2d pos)
			{
				Index3i triangle3 = Mesh.GetTriangle(tid);
				int num6 = query.ToTriangleUnsigned(pos, triangle3.a, triangle3.b, triangle3.c);
				return num6 == -1 || num6 == 0;
			};
			CurveVertices = new int[Curve.VertexCount];
			for (int num2 = 0; num2 < Curve.VertexCount; num2++)
			{
				Vector2d vector2d = Curve[num2];
				bool flag = false;
				int num3 = -1;
				if (triSpatial != null)
				{
					num3 = triSpatial.FindContainingTriangle(vector2d, containsF);
				}
				else
				{
					foreach (int item2 in Mesh.TriangleIndices())
					{
						Index3i triangle = Mesh.GetTriangle(item2);
						int num4 = query.ToTriangleUnsigned(vector2d, triangle.a, triangle.b, triangle.c);
						if (num4 == -1 || num4 == 0)
						{
							num3 = item2;
							break;
						}
					}
				}
				if (num3 != -1)
				{
					Index3i triangle2 = Mesh.GetTriangle(num3);
					Vector3d bary_coords = MathUtil.BarycentricCoords(vector2d, PointF(triangle2.a), PointF(triangle2.b), PointF(triangle2.c));
					bool is_existing_v;
					int num5 = insert_corner_from_bary(num2, num3, bary_coords, 0.01, 100.0 * SpatialEpsilon, out is_existing_v);
					if (num5 > 0)
					{
						CurveVertices[num2] = num5;
						if (is_existing_v)
						{
							MeshVertsOnCurve.Add(num5);
						}
						flag = true;
					}
				}
				if (!flag)
				{
					foreach (int item3 in Mesh.VertexIndices())
					{
						Vector2d v = PointF(item3);
						if (vector2d.Distance(v) < SpatialEpsilon)
						{
							CurveVertices[num2] = item3;
							MeshVertsOnCurve.Add(item3);
							flag = true;
						}
					}
				}
				if (!flag)
				{
					throw new Exception("MeshInsertUVPolyCurve.insert_corners: curve vertex " + num2 + " is not inside or on any mesh triangle!");
				}
			}
		}

		private int insert_corner_from_bary(int iCorner, int tid, Vector3d bary_coords, double bary_tol, double spatial_tol, out bool is_existing_v)
		{
			is_existing_v = false;
			Vector2d vector2d = Curve[iCorner];
			Index3i triangle = Mesh.GetTriangle(tid);
			int num = -1;
			if (bary_coords.x > 1.0 - bary_tol)
			{
				num = triangle.a;
			}
			else if (bary_coords.y > 1.0 - bary_tol)
			{
				num = triangle.b;
			}
			else if (bary_coords.z > 1.0 - bary_tol)
			{
				num = triangle.c;
			}
			if (num != -1 && PointF(num).Distance(vector2d) < spatial_tol)
			{
				is_existing_v = true;
				return num;
			}
			int num2 = -1;
			if (bary_coords.x < bary_tol)
			{
				num2 = 1;
			}
			else if (bary_coords.y < bary_tol)
			{
				num2 = 2;
			}
			else if (bary_coords.z < bary_tol)
			{
				num2 = 0;
			}
			if (num2 >= 0)
			{
				int triEdge = Mesh.GetTriEdge(tid, num2);
				Index2i edgeV = Mesh.GetEdgeV(triEdge);
				if (new Segment2d(PointF(edgeV.a), PointF(edgeV.b)).DistanceSquared(vector2d) < spatial_tol * spatial_tol)
				{
					Index2i edgeT = Mesh.GetEdgeT(triEdge);
					spatial_remove_triangles(edgeT.a, edgeT.b);
					DMesh3.EdgeSplitInfo split;
					MeshResult meshResult = Mesh.SplitEdge(triEdge, out split);
					if (meshResult != MeshResult.Ok)
					{
						throw new Exception("MeshInsertUVPolyCurve.insert_corner_from_bary: edge split failed in case sum==2 - " + meshResult);
					}
					SetPointF(split.vNew, vector2d);
					spatial_add_triangles(edgeT.a, edgeT.b);
					spatial_add_triangles(split.eNewT2, split.eNewT3);
					return split.vNew;
				}
			}
			spatial_remove_triangle(tid);
			DMesh3.PokeTriangleInfo result;
			MeshResult meshResult2 = Mesh.PokeTriangle(tid, bary_coords, out result);
			if (meshResult2 != MeshResult.Ok)
			{
				throw new Exception("MeshInsertUVPolyCurve.insert_corner_from_bary: face poke failed - " + meshResult2);
			}
			SetPointF(result.new_vid, vector2d);
			spatial_add_triangle(tid);
			spatial_add_triangle(result.new_t1);
			spatial_add_triangle(result.new_t2);
			return result.new_vid;
		}

		public virtual bool Apply()
		{
			HashSet<int> hashSet = new HashSet<int>();
			insert_corners(hashSet);
			HashSet<int> hashSet2 = new HashSet<int>();
			HashSet<int> hashSet3 = new HashSet<int>();
			OnCutEdges = new HashSet<int>();
			HashSet<int> hashSet4 = new HashSet<int>();
			HashSet<int> hashSet5 = new HashSet<int>();
			sbyte[] signs = new sbyte[2 * Mesh.MaxVertexID + 2 * Curve.VertexCount];
			HashSet<int> hashSet6 = new HashSet<int>();
			HashSet<int> hashSet7 = new HashSet<int>();
			HashSet<int> hashSet8 = new HashSet<int>();
			int num = (IsLoop ? Curve.VertexCount : (Curve.VertexCount - 1));
			for (int i = 0; i < num; i++)
			{
				int num2 = i;
				int num3 = (i + 1) % Curve.VertexCount;
				Segment2d seg = new Segment2d(Curve[num2], Curve[num3]);
				int i0_vid = CurveVertices[num2];
				int i1_vid = CurveVertices[num3];
				int num4 = Mesh.FindEdge(i0_vid, i1_vid);
				if (num4 != -1)
				{
					add_cut_edge(num4);
					continue;
				}
				if (triSpatial != null)
				{
					hashSet6.Clear();
					hashSet7.Clear();
					hashSet8.Clear();
					AxisAlignedBox2d range = new AxisAlignedBox2d(seg.P0);
					range.Contain(seg.P1);
					range.Expand(9.999999747378752E-06);
					triSpatial.FindTrianglesInRange(range, hashSet6);
					IndexUtil.TrianglesToVertices(Mesh, hashSet6, hashSet7);
					IndexUtil.TrianglesToEdges(Mesh, hashSet6, hashSet8);
				}
				int maxVertexID = Mesh.MaxVertexID;
				IEnumerable<int> source = Interval1i.Range(maxVertexID);
				if (triSpatial != null)
				{
					source = hashSet7;
				}
				if (signs.Length < maxVertexID)
				{
					signs = new sbyte[2 * maxVertexID];
				}
				gParallel.ForEach(source, delegate(int vid)
				{
					if (Mesh.IsVertex(vid))
					{
						if (vid == i0_vid || vid == i1_vid)
						{
							signs[vid] = 0;
						}
						else
						{
							Vector2d test = PointF(vid);
							signs[vid] = (sbyte)seg.WhichSide(test, SpatialEpsilon);
						}
					}
					else
					{
						signs[vid] = sbyte.MaxValue;
					}
				});
				int maxEdgeID = Mesh.MaxEdgeID;
				hashSet4.Clear();
				hashSet5.Clear();
				hashSet5.Add(i0_vid);
				hashSet5.Add(i1_vid);
				IEnumerable<int> enumerable = Interval1i.Range(maxEdgeID);
				if (triSpatial != null)
				{
					enumerable = hashSet8;
				}
				foreach (int item2 in enumerable)
				{
					if (!Mesh.IsEdge(item2) || item2 >= maxEdgeID || hashSet4.Contains(item2) || Mesh.IsBoundaryEdge(item2))
					{
						continue;
					}
					Index2i edgeV = Mesh.GetEdgeV(item2);
					int num5 = signs[edgeV.a];
					int num6 = signs[edgeV.b];
					bool flag = false;
					if (num5 == 0)
					{
						flag = hashSet.Contains(edgeV.a) || Math.Abs(seg.Project(PointF(edgeV.a))) < seg.Extent + SpatialEpsilon;
					}
					bool flag2 = false;
					if (num6 == 0)
					{
						flag2 = hashSet.Contains(edgeV.b) || Math.Abs(seg.Project(PointF(edgeV.b))) < seg.Extent + SpatialEpsilon;
					}
					if (flag || flag2)
					{
						if (flag && flag2)
						{
							hashSet2.Add(item2);
							add_cut_edge(item2);
							hashSet5.Add(edgeV.a);
							hashSet5.Add(edgeV.b);
						}
						else
						{
							int item = (flag ? edgeV.a : edgeV.b);
							hashSet3.Add(item);
							hashSet5.Add(item);
						}
					}
					else
					{
						if (num5 * num6 > 0)
						{
							continue;
						}
						Vector2d vector2d = PointF(edgeV.a);
						Vector2d vector2d2 = PointF(edgeV.b);
						Segment2d seg2 = new Segment2d(vector2d, vector2d2);
						IntrSegment2Segment2 intrSegment2Segment = new IntrSegment2Segment2(seg, seg2);
						intrSegment2Segment.Compute();
						if (intrSegment2Segment.Type == IntersectionType.Segment)
						{
							hashSet2.Add(item2);
							hashSet5.Add(edgeV.a);
							hashSet5.Add(edgeV.b);
							add_cut_edge(item2);
						}
						else
						{
							if (intrSegment2Segment.Type != IntersectionType.Point)
							{
								continue;
							}
							Vector2d point = intrSegment2Segment.Point0;
							double split_t = Math.Sqrt(point.DistanceSquared(vector2d) / vector2d.DistanceSquared(vector2d2));
							if (!(Math.Abs(seg2.Project(point)) < seg2.Extent - SpatialEpsilon))
							{
								continue;
							}
							Index2i edgeT = Mesh.GetEdgeT(item2);
							spatial_remove_triangles(edgeT.a, edgeT.b);
							DMesh3.EdgeSplitInfo split;
							MeshResult meshResult = Mesh.SplitEdge(item2, out split, split_t);
							if (meshResult != MeshResult.Ok)
							{
								throw new Exception("MeshInsertUVSegment.Apply: SplitEdge failed - " + meshResult);
							}
							SetPointF(split.vNew, point);
							hashSet5.Add(split.vNew);
							hashSet4.Add(split.eNewBN);
							hashSet4.Add(split.eNewCN);
							spatial_add_triangles(edgeT.a, edgeT.b);
							spatial_add_triangles(split.eNewT2, split.eNewT3);
							Index2i edgeV2 = Mesh.GetEdgeV(split.eNewCN);
							if (hashSet5.Contains(edgeV2.a) && hashSet5.Contains(edgeV2.b))
							{
								add_cut_edge(split.eNewCN);
							}
							if (split.eNewDN != -1)
							{
								hashSet4.Add(split.eNewDN);
								Index2i edgeV3 = Mesh.GetEdgeV(split.eNewDN);
								if (hashSet5.Contains(edgeV3.a) && hashSet5.Contains(edgeV3.b))
								{
									add_cut_edge(split.eNewDN);
								}
							}
						}
					}
				}
			}
			if (EnableCutSpansAndLoops)
			{
				find_cut_paths(OnCutEdges);
			}
			return true;
		}

		private void add_cut_edge(int eid)
		{
			OnCutEdges.Add(eid);
		}

		public void Simplify()
		{
			for (int i = 0; i < Loops.Count; i++)
			{
				EdgeLoop value = simplify(Loops[i]);
				Loops[i] = value;
			}
		}

		private EdgeLoop simplify(EdgeLoop loop)
		{
			HashSet<int> hashSet = new HashSet<int>(CurveVertices);
			List<int> list = new List<int>();
			for (int i = 0; i < loop.EdgeCount; i++)
			{
				int num = loop.Edges[i];
				Index2i edgeV = Mesh.GetEdgeV(num);
				if (hashSet.Contains(edgeV.a) && hashSet.Contains(edgeV.b))
				{
					list.Add(num);
					continue;
				}
				int num2 = edgeV.a;
				int num3 = edgeV.b;
				Vector3d zero = Vector3d.Zero;
				if (!hashSet.Contains(edgeV.b))
				{
					zero = ((!hashSet.Contains(edgeV.a)) ? (0.5 * (Mesh.GetVertex(edgeV.a) + Mesh.GetVertex(edgeV.b))) : Mesh.GetVertex(edgeV.a));
				}
				else
				{
					num2 = edgeV.b;
					num3 = edgeV.a;
					zero = Mesh.GetVertex(edgeV.b);
				}
				if (MeshUtil.CheckIfCollapseCreatesFlip(Mesh, num, zero))
				{
					list.Add(num);
					continue;
				}
				Index4i edge = Mesh.GetEdge(num);
				int vB = IndexUtil.find_tri_other_vtx(num2, num3, Mesh.GetTriangle(edge.c));
				int vB2 = IndexUtil.find_tri_other_vtx(num2, num3, Mesh.GetTriangle(edge.d));
				int item = Mesh.FindEdge(num3, vB);
				int item2 = Mesh.FindEdge(num3, vB2);
				DMesh3.EdgeCollapseInfo collapse;
				if (OnCutEdges.Contains(item) || OnCutEdges.Contains(item2))
				{
					list.Add(num);
				}
				else if (Mesh.CollapseEdge(num2, num3, out collapse) == MeshResult.Ok)
				{
					Mesh.SetVertex(collapse.vKept, zero);
					OnCutEdges.Remove(collapse.eCollapsed);
				}
				else
				{
					list.Add(num);
				}
			}
			return EdgeLoop.FromEdges(Mesh, list);
		}

		private void find_cut_paths(HashSet<int> CutEdges)
		{
			Spans = new List<EdgeSpan>();
			Loops = new List<EdgeLoop>();
			HashSet<int> hashSet = new HashSet<int>(CutEdges);
			while (hashSet.Count > 0)
			{
				int num = hashSet.First();
				hashSet.Remove(num);
				Index2i edgeV = Mesh.GetEdgeV(num);
				bool bClosedLoop;
				List<int> list = walk_edge_span_forward(Mesh, num, edgeV.a, hashSet, out bClosedLoop);
				if (!bClosedLoop)
				{
					List<int> list2 = walk_edge_span_forward(Mesh, num, edgeV.b, hashSet, out bClosedLoop);
					if (bClosedLoop)
					{
						throw new Exception("find_cut_paths: how did this possibly happen?!?");
					}
					if (list2.Count > 1)
					{
						list2.Reverse();
						list2.RemoveAt(list2.Count - 1);
						list2.AddRange(list);
						Index2i ev = Mesh.GetEdgeV(list2[0]);
						Index2i ev2 = Mesh.GetEdgeV(list2[list2.Count - 1]);
						bClosedLoop = list2.Count > 2 && IndexUtil.find_shared_edge_v(ref ev, ref ev2) != -1;
						list = list2;
					}
				}
				if (bClosedLoop)
				{
					EdgeLoop item = EdgeLoop.FromEdges(Mesh, list);
					Loops.Add(item);
				}
				else
				{
					EdgeSpan item2 = EdgeSpan.FromEdges(Mesh, list);
					Spans.Add(item2);
				}
			}
		}

		private static List<int> walk_edge_span_forward(DMesh3 mesh, int start_edge, int start_pivot_v, HashSet<int> EdgeSet, out bool bClosedLoop)
		{
			bClosedLoop = false;
			List<int> list = new List<int>();
			list.Add(start_edge);
			int num = start_pivot_v;
			int num2 = IndexUtil.find_edge_other_v(mesh.GetEdgeV(start_edge), start_pivot_v);
			bool flag = false;
			while (!flag)
			{
				int num3 = -1;
				foreach (int item in mesh.VtxEdgesItr(num))
				{
					if (EdgeSet.Contains(item))
					{
						num3 = item;
						break;
					}
				}
				if (num3 == -1)
				{
					flag = true;
					break;
				}
				Index2i edgeV = mesh.GetEdgeV(num3);
				if (edgeV.a == num)
				{
					num = edgeV.b;
				}
				else
				{
					if (edgeV.b != num)
					{
						throw new Exception("walk_edge_span_forward: found valid next edge but not connected to previous vertex??");
					}
					num = edgeV.a;
				}
				list.Add(num3);
				EdgeSet.Remove(num3);
				if (num == num2)
				{
					flag = true;
					bClosedLoop = true;
				}
			}
			return list;
		}
	}
	public class MeshIsoCurves
	{
		public enum RootfindingModes
		{
			SingleLerp,
			LerpSteps,
			Bisection
		}

		public enum TriangleCase
		{
			EdgeEdge = 1,
			EdgeVertex,
			OnEdge
		}

		public struct GraphEdgeInfo
		{
			public TriangleCase caseType;

			public int mesh_tri;

			public Index2i mesh_edges;

			public Index2i order;
		}

		public DMesh3 Mesh;

		public Func<Vector3d, double> ValueF;

		public Func<int, double> VertexValueF;

		public bool PrecomputeVertexValues;

		public RootfindingModes RootMode;

		public int RootModeSteps = 5;

		public DGraph3 Graph;

		public bool WantGraphEdgeInfo;

		public DVector<GraphEdgeInfo> GraphEdges;

		private Dictionary<int, Vector3d> EdgeLocations = new Dictionary<int, Vector3d>();

		private Dictionary<Vector3d, int> Vertices;

		public MeshIsoCurves(DMesh3 mesh, Func<Vector3d, double> valueF)
		{
			Mesh = mesh;
			ValueF = valueF;
		}

		public void Compute()
		{
			compute_full(Mesh.TriangleIndices(), bIsFullMeshHint: true);
		}

		public void Compute(IEnumerable<int> Triangles)
		{
			compute_full(Triangles);
		}

		protected void compute_full(IEnumerable<int> Triangles, bool bIsFullMeshHint = false)
		{
			Graph = new DGraph3();
			if (WantGraphEdgeInfo)
			{
				GraphEdges = new DVector<GraphEdgeInfo>();
			}
			Vertices = new Dictionary<Vector3d, int>();
			double[] vertex_values = null;
			if (PrecomputeVertexValues)
			{
				vertex_values = new double[Mesh.MaxVertexID];
				IEnumerable<int> source = Mesh.VertexIndices();
				if (!bIsFullMeshHint)
				{
					MeshVertexSelection meshVertexSelection = new MeshVertexSelection(Mesh);
					meshVertexSelection.SelectTriangleVertices(Triangles);
					source = meshVertexSelection;
				}
				gParallel.ForEach(source, delegate(int vid)
				{
					vertex_values[vid] = ValueF(Mesh.GetVertex(vid));
				});
				VertexValueF = (int vid) => vertex_values[vid];
			}
			foreach (int Triangle in Triangles)
			{
				Vector3dTuple3 vector3dTuple = default(Vector3dTuple3);
				Mesh.GetTriVertices(Triangle, ref vector3dTuple.V0, ref vector3dTuple.V1, ref vector3dTuple.V2);
				Index3i triangle = Mesh.GetTriangle(Triangle);
				Vector3d vector3d = ((VertexValueF != null) ? new Vector3d(VertexValueF(triangle.a), VertexValueF(triangle.b), VertexValueF(triangle.c)) : new Vector3d(ValueF(vector3dTuple.V0), ValueF(vector3dTuple.V1), ValueF(vector3dTuple.V2)));
				if ((vector3d.x < 0.0 && vector3d.y < 0.0 && vector3d.z < 0.0) || (vector3d.x > 0.0 && vector3d.y > 0.0 && vector3d.z > 0.0))
				{
					continue;
				}
				Index3i triEdges = Mesh.GetTriEdges(Triangle);
				if (vector3d.x * vector3d.y * vector3d.z == 0.0)
				{
					int num = ((vector3d.x != 0.0) ? ((vector3d.y == 0.0) ? 1 : 2) : 0);
					int num2 = (num + 1) % 3;
					int num3 = (num + 2) % 3;
					if (vector3d[num2] * vector3d[num3] > 0.0)
					{
						continue;
					}
					if (vector3d[num2] == 0.0 || vector3d[num3] == 0.0)
					{
						int num4 = ((vector3d[num2] == 0.0) ? num2 : num3);
						if ((num + 1) % 3 != num4)
						{
							int num5 = num;
							num = num4;
							num4 = num5;
						}
						int num6 = add_or_append_vertex(Mesh.GetVertex(triangle[num]));
						int num7 = add_or_append_vertex(Mesh.GetVertex(triangle[num4]));
						int num8 = Graph.AppendEdge(num6, num7, 3);
						if (num8 >= 0 && WantGraphEdgeInfo)
						{
							add_on_edge(num8, Triangle, triEdges[num], new Index2i(num6, num7));
						}
						continue;
					}
					int num9 = add_or_append_vertex(Mesh.GetVertex(triangle[num]));
					int num10 = num2;
					int num11 = num3;
					if (triangle[num11] < triangle[num10])
					{
						int num12 = num10;
						num10 = num11;
						num11 = num12;
					}
					Vector3d vector3d2 = find_crossing(vector3dTuple[num10], vector3dTuple[num11], vector3d[num10], vector3d[num11]);
					int num13 = add_or_append_vertex(vector3d2);
					add_edge_pos(triangle[num10], triangle[num11], vector3d2);
					if (num9 != num13)
					{
						int num14 = Graph.AppendEdge(num9, num13, 2);
						if (num14 >= 0 && WantGraphEdgeInfo)
						{
							add_edge_vert(num14, Triangle, triEdges[(num + 1) % 3], triangle[num], new Index2i(num9, num13));
						}
					}
					continue;
				}
				Index3i min = Index3i.Min;
				int num15 = 0;
				for (int num16 = 0; num16 < 3; num16++)
				{
					int num17 = num16;
					int num18 = (num16 + 1) % 3;
					if (vector3d[num17] < 0.0)
					{
						num15++;
					}
					if (!(vector3d[num17] * vector3d[num18] > 0.0))
					{
						if (triangle[num18] < triangle[num17])
						{
							int num19 = num17;
							num17 = num18;
							num18 = num19;
						}
						Vector3d vector3d3 = find_crossing(vector3dTuple[num17], vector3dTuple[num18], vector3d[num17], vector3d[num18]);
						min[num16] = add_or_append_vertex(vector3d3);
						add_edge_pos(triangle[num17], triangle[num18], vector3d3);
					}
				}
				int num20 = ((min.a == int.MinValue) ? 1 : 0);
				int num21 = ((min.c == int.MinValue) ? 1 : 2);
				if (num20 == 0 && num21 == 2)
				{
					num20 = 2;
					num21 = 0;
				}
				if (num15 == 1)
				{
					int num22 = num20;
					num20 = num21;
					num21 = num22;
				}
				int num23 = min[num20];
				int num24 = min[num21];
				if (num23 != num24)
				{
					int num25 = Graph.AppendEdge(num23, num24, 1);
					if (num25 >= 0 && WantGraphEdgeInfo)
					{
						add_edge_edge(num25, Triangle, new Index2i(triEdges[num20], triEdges[num21]), new Index2i(num23, num24));
					}
				}
			}
			Vertices = null;
		}

		private int add_or_append_vertex(Vector3d pos)
		{
			if (!Vertices.TryGetValue(pos, out var value))
			{
				value = Graph.AppendVertex(pos);
				Vertices.Add(pos, value);
			}
			return value;
		}

		private void add_edge_edge(int graph_eid, int mesh_tri, Index2i mesh_edges, Index2i order)
		{
			GraphEdgeInfo value = new GraphEdgeInfo
			{
				caseType = TriangleCase.EdgeEdge,
				mesh_edges = mesh_edges,
				mesh_tri = mesh_tri,
				order = order
			};
			GraphEdges.insertAt(value, graph_eid);
		}

		private void add_edge_vert(int graph_eid, int mesh_tri, int mesh_edge, int mesh_vert, Index2i order)
		{
			GraphEdgeInfo value = new GraphEdgeInfo
			{
				caseType = TriangleCase.EdgeVertex,
				mesh_edges = new Index2i(mesh_edge, mesh_vert),
				mesh_tri = mesh_tri,
				order = order
			};
			GraphEdges.insertAt(value, graph_eid);
		}

		private void add_on_edge(int graph_eid, int mesh_tri, int mesh_edge, Index2i order)
		{
			GraphEdgeInfo value = new GraphEdgeInfo
			{
				caseType = TriangleCase.OnEdge,
				mesh_edges = new Index2i(mesh_edge, -1),
				mesh_tri = mesh_tri,
				order = order
			};
			GraphEdges.insertAt(value, graph_eid);
		}

		private Vector3d find_crossing(Vector3d a, Vector3d b, double fA, double fB)
		{
			if (fB < fA)
			{
				Vector3d vector3d = a;
				a = b;
				b = vector3d;
				double num = fA;
				fA = fB;
				fB = num;
			}
			if (RootMode == RootfindingModes.Bisection)
			{
				for (int i = 0; i < RootModeSteps; i++)
				{
					Vector3d vector3d2 = Vector3d.Lerp(a, b, 0.5);
					double num2 = ValueF(vector3d2);
					if (num2 < 0.0)
					{
						fA = num2;
						a = vector3d2;
					}
					else
					{
						fB = num2;
						b = vector3d2;
					}
				}
				return Vector3d.Lerp(a, b, 0.5);
			}
			if (Math.Abs(fB - fA) < 1E-08)
			{
				return a;
			}
			double num3 = 0.0;
			if (RootMode == RootfindingModes.LerpSteps)
			{
				for (int j = 0; j < RootModeSteps; j++)
				{
					num3 = MathUtil.Clamp((0.0 - fA) / (fB - fA), 0.0, 1.0);
					Vector3d vector3d3 = (1.0 - num3) * a + num3 * b;
					double num4 = ValueF(vector3d3);
					if (num4 < 0.0)
					{
						fA = num4;
						a = vector3d3;
					}
					else
					{
						fB = num4;
						b = vector3d3;
					}
				}
			}
			num3 = MathUtil.Clamp((0.0 - fA) / (fB - fA), 0.0, 1.0);
			return (1.0 - num3) * a + num3 * b;
		}

		private void add_edge_pos(int a, int b, Vector3d crossing_pos)
		{
			int num = Mesh.FindEdge(a, b);
			if (num == -1)
			{
				throw new Exception("MeshIsoCurves.add_edge_split: invalid edge?");
			}
			if (!EdgeLocations.ContainsKey(num))
			{
				EdgeLocations[num] = crossing_pos;
			}
		}

		public void SplitAtIsoCrossings(double min_len = 0.0)
		{
			foreach (KeyValuePair<int, Vector3d> edgeLocation in EdgeLocations)
			{
				int key = edgeLocation.Key;
				Vector3d value = edgeLocation.Value;
				if (!Mesh.IsEdge(key))
				{
					continue;
				}
				Index2i edgeV = Mesh.GetEdgeV(key);
				Vector3d vertex = Mesh.GetVertex(edgeV.a);
				Vector3d vertex2 = Mesh.GetVertex(edgeV.b);
				if (!(vertex.Distance(vertex2) < min_len))
				{
					Vector3d v = (vertex + vertex2) * 0.5;
					if (!(vertex.Distance(v) < min_len) && !(vertex2.Distance(v) < min_len) && Mesh.SplitEdge(key, out var split) == MeshResult.Ok)
					{
						Mesh.SetVertex(split.vNew, value);
					}
				}
			}
		}

		public bool ShouldReverseGraphEdge(int graph_eid)
		{
			if (GraphEdges == null)
			{
				throw new Exception("MeshIsoCurves.OrientEdge: must track edge graph info to orient edge");
			}
			Index2i edgeV = Graph.GetEdgeV(graph_eid);
			GraphEdgeInfo graphEdgeInfo = GraphEdges[graph_eid];
			if (edgeV.b == graphEdgeInfo.order.a && edgeV.a == graphEdgeInfo.order.b)
			{
				return true;
			}
			return false;
		}
	}
	public class MeshIterativeSmooth
	{
		public enum SmoothTypes
		{
			Uniform,
			Cotan,
			MeanValue
		}

		public DMesh3 Mesh;

		public int[] Vertices;

		public double Alpha = 0.25;

		public int Rounds = 10;

		public SmoothTypes SmoothType;

		public Func<Vector3d, Vector3f, int, Vector3d> ProjectF;

		private Vector3d[] SmoothedPostions;

		public MeshIterativeSmooth(DMesh3 mesh, int[] vertices, bool bOwnVertices = false)
		{
			Mesh = mesh;
			Vertices = (bOwnVertices ? vertices : ((int[])vertices.Clone()));
			SmoothedPostions = new Vector3d[Vertices.Length];
			ProjectF = null;
		}

		public virtual ValidationStatus Validate()
		{
			return ValidationStatus.Ok;
		}

		public virtual bool Smooth()
		{
			int num = Vertices.Length;
			double a = MathUtil.Clamp(Alpha, 0.0, 1.0);
			double num2 = MathUtil.Clamp(Rounds, 0, 10000);
			Func<DMesh3, int, double, Vector3d> smoothFunc = MeshUtil.UniformSmooth;
			if (SmoothType == SmoothTypes.MeanValue)
			{
				smoothFunc = MeshUtil.MeanValueSmooth;
			}
			else if (SmoothType == SmoothTypes.Cotan)
			{
				smoothFunc = MeshUtil.CotanSmooth;
			}
			Action<int> body = delegate(int i)
			{
				int arg = Vertices[i];
				SmoothedPostions[i] = smoothFunc(Mesh, arg, a);
			};
			Action<int> body2 = delegate(int i)
			{
				Vector3d arg = SmoothedPostions[i];
				SmoothedPostions[i] = ProjectF(arg, Vector3f.AxisY, Vertices[i]);
			};
			IndexRangeEnumerator source = new IndexRangeEnumerator(0, num);
			for (int num3 = 0; (double)num3 < num2; num3++)
			{
				gParallel.ForEach(source, body);
				if (ProjectF != null)
				{
					gParallel.ForEach(source, body2);
				}
				for (int num4 = 0; num4 < num; num4++)
				{
					Mesh.SetVertex(Vertices[num4], SmoothedPostions[num4]);
				}
			}
			return true;
		}
	}
	public class MeshLocalParam
	{
		public enum UVModes
		{
			ExponentialMap,
			ExponentialMap_UpwindAvg,
			PlanarProjection
		}

		private class GraphNode : DynamicPriorityQueueNode, IEquatable<GraphNode>
		{
			public int id;

			public GraphNode parent;

			public float graph_distance;

			public Vector2f uv;

			public bool frozen;

			public bool Equals(GraphNode other)
			{
				return id == other.id;
			}
		}

		public static readonly Vector2f InvalidUV = new Vector2f(float.MaxValue, float.MaxValue);

		public UVModes UVMode = UVModes.ExponentialMap_UpwindAvg;

		private DynamicPriorityQueue<GraphNode> SparseQueue;

		private SparseObjectList<GraphNode> SparseNodes;

		private MemoryPool<GraphNode> SparseNodePool;

		private Func<int, Vector3f> PositionF;

		private Func<int, Vector3f> NormalF;

		private Func<int, IEnumerable<int>> NeighboursF;

		private Frame3f SeedFrame;

		private float max_graph_distance;

		private float max_uv_distance;

		public float MaxGraphDistance => max_graph_distance;

		public float MaxUVDistance => max_uv_distance;

		public MeshLocalParam(int nMaxID, Func<int, Vector3f> nodePositionF, Func<int, Vector3f> nodeNormalF, Func<int, IEnumerable<int>> neighboursF)
		{
			PositionF = nodePositionF;
			NormalF = nodeNormalF;
			NeighboursF = neighboursF;
			SparseQueue = new DynamicPriorityQueue<GraphNode>();
			SparseNodes = new SparseObjectList<GraphNode>(nMaxID, 0);
			SparseNodePool = new MemoryPool<GraphNode>();
			max_graph_distance = float.MinValue;
			max_uv_distance = float.MinValue;
		}

		public void Reset()
		{
			SparseQueue.Clear(bFreeMemory: false);
			SparseNodes.Clear();
			SparseNodePool.ReturnAll();
			max_graph_distance = float.MinValue;
		}

		public void ComputeToMaxDistance(Frame3f seedFrame, Index3i seedNbrs, float fMaxGraphDistance)
		{
			SeedFrame = seedFrame;
			for (int i = 0; i < 3; i++)
			{
				int num = seedNbrs[i];
				GraphNode graphNode = get_node(num);
				graphNode.uv = compute_local_uv(ref SeedFrame, PositionF(num));
				graphNode.graph_distance = graphNode.uv.Length;
				graphNode.frozen = true;
				SparseQueue.Enqueue(graphNode, graphNode.graph_distance);
			}
			while (SparseQueue.Count > 0)
			{
				GraphNode graphNode2 = SparseQueue.Dequeue();
				max_graph_distance = Math.Max(graphNode2.graph_distance, max_graph_distance);
				if (max_graph_distance > fMaxGraphDistance)
				{
					return;
				}
				if (graphNode2.parent != null)
				{
					switch (UVMode)
					{
					case UVModes.ExponentialMap:
						update_uv_expmap(graphNode2);
						break;
					case UVModes.ExponentialMap_UpwindAvg:
						update_uv_upwind_expmap(graphNode2);
						break;
					case UVModes.PlanarProjection:
						update_uv_planar(graphNode2);
						break;
					}
				}
				float lengthSquared = graphNode2.uv.LengthSquared;
				if (lengthSquared > max_uv_distance)
				{
					max_uv_distance = lengthSquared;
				}
				graphNode2.frozen = true;
				update_neighbours_sparse(graphNode2);
			}
			max_uv_distance = (float)Math.Sqrt(max_uv_distance);
		}

		public void TransformUV(float fScale, Vector2f vTranslate)
		{
			foreach (KeyValuePair<int, GraphNode> item in SparseNodes.NonZeroValues())
			{
				GraphNode value = item.Value;
				if (value.frozen)
				{
					value.uv = value.uv * fScale + vTranslate;
				}
			}
		}

		public Vector2f GetUV(int id)
		{
			return SparseNodes[id]?.uv ?? InvalidUV;
		}

		public void ApplyUVs(Action<int, Vector2f> applyF)
		{
			foreach (KeyValuePair<int, GraphNode> item in SparseNodes.NonZeroValues())
			{
				GraphNode value = item.Value;
				if (value.frozen)
				{
					applyF(value.id, value.uv);
				}
			}
		}

		private Vector2f compute_local_uv(ref Frame3f f, Vector3f pos)
		{
			pos -= f.Origin;
			return new Vector2f(pos.Dot(f.X), pos.Dot(f.Y));
		}

		private Vector2f propagate_uv(Vector3f pos, Vector2f nbrUV, ref Frame3f fNbr, ref Frame3f fSeed)
		{
			Vector2f vector2f = compute_local_uv(ref fNbr, pos);
			Frame3f frame3f = fSeed;
			frame3f.AlignAxis(2, fNbr.Z);
			Vector3f x = frame3f.X;
			Vector3f x2 = fNbr.X;
			float num = x2.Dot(x);
			float num2 = 1f - num * num;
			if (num2 < 0f)
			{
				num2 = 0f;
			}
			float num3 = (float)Math.Sqrt(num2);
			if (x2.Cross(x).Dot(fNbr.Z) < 0f)
			{
				num3 = 0f - num3;
			}
			Matrix2f matrix2f = new Matrix2f(num, num3, 0f - num3, num);
			return nbrUV + matrix2f * vector2f;
		}

		private void update_uv_expmap(GraphNode node)
		{
			int id = node.id;
			int id2 = node.parent.id;
			Vector3f origin = PositionF(id2);
			Frame3f fNbr = new Frame3f(origin, NormalF(id2));
			node.uv = propagate_uv(PositionF(id), node.parent.uv, ref fNbr, ref SeedFrame);
		}

		private void update_uv_upwind_expmap(GraphNode node)
		{
			int id = node.id;
			Vector3f pos = PositionF(id);
			Vector2f zero = Vector2f.Zero;
			float num = 0f;
			int num2 = 0;
			foreach (int item in NeighboursF(node.id))
			{
				GraphNode graphNode = get_node(item, bCreateIfMissing: false);
				if (graphNode.frozen)
				{
					Vector3f vector3f = PositionF(item);
					Frame3f fNbr = new Frame3f(vector3f, NormalF(item));
					Vector2f vector2f = propagate_uv(pos, graphNode.uv, ref fNbr, ref SeedFrame);
					float num3 = 1f / (pos.DistanceSquared(vector3f) + 1E-06f);
					zero += num3 * vector2f;
					num += num3;
					num2++;
				}
			}
			zero /= num;
			node.uv = zero;
		}

		private void update_uv_planar(GraphNode g)
		{
			g.uv = compute_local_uv(ref SeedFrame, PositionF(g.id));
		}

		private GraphNode get_node(int id, bool bCreateIfMissing = true)
		{
			GraphNode graphNode = SparseNodes[id];
			if (graphNode == null)
			{
				graphNode = SparseNodePool.Allocate();
				graphNode.id = id;
				graphNode.parent = null;
				graphNode.frozen = false;
				graphNode.uv = Vector2f.Zero;
				graphNode.graph_distance = float.MaxValue;
				SparseNodes[id] = graphNode;
			}
			return graphNode;
		}

		private void update_neighbours_sparse(GraphNode parent)
		{
			Vector3f vector3f = PositionF(parent.id);
			float graph_distance = parent.graph_distance;
			foreach (int item in NeighboursF(parent.id))
			{
				GraphNode graphNode = get_node(item);
				if (graphNode.frozen)
				{
					continue;
				}
				float num = graph_distance + vector3f.Distance(PositionF(item));
				if (SparseQueue.Contains(graphNode))
				{
					if (num < graphNode.priority)
					{
						graphNode.parent = parent;
						graphNode.graph_distance = num;
						SparseQueue.Update(graphNode, graphNode.graph_distance);
					}
				}
				else
				{
					graphNode.parent = parent;
					graphNode.graph_distance = num;
					SparseQueue.Enqueue(graphNode, graphNode.graph_distance);
				}
			}
		}
	}
	public class MeshLoopClosure
	{
		public DMesh3 Mesh;

		public EdgeLoop InitialBorderLoop;

		public Frame3f FlatClosePlane;

		public double TargetEdgeLen;

		public int ExtrudeGroup = -1;

		public int FillGroup = -1;

		public MeshLoopClosure(DMesh3 mesh, EdgeLoop border_loop)
		{
			Mesh = mesh;
			InitialBorderLoop = border_loop;
		}

		public virtual ValidationStatus Validate()
		{
			ValidationStatus validationStatus = MeshValidation.IsBoundaryLoop(Mesh, InitialBorderLoop);
			if (validationStatus != ValidationStatus.Ok)
			{
				return validationStatus;
			}
			ValidationStatus validationStatus2 = MeshValidation.HasDuplicateTriangles(Mesh);
			if (validationStatus2 != ValidationStatus.Ok)
			{
				return validationStatus2;
			}
			return ValidationStatus.Ok;
		}

		public virtual bool Close()
		{
			Close_Flat();
			return true;
		}

		public void Close_Flat()
		{
			MeshQueries.EdgeLengthStats(Mesh, out var _, out var _, out var avgEdgeLen, 1000);
			double num = ((TargetEdgeLen <= 0.0) ? avgEdgeLen : TargetEdgeLen);
			cleanup_boundary(Mesh, InitialBorderLoop, avgEdgeLen, out var result_edges);
			MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh);
			int num2 = meshBoundaryLoops.FindLoopContainingEdge(result_edges[0]);
			if (num2 == -1)
			{
				num2 = meshBoundaryLoops.MaxVerticesLoopIndex;
			}
			EdgeLoop loop = meshBoundaryLoops.Loops[num2];
			int num3 = ((ExtrudeGroup == -1) ? Mesh.AllocateTriangleGroup() : ExtrudeGroup);
			int group_id = ((FillGroup == -1) ? Mesh.AllocateTriangleGroup() : FillGroup);
			MeshExtrudeLoop meshExtrudeLoop = new MeshExtrudeLoop(Mesh, loop);
			meshExtrudeLoop.PositionF = (Vector3d v, Vector3f n, int i) => FlatClosePlane.ProjectToPlane((Vector3f)v, 1);
			meshExtrudeLoop.Extrude(num3);
			MeshValidation.IsBoundaryLoop(Mesh, meshExtrudeLoop.NewLoop);
			MeshLoopSmooth meshLoopSmooth = new MeshLoopSmooth(Mesh, meshExtrudeLoop.NewLoop);
			meshLoopSmooth.ProjectF = (Vector3d v, int i) => FlatClosePlane.ProjectToPlane((Vector3f)v, 1);
			meshLoopSmooth.Alpha = 0.5;
			meshLoopSmooth.Rounds = 100;
			meshLoopSmooth.Smooth();
			SimpleHoleFiller simpleHoleFiller = new SimpleHoleFiller(Mesh, meshExtrudeLoop.NewLoop);
			simpleHoleFiller.Fill(group_id);
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(Mesh);
			meshFaceSelection.Select(meshExtrudeLoop.NewTriangles);
			meshFaceSelection.Select(simpleHoleFiller.NewTriangles);
			meshFaceSelection.ExpandToOneRingNeighbours();
			meshFaceSelection.ExpandToOneRingNeighbours();
			meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			int[] regionTris = meshFaceSelection.ToArray();
			FaceGroupUtil.SetGroupToGroup(Mesh, num3, 0);
			RegionRemesher regionRemesher = new RegionRemesher(Mesh, regionTris);
			DCurveProjectionTarget target = new DCurveProjectionTarget(MeshUtil.ExtractLoopV(Mesh, meshExtrudeLoop.NewLoop.Vertices));
			int[] array = (int[])meshExtrudeLoop.NewLoop.Vertices.Clone();
			regionRemesher.Region.MapVerticesToSubmesh(array);
			MeshConstraintUtil.ConstrainVtxLoopTo(regionRemesher.Constraints, regionRemesher.Mesh, array, target);
			DMeshAABBTree3 dMeshAABBTree = new DMeshAABBTree3(Mesh);
			dMeshAABBTree.Build();
			MeshProjectionTarget projectionTarget = new MeshProjectionTarget(Mesh, dMeshAABBTree);
			regionRemesher.SetProjectionTarget(projectionTarget);
			if (true)
			{
				regionRemesher.Precompute();
				regionRemesher.EnableFlips = (regionRemesher.EnableSplits = (regionRemesher.EnableCollapses = true));
				regionRemesher.MinEdgeLength = num;
				regionRemesher.MaxEdgeLength = 2.0 * num;
				regionRemesher.EnableSmoothing = true;
				regionRemesher.SmoothSpeedT = 1.0;
				for (int num4 = 0; num4 < 40; num4++)
				{
					regionRemesher.BasicRemeshPass();
				}
				regionRemesher.SetProjectionTarget(null);
				regionRemesher.SmoothSpeedT = 0.25;
				for (int num5 = 0; num5 < 10; num5++)
				{
					regionRemesher.BasicRemeshPass();
				}
				regionRemesher.BackPropropagate();
			}
			smooth_region(Mesh, regionRemesher.Region.BaseBorderV, 3);
		}

		public static void smooth_region(DMesh3 mesh, IEnumerable<int> vertices, int nRings)
		{
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(mesh);
			meshFaceSelection.SelectVertexOneRings(vertices);
			for (int i = 0; i < nRings; i++)
			{
				meshFaceSelection.ExpandToOneRingNeighbours();
			}
			meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(mesh);
			meshVertexSelection.SelectTriangleVertices(meshFaceSelection.ToArray());
			MeshIterativeSmooth meshIterativeSmooth = new MeshIterativeSmooth(mesh, meshVertexSelection.ToArray(), bOwnVertices: true);
			meshIterativeSmooth.Alpha = 0.20000000298023224;
			meshIterativeSmooth.Rounds = 10;
			meshIterativeSmooth.Smooth();
		}

		public static void smooth_loop(DMesh3 mesh, EdgeLoop loop, int nRings)
		{
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(mesh);
			meshFaceSelection.SelectVertexOneRings(loop.Vertices);
			for (int i = 0; i < nRings; i++)
			{
				meshFaceSelection.ExpandToOneRingNeighbours();
			}
			meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(mesh);
			meshVertexSelection.SelectTriangleVertices(meshFaceSelection.ToArray());
			meshVertexSelection.Deselect(loop.Vertices);
			MeshLoopSmooth meshLoopSmooth = new MeshLoopSmooth(mesh, loop);
			meshLoopSmooth.Rounds = 1;
			MeshIterativeSmooth meshIterativeSmooth = new MeshIterativeSmooth(mesh, meshVertexSelection.ToArray(), bOwnVertices: true);
			meshIterativeSmooth.Rounds = 1;
			for (int j = 0; j < 10; j++)
			{
				meshLoopSmooth.Smooth();
				meshIterativeSmooth.Smooth();
			}
		}

		public static void cleanup_boundary(DMesh3 mesh, EdgeLoop loop, double target_edge_len, out List<int> result_edges, int nRings = 3)
		{
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(mesh);
			meshFaceSelection.SelectVertexOneRings(loop.Vertices);
			for (int i = 0; i < nRings; i++)
			{
				meshFaceSelection.ExpandToOneRingNeighbours();
			}
			meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			RegionRemesher regionRemesher = new RegionRemesher(mesh, meshFaceSelection.ToArray());
			int[] array = new int[loop.EdgeCount];
			Array.Copy(loop.Edges, array, loop.EdgeCount);
			regionRemesher.Region.MapEdgesToSubmesh(array);
			MeshConstraintUtil.AddTrackedEdges(regionRemesher.Constraints, array, 100);
			regionRemesher.Precompute();
			regionRemesher.EnableFlips = (regionRemesher.EnableSplits = (regionRemesher.EnableCollapses = true));
			regionRemesher.MinEdgeLength = target_edge_len;
			regionRemesher.MaxEdgeLength = 2.0 * target_edge_len;
			regionRemesher.EnableSmoothing = true;
			regionRemesher.SmoothSpeedT = 0.10000000149011612;
			for (int j = 0; j < nRings * 3; j++)
			{
				regionRemesher.BasicRemeshPass();
			}
			List<int> edges = regionRemesher.Constraints.FindConstrainedEdgesBySetID(100);
			regionRemesher.BackPropropagate();
			result_edges = MeshIndexUtil.MapEdgesViaVertexMap(regionRemesher.ReinsertSubToBaseMapV, regionRemesher.Region.SubMesh, regionRemesher.BaseMesh, edges);
		}
	}
	public class MeshLoopSmooth
	{
		public DMesh3 Mesh;

		public EdgeLoop Loop;

		public double Alpha = 0.25;

		public int Rounds = 10;

		public Func<Vector3d, int, Vector3d> ProjectF;

		private Vector3d[] SmoothedPostions;

		public MeshLoopSmooth(DMesh3 mesh, EdgeLoop loop)
		{
			Mesh = mesh;
			Loop = loop;
			SmoothedPostions = new Vector3d[Loop.Vertices.Length];
			ProjectF = null;
		}

		public virtual ValidationStatus Validate()
		{
			return MeshValidation.IsEdgeLoop(Mesh, Loop);
		}

		public virtual bool Smooth()
		{
			int NV = Loop.Vertices.Length;
			double a = MathUtil.Clamp(Alpha, 0.0, 1.0);
			double num = MathUtil.Clamp(Rounds, 0, 10000);
			for (int i = 0; (double)i < num; i++)
			{
				gParallel.ForEach(Interval1i.Range(NV), delegate(int num2)
				{
					int vID = Loop.Vertices[(num2 + 1) % NV];
					Vector3d vertex = Mesh.GetVertex(Loop.Vertices[num2]);
					Vector3d vertex2 = Mesh.GetVertex(vID);
					Vector3d vertex3 = Mesh.GetVertex(Loop.Vertices[(num2 + 2) % NV]);
					Vector3d vector3d = (vertex + vertex3) * 0.5;
					SmoothedPostions[num2] = (1.0 - a) * vertex2 + a * vector3d;
				});
				gParallel.ForEach(Interval1i.Range(NV), delegate(int num3)
				{
					int num2 = Loop.Vertices[(num3 + 1) % NV];
					Vector3d vector3d = SmoothedPostions[num3];
					if (ProjectF != null)
					{
						vector3d = ProjectF(vector3d, num2);
					}
					Mesh.SetVertex(num2, vector3d);
				});
			}
			return true;
		}
	}
	public class MeshMeshCut
	{
		private class SegmentVtx
		{
			public Vector3d v;

			public int type = -1;

			public int initial_type = -1;

			public int vtx_id = -1;

			public int elem_id = -1;
		}

		private class IntersectSegment
		{
			public int base_tid;

			public SegmentVtx v0;

			public SegmentVtx v1;

			public SegmentVtx this[int key]
			{
				get
				{
					if (key != 0)
					{
						return v1;
					}
					return v0;
				}
				set
				{
					if (key == 0)
					{
						v0 = value;
					}
					else
					{
						v1 = value;
					}
				}
			}
		}

		public DMesh3 Target;

		public DMesh3 CutMesh;

		private PointHashGrid3d<int> PointHash;

		public double VertexSnapTol = 1E-05;

		public List<int> CutVertices;

		private List<SegmentVtx> SegVertices;

		private Dictionary<int, SegmentVtx> VIDToSegVtxMap;

		private Dictionary<int, List<SegmentVtx>> FaceVertices;

		private Dictionary<int, List<SegmentVtx>> EdgeVertices;

		private IntersectSegment[] Segments;

		private Vector3d[] BaseFaceCentroids;

		private Vector3d[] BaseFaceNormals;

		private Dictionary<int, HashSet<int>> SubFaces;

		private Dictionary<int, int> ParentFaces;

		private HashSet<int> SegmentInsertVertices;

		public void Compute()
		{
			double cellSize = Target.CachedBounds.MaxDim / 64.0;
			PointHash = new PointHashGrid3d<int>(cellSize, -1);
			foreach (int item in Target.VertexIndices())
			{
				Vector3d vertex = Target.GetVertex(item);
				int num = find_existing_vertex(vertex);
				if (num != -1)
				{
					Console.WriteLine("VERTEX {0} IS DUPLICATE OF {1}!", item, num);
				}
				PointHash.InsertPointUnsafe(item, vertex);
			}
			initialize();
			find_segments();
			insert_face_vertices();
			insert_edge_vertices();
			connect_edges();
			foreach (SegmentVtx segVertex in SegVertices)
			{
				SegmentInsertVertices.Add(segVertex.vtx_id);
			}
		}

		public void RemoveContained()
		{
			DMeshAABBTree3 spatial = new DMeshAABBTree3(CutMesh, autoBuild: true);
			spatial.WindingNumber(Vector3d.Zero);
			SafeListBuilder<int> removeT = new SafeListBuilder<int>();
			gParallel.ForEach(Target.TriangleIndices(), delegate(int tid)
			{
				Vector3d triCentroid = Target.GetTriCentroid(tid);
				if (spatial.WindingNumber(triCentroid) > 0.9)
				{
					removeT.SafeAdd(tid);
				}
			});
			MeshEditor.RemoveTriangles(Target, removeT.Result);
			CutVertices = new List<int>();
			foreach (int segmentInsertVertex in SegmentInsertVertices)
			{
				if (Target.IsVertex(segmentInsertVertex))
				{
					CutVertices.Add(segmentInsertVertex);
				}
			}
		}

		public void AppendSegments(double r)
		{
			IntersectSegment[] segments = Segments;
			foreach (IntersectSegment intersectSegment in segments)
			{
				Segment3d seg = new Segment3d(intersectSegment.v0.v, intersectSegment.v1.v);
				if (Target.FindEdge(intersectSegment.v0.vtx_id, intersectSegment.v1.vtx_id) == -1)
				{
					MeshEditor.AppendLine(Target, seg, (float)r);
				}
			}
		}

		public void ColorFaces()
		{
			int num = 1;
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			foreach (int key in SubFaces.Keys)
			{
				dictionary[key] = num++;
			}
			Target.EnableTriangleGroups();
			foreach (int item in Target.TriangleIndices())
			{
				if (ParentFaces.ContainsKey(item))
				{
					Target.SetTriangleGroup(item, dictionary[ParentFaces[item]]);
				}
				else if (SubFaces.ContainsKey(item))
				{
					Target.SetTriangleGroup(item, dictionary[item]);
				}
			}
		}

		private void initialize()
		{
			BaseFaceCentroids = new Vector3d[Target.MaxTriangleID];
			BaseFaceNormals = new Vector3d[Target.MaxTriangleID];
			double fArea = 0.0;
			foreach (int item in Target.TriangleIndices())
			{
				Target.GetTriInfo(item, out BaseFaceNormals[item], out fArea, out BaseFaceCentroids[item]);
			}
			SegVertices = new List<SegmentVtx>();
			EdgeVertices = new Dictionary<int, List<SegmentVtx>>();
			FaceVertices = new Dictionary<int, List<SegmentVtx>>();
			SubFaces = new Dictionary<int, HashSet<int>>();
			ParentFaces = new Dictionary<int, int>();
			SegmentInsertVertices = new HashSet<int>();
			VIDToSegVtxMap = new Dictionary<int, SegmentVtx>();
		}

		private void find_segments()
		{
			Dictionary<Vector3d, SegmentVtx> dictionary = new Dictionary<Vector3d, SegmentVtx>();
			DMeshAABBTree3 dMeshAABBTree = new DMeshAABBTree3(Target, autoBuild: true);
			DMeshAABBTree3 otherTree = new DMeshAABBTree3(CutMesh, autoBuild: true);
			DMeshAABBTree3.IntersectionsQueryResult intersectionsQueryResult = dMeshAABBTree.FindAllIntersections(otherTree);
			Segments = new IntersectSegment[intersectionsQueryResult.Segments.Count];
			for (int i = 0; i < Segments.Length; i++)
			{
				DMeshAABBTree3.SegmentIntersection segmentIntersection = intersectionsQueryResult.Segments[i];
				Vector3dTuple2 vector3dTuple = new Vector3dTuple2(segmentIntersection.point0, segmentIntersection.point1);
				IntersectSegment intersectSegment = new IntersectSegment
				{
					base_tid = segmentIntersection.t0
				};
				Segments[i] = intersectSegment;
				for (int j = 0; j < 2; j++)
				{
					Vector3d v = vector3dTuple[j];
					if (dictionary.TryGetValue(v, out var value))
					{
						intersectSegment[j] = value;
						continue;
					}
					value = new SegmentVtx
					{
						v = v
					};
					SegVertices.Add(value);
					dictionary[v] = value;
					intersectSegment[j] = value;
					int num = find_existing_vertex(segmentIntersection.point0);
					if (num >= 0)
					{
						value.initial_type = (value.type = 0);
						value.elem_id = num;
						value.vtx_id = num;
						VIDToSegVtxMap[value.vtx_id] = value;
						continue;
					}
					Triangle3d tri = default(Triangle3d);
					Target.GetTriVertices(segmentIntersection.t0, ref tri.V0, ref tri.V1, ref tri.V2);
					Index3i triangle = Target.GetTriangle(segmentIntersection.t0);
					int num2 = on_edge(ref tri, ref v);
					if (num2 >= 0)
					{
						value.initial_type = (value.type = 1);
						value.elem_id = Target.FindEdge(triangle[num2], triangle[(num2 + 1) % 3]);
						add_edge_vtx(value.elem_id, value);
					}
					else
					{
						value.initial_type = (value.type = 2);
						value.elem_id = segmentIntersection.t0;
						add_face_vtx(value.elem_id, value);
					}
				}
			}
		}

		private void insert_face_vertices()
		{
			while (FaceVertices.Count > 0)
			{
				KeyValuePair<int, List<SegmentVtx>> keyValuePair = FaceVertices.First();
				int key = keyValuePair.Key;
				List<SegmentVtx> value = keyValuePair.Value;
				SegmentVtx segmentVtx = value[value.Count - 1];
				value.RemoveAt(value.Count - 1);
				if (Target.PokeTriangle(key, out var result) != MeshResult.Ok)
				{
					throw new Exception("shit");
				}
				int new_vid = result.new_vid;
				Target.SetVertex(new_vid, segmentVtx.v);
				segmentVtx.vtx_id = new_vid;
				VIDToSegVtxMap[segmentVtx.vtx_id] = segmentVtx;
				PointHash.InsertPoint(segmentVtx.vtx_id, segmentVtx.v);
				FaceVertices.Remove(key);
				Index3i new_edges = result.new_edges;
				Index3i pokeTris = new Index3i(key, result.new_t1, result.new_t2);
				foreach (SegmentVtx item in value)
				{
					update_from_poke(item, new_edges, pokeTris);
					if (item.type == 1)
					{
						add_edge_vtx(item.elem_id, item);
					}
					else if (item.type == 2)
					{
						add_face_vtx(item.elem_id, item);
					}
				}
				add_poke_subfaces(key, ref result);
			}
		}

		private void update_from_poke(SegmentVtx sv, Index3i pokeEdges, Index3i pokeTris)
		{
			int num = find_existing_vertex(sv.v);
			if (num >= 0)
			{
				sv.type = 0;
				sv.elem_id = num;
				sv.vtx_id = num;
				VIDToSegVtxMap[sv.vtx_id] = sv;
				return;
			}
			for (int i = 0; i < 3; i++)
			{
				if (is_on_edge(pokeEdges[i], sv.v))
				{
					sv.type = 1;
					sv.elem_id = pokeEdges[i];
					return;
				}
			}
			for (int j = 0; j < 3; j++)
			{
				if (is_in_triangle(pokeTris[j], sv.v))
				{
					sv.type = 2;
					sv.elem_id = pokeTris[j];
					return;
				}
			}
			Console.WriteLine("unsorted vertex!");
			sv.elem_id = pokeTris.a;
		}

		private void insert_edge_vertices()
		{
			while (EdgeVertices.Count > 0)
			{
				KeyValuePair<int, List<SegmentVtx>> keyValuePair = EdgeVertices.First();
				int key = keyValuePair.Key;
				List<SegmentVtx> value = keyValuePair.Value;
				SegmentVtx segmentVtx = value[value.Count - 1];
				value.RemoveAt(value.Count - 1);
				Index2i edgeT = Target.GetEdgeT(key);
				if (Target.SplitEdge(key, out var split) != MeshResult.Ok)
				{
					throw new Exception("insert_edge_vertices: split failed!");
				}
				int vNew = split.vNew;
				Index2i splitEdges = new Index2i(key, split.eNewBN);
				Target.SetVertex(vNew, segmentVtx.v);
				segmentVtx.vtx_id = vNew;
				VIDToSegVtxMap[segmentVtx.vtx_id] = segmentVtx;
				PointHash.InsertPoint(segmentVtx.vtx_id, segmentVtx.v);
				EdgeVertices.Remove(key);
				foreach (SegmentVtx item in value)
				{
					update_from_split(item, splitEdges);
					if (item.type == 1)
					{
						add_edge_vtx(item.elem_id, item);
					}
				}
				add_split_subfaces(edgeT, ref split);
			}
		}

		private void update_from_split(SegmentVtx sv, Index2i splitEdges)
		{
			int num = find_existing_vertex(sv.v);
			if (num >= 0)
			{
				sv.type = 0;
				sv.elem_id = num;
				sv.vtx_id = num;
				VIDToSegVtxMap[sv.vtx_id] = sv;
				return;
			}
			for (int i = 0; i < 2; i++)
			{
				if (is_on_edge(splitEdges[i], sv.v))
				{
					sv.type = 1;
					sv.elem_id = splitEdges[i];
					return;
				}
			}
			throw new Exception("update_from_split: unsortable vertex?");
		}

		private void connect_edges()
		{
			int num = Segments.Length;
			for (int i = 0; i < num; i++)
			{
				IntersectSegment intersectSegment = Segments[i];
				if (intersectSegment.v0 == intersectSegment.v1 || intersectSegment.v0.vtx_id == intersectSegment.v1.vtx_id)
				{
					continue;
				}
				int vtx_id = intersectSegment.v0.vtx_id;
				int vtx_id2 = intersectSegment.v1.vtx_id;
				if (vtx_id == -1 || vtx_id2 == -1)
				{
					throw new Exception("segment vertex is not defined?");
				}
				if (Target.FindEdge(vtx_id, vtx_id2) == -1)
				{
					try
					{
						insert_segment(intersectSegment);
					}
					catch (Exception)
					{
					}
				}
			}
		}

		private void insert_segment(IntersectSegment seg)
		{
			List<int> regionTris = get_all_baseface_tris(seg.base_tid);
			RegionOperator regionOperator = new RegionOperator(Target, regionTris);
			Vector3d n = BaseFaceNormals[seg.base_tid];
			Vector3d c = BaseFaceCentroids[seg.base_tid];
			Vector3d.MakePerpVectors(ref n, out var e0, out var e1);
			DMesh3 subMesh = regionOperator.Region.SubMesh;
			MeshTransforms.PerVertexTransform(subMesh, delegate(Vector3d vector3d)
			{
				vector3d -= c;
				return new Vector3d(vector3d.Dot(e0), vector3d.Dot(e1), 0.0);
			});
			Vector3d v = seg.v0.v;
			Vector3d v2 = seg.v1.v;
			v -= c;
			v2 -= c;
			Vector2d v3 = new Vector2d(v.Dot(e0), v.Dot(e1));
			Vector2d v4 = new Vector2d(v2.Dot(e0), v2.Dot(e1));
			PolyLine2d polyLine2d = new PolyLine2d();
			polyLine2d.AppendVertex(v3);
			polyLine2d.AppendVertex(v4);
			MeshInsertUVPolyCurve meshInsertUVPolyCurve = new MeshInsertUVPolyCurve(subMesh, polyLine2d);
			meshInsertUVPolyCurve.Apply();
			MeshVertexSelection meshVertexSelection = new MeshVertexSelection(subMesh);
			meshVertexSelection.SelectEdgeVertices(meshInsertUVPolyCurve.OnCutEdges);
			MeshTransforms.PerVertexTransform(subMesh, (Vector3d vector3d) => c + vector3d.x * e0 + vector3d.y * e1);
			regionOperator.BackPropropagate();
			foreach (int item in meshVertexSelection)
			{
				SegmentInsertVertices.Add(regionOperator.ReinsertSubToBaseMapV[item]);
			}
			add_regionop_subfaces(seg.base_tid, regionOperator);
		}

		private void add_edge_vtx(int eid, SegmentVtx vtx)
		{
			if (EdgeVertices.TryGetValue(eid, out var value))
			{
				value.Add(vtx);
				return;
			}
			value = new List<SegmentVtx> { vtx };
			EdgeVertices[eid] = value;
		}

		private void add_face_vtx(int tid, SegmentVtx vtx)
		{
			if (FaceVertices.TryGetValue(tid, out var value))
			{
				value.Add(vtx);
				return;
			}
			value = new List<SegmentVtx> { vtx };
			FaceVertices[tid] = value;
		}

		private void add_poke_subfaces(int tid, ref DMesh3.PokeTriangleInfo pokeInfo)
		{
			int num = get_parent(tid);
			HashSet<int> subfaces = get_subfaces(num);
			if (tid != num)
			{
				add_subface(subfaces, num, tid);
			}
			add_subface(subfaces, num, pokeInfo.new_t1);
			add_subface(subfaces, num, pokeInfo.new_t2);
		}

		private void add_split_subfaces(Index2i origTris, ref DMesh3.EdgeSplitInfo splitInfo)
		{
			int num = get_parent(origTris.a);
			HashSet<int> subfaces = get_subfaces(num);
			if (origTris.a != num)
			{
				add_subface(subfaces, num, origTris.a);
			}
			add_subface(subfaces, num, splitInfo.eNewT2);
			if (origTris.b != -1)
			{
				int num2 = get_parent(origTris.b);
				HashSet<int> subfaces2 = get_subfaces(num2);
				if (origTris.b != num2)
				{
					add_subface(subfaces2, num2, origTris.b);
				}
				add_subface(subfaces2, num2, splitInfo.eNewT3);
			}
		}

		private void add_regionop_subfaces(int parent, RegionOperator op)
		{
			HashSet<int> subfaces = get_subfaces(parent);
			int[] currentBaseTriangles = op.CurrentBaseTriangles;
			foreach (int num in currentBaseTriangles)
			{
				if (num != parent)
				{
					add_subface(subfaces, parent, num);
				}
			}
		}

		private int get_parent(int tid)
		{
			if (!ParentFaces.TryGetValue(tid, out var value))
			{
				return tid;
			}
			return value;
		}

		private HashSet<int> get_subfaces(int parent)
		{
			if (!SubFaces.TryGetValue(parent, out var value))
			{
				value = new HashSet<int>();
				SubFaces[parent] = value;
			}
			return value;
		}

		private void add_subface(HashSet<int> subfaces, int parent, int tid)
		{
			subfaces.Add(tid);
			ParentFaces[tid] = parent;
		}

		private List<int> get_all_baseface_tris(int base_tid)
		{
			return new List<int>(get_subfaces(base_tid)) { base_tid };
		}

		private bool is_inserted_free_edge(int eid)
		{
			Index2i edgeT = Target.GetEdgeT(eid);
			if (get_parent(edgeT.a) != get_parent(edgeT.b))
			{
				return false;
			}
			throw new Exception("not done yet!");
		}

		protected int on_edge(ref Triangle3d tri, ref Vector3d v)
		{
			if (new Segment3d(tri.V0, tri.V1).DistanceSquared(v) < VertexSnapTol * VertexSnapTol)
			{
				return 0;
			}
			if (new Segment3d(tri.V1, tri.V2).DistanceSquared(v) < VertexSnapTol * VertexSnapTol)
			{
				return 1;
			}
			if (new Segment3d(tri.V2, tri.V0).DistanceSquared(v) < VertexSnapTol * VertexSnapTol)
			{
				return 2;
			}
			return -1;
		}

		protected int on_edge_eid(int tid, Vector3d v)
		{
			Index3i triangle = Target.GetTriangle(tid);
			Triangle3d tri = default(Triangle3d);
			Target.GetTriVertices(tid, ref tri.V0, ref tri.V1, ref tri.V2);
			int num = on_edge(ref tri, ref v);
			if (num < 0)
			{
				return -1;
			}
			return Target.FindEdge(triangle[num], triangle[(num + 1) % 3]);
		}

		protected bool is_on_edge(int eid, Vector3d v)
		{
			Index2i edgeV = Target.GetEdgeV(eid);
			return new Segment3d(Target.GetVertex(edgeV.a), Target.GetVertex(edgeV.b)).DistanceSquared(v) < VertexSnapTol * VertexSnapTol;
		}

		protected bool is_in_triangle(int tid, Vector3d v)
		{
			Triangle3d triangle3d = default(Triangle3d);
			Target.GetTriVertices(tid, ref triangle3d.V0, ref triangle3d.V1, ref triangle3d.V2);
			Vector3d vector3d = triangle3d.BarycentricCoords(v);
			if (vector3d.x >= 0.0 && vector3d.y >= 0.0 && vector3d.z >= 0.0 && vector3d.x < 1.0 && vector3d.y <= 1.0)
			{
				return vector3d.z <= 1.0;
			}
			return false;
		}

		protected int find_existing_vertex(Vector3d pt)
		{
			return find_nearest_vertex(pt, VertexSnapTol);
		}

		protected int find_nearest_vertex(Vector3d pt, double searchRadius, int ignore_vid = -1)
		{
			KeyValuePair<int, double> keyValuePair = ((ignore_vid == -1) ? PointHash.FindNearestInRadius(pt, searchRadius, (int b) => pt.DistanceSquared(Target.GetVertex(b))) : PointHash.FindNearestInRadius(pt, searchRadius, (int b) => pt.DistanceSquared(Target.GetVertex(b)), (int vid) => vid == ignore_vid));
			if (keyValuePair.Key == PointHash.InvalidValue)
			{
				return -1;
			}
			return keyValuePair.Key;
		}
	}
	public struct SetGroupBehavior(SetGroupBehavior.Modes mode, int id = 0)
	{
		public enum Modes
		{
			Ignore,
			AutoGenerate,
			UseConstant
		}

		private Modes Mode = mode;

		private int SetGroupID = id;

		public static SetGroupBehavior Ignore => new SetGroupBehavior(Modes.Ignore);

		public static SetGroupBehavior AutoGenerate => new SetGroupBehavior(Modes.AutoGenerate);

		public int GetGroupID(DMesh3 mesh)
		{
			if (Mode == Modes.Ignore)
			{
				return -1;
			}
			if (Mode == Modes.AutoGenerate)
			{
				return mesh.AllocateTriangleGroup();
			}
			return SetGroupID;
		}

		public static SetGroupBehavior SetTo(int groupID)
		{
			return new SetGroupBehavior(Modes.UseConstant, groupID);
		}
	}
