	}
	public class MeshPlaneCut
	{
		public DMesh3 Mesh;

		public Vector3d PlaneOrigin;

		public Vector3d PlaneNormal;

		public bool CollapseDegenerateEdgesOnCut = true;

		public double DegenerateEdgeTol = 9.999999974752427E-07;

		public MeshFaceSelection CutFaceSet;

		public List<EdgeLoop> CutLoops;

		public List<EdgeSpan> CutSpans;

		public bool CutLoopsFailed;

		public bool FoundOpenSpans;

		public List<int[]> LoopFillTriangles;

		public MeshPlaneCut(DMesh3 mesh, Vector3d origin, Vector3d normal)
		{
			Mesh = mesh;
			PlaneOrigin = origin;
			PlaneNormal = normal;
		}

		public virtual ValidationStatus Validate()
		{
			return ValidationStatus.Ok;
		}

		public virtual bool Cut()
		{
			double invalidDist = double.MinValue;
			MeshEdgeSelection meshEdgeSelection = null;
			MeshVertexSelection meshVertexSelection = null;
			if (CutFaceSet != null)
			{
				meshEdgeSelection = new MeshEdgeSelection(Mesh, CutFaceSet);
				meshVertexSelection = new MeshVertexSelection(Mesh, meshEdgeSelection);
			}
			int maxVertexID = Mesh.MaxVertexID;
			double[] signs = new double[maxVertexID];
			gParallel.ForEach(Interval1i.Range(maxVertexID), delegate(int vid)
			{
				if (Mesh.IsVertex(vid))
				{
					Vector3d vertex = Mesh.GetVertex(vid);
					signs[vid] = (vertex - PlaneOrigin).Dot(PlaneNormal);
				}
				else
				{
					signs[vid] = invalidDist;
				}
			});
			HashSet<int> ZeroEdges = new HashSet<int>();
			HashSet<int> hashSet = new HashSet<int>();
			HashSet<int> OnCutEdges = new HashSet<int>();
			int maxEdgeID = Mesh.MaxEdgeID;
			HashSet<int> hashSet2 = new HashSet<int>();
			IEnumerable<int> enumerable = Interval1i.Range(maxEdgeID);
			if (meshEdgeSelection != null)
			{
				enumerable = meshEdgeSelection;
			}
			foreach (int item in enumerable)
			{
				if (!Mesh.IsEdge(item) || item >= maxEdgeID || hashSet2.Contains(item))
				{
					continue;
				}
				Index2i edgeV = Mesh.GetEdgeV(item);
				double num = signs[edgeV.a];
				double num2 = signs[edgeV.b];
				int num3 = ((Math.Abs(num) < 2.220446049250313E-16) ? 1 : 0);
				int num4 = ((Math.Abs(num2) < 2.220446049250313E-16) ? 1 : 0);
				if (num3 + num4 > 0)
				{
					if (num3 + num4 == 2)
					{
						ZeroEdges.Add(item);
					}
					else
					{
						hashSet.Add((num3 == 1) ? edgeV[0] : edgeV[1]);
					}
				}
				else if (!(num * num2 > 0.0))
				{
					if (Mesh.SplitEdge(item, out var split) != MeshResult.Ok)
					{
						throw new Exception("MeshPlaneCut.Cut: failed in SplitEdge");
					}
					double num5 = num / (num - num2);
					Vector3d vNewPos = (1.0 - num5) * Mesh.GetVertex(edgeV.a) + num5 * Mesh.GetVertex(edgeV.b);
					Mesh.SetVertex(split.vNew, vNewPos);
					hashSet2.Add(split.eNewBN);
					hashSet2.Add(split.eNewCN);
					OnCutEdges.Add(split.eNewCN);
					if (split.eNewDN != -1)
					{
						hashSet2.Add(split.eNewDN);
						OnCutEdges.Add(split.eNewDN);
					}
				}
			}
			IEnumerable<int> enumerable2 = Interval1i.Range(maxVertexID);
			if (meshVertexSelection != null)
			{
				enumerable2 = meshVertexSelection;
			}
			foreach (int item2 in enumerable2)
			{
				if (signs[item2] > 0.0 && Mesh.IsVertex(item2))
				{
					Mesh.RemoveVertex(item2);
				}
			}
			if (CollapseDegenerateEdgesOnCut)
			{
				collapse_degenerate_edges(OnCutEdges, ZeroEdges);
			}
			Func<int, bool> edgeFilterF = (int eid) => (OnCutEdges.Contains(eid) || ZeroEdges.Contains(eid)) ? true : false;
			try
			{
				MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh, bAutoCompute: false);
				meshBoundaryLoops.EdgeFilterF = edgeFilterF;
				meshBoundaryLoops.Compute();
				CutLoops = meshBoundaryLoops.Loops;
				CutSpans = meshBoundaryLoops.Spans;
				CutLoopsFailed = false;
				FoundOpenSpans = CutSpans.Count > 0;
			}
			catch
			{
				CutLoops = new List<EdgeLoop>();
				CutLoopsFailed = true;
			}
			return true;
		}

		protected void collapse_degenerate_edges(HashSet<int> OnCutEdges, HashSet<int> ZeroEdges)
		{
			HashSet<int>[] array = new HashSet<int>[2] { OnCutEdges, ZeroEdges };
			double num = DegenerateEdgeTol * DegenerateEdgeTol;
			Vector3d a = Vector3d.Zero;
			Vector3d b = Vector3d.Zero;
			int num2 = 0;
			do
			{
				num2 = 0;
				HashSet<int>[] array2 = array;
				for (int i = 0; i < array2.Length; i++)
				{
					foreach (int item in array2[i])
					{
						if (!Mesh.IsEdge(item))
						{
							continue;
						}
						Mesh.GetEdgeV(item, ref a, ref b);
						if (!(a.DistanceSquared(b) > num))
						{
							Index2i edgeV = Mesh.GetEdgeV(item);
							if (Mesh.CollapseEdge(edgeV.a, edgeV.b, out var _) == MeshResult.Ok)
							{
								num2++;
							}
						}
					}
				}
			}
			while (num2 != 0);
		}

		public bool FillHoles(int constantGroupID = -1)
		{
			bool result = true;
			LoopFillTriangles = new List<int[]>(CutLoops.Count);
			foreach (EdgeLoop cutLoop in CutLoops)
			{
				SimpleHoleFiller simpleHoleFiller = new SimpleHoleFiller(Mesh, cutLoop);
				int group_id = ((constantGroupID >= 0) ? constantGroupID : Mesh.AllocateTriangleGroup());
				if (simpleHoleFiller.Fill(group_id))
				{
					result = false;
					LoopFillTriangles.Add(simpleHoleFiller.NewTriangles);
				}
				else
				{
					LoopFillTriangles.Add(null);
				}
			}
			return result;
		}
	}
	public class MeshTrimLoop
	{
		public DMesh3 Mesh;

		public DMeshAABBTree3 Spatial;

		public DCurve3 TrimLine;

		public int RemeshBorderRings = 2;

		public double SmoothingAlpha = 1.0;

		public double TargetEdgeLength;

		public int RemeshRounds = 20;

		private int seed_tri = -1;

		private Vector3d seed_pt = Vector3d.MaxValue;

		public MeshTrimLoop(DMesh3 mesh, DCurve3 trimline, int tSeedTID, DMeshAABBTree3 spatial = null)
		{
			if (spatial != null && spatial.Mesh == mesh)
			{
				throw new ArgumentException("MeshTrimLoop: input spatial DS must have its own copy of mesh");
			}
			Mesh = mesh;
			TrimLine = new DCurve3(trimline);
			if (spatial != null)
			{
				Spatial = spatial;
			}
			seed_tri = tSeedTID;
		}

		public MeshTrimLoop(DMesh3 mesh, DCurve3 trimline, Vector3d vSeedPt, DMeshAABBTree3 spatial = null)
		{
			if (spatial != null && spatial.Mesh == mesh)
			{
				throw new ArgumentException("MeshTrimLoop: input spatial DS must have its own copy of mesh");
			}
			Mesh = mesh;
			TrimLine = new DCurve3(trimline);
			if (spatial != null)
			{
				Spatial = spatial;
			}
			seed_pt = vSeedPt;
		}

		public virtual ValidationStatus Validate()
		{
			return ValidationStatus.Ok;
		}

		public virtual bool Trim()
		{
			if (Spatial == null)
			{
				Spatial = new DMeshAABBTree3(new DMesh3(Mesh, bCompact: false, MeshComponents.None));
				Spatial.Build();
			}
			if (seed_tri == -1)
			{
				seed_tri = Spatial.FindNearestTriangle(seed_pt);
			}
			MeshFaceSelection meshFaceSelection = new MeshFacesFromLoop(Mesh, TrimLine, Spatial, seed_tri).ToSelection();
			meshFaceSelection.LocalOptimize(bClipFins: true, bFillEars: true);
			MeshEditor meshEditor = new MeshEditor(Mesh);
			meshEditor.RemoveTriangles(meshFaceSelection, bRemoveIsolatedVerts: true);
			MeshConnectedComponents meshConnectedComponents = new MeshConnectedComponents(Mesh);
			meshConnectedComponents.FindConnectedT();
			if (meshConnectedComponents.Count > 1)
			{
				int largestByCount = meshConnectedComponents.LargestByCount;
				for (int i = 0; i < meshConnectedComponents.Count; i++)
				{
					if (i != largestByCount)
					{
						meshEditor.RemoveTriangles(meshConnectedComponents[i].Indices, bRemoveIsolatedVerts: true);
					}
				}
			}
			meshEditor.RemoveAllBowtieVertices(bRepeatUntilClean: true);
			MeshBoundaryLoops meshBoundaryLoops = new MeshBoundaryLoops(Mesh);
			bool flag = false;
			try
			{
				flag = meshBoundaryLoops.Compute();
			}
			catch (Exception)
			{
				return false;
			}
			if (!flag)
			{
				return false;
			}
			if (meshBoundaryLoops.Count > 1)
			{
				return false;
			}
			int[] vertices = meshBoundaryLoops[0].Vertices;
			MeshFaceSelection meshFaceSelection2 = new MeshFaceSelection(Mesh);
			meshFaceSelection2.SelectVertexOneRings(vertices);
			meshFaceSelection2.ExpandToOneRingNeighbours(RemeshBorderRings);
			RegionRemesher regionRemesher = new RegionRemesher(Mesh, meshFaceSelection2.ToArray());
			regionRemesher.Region.MapVerticesToSubmesh(vertices);
			double num = TargetEdgeLength;
			if (num <= 0.0)
			{
				MeshQueries.EdgeLengthStatsFromEdges(Mesh, meshBoundaryLoops[0].Edges, out var _, out var _, out var avgEdgeLen);
				num = avgEdgeLen;
			}
			MeshProjectionTarget meshProjectionTarget = new MeshProjectionTarget(Spatial.Mesh, Spatial);
			regionRemesher.SetProjectionTarget(meshProjectionTarget);
			regionRemesher.SetTargetEdgeLength(num);
			regionRemesher.SmoothSpeedT = SmoothingAlpha;
			DCurveProjectionTarget dCurveProjectionTarget = new DCurveProjectionTarget(TrimLine);
			SequentialProjectionTarget target = new SequentialProjectionTarget(dCurveProjectionTarget, meshProjectionTarget);
			int setID = 3;
			MeshConstraintUtil.ConstrainVtxLoopTo(regionRemesher, vertices, target, setID);
			for (int j = 0; j < RemeshRounds; j++)
			{
				regionRemesher.BasicRemeshPass();
			}
			regionRemesher.BackPropropagate();
			return true;
		}
	}
	public class PlanarHoleFiller
	{
		private class FillLoop
		{
			public EdgeLoop edgeLoop;

			public Polygon2d poly;
		}

		public DMesh3 Mesh;

		public Vector3d PlaneOrigin;

		public Vector3d PlaneNormal;

		public double FillTargetEdgeLen = double.MaxValue;

		public bool MergeFillBoundary = true;

		public bool OutputHasCracks;

		public int FailedInsertions;

		public int FailedMerges;

		private Vector3d PlaneX;

		private Vector3d PlaneY;

		private List<FillLoop> Loops = new List<FillLoop>();

		private AxisAlignedBox2d Bounds;

		public PlanarHoleFiller(DMesh3 mesh)
		{
			Mesh = mesh;
			Bounds = AxisAlignedBox2d.Empty;
		}

		public PlanarHoleFiller(MeshPlaneCut cut)
		{
			Mesh = cut.Mesh;
			AddFillLoops(cut.CutLoops);
			SetPlane(cut.PlaneOrigin, cut.PlaneNormal);
		}

		public void SetPlane(Vector3d origin, Vector3d normal)
		{
			PlaneOrigin = origin;
			PlaneNormal = normal;
			Vector3d.ComputeOrthogonalComplement(1, PlaneNormal, ref PlaneX, ref PlaneY);
		}

		public void SetPlane(Vector3d origin, Vector3d normal, Vector3d planeX, Vector3d planeY)
		{
			PlaneOrigin = origin;
			PlaneNormal = normal;
			PlaneX = planeX;
			PlaneY = planeY;
		}

		public void AddFillLoop(EdgeLoop loop)
		{
			Loops.Add(new FillLoop
			{
				edgeLoop = loop
			});
		}

		public void AddFillLoops(IEnumerable<EdgeLoop> loops)
		{
			foreach (EdgeLoop loop in loops)
			{
				AddFillLoop(loop);
			}
		}

		public bool Fill()
		{
			compute_polygons();
			Vector2d shiftOrigin = Bounds.Center;
			double scale = 1.0 / Bounds.MaxDim;
			foreach (FillLoop loop in Loops)
			{
				loop.poly.Translate(-shiftOrigin);
				loop.poly.Scale(scale * Vector2d.One, Vector2d.Zero);
			}
			Dictionary<PlanarComplex.Element, int> dictionary = new Dictionary<PlanarComplex.Element, int>();
			PlanarComplex planarComplex = new PlanarComplex();
			for (int i = 0; i < Loops.Count; i++)
			{
				PlanarComplex.Element key = planarComplex.Add(Loops[i].poly);
				dictionary[key] = i;
			}
			PlanarComplex.SolidRegionInfo solidRegionInfo = planarComplex.FindSolidRegions(PlanarComplex.FindSolidsOptions.SortPolygons);
			List<Index2i> list = new List<Index2i>();
			List<Index2i> list2 = new List<Index2i>();
			for (int j = 0; j < solidRegionInfo.Polygons.Count; j++)
			{
				GeneralPolygon2d generalPolygon2d = solidRegionInfo.Polygons[j];
				PlanarComplex.GeneralSolid generalSolid = solidRegionInfo.PolygonsSources[j];
				float num = 1.5f;
				int num2 = 0;
				if (FillTargetEdgeLen < double.MaxValue && FillTargetEdgeLen > 0.0)
				{
					int num3 = (int)((double)(num / (float)scale) / FillTargetEdgeLen) + 1;
					num2 = ((num3 > 1) ? num3 : 0);
				}
				MeshGenerator meshGenerator = ((num2 != 0) ? new GriddedRectGenerator
				{
					IndicesMap = new Index2i(1, 2),
					Width = num,
					Height = num,
					EdgeVertices = num2
				} : new TrivialRectGenerator
				{
					IndicesMap = new Index2i(1, 2),
					Width = num,
					Height = num
				});
				DMesh3 dMesh = meshGenerator.Generate().MakeDMesh();
				dMesh.ReverseOrientation();
				List<Polygon2d> list3 = new List<Polygon2d> { generalPolygon2d.Outer };
				list3.AddRange(generalPolygon2d.Holes);
				int[][] array = new int[list3.Count][];
				for (int k = 0; k < list3.Count; k++)
				{
					MeshInsertUVPolyCurve meshInsertUVPolyCurve = new MeshInsertUVPolyCurve(dMesh, list3[k]);
					ValidationStatus num4 = meshInsertUVPolyCurve.Validate(9.999999974752427E-07 * scale);
					bool flag = true;
					if (num4 == ValidationStatus.Ok && meshInsertUVPolyCurve.Apply())
					{
						meshInsertUVPolyCurve.Simplify();
						array[k] = meshInsertUVPolyCurve.CurveVertices;
						flag = meshInsertUVPolyCurve.Loops.Count != 1 || meshInsertUVPolyCurve.Loops[0].VertexCount != list3[k].VertexCount;
					}
					if (flag)
					{
						list.Add(new Index2i(j, k));
					}
				}
				List<int> list4 = new List<int>();
				foreach (int item in dMesh.TriangleIndices())
				{
					if (!generalPolygon2d.Contains(dMesh.GetTriCentroid(item).xy))
					{
						list4.Add(item);
					}
				}
				foreach (int item2 in list4)
				{
					dMesh.RemoveTriangle(item2);
				}
				MeshTransforms.PerVertexTransform(dMesh, delegate(Vector3d v)
				{
					Vector2d xy = v.xy;
					xy /= scale;
					xy += shiftOrigin;
					return to3D(xy);
				});
				IndexMap mergeMapV = new IndexMap(bForceSparse: true);
				if (MergeFillBoundary)
				{
					for (int num5 = 0; num5 < list3.Count; num5++)
					{
						if (array[num5] != null)
						{
							int[] array2 = array[num5];
							_ = array2.Length;
							PlanarComplex.Element key2 = ((num5 == 0) ? generalSolid.Outer : generalSolid.Holes[num5 - 1]);
							int index = dictionary[key2];
							EdgeLoop edgeLoop = Loops[index].edgeLoop;
							List<int> list5 = build_merge_map(dMesh, array2, Mesh, edgeLoop.Vertices, 9.999999974752427E-07, mergeMapV);
							if (list5 != null && list5.Count > 0)
							{
								list.Add(new Index2i(j, num5));
								OutputHasCracks = true;
							}
						}
					}
				}
				new MeshEditor(Mesh).AppendMesh(dMesh, mergeMapV, out var _, Mesh.AllocateTriangleGroup());
			}
			FailedInsertions = list.Count;
			FailedMerges = list2.Count;
			if (list.Count > 0 || list2.Count > 0)
			{
				return false;
			}
			return true;
		}

		private List<int> build_merge_map(DMesh3 fillMesh, int[] fillLoopV, DMesh3 targetMesh, int[] targetLoopV, double tol, IndexMap mergeMapV)
		{
			if (fillLoopV.Length == targetLoopV.Length && build_merge_map_simple(fillMesh, fillLoopV, targetMesh, targetLoopV, tol, mergeMapV))
			{
				return null;
			}
			int num = fillLoopV.Length;
			int num2 = targetLoopV.Length;
			bool[] array = new bool[num];
			_ = new bool[num2];
			_ = new int[num];
			_ = new int[num2];
			List<int> list = new List<int>();
			SmallListSet smallListSet = new SmallListSet();
			smallListSet.Resize(num);
			double num3 = tol * tol;
			for (int i = 0; i < num; i++)
			{
				if (!fillMesh.IsVertex(fillLoopV[i]))
				{
					array[i] = true;
					list.Add(i);
					continue;
				}
				smallListSet.AllocateAt(i);
				Vector3d vertex = fillMesh.GetVertex(fillLoopV[i]);
				for (int j = 0; j < num2; j++)
				{
					Vector3d v = targetMesh.GetVertex(targetLoopV[j]);
					if (vertex.DistanceSquared(ref v) < num3)
					{
						smallListSet.Insert(i, j);
					}
				}
			}
			for (int k = 0; k < num; k++)
			{
				if (!array[k] && smallListSet.Count(k) == 1)
				{
					int num4 = smallListSet.First(k);
					mergeMapV[fillLoopV[k]] = targetLoopV[num4];
					array[k] = true;
				}
			}
			for (int l = 0; l < num; l++)
			{
				if (!array[l])
				{
					list.Add(l);
				}
			}
			return list;
		}

		private bool build_merge_map_simple(DMesh3 fillMesh, int[] fillLoopV, DMesh3 targetMesh, int[] targetLoopV, double tol, IndexMap mergeMapV)
		{
			if (fillLoopV.Length != targetLoopV.Length)
			{
				return false;
			}
			int num = fillLoopV.Length;
			for (int i = 0; i < num; i++)
			{
				if (!fillMesh.IsVertex(fillLoopV[i]))
				{
					return false;
				}
				Vector3d vertex = fillMesh.GetVertex(fillLoopV[i]);
				Vector3d vertex2 = Mesh.GetVertex(targetLoopV[i]);
				if (vertex.Distance(vertex2) > tol)
				{
					return false;
				}
			}
			for (int j = 0; j < num; j++)
			{
				mergeMapV[fillLoopV[j]] = targetLoopV[j];
			}
			return true;
		}

		private void compute_polygons()
		{
			Bounds = AxisAlignedBox2d.Empty;
			for (int i = 0; i < Loops.Count; i++)
			{
				EdgeLoop edgeLoop = Loops[i].edgeLoop;
				Polygon2d polygon2d = new Polygon2d();
				int[] vertices = edgeLoop.Vertices;
				foreach (int vID in vertices)
				{
					Vector2d v = to2D(Mesh.GetVertex(vID));
					polygon2d.AppendVertex(v);
				}
				Loops[i].poly = polygon2d;
				Bounds.Contain(polygon2d.Bounds);
			}
		}

		private bool inPolygon(Vector2d v2, List<GeneralPolygon2d> polys, bool all = false)
		{
			int num = 0;
			foreach (GeneralPolygon2d poly in polys)
			{
				if (poly.Contains(v2))
				{
					if (!all)
					{
						return true;
					}
					num++;
				}
			}
			if (all && num == polys.Count)
			{
				return true;
			}
			return false;
		}

		private Vector2d to2D(Vector3d v)
		{
			Vector3d v2 = v - PlaneOrigin;
			v2 -= v2.Dot(PlaneNormal) * PlaneNormal;
			return new Vector2d(PlaneX.Dot(v2), PlaneY.Dot(v2));
		}

		private Vector3d to3D(Vector2d v)
		{
			return PlaneOrigin + PlaneX * v.x + PlaneY * v.y;
		}
	}
	public class PlanarSpansFiller
	{
		public DMesh3 Mesh;

		public Vector3d PlaneOrigin;

		public Vector3d PlaneNormal;

		public double FillTargetEdgeLen = double.MaxValue;

		public bool MergeFillBoundary;

		private Vector3d PlaneX;

		private Vector3d PlaneY;

		private List<EdgeSpan> FillSpans;

		private Polygon2d SpansPoly;

		private AxisAlignedBox2d Bounds;

		public PlanarSpansFiller(DMesh3 mesh, IList<EdgeSpan> spans)
		{
			Mesh = mesh;
			FillSpans = new List<EdgeSpan>(spans);
			Bounds = AxisAlignedBox2d.Empty;
		}

		public void SetPlane(Vector3d origin, Vector3d normal)
		{
			PlaneOrigin = origin;
			PlaneNormal = normal;
			Vector3d.ComputeOrthogonalComplement(1, PlaneNormal, ref PlaneX, ref PlaneY);
		}

		public void SetPlane(Vector3d origin, Vector3d normal, Vector3d planeX, Vector3d planeY)
		{
			PlaneOrigin = origin;
			PlaneNormal = normal;
			PlaneX = planeX;
			PlaneY = planeY;
		}

		public bool Fill()
		{
			compute_polygon();
			Vector2d shiftOrigin = Bounds.Center;
			double scale = 1.0 / Bounds.MaxDim;
			SpansPoly.Translate(-shiftOrigin);
			SpansPoly.Scale(scale * Vector2d.One, Vector2d.Zero);
			new Dictionary<PlanarComplex.Element, int>();
			float num = 1.5f;
			int num2 = 0;
			if (FillTargetEdgeLen < double.MaxValue && FillTargetEdgeLen > 0.0)
			{
				int num3 = (int)((double)(num / (float)scale) / FillTargetEdgeLen) + 1;
				num2 = ((num3 > 1) ? num3 : 0);
			}
			MeshGenerator meshGenerator = ((num2 != 0) ? new GriddedRectGenerator
			{
				IndicesMap = new Index2i(1, 2),
				Width = num,
				Height = num,
				EdgeVertices = num2
			} : new TrivialRectGenerator
			{
				IndicesMap = new Index2i(1, 2),
				Width = num,
				Height = num
			});
			DMesh3 dMesh = meshGenerator.Generate().MakeDMesh();
			dMesh.ReverseOrientation();
			int[] array = null;
			MeshInsertUVPolyCurve meshInsertUVPolyCurve = new MeshInsertUVPolyCurve(dMesh, SpansPoly);
			ValidationStatus num4 = meshInsertUVPolyCurve.Validate(9.999999974752427E-07 * scale);
			bool flag = true;
			if (num4 == ValidationStatus.Ok && meshInsertUVPolyCurve.Apply())
			{
				meshInsertUVPolyCurve.Simplify();
				array = meshInsertUVPolyCurve.CurveVertices;
				flag = false;
			}
			if (flag)
			{
				return false;
			}
			List<int> list = new List<int>();
			foreach (int item in dMesh.TriangleIndices())
			{
				Vector3d triCentroid = dMesh.GetTriCentroid(item);
				if (!SpansPoly.Contains(triCentroid.xy))
				{
					list.Add(item);
				}
			}
			foreach (int item2 in list)
			{
				dMesh.RemoveTriangle(item2);
			}
			MeshTransforms.PerVertexTransform(dMesh, delegate(Vector3d v)
			{
				Vector2d xy = v.xy;
				xy /= scale;
				xy += shiftOrigin;
				return to3D(xy);
			});
			IndexMap mergeMapV = new IndexMap(bForceSparse: true);
			if (MergeFillBoundary && array != null)
			{
				throw new NotImplementedException("PlanarSpansFiller: merge fill boundary not implemented!");
			}
			new MeshEditor(Mesh).AppendMesh(dMesh, mergeMapV, out var _, Mesh.AllocateTriangleGroup());
			return true;
		}

		private void compute_polygon()
		{
			SpansPoly = new Polygon2d();
			for (int i = 0; i < FillSpans.Count; i++)
			{
				int[] vertices = FillSpans[i].Vertices;
				foreach (int vID in vertices)
				{
					Vector2d v = to2D(Mesh.GetVertex(vID));
					SpansPoly.AppendVertex(v);
				}
			}
			Bounds = SpansPoly.Bounds;
		}

		private Vector2d to2D(Vector3d v)
		{
			Vector3d v2 = v - PlaneOrigin;
			v2 -= v2.Dot(PlaneNormal) * PlaneNormal;
			return new Vector2d(PlaneX.Dot(v2), PlaneY.Dot(v2));
		}

		private Vector3d to3D(Vector2d v)
		{
			return PlaneOrigin + PlaneX * v.x + PlaneY * v.y;
		}
	}
	public class RegionOperator
	{
		public DMesh3 BaseMesh;

		public DSubmesh3 Region;

		public IndexMap ReinsertSubToBaseMapV;

		public IndexMap ReinsertSubToBaseMapT;

		public MeshEditor.DuplicateTriBehavior ReinsertDuplicateTriBehavior;

		private int[] cur_base_tris;

		public int[] CurrentBaseTriangles => cur_base_tris;

		public RegionOperator(DMesh3 mesh, int[] regionTris, Action<DSubmesh3> submeshConfigF = null)
		{
			BaseMesh = mesh;
			Region = new DSubmesh3(mesh);
			submeshConfigF?.Invoke(Region);
			Region.Compute(regionTris);
			Region.ComputeBoundaryInfo(regionTris);
			cur_base_tris = (int[])regionTris.Clone();
		}

		public RegionOperator(DMesh3 mesh, IEnumerable<int> regionTris, Action<DSubmesh3> submeshConfigF = null)
		{
			BaseMesh = mesh;
			Region = new DSubmesh3(mesh);
			submeshConfigF?.Invoke(Region);
			Region.Compute(regionTris);
			int tri_count_est = regionTris.Count();
			Region.ComputeBoundaryInfo(regionTris, tri_count_est);
			cur_base_tris = regionTris.ToArray();
		}

		public HashSet<int> CurrentBaseInteriorVertices()
		{
			HashSet<int> hashSet = new HashSet<int>();
			IndexHashSet baseBorderV = Region.BaseBorderV;
			int[] array = cur_base_tris;
			foreach (int tID in array)
			{
				Index3i triangle = BaseMesh.GetTriangle(tID);
				if (!baseBorderV[triangle.a])
				{
					hashSet.Add(triangle.a);
				}
				if (!baseBorderV[triangle.b])
				{
					hashSet.Add(triangle.b);
				}
				if (!baseBorderV[triangle.c])
				{
					hashSet.Add(triangle.c);
				}
			}
			return hashSet;
		}

		public void RepairPossibleNonManifoldEdges()
		{
			int maxEdgeID = Region.SubMesh.MaxEdgeID;
			List<int> list = new List<int>();
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (!Region.SubMesh.IsEdge(i) || Region.SubMesh.IsBoundaryEdge(i))
				{
					continue;
				}
				Index2i edgeV = Region.SubMesh.GetEdgeV(i);
				if (Region.SubMesh.IsBoundaryVertex(edgeV.a) && Region.SubMesh.IsBoundaryVertex(edgeV.b))
				{
					int num = Region.MapVertexToBaseMesh(edgeV.a);
					int num2 = Region.MapVertexToBaseMesh(edgeV.b);
					if (num != -1 && num2 != -1 && Region.BaseMesh.FindEdge(num, num2) != -1)
					{
						list.Add(i);
					}
				}
			}
			for (int j = 0; j < list.Count; j++)
			{
				Region.SubMesh.SplitEdge(list[j], out var _);
			}
		}

		public void SetSubmeshGroupID(int gid)
		{
			FaceGroupUtil.SetGroupID(Region.SubMesh, gid);
		}

		public bool BackPropropagate(bool bAllowSubmeshRepairs = true)
		{
			if (bAllowSubmeshRepairs)
			{
				RepairPossibleNonManifoldEdges();
			}
			MeshEditor meshEditor = new MeshEditor(BaseMesh);
			meshEditor.RemoveTriangles(cur_base_tris, bRemoveIsolatedVerts: true);
			int[] new_tris = new int[Region.SubMesh.TriangleCount];
			ReinsertSubToBaseMapV = null;
			bool result = meshEditor.ReinsertSubmesh(Region, ref new_tris, out ReinsertSubToBaseMapV, ReinsertDuplicateTriBehavior);
			int maxTriangleID = Region.SubMesh.MaxTriangleID;
			ReinsertSubToBaseMapT = new IndexMap(bForceSparse: false, maxTriangleID);
			int num = 0;
			for (int i = 0; i < maxTriangleID; i++)
			{
				if (Region.SubMesh.IsTriangle(i))
				{
					ReinsertSubToBaseMapT[i] = new_tris[num++];
				}
			}
			cur_base_tris = new_tris;
			return result;
		}

		public bool BackPropropagateVertices(bool bRecomputeBoundaryNormals = false)
		{
			bool flag = Region.SubMesh.HasVertexNormals && Region.BaseMesh.HasVertexNormals;
			foreach (int item in Region.SubMesh.VertexIndices())
			{
				int vID = Region.SubToBaseV[item];
				Vector3d vertex = Region.SubMesh.GetVertex(item);
				Region.BaseMesh.SetVertex(vID, vertex);
				if (flag)
				{
					Region.BaseMesh.SetVertexNormal(vID, Region.SubMesh.GetVertexNormal(item));
				}
			}
			if (bRecomputeBoundaryNormals)
			{
				foreach (int item2 in Region.BaseBorderV)
				{
					Vector3d vector3d = MeshNormals.QuickCompute(Region.BaseMesh, item2);
					Region.BaseMesh.SetVertexNormal(item2, (Vector3f)vector3d);
				}
			}
			return true;
		}
	}
	public class SimpleHoleFiller
	{
		public DMesh3 Mesh;

		public EdgeLoop Loop;

		public int NewVertex;

		public int[] NewTriangles;

		public SimpleHoleFiller(DMesh3 mesh, EdgeLoop loop)
		{
			Mesh = mesh;
			Loop = loop;
			NewVertex = -1;
			NewTriangles = null;
		}

		public virtual ValidationStatus Validate()
		{
			return MeshValidation.IsBoundaryLoop(Mesh, Loop);
		}

		public virtual bool Fill(int group_id = -1)
		{
			if (Loop.Vertices.Length < 3)
			{
				return false;
			}
			if (Loop.Vertices.Length == 3)
			{
				Index3i tv = new Index3i(Loop.Vertices[0], Loop.Vertices[2], Loop.Vertices[1]);
				int num = Mesh.AppendTriangle(tv, group_id);
				if (num < 0)
				{
					return false;
				}
				NewTriangles = new int[1] { num };
				NewVertex = -1;
				return true;
			}
			Vector3d zero = Vector3d.Zero;
			for (int i = 0; i < Loop.Vertices.Length; i++)
			{
				zero += Mesh.GetVertex(Loop.Vertices[i]);
			}
			zero *= 1.0 / (double)Loop.Vertices.Length;
			NewVertex = Mesh.AppendVertex(zero);
			MeshEditor meshEditor = new MeshEditor(Mesh);
			try
			{
				NewTriangles = meshEditor.AddTriangleFan_OrderedVertexLoop(NewVertex, Loop.Vertices, group_id);
			}
			catch
			{
				NewTriangles = null;
			}
			if (NewTriangles == null)
			{
				Mesh.RemoveVertex(NewVertex);
				NewVertex = -1;
				return false;
			}
			return true;
		}
	}
	public class MeshBoundaryLoopsException : Exception
	{
		public bool UnclosedLoop;

		public bool BowtieFailure;

		public bool RepeatedEdge;

		public MeshBoundaryLoopsException(string message)
			: base(message)
		{
		}
	}
	public class MeshBoundaryLoops : IEnumerable<EdgeLoop>, IEnumerable
	{
		public enum SpanBehaviors
		{
			Ignore,
			ThrowException,
			Compute
		}

		public enum FailureBehaviors
		{
			ThrowException,
			ConvertToOpenSpan
		}

		private struct Subloops
		{
			public List<EdgeLoop> Loops;

			public List<EdgeSpan> Spans;
		}

		public DMesh3 Mesh;

		public List<EdgeLoop> Loops;

		public List<EdgeSpan> Spans;

		public bool SawOpenSpans;

		public bool FellBackToSpansOnFailure;

		public SpanBehaviors SpanBehavior = SpanBehaviors.Compute;

		public FailureBehaviors FailureBehavior = FailureBehaviors.ConvertToOpenSpan;

		public Func<int, bool> EdgeFilterF;

		public List<int> FailureBowties;

		public int Count => Loops.Count;

		public int SpanCount => Spans.Count;

		public EdgeLoop this[int index] => Loops[index];

		public int MaxVerticesLoopIndex
		{
			get
			{
				int num = 0;
				for (int i = 1; i < Loops.Count; i++)
				{
					if (Loops[i].Vertices.Length > Loops[num].Vertices.Length)
					{
						num = i;
					}
				}
				return num;
			}
		}

		public MeshBoundaryLoops(DMesh3 mesh, bool bAutoCompute = true)
		{
			Mesh = mesh;
			if (bAutoCompute)
			{
				Compute();
			}
		}

		public IEnumerator<EdgeLoop> GetEnumerator()
		{
			return Loops.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return Loops.GetEnumerator();
		}

		public Index2i FindVertexIndex(int vID)
		{
			int count = Loops.Count;
			for (int i = 0; i < count; i++)
			{
				int num = Loops[i].FindVertexIndex(vID);
				if (num >= 0)
				{
					return new Index2i(i, num);
				}
			}
			return Index2i.Max;
		}

		public int FindLoopContainingVertex(int vid)
		{
			int count = Loops.Count;
			for (int i = 0; i < count; i++)
			{
				if (Enumerable.Contains(Loops[i].Vertices, vid))
				{
					return i;
				}
			}
			return -1;
		}

		public int FindLoopContainingEdge(int eid)
		{
			int count = Loops.Count;
			for (int i = 0; i < count; i++)
			{
				if (Enumerable.Contains(Loops[i].Edges, eid))
				{
					return i;
				}
			}
			return -1;
		}

		public bool Compute()
		{
			Loops = new List<EdgeLoop>();
			Spans = new List<EdgeSpan>();
			if (Mesh.CachedIsClosed)
			{
				return true;
			}
			int maxEdgeID = Mesh.MaxEdgeID;
			BitArray bitArray = new BitArray(maxEdgeID);
			bitArray.SetAll(value: false);
			List<int> list = new List<int>();
			List<int> list2 = new List<int>();
			List<int> list3 = new List<int>();
			int[] array = new int[16];
			for (int i = 0; i < maxEdgeID; i++)
			{
				if (!Mesh.IsEdge(i) || bitArray[i] || !Mesh.IsBoundaryEdge(i))
				{
					continue;
				}
				if (EdgeFilterF != null && !EdgeFilterF(i))
				{
					bitArray[i] = true;
					continue;
				}
				int num = i;
				bitArray[num] = true;
				list.Add(num);
				int num2 = i;
				bool flag = false;
				bool flag2 = false;
				while (!flag)
				{
					Index2i orientedBoundaryEdgeV = Mesh.GetOrientedBoundaryEdgeV(num2);
					int a = orientedBoundaryEdgeV.a;
					int num3 = orientedBoundaryEdgeV.b;
					if (flag2)
					{
						a = orientedBoundaryEdgeV.b;
						num3 = orientedBoundaryEdgeV.a;
					}
					else
					{
						list2.Add(a);
					}
					int e = -1;
					int e2 = 1;
					int num4 = Mesh.VtxBoundaryEdges(num3, ref e, ref e2);
					if (EdgeFilterF != null)
					{
						if (num4 > 2)
						{
							if (num4 >= array.Length)
							{
								array = new int[num4];
							}
							int max_i = Mesh.VtxAllBoundaryEdges(num3, array);
							max_i = BufferUtil.CountValid(array, EdgeFilterF, max_i);
						}
						else
						{
							if (!EdgeFilterF(e))
							{
								num4--;
							}
							if (!EdgeFilterF(e2))
							{
								num4--;
							}
						}
					}
					if (num4 < 2)
					{
						if (SpanBehavior == SpanBehaviors.ThrowException)
						{
							throw new MeshBoundaryLoopsException("MeshBoundaryLoops.Compute: found open span at vertex " + num3)
							{
								UnclosedLoop = true
							};
						}
						if (flag2)
						{
							flag = true;
							continue;
						}
						flag2 = true;
						num2 = list[0];
						list.Reverse();
						continue;
					}
					int num5 = -1;
					if (num4 > 2)
					{
						if (num3 == list2[0])
						{
							num5 = -2;
						}
						else
						{
							if (num4 >= array.Length)
							{
								array = new int[2 * num4];
							}
							int num6 = Mesh.VtxAllBoundaryEdges(num3, array);
							if (EdgeFilterF != null)
							{
								num6 = BufferUtil.FilterInPlace(array, EdgeFilterF, num6);
							}
							num5 = find_left_turn_edge(num2, num3, array, num6, bitArray);
							if (num5 == -1)
							{
								if (FailureBehavior == FailureBehaviors.ThrowException || SpanBehavior == SpanBehaviors.ThrowException)
								{
									throw new MeshBoundaryLoopsException("MeshBoundaryLoops.Compute: cannot find valid outgoing edge at bowtie vertex " + num3)
									{
										BowtieFailure = true
									};
								}
								if (flag2)
								{
									flag = true;
									continue;
								}
								flag2 = true;
								flag = true;
								continue;
							}
						}
						if (!list3.Contains(num3))
						{
							list3.Add(num3);
						}
					}
					else
					{
						num5 = ((e == num2) ? e2 : e);
					}
					if (num5 == -2)
					{
						flag = true;
					}
					else if (num5 == num)
					{
						flag = true;
					}
					else if (bitArray[num5])
					{
						if (FailureBehavior == FailureBehaviors.ThrowException || SpanBehavior == SpanBehaviors.ThrowException)
						{
							throw new MeshBoundaryLoopsException("MeshBoundaryLoops.Compute: encountered repeated edge " + num5)
							{
								RepeatedEdge = true
							};
						}
						flag2 = true;
						flag = true;
					}
					else
					{
						list.Add(num5);
						bitArray[num5] = true;
						num2 = num5;
					}
				}
				if (flag2)
				{
					SawOpenSpans = true;
					if (SpanBehavior == SpanBehaviors.Compute)
					{
						list.Reverse();
						EdgeSpan item = EdgeSpan.FromEdges(Mesh, list);
						Spans.Add(item);
					}
				}
				else if (list3.Count > 0)
				{
					Subloops subloops = extract_subloops(list2, list, list3);
					foreach (EdgeLoop loop in subloops.Loops)
					{
						Loops.Add(loop);
					}
					if (subloops.Spans.Count > 0)
					{
						FellBackToSpansOnFailure = true;
						foreach (EdgeSpan span in subloops.Spans)
						{
							Spans.Add(span);
						}
					}
				}
				else
				{
					EdgeLoop edgeLoop = new EdgeLoop(Mesh);
					edgeLoop.Vertices = list2.ToArray();
					edgeLoop.Edges = list.ToArray();
					Loops.Add(edgeLoop);
				}
				list.Clear();
				list2.Clear();
				list3.Clear();
			}
			return true;
		}

		private Vector3d get_vtx_normal(int vid)
		{
			Vector3d zero = Vector3d.Zero;
			foreach (int item in Mesh.VtxTrianglesItr(vid))
			{
				zero += Mesh.GetTriNormal(item);
			}
			zero.Normalize();
			return zero;
		}

		private int find_left_turn_edge(int incoming_e, int bowtie_v, int[] bdry_edges, int bdry_edges_count, BitArray used_edges)
		{
			Vector3d vector3d = get_vtx_normal(bowtie_v);
			int vID = Mesh.edge_other_v(incoming_e, bowtie_v);
			Vector3d vector3d2 = Mesh.GetVertex(bowtie_v) - Mesh.GetVertex(vID);
			int result = -1;
			double num = double.MaxValue;
			for (int i = 0; i < bdry_edges_count; i++)
			{
				int num2 = bdry_edges[i];
				if (used_edges[num2])
				{
					continue;
				}
				Index2i orientedBoundaryEdgeV = Mesh.GetOrientedBoundaryEdgeV(num2);
				if (orientedBoundaryEdgeV.a == bowtie_v)
				{
					Vector3d vector3d3 = Mesh.GetVertex(orientedBoundaryEdgeV.b) - Mesh.GetVertex(bowtie_v);
					float num3 = MathUtil.PlaneAngleSignedD((Vector3f)vector3d2, (Vector3f)vector3d3, (Vector3f)vector3d);
					if (num == double.MaxValue || (double)num3 < num)
					{
						num = num3;
						result = num2;
					}
				}
			}
			return result;
		}

		private Subloops extract_subloops(List<int> loopV, List<int> loopE, List<int> bowties)
		{
			Subloops result = new Subloops
			{
				Loops = new List<EdgeLoop>(),
				Spans = new List<EdgeSpan>()
			};
			List<int> list = new List<int>();
			foreach (int bowty in bowties)
			{
				if (count_in_list(loopV, bowty) > 1)
				{
					list.Add(bowty);
				}
			}
			if (list.Count == 0)
			{
				result.Loops.Add(new EdgeLoop(Mesh)
				{
					Vertices = loopV.ToArray(),
					Edges = loopE.ToArray(),
					BowtieVertices = bowties.ToArray()
				});
				return result;
			}
			while (list.Count > 0)
			{
				int i = 0;
				int num = 0;
				int start_i = -1;
				int end_i = -1;
				int num2 = -1;
				int num3 = int.MaxValue;
				for (; i < list.Count; i++)
				{
					num = list[i];
					if (is_simple_bowtie_loop(loopV, list, num, out start_i, out end_i))
					{
						int num4 = count_span(loopV, start_i, end_i);
						if (num4 < num3)
						{
							num2 = num;
							num3 = num4;
						}
					}
				}
				if (num2 == -1)
				{
					if (FailureBehavior == FailureBehaviors.ThrowException)
					{
						FailureBowties = list;
						throw new MeshBoundaryLoopsException("MeshBoundaryLoops.Compute: Cannot find a valid simple loop");
					}
					EdgeSpan edgeSpan = new EdgeSpan(Mesh);
					List<int> list2 = new List<int>();
					for (int j = 0; j < loopV.Count; j++)
					{
						if (loopV[j] != -1)
						{
							list2.Add(loopV[j]);
						}
					}
					edgeSpan.Vertices = list2.ToArray();
					edgeSpan.Edges = EdgeSpan.VerticesToEdges(Mesh, edgeSpan.Vertices);
					edgeSpan.BowtieVertices = bowties.ToArray();
					result.Spans.Add(edgeSpan);
					return result;
				}
				if (num != num2)
				{
					num = num2;
					is_simple_bowtie_loop(loopV, list, num, out start_i, out end_i);
				}
				EdgeLoop edgeLoop = new EdgeLoop(Mesh);
				edgeLoop.Vertices = extract_span(loopV, start_i, end_i, bMarkInvalid: true);
				edgeLoop.Edges = EdgeLoop.VertexLoopToEdgeLoop(Mesh, edgeLoop.Vertices);
				edgeLoop.BowtieVertices = bowties.ToArray();
				result.Loops.Add(edgeLoop);
				if (count_in_list(loopV, num) < 2)
				{
					list.Remove(num);
				}
			}
			int num5 = 0;
			for (int k = 0; k < loopV.Count; k++)
			{
				if (loopV[k] != -1)
				{
					num5++;
				}
			}
			if (num5 > 0)
			{
				EdgeLoop edgeLoop2 = new EdgeLoop(Mesh);
				edgeLoop2.Vertices = new int[num5];
				int num6 = 0;
				for (int l = 0; l < loopV.Count; l++)
				{
					if (loopV[l] != -1)
					{
						edgeLoop2.Vertices[num6++] = loopV[l];
					}
				}
				edgeLoop2.Edges = EdgeLoop.VertexLoopToEdgeLoop(Mesh, edgeLoop2.Vertices);
				edgeLoop2.BowtieVertices = bowties.ToArray();
				result.Loops.Add(edgeLoop2);
			}
			return result;
		}

		private bool is_simple_bowtie_loop(List<int> loopV, List<int> bowties, int bowtieV, out int start_i, out int end_i)
		{
			start_i = find_index(loopV, 0, bowtieV);
			end_i = find_index(loopV, start_i + 1, bowtieV);
			if (is_simple_path(loopV, bowties, bowtieV, start_i, end_i))
			{
				return true;
			}
			if (is_simple_path(loopV, bowties, bowtieV, end_i, start_i))
			{
				int num = start_i;
				start_i = end_i;
				end_i = num;
				return true;
			}
			return false;
		}

		private bool is_simple_path(List<int> loopV, List<int> bowties, int bowtieV, int i1, int i2)
		{
			int count = loopV.Count;
			for (int num = i1; num != i2; num = (num + 1) % count)
			{
				int num2 = loopV[num];
				if (num2 != -1 && num2 != bowtieV && bowties.Contains(num2))
				{
					return false;
				}
			}
			return true;
		}

		private int[] extract_span(List<int> loop, int i0, int i1, bool bMarkInvalid)
		{
			int[] array = new int[count_span(loop, i0, i1)];
			int num = 0;
			int count = loop.Count;
			for (int num2 = i0; num2 != i1; num2 = (num2 + 1) % count)
			{
				if (loop[num2] != -1)
				{
					array[num++] = loop[num2];
					if (bMarkInvalid)
					{
						loop[num2] = -1;
					}
				}
			}
			return array;
		}

		private int count_span(List<int> l, int i0, int i1)
		{
			int num = 0;
			int count = l.Count;
			for (int num2 = i0; num2 != i1; num2 = (num2 + 1) % count)
			{
				if (l[num2] != -1)
				{
					num++;
				}
			}
			return num;
		}

		private int find_index(List<int> loop, int start, int item)
		{
			for (int i = start; i < loop.Count; i++)
			{
				if (loop[i] == item)
				{
					return i;
				}
			}
			return -1;
		}

		private int count_in_list(List<int> loop, int item)
		{
			int num = 0;
			for (int i = 0; i < loop.Count; i++)
			{
				if (loop[i] == item)
				{
					num++;
				}
			}
			return num;
		}
	}
	public class MeshConnectedComponents : IEnumerable<MeshConnectedComponents.Component>, IEnumerable
	{
		public struct Component
		{
			public int[] Indices;
		}

		public DMesh3 Mesh;

		public IEnumerable<int> FilterSet;

		public Func<int, bool> FilterF;

		public Func<int, bool> SeedFilterF;

		public List<Component> Components;

		public int Count => Components.Count;

		public Component this[int index] => Components[index];

		public int LargestByCount
		{
			get
			{
				int num = 0;
				int num2 = Components[num].Indices.Length;
				for (int i = 1; i < Components.Count; i++)
				{
					if (Components[i].Indices.Length > num2)
					{
						num2 = Components[i].Indices.Length;
						num = i;
					}
				}
				return num;
			}
		}

		public MeshConnectedComponents(DMesh3 mesh)
		{
			Mesh = mesh;
			Components = new List<Component>();
		}

		public IEnumerator<Component> GetEnumerator()
		{
			return Components.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return Components.GetEnumerator();
		}

		public void SortByCount(bool bIncreasing = true)
		{
			if (bIncreasing)
			{
				Components.Sort((Component x, Component y) => x.Indices.Length.CompareTo(y.Indices.Length));
			}
			else
			{
				Components.Sort((Component x, Component y) => -x.Indices.Length.CompareTo(y.Indices.Length));
			}
		}

		public void SortByValue(Func<Component, double> valueF, bool bIncreasing = true)
		{
			Dictionary<Component, double> vals = new Dictionary<Component, double>();
			foreach (Component component in Components)
			{
				vals[component] = valueF(component);
			}
			if (bIncreasing)
			{
				Components.Sort((Component x, Component y) => vals[x].CompareTo(vals[y]));
			}
			else
			{
				Components.Sort((Component x, Component y) => -vals[x].CompareTo(vals[y]));
			}
		}

		public void FindConnectedT()
		{
			Components = new List<Component>();
			int maxTriangleID = Mesh.MaxTriangleID;
			Func<int, bool> func = (int i) => Mesh.IsTriangle(i);
			if (FilterF != null)
			{
				func = (int i) => Mesh.IsTriangle(i) && FilterF(i);
			}
			byte[] array = new byte[Mesh.MaxTriangleID];
			Interval1i empty = Interval1i.Empty;
			if (FilterSet != null)
			{
				for (int num = 0; num < maxTriangleID; num++)
				{
					array[num] = byte.MaxValue;
				}
				foreach (int item2 in FilterSet)
				{
					if (func(item2))
					{
						array[item2] = 0;
						empty.Contain(item2);
					}
				}
			}
			else
			{
				for (int num2 = 0; num2 < maxTriangleID; num2++)
				{
					if (func(num2))
					{
						array[num2] = 0;
						empty.Contain(num2);
					}
					else
					{
						array[num2] = byte.MaxValue;
					}
				}
			}
			List<int> list = new List<int>(maxTriangleID / 10);
			List<int> list2 = new List<int>(maxTriangleID / 10);
			IEnumerable<int> enumerable2;
			if (FilterSet == null)
			{
				IEnumerable<int> enumerable = empty;
				enumerable2 = enumerable;
			}
			else
			{
				enumerable2 = FilterSet;
			}
			foreach (int item3 in enumerable2)
			{
				if (array[item3] == byte.MaxValue)
				{
					continue;
				}
				int num3 = item3;
				if (SeedFilterF != null && !SeedFilterF(num3))
				{
					continue;
				}
				list.Add(num3);
				array[num3] = 1;
				while (list.Count > 0)
				{
					int num4 = list[list.Count - 1];
					list.RemoveAt(list.Count - 1);
					array[num4] = 2;
					list2.Add(num4);
					Index3i triNeighbourTris = Mesh.GetTriNeighbourTris(num4);
					for (int num5 = 0; num5 < 3; num5++)
					{
						int num6 = triNeighbourTris[num5];
						if (num6 != -1 && array[num6] == 0)
						{
							list.Add(num6);
							array[num6] = 1;
						}
					}
				}
				Component item = new Component
				{
					Indices = list2.ToArray()
				};
				Components.Add(item);
				for (int num7 = 0; num7 < item.Indices.Length; num7++)
				{
					array[item.Indices[num7]] = byte.MaxValue;
				}
				list2.Clear();
				list.Clear();
			}
		}

		public static DMesh3[] Separate(DMesh3 meshIn)
		{
			MeshConnectedComponents meshConnectedComponents = new MeshConnectedComponents(meshIn);
			meshConnectedComponents.FindConnectedT();
			meshConnectedComponents.SortByCount(bIncreasing: false);
			DMesh3[] array = new DMesh3[meshConnectedComponents.Components.Count];
			int num = 0;
			foreach (Component component in meshConnectedComponents.Components)
			{
				DSubmesh3 dSubmesh = new DSubmesh3(meshIn, component.Indices);
				array[num++] = dSubmesh.SubMesh;
			}
			return array;
		}

		public static DMesh3 LargestT(DMesh3 meshIn)
		{
			MeshConnectedComponents meshConnectedComponents = new MeshConnectedComponents(meshIn);
			meshConnectedComponents.FindConnectedT();
			meshConnectedComponents.SortByCount(bIncreasing: false);
			return new DSubmesh3(meshIn, meshConnectedComponents.Components[0].Indices).SubMesh;
		}

		public static HashSet<int> FindConnectedT(DMesh3 mesh, int tSeed)
		{
			HashSet<int> hashSet = new HashSet<int>();
			hashSet.Add(tSeed);
			List<int> list = new List<int>(64) { tSeed };
			while (list.Count > 0)
			{
				int tID = list[list.Count - 1];
				list.RemoveAt(list.Count - 1);
				Index3i triNeighbourTris = mesh.GetTriNeighbourTris(tID);
				for (int i = 0; i < 3; i++)
				{
					int num = triNeighbourTris[i];
					if (num != -1 && !hashSet.Contains(num))
					{
						hashSet.Add(num);
						list.Add(num);
					}
				}
			}
			return hashSet;
		}
	}
