			: this(mesh)
		{
			minCount = MathUtil.Clamp(minCount, 1, 2);
			foreach (int item in mesh.EdgeIndices())
			{
				Index2i edgeV = mesh.GetEdgeV(item);
				if ((convertV.IsSelected(edgeV.a) ? 1 : 0) + (convertV.IsSelected(edgeV.b) ? 1 : 0) >= minCount)
