	public enum ValidationStatus
	{
		Ok,
		NotAVertex,
		NotBoundaryVertex,
		NotBoundaryEdge,
		NotATriangle,
		VerticesNotConnectedByEdge,
		IncorrectLoopOrientation,
		DuplicateTriangles,
		NearDegenerateMeshEdges,
		NearDenegerateInputGeometry
	}
	public static class MeshValidation
	{
		public static ValidationStatus IsEdgeLoop(DMesh3 mesh, EdgeLoop loop)
		{
			int num = loop.Vertices.Length;
			for (int i = 0; i < num; i++)
			{
				if (!mesh.IsVertex(loop.Vertices[i]))
				{
					return ValidationStatus.NotAVertex;
				}
			}
			for (int j = 0; j < num; j++)
			{
				int vA = loop.Vertices[j];
				int vB = loop.Vertices[(j + 1) % num];
				if (mesh.FindEdge(vA, vB) == -1)
				{
					return ValidationStatus.VerticesNotConnectedByEdge;
				}
			}
			return ValidationStatus.Ok;
		}

		public static ValidationStatus IsBoundaryLoop(DMesh3 mesh, EdgeLoop loop)
		{
			int num = loop.Vertices.Length;
			for (int i = 0; i < num; i++)
			{
				if (!mesh.IsBoundaryVertex(loop.Vertices[i]))
				{
					return ValidationStatus.NotBoundaryVertex;
				}
			}
			for (int j = 0; j < num; j++)
			{
				int num2 = loop.Vertices[j];
				int num3 = loop.Vertices[(j + 1) % num];
				int num4 = mesh.FindEdge(num2, num3);
				if (num4 == -1)
				{
					return ValidationStatus.VerticesNotConnectedByEdge;
				}
				if (!mesh.IsBoundaryEdge(num4))
				{
					return ValidationStatus.NotBoundaryEdge;
				}
				Index2i orientedBoundaryEdgeV = mesh.GetOrientedBoundaryEdgeV(num4);
				if (orientedBoundaryEdgeV.a != num2 || orientedBoundaryEdgeV.b != num3)
				{
					return ValidationStatus.IncorrectLoopOrientation;
				}
			}
			return ValidationStatus.Ok;
		}

		public static ValidationStatus HasDuplicateTriangles(DMesh3 mesh)
		{
			foreach (int item in mesh.TriangleIndices())
			{
				Index3i triNeighbourTris = mesh.GetTriNeighbourTris(item);
				if (triNeighbourTris.a == triNeighbourTris.b && triNeighbourTris.b == triNeighbourTris.c && triNeighbourTris.a != -1)
				{
					return ValidationStatus.DuplicateTriangles;
				}
			}
			return ValidationStatus.Ok;
		}
	}
	public class RayIntersection
	{
		private RayIntersection()
		{
		}

		public static bool Sphere(Vector3f vOrigin, Vector3f vDirection, Vector3f vCenter, float fRadius, out float fRayT)
		{
			bool result = SphereSigned(ref vOrigin, ref vDirection, ref vCenter, fRadius, out fRayT);
			fRayT = Math.Abs(fRayT);
			return result;
		}

		public static bool SphereSigned(ref Vector3f vOrigin, ref Vector3f vDirection, ref Vector3f vCenter, float fRadius, out float fRayT)
		{
			fRayT = 0f;
			Vector3f v = vOrigin - vCenter;
			float num = v.Dot(vDirection);
			float num2 = v.Dot(v) - fRadius * fRadius;
			if (num2 > 0f && num > 0f)
			{
				return false;
			}
			float num3 = num * num - num2;
			if (num3 < 0f)
			{
				return false;
			}
			fRayT = 0f - num - (float)Math.Sqrt(num3);
			return true;
		}

		public static bool SphereSigned(ref Vector3d vOrigin, ref Vector3d vDirection, ref Vector3d vCenter, double fRadius, out double fRayT)
		{
			fRayT = 0.0;
			Vector3d v = vOrigin - vCenter;
			double num = v.Dot(ref vDirection);
			double num2 = v.Dot(v) - fRadius * fRadius;
			if (num2 > 0.0 && num > 0.0)
			{
				return false;
			}
			double num3 = num * num - num2;
			if (num3 < 0.0)
			{
				return false;
			}
			fRayT = 0.0 - num - Math.Sqrt(num3);
			return true;
		}

		public static bool InfiniteCylinder(Vector3f vOrigin, Vector3f vDirection, Vector3f vCylOrigin, Vector3f vCylAxis, float fRadius, out float fRayT)
		{
			bool result = InfiniteCylinderSigned(vOrigin, vDirection, vCylOrigin, vCylAxis, fRadius, out fRayT);
			fRayT = Math.Abs(fRayT);
			return result;
		}

		public static bool InfiniteCylinderSigned(Vector3f vOrigin, Vector3f vDirection, Vector3f vCylOrigin, Vector3f vCylAxis, float fRadius, out float fRayT)
		{
			fRayT = 0f;
			Vector3f vector3f = vCylAxis;
			Vector3f vector3f2 = vOrigin - vCylOrigin;
			if (vector3f2.DistanceSquared(vector3f2.Dot(vector3f) * vector3f) > fRadius * fRadius)
			{
				return false;
			}
			Vector3f v = vector3f2.Cross(vector3f);
			Vector3f v2 = vDirection.Cross(vector3f);
			float num = vector3f.Dot(vector3f);
			float num2 = v2.Dot(v2);
			float num3 = 2f * v2.Dot(v);
			float num4 = v.Dot(v) - fRadius * fRadius * num;
			double num5 = num3 * num3 - 4f * num2 * num4;
			if (num5 <= 0.0)
			{
				return false;
			}
			num5 = Math.Sqrt(num5);
			fRayT = (0f - num3 - (float)num5) / (2f * num2);
			return true;
		}
	}
	public class Circle3d
	{
		public Vector3d Center;

		public Vector3d Normal;

		public Vector3d PlaneX;

		public Vector3d PlaneY;

		public double Radius;

		public bool IsReversed;

		public bool IsClosed => true;

		public double ParamLength => 1.0;

		public bool HasArcLength => true;

		public double ArcLength => Math.PI * 2.0 * Radius;

		public double Circumference => Math.PI * 2.0 * Radius;

		public double Diameter => 2.0 * Radius;

		public double Area => Math.PI * Radius * Radius;

		public Circle3d(Vector3d center, double radius, Vector3d axis0, Vector3d axis1, Vector3d normal)
		{
			IsReversed = false;
			Center = center;
			Normal = normal;
			PlaneX = axis0;
			PlaneY = axis1;
			Radius = radius;
		}

		public Circle3d(Frame3f frame, double radius, int nNormalAxis = 1)
		{
			IsReversed = false;
			Center = frame.Origin;
			Normal = frame.GetAxis(nNormalAxis);
			PlaneX = frame.GetAxis((nNormalAxis + 1) % 3);
			PlaneY = frame.GetAxis((nNormalAxis + 2) % 3);
			Radius = radius;
		}

		public Circle3d(Vector3d center, double radius)
		{
			IsReversed = false;
			Center = center;
			Normal = Vector3d.AxisY;
			PlaneX = Vector3d.AxisX;
			PlaneY = Vector3d.AxisZ;
			Radius = radius;
		}

		public void Reverse()
		{
			IsReversed = !IsReversed;
		}

		public Vector3d SampleDeg(double degrees)
		{
			double num = degrees * (Math.PI / 180.0);
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return Center + num2 * Radius * PlaneX + num3 * Radius * PlaneY;
		}

		public Vector3d SampleRad(double radians)
		{
			double num = Math.Cos(radians);
			double num2 = Math.Sin(radians);
			return Center + num * Radius * PlaneX + num2 * Radius * PlaneY;
		}

		public Vector3d SampleT(double t)
		{
			double num = (IsReversed ? ((0.0 - t) * (Math.PI * 2.0)) : (t * (Math.PI * 2.0)));
			double num2 = Math.Cos(num);
			double num3 = Math.Sin(num);
			return Center + num2 * Radius * PlaneX + num3 * Radius * PlaneY;
		}

		public Vector3d SampleArcLength(double a)
		{
			double num = a / ArcLength;
			double num2 = (IsReversed ? ((0.0 - num) * (Math.PI * 2.0)) : (num * (Math.PI * 2.0)));
			double num3 = Math.Cos(num2);
			double num4 = Math.Sin(num2);
			return Center + num3 * Radius * PlaneX + num4 * Radius * PlaneY;
		}
	}
