	public class CholeskyDecomposition
	{
		public DenseMatrix A;

		public DenseMatrix L;

		public CholeskyDecomposition(DenseMatrix m)
		{
			A = m;
		}

		public bool Compute()
		{
			if (A.Rows != A.Columns)
			{
				throw new Exception("CholeskyDecomposition.Compute(): cannot be applied to non-square matrix");
			}
			int rows = A.Rows;
			L = new DenseMatrix(rows, rows);
			double[] buffer = L.Buffer;
			L[0, 0] = Math.Sqrt(A[0, 0]);
			for (int i = 1; i < rows; i++)
			{
				L[i, 0] = A[i, 0] / L[0, 0];
				double num = L[i, 0] * L[i, 0];
				for (int j = 1; j < i; j++)
				{
					double num2 = 0.0;
					int num3 = i * rows;
					int num4 = j * rows;
					int num5 = num4 + j;
					while (num4 < num5)
					{
						num2 += buffer[num3++] * buffer[num4++];
					}
					L[i, j] = 1.0 / L[j, j] * (A[i, j] - num2);
					num += L[i, j] * L[i, j];
				}
				L[i, i] = Math.Sqrt(A[i, i] - num);
			}
			return true;
		}

		public bool ComputeParallel()
		{
			if (A.Rows != A.Columns)
			{
				throw new Exception("CholeskyDecomposition.ComputeParallel(): cannot be applied to non-square matrix");
			}
			int N = A.Rows;
			L = new DenseMatrix(N, N);
			double[] Lbuf = L.Buffer;
			Action<int> compute_diag = delegate(int r)
			{
				double num4 = 0.0;
				int num5 = r * N;
				int num6 = num5 + r;
				do
				{
					num4 += Lbuf[num5] * Lbuf[num5];
				}
				while (num5++ < num6);
				L[r, r] = Math.Sqrt(A[r, r] - num4);
			};
			L[0, 0] = Math.Sqrt(A[0, 0]);
			for (int num = 1; num < N; num++)
			{
				L[num, 0] = A[num, 0] / L[0, 0];
			}
			compute_diag(1);
			int c = 1;
			while (c < N)
			{
				int num2 = N - 1 - (c + 1);
				gParallel.BlockStartEnd(c + 1, N - 1, delegate(int a, int b)
				{
					for (int i = a; i <= b; i++)
					{
						double num4 = 0.0;
						int num5 = i * N;
						int num6 = c * N;
						int num7 = num6 + c;
						while (num6 < num7)
						{
							num4 += Lbuf[num5++] * Lbuf[num6++];
						}
						L[i, c] = 1.0 / L[c, c] * (A[i, c] - num4);
						if (i == c + 1)
						{
							compute_diag(i);
						}
					}
				}, Math.Max(num2 / 20, 1));
				int num3 = c + 1;
				c = num3;
			}
			return true;
		}

		private IEnumerable<Vector2i> diag_itr()
		{
			int N = A.Rows;
			for (int r = 2; r < N; r++)
			{
				Vector2i rj = new Vector2i(r - 1, 1);
				while (rj.y <= rj.x)
				{
					yield return rj;
					rj.x--;
					rj.y++;
				}
			}
			for (int r = 1; r < N; r++)
			{
				Vector2i rj = new Vector2i(N - 1, r);
				while (rj.y <= rj.x)
				{
					yield return rj;
					rj.x--;
					rj.y++;
				}
			}
		}

		public void Solve(double[] B, double[] X, double[] Y)
		{
			int rows = A.Rows;
			if (Y == null)
			{
				Y = new double[rows];
			}
			Y[0] = B[0] / L[0, 0];
			for (int i = 1; i < rows; i++)
			{
				double num = 0.0;
				for (int j = 0; j < i; j++)
				{
					num += L[i, j] * Y[j];
				}
				Y[i] = (B[i] - num) / L[i, i];
			}
			X[rows - 1] = Y[rows - 1] / L[rows - 1, rows - 1];
			for (int num2 = rows - 2; num2 >= 0; num2--)
			{
				double num3 = 0.0;
				for (int k = num2 + 1; k < rows; k++)
				{
					num3 += L[k, num2] * X[k];
				}
				X[num2] = (Y[num2] - num3) / L[num2, num2];
			}
		}
	}
	public class DenseMatrix : IMatrix
	{
		private double[] d;

		private int N;

		private int M;

		public double[] Buffer => d;

		public int Rows => N;

		public int Columns => M;

		public Index2i Size => new Index2i(N, M);

		public int Length => M * N;

		public double this[int r, int c]
		{
			get
			{
				return d[r * M + c];
			}
			set
			{
				d[r * M + c] = value;
			}
		}

		public double this[int i]
		{
			get
			{
				return d[i];
			}
			set
			{
				d[i] = value;
			}
		}

		public DenseMatrix(int Nrows, int Mcols)
		{
			d = new double[Nrows * Mcols];
			Array.Clear(d, 0, d.Length);
			N = Nrows;
			M = Mcols;
		}

		public DenseMatrix(DenseMatrix copy)
		{
			N = copy.N;
			M = copy.M;
			d = new double[N * M];
			Array.Copy(copy.d, d, copy.d.Length);
		}

		public void Set(int r, int c, double value)
		{
			d[r * M + c] = value;
		}

		public void Set(double[] values)
		{
			if (values.Length != N * M)
			{
				throw new Exception("DenseMatrix.Set: incorrect length");
			}
			Array.Copy(values, d, d.Length);
		}

		public DenseVector Row(int r)
		{
			DenseVector denseVector = new DenseVector(M);
			int num = r * M;
			for (int i = 0; i < M; i++)
			{
				denseVector[i] = d[num + i];
			}
			return denseVector;
		}

		public DenseVector Column(int c)
		{
			DenseVector denseVector = new DenseVector(N);
			for (int i = 0; i < N; i++)
			{
				denseVector[i] = d[i * M + c];
			}
			return denseVector;
		}

		public DenseVector Diagonal()
		{
			if (M != N)
			{
				throw new Exception("DenseMatrix.Diagonal: matrix is not square!");
			}
			DenseVector denseVector = new DenseVector(N);
			for (int i = 0; i < N; i++)
			{
				denseVector[i] = d[i * M + i];
			}
			return denseVector;
		}

		public DenseMatrix Transpose()
		{
			DenseMatrix denseMatrix = new DenseMatrix(M, N);
			for (int i = 0; i < N; i++)
			{
				for (int j = 0; j < M; j++)
				{
					denseMatrix.d[j * M + i] = d[i * M + j];
				}
			}
			return denseMatrix;
		}

		public void TransposeInPlace()
		{
			if (N != M)
			{
				double[] array = new double[M * N];
				for (int i = 0; i < N; i++)
				{
					for (int j = 0; j < M; j++)
					{
						array[j * M + i] = d[i * M + j];
					}
				}
				d = array;
				int m = M;
				M = N;
				N = m;
				return;
			}
			for (int k = 0; k < N; k++)
			{
				for (int l = 0; l < M; l++)
				{
					if (l != k)
					{
						int num = k * M + l;
						int num2 = l * M + k;
						double num3 = d[num];
						d[num] = d[num2];
						d[num2] = num3;
					}
				}
			}
		}

		public bool IsSymmetric(double dTolerance = 2.220446049250313E-16)
		{
			if (M != N)
			{
				throw new Exception("DenseMatrix.IsSymmetric: matrix is not square!");
			}
			for (int i = 0; i < N; i++)
			{
				for (int j = 0; j < i; j++)
				{
					if (Math.Abs(d[i * M + j] - d[j * M + i]) > dTolerance)
					{
						return false;
					}
				}
			}
			return true;
		}

		public bool IsPositiveDefinite()
		{
			if (M != N)
			{
				throw new Exception("DenseMatrix.IsPositiveDefinite: matrix is not square!");
			}
			if (!IsSymmetric())
			{
				throw new Exception("DenseMatrix.IsPositiveDefinite: matrix is not symmetric!");
			}
			for (int i = 0; i < N; i++)
			{
				double num = d[i * M + i];
				double num2 = 0.0;
				for (int j = 0; j < N; j++)
				{
					if (j != i)
					{
						num2 += Math.Abs(d[i * M + j]);
					}
				}
				if (num < 0.0 || num < num2)
				{
					return false;
				}
			}
			return true;
		}

		public bool EpsilonEquals(DenseMatrix m2, double epsilon = 1E-08)
		{
			if (N != m2.N || M != m2.M)
			{
				throw new Exception("DenseMatrix.Equals: matrices are not the same size!");
			}
			for (int i = 0; i < d.Length; i++)
			{
				if (Math.Abs(d[i] - m2.d[i]) > epsilon)
				{
					return false;
				}
			}
			return true;
		}

		public DenseVector Multiply(DenseVector X)
		{
			DenseVector denseVector = new DenseVector(X.Length);
			Multiply(X.Buffer, denseVector.Buffer);
			return denseVector;
		}

		public void Multiply(DenseVector X, DenseVector R)
		{
			Multiply(X.Buffer, R.Buffer);
		}

		public void Multiply(double[] X, double[] Result)
		{
			for (int i = 0; i < N; i++)
			{
				Result[i] = 0.0;
				int num = i * M;
				for (int j = 0; j < M; j++)
				{
					Result[i] += d[num + j] * X[j];
				}
			}
		}

		public void Add(DenseMatrix M2)
		{
			if (N != M2.N || M != M2.M)
			{
				throw new Exception("DenseMatrix.Add: matrices have incompatible dimensions");
			}
			for (int i = 0; i < d.Length; i++)
			{
				d[i] += M2.d[i];
			}
		}

		public void Add(IMatrix M2)
		{
			if (N != M2.Rows || M != M2.Columns)
			{
				throw new Exception("DenseMatrix.Add: matrices have incompatible dimensions");
			}
			for (int i = 0; i < N; i++)
			{
				for (int j = 0; j < M; j++)
				{
					d[i * M + j] += M2[i, j];
				}
			}
		}

		public void MulAdd(DenseMatrix M2, double s)
		{
			if (N != M2.N || M != M2.M)
			{
				throw new Exception("DenseMatrix.MulAdd: matrices have incompatible dimensions");
			}
			for (int i = 0; i < d.Length; i++)
			{
				d[i] += s * M2.d[i];
			}
		}

		public void MulAdd(IMatrix M2, double s)
		{
			if (N != M2.Rows || M != M2.Columns)
			{
				throw new Exception("DenseMatrix.MulAdd: matrices have incompatible dimensions");
			}
			for (int i = 0; i < N; i++)
			{
				for (int j = 0; j < M; j++)
				{
					d[i * M + j] += s * M2[i, j];
				}
			}
		}

		public DenseMatrix Multiply(DenseMatrix M2, bool bParallel = true)
		{
			DenseMatrix R = new DenseMatrix(Rows, M2.Columns);
			Multiply(M2, ref R, bParallel);
			return R;
		}

		public void Multiply(DenseMatrix M2, ref DenseMatrix R, bool bParallel = true)
		{
			int n = N;
			int cols1 = M;
			int n2 = M2.N;
			int cols2 = M2.M;
			if (cols1 != n2)
			{
				throw new Exception("DenseMatrix.Multiply: matrices have incompatible dimensions");
			}
			if (R == null)
			{
				R = new DenseMatrix(Rows, M2.Columns);
			}
			if (R.Rows != n || R.Columns != cols2)
			{
				throw new Exception("DenseMatrix.Multiply: Result matrix has incorrect dimensions");
			}
			if (bParallel)
			{
				DenseMatrix Rt = R;
				gParallel.ForEach(Interval1i.Range(0, n), delegate(int r1i)
				{
					int num6 = r1i * M;
					for (int i = 0; i < cols2; i++)
					{
						double num7 = 0.0;
						for (int j = 0; j < cols1; j++)
						{
							num7 += d[num6 + j] * M2.d[j * M + i];
						}
						Rt[num6 + i] = num7;
					}
				});
				return;
			}
			for (int num = 0; num < n; num++)
			{
				int num2 = num * M;
				for (int num3 = 0; num3 < cols2; num3++)
				{
					double num4 = 0.0;
					for (int num5 = 0; num5 < cols1; num5++)
					{
						num4 += d[num2 + num5] * M2.d[num5 * M + num3];
					}
					R[num2 + num3] = num4;
				}
			}
		}
	}
	public class DenseVector
	{
		private double[] d;

		private int N;

		public int Size => N;

		public int Length => N;

		public double this[int i]
		{
			get
			{
				return d[i];
			}
			set
			{
				d[i] = value;
			}
		}

		public double[] Buffer => d;

		public DenseVector(int N)
		{
			d = new double[N];
			Array.Clear(d, 0, d.Length);
			this.N = N;
		}

		public void Set(int i, double value)
		{
			d[i] = value;
		}

		public double Dot(DenseVector v2)
		{
			return Dot(v2.d);
		}

		public double Dot(double[] v2)
		{
			if (v2.Length != N)
			{
				throw new Exception("DenseVector.Dot: incompatible lengths");
			}
			double num = 0.0;
			for (int i = 0; i < v2.Length; i++)
			{
				num += d[i] * v2[i];
			}
			return num;
		}
	}
	public class FastQuaternionSVD
	{
		private int NumJacobiIterations = 4;

		public Quaterniond U;

		public Quaterniond V;

		public Vector3d S;

		private SymmetricMatrix3d ATA;

		private double[] AV;

		private const double gamma = 5.82842712474619;

		private const double sinBackup = 0.3826834323650897;

		private const double cosBackup = 0.9238795325112867;

		public FastQuaternionSVD()
		{
		}

		public FastQuaternionSVD(Matrix3d matrix, double epsilon = 2.220446049250313E-16, int jacobiIters = 4)
		{
			Solve(matrix, epsilon, jacobiIters);
		}

		public void Solve(Matrix3d matrix, double epsilon = 2.220446049250313E-16, int jacobiIters = -1)
		{
			if (jacobiIters != -1)
			{
				NumJacobiIterations = jacobiIters;
			}
			if (ATA == null)
			{
				ATA = new SymmetricMatrix3d();
			}
			ATA.SetATA(ref matrix);
			Vector4d V = jacobiDiagonalize(ATA);
			if (AV == null)
			{
				AV = new double[9];
			}
			computeAV(ref matrix, ref V, AV);
			Vector4d U = Vector4d.Zero;
			QRFactorize(AV, ref V, epsilon, ref S, ref U);
			this.U = new Quaterniond(U[1], U[2], U[3], U[0]);
			this.V = new Quaterniond(V[1], V[2], V[3], V[0]);
		}

		public Matrix3d ReconstructMatrix()
		{
			Matrix3d matrix3d = new Matrix3d(S[0], S[1], S[2]);
			return U.ToRotationMatrix() * matrix3d * V.Conjugate().ToRotationMatrix();
		}

		private Vector4d jacobiDiagonalize(SymmetricMatrix3d ATA)
		{
			Vector4d lhs = new Vector4d(1.0, 0.0, 0.0, 0.0);
			for (int i = 0; i < NumJacobiIterations; i++)
			{
				Vector2d vector2d = givensAngles(ATA, 0, 1);
				ATA.quatConjugate01(vector2d.x, vector2d.y);
				quatTimesEqualCoordinateAxis(ref lhs, vector2d.x, vector2d.y, 2);
				vector2d = givensAngles(ATA, 1, 2);
				ATA.quatConjugate12(vector2d.x, vector2d.y);
				quatTimesEqualCoordinateAxis(ref lhs, vector2d.x, vector2d.y, 0);
				vector2d = givensAngles(ATA, 0, 2);
				ATA.quatConjugate02(vector2d.x, vector2d.y);
				quatTimesEqualCoordinateAxis(ref lhs, vector2d.x, vector2d.y, 1);
			}
			return lhs;
		}

		private Vector2d givensAngles(SymmetricMatrix3d B, int p, int q)
		{
			double num = 0.0;
			double num2 = 0.0;
			switch (p)
			{
			case 0:
				if (q == 1)
				{
					num = B.entries[p] - B.entries[q];
					num2 = 0.5 * B.entries[3];
				}
				else
				{
					num = B.entries[q] - B.entries[p];
					num2 = 0.5 * B.entries[4];
				}
				break;
			case 1:
				num = B.entries[p] - B.entries[q];
				num2 = 0.5 * B.entries[5];
				break;
			}
			double num3 = 1.0 / Math.Sqrt(num * num + num2 * num2);
			num *= num3;
			num2 *= num3;
			bool num4 = 5.82842712474619 * num2 * num2 < num * num;
			num = (num4 ? num : 0.9238795325112867);
			num2 = (num4 ? num2 : 0.3826834323650897);
			return new Vector2d(num, num2);
		}

		private void computeAV(ref Matrix3d matrix, ref Vector4d V, double[] buf)
		{
			Matrix3d matrix3d = new Quaterniond(V[1], V[2], V[3], V[0]).ToRotationMatrix();
			(matrix * matrix3d).ToBuffer(buf);
		}

		private void QRFactorize(double[] AV, ref Vector4d V, double eps, ref Vector3d S, ref Vector4d U)
		{
			permuteColumns(AV, ref V);
			U = new Vector4d(1.0, 0.0, 0.0, 0.0);
			Vector2d vector2d = computeGivensQR(AV, eps, 1, 0);
			givensQTB2(AV, vector2d.x, vector2d.y);
			quatTimesEqualCoordinateAxis(ref U, vector2d.x, vector2d.y, 2);
			Vector2d vector2d2 = computeGivensQR(AV, eps, 2, 0);
			givensQTB1(AV, vector2d2.x, 0.0 - vector2d2.y);
			quatTimesEqualCoordinateAxis(ref U, vector2d2.x, 0.0 - vector2d2.y, 1);
			Vector2d vector2d3 = computeGivensQR(AV, eps, 2, 1);
			givensQTB0(AV, vector2d3.x, vector2d3.y);
			quatTimesEqualCoordinateAxis(ref U, vector2d3.x, vector2d3.y, 0);
			S = new Vector3d(AV[0], AV[4], AV[8]);
		}

		private Vector2d computeGivensQR(double[] B, double eps, int r, int c)
		{
			double num = B[4 * c];
			double num2 = B[3 * r + c];
			double num3 = Math.Sqrt(num * num + num2 * num2);
			double num4 = ((num3 > eps) ? num2 : 0.0);
			double num5 = Math.Abs(num) + Math.Max(num3, eps);
			if (num < 0.0)
			{
				double num6 = num4;
				num4 = num5;
				num5 = num6;
			}
			double num7 = 1.0 / Math.Sqrt(num5 * num5 + num4 * num4);
			num5 *= num7;
			num4 *= num7;
			return new Vector2d(num5, num4);
		}

		private void givensQTB2(double[] B, double ch, double sh)
		{
			double num = ch * ch - sh * sh;
			double num2 = 2.0 * sh * ch;
			double num3 = B[0] * num + B[3] * num2;
			double num4 = B[1] * num + B[4] * num2;
			double num5 = B[2] * num + B[5] * num2;
			double num6 = 0.0;
			double num7 = B[4] * num - B[1] * num2;
			double num8 = B[5] * num - B[2] * num2;
			B[0] = num3;
			B[1] = num4;
			B[2] = num5;
			B[3] = num6;
			B[4] = num7;
			B[5] = num8;
		}

		private void givensQTB1(double[] B, double ch, double sh)
		{
			double num = ch * ch - sh * sh;
			double num2 = 2.0 * sh * ch;
			double num3 = B[0] * num - B[6] * num2;
			double num4 = B[1] * num - B[7] * num2;
			double num5 = B[2] * num - B[8] * num2;
			double num6 = 0.0;
			double num7 = B[1] * num2 + B[7] * num;
			double num8 = B[2] * num2 + B[8] * num;
			B[0] = num3;
			B[1] = num4;
			B[2] = num5;
			B[6] = num6;
			B[7] = num7;
			B[8] = num8;
		}

		private void givensQTB0(double[] B, double ch, double sh)
		{
			double num = ch * ch - sh * sh;
			double num2 = 2.0 * ch * sh;
			double num3 = B[4] * num + B[7] * num2;
			double num4 = B[8] * num - B[5] * num2;
			B[4] = num3;
			B[8] = num4;
		}

		private void quatTimesEqualCoordinateAxis(ref Vector4d lhs, double c, double s, int i)
		{
			double x = lhs.x * c - lhs[i + 1] * s;
			Vector3d vector3d = new Vector3d(c * lhs.y, c * lhs.z, c * lhs.w);
			vector3d[i] += lhs.x * s;
			vector3d[(i + 1) % 3] += s * lhs[1 + (i + 2) % 3];
			vector3d[(i + 2) % 3] -= s * lhs[1 + (i + 1) % 3];
			lhs.x = x;
			lhs.y = vector3d.x;
			lhs.z = vector3d.y;
			lhs.w = vector3d.z;
		}

		private void permuteColumns(double[] B, ref Vector4d V)
		{
			double num = B[0] * B[0] + B[3] * B[3] + B[6] * B[6];
			double num2 = B[1] * B[1] + B[4] * B[4] + B[7] * B[7];
			double num3 = B[2] * B[2] + B[5] * B[5] + B[8] * B[8];
			if (num < num2)
			{
				swapColsNeg(B, 0, 1);
				quatTimesEqualCoordinateAxis(ref V, 0.7071067811865475, 0.7071067811865475, 2);
				double num4 = num;
				num = num2;
				num2 = num4;
			}
			if (num < num3)
			{
				swapColsNeg(B, 0, 2);
				quatTimesEqualCoordinateAxis(ref V, 0.7071067811865475, -0.7071067811865475, 1);
				double num5 = num;
				num = num3;
				num3 = num5;
			}
			if (num2 < num3)
			{
				swapColsNeg(B, 1, 2);
				quatTimesEqualCoordinateAxis(ref V, 0.7071067811865475, 0.7071067811865475, 0);
			}
		}

		private void swapColsNeg(double[] B, int i, int j)
		{
			double num = 0.0 - B[i];
			B[i] = B[j];
			B[j] = num;
			num = 0.0 - B[i + 3];
			B[i + 3] = B[j + 3];
			B[j + 3] = num;
			num = 0.0 - B[i + 6];
			B[i + 6] = B[j + 6];
			B[j + 6] = num;
		}
	}
	internal class SymmetricMatrix3d
	{
		public double[] entries = new double[6];

		public void SetATA(ref Matrix3d A)
		{
			Vector3d vector3d = A.Column(0);
			Vector3d v = A.Column(1);
			Vector3d v2 = A.Column(2);
			entries[0] = vector3d.LengthSquared;
			entries[1] = v.LengthSquared;
			entries[2] = v2.LengthSquared;
			entries[3] = vector3d.Dot(v);
			entries[4] = vector3d.Dot(v2);
			entries[5] = v.Dot(v2);
		}

		public void quatConjugate01(double c, double s)
		{
			double num = c * c - s * s;
			double num2 = 2.0 * s * c;
			double num3 = num2 * num;
			double num4 = num * num;
			double num5 = num2 * num2;
			double num6 = num4 * entries[0] + 2.0 * num3 * entries[3] + num5 * entries[1];
			double num7 = num5 * entries[0] - 2.0 * num3 * entries[3] + num4 * entries[1];
			double num8 = entries[3] * (num4 - num5) + num3 * (entries[1] - entries[0]);
			double num9 = num * entries[4] + num2 * entries[5];
			double num10 = num * entries[5] - num2 * entries[4];
			entries[0] = num6;
			entries[1] = num7;
			entries[3] = num8;
			entries[4] = num9;
			entries[5] = num10;
		}

		public void quatConjugate02(double c, double s)
		{
			double num = c * c - s * s;
			double num2 = 2.0 * s * c;
			double num3 = num2 * num;
			double num4 = num * num;
			double num5 = num2 * num2;
			double num6 = num4 * entries[0] - 2.0 * num3 * entries[4] + num5 * entries[2];
			double num7 = num5 * entries[0] + 2.0 * num3 * entries[4] + num4 * entries[2];
			double num8 = num * entries[3] - num2 * entries[5];
			double num9 = num3 * (entries[0] - entries[2]) + (num4 - num5) * entries[4];
			double num10 = num2 * entries[3] + num * entries[5];
			entries[0] = num6;
			entries[2] = num7;
			entries[3] = num8;
			entries[4] = num9;
			entries[5] = num10;
		}

		public void quatConjugate12(double c, double s)
		{
			double num = c * c - s * s;
			double num2 = 2.0 * s * c;
			double num3 = num2 * num;
			double num4 = num * num;
			double num5 = num2 * num2;
			double num6 = num4 * entries[1] + 2.0 * num3 * entries[5] + num5 * entries[2];
			double num7 = num5 * entries[1] - 2.0 * num3 * entries[5] + num4 * entries[2];
			double num8 = num * entries[3] + num2 * entries[4];
			double num9 = (0.0 - num2) * entries[3] + num * entries[4];
			double num10 = (num4 - num5) * entries[5] + num3 * (entries[2] - entries[1]);
			entries[1] = num6;
			entries[2] = num7;
			entries[3] = num8;
			entries[4] = num9;
			entries[5] = num10;
		}
	}
