		public double this[int r, int c]
		{
			get
			{
				nonzero[] array = Rows[r];
				int num = array.Length;
				for (int i = 0; i < num; i++)
				{
					if (array[i].j == c)
					{
						return array[i].d;
					}
				}
				return 0.0;
			}
			set
			{
				nonzero[] array = Rows[r];
				int num = array.Length;
				for (int i = 0; i < num; i++)
				{
					if (array[i].j == c)
					{
						array[i].d = value;
						return;
					}
				}
				throw new Exception("PackedSparseMatrix[r,c]: value at index " + r + "," + c + " does not exist!");
			}
		}

		public double FrobeniusNorm
		{
			get
			{
				double num = 0.0;
				for (int i = 0; i < Rows.Length; i++)
				{
					nonzero[] array = Rows[i];
					for (int j = 0; j < array.Length; j++)
					{
						num += array[j].d * array[j].d;
					}
				}
				return Math.Sqrt(num);
			}
		}

		public double MaxNorm
		{
			get
			{
				double num = 0.0;
				for (int i = 0; i < Rows.Length; i++)
				{
					nonzero[] array = Rows[i];
					for (int j = 0; j < array.Length; j++)
					{
						if (array[j].d > num)
						{
							num = array[j].d;
						}
					}
				}
				return num;
			}
		}

		public double Trace
		{
			get
			{
				double num = 0.0;
				for (int i = 0; i < Rows.Length; i++)
				{
					nonzero[] array = Rows[i];
					for (int j = 0; j < array.Length; j++)
					{
						if (array[j].j == i)
						{
							num += array[j].d;
						}
					}
				}
				return num;
			}
		}

		public PackedSparseMatrix(PackedSparseMatrix copy)
		{
			int num = copy.Rows.Length;
			Rows = new nonzero[num][];
			for (int i = 0; i < num; i++)
			{
				Rows[i] = new nonzero[copy.Rows[i].Length];
				Array.Copy(copy.Rows[i], Rows[i], Rows[i].Length);
			}
			Columns = copy.Columns;
			Sorted = copy.Sorted;
			NumNonZeros = copy.NumNonZeros;
			StorageMode = copy.StorageMode;
			IsSymmetric = copy.IsSymmetric;
		}

		public PackedSparseMatrix(SymmetricSparseMatrix m, bool bTranspose = false)
		{
			int num = (bTranspose ? m.Columns : m.Rows);
			Columns = (bTranspose ? m.Columns : m.Rows);
			Rows = new nonzero[num][];
			int[] array = new int[num];
			foreach (Index2i item in m.NonZeroIndices())
			{
				array[item.a]++;
				if (item.a != item.b)
				{
					array[item.b]++;
				}
			}
			NumNonZeros = 0;
			for (int i = 0; i < num; i++)
			{
				Rows[i] = new nonzero[array[i]];
				NumNonZeros += array[i];
			}
			int[] array2 = new int[num];
			foreach (KeyValuePair<Index2i, double> item2 in m.NonZeros())
			{
				int num2 = item2.Key.a;
				int num3 = item2.Key.b;
				if (bTranspose)
				{
					int num4 = num2;
					num2 = num3;
					num3 = num4;
				}
				int num5 = array2[num2]++;
				Rows[num2][num5].j = num3;
				Rows[num2][num5].d = item2.Value;
				if (num2 != num3)
				{
					num5 = array2[num3]++;
					Rows[num3][num5].j = num2;
					Rows[num3][num5].d = item2.Value;
				}
			}
			Sorted = false;
			IsSymmetric = true;
			StorageMode = StorageModes.Full;
		}

		public PackedSparseMatrix(DVector<matrix_entry> entries, int numRows, int numCols, bool bSymmetric = true)
		{
			Columns = numCols;
			Rows = new nonzero[numRows][];
			int size = entries.size;
			int[] array = new int[numRows];
			for (int i = 0; i < size; i++)
			{
				array[entries[i].r]++;
				if (bSymmetric && entries[i].r != entries[i].c)
				{
					array[entries[i].c]++;
				}
			}
			NumNonZeros = 0;
			for (int j = 0; j < numRows; j++)
			{
				Rows[j] = new nonzero[array[j]];
				NumNonZeros += array[j];
			}
			int[] array2 = new int[numRows];
			for (int k = 0; k < size; k++)
			{
				matrix_entry matrix_entry2 = entries[k];
				int num = array2[matrix_entry2.r]++;
				Rows[matrix_entry2.r][num].j = matrix_entry2.c;
				Rows[matrix_entry2.r][num].d = matrix_entry2.value;
				if (bSymmetric && matrix_entry2.c != matrix_entry2.r)
				{
					num = array2[matrix_entry2.c]++;
					Rows[matrix_entry2.c][num].j = matrix_entry2.r;
					Rows[matrix_entry2.c][num].d = matrix_entry2.value;
				}
			}
			Sorted = false;
			IsSymmetric = bSymmetric;
			StorageMode = StorageModes.Full;
		}

		public static PackedSparseMatrix FromDense(DenseMatrix m, bool bSymmetric)
		{
			DVector<matrix_entry> dVector = new DVector<matrix_entry>();
			for (int i = 0; i < m.Rows; i++)
			{
				int num = (bSymmetric ? (i + 1) : m.Columns);
				for (int j = 0; j < num; j++)
				{
					if (m[i, j] != 0.0)
					{
						dVector.Add(new matrix_entry
						{
							r = i,
							c = j,
							value = m[i, j]
						});
					}
				}
			}
			return new PackedSparseMatrix(dVector, m.Rows, m.Columns, bSymmetric);
		}

		public void Sort(bool bParallel = true)
		{
			if (bParallel)
			{
				gParallel.BlockStartEnd(0, Rows.Length - 1, delegate(int a, int b)
				{
					for (int i = a; i <= b; i++)
					{
						Array.Sort(Rows[i], (nonzero x, nonzero y) => x.j.CompareTo(y.j));
					}
				});
			}
			else
			{
				for (int num = 0; num < Rows.Length; num++)
				{
					Array.Sort(Rows[num], (nonzero x, nonzero y) => x.j.CompareTo(y.j));
				}
			}
			Sorted = true;
		}

		public Interval1i NonZerosRange(int r)
		{
			nonzero[] array = Rows[r];
			if (array.Length == 0)
			{
				return Interval1i.Empty;
			}
			if (!Sorted)
			{
				Interval1i empty = Interval1i.Empty;
				for (int i = 0; i < array.Length; i++)
				{
					empty.Contain(array[i].j);
				}
				return empty;
			}
			return new Interval1i(array[0].j, array[^1].j);
		}

		public IEnumerable<Vector2i> NonZeroIndicesByRow(bool bWantSorted = true)
		{
			if (bWantSorted && !Sorted)
			{
				throw new Exception("PackedSparseMatrix.NonZeroIndicesByRow: sorting requested but not available");
			}
			int N = Rows.Length;
			int r = 0;
			while (r < N)
			{
				nonzero[] Row = Rows[r];
				int num;
				for (int i = 0; i < Row.Length; i = num)
				{
					yield return new Vector2i(r, Row[i].j);
					num = i + 1;
				}
				num = r + 1;
				r = num;
			}
		}

		public IEnumerable<Vector2i> NonZeroIndicesForRow(int r, bool bWantSorted = true)
		{
			if (bWantSorted && !Sorted)
			{
				throw new Exception("PackedSparseMatrix.NonZeroIndicesByRow: sorting requested but not available");
			}
			nonzero[] Row = Rows[r];
			int i = 0;
			while (i < Row.Length)
			{
				yield return new Vector2i(r, Row[i].j);
				int num = i + 1;
				i = num;
			}
		}

		public void Multiply(double[] X, double[] Result)
		{
			Array.Clear(Result, 0, Result.Length);
			for (int i = 0; i < Rows.Length; i++)
			{
				int num = Rows[i].Length;
				for (int j = 0; j < num; j++)
				{
					int j2 = Rows[i][j].j;
					Result[i] += Rows[i][j].d * X[j2];
				}
			}
		}

		public void Multiply_Parallel(double[] X, double[] Result)
		{
			gParallel.BlockStartEnd(0, Rows.Length - 1, delegate(int i_start, int i_end)
			{
				for (int i = i_start; i <= i_end; i++)
				{
					Result[i] = 0.0;
					nonzero[] array = Rows[i];
					int num = array.Length;
					for (int j = 0; j < num; j++)
					{
						Result[i] += array[j].d * X[array[j].j];
					}
				}
			});
		}

		public void Multiply_Parallel_3(double[][] X, double[][] Result)
		{
			_ = X.Length;
			gParallel.BlockStartEnd(0, Rows.Length - 1, delegate(int i_start, int i_end)
			{
				for (int i = i_start; i <= i_end; i++)
				{
					Result[0][i] = (Result[1][i] = (Result[2][i] = 0.0));
					nonzero[] array = Rows[i];
					int num = array.Length;
					for (int j = 0; j < num; j++)
					{
						int j2 = array[j].j;
						double d = array[j].d;
						Result[0][i] += d * X[0][j2];
						Result[1][i] += d * X[1][j2];
						Result[2][i] += d * X[2][j2];
					}
				}
			});
		}

		public double DotRowColumn(int r, int c, PackedSparseMatrix MTranspose)
		{
			if (!Sorted || !MTranspose.Sorted)
			{
				throw new Exception("PackedSparseMatrix.DotRowColumn: matrices must be sorted!");
			}
			if (Rows.Length != MTranspose.Rows.Length)
			{
				throw new Exception("PackedSparseMatrix.DotRowColumn: matrices are not the same size!");
			}
			int num = 0;
			int num2 = 0;
			nonzero[] array = Rows[r];
			nonzero[] array2 = MTranspose.Rows[c];
			int num3 = array.Length;
			int num4 = array2.Length;
			int j = array2[num4 - 1].j;
			int j2 = array[num3 - 1].j;
			double num5 = 0.0;
			while (num < num3 && num2 < num4 && array[num].j <= j && array2[num2].j <= j2)
			{
				if (array[num].j == array2[num2].j)
				{
					num5 += array[num].d * array2[num2].d;
					num++;
					num2++;
				}
				else if (array[num].j < array2[num2].j)
				{
					num++;
				}
				else
				{
					num2++;
				}
			}
			return num5;
		}

		public double DotRowSelf(int r)
		{
			nonzero[] array = Rows[r];
			double num = 0.0;
			for (int i = 0; i < array.Length; i++)
			{
				num += array[i].d * array[i].d;
			}
			return num;
		}

		public void DotRowAllColumns(int r, double[] sums, int[] col_indices, PackedSparseMatrix MTranspose)
		{
			int num = Rows.Length;
			int i = 0;
			nonzero[] array = Rows[r];
			int num2 = array.Length;
			Array.Clear(sums, 0, num);
			Array.Clear(col_indices, 0, num);
			for (; i < num2; i++)
			{
				int j = array[i].j;
				for (int k = 0; k < num; k++)
				{
					nonzero[] array2 = MTranspose.Rows[k];
					int l = col_indices[k];
					if (l < array2.Length)
					{
						for (; l < array2.Length && array2[l].j < j; l++)
						{
						}
						if (l < array2.Length && j == array2[l].j)
						{
							sums[k] += array[i].d * array2[l].d;
							l++;
						}
						col_indices[k] = l;
					}
				}
			}
		}

		public double DotRows(int r1, int r2, int MaxCol = int.MaxValue)
		{
			if (!Sorted)
			{
				throw new Exception("PackedSparseMatrix.DotRows: matrices must be sorted!");
			}
			MaxCol = Math.Min(MaxCol, Columns);
			int num = 0;
			int num2 = 0;
			nonzero[] array = Rows[r1];
			nonzero[] array2 = Rows[r2];
			int num3 = array.Length;
			int num4 = array2.Length;
			double num5 = 0.0;
			while (num < num3 && num2 < num4 && array[num].j <= MaxCol && array2[num2].j <= MaxCol)
			{
				if (array[num].j == array2[num2].j)
				{
					num5 += array[num].d * array2[num2].d;
					num++;
					num2++;
				}
				else if (array[num].j < array2[num2].j)
				{
					num++;
				}
				else
				{
					num2++;
				}
			}
			return num5;
		}

		public double DotRowVector(int r, double[] vec, int MaxCol = int.MaxValue)
		{
			if (!Sorted && MaxCol < int.MaxValue)
			{
				throw new Exception("PackedSparseMatrix.DotRows: matrices must be sorted if MaxCol is specified!");
			}
			MaxCol = Math.Min(MaxCol, Columns);
			nonzero[] array = Rows[r];
			double num = 0.0;
			for (int i = 0; i < array.Length && array[i].j <= MaxCol; i++)
			{
				num += array[i].d * vec[array[i].j];
			}
			return num;
		}

		public double DotColumnVector(int c, double[] vec, int start_row = 0, int end_row = int.MaxValue)
		{
			_ = Rows.Length;
			double num = 0.0;
			if (Sorted)
			{
				for (int i = start_row; i <= end_row; i++)
				{
					nonzero[] array = Rows[i];
					for (int j = 0; j < array.Length; j++)
					{
						if (array[j].j == c)
						{
							num += array[j].d * vec[i];
							break;
						}
						if (array[j].j > c)
						{
							break;
						}
					}
				}
			}
			else
			{
				for (int k = start_row; k <= end_row; k++)
				{
					nonzero[] array2 = Rows[k];
					for (int l = 0; l < array2.Length; l++)
					{
						if (array2[l].j == c)
						{
							num += array2[l].d * vec[k];
							break;
						}
					}
				}
			}
			return num;
		}

		public PackedSparseMatrix Square()
		{
			if (Rows.Length != Columns)
			{
				throw new Exception("PackedSparseMatrix.Square: matrix is not square!");
			}
			int columns = Columns;
			DVector<matrix_entry> entries = new DVector<matrix_entry>();
			SpinLock entries_lock = default(SpinLock);
			gParallel.BlockStartEnd(0, columns - 1, delegate(int r_start, int r_end)
			{
				for (int i = r_start; i <= r_end; i++)
				{
					HashSet<int> hashSet = new HashSet<int> { i };
					nonzero[] array = Rows[i];
					for (int j = 0; j < array.Length; j++)
					{
						if (array[j].j > i)
						{
							hashSet.Add(array[j].j);
						}
						nonzero[] array2 = Rows[array[j].j];
						for (int k = 0; k < array2.Length; k++)
						{
							if (array2[k].j > i)
							{
								hashSet.Add(array2[k].j);
							}
						}
					}
					foreach (int item in hashSet)
					{
						double value = DotRowColumn(i, item, this);
						if (Math.Abs(value) > 1E-08)
						{
							bool lockTaken = false;
							entries_lock.Enter(ref lockTaken);
							entries.Add(new matrix_entry
							{
								r = i,
								c = item,
								value = value
							});
							entries_lock.Exit();
						}
					}
				}
			});
			return new PackedSparseMatrix(entries, columns, columns);
		}

		public string MatrixInfo(bool bExtended = false)
		{
			string text = $"Rows {Rows.Length}  Cols {Columns}   NonZeros {NumNonZeros}  Sorted {Sorted}";
			if (bExtended)
			{
				double num = 0.0;
				nonzero[][] rows = Rows;
				foreach (nonzero[] array in rows)
				{
					for (int j = 0; j < array.Length; j++)
					{
						nonzero nonzero2 = array[j];
						num += nonzero2.d;
					}
				}
				text += $"  Sum {num}  Frobenius {FrobeniusNorm}  Max {MaxNorm}  Trace {Trace}";
			}
			return text;
		}
	}
	public class SingularValueDecomposition
	{
		private struct GivensRotation(int inIndex0, int inIndex1, double inCs, double inSn)
		{
			public int index0 = inIndex0;

			public int index1 = inIndex1;

			public double cs = inCs;

			public double sn = inSn;
		}

		private int mNumRows;

		private int mNumCols;

		private int mMaxIterations;

		private double[] mMatrix;

		private double[] mDiagonal;

		private double[] mSuperdiagonal;

		private List<GivensRotation> mRGivens;

		private List<GivensRotation> mLGivens;

		private double[] mFixupDiagonal;

		private int[] mPermutation;

		private int[] mVisited;

		private double[] mTwoInvUTU;

		private double[] mTwoInvVTV;

		private double[] mUVector;

		private double[] mVVector;

		private double[] mWVector;

		public SingularValueDecomposition(int numRows, int numCols, int maxIterations)
		{
			mNumRows = (mNumCols = (mMaxIterations = 0));
			if (numCols > 1 && numRows >= numCols && maxIterations > 0)
			{
				mNumRows = numRows;
				mNumCols = numCols;
				mMaxIterations = maxIterations;
				mMatrix = new double[numRows * numCols];
				mDiagonal = new double[numCols];
				mSuperdiagonal = new double[numCols - 1];
				mRGivens = new List<GivensRotation>(maxIterations * (numCols - 1));
				mLGivens = new List<GivensRotation>(maxIterations * (numCols - 1));
				mFixupDiagonal = new double[numCols];
				mPermutation = new int[numCols];
				mVisited = new int[numCols];
				mTwoInvUTU = new double[numCols];
				mTwoInvVTV = new double[numCols - 2];
				mUVector = new double[numRows];
				mVVector = new double[numCols];
				mWVector = new double[numRows];
			}
		}

		public uint Solve(double[] input, int sortType = -1)
		{
			if (mNumRows > 0)
			{
				int num = mNumRows * mNumCols;
				Array.Copy(input, mMatrix, num);
				Bidiagonalize();
				double num2 = Math.Abs(input[0]);
				for (int i = 1; i < num; i++)
				{
					double num3 = Math.Abs(input[i]);
					if (num3 > num2)
					{
						num2 = num3;
					}
				}
				double num4 = 0.0;
				if (num2 > 0.0)
				{
					double num5 = 1.0 / num2;
					for (int j = 0; j < num; j++)
					{
						double num6 = input[j] * num5;
						num4 += num6 * num6;
					}
					num4 = num2 * Math.Sqrt(num4);
				}
				double num7 = double.Epsilon;
				double threshold = 8.0 * num7 * num4;
				mRGivens.Clear();
				mLGivens.Clear();
				for (uint num8 = 0u; num8 < mMaxIterations; num8++)
				{
					int num9 = -1;
					int num10 = -1;
					for (int num11 = mNumCols - 2; num11 >= 0; num11--)
					{
						double value = mDiagonal[num11];
						double value2 = mSuperdiagonal[num11];
						double value3 = mDiagonal[num11 + 1];
						double num12 = Math.Abs(value) + Math.Abs(value3);
						if (num12 + Math.Abs(value2) != num12)
						{
							if (num10 == -1)
							{
								num10 = num11;
							}
							num9 = num11;
						}
						else if (num9 >= 0)
						{
							break;
						}
					}
					if (num10 == -1)
					{
						EnsureNonnegativeDiagonal();
						ComputePermutation(sortType);
						return num8;
					}
					if (DiagonalEntriesNonzero(num9, num10, threshold))
					{
						DoGolubKahanStep(num9, num10);
					}
				}
				return uint.MaxValue;
			}
			return 0u;
		}

		public void GetSingularValues(double[] singularValues)
		{
			if (singularValues == null || mNumCols <= 0)
			{
				return;
			}
			if (mPermutation[0] >= 0)
			{
				for (int i = 0; i < mNumCols; i++)
				{
					int num = mPermutation[i];
					singularValues[i] = mDiagonal[num];
				}
			}
			else
			{
				for (int j = 0; j < mNumCols; j++)
				{
					singularValues[j] = mDiagonal[j];
				}
			}
		}

		public void GetU(double[] uMatrix)
		{
			if (uMatrix == null || mNumCols == 0)
			{
				return;
			}
			Array.Clear(uMatrix, 0, uMatrix.Length);
			for (int i = 0; i < mNumRows; i++)
			{
				uMatrix[i + mNumRows * i] = 1.0;
			}
			int num = mNumCols - 1;
			int num2 = num + 1;
			while (num >= 0)
			{
				double num3 = mTwoInvUTU[num];
				mUVector[num] = 1.0;
				for (int j = num2; j < mNumRows; j++)
				{
					mUVector[j] = mMatrix[num + mNumCols * j];
				}
				mWVector[num] = num3;
				for (int j = num2; j < mNumRows; j++)
				{
					mWVector[j] = 0.0;
					for (int k = num2; k < mNumRows; k++)
					{
						mWVector[j] += mUVector[k] * uMatrix[j + mNumRows * k];
					}
					mWVector[j] *= num3;
				}
				for (int j = num; j < mNumRows; j++)
				{
					for (int k = num; k < mNumRows; k++)
					{
						uMatrix[k + mNumRows * j] -= mUVector[j] * mWVector[k];
					}
				}
				num--;
				num2--;
			}
			foreach (GivensRotation mLGiven in mLGivens)
			{
				int num4 = mLGiven.index0;
				int num5 = mLGiven.index1;
				int j = 0;
				while (j < mNumRows)
				{
					double num6 = uMatrix[num4];
					double num7 = uMatrix[num5];
					double num8 = mLGiven.cs * num6 - mLGiven.sn * num7;
					double num9 = mLGiven.sn * num6 + mLGiven.cs * num7;
					uMatrix[num4] = num8;
					uMatrix[num5] = num9;
					j++;
					num4 += mNumRows;
					num5 += mNumRows;
				}
			}
			if (mPermutation[0] < 0)
			{
				return;
			}
			Array.Clear(mVisited, 0, mVisited.Length);
			for (int k = 0; k < mNumCols; k++)
			{
				if (mVisited[k] != 0 || mPermutation[k] == k)
				{
					continue;
				}
				int num10 = k;
				int num11 = k;
				for (int j = 0; j < mNumRows; j++)
				{
					mWVector[j] = uMatrix[k + mNumRows * j];
				}
				int num12;
				while ((num12 = mPermutation[num11]) != num10)
				{
					mVisited[num11] = 1;
					for (int j = 0; j < mNumRows; j++)
					{
						uMatrix[num11 + mNumRows * j] = uMatrix[num12 + mNumRows * j];
					}
					num11 = num12;
				}
				mVisited[num11] = 1;
				for (int j = 0; j < mNumRows; j++)
				{
					uMatrix[num11 + mNumRows * j] = mWVector[j];
				}
			}
		}

		public void GetV(double[] vMatrix)
		{
			if (vMatrix == null || mNumCols == 0)
			{
				return;
			}
			Array.Clear(vMatrix, 0, vMatrix.Length);
			for (int i = 0; i < mNumCols; i++)
			{
				vMatrix[i + mNumCols * i] = 1.0;
			}
			int num = mNumCols - 3;
			int num2 = num + 1;
			int num3 = num + 2;
			while (num >= 0)
			{
				double num4 = mTwoInvVTV[num];
				mVVector[num2] = 1.0;
				for (int j = num3; j < mNumCols; j++)
				{
					mVVector[j] = mMatrix[mNumCols * num + j];
				}
				mWVector[num2] = num4;
				for (int j = num3; j < mNumCols; j++)
				{
					mWVector[j] = 0.0;
					for (int k = num3; k < mNumCols; k++)
					{
						mWVector[j] += mVVector[k] * vMatrix[j + mNumCols * k];
					}
					mWVector[j] *= num4;
				}
				for (int j = num2; j < mNumCols; j++)
				{
					for (int k = num2; k < mNumCols; k++)
					{
						vMatrix[k + mNumCols * j] -= mVVector[j] * mWVector[k];
					}
				}
				num--;
				num2--;
				num3--;
			}
			foreach (GivensRotation mRGiven in mRGivens)
			{
				int num5 = mRGiven.index0;
				int num6 = mRGiven.index1;
				int k = 0;
				while (k < mNumCols)
				{
					double num7 = vMatrix[num5];
					double num8 = vMatrix[num6];
					double num9 = mRGiven.cs * num7 - mRGiven.sn * num8;
					double num10 = mRGiven.sn * num7 + mRGiven.cs * num8;
					vMatrix[num5] = num9;
					vMatrix[num6] = num10;
					k++;
					num5 += mNumCols;
					num6 += mNumCols;
				}
			}
			for (int j = 0; j < mNumCols; j++)
			{
				for (int k = 0; k < mNumCols; k++)
				{
					vMatrix[k + mNumCols * j] *= mFixupDiagonal[k];
				}
			}
			if (mPermutation[0] < 0)
			{
				return;
			}
			Array.Clear(mVisited, 0, mVisited.Length);
			for (int k = 0; k < mNumCols; k++)
			{
				if (mVisited[k] != 0 || mPermutation[k] == k)
				{
					continue;
				}
				int num11 = k;
				int num12 = k;
				for (int j = 0; j < mNumCols; j++)
				{
					mWVector[j] = vMatrix[k + mNumCols * j];
				}
				int num13;
				while ((num13 = mPermutation[num12]) != num11)
				{
					mVisited[num12] = 1;
					for (int j = 0; j < mNumCols; j++)
					{
						vMatrix[num12 + mNumCols * j] = vMatrix[num13 + mNumCols * j];
					}
					num12 = num13;
				}
				mVisited[num12] = 1;
				for (int j = 0; j < mNumCols; j++)
				{
					vMatrix[num12 + mNumCols * j] = mWVector[j];
				}
			}
		}

		private void Bidiagonalize()
		{
			int num = 0;
			int num2 = 1;
			while (num < mNumCols)
			{
				double num3 = 0.0;
				for (int i = num; i < mNumRows; i++)
				{
					double num4 = mMatrix[num + mNumCols * i];
					mUVector[i] = num4;
					num3 += num4 * num4;
				}
				double num5 = 1.0;
				num3 = Math.Sqrt(num3);
				if (num3 > 0.0)
				{
					double num6 = mUVector[num];
					double num7 = ((num6 >= 0.0) ? 1.0 : (-1.0));
					double num8 = 1.0 / (num6 + num7 * num3);
					mUVector[num] = 1.0;
					for (int i = num2; i < mNumRows; i++)
					{
						mUVector[i] *= num8;
						num5 += mUVector[i] * mUVector[i];
					}
				}
				double num9 = 1.0 / num5 * 2.0;
				for (int j = num; j < mNumCols; j++)
				{
					mWVector[j] = 0.0;
					for (int i = num; i < mNumRows; i++)
					{
						mWVector[j] += mMatrix[j + mNumCols * i] * mUVector[i];
					}
					mWVector[j] *= num9;
				}
				for (int i = num; i < mNumRows; i++)
				{
					for (int j = num; j < mNumCols; j++)
					{
						mMatrix[j + mNumCols * i] -= mUVector[i] * mWVector[j];
					}
				}
				if (num < mNumCols - 2)
				{
					num3 = 0.0;
					for (int j = num2; j < mNumCols; j++)
					{
						double num10 = mMatrix[j + mNumCols * num];
						mVVector[j] = num10;
						num3 += num10 * num10;
					}
					double num11 = 1.0;
					num3 = Math.Sqrt(num3);
					if (num3 > 0.0)
					{
						double num12 = mVVector[num2];
						double num13 = ((num12 >= 0.0) ? 1.0 : (-1.0));
						double num14 = 1.0 / (num12 + num13 * num3);
						mVVector[num2] = 1.0;
						for (int j = num2 + 1; j < mNumCols; j++)
						{
							mVVector[j] *= num14;
							num11 += mVVector[j] * mVVector[j];
						}
					}
					double num15 = 1.0 / num11 * 2.0;
					for (int i = num; i < mNumRows; i++)
					{
						mWVector[i] = 0.0;
						for (int j = num2; j < mNumCols; j++)
						{
							mWVector[i] += mMatrix[j + mNumCols * i] * mVVector[j];
						}
						mWVector[i] *= num15;
					}
					for (int i = num; i < mNumRows; i++)
					{
						for (int j = num2; j < mNumCols; j++)
						{
							mMatrix[j + mNumCols * i] -= mWVector[i] * mVVector[j];
						}
					}
					mTwoInvVTV[num] = num15;
					for (int j = num + 2; j < mNumCols; j++)
					{
						mMatrix[j + mNumCols * num] = mVVector[j];
					}
				}
				mTwoInvUTU[num] = num9;
				for (int i = num2; i < mNumRows; i++)
				{
					mMatrix[num + mNumCols * i] = mUVector[i];
				}
				num++;
				num2++;
			}
			int num16 = mNumCols - 1;
			int num17 = 0;
			int num18 = mNumCols + 1;
			int num19 = 0;
			while (num19 < num16)
			{
				mDiagonal[num19] = mMatrix[num17];
				mSuperdiagonal[num19] = mMatrix[num17 + 1];
				num19++;
				num17 += num18;
			}
			mDiagonal[num19] = mMatrix[num17];
		}

		private void GetSinCos(double x, double y, out double cs, out double sn)
		{
			if (y != 0.0)
			{
				if (Math.Abs(y) > Math.Abs(x))
				{
					double num = (0.0 - x) / y;
					sn = 1.0 / Math.Sqrt(1.0 + num * num);
					cs = sn * num;
				}
				else
				{
					double num = (0.0 - y) / x;
					cs = 1.0 / Math.Sqrt(1.0 + num * num);
					sn = cs * num;
				}
			}
			else
			{
				cs = 1.0;
				sn = 0.0;
			}
		}

		private bool DiagonalEntriesNonzero(int imin, int imax, double threshold)
		{
			for (int i = imin; i <= imax; i++)
			{
				if (!(Math.Abs(mDiagonal[i]) <= threshold))
				{
					continue;
				}
				double num = mSuperdiagonal[i];
				mSuperdiagonal[i] = 0.0;
				for (int j = i + 1; j <= imax + 1; j++)
				{
					double num2 = mDiagonal[j];
					GetSinCos(num2, num, out var cs, out var sn);
					mLGivens.Add(new GivensRotation(i, j, cs, sn));
					mDiagonal[j] = cs * num2 - sn * num;
					if (j <= imax)
					{
						double num3 = mSuperdiagonal[j];
						mSuperdiagonal[j] = cs * num3;
						num = sn * num3;
					}
				}
				return false;
			}
			return true;
		}

		private void DoGolubKahanStep(int imin, int imax)
		{
			double num = (((double)imax >= 1.0) ? mSuperdiagonal[imax - 1] : 0.0);
			double num2 = mDiagonal[imax];
			double num3 = mSuperdiagonal[imax];
			double num4 = mDiagonal[imax + 1];
			double num5 = num2 * num2 + num * num;
			double num6 = num2 * num3;
			double num7 = num4 * num4 + num3 * num3;
			double num8 = (num5 - num7) * 0.5;
			double num9 = ((num8 >= 0.0) ? 1.0 : (-1.0));
			double num10 = num6 * num6;
			double num11 = num7 - num10 / (num8 + num9 * Math.Sqrt(num8 * num8 + num10));
			double x = mDiagonal[imin] * mDiagonal[imin] - num11;
			double y = mDiagonal[imin] * mSuperdiagonal[imin];
			double num12 = 0.0;
			int num13 = imin - 1;
			int num14 = imin;
			int num15 = imin + 1;
			while (num14 <= imax)
			{
				GetSinCos(x, y, out var cs, out var sn);
				mRGivens.Add(new GivensRotation(num14, num15, cs, sn));
				if (num14 > imin)
				{
					mSuperdiagonal[num13] = cs * mSuperdiagonal[num13] - sn * num12;
				}
				num7 = mDiagonal[num14];
				double num16 = mSuperdiagonal[num14];
				double num17 = mDiagonal[num15];
				mDiagonal[num14] = cs * num7 - sn * num16;
				mSuperdiagonal[num14] = sn * num7 + cs * num16;
				mDiagonal[num15] = cs * num17;
				double num18 = (0.0 - sn) * num17;
				x = mDiagonal[num14];
				y = num18;
				GetSinCos(x, y, out cs, out sn);
				mLGivens.Add(new GivensRotation(num14, num15, cs, sn));
				num7 = mDiagonal[num14];
				num16 = mSuperdiagonal[num14];
				num17 = mDiagonal[num15];
				mDiagonal[num14] = cs * num7 - sn * num18;
				mSuperdiagonal[num14] = cs * num16 - sn * num17;
				mDiagonal[num15] = sn * num16 + cs * num17;
				if (num14 < imax)
				{
					double num19 = mSuperdiagonal[num15];
					num12 = (0.0 - sn) * num19;
					mSuperdiagonal[num15] = cs * num19;
					x = mSuperdiagonal[num14];
					y = num12;
				}
				num13++;
				num14++;
				num15++;
			}
		}

		private void EnsureNonnegativeDiagonal()
		{
			for (int i = 0; i < mNumCols; i++)
			{
				if (mDiagonal[i] >= 0.0)
				{
					mFixupDiagonal[i] = 1.0;
					continue;
				}
				mDiagonal[i] = 0.0 - mDiagonal[i];
				mFixupDiagonal[i] = -1.0;
			}
		}

		private void ComputePermutation(int sortType)
		{
			if (sortType == 0)
			{
				mPermutation[0] = -1;
				return;
			}
			double[] array = new double[mNumCols];
			int[] array2 = new int[mNumCols];
			for (int i = 0; i < mNumCols; i++)
			{
				array[i] = mDiagonal[i];
				array2[i] = i;
			}
			Array.Sort(array, array2);
			if (sortType < 0)
			{
				Array.Reverse(array2);
			}
			mPermutation = array2;
		}
	}
	public class SymmetricSparseMatrix : IMatrix
	{
		private struct mval
		{
			public int k;

			public double v;
		}

		private Dictionary<Index2i, double> d = new Dictionary<Index2i, double>();

		private int N;

		public int Rows => N;

		public int Columns => N;

		public Index2i Size => new Index2i(N, N);

		public double this[int r, int c]
		{
			get
			{
				Index2i key = new Index2i(Math.Min(r, c), Math.Max(r, c));
				if (d.TryGetValue(key, out var value))
				{
					return value;
				}
				return 0.0;
			}
			set
			{
				Set(r, c, value);
			}
		}

		public SymmetricSparseMatrix(int setN = 0)
		{
			N = setN;
		}

		public SymmetricSparseMatrix(DenseMatrix m)
		{
			if (m.Rows != m.Columns)
			{
				throw new Exception("SymmetricSparseMatrix(DenseMatrix): Matrix is not square!");
			}
			if (!m.IsSymmetric())
			{
				throw new Exception("SymmetricSparseMatrix(DenseMatrix): Matrix is not symmetric!");
			}
			N = m.Rows;
			for (int i = 0; i < N; i++)
			{
				for (int j = i; j < N; j++)
				{
					Set(i, j, m[i, j]);
				}
			}
		}

		public SymmetricSparseMatrix(SymmetricSparseMatrix m)
		{
			N = m.N;
			d = new Dictionary<Index2i, double>(m.d);
		}

		public void Set(int r, int c, double value)
		{
			Index2i key = new Index2i(Math.Min(r, c), Math.Max(r, c));
			d[key] = value;
			if (r >= N)
			{
				N = r + 1;
			}
			if (c >= N)
			{
				N = c + 1;
			}
		}

		public void Multiply(double[] X, double[] Result)
		{
			Array.Clear(Result, 0, Result.Length);
			foreach (KeyValuePair<Index2i, double> item in d)
			{
				int a = item.Key.a;
				int b = item.Key.b;
				Result[a] += item.Value * X[b];
				if (a != b)
				{
					Result[b] += item.Value * X[a];
				}
			}
		}

		public SymmetricSparseMatrix Square(bool bParallel = true)
		{
			SymmetricSparseMatrix R = new SymmetricSparseMatrix();
			PackedSparseMatrix M = new PackedSparseMatrix(this);
			M.Sort();
			if (bParallel)
			{
				gParallel.ForEach(Interval1i.Range(N), delegate(int r1i)
				{
					for (int i = r1i; i < N; i++)
					{
						double value2 = M.DotRowColumn(r1i, i, M);
						if (Math.Abs(value2) > 1E-08)
						{
							lock (R)
							{
								R[r1i, i] = value2;
							}
						}
					}
				});
			}
			else
			{
				for (int num = 0; num < N; num++)
				{
					for (int num2 = num; num2 < N; num2++)
					{
						double value = M.DotRowColumn(num, num2, M);
						if (Math.Abs(value) > 1E-08)
						{
							R[num, num2] = value;
						}
					}
				}
			}
			return R;
		}

		public PackedSparseMatrix SquarePackedParallel()
		{
			PackedSparseMatrix packedSparseMatrix = new PackedSparseMatrix(this);
			packedSparseMatrix.Sort();
			return packedSparseMatrix.Square();
		}

		public SymmetricSparseMatrix Multiply(SymmetricSparseMatrix M2)
		{
			SymmetricSparseMatrix R = new SymmetricSparseMatrix();
			Multiply(M2, ref R);
			return R;
		}

		public void Multiply(SymmetricSparseMatrix M2, ref SymmetricSparseMatrix R, bool bParallel = true)
		{
			multiply_fast(M2, ref R, bParallel);
		}

		private void multiply_fast(SymmetricSparseMatrix M2in, ref SymmetricSparseMatrix Rin, bool bParallel)
		{
			int N = Rows;
			if (M2in.Rows != N)
			{
				throw new Exception("SymmetricSparseMatrix.Multiply: matrices have incompatible dimensions");
			}
			if (Rin == null)
			{
				Rin = new SymmetricSparseMatrix();
			}
			SymmetricSparseMatrix R = Rin;
			PackedSparseMatrix M = new PackedSparseMatrix(this);
			M.Sort();
			PackedSparseMatrix M2 = new PackedSparseMatrix(M2in, bTranspose: true);
			M2.Sort();
			if (bParallel)
			{
				gParallel.ForEach(Interval1i.Range(N), delegate(int r1i)
				{
					for (int i = r1i; i < N; i++)
					{
						double value2 = M.DotRowColumn(r1i, i, M2);
						if (Math.Abs(value2) > 1E-08)
						{
							lock (R)
							{
								R[r1i, i] = value2;
							}
						}
					}
				});
				return;
			}
			for (int num = 0; num < N; num++)
			{
				for (int num2 = num; num2 < N; num2++)
				{
					double value = M.DotRowColumn(num, num2, M2);
					if (Math.Abs(value) > 1E-08)
					{
						R[num, num2] = value;
					}
				}
			}
		}

		private void multiply_slow(SymmetricSparseMatrix M2, ref SymmetricSparseMatrix R)
		{
			int rows = Rows;
			if (M2.Rows != rows)
			{
				throw new Exception("SymmetricSparseMatrix.Multiply: matrices have incompatible dimensions");
			}
			if (R == null)
			{
				R = new SymmetricSparseMatrix();
			}
			List<mval> list = new List<mval>(128);
			for (int i = 0; i < rows; i++)
			{
				list.Clear();
				get_row_nonzeros(i, list);
				int count = list.Count;
				for (int j = i; j < rows; j++)
				{
					double num = 0.0;
					for (int k = 0; k < count; k++)
					{
						int k2 = list[k].k;
						num += list[k].v * M2[k2, j];
					}
					if (Math.Abs(num) > 1E-08)
					{
						R[i, j] = num;
					}
				}
			}
		}

		public IEnumerable<KeyValuePair<Index2i, double>> NonZeros()
		{
			return d;
		}

		public IEnumerable<Index2i> NonZeroIndices()
		{
			return d.Keys;
		}

		public bool EpsilonEqual(SymmetricSparseMatrix B, double eps = 2.220446049250313E-16)
		{
			foreach (KeyValuePair<Index2i, double> item in d)
			{
				if (Math.Abs(B[item.Key.a, item.Key.b] - item.Value) > eps)
				{
					return false;
				}
			}
			foreach (KeyValuePair<Index2i, double> item2 in B.d)
			{
				if (Math.Abs(this[item2.Key.a, item2.Key.b] - item2.Value) > eps)
				{
					return false;
				}
			}
			return true;
		}

		private void get_row_nonzeros(int r, List<mval> buf)
		{
			int rows = Rows;
			for (int i = 0; i < rows; i++)
			{
				double num = this[r, i];
				if (num != 0.0)
				{
					buf.Add(new mval
					{
						k = i,
						v = num
					});
				}
			}
		}
	}
	public class DiagonalMatrix
	{
		public double[] D;

		public int Rows => D.Length;

		public int Columns => D.Length;

		public Index2i Size => new Index2i(D.Length, D.Length);

		public double this[int r, int c]
		{
			get
			{
				return D[r];
			}
			set
			{
				Set(r, c, value);
			}
		}

		public DiagonalMatrix(int N)
		{
			D = new double[N];
		}

		public void Clear()
		{
			Array.Clear(D, 0, D.Length);
		}

		public void Set(int r, int c, double value)
		{
			if (r == c)
			{
				D[r] = value;
				return;
			}
			throw new Exception("DiagonalMatrix.Set: tried to set off-diagonal entry!");
		}

		public void Multiply(double[] X, double[] Result)
		{
			for (int i = 0; i < X.Length; i++)
			{
				Result[i] = D[i] * X[i];
			}
		}
	}
	public class SparseSymmetricCG
	{
		public Action<double[], double[]> MultiplyF;

		public Action<double[], double[]> PreconditionMultiplyF;

		public double[] B;

		public double[] X;

		public bool UseXAsInitialGuess = true;

		public int MaxIterations = 1024;

		public int Iterations;

		private double[] R;

		private double[] P;

		private double[] AP;

		private double[] Z;

		public bool Solve()
		{
			Iterations = 0;
			int num = B.Length;
			R = new double[num];
			P = new double[num];
			AP = new double[num];
			if (X == null || !UseXAsInitialGuess)
			{
				if (X == null)
				{
					X = new double[num];
				}
				Array.Clear(X, 0, X.Length);
				Array.Copy(B, R, B.Length);
			}
			else
			{
				InitializeR(R);
			}
			double num2 = Math.Sqrt(BufferUtil.Dot(B, B));
			double num3 = BufferUtil.Dot(R, R);
			if (num3 < 1E-08 * num2)
			{
				return true;
			}
			Array.Copy(R, P, R.Length);
			MultiplyF(P, AP);
			double alpha = num3 / BufferUtil.Dot(P, AP);
			BufferUtil.MultiplyAdd(X, alpha, P);
			BufferUtil.MultiplyAdd(R, 0.0 - alpha, AP);
			double num4 = BufferUtil.Dot(R, R);
			int i;
			for (i = 1; i < MaxIterations; i++)
			{
				if (Math.Sqrt(num4) <= 1E-08 * num2)
				{
					break;
				}
				double beta = num4 / num3;
				UpdateP(P, beta, R);
				MultiplyF(P, AP);
				alpha = num4 / BufferUtil.Dot(P, AP);
				double RdotR = 0.0;
				gParallel.Evaluate(delegate
				{
					BufferUtil.MultiplyAdd(X, alpha, P);
				}, delegate
				{
					RdotR = BufferUtil.MultiplyAdd_GetSqrSum(R, 0.0 - alpha, AP);
				});
				num3 = num4;
				num4 = RdotR;
			}
			Iterations = i;
			return i < MaxIterations;
		}

		private void UpdateP(double[] P, double beta, double[] R)
		{
			for (int i = 0; i < P.Length; i++)
			{
				P[i] = R[i] + beta * P[i];
			}
		}

		private void InitializeR(double[] R)
		{
			MultiplyF(X, R);
			for (int i = 0; i < X.Length; i++)
			{
				R[i] = B[i] - R[i];
			}
		}

		public bool SolvePreconditioned()
		{
			Iterations = 0;
			int n = B.Length;
			R = new double[n];
			P = new double[n];
			AP = new double[n];
			Z = new double[n];
			if (X == null || !UseXAsInitialGuess)
			{
				if (X == null)
				{
					X = new double[n];
				}
				Array.Clear(X, 0, X.Length);
				Array.Copy(B, R, B.Length);
			}
			else
			{
				InitializeR(R);
			}
			double num = Math.Sqrt(BufferUtil.Dot(B, B));
			MultiplyF(X, R);
			for (int i = 0; i < n; i++)
			{
				R[i] = B[i] - R[i];
			}
			PreconditionMultiplyF(R, Z);
			Array.Copy(Z, P, n);
			double RdotZ_k = BufferUtil.Dot(R, Z);
			int num2 = 0;
			while (num2++ < MaxIterations)
			{
				if (Math.Sqrt(RdotZ_k) <= 1E-08 * num)
				{
					break;
				}
				MultiplyF(P, AP);
				double alpha_k = RdotZ_k / BufferUtil.Dot(P, AP);
				gParallel.Evaluate(delegate
				{
					BufferUtil.MultiplyAdd(X, alpha_k, P);
				}, delegate
				{
					BufferUtil.MultiplyAdd(R, 0.0 - alpha_k, AP);
				});
				PreconditionMultiplyF(R, Z);
				double beta_k = BufferUtil.Dot(Z, R) / RdotZ_k;
				gParallel.Evaluate(delegate
				{
					for (int j = 0; j < n; j++)
					{
						P[j] = Z[j] + beta_k * P[j];
					}
				}, delegate
				{
					RdotZ_k = BufferUtil.Dot(R, Z);
				});
			}
			Iterations = num2;
			return num2 < MaxIterations;
		}
	}
	public class SparseSymmetricCGMultipleRHS
	{
		public Action<double[][], double[][]> MultiplyF;

		public Action<double[][], double[][]> PreconditionMultiplyF;

		public double[][] B;

		public double ConvergeTolerance = 1E-08;

		public double[][] X;

		public bool UseXAsInitialGuess = true;

		public int MaxIterations = 1024;

		public int Iterations;

		private double[][] R;

		private double[][] P;

		private double[][] W;

		private double[][] AP;

		private double[][] Z;

		public bool Solve()
		{
			Iterations = 0;
			if (B == null || MultiplyF == null)
			{
				throw new Exception("SparseSymmetricCGMultipleRHS.Solve(): Must set B and MultiplyF!");
			}
			int num = B.Length;
			if (num == 0)
			{
				throw new Exception("SparseSymmetricCGMultipleRHS.Solve(): Need at least one RHS vector in B");
			}
			int num2 = B[0].Length;
			R = BufferUtil.AllocNxM(num, num2);
			P = BufferUtil.AllocNxM(num, num2);
			W = BufferUtil.AllocNxM(num, num2);
			if (X == null || !UseXAsInitialGuess)
			{
				if (X == null)
				{
					X = BufferUtil.AllocNxM(num, num2);
				}
				for (int i = 0; i < num; i++)
				{
					Array.Clear(X[i], 0, num2);
					Array.Copy(B[i], R[i], num2);
				}
			}
			else
			{
				InitializeR(R);
			}
			double[] array = new double[num];
			for (int j = 0; j < num; j++)
			{
				array[j] = BufferUtil.Dot(B[j], B[j]);
			}
			double[] array2 = new double[num];
			for (int k = 0; k < num; k++)
			{
				array2[k] = Math.Sqrt(array[k]);
			}
			double[] rho0 = new double[num];
			for (int l = 0; l < num; l++)
			{
				rho0[l] = BufferUtil.Dot(R[l], R[l]);
			}
			bool[] converged = new bool[num];
			int num3 = 0;
			for (int m = 0; m < num; m++)
			{
				converged[m] = rho0[m] < ConvergeTolerance * array2[m];
				if (converged[m])
				{
					num3++;
				}
			}
			if (num3 == num)
			{
				return true;
			}
			for (int n = 0; n < num; n++)
			{
				Array.Copy(R[n], P[n], num2);
			}
			MultiplyF(P, W);
			double[] alpha = new double[num];
			for (int num4 = 0; num4 < num; num4++)
			{
				alpha[num4] = rho0[num4] / BufferUtil.Dot(P[num4], W[num4]);
			}
			for (int num5 = 0; num5 < num; num5++)
			{
				BufferUtil.MultiplyAdd(X[num5], alpha[num5], P[num5]);
			}
			for (int num6 = 0; num6 < num; num6++)
			{
				BufferUtil.MultiplyAdd(R[num6], 0.0 - alpha[num6], W[num6]);
			}
			double[] rho1 = new double[num];
			for (int num7 = 0; num7 < num; num7++)
			{
				rho1[num7] = BufferUtil.Dot(R[num7], R[num7]);
			}
			double[] array3 = new double[num];
			Interval1i interval1i = Interval1i.Range(num);
			int num8;
			for (num8 = 1; num8 < MaxIterations; num8++)
			{
				bool flag = true;
				for (int num9 = 0; num9 < num; num9++)
				{
					if (!converged[num9] && Math.Sqrt(rho1[num9]) <= ConvergeTolerance * array2[num9])
					{
						converged[num9] = true;
					}
					if (!converged[num9])
					{
						flag = false;
					}
				}
				if (flag)
				{
					break;
				}
				for (int num10 = 0; num10 < num; num10++)
				{
					array3[num10] = rho1[num10] / rho0[num10];
				}
				UpdateP(P, array3, R, converged);
				MultiplyF(P, W);
				gParallel.ForEach(interval1i, delegate(int num11)
				{
					if (!converged[num11])
					{
						alpha[num11] = rho1[num11] / BufferUtil.Dot(P[num11], W[num11]);
					}
				});
				gParallel.ForEach(interval1i, delegate(int num11)
				{
					if (!converged[num11])
					{
						BufferUtil.MultiplyAdd(X[num11], alpha[num11], P[num11]);
					}
				});
				gParallel.ForEach(interval1i, delegate(int num11)
				{
					if (!converged[num11])
					{
						rho0[num11] = rho1[num11];
						rho1[num11] = BufferUtil.MultiplyAdd_GetSqrSum(R[num11], 0.0 - alpha[num11], W[num11]);
					}
				});
			}
			Iterations = num8;
			return num8 < MaxIterations;
		}

		public bool SolvePreconditioned()
		{
			Iterations = 0;
			if (B == null || MultiplyF == null || PreconditionMultiplyF == null)
			{
				throw new Exception("SparseSymmetricCGMultipleRHS.SolvePreconditioned(): Must set B and MultiplyF and PreconditionMultiplyF!");
			}
			int num = B.Length;
			if (num == 0)
			{
				throw new Exception("SparseSymmetricCGMultipleRHS.SolvePreconditioned(): Need at least one RHS vector in B");
			}
			int n = B[0].Length;
			R = BufferUtil.AllocNxM(num, n);
			P = BufferUtil.AllocNxM(num, n);
			AP = BufferUtil.AllocNxM(num, n);
			Z = BufferUtil.AllocNxM(num, n);
			if (X == null || !UseXAsInitialGuess)
			{
				if (X == null)
				{
					X = BufferUtil.AllocNxM(num, n);
				}
				for (int i = 0; i < num; i++)
				{
					Array.Clear(X[i], 0, n);
					Array.Copy(B[i], R[i], n);
				}
			}
			else
			{
				InitializeR(R);
			}
			double[] array = new double[num];
			for (int j = 0; j < num; j++)
			{
				array[j] = BufferUtil.Dot(B[j], B[j]);
			}
			double[] array2 = new double[num];
			for (int k = 0; k < num; k++)
			{
				array2[k] = Math.Sqrt(array[k]);
			}
			MultiplyF(X, R);
			for (int l = 0; l < num; l++)
			{
				for (int m = 0; m < n; m++)
				{
					R[l][m] = B[l][m] - R[l][m];
				}
			}
			PreconditionMultiplyF(R, Z);
			for (int num2 = 0; num2 < num; num2++)
			{
				Array.Copy(Z[num2], P[num2], n);
			}
			double[] RdotZ_k = new double[num];
			for (int num3 = 0; num3 < num; num3++)
			{
				RdotZ_k[num3] = BufferUtil.Dot(R[num3], Z[num3]);
			}
			double[] alpha_k = new double[num];
			double[] beta_k = new double[num];
			bool[] converged = new bool[num];
			Interval1i interval1i = Interval1i.Range(num);
			int num4 = 0;
			while (num4++ < MaxIterations)
			{
				bool flag = true;
				for (int num5 = 0; num5 < num; num5++)
				{
					if (!converged[num5] && Math.Sqrt(RdotZ_k[num5]) <= ConvergeTolerance * array2[num5])
					{
						converged[num5] = true;
					}
					if (!converged[num5])
					{
						flag = false;
					}
				}
				if (flag)
				{
					break;
				}
				MultiplyF(P, AP);
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						alpha_k[num6] = RdotZ_k[num6] / BufferUtil.Dot(P[num6], AP[num6]);
					}
				});
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						BufferUtil.MultiplyAdd(X[num6], alpha_k[num6], P[num6]);
					}
				});
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						BufferUtil.MultiplyAdd(R[num6], 0.0 - alpha_k[num6], AP[num6]);
					}
				});
				PreconditionMultiplyF(R, Z);
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						beta_k[num6] = BufferUtil.Dot(Z[num6], R[num6]) / RdotZ_k[num6];
					}
				});
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						for (int num7 = 0; num7 < n; num7++)
						{
							P[num6][num7] = Z[num6][num7] + beta_k[num6] * P[num6][num7];
						}
					}
				});
				gParallel.ForEach(interval1i, delegate(int num6)
				{
					if (!converged[num6])
					{
						RdotZ_k[num6] = BufferUtil.Dot(R[num6], Z[num6]);
					}
				});
			}
			Iterations = num4;
			return num4 < MaxIterations;
		}

		private void UpdateP(double[][] P, double[] beta, double[][] R, bool[] converged)
		{
			gParallel.ForEach(Interval1i.Range(P.Length), delegate(int j)
			{
				if (!converged[j])
				{
					int num = P[j].Length;
					for (int i = 0; i < num; i++)
					{
						P[j][i] = R[j][i] + beta[j] * P[j][i];
					}
				}
			});
		}

		private void InitializeR(double[][] R)
		{
			MultiplyF(X, R);
			for (int i = 0; i < X.Length; i++)
			{
				int num = R[i].Length;
				for (int j = 0; j < num; j++)
				{
					R[i][j] = B[i][j] - R[i][j];
				}
			}
		}
	}
	public class SymmetricEigenSolver
	{
		public enum SortType
		{
			Decreasing = -1,
			NoSorting,
			Increasing
		}

		private struct GivensRotation(int inIndex, double inCs, double inSn)
		{
			public int index = inIndex;

			public double cs = inCs;

			public double sn = inSn;
		}

		private struct SortItem
		{
			public double eigenvalue;

			public int index;
		}

		public const int NO_CONVERGENCE = int.MaxValue;

		private int mSize;

		private int mMaxIterations;

		private double[] mMatrix;

		private double[] mDiagonal;

		private double[] mSuperdiagonal;

		private List<GivensRotation> mGivens;

		private int[] mPermutation;

		private int[] mVisited;

		private int mIsRotation;

		private double[] mPVector;

		private double[] mVVector;

		private double[] mWVector;

		public SymmetricEigenSolver(int size, int maxIterations)
		{
			mSize = (mMaxIterations = 0);
			mIsRotation = -1;
			if (size > 1 && maxIterations > 0)
			{
				mSize = size;
				mMaxIterations = maxIterations;
				mMatrix = new double[size * size];
				mDiagonal = new double[size];
				mSuperdiagonal = new double[size - 1];
				mGivens = new List<GivensRotation>(maxIterations * (size - 1));
				mPermutation = new int[size];
				mVisited = new int[size];
				mPVector = new double[size];
				mVVector = new double[size];
				mWVector = new double[size];
			}
		}

		public int Solve(double[] input, SortType eSort)
		{
			if (mSize > 0)
			{
				Array.Copy(input, mMatrix, mSize * mSize);
				Tridiagonalize();
				mGivens.Clear();
				for (int i = 0; i < mMaxIterations; i++)
				{
					int num = -1;
					int num2 = -1;
					for (int num3 = mSize - 2; num3 >= 0; num3--)
					{
						double value = mDiagonal[num3];
						double value2 = mSuperdiagonal[num3];
						double value3 = mDiagonal[num3 + 1];
						double num4 = Math.Abs(value) + Math.Abs(value3);
						if (num4 + Math.Abs(value2) != num4)
						{
							if (num2 == -1)
							{
								num2 = num3;
							}
							num = num3;
						}
						else if (num >= 0)
						{
							break;
						}
					}
					if (num2 == -1)
					{
						ComputePermutation((int)eSort);
						return i;
					}
					DoQRImplicitShift(num, num2);
				}
				return int.MaxValue;
			}
			return 0;
		}

		public void GetEigenvalues(double[] eigenvalues)
		{
			if (eigenvalues == null || mSize <= 0)
			{
				return;
			}
			if (mPermutation[0] >= 0)
			{
				for (int i = 0; i < mSize; i++)
				{
					int num = mPermutation[i];
					eigenvalues[i] = mDiagonal[num];
				}
			}
			else
			{
				Array.Copy(mDiagonal, eigenvalues, mSize);
			}
		}

		public double[] GetEigenvalues()
		{
			double[] array = new double[mSize];
			GetEigenvalues(array);
			return array;
		}

		public double GetEigenvalue(int c)
		{
			if (mSize > 0)
			{
				if (mPermutation[0] >= 0)
				{
					return mDiagonal[mPermutation[c]];
				}
				return mDiagonal[c];
			}
			return double.MaxValue;
		}

		public void GetEigenvectors(double[] eigenvectors)
		{
			if (eigenvectors == null || mSize <= 0)
			{
				return;
			}
			Array.Clear(eigenvectors, 0, mSize * mSize);
			for (int i = 0; i < mSize; i++)
			{
				eigenvectors[i + mSize * i] = 1.0;
			}
			int num = mSize - 3;
			int num2 = num + 1;
			while (num >= 0)
			{
				ArrayAlias<double> arrayAlias = new ArrayAlias<double>(mMatrix, num);
				double num3 = arrayAlias[mSize * (num + 1)];
				int j;
				for (j = 0; j < num + 1; j++)
				{
					mVVector[j] = 0.0;
				}
				mVVector[j] = 1.0;
				for (j++; j < mSize; j++)
				{
					mVVector[j] = arrayAlias[mSize * j];
				}
				for (j = 0; j < mSize; j++)
				{
					mWVector[j] = 0.0;
					for (int k = num2; k < mSize; k++)
					{
						mWVector[j] += mVVector[k] * eigenvectors[j + mSize * k];
					}
					mWVector[j] *= num3;
				}
				for (j = num2; j < mSize; j++)
				{
					for (int k = 0; k < mSize; k++)
					{
						eigenvectors[k + mSize * j] -= mVVector[j] * mWVector[k];
					}
				}
				num--;
				num2--;
			}
			foreach (GivensRotation mGiven in mGivens)
			{
				for (int j = 0; j < mSize; j++)
				{
					int num4 = mGiven.index + mSize * j;
					double num5 = eigenvectors[num4];
					double num6 = eigenvectors[num4 + 1];
					double num7 = mGiven.cs * num5 - mGiven.sn * num6;
					double num8 = mGiven.sn * num5 + mGiven.cs * num6;
					eigenvectors[num4] = num7;
					eigenvectors[num4 + 1] = num8;
				}
			}
			mIsRotation = 1 - (mSize & 1);
			if (mPermutation[0] < 0)
			{
				return;
			}
			Array.Clear(mVisited, 0, mVisited.Length);
			for (int l = 0; l < mSize; l++)
			{
				if (mVisited[l] != 0 || mPermutation[l] == l)
				{
					continue;
				}
				mIsRotation = 1 - mIsRotation;
				int num9 = l;
				int num10 = l;
				for (int m = 0; m < mSize; m++)
				{
					mPVector[m] = eigenvectors[l + mSize * m];
				}
				int num11;
				while ((num11 = mPermutation[num10]) != num9)
				{
					mVisited[num10] = 1;
					for (int m = 0; m < mSize; m++)
					{
						eigenvectors[num10 + mSize * m] = eigenvectors[num11 + mSize * m];
					}
					num10 = num11;
				}
				mVisited[num10] = 1;
				for (int m = 0; m < mSize; m++)
				{
					eigenvectors[num10 + mSize * m] = mPVector[m];
				}
			}
		}

		public double[] GetEigenvectors()
		{
			double[] array = new double[mSize * mSize];
			GetEigenvectors(array);
			return array;
		}

		public bool IsRotation()
		{
			if (mSize > 0)
			{
				if (mIsRotation == -1)
				{
					mIsRotation = 1 - (mSize & 1);
					if (mPermutation[0] >= 0)
					{
						Array.Clear(mVisited, 0, mVisited.Length);
						for (int i = 0; i < mSize; i++)
						{
							if (mVisited[i] == 0 && mPermutation[i] != i)
							{
								int num = i;
								int num2 = i;
								int num3;
								while ((num3 = mPermutation[num2]) != num)
								{
									mVisited[num2] = 1;
									num2 = num3;
								}
								mVisited[num2] = 1;
							}
						}
					}
				}
				return mIsRotation == 1;
			}
			return false;
		}

		public void GetEigenvector(int c, double[] eigenvector)
		{
			if (0 > c || c >= mSize)
			{
				return;
			}
			double[] array = eigenvector;
			double[] array2 = mPVector;
			Array.Clear(array, 0, mSize);
			if (mPermutation[c] >= 0)
			{
				array[mPermutation[c]] = 1.0;
			}
			else
			{
				array[c] = 1.0;
			}
			for (int num = mGivens.Count - 1; num >= 0; num--)
			{
				GivensRotation givensRotation = mGivens[num];
				double num2 = array[givensRotation.index];
				double num3 = array[givensRotation.index + 1];
				double num4 = givensRotation.cs * num2 + givensRotation.sn * num3;
				double num5 = (0.0 - givensRotation.sn) * num2 + givensRotation.cs * num3;
				array[givensRotation.index] = num4;
				array[givensRotation.index + 1] = num5;
			}
			for (int num6 = mSize - 3; num6 >= 0; num6--)
			{
				ArrayAlias<double> arrayAlias = new ArrayAlias<double>(mMatrix, num6);
				double num7 = arrayAlias[mSize * (num6 + 1)];
				int i;
				for (i = 0; i < num6 + 1; i++)
				{
					array2[i] = array[i];
				}
				double num8 = array[i];
				for (int j = i + 1; j < mSize; j++)
				{
					num8 += array[j] * arrayAlias[mSize * j];
				}
				num8 *= num7;
				array2[i] = array[i] - num8;
				for (i++; i < mSize; i++)
				{
					array2[i] = array[i] - num8 * arrayAlias[mSize * i];
				}
				double[] array3 = array;
				array = array2;
				array2 = array3;
			}
			if (array != eigenvector)
			{
				Array.Copy(array, eigenvector, mSize);
			}
		}

		public double[] GetEigenvector(int c)
		{
			double[] array = new double[mSize];
			GetEigenvector(c, array);
			return array;
		}

		private void Tridiagonalize()
		{
			int num = 0;
			int num2 = 1;
			while (num < mSize - 2)
			{
				double num3 = 0.0;
				for (int i = 0; i < num2; i++)
				{
					mVVector[i] = 0.0;
				}
				for (int i = num2; i < mSize; i++)
				{
					double num4 = mMatrix[i + mSize * num];
					mVVector[i] = num4;
					num3 += num4 * num4;
				}
				double num5 = 1.0;
				num3 = Math.Sqrt(num3);
				if (num3 > 0.0)
				{
					double num6 = mVVector[num2];
					double num7 = ((num6 >= 0.0) ? 1 : (-1));
					double num8 = 1.0 / (num6 + num7 * num3);
					mVVector[num2] = 1.0;
					for (int i = num2 + 1; i < mSize; i++)
					{
						mVVector[i] *= num8;
						num5 += mVVector[i] * mVVector[i];
					}
				}
				double num9 = 1.0 / num5;
				double num10 = num9 * 2.0;
				double num11 = 0.0;
				for (int i = num; i < mSize; i++)
				{
					mPVector[i] = 0.0;
					int j;
					for (j = num; j < i; j++)
					{
						mPVector[i] += mMatrix[i + mSize * j] * mVVector[j];
					}
					for (; j < mSize; j++)
					{
						mPVector[i] += mMatrix[j + mSize * i] * mVVector[j];
					}
					mPVector[i] *= num10;
					num11 += mPVector[i] * mVVector[i];
				}
				num11 *= num9;
				for (int i = num; i < mSize; i++)
				{
					mWVector[i] = mPVector[i] - num11 * mVVector[i];
				}
				for (int i = num; i < mSize; i++)
				{
					double num12 = mVVector[i];
					double num13 = mWVector[i];
					double num14 = num12 * num13 * 2.0;
					mMatrix[i + mSize * i] -= num14;
					for (int j = i + 1; j < mSize; j++)
					{
						num14 = num12 * mWVector[j] + num13 * mVVector[j];
						mMatrix[j + mSize * i] -= num14;
					}
				}
				mMatrix[num + mSize * num2] = num10;
				for (int i = num2 + 1; i < mSize; i++)
				{
					mMatrix[num + mSize * i] = mVVector[i];
				}
				num++;
				num2++;
			}
			int num15 = mSize - 1;
			int num16 = 0;
			int num17 = mSize + 1;
			int num18 = 0;
			while (num18 < num15)
			{
				mDiagonal[num18] = mMatrix[num16];
				mSuperdiagonal[num18] = mMatrix[num16 + 1];
				num18++;
				num16 += num17;
			}
			mDiagonal[num18] = mMatrix[num16];
		}

		private void GetSinCos(double x, double y, ref double cs, ref double sn)
		{
			if (y != 0.0)
			{
				if (Math.Abs(y) > Math.Abs(x))
				{
					double num = (0.0 - x) / y;
					sn = 1.0 / Math.Sqrt(1.0 + num * num);
					cs = sn * num;
				}
				else
				{
					double num = (0.0 - y) / x;
					cs = 1.0 / Math.Sqrt(1.0 + num * num);
					sn = cs * num;
				}
			}
			else
			{
				cs = 1.0;
				sn = 0.0;
			}
		}

		private void DoQRImplicitShift(int imin, int imax)
		{
			double num = mDiagonal[imax];
			double num2 = mSuperdiagonal[imax];
			double num3 = mDiagonal[imax + 1];
			double num4 = (num - num3) * 0.5;
			double num5 = ((num4 >= 0.0) ? 1 : (-1));
			double num6 = num2 * num2;
			double num7 = num3 - num6 / (num4 + num5 * Math.Sqrt(num4 * num4 + num6));
			double x = mDiagonal[imin] - num7;
			double y = mSuperdiagonal[imin];
			double cs = 0.0;
			double sn = 0.0;
			double num8 = 0.0;
			int num9 = imin - 1;
			int num10 = imin;
			int num11 = imin + 1;
			while (num10 <= imax)
			{
				GetSinCos(x, y, ref cs, ref sn);
				mGivens.Add(new GivensRotation(num10, cs, sn));
				if (num10 > imin)
				{
					mSuperdiagonal[num9] = cs * mSuperdiagonal[num9] - sn * num8;
				}
				num3 = mDiagonal[num10];
				double num12 = mSuperdiagonal[num10];
				double num13 = mDiagonal[num11];
				double num14 = cs * num3 - sn * num12;
				double num15 = cs * num12 - sn * num13;
				double num16 = sn * num3 + cs * num12;
				double num17 = sn * num12 + cs * num13;
				mDiagonal[num10] = cs * num14 - sn * num15;
				mSuperdiagonal[num10] = sn * num14 + cs * num15;
				mDiagonal[num11] = sn * num16 + cs * num17;
				if (num10 < imax)
				{
					double num18 = mSuperdiagonal[num11];
					num8 = (0.0 - sn) * num18;
					mSuperdiagonal[num11] = cs * num18;
					x = mSuperdiagonal[num10];
					y = num8;
				}
				num9++;
				num10++;
				num11++;
			}
		}

		private void ComputePermutation(int sortType)
		{
			mIsRotation = -1;
			if (sortType == 0)
			{
				mPermutation[0] = -1;
				return;
			}
			SortItem[] array = new SortItem[mSize];
			for (int i = 0; i < mSize; i++)
			{
				array[i].eigenvalue = mDiagonal[i];
				array[i].index = i;
			}
			if (sortType > 0)
			{
				Array.Sort(array, (SortItem a, SortItem b) => (a.eigenvalue != b.eigenvalue) ? ((!(a.eigenvalue < b.eigenvalue)) ? 1 : (-1)) : 0);
			}
			else
			{
				Array.Sort(array, (SortItem a, SortItem b) => (a.eigenvalue != b.eigenvalue) ? ((!(a.eigenvalue > b.eigenvalue)) ? 1 : (-1)) : 0);
			}
			for (int num = 0; num < mSize; num++)
			{
				mPermutation[num] = array[num].index;
			}
		}
	}
	public class TransformedIntersectionTarget : IIntersectionTarget
	{
		private DMeshIntersectionTarget BaseTarget;

		public Func<Ray3d, Ray3d> MapToBaseF;

		public Func<Vector3d, Vector3d> MapFromBasePosF;

		public Func<Vector3d, Vector3d> MapFromBaseNormalF;

		public bool HasNormal => BaseTarget.HasNormal;

		public bool RayIntersect(Ray3d ray, out Vector3d vHit, out Vector3d vHitNormal)
		{
			Ray3d ray2 = MapToBaseF(ray);
			if (BaseTarget.RayIntersect(ray2, out vHit, out vHitNormal))
			{
				vHit = MapFromBasePosF(vHit);
				vHitNormal = MapFromBasePosF(vHitNormal);
				return true;
			}
			return false;
		}
	}
	public class DMeshIntersectionTarget : IIntersectionTarget
	{
		public bool UseFaceNormal = true;

		public DMesh3 Mesh { get; set; }

		public ISpatial Spatial { get; set; }

		public bool HasNormal => true;

		public DMeshIntersectionTarget()
		{
		}

		public DMeshIntersectionTarget(DMesh3 mesh, ISpatial spatial)
		{
			Mesh = mesh;
			Spatial = spatial;
		}

		public bool RayIntersect(Ray3d ray, out Vector3d vHit, out Vector3d vHitNormal)
		{
			vHit = Vector3d.Zero;
			vHitNormal = Vector3d.AxisX;
			int num = Spatial.FindNearestHitTriangle(ray);
			if (num == -1)
			{
				return false;
			}
			IntrRay3Triangle3 intrRay3Triangle = MeshQueries.TriangleIntersection(Mesh, num, ray);
			vHit = ray.PointAt(intrRay3Triangle.RayParameter);
			if (!UseFaceNormal && Mesh.HasVertexNormals)
			{
				vHitNormal = Mesh.GetTriBaryNormal(num, intrRay3Triangle.TriangleBaryCoords.x, intrRay3Triangle.TriangleBaryCoords.y, intrRay3Triangle.TriangleBaryCoords.z);
			}
			else
			{
				vHitNormal = Mesh.GetTriNormal(num);
			}
			return true;
		}
	}
	public class PlaneIntersectionTarget : IIntersectionTarget
	{
		public Frame3f PlaneFrame;

		public int NormalAxis = 2;

		public bool HasNormal => true;

		public bool RayIntersect(Ray3d ray, out Vector3d vHit, out Vector3d vHitNormal)
		{
			Vector3f vector3f = PlaneFrame.RayPlaneIntersection((Vector3f)ray.Origin, (Vector3f)ray.Direction, NormalAxis);
			vHit = vector3f;
			vHitNormal = Vector3f.AxisY;
			return vector3f != Vector3f.Invalid;
		}
	}
	public class MeshProjectionTarget : IOrientedProjectionTarget, IProjectionTarget
	{
		public DMesh3 Mesh { get; set; }

		public ISpatial Spatial { get; set; }

		public MeshProjectionTarget()
		{
		}

		public MeshProjectionTarget(DMesh3 mesh, ISpatial spatial)
		{
			Mesh = mesh;
			Spatial = spatial;
			if (Spatial == null)
			{
				Spatial = new DMeshAABBTree3(mesh, autoBuild: true);
			}
		}

		public MeshProjectionTarget(DMesh3 mesh)
		{
			Mesh = mesh;
			Spatial = new DMeshAABBTree3(mesh, autoBuild: true);
		}

		public virtual Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			int tID = Spatial.FindNearestTriangle(vPoint);
			Triangle3d triangle = default(Triangle3d);
			Mesh.GetTriVertices(tID, ref triangle.V0, ref triangle.V1, ref triangle.V2);
			DistPoint3Triangle3.DistanceSqr(ref vPoint, ref triangle, out var closestPoint, out var _);
			return closestPoint;
		}

		public virtual Vector3d Project(Vector3d vPoint, out Vector3d vProjectNormal, int identifier = -1)
		{
			int tID = Spatial.FindNearestTriangle(vPoint);
			Triangle3d triangle = default(Triangle3d);
			Mesh.GetTriVertices(tID, ref triangle.V0, ref triangle.V1, ref triangle.V2);
			DistPoint3Triangle3.DistanceSqr(ref vPoint, ref triangle, out var closestPoint, out var _);
			vProjectNormal = triangle.Normal;
			return closestPoint;
		}

		public static MeshProjectionTarget Auto(DMesh3 mesh, bool bForceCopy = true)
		{
			if (bForceCopy)
			{
				return new MeshProjectionTarget(new DMesh3(mesh, bCompact: false, MeshComponents.None));
			}
			return new MeshProjectionTarget(mesh);
		}

		public static MeshProjectionTarget Auto(DMesh3 mesh, IEnumerable<int> triangles, int nExpandRings = 5)
		{
			MeshFaceSelection meshFaceSelection = new MeshFaceSelection(mesh);
			meshFaceSelection.Select(triangles);
			meshFaceSelection.ExpandToOneRingNeighbours(nExpandRings);
			return new MeshProjectionTarget(new DSubmesh3(mesh, meshFaceSelection).SubMesh);
		}
	}
	public class TransformedMeshProjectionTarget : MeshProjectionTarget
	{
		public TransformSequence SourceToTargetXForm;

		public TransformSequence TargetToSourceXForm;

		public TransformedMeshProjectionTarget()
		{
		}

		public TransformedMeshProjectionTarget(DMesh3 mesh, ISpatial spatial)
			: base(mesh, spatial)
		{
		}

		public TransformedMeshProjectionTarget(DMesh3 mesh)
			: base(mesh)
		{
		}

		public void SetTransform(TransformSequence sourceToTargetX)
		{
			SourceToTargetXForm = sourceToTargetX;
			TargetToSourceXForm = SourceToTargetXForm.MakeInverse();
		}

		public override Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			Vector3d vPoint2 = SourceToTargetXForm.TransformP(vPoint);
			Vector3d p = base.Project(vPoint2, identifier);
			return TargetToSourceXForm.TransformP(p);
		}

		public override Vector3d Project(Vector3d vPoint, out Vector3d vProjectNormal, int identifier = -1)
		{
			Vector3d vPoint2 = SourceToTargetXForm.TransformP(vPoint);
			Vector3d vProjectNormal2;
			Vector3d p = base.Project(vPoint2, out vProjectNormal2, identifier);
			vProjectNormal = TargetToSourceXForm.TransformV(vProjectNormal2).Normalized;
			return TargetToSourceXForm.TransformP(p);
		}
	}
	public class PlaneProjectionTarget : IProjectionTarget
	{
		public Vector3d Origin;

		public Vector3d Normal;

		public Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			Vector3d vector3d = vPoint - Origin;
			return Origin + (vector3d - vector3d.Dot(Normal) * Normal);
		}
	}
	public class CircleProjectionTarget : IProjectionTarget
	{
		public Circle3d Circle;

		public Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			DistPoint3Circle3 distPoint3Circle = new DistPoint3Circle3(vPoint, Circle);
			distPoint3Circle.GetSquared();
			return distPoint3Circle.CircleClosest;
		}
	}
	public class CylinderProjectionTarget : IProjectionTarget
	{
		public Cylinder3d Cylinder;

		public Vector3d Project(Vector3d vPoint, int identifer = -1)
		{
			DistPoint3Cylinder3 distPoint3Cylinder = new DistPoint3Cylinder3(vPoint, Cylinder);
			distPoint3Cylinder.GetSquared();
			return distPoint3Cylinder.CylinderClosest;
		}
	}
	public class SequentialProjectionTarget : IProjectionTarget
	{
		public IProjectionTarget[] Targets { get; set; }

		public SequentialProjectionTarget()
		{
		}

		public SequentialProjectionTarget(params IProjectionTarget[] targets)
		{
			Targets = targets;
		}

		public Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			Vector3d vector3d = vPoint;
			for (int i = 0; i < Targets.Length; i++)
			{
				vector3d = Targets[i].Project(vector3d, identifier);
			}
			return vector3d;
		}
	}
	public class BiGrid3<BlockType> where BlockType : class, IGridElement3, IFixedGrid3
	{
		private Vector3i block_size;

		private MultigridIndexer3 indexer;

		private DSparseGrid3<BlockType> sparse_grid;

		public Vector3i BlockSize => block_size;

		public MultigridIndexer3 Indexer => indexer;

		public DSparseGrid3<BlockType> BlockGrid => sparse_grid;

		public BiGrid3(BlockType exemplar)
		{
			block_size = exemplar.Dimensions;
			indexer = new MultigridIndexer3(block_size);
			sparse_grid = new DSparseGrid3<BlockType>(exemplar);
		}

		public void Update(Index3i index, Action<BlockType, Vector3i> UpdateF)
		{
			GridLevelIndex gridLevelIndex = Indexer.ToBlock(index);
			BlockType arg = sparse_grid.Get(gridLevelIndex.block_index);
			UpdateF(arg, gridLevelIndex.local_index);
		}

		public IEnumerable<KeyValuePair<Vector3i, BlockType>> AllocatedBlocks()
		{
			return sparse_grid.Allocated();
		}
	}
	public class Bitmap2
	{
		public BitArray Bits;

		private Vector2i dimensions;

		private int row_size;

		public Vector2i Dimensions => dimensions;

		public AxisAlignedBox2i GridBounds => new AxisAlignedBox2i(Vector2i.Zero, Dimensions);

		public bool this[int i]
		{
			get
			{
				return Bits[i];
			}
			set
			{
				Bits[i] = value;
			}
		}

		public bool this[int r, int c]
		{
			get
			{
				return Bits[r * row_size + c];
			}
			set
			{
				Bits[r * row_size + c] = value;
			}
		}

		public bool this[Vector2i idx]
		{
			get
			{
				int index = idx.y * row_size + idx.x;
				return Bits[index];
			}
			set
			{
				int index = idx.y * row_size + idx.x;
				Bits[index] = value;
			}
		}

		public Bitmap2(Vector2i dims)
		{
			Resize(dims);
		}

		public Bitmap2(int Width, int Height)
		{
			Resize(new Vector2i(Width, Height));
		}

		public void Resize(Vector2i dims)
		{
			int length = dims.x * dims.y;
			Bits = new BitArray(length);
			dimensions = dims;
			row_size = dims.x;
		}

		public void Set(Vector2i idx, bool val)
		{
			int index = idx.y * row_size + idx.x;
			Bits[index] = val;
		}

		public bool Get(Vector2i idx)
		{
			int index = idx.y * row_size + idx.x;
			return Bits[index];
		}

		public Vector2i ToIndex(int i)
		{
			int num = i / row_size;
			i -= num * row_size;
			return new Vector2i(i, num);
		}

		public int ToLinear(Vector2i idx)
		{
			return idx.y * row_size + idx.x;
		}

		public IEnumerable<Vector2i> Indices()
		{
			int y = 0;
			while (y < Dimensions.y)
			{
				int num;
				for (int x = 0; x < Dimensions.x; x = num)
				{
					yield return new Vector2i(x, y);
					num = x + 1;
				}
				num = y + 1;
				y = num;
			}
		}

		public IEnumerable<Vector2i> NonZeros()
		{
			int i = 0;
			while (i < Bits.Count)
			{
				if (Bits[i])
				{
					yield return ToIndex(i);
				}
				int num = i + 1;
				i = num;
			}
		}
	}
	public interface IBinaryVoxelGrid
	{
		AxisAlignedBox3i GridBounds { get; }

		bool Get(Vector3i i);

		IEnumerable<Vector3i> NonZeros();
	}
	public class Bitmap3 : IBinaryVoxelGrid, IGridElement3, IFixedGrid3
	{
		public BitArray Bits;

		private Vector3i dimensions;

		private int row_size;

		private int slab_size;

		private SpinLock bit_lock;

		public Vector3i Dimensions => dimensions;

		public AxisAlignedBox3i GridBounds => new AxisAlignedBox3i(Vector3i.Zero, Dimensions);

		public bool this[int i]
		{
			get
			{
				return Bits[i];
			}
			set
			{
				Bits[i] = value;
			}
		}

		public bool this[Vector3i idx]
		{
			get
			{
				int index = idx.z * slab_size + idx.y * row_size + idx.x;
				return Bits[index];
			}
			set
			{
				int index = idx.z * slab_size + idx.y * row_size + idx.x;
				Bits[index] = value;
			}
		}

		public Bitmap3(Vector3i dims)
		{
			int length = dims.x * dims.y * dims.z;
			Bits = new BitArray(length);
			dimensions = dims;
			row_size = dims.x;
			slab_size = dims.x * dims.y;
		}

		public void Set(Vector3i idx, bool val)
		{
			int index = idx.z * slab_size + idx.y * row_size + idx.x;
			Bits[index] = val;
		}

		public void SafeSet(Vector3i idx, bool val)
		{
			bool lockTaken = false;
			bit_lock.Enter(ref lockTaken);
			int index = idx.z * slab_size + idx.y * row_size + idx.x;
			Bits[index] = val;
			bit_lock.Exit();
		}

		public bool Get(Vector3i idx)
		{
			int index = idx.z * slab_size + idx.y * row_size + idx.x;
			return Bits[index];
		}

		public Vector3i ToIndex(int i)
		{
			int num = i / slab_size;
			i -= num * slab_size;
			int num2 = i / row_size;
			i -= num2 * row_size;
			return new Vector3i(i, num2, num);
		}

		public int ToLinear(Vector3i idx)
		{
			return idx.z * slab_size + idx.y * row_size + idx.x;
		}

		public IEnumerable<Vector3i> Indices()
		{
			int z = 0;
			while (z < Dimensions.z)
			{
				int num;
				for (int y = 0; y < Dimensions.y; y = num)
				{
					for (int x = 0; x < Dimensions.x; x = num)
					{
						yield return new Vector3i(x, y, z);
						num = x + 1;
					}
					num = y + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public IEnumerable<Vector3i> NonZeros()
		{
			int i = 0;
			while (i < Bits.Count)
			{
				if (Bits[i])
				{
					yield return ToIndex(i);
				}
				int num = i + 1;
				i = num;
			}
		}

		public void Filter(int nMinNbrs)
		{
			AxisAlignedBox3i gridBounds = GridBounds;
			gridBounds.Max -= Vector3i.One;
			for (int i = 0; i < Bits.Length; i++)
			{
				if (!Bits[i])
				{
					continue;
				}
				Vector3i vector3i = ToIndex(i);
				int num = 0;
				for (int j = 0; j < 6; j++)
				{
					if (num > nMinNbrs)
					{
						break;
					}
					Vector3i vector3i2 = vector3i + gIndices.GridOffsets6[j];
					if (gridBounds.Contains(vector3i2) && Get(vector3i2))
					{
						num++;
					}
				}
				if (num <= nMinNbrs)
				{
					Bits[i] = false;
				}
			}
		}

		public virtual IGridElement3 CreateNewGridElement(bool bCopy)
		{
			Bitmap3 result = new Bitmap3(Dimensions);
			if (bCopy)
			{
				throw new NotImplementedException();
			}
			return result;
		}
	}
	public class DCurve3BoxTree
	{
		public DCurve3 Curve;

		private Box3d[] boxes;

		private int layers;

		private List<int> layer_counts;

		public DCurve3BoxTree(DCurve3 curve)
		{
			Curve = curve;
			build_sequential(curve);
		}

		public double DistanceSquared(Vector3d pt)
		{
			int iNearSeg;
			double fNearSegT;
			return SquaredDistance(pt, out iNearSeg, out fNearSegT);
		}

		public double Distance(Vector3d pt)
		{
			int iNearSeg;
			double fNearSegT;
			return Math.Sqrt(SquaredDistance(pt, out iNearSeg, out fNearSegT));
		}

		public Vector3d NearestPoint(Vector3d pt)
		{
			SquaredDistance(pt, out var iNearSeg, out var fNearSegT);
			return Curve.PointAt(iNearSeg, fNearSegT);
		}

		public double SquaredDistance(Vector3d pt, out int iNearSeg, out double fNearSegT, double max_dist = double.MaxValue)
		{
			int iLayerStart = boxes.Length - 1;
			int iLayer = layers - 1;
			double min_dist = max_dist;
			iNearSeg = -1;
			fNearSegT = 0.0;
			find_min_distance(ref pt, ref min_dist, ref iNearSeg, ref fNearSegT, 0, iLayerStart, iLayer);
			if (iNearSeg == -1)
			{
				return double.MaxValue;
			}
			return min_dist;
		}

		private void find_min_distance(ref Vector3d pt, ref double min_dist, ref int min_dist_seg, ref double min_dist_segt, int bi, int iLayerStart, int iLayer)
		{
			if (iLayer == 0)
			{
				int num = 2 * bi;
				double num2 = Curve.GetSegment(num).DistanceSquared(pt, out var t);
				if (num2 <= min_dist)
				{
					min_dist = num2;
					min_dist_seg = num;
					min_dist_segt = t;
				}
				if (num + 1 < Curve.SegmentCount)
				{
					num2 = Curve.GetSegment(num + 1).DistanceSquared(pt, out t);
					if (num2 <= min_dist)
					{
						min_dist = num2;
						min_dist_seg = num + 1;
						min_dist_segt = t;
					}
				}
				return;
			}
			int num3 = iLayer - 1;
			int num4 = layer_counts[num3];
			int num5 = iLayerStart - num4;
			int num6 = num5 + 2 * bi;
			if (boxes[num6].DistanceSquared(pt) <= min_dist)
			{
				find_min_distance(ref pt, ref min_dist, ref min_dist_seg, ref min_dist_segt, 2 * bi, num5, num3);
			}
			if (2 * bi + 1 < num4)
			{
				int num7 = num6 + 1;
				if (boxes[num7].DistanceSquared(pt) <= min_dist)
				{
					find_min_distance(ref pt, ref min_dist, ref min_dist_seg, ref min_dist_segt, 2 * bi + 1, num5, num3);
				}
			}
		}

		public double SquaredDistance(Ray3d ray, out int iNearSeg, out double fNearSegT, out double fRayT, double max_dist = double.MaxValue)
		{
			int iLayerStart = boxes.Length - 1;
			int iLayer = layers - 1;
			double min_dist = max_dist;
			iNearSeg = -1;
			fNearSegT = 0.0;
			fRayT = double.MaxValue;
			find_min_distance(ref ray, ref min_dist, ref iNearSeg, ref fNearSegT, ref fRayT, 0, iLayerStart, iLayer);
			if (iNearSeg == -1)
			{
				return double.MaxValue;
			}
			return min_dist;
		}

		private void find_min_distance(ref Ray3d ray, ref double min_dist, ref int min_dist_seg, ref double min_dist_segt, ref double min_dist_rayt, int bi, int iLayerStart, int iLayer)
		{
			if (iLayer == 0)
			{
				int num = 2 * bi;
				Segment3d segment = Curve.GetSegment(num);
				double num2 = Math.Sqrt(DistRay3Segment3.SquaredDistance(ref ray, ref segment, out var rayT, out var segT));
				if (num2 <= min_dist)
				{
					min_dist = num2;
					min_dist_seg = num;
					min_dist_segt = segT;
					min_dist_rayt = rayT;
				}
				if (num + 1 < Curve.SegmentCount)
				{
					Segment3d segment2 = Curve.GetSegment(num + 1);
					num2 = Math.Sqrt(DistRay3Segment3.SquaredDistance(ref ray, ref segment2, out rayT, out segT));
					if (num2 <= min_dist)
					{
						min_dist = num2;
						min_dist_seg = num + 1;
						min_dist_segt = segT;
						min_dist_rayt = rayT;
					}
				}
				return;
			}
			int num3 = iLayer - 1;
			int num4 = layer_counts[num3];
			int num5 = iLayerStart - num4;
			int num6 = num5 + 2 * bi;
			if (IntrRay3Box3.Intersects(ref ray, ref boxes[num6], min_dist))
			{
				find_min_distance(ref ray, ref min_dist, ref min_dist_seg, ref min_dist_segt, ref min_dist_rayt, 2 * bi, num5, num3);
			}
			if (2 * bi + 1 < num4)
			{
				int num7 = num6 + 1;
				if (IntrRay3Box3.Intersects(ref ray, ref boxes[num7], min_dist))
				{
					find_min_distance(ref ray, ref min_dist, ref min_dist_seg, ref min_dist_segt, ref min_dist_rayt, 2 * bi + 1, num5, num3);
				}
			}
		}

		public bool FindClosestRayIntersction(Ray3d ray, double radius, out int hitSegment, out double fRayT)
		{
			int iLayerStart = boxes.Length - 1;
			int iLayer = layers - 1;
			hitSegment = -1;
			fRayT = double.MaxValue;
			find_closest_ray_intersction(ref ray, radius, ref hitSegment, ref fRayT, 0, iLayerStart, iLayer);
			return hitSegment != -1;
		}

		private void find_closest_ray_intersction(ref Ray3d ray, double radius, ref int nearestSegment, ref double nearest_ray_t, int bi, int iLayerStart, int iLayer)
		{
			if (iLayer == 0)
			{
				int num = 2 * bi;
				Segment3d segment = Curve.GetSegment(num);
				if (DistRay3Segment3.SquaredDistance(ref ray, ref segment, out var rayT, out var segT) <= radius * radius && rayT < nearest_ray_t)
				{
					nearestSegment = num;
					nearest_ray_t = rayT;
				}
				if (num + 1 < Curve.SegmentCount)
				{
					Segment3d segment2 = Curve.GetSegment(num + 1);
					if (DistRay3Segment3.SquaredDistance(ref ray, ref segment2, out rayT, out segT) <= radius * radius && rayT < nearest_ray_t)
					{
						nearestSegment = num + 1;
						nearest_ray_t = rayT;
					}
				}
				return;
			}
			int num2 = iLayer - 1;
			int num3 = layer_counts[num2];
			int num4 = iLayerStart - num3;
			int num5 = num4 + 2 * bi;
			if (IntrRay3Box3.Intersects(ref ray, ref boxes[num5], radius))
			{
				find_closest_ray_intersction(ref ray, radius, ref nearestSegment, ref nearest_ray_t, 2 * bi, num4, num2);
			}
			if (2 * bi + 1 < num3)
			{
				int num6 = num5 + 1;
				if (IntrRay3Box3.Intersects(ref ray, ref boxes[num6], radius))
				{
					find_closest_ray_intersction(ref ray, radius, ref nearestSegment, ref nearest_ray_t, 2 * bi + 1, num4, num2);
				}
			}
		}

		private void build_sequential(DCurve3 curve)
		{
			int vertexCount = curve.VertexCount;
			int num = (curve.Closed ? vertexCount : (vertexCount - 1));
			int num2 = 0;
			layers = 0;
			layer_counts = new List<int>();
			int num3 = 0;
			while (num > 1)
			{
				int num4 = num / 2 + ((num % 2 != 0) ? 1 : 0);
				num2 += num4;
				num = num4;
				layer_counts.Add(num4);
				num3 += num4;
				layers++;
			}
			if (layers == 0)
			{
				layers = 1;
				num2 = 1;
				layer_counts = new List<int> { 1 };
			}
			boxes = new Box3d[num2];
			num3 = 0;
			int num5 = (curve.Closed ? vertexCount : (vertexCount - 1));
			for (int i = 0; i < num5; i += 2)
			{
				Vector3d vector3d = curve[(i + 1) % vertexCount];
				Segment3d seg = new Segment3d(curve[i], vector3d);
				Box3d box = new Box3d(seg);
				if (i < vertexCount - 1)
				{
					Segment3d seg2 = new Segment3d(vector3d, curve[(i + 2) % vertexCount]);
					Box3d box2 = new Box3d(seg2);
					box = Box3d.Merge(ref box, ref box2);
				}
				boxes[num3++] = box;
			}
			num = num3;
			if (num == 1)
			{
				return;
			}
			int num6 = 0;
			bool flag = false;
			while (!flag)
			{
				int num7 = num3;
				for (int j = 0; j < num; j += 2)
				{
					Box3d box3d = Box3d.Merge(ref boxes[num6 + j], ref boxes[num6 + j + 1]);
					boxes[num3++] = box3d;
				}
				num = num / 2 + ((num % 2 != 0) ? 1 : 0);
				num6 = num7;
				if (num == 1)
				{
					flag = true;
				}
			}
		}
	}
	public class DCurveProjectionTarget : IProjectionTarget
	{
		public DCurve3 Curve;

		public DCurveProjectionTarget(DCurve3 curve)
		{
			Curve = curve;
		}

		public Vector3d Project(Vector3d vPoint, int identifier = -1)
		{
			Vector3d result = Vector3d.Zero;
			double num = double.MaxValue;
			int vertexCount = Curve.VertexCount;
			int num2 = (Curve.Closed ? vertexCount : (vertexCount - 1));
			for (int i = 0; i < num2; i++)
			{
				Vector3d vector3d = new Segment3d(Curve[i], Curve[(i + 1) % vertexCount]).NearestPoint(vPoint);
				double num3 = vector3d.DistanceSquared(vPoint);
				if (num3 < num)
				{
					num = num3;
					result = vector3d;
				}
			}
			if (!(num < double.MaxValue))
			{
				return vPoint;
			}
			return result;
		}
	}
	public class DenseGrid2f
	{
		public float[] Buffer;

		public int ni;

		public int nj;

		public int size => ni * nj;

		public float this[int i]
		{
			get
			{
				return Buffer[i];
			}
			set
			{
				Buffer[i] = value;
			}
		}

		public float this[int i, int j]
		{
			get
			{
				return Buffer[i + ni * j];
			}
			set
			{
				Buffer[i + ni * j] = value;
			}
		}

		public float this[Vector2i ijk]
		{
			get
			{
				return Buffer[ijk.x + ni * ijk.y];
			}
			set
			{
				Buffer[ijk.x + ni * ijk.y] = value;
			}
		}

		public AxisAlignedBox2i Bounds => new AxisAlignedBox2i(0, 0, ni, nj);

		public DenseGrid2f()
		{
			ni = (nj = 0);
		}

		public DenseGrid2f(int ni, int nj, float initialValue)
		{
			resize(ni, nj);
			assign(initialValue);
		}

		public DenseGrid2f(DenseGrid2f copy)
		{
			Buffer = new float[copy.Buffer.Length];
			Array.Copy(copy.Buffer, Buffer, Buffer.Length);
			ni = copy.ni;
			nj = copy.nj;
		}

		public void swap(DenseGrid2f g2)
		{
			float[] buffer = g2.Buffer;
			g2.Buffer = Buffer;
			Buffer = buffer;
		}

		public void resize(int ni, int nj)
		{
			Buffer = new float[ni * nj];
			this.ni = ni;
			this.nj = nj;
		}

		public void assign(float value)
		{
			for (int i = 0; i < Buffer.Length; i++)
			{
				Buffer[i] = value;
			}
		}

		public void assign_border(float value, int rings)
		{
			for (int i = 0; i < rings; i++)
			{
				int num = nj - 1 - i;
				for (int j = 0; j < ni; j++)
				{
					Buffer[j + ni * i] = value;
					Buffer[j + ni * num] = value;
				}
			}
			int num2 = nj - 1 - rings;
			for (int k = rings; k < num2; k++)
			{
				for (int l = 0; l < rings; l++)
				{
					Buffer[l + ni * k] = value;
					Buffer[ni - 1 - l + ni * k] = value;
				}
			}
		}

		public void clear()
		{
			Array.Clear(Buffer, 0, Buffer.Length);
		}

		public void copy(DenseGrid2f copy)
		{
			Array.Copy(copy.Buffer, Buffer, Buffer.Length);
		}

		public void get_x_pair(int i0, int j, out double a, out double b)
		{
			int num = ni * j;
			a = Buffer[num + i0];
			b = Buffer[num + i0 + 1];
		}

		public void apply(Func<float, float> f)
		{
			for (int i = 0; i < nj; i++)
			{
				for (int j = 0; j < ni; j++)
				{
					int num = j + ni * i;
					Buffer[num] = f(Buffer[num]);
				}
			}
		}

		public void set_min(DenseGrid2f grid2)
		{
			for (int i = 0; i < Buffer.Length; i++)
			{
				Buffer[i] = Math.Min(Buffer[i], grid2.Buffer[i]);
			}
		}

		public void set_max(DenseGrid2f grid2)
		{
			for (int i = 0; i < Buffer.Length; i++)
			{
				Buffer[i] = Math.Max(Buffer[i], grid2.Buffer[i]);
			}
		}

		public IEnumerable<Vector2i> Indices()
		{
			int y = 0;
			while (y < nj)
			{
				int num;
				for (int x = 0; x < ni; x = num)
				{
					yield return new Vector2i(x, y);
					num = x + 1;
				}
				num = y + 1;
				y = num;
			}
		}

		public IEnumerable<Vector2i> InsetIndices(int border_width)
		{
			int stopy = nj - border_width;
			int stopx = ni - border_width;
			int y = border_width;
			while (y < stopy)
			{
				int num;
				for (int x = border_width; x < stopx; x = num)
				{
					yield return new Vector2i(x, y);
					num = x + 1;
				}
				num = y + 1;
				y = num;
			}
		}
	}
