			a = Buffer[num + i0];
			b = Buffer[num + i0 + 1];
		}

		public void apply(Func<float, float> f)
		{
			for (int i = 0; i < nk; i++)
			{
				for (int j = 0; j < nj; j++)
				{
					for (int k = 0; k < ni; k++)
					{
						int num = k + ni * (j + nj * i);
						Buffer[num] = f(Buffer[num]);
					}
				}
			}
		}

		public DenseGrid2f get_slice(int slice_i, int dimension)
		{
			DenseGrid2f denseGrid2f;
			switch (dimension)
			{
			case 0:
			{
				denseGrid2f = new DenseGrid2f(nj, nk, 0f);
				for (int k = 0; k < nk; k++)
				{
					for (int l = 0; l < nj; l++)
					{
						denseGrid2f[l, k] = Buffer[slice_i + ni * (l + nj * k)];
					}
				}
				break;
			}
			case 1:
			{
				denseGrid2f = new DenseGrid2f(ni, nk, 0f);
				for (int m = 0; m < nk; m++)
				{
					for (int n = 0; n < ni; n++)
					{
						denseGrid2f[n, m] = Buffer[n + ni * (slice_i + nj * m)];
					}
				}
				break;
			}
			default:
			{
				denseGrid2f = new DenseGrid2f(ni, nj, 0f);
				for (int i = 0; i < nj; i++)
				{
					for (int j = 0; j < ni; j++)
					{
						denseGrid2f[j, i] = Buffer[j + ni * (i + nj * slice_i)];
					}
				}
				break;
			}
			}
			return denseGrid2f;
		}

		public void set_slice(DenseGrid2f slice, int slice_i, int dimension)
		{
			switch (dimension)
			{
			case 0:
			{
				for (int i = 0; i < nk; i++)
				{
					for (int j = 0; j < nj; j++)
					{
						Buffer[slice_i + ni * (j + nj * i)] = slice[j, i];
					}
				}
				return;
			}
			case 1:
			{
				for (int k = 0; k < nk; k++)
				{
					for (int l = 0; l < ni; l++)
					{
						Buffer[l + ni * (slice_i + nj * k)] = slice[l, k];
					}
				}
				return;
			}
			}
			for (int m = 0; m < nj; m++)
			{
				for (int n = 0; n < ni; n++)
				{
					Buffer[n + ni * (m + nj * slice_i)] = slice[n, m];
				}
			}
		}

		public IEnumerable<Vector3i> Indices()
		{
			int z = 0;
			while (z < nk)
			{
				int num;
				for (int y = 0; y < nj; y = num)
				{
					for (int x = 0; x < ni; x = num)
					{
						yield return new Vector3i(x, y, z);
						num = x + 1;
					}
					num = y + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public IEnumerable<Vector3i> InsetIndices(int border_width)
		{
			int stopy = nj - border_width;
			int stopx = ni - border_width;
			int z = border_width;
			while (z < nk - border_width)
			{
				int num;
				for (int y = border_width; y < stopy; y = num)
				{
					for (int x = border_width; x < stopx; x = num)
					{
						yield return new Vector3i(x, y, z);
						num = x + 1;
					}
					num = y + 1;
				}
				num = z + 1;
				z = num;
			}
		}

		public Vector3i to_index(int idx)
		{
			int x = idx % ni;
			int y = idx / ni % nj;
			int z = idx / (ni * nj);
			return new Vector3i(x, y, z);
		}

		public int to_linear(int i, int j, int k)
		{
			return i + ni * (j + nj * k);
		}

		public int to_linear(ref Vector3i ijk)
		{
			return ijk.x + ni * (ijk.y + nj * ijk.z);
		}

		public int to_linear(Vector3i ijk)
		{
			return ijk.x + ni * (ijk.y + nj * ijk.z);
		}
	}
	public class DenseGrid3i
	{
		public int[] Buffer;

		public int ni;

		public int nj;

		public int nk;

		public int size => ni * nj * nk;

		public int this[int i]
		{
			get
			{
				return Buffer[i];
			}
			set
			{
				Buffer[i] = value;
			}
		}

		public int this[int i, int j, int k]
		{
			get
			{
				return Buffer[i + ni * (j + nj * k)];
			}
			set
			{
				Buffer[i + ni * (j + nj * k)] = value;
			}
		}

		public int this[Vector3i ijk]
		{
			get
			{
				return Buffer[ijk.x + ni * (ijk.y + nj * ijk.z)];
			}
			set
			{
				Buffer[ijk.x + ni * (ijk.y + nj * ijk.z)] = value;
			}
		}

		public DenseGrid3i()
		{
			ni = (nj = (nk = 0));
		}

		public DenseGrid3i(int ni, int nj, int nk, int initialValue)
		{
			resize(ni, nj, nk);
			assign(initialValue);
		}

		public void resize(int ni, int nj, int nk)
		{
			Buffer = new int[ni * nj * nk];
			this.ni = ni;
			this.nj = nj;
			this.nk = nk;
		}

		public void assign(int value)
		{
			for (int i = 0; i < Buffer.Length; i++)
			{
				Buffer[i] = value;
			}
		}

		public void increment(int i, int j, int k)
		{
			Buffer[i + ni * (j + nj * k)]++;
		}

		public void decrement(int i, int j, int k)
		{
			Buffer[i + ni * (j + nj * k)]--;
		}

		public void atomic_increment(int i, int j, int k)
		{
			Interlocked.Increment(ref Buffer[i + ni * (j + nj * k)]);
		}

		public void atomic_decrement(int i, int j, int k)
		{
			Interlocked.Decrement(ref Buffer[i + ni * (j + nj * k)]);
		}

		public void atomic_incdec(int i, int j, int k, bool decrement = false)
		{
			if (decrement)
			{
				Interlocked.Decrement(ref Buffer[i + ni * (j + nj * k)]);
			}
			else
			{
				Interlocked.Increment(ref Buffer[i + ni * (j + nj * k)]);
			}
		}

