				throw new Exception("DMeshAABBTree3.FindNearestTriangle: mesh has been modified since tree construction");
			}
			fNearestDistSqr = ((fMaxDist < double.MaxValue) ? (fMaxDist * fMaxDist) : double.MaxValue);
