	public struct ScaleGridIndexer3(double cellSize) : IGridWorldIndexer3
	{
		public double CellSize = cellSize;

		public Vector3i ToGrid(Vector3d point)
		{
			return new Vector3i((int)(point.x / CellSize), (int)(point.y / CellSize), (int)(point.z / CellSize));
		}

		public Vector3d ToGridf(Vector3d point)
		{
			return new Vector3d(point.x / CellSize, point.y / CellSize, point.z / CellSize);
		}

		public Vector3d FromGrid(Vector3i gridpoint)
		{
			return new Vector3d((double)gridpoint.x * CellSize, (double)gridpoint.y * CellSize, (double)gridpoint.z * CellSize);
		}

		public Vector3d FromGrid(Vector3d gridpointf)
		{
			return new Vector3d(gridpointf.x * CellSize, gridpointf.y * CellSize, gridpointf.z * CellSize);
		}
	}
	public struct ShiftGridIndexer3(Vector3d origin, double cellSize) : IGridWorldIndexer3
	{
		public Vector3d Origin = origin;

		public double CellSize = cellSize;

		public Vector3i ToGrid(Vector3d point)
		{
			return new Vector3i((int)((point.x - Origin.x) / CellSize), (int)((point.y - Origin.y) / CellSize), (int)((point.z - Origin.z) / CellSize));
		}

		public Vector3d ToGridf(Vector3d point)
		{
			return new Vector3d((point.x - Origin.x) / CellSize, (point.y - Origin.y) / CellSize, (point.z - Origin.z) / CellSize);
		}

		public Vector3d FromGrid(Vector3i gridpoint)
		{
			return new Vector3d((double)gridpoint.x * CellSize + Origin.x, (double)gridpoint.y * CellSize + Origin.y, (double)gridpoint.z * CellSize + Origin.z);
		}

		public Vector3d FromGrid(Vector3d gridpointf)
		{
			return new Vector3d(gridpointf.x * CellSize + Origin.x, gridpointf.y * CellSize + Origin.y, gridpointf.z * CellSize + Origin.z);
		}
	}
	public struct FrameGridIndexer3(Frame3f frame, Vector3f cellSize) : IGridWorldIndexer3
	{
		public Frame3f GridFrame = frame;

		public Vector3f CellSize = cellSize;

		public Vector3i ToGrid(Vector3d point)
		{
			Vector3f v = (Vector3f)point;
			v = GridFrame.ToFrameP(ref v);
			return (Vector3i)(v / CellSize);
		}

		public Vector3d ToGridf(Vector3d point)
		{
			point = GridFrame.ToFrameP(ref point);
			point.x /= CellSize.x;
			point.y /= CellSize.y;
			point.z /= CellSize.z;
			return point;
		}

		public Vector3d FromGrid(Vector3i gridpoint)
		{
			Vector3f v = CellSize * (Vector3f)gridpoint;
			return GridFrame.FromFrameP(ref v);
		}

		public Vector3d FromGrid(Vector3d gridpointf)
		{
			gridpointf *= (Vector3d)CellSize;
			return GridFrame.FromFrameP(ref gridpointf);
		}
	}
	public struct MultigridIndexer3(Vector3i blockSize) : IMultigridIndexer3
	{
		public Vector3i OuterShift = (BlockShift = Vector3i.Zero);

		public Vector3i BlockSize = blockSize;

		public Vector3i BlockShift;

		public Vector3i ToBlockIndex(Vector3i outer_index)
		{
			Vector3i vector3i = outer_index - OuterShift;
			vector3i.x = ((vector3i.x >= 0) ? (vector3i.x / BlockSize.x) : (vector3i.x / BlockSize.x - 1));
			vector3i.y = ((vector3i.y >= 0) ? (vector3i.y / BlockSize.y) : (vector3i.y / BlockSize.y - 1));
			vector3i.z = ((vector3i.z >= 0) ? (vector3i.z / BlockSize.z) : (vector3i.z / BlockSize.z - 1));
			return vector3i - BlockShift;
		}

		public Vector3i ToBlockLocal(Vector3i outer_index)
		{
			Vector3i vector3i = ToBlockIndex(outer_index);
			return outer_index - vector3i * BlockSize;
		}

		public GridLevelIndex ToBlock(Vector3i outer_index)
		{
			Vector3i vector3i = outer_index - OuterShift;
			vector3i.x = ((vector3i.x >= 0) ? (vector3i.x / BlockSize.x) : (vector3i.x / BlockSize.x - 1));
			vector3i.y = ((vector3i.y >= 0) ? (vector3i.y / BlockSize.y) : (vector3i.y / BlockSize.y - 1));
			vector3i.z = ((vector3i.z >= 0) ? (vector3i.z / BlockSize.z) : (vector3i.z / BlockSize.z - 1));
			vector3i -= BlockShift;
			return new GridLevelIndex
			{
				block_index = vector3i,
				local_index = outer_index - vector3i * BlockSize
			};
		}

		public Vector3i FromBlock(Vector3i block_idx)
		{
			return (block_idx + BlockShift) * BlockSize + OuterShift;
		}
	}
