	public class GeneralPolygon2dBoxTree
	{
		public GeneralPolygon2d Polygon;

		private Polygon2dBoxTree OuterTree;

		private Polygon2dBoxTree[] HoleTrees;

		public GeneralPolygon2dBoxTree(GeneralPolygon2d poly)
		{
			Polygon = poly;
			OuterTree = new Polygon2dBoxTree(poly.Outer);
			int count = poly.Holes.Count;
			if (count > 0)
			{
				HoleTrees = new Polygon2dBoxTree[count];
				for (int i = 0; i < count; i++)
				{
					HoleTrees[i] = new Polygon2dBoxTree(poly.Holes[i]);
				}
			}
		}

		public double DistanceSquared(Vector2d pt, out int iHoleIndex, out int iNearSeg, out double fNearSegT)
		{
			iHoleIndex = -1;
			double num = OuterTree.SquaredDistance(pt, out iNearSeg, out fNearSegT);
			int num2 = ((HoleTrees != null) ? HoleTrees.Length : 0);
			for (int i = 0; i < num2; i++)
			{
				int iNearSeg2;
				double fNearSegT2;
				double num3 = HoleTrees[i].SquaredDistance(pt, out iNearSeg2, out fNearSegT2, num);
				if (num3 < num)
				{
					num = num3;
					iHoleIndex = i;
					iNearSeg = iNearSeg2;
					fNearSegT = fNearSegT2;
				}
			}
			return num;
		}

		public double DistanceSquared(Vector2d pt)
		{
			int iHoleIndex;
			int iNearSeg;
			double fNearSegT;
			return DistanceSquared(pt, out iHoleIndex, out iNearSeg, out fNearSegT);
		}

		public double Distance(Vector2d pt)
		{
			int iHoleIndex;
			int iNearSeg;
			double fNearSegT;
			return Math.Sqrt(DistanceSquared(pt, out iHoleIndex, out iNearSeg, out fNearSegT));
		}

		public Vector2d NearestPoint(Vector2d pt)
		{
			DistanceSquared(pt, out var iHoleIndex, out var iNearSeg, out var fNearSegT);
			return Polygon.PointAt(iNearSeg, fNearSegT, iHoleIndex);
		}
	}
	public class Polygon2dBoxTree
	{
		public Polygon2d Polygon;

		private Box2d[] boxes;

		private int layers;

		private List<int> layer_counts;

		public Polygon2dBoxTree(Polygon2d poly)
		{
			Polygon = poly;
			build_sequential(poly);
		}

		public double DistanceSquared(Vector2d pt)
		{
			int iNearSeg;
			double fNearSegT;
			return SquaredDistance(pt, out iNearSeg, out fNearSegT);
		}

		public double Distance(Vector2d pt)
		{
			int iNearSeg;
			double fNearSegT;
			return Math.Sqrt(SquaredDistance(pt, out iNearSeg, out fNearSegT));
		}

		public Vector2d NearestPoint(Vector2d pt)
		{
			SquaredDistance(pt, out var iNearSeg, out var fNearSegT);
			return Polygon.PointAt(iNearSeg, fNearSegT);
		}

		public double SquaredDistance(Vector2d pt, out int iNearSeg, out double fNearSegT, double max_dist = double.MaxValue)
		{
			int iLayerStart = boxes.Length - 1;
			int iLayer = layers - 1;
			double min_dist = max_dist;
			iNearSeg = -1;
			fNearSegT = 0.0;
			find_min_distance(ref pt, ref min_dist, ref iNearSeg, ref fNearSegT, 0, iLayerStart, iLayer);
			if (iNearSeg == -1)
			{
				return double.MaxValue;
			}
			return min_dist;
		}

		private void find_min_distance(ref Vector2d pt, ref double min_dist, ref int min_dist_seg, ref double min_dist_segt, int bi, int iLayerStart, int iLayer)
		{
			if (iLayer == 0)
			{
				int num = 2 * bi;
				double num2 = Polygon.Segment(num).DistanceSquared(pt, out var t);
				if (num2 <= min_dist)
				{
					min_dist = num2;
					min_dist_seg = num;
					min_dist_segt = t;
				}
				if (num + 1 < Polygon.VertexCount)
				{
					num2 = Polygon.Segment(num + 1).DistanceSquared(pt, out t);
					if (num2 <= min_dist)
					{
						min_dist = num2;
						min_dist_seg = num + 1;
						min_dist_segt = t;
					}
				}
				return;
			}
			int num3 = iLayer - 1;
			int num4 = layer_counts[num3];
			int num5 = iLayerStart - num4;
			int num6 = num5 + 2 * bi;
			if (boxes[num6].DistanceSquared(pt) <= min_dist)
			{
				find_min_distance(ref pt, ref min_dist, ref min_dist_seg, ref min_dist_segt, 2 * bi, num5, num3);
			}
			if (2 * bi + 1 < num4)
			{
				int num7 = num6 + 1;
				if (boxes[num7].DistanceSquared(pt) <= min_dist)
				{
					find_min_distance(ref pt, ref min_dist, ref min_dist_seg, ref min_dist_segt, 2 * bi + 1, num5, num3);
				}
			}
		}

		private void build_sequential(Polygon2d poly)
		{
			int vertexCount = poly.VertexCount;
			int num = vertexCount;
			int num2 = 0;
			layers = 0;
			layer_counts = new List<int>();
			int num3 = 0;
			while (num > 1)
			{
				int num4 = num / 2 + ((num % 2 != 0) ? 1 : 0);
				num2 += num4;
				num = num4;
				layer_counts.Add(num4);
				num3 += num4;
				layers++;
			}
			boxes = new Box2d[num2];
			num3 = 0;
			for (int i = 0; i < vertexCount; i += 2)
			{
				Vector2d vector2d = poly[(i + 1) % vertexCount];
				Segment2d seg = new Segment2d(poly[i], vector2d);
				Box2d box = new Box2d(seg);
				if (i < vertexCount - 1)
				{
					Segment2d seg2 = new Segment2d(vector2d, poly[(i + 2) % vertexCount]);
					Box2d box2 = new Box2d(seg2);
					box = Box2d.Merge(ref box, ref box2);
				}
				boxes[num3++] = box;
			}
			num = num3;
			int num5 = 0;
			bool flag = false;
			while (!flag)
			{
				int num6 = num3;
				for (int j = 0; j < num; j += 2)
				{
					Box2d box2d = Box2d.Merge(ref boxes[num5 + j], ref boxes[num5 + j + 1]);
					boxes[num3++] = box2d;
				}
				num = num / 2 + ((num % 2 != 0) ? 1 : 0);
				num5 = num6;
				if (num == 1)
				{
					flag = true;
				}
			}
		}
	}
	public class SegmentHashGrid2d<T>
	{
		private Dictionary<Vector2i, List<T>> Hash;

		private ScaleGridIndexer2 Indexer;

		private double MaxExtent;

		private T invalidValue;

		private SpinLock spinlock;

		public SegmentHashGrid2d(double cellSize, T invalidValue)
		{
			Hash = new Dictionary<Vector2i, List<T>>();
			Indexer = new ScaleGridIndexer2
			{
				CellSize = cellSize
			};
			MaxExtent = 0.0;
			spinlock = default(SpinLock);
			this.invalidValue = invalidValue;
		}

		public void InsertSegment(T value, Vector2d center, double extent)
		{
			Vector2i idx = Indexer.ToGrid(center);
			if (extent > MaxExtent)
			{
				MaxExtent = extent;
			}
			insert_segment(value, idx);
		}

		public void InsertSegmentUnsafe(T value, Vector2d center, double extent)
		{
			Vector2i idx = Indexer.ToGrid(center);
			if (extent > MaxExtent)
			{
				MaxExtent = extent;
			}
			insert_segment(value, idx, threadsafe: false);
		}

		public bool RemoveSegment(T value, Vector2d center)
		{
			Vector2i idx = Indexer.ToGrid(center);
			return remove_segment(value, idx);
		}

		public bool RemoveSegmentUnsafe(T value, Vector2d center)
		{
			Vector2i idx = Indexer.ToGrid(center);
			return remove_segment(value, idx, threadsafe: false);
		}

		public void UpdateSegment(T value, Vector2d old_center, Vector2d new_center, double new_extent)
		{
			if (new_extent > MaxExtent)
			{
				MaxExtent = new_extent;
			}
			Vector2i vector2i = Indexer.ToGrid(old_center);
			Vector2i vector2i2 = Indexer.ToGrid(new_center);
			if (!(vector2i == vector2i2))
			{
				remove_segment(value, vector2i);
				insert_segment(value, vector2i2);
			}
		}

		public void UpdateSegmentUnsafe(T value, Vector2d old_center, Vector2d new_center, double new_extent)
		{
			if (new_extent > MaxExtent)
			{
				MaxExtent = new_extent;
			}
			Vector2i vector2i = Indexer.ToGrid(old_center);
			Vector2i vector2i2 = Indexer.ToGrid(new_center);
			if (!(vector2i == vector2i2))
			{
				remove_segment(value, vector2i, threadsafe: false);
				insert_segment(value, vector2i2, threadsafe: false);
			}
		}

		public KeyValuePair<T, double> FindNearestInRadius(Vector2d query_pt, double radius, Func<T, double> distF, Func<T, bool> ignoreF = null)
		{
			double num = radius + MaxExtent;
			Vector2i vector2i = Indexer.ToGrid(query_pt - num * Vector2d.One);
			Vector2i vector2i2 = Indexer.ToGrid(query_pt + num * Vector2d.One);
			double num2 = double.MaxValue;
			T key = invalidValue;
			if (ignoreF == null)
			{
				ignoreF = (T pt) => false;
			}
			for (int num3 = vector2i.y; num3 <= vector2i2.y; num3++)
			{
				for (int num4 = vector2i.x; num4 <= vector2i2.x; num4++)
				{
					Vector2i key2 = new Vector2i(num4, num3);
					if (!Hash.TryGetValue(key2, out var value))
					{
						continue;
					}
					foreach (T item in value)
					{
						if (!ignoreF(item))
						{
							double num5 = distF(item);
							if (num5 < radius && num5 < num2)
							{
								key = item;
								num2 = num5;
							}
						}
					}
				}
			}
			return new KeyValuePair<T, double>(key, num2);
		}

		public KeyValuePair<T, double> FindNearestInSquaredRadius(Vector2d query_pt, double radiusSqr, Func<T, double> distSqrF, Func<T, bool> ignoreF = null)
		{
			double num = Math.Sqrt(radiusSqr) + MaxExtent;
			Vector2i vector2i = Indexer.ToGrid(query_pt - num * Vector2d.One);
			Vector2i vector2i2 = Indexer.ToGrid(query_pt + num * Vector2d.One);
			double num2 = double.MaxValue;
			T key = invalidValue;
			if (ignoreF == null)
			{
				ignoreF = (T pt) => false;
			}
			for (int num3 = vector2i.y; num3 <= vector2i2.y; num3++)
			{
				for (int num4 = vector2i.x; num4 <= vector2i2.x; num4++)
				{
					Vector2i key2 = new Vector2i(num4, num3);
					if (!Hash.TryGetValue(key2, out var value))
					{
						continue;
					}
					foreach (T item in value)
					{
						if (!ignoreF(item))
						{
							double num5 = distSqrF(item);
							if (num5 < radiusSqr && num5 < num2)
							{
								key = item;
								num2 = num5;
							}
						}
					}
				}
			}
			return new KeyValuePair<T, double>(key, num2);
		}

		private void insert_segment(T value, Vector2i idx, bool threadsafe = true)
		{
			bool lockTaken = false;
			while (threadsafe && !lockTaken)
			{
				spinlock.Enter(ref lockTaken);
			}
			if (Hash.TryGetValue(idx, out var value2))
			{
				value2.Add(value);
			}
			else
			{
				Hash[idx] = new List<T> { value };
			}
			if (lockTaken)
			{
				spinlock.Exit();
			}
		}

		private bool remove_segment(T value, Vector2i idx, bool threadsafe = true)
		{
			bool lockTaken = false;
			while (threadsafe && !lockTaken)
			{
				spinlock.Enter(ref lockTaken);
			}
			bool result = false;
			if (Hash.TryGetValue(idx, out var value2))
			{
				result = value2.Remove(value);
			}
			if (lockTaken)
			{
				spinlock.Exit();
			}
